/// カレンダーのイベント（1 日の予定）
/// [startTime] / [endTime] は "HH:mm" 形式で、null なら終日イベント
/// [colorArgb] はイベント表示色（null ならデフォルト紫）
/// [googleId] が non-null なら Google Calendar 由来の読み取り専用イベント
class CalendarEvent {
  final String id;
  final String title;
  final String? memo;
  final String? startTime; // "HH:mm" or null
  final String? endTime; // "HH:mm" or null
  final int? colorArgb;
  final String? googleId;

  /// グループ共有時のイベント所有者UID。
  /// null = 自分のイベント（移行期/ローカル）。
  /// 他人の uid のときは UI 上で読み取り専用扱い。
  final String? ownerUid;

  /// 所有者の表示名（他人のイベント表示用、表示以外には使わない）
  final String? ownerName;

  CalendarEvent({
    required this.id,
    required this.title,
    this.memo,
    this.startTime,
    this.endTime,
    this.colorArgb,
    this.googleId,
    this.ownerUid,
    this.ownerName,
  });

  bool get isGoogleEvent => googleId != null;

  /// 他人のイベント（自分以外の uid が owner）かどうか。
  /// ownerUid が null のときは自分のイベントとして扱う（後方互換）。
  bool isOthersEvent(String? myUid) =>
      ownerUid != null && myUid != null && ownerUid != myUid;

  Map<String, dynamic> toJson() => {
        'id': id,
        'title': title,
        'memo': memo,
        'startTime': startTime,
        'endTime': endTime,
        'colorArgb': colorArgb,
        'googleId': googleId,
        'ownerUid': ownerUid,
        'ownerName': ownerName,
      };
  factory CalendarEvent.fromJson(Map<String, dynamic> j) => CalendarEvent(
        id: j['id'] as String,
        title: j['title'] as String,
        memo: j['memo'] as String?,
        startTime: j['startTime'] as String?,
        endTime: j['endTime'] as String?,
        colorArgb: j['colorArgb'] as int?,
        googleId: j['googleId'] as String?,
        ownerUid: j['ownerUid'] as String?,
        ownerName: j['ownerName'] as String?,
      );
}

/// 集中ロックのスケジュール 1 件 (ユーザー要望: 曜日指定で複数設定)。
/// [days] は DateTime.weekday (1=月 … 7=日) の集合。 空なら毎日。
/// 時刻は 0 時からの分 ([startMin], [endMin])。 start>end は深夜跨ぎ。
class FocusLockSchedule {
  String id;
  bool enabled;
  int startMin;
  int endMin;
  Set<int> days;
  FocusLockSchedule({
    required this.id,
    this.enabled = true,
    required this.startMin,
    required this.endMin,
    Set<int>? days,
  }) : days = days ?? <int>{};

  Map<String, dynamic> toJson() => {
        'id': id,
        'enabled': enabled,
        'startMin': startMin,
        'endMin': endMin,
        'days': days.toList(),
      };

  factory FocusLockSchedule.fromJson(Map<String, dynamic> j) =>
      FocusLockSchedule(
        id: j['id'] as String? ??
            'fls_${DateTime.now().microsecondsSinceEpoch}',
        enabled: j['enabled'] as bool? ?? true,
        startMin: (j['startMin'] as num?)?.toInt() ?? (22 * 60),
        endMin: (j['endMin'] as num?)?.toInt() ?? (6 * 60),
        days: ((j['days'] as List?)?.map((e) => (e as num).toInt()).toSet()) ??
            <int>{},
      );
}

/// グループ内のメンバー情報（カレンダー共有用）。
/// `downloadCalendarEventsFromCloud` がグループの /members から取得し、
/// UI のユーザー切替セレクタに表示する。
///
/// `plan` は 'free' / 'pro' / 'max' / 'developer' / 'coupon' のいずれか。
/// 'free' のメンバーは Max プランから見ても閲覧できないものとして扱う
/// (= 仕様上 Pro プラン以上のメンバーのみ閲覧可能)。
class CalendarMemberInfo {
  final String uid;
  final String displayName;
  final String plan;
  final bool allowSharing;
  CalendarMemberInfo({
    required this.uid,
    required this.displayName,
    required this.plan,
    required this.allowSharing,
  });

  /// Pro 以上 (= Max プランから見たときに「閲覧可能」になりうる) かどうか。
  /// developer / coupon も Pro 以上扱い。
  bool get isProOrAbove =>
      plan == 'pro' || plan == 'max' || plan == 'developer' || plan == 'coupon';
}

// ─── ページモデル ─────────────────────────────────────────────────────────────

/// マインドマップのフォルダー（ページをグルーピングするための UI 概念）。
/// ページは `folderId` でフォルダーに所属する。フォルダーはネスト不可（フラット）。
class MindMapFolder {
  final String id;
  String name;

  /// Drawer 上で展開状態か(永続化)
  bool expanded;

  /// このフォルダーがディスク上のディレクトリと連動しているか。
  /// 設定されていれば、配下のページは新規作成・編集時に自動的に
  /// このディレクトリ配下に JSON ファイルとして書き出される。
  /// null = 連動なし(通常のフォルダー)。
  String? linkedDirPath;

  MindMapFolder({
    required this.id,
    required this.name,
    this.expanded = true,
    this.linkedDirPath,
  });

  Map<String, dynamic> toJson() => {
        'id': id,
        'name': name,
        'expanded': expanded,
        if (linkedDirPath != null) 'linkedDirPath': linkedDirPath,
      };

  factory MindMapFolder.fromJson(Map<String, dynamic> json) => MindMapFolder(
        id: json['id'] as String,
        name: json['name'] as String,
        expanded: json['expanded'] as bool? ?? true,
        linkedDirPath: json['linkedDirPath'] as String?,
      );
}

class MindMapPage {
  final String id;
  String name;
  final Map<String, MindMapNode> nodes;
  final List<NodeConnection> connections;

  /// 最終更新日時（ローカル編集のたびに更新）
  DateTime lastModifiedAt;

  /// 所属フォルダーの ID。null ならルート（フォルダー外）。
  String? folderId;

  /// このマップへの他ユーザーからの再アップロードを制限するか。
  /// true なら、 別のユーザー (= 異なる UID) が同じ pageId にアップロードしよ
  /// うとした時に拒否される。 false ならグループ全員が上書き可能 (= 既定)。
  ///
  /// ユーザー要望: 「クラウドに新しいマップをアップロードする時に他ユーザー
  ///   による再アップロードを制限できる機能を作って」 への対応。
  ///
  /// セキュリティ補足:
  ///   アプリ側のロジックだけでは Firestore に直接書き込まれる攻撃を防げない
  ///   ため、 本番運用では Firestore セキュリティルールで同じ制御を入れる
  ///   ことを推奨する (= 既存ドキュメントの uploadRestricted が true で
  ///   restrictedByUid が request.auth.uid と一致しない場合は write を拒否)。
  bool uploadRestricted;

  /// 制限を設定したユーザーの UID。 [uploadRestricted] が true の時のみ意味を
  /// 持つ。 このユーザーだけが引き続き上書き可能、 他の UID からは拒否される。
  String? restrictedByUid;

  /// マインドマップに挿入された装飾図形 (= 直線、 矢印、 長方形等)。
  ///
  /// ユーザー要望「直線や矢印線、 長方形等の図形を挿入できるようにして」 への
  /// 対応で導入。 ノード・コネクションとは別の独立した装飾要素として、 マップ
  /// 上の任意の位置に配置できる。 永続化は通常のページ JSON に含める。
  final List<MapDecoration> decorations;

  /// マップの背景画像 (= ユーザー要望「マップの背景画像を自由にカスタマイズ」)。
  /// `attachments/` 以下に保存したローカルファイルのパス。 null なら背景画像
  /// なし (= グリッドのみ)。 ページごとに独立して持てる。
  String? backgroundImagePath;

  /// 背景画像の不透明度 (0〜100)。 既定 50 (半透明) で、 ノード/接続が
  /// 上に乗っても視認性を確保する。 ユーザーがダイアログでスライダー
  /// 調整可能。
  int backgroundOpacityPercent;

  /// 背景画像の表示モード:
  ///   'cover' = キャンバス全体を覆う (アスペクト比を維持して中央クロップ)
  ///   'contain' = アスペクト比を維持して全体が収まるよう縮小 (余白あり)
  ///   'tile' = タイル状に繰り返し
  /// 既定 'cover'。
  String backgroundFit;

  /// ページ種別。 'normal' = 通常マップ、 'bookshelf' = ギャラリーページ
  /// (= ユーザー要望: PDF/画像/動画を等間隔・同寸のタイルで自動整列する専用
  ///  ページ)。 ギャラリーページではノード追加・貼り付け・YouTube 取り込みの後に
  ///  自動で `arrangeAsBookshelf` が走る。
  String pageType;

  /// ギャラリーページの 1 段(行)あたりのタイル数 (= 横の要素数)。
  /// 0 = 自動 (= kShelfDefaultPerRow)。 1 以上ならその列数で段折り返し。
  int shelfPerRow;

  /// ギャラリーページの段数 (= 縦の要素数)。 0 = 自動 (要素数から算出)。
  /// 1 以上なら +ボックスをこの段数ぶんだけ表示する (= ユーザー要望: +ボックスが
  /// 勝手に増えないよう、 縦横の要素数を手動で固定できる)。
  int shelfRows;

  MindMapPage({
    required this.id,
    required this.name,
    Map<String, MindMapNode>? nodes,
    List<NodeConnection>? connections,
    DateTime? lastModifiedAt,
    this.folderId,
    this.uploadRestricted = false,
    this.restrictedByUid,
    List<MapDecoration>? decorations,
    this.backgroundImagePath,
    this.backgroundOpacityPercent = 50,
    this.backgroundFit = 'cover',
    this.pageType = 'normal',
    this.shelfPerRow = 0,
    this.shelfRows = 0,
  })  : nodes = nodes ?? {},
        connections = connections ?? [],
        decorations = decorations ?? <MapDecoration>[],
        lastModifiedAt = lastModifiedAt ?? DateTime.now();

  Map<String, dynamic> toJson() => {
        'id': id,
        'name': name,
        'nodes': nodes.values.map((n) => n.toJson()).toList(),
        'connections': connections.map((c) => c.toJson()).toList(),
        'lastModifiedAt': lastModifiedAt.millisecondsSinceEpoch,
        if (folderId != null) 'folderId': folderId,
        // 制限フラグは値があるときだけ書き出す (= 旧版データとの互換性維持)
        if (uploadRestricted) 'uploadRestricted': true,
        if (restrictedByUid != null) 'restrictedByUid': restrictedByUid,
        // 装飾図形リスト (= 空の時は省略してファイルサイズ節約)
        if (decorations.isNotEmpty)
          'decorations': decorations.map((d) => d.toJson()).toList(),
        // 背景画像 (= 値が無ければ書き出さない: 旧版互換 + ファイル節約)
        if (backgroundImagePath != null)
          'backgroundImagePath': backgroundImagePath,
        if (backgroundImagePath != null)
          'backgroundOpacityPercent': backgroundOpacityPercent,
        if (backgroundImagePath != null && backgroundFit != 'cover')
          'backgroundFit': backgroundFit,
        // ギャラリーページ種別 (= 既定 'normal' の時は省略して旧版互換)
        if (pageType != 'normal') 'pageType': pageType,
        if (shelfPerRow != 0) 'shelfPerRow': shelfPerRow,
        if (shelfRows != 0) 'shelfRows': shelfRows,
      };

  factory MindMapPage.fromJson(Map<String, dynamic> json) {
    final tsRaw = json['lastModifiedAt'];
    final ts = tsRaw is int
        ? DateTime.fromMillisecondsSinceEpoch(tsRaw)
        : DateTime.now();
    final page = MindMapPage(
      id: json['id'] as String,
      name: json['name'] as String,
      lastModifiedAt: ts,
      folderId: json['folderId'] as String?,
      uploadRestricted: (json['uploadRestricted'] as bool?) ?? false,
      restrictedByUid: json['restrictedByUid'] as String?,
      backgroundImagePath: json['backgroundImagePath'] as String?,
      backgroundOpacityPercent:
          (json['backgroundOpacityPercent'] as int?) ?? 50,
      backgroundFit: (json['backgroundFit'] as String?) ?? 'cover',
      pageType: (json['pageType'] as String?) ?? 'normal',
      shelfPerRow: (json['shelfPerRow'] as int?) ?? 0,
      shelfRows: (json['shelfRows'] as int?) ?? 0,
    );
    final nodeList = json['nodes'] as List<dynamic>? ?? [];
    for (final item in nodeList) {
      final node = MindMapNode.fromJson(item as Map<String, dynamic>);
      page.nodes[node.id] = node;
    }
    final connList = json['connections'] as List<dynamic>? ?? [];
    for (final item in connList) {
      page.connections
          .add(NodeConnection.fromJson(item as Map<String, dynamic>));
    }
    // v2 legacy: parentId/childIds → connections 移行
    if (connList.isEmpty) {
      _migrateLegacyConnections(json, page);
    }
    // 装飾図形の読み込み (= 旧版互換: フィールドが無ければ空のまま)
    final decoList = json['decorations'] as List<dynamic>? ?? [];
    for (final item in decoList) {
      try {
        page.decorations
            .add(MapDecoration.fromJson(item as Map<String, dynamic>));
      } catch (_) {
        // 不正なエントリはスキップ
      }
    }
    return page;
  }

  static void _migrateLegacyConnections(
      Map<String, dynamic> json, MindMapPage page) {
    final nodeList = json['nodes'] as List<dynamic>? ?? [];
    for (final item in nodeList) {
      final m = item as Map<String, dynamic>;
      final parentId = m['parentId'] as String?;
      final nodeId = m['id'] as String;
      if (parentId != null && page.nodes.containsKey(parentId)) {
        page.connections.add(NodeConnection(
          fromId: parentId,
          fromAnchor: AnchorDirection.east,
          toId: nodeId,
          toAnchor: AnchorDirection.west,
        ));
      }
    }
  }
}

/// マインドマップに挿入できる装飾図形の種類。
///
/// ユーザー要望「直線や矢印線、 長方形等の図形を挿入できるようにして」 への
/// 対応で導入。 PowerPoint の「図形を挿入」 と同じ感覚で、 マップ上に装飾
/// 要素を自由に配置できる。
enum MapDecorationKind {
  /// 直線 (= start から end への線分、 端点なし)。
  line,

  /// 矢印 (= start から end への線分、 end 側に矢じり付き)。
  arrow,

  /// 長方形 (= start を左上、 end を右下とする矩形、 枠線のみ)。
  rectangle,

  /// 楕円 (= start / end を対角とする矩形に内接する楕円、 枠線のみ)。
  ellipse,

  /// 波線 (= start から end への正弦波状の線)。
  wavyLine,

  /// 塗りつぶし長方形。
  filledRectangle,

  /// 円 (= start/end の対角に内接する正円、 塗りつぶし)。
  circle,

  /// 中空円 (= 正円、 枠線のみ)。
  hollowCircle,
}

/// マインドマップに配置される装飾図形 1 個分のデータ。
class MapDecoration {
  /// 一意 ID。 削除や編集の対象を特定するため。
  final String id;

  /// 図形の種類。
  MapDecorationKind kind;

  /// 開始点 (= マップ座標系。 ノードの position と同じ系)。
  Offset start;

  /// 終了点 (= マップ座標系)。
  Offset end;

  /// 色 (RGB 24bit 値、 例: 0xFF0000 = 赤)。 描画時に 0xFF000000 と OR する。
  int colorRgb;

  /// 線の太さ (= 直線/矢印/枠線の幅)。 ピクセル単位。
  double strokeWidth;

  /// 図形内に表示する文字 (ユーザー要望)。 空文字なら非表示。
  String text;

  /// 文字の位置 (外接矩形内の正規化座標 0.0〜1.0)。
  /// (0,0)=左上 / (0.5,0.5)=中央 / (1,1)=右下。 9 アンカーの既定値にも、
  /// 自由ドラッグで任意の位置にも使える (ユーザー要望)。
  double textAnchorX;
  double textAnchorY;

  MapDecoration({
    required this.id,
    required this.kind,
    required this.start,
    required this.end,
    this.colorRgb = 0x222222,
    this.strokeWidth = 2.5,
    this.text = '',
    this.textAnchorX = 0.5,
    this.textAnchorY = 0.5,
  });

  Map<String, dynamic> toJson() => {
        'id': id,
        'kind': kind.name,
        'startX': start.dx,
        'startY': start.dy,
        'endX': end.dx,
        'endY': end.dy,
        'colorRgb': colorRgb,
        'strokeWidth': strokeWidth,
        'text': text,
        'textAnchorX': textAnchorX,
        'textAnchorY': textAnchorY,
      };

  factory MapDecoration.fromJson(Map<String, dynamic> json) {
    final kindStr = json['kind'] as String? ?? 'line';
    final kind = MapDecorationKind.values.firstWhere((k) => k.name == kindStr,
        orElse: () => MapDecorationKind.line);
    return MapDecoration(
      id: json['id'] as String,
      kind: kind,
      start: Offset((json['startX'] as num?)?.toDouble() ?? 0,
          (json['startY'] as num?)?.toDouble() ?? 0),
      end: Offset((json['endX'] as num?)?.toDouble() ?? 0,
          (json['endY'] as num?)?.toDouble() ?? 0),
      colorRgb: (json['colorRgb'] as num?)?.toInt() ?? 0x222222,
      strokeWidth: (json['strokeWidth'] as num?)?.toDouble() ?? 2.5,
      text: json['text'] as String? ?? '',
      textAnchorX: (json['textAnchorX'] as num?)?.toDouble() ?? 0.5,
      textAnchorY: (json['textAnchorY'] as num?)?.toDouble() ?? 0.5,
    );
  }

  MapDecoration copyWith({
    MapDecorationKind? kind,
    Offset? start,
    Offset? end,
    int? colorRgb,
    double? strokeWidth,
    String? text,
    double? textAnchorX,
    double? textAnchorY,
  }) {
    return MapDecoration(
      id: id,
      kind: kind ?? this.kind,
      start: start ?? this.start,
      end: end ?? this.end,
      colorRgb: colorRgb ?? this.colorRgb,
      strokeWidth: strokeWidth ?? this.strokeWidth,
      text: text ?? this.text,
      textAnchorX: textAnchorX ?? this.textAnchorX,
      textAnchorY: textAnchorY ?? this.textAnchorY,
    );
  }
}

// ─── Undo/Redo スナップショット ───────────────────────────────────────────────

/// チャンネル動画キューデータ
class ChannelVideoQueue {
  final List<String> videoIds;
  final List<String> titles;
  ChannelVideoQueue({required this.videoIds, required this.titles});
}

class _PageSnapshot {
  final Map<String, MindMapNode> nodes;
  final List<NodeConnection> connections;
  final Map<String, Set<String>> namedGroups;
  // 装飾図形も undo/redo の対象にする (= 図形作成/編集/削除を Ctrl+Z で戻す)。
  final List<MapDecoration> decorations;

  _PageSnapshot({
    required this.nodes,
    required this.connections,
    required this.namedGroups,
    this.decorations = const [],
  });

  factory _PageSnapshot.from(
          MindMapPage page, Map<String, Set<String>> groups) =>
      _PageSnapshot(
        // ── 重要: ノードは copyWith() で **新しいインスタンス** にコピーする ──
        //
        // 旧実装は `MapEntry(e.key, e.value)` で同じ MindMapNode 参照を
        // そのまま入れていた。これだと「インスタンスのフィールドを直接
        // 書き換える」 系の操作 (例: `clearNodeContent` での
        // `node.title = ''` / `node.memoText = null` など) を行ったあとに
        // undo() しても、 スナップショット内の同じインスタンスもろとも
        // 書き換わっているため何も復元されない、 という不具合があった。
        //
        // ユーザー報告: 「Ctrl+Shift+L で動画等をクリアにした後、 Ctrl+Z で
        // 戻すことができない」
        //
        // copyWith() は新しい MindMapNode を作るので、 以降の直接書き換えが
        // スナップショット側に波及しなくなり、 undo / redo が正しく動く。
        nodes: Map.fromEntries(
            page.nodes.entries.map((e) => MapEntry(e.key, e.value.copyWith()))),
        connections: List.of(page.connections),
        namedGroups: Map.fromEntries(
            groups.entries.map((e) => MapEntry(e.key, Set.of(e.value)))),
        // 図形は copyWith() で別インスタンス化して、 以降の直接書き換えが
        // スナップショットに波及しないようにする (ノードと同じ理由)。
        decorations: page.decorations.map((d) => d.copyWith()).toList(),
      );
}

// ─── プロバイダー ─────────────────────────────────────────────────────────────

/// AI 要約 / 解説マップ生成の結果。
/// summarizeFileToNewPage / explainConceptToNewPage が返す。
/// 画面側はこの値を見て「どのページに作成されたか」「ルートをどこに
/// 中心表示すればよいか」を判断する。
class AiMapResult {
  /// ノードが配置されたページのインデックス。
  /// addToCurrentPage=true の場合は呼び出し時の現在ページ、
  /// false (新規ページ) の場合は新しく作られたページのインデックス。
  final int pageIndex;

  /// 生成したルートノードの ID。
  final String rootId;

  /// ルートノードの canvas 座標 (左上)。画面側はここに viewport を
  /// 寄せれば「生成された木」を中心に表示できる。
  final Offset rootPosition;

  /// 既存ページに追加した (true) か、新規ページに作った (false) か。
  /// 呼び出し側 (画面) で page 切替の要否を判定するのに使う。
  final bool addedToCurrentPage;

  const AiMapResult({
    required this.pageIndex,
    required this.rootId,
    required this.rootPosition,
    required this.addedToCurrentPage,
  });
}

/// 網羅モードの解説生成を途中で停止したときの一時保存セッション。
///
/// 生成は「Plan (子テーマ列挙) → Expand (バッチごとの詳細) → Merge (1 ページに配置)」
/// の 3 段で進行する。網羅モードでは Expand が長時間かかるため、ユーザーが
/// 「いったん止めて、後で続きから再開したい」と思うことがある。
/// その状態を保持するのがこのクラス。
///
/// 一時停止時の動作:
///  - その時点までに完了済の subject (子テーマ) は **既にページに配置済**。
///  - まだ実行していない subject は [remainingSubjects] に文字列で保持。
///  - 再開時はこのセッションを使って残りの subject を Expand → 既存ページの
///    親ルート (parentRootId) の子として追記する。
class PausedExplainSession {
  /// マスターテーマ (例: "各都道府県の有名人")
  final String term;
  final String userInstruction;

  /// 'rough' | 'standard' | 'detailed'
  final String detail;

  /// 既に部分配置されたページの index
  final int pageIndex;

  /// ページ id (page 並び替え等で index がずれても追跡できるように)
  final String pageId;

  /// 親ルートノード (term を表す) の id。
  /// 再開時に新しい subject roots はこの子として追加する。
  final String parentRootId;

  /// 残り未処理の subject 一覧 (バッチに分けて Expand する対象)。
  final List<String> remainingSubjects;

  /// 完了済 subject 数 (進捗表示用)
  final int doneCount;

  /// 全 subject 数
  final int totalCount;

  /// 一時停止された時刻 (UI に "X 分前に停止" 等を表示する用)
  final DateTime pausedAt;

  PausedExplainSession({
    required this.term,
    required this.userInstruction,
    required this.detail,
    required this.pageIndex,
    required this.pageId,
    required this.parentRootId,
    required this.remainingSubjects,
    required this.doneCount,
    required this.totalCount,
    DateTime? pausedAt,
  }) : pausedAt = pausedAt ?? DateTime.now();

  PausedExplainSession copyWith({
    int? pageIndex,
    List<String>? remainingSubjects,
    int? doneCount,
  }) =>
      PausedExplainSession(
        term: term,
        userInstruction: userInstruction,
        detail: detail,
        pageIndex: pageIndex ?? this.pageIndex,
        pageId: pageId,
        parentRootId: parentRootId,
        remainingSubjects: remainingSubjects ?? this.remainingSubjects,
        doneCount: doneCount ?? this.doneCount,
        totalCount: totalCount,
        pausedAt: pausedAt,
      );
}

/// `_validateUrlsInStructure` 内部用。AI が出力した JSON ツリー内に散らばる
/// URL フィールド一個を「親 Map」「フィールド名」「URL 文字列」の組で参照する
/// ためのヘルパ。検証後、無効なら親 Map.remove(field) で消す。
class _UrlSlot {
  final Map node;
  final String field;
  final String url;
  _UrlSlot({required this.node, required this.field, required this.url});
}

/// `_uploadPageAttachments` のジョブキュー要素。
/// 1 ファイル分のアップロードに必要な情報をまとめる。
/// バイト数を事前に取っておくのは、ページ全体での進捗計算 (累計済み /
/// 合計バイト) を正確にやるため。
enum _AttachmentKind { image, video }

class _AttachmentToUpload {
  final String nodeId;
  final _AttachmentKind kind;
  final String localPath;
  final String name;
  final int sizeBytes;
  _AttachmentToUpload({
    required this.nodeId,
    required this.kind,
    required this.localPath,
    required this.name,
    required this.sizeBytes,
  });
}

/// AI 要約・解説に使った「資料の文脈」をページ単位で保持するためのクラス。
/// 要約完了後、ユーザーが「この資料についてもう少し質問したい」と思った
/// ときに参照する。ファイル要約 (summarize) のページにのみ作成される
/// (explain は概念解説で AI 内部知識ベースなので追加文脈は不要)。
///
/// テキスト系ファイル: textContent に本文を保存。
/// バイナリ系 (PDF/docx/pptx): filePath だけ保存し、毎回 AI に再添付する。
class AiPageContext {
  /// 資料ファイル名 (UI 表示用)
  final String fileName;

  /// テキスト系ファイルの本文 (60K 文字に切り詰め済み)。バイナリは null。
  final String? textContent;

  /// バイナリドキュメント (pdf/docx/pptx) のフルパス。テキストは null。
  /// ファイルが移動・削除された場合のフォールバックは textContent 無しで askAi。
  final String? filePath;

  /// 拡張子 ('pdf'/'docx'/'pptx'/'txt' など)。バイナリ判定に使う。
  final String? ext;

  /// 追加質問の履歴 (ユーザーが Q&A した分だけ蓄積)。
  /// chronological 順 (古い → 新しい)。
  final List<AiQAEntry> qaHistory;

  AiPageContext({
    required this.fileName,
    this.textContent,
    this.filePath,
    this.ext,
  }) : qaHistory = [];
}

/// 1 回ぶんの追加質問と回答 (Q&A 1 ターン)。
class AiQAEntry {
  final String question;
  final String answer;
  final DateTime ts;
  const AiQAEntry({
    required this.question,
    required this.answer,
    required this.ts,
  });
}

/// サブスクリプションプラン種別。
/// - `free`: 無料プラン (制限あり: 2ページまで、クラウドデータは3日で削除、
///   YouTube動画ダウンロード不可)
/// - `pro`: 有料プラン (無制限ページ、永久クラウド保存、動画DL可)
/// - `max`: より上位のプラン (将来用、現状機能は Pro と同等だが識別可能)
///
/// 現状は実課金接続前なので、開発者モードで `_devImpersonatePlan` を切り替えて
/// 各プランの動作をテストする。本番課金 (RevenueCat 等) が繋がったら、
/// `_proSubscribed` の代わりにこの enum を購入結果から書き込む形に拡張する。
enum SubscriptionPlan { free, pro, max }

/// メッセージ/問い合わせ送信時に displayName が未設定だった場合に投げる
/// 専用例外。UI 側はこれをキャッチしてユーザー名設定ダイアログを開く。
class _DisplayNameRequiredException implements Exception {
  const _DisplayNameRequiredException();
  @override
  String toString() => 'Display name is required to send messages.';
}

/// 公開 API: `_DisplayNameRequiredException` の判定用ヘルパ。
/// UI 側で `catch (e) { if (isDisplayNameRequiredError(e)) ... }` のように使う。
bool isDisplayNameRequiredError(Object e) => e is _DisplayNameRequiredException;

/// 再アップロード制限がかかっているマップに対して、 他ユーザー (= 制限を
/// 掛けたユーザー以外) が上書きアップロードを試みた時に投げられる例外。
///
/// ユーザー要望: 「クラウドに新しいマップをアップロードする時に他ユーザーに
///   よる再アップロードを制限できる機能を作って」 への対応で導入。
///
/// UI 側は `catch (e) { if (isUploadRestrictedError(e)) ... }` でキャッチして
/// 「このマップは他のユーザーによって制限されています」 と表示するのが想定。
class _UploadRestrictedException implements Exception {
  final String message;
  const _UploadRestrictedException(this.message);
  @override
  String toString() => message;
}

/// 公開 API: `_UploadRestrictedException` の判定用ヘルパ。
bool isUploadRestrictedError(Object e) => e is _UploadRestrictedException;

// ─── 連番オートフィル: 連番パターン認識 ─────────────────────────────────────
//
// 「第一章」→「第二章」、 「Chapter 1」→「Chapter 2」のように、
// 入力テキストに含まれる **連番らしき部分** を検出して次の値を返す。
// 認識できないテキストには null を返す。
//
// サポートする連番:
// - 半角アラビア数字 (1, 2, 3...)
// - 全角アラビア数字 (１, ２, ３...)
// - 漢数字 (一, 二, 三 ... 千) — 簡易: 1〜99 をサポート
// - 半角アルファベット 1 文字 (A, B, C... / a, b, c...)
// - ローマ数字 (I, II, III, IV... XX まで)
// - ひらがな五十音 (あ, い, う... を, ん) 1 文字限定
// - カタカナ五十音 (ア, イ, ウ... ン) 1 文字限定

/// 漢数字 1〜9 のテーブル。
const Map<String, int> _kanjiDigit = {
  '一': 1,
  '二': 2,
  '三': 3,
  '四': 4,
  '五': 5,
  '六': 6,
  '七': 7,
  '八': 8,
  '九': 9,
};

/// 漢数字テキスト (例: "四十二") を整数に変換。 失敗で null。 1〜99 のみ対応。
int? _parseKanjiNumber(String s) {
  if (s.isEmpty) return null;
  if (s == '十') return 10;
  if (_kanjiDigit.containsKey(s)) return _kanjiDigit[s];
  final tenIdx = s.indexOf('十');
  if (tenIdx < 0) return null;
  final before = s.substring(0, tenIdx);
  final after = s.substring(tenIdx + 1);
  final tens = before.isEmpty ? 1 : (_kanjiDigit[before] ?? -1);
  final ones = after.isEmpty ? 0 : (_kanjiDigit[after] ?? -1);
  if (tens < 0 || ones < 0) return null;
  return tens * 10 + ones;
}

/// 整数 1〜99 を漢数字に変換。 範囲外は null。
String? _toKanjiNumber(int n) {
  if (n < 1 || n > 99) return null;
  if (n < 10) {
    return _kanjiDigit.entries.firstWhere((e) => e.value == n).key;
  }
  if (n == 10) return '十';
  final tens = n ~/ 10;
  final ones = n % 10;
  final tensStr = tens == 1
      ? '十'
      : '${_kanjiDigit.entries.firstWhere((e) => e.value == tens).key}十';
  if (ones == 0) return tensStr;
  return '$tensStr${_kanjiDigit.entries.firstWhere((e) => e.value == ones).key}';
}

/// ローマ数字 1〜20 のテーブル。
const List<String> _romanNumerals = [
  'I',
  'II',
  'III',
  'IV',
  'V',
  'VI',
  'VII',
  'VIII',
  'IX',
  'X',
