];

/// カタカナ五十音順 (1 文字)。
const List<String> _katakanaTable = [
  'ア',
  'イ',
  'ウ',
  'エ',
  'オ',
  'カ',
  'キ',
  'ク',
  'ケ',
  'コ',
  'サ',
  'シ',
