/// 全角数字 → 半角数字。
String _toHalfWidthDigits(String s) {
  return s.replaceAllMapped(RegExp(r'[\uFF10-\uFF19]'),
      (m) => String.fromCharCode(m.group(0)!.codeUnitAt(0) - 0xFEE0));
}

/// 半角数字 → 全角数字。
String _toFullWidthDigits(String s) {
  return s.replaceAllMapped(RegExp(r'[0-9]'),
      (m) => String.fromCharCode(m.group(0)!.codeUnitAt(0) + 0xFEE0));
}

/// 連番タイトルの「次の値」を返す。 認識できなければ null。
String? nextSequenceTitle(String text) {
  if (text.isEmpty) return null;

  // 連番ラベルとして扱う「数値の前の文章 (prefix)」 の最大長。 これを超えると
  // 通常の文章 (連番ではない) である確率が高いのでオートフィルしない
  // (= ユーザー要望: 数値の前の文章が長いときは関係ない文章の確率が高い)。
  // "Chapter " (8 文字) 等の一般的な短いラベルは通す。
  const maxSeqPrefixLen = 8;

  // 1. 末尾の半角アラビア数字 (例: "Chapter 5" → "Chapter 6")。
  final halfDigit = RegExp(r'^(.*?)(\d+)([^\d]*)$').firstMatch(text);
  if (halfDigit != null) {
    final prefix = halfDigit.group(1)!;
    if (prefix.length > maxSeqPrefixLen) return null;
    final num = int.parse(halfDigit.group(2)!);
    final suffix = halfDigit.group(3)!;
    return '$prefix${num + 1}$suffix';
  }

  // 2. 末尾の全角アラビア数字 (例: "第１章" → "第２章")。
  final fullDigit =
      RegExp(r'^(.*?)([\uFF10-\uFF19]+)([^\uFF10-\uFF19]*)$').firstMatch(text);
  if (fullDigit != null) {
    final prefix = fullDigit.group(1)!;
    if (prefix.length > maxSeqPrefixLen) return null;
    final num = int.parse(_toHalfWidthDigits(fullDigit.group(2)!));
    final suffix = fullDigit.group(3)!;
    final nextStr = _toFullWidthDigits('${num + 1}');
    return '$prefix$nextStr$suffix';
  }

  // 3. 漢数字シーケンス (例: "第一章" → "第二章")。
  //
  //    ユーザー要望「一覧等の漢数字に反応して二覧とか意味の分からない言葉が
  //      オートフィルで出てきてしまう」 への対応。
  //    旧実装は タイトル中に漢数字があれば無条件で +1 していたため、
  //      "一覧" → "二覧"、 "一般" → "二般"、 "一部" → "二部" のように、
  //      漢数字を含む 通常の単語 まで連番扱いして壊れていた。
  //    新実装: 「連番として使われている」 と判断できる文脈に限定する:
  //      (a) タイトル全体が漢数字のみ      (例: "三"        → "四")
  //      (b) 漢数字の直前が "第"           (例: "第一", "第3" 相当 → "第二")
  //      (c) 漢数字の直後が連番カウンタ    (例: "一章" → "二章", "三話" → "四話")
  //    これにより "一覧" 等の単語は (覧 が連番カウンタでないので) 除外される。
  final kanjiMatch =
      RegExp(r'^(.*?)([一二三四五六七八九十]+)([^一二三四五六七八九十]*)$').firstMatch(text);
  if (kanjiMatch != null) {
    final prefix = kanjiMatch.group(1)!;
    final kanjiPart = kanjiMatch.group(2)!;
    final suffix = kanjiMatch.group(3)!;
    // ── 連番として扱ってよい文脈か判定 ──
    final isWholeNumber = prefix.isEmpty && suffix.isEmpty;
    final hasDaiPrefix = prefix.endsWith('第');
    // 連番カウンタ (= 後続がこれらで始まるなら ordinal/連番とみなす)。
    // "覧"(一覧) "般"(一般) "緒"(一緒) "度"(一度) "角"(三角) 等の
    // 通常の語を構成する文字は含めない。
    const seqCounters = [
      '章',
      '話',
      '節',
      '巻',
      '編',
      '限',
      '講',
      '問',
      '幕',
      '号',
      '回',
      '番',
      '期',
      '弾',
      '課',
      '級',
      'ステップ',
      '段階',
      'ステージ',
      '限目',
      '回目',
      '番目',
      '日目',
      '週目',
      '時限',
      '時間目',
    ];
    final hasSeqCounter = seqCounters.any((c) => suffix.startsWith(c));
    if (isWholeNumber || hasDaiPrefix || hasSeqCounter) {
      final num = _parseKanjiNumber(kanjiPart);
      if (num != null && num < 99) {
        final nextStr = _toKanjiNumber(num + 1);
        if (nextStr != null) {
          return '$prefix$nextStr$suffix';
        }
      }
    }
  }

  // 4. ローマ数字 (例: "Section III" → "Section IV")。
  final romanMatch = RegExp(r'^(.*?)\b([IVX]+)\b([^IVX]*)$').firstMatch(text);
  if (romanMatch != null) {
    final prefix = romanMatch.group(1)!;
    final roman = romanMatch.group(2)!;
    final suffix = romanMatch.group(3)!;
    final idx = _romanNumerals.indexOf(roman);
    if (idx >= 0 && idx + 1 < _romanNumerals.length) {
      return '$prefix${_romanNumerals[idx + 1]}$suffix';
    }
  }

  // 5. 単独のアルファベット (例: "Section A" → "Section B")。
  final alphaMatch = RegExp(r'^(.*?)([A-Za-z])([^A-Za-z]*)$').firstMatch(text);
  if (alphaMatch != null) {
    final prefix = alphaMatch.group(1)!;
    final letter = alphaMatch.group(2)!;
    final suffix = alphaMatch.group(3)!;
    if (prefix.isEmpty || !RegExp(r'[A-Za-z]$').hasMatch(prefix)) {
      final code = letter.codeUnitAt(0);
      if ((code >= 65 && code < 90) || (code >= 97 && code < 122)) {
        final next = String.fromCharCode(code + 1);
        return '$prefix$next$suffix';
      }
    }
  }

  // 6. ひらがな / カタカナ 1 文字。
  if (text.length == 1) {
    final hIdx = _hiraganaTable.indexOf(text);
    if (hIdx >= 0 && hIdx + 1 < _hiraganaTable.length) {
      return _hiraganaTable[hIdx + 1];
    }
    final kIdx = _katakanaTable.indexOf(text);
    if (kIdx >= 0 && kIdx + 1 < _katakanaTable.length) {
      return _katakanaTable[kIdx + 1];
    }
  }

  return null;
}

// ═══════════════════════════════════════════════════════════════
//  PDF ハイライト永続化用データモデル
// ═══════════════════════════════════════════════════════════════
//
// PDF にユーザーが引いたマーカー (ハイライト) を、 アプリ再起動後も
// 復元できるよう永続化するためのモデル。 syncfusion の HighlightAnnotation
// は List<PdfTextLine> を要求するので、 各行ごとに「ページ番号 + 矩形」
// を保存しておき、 ロード時に PdfTextLine + HighlightAnnotation に
// 組み立て直して PdfViewerController.addAnnotation で再描画する。
//
// 保存先: SharedPreferences の 'pdfHighlights' キーに、
//         ノード ID → ハイライト一覧 のマップとして JSON で格納。

/// PDF テキストの 1 行分の矩形 (PDF 論理座標)。
class PdfHighlightLine {
  final int pageNumber;
  final double left;
  final double top;
  final double right;
  final double bottom;
  final String text;

  PdfHighlightLine({
    required this.pageNumber,
    required this.left,
    required this.top,
    required this.right,
    required this.bottom,
    required this.text,
  });

  Map<String, dynamic> toJson() => {
        'page': pageNumber,
        'l': left,
        't': top,
        'r': right,
        'b': bottom,
        'text': text,
      };

  factory PdfHighlightLine.fromJson(Map<String, dynamic> j) => PdfHighlightLine(
        pageNumber: (j['page'] as num?)?.toInt() ?? 1,
        left: (j['l'] as num?)?.toDouble() ?? 0,
        top: (j['t'] as num?)?.toDouble() ?? 0,
        right: (j['r'] as num?)?.toDouble() ?? 0,
        bottom: (j['b'] as num?)?.toDouble() ?? 0,
        text: j['text'] as String? ?? '',
      );
}

/// 1 つのハイライト (= マーカー)。 複数行に跨る選択は複数の lines を持つ。
class PdfHighlight {
  /// 一意 ID。 削除時の対象指定に使う。
  final String id;

  /// ハイライト対象の行ごとの矩形リスト。
  final List<PdfHighlightLine> lines;

  /// ハイライト元のテキスト (一覧表示・検索用)。
  final String text;

  /// 作成日時 (millis since epoch)。
  final int createdAt;

  /// マーカー色 (ARGB int)。 旧データには無いので fromJson で黄色フォールバック。
  final int colorValue;

  PdfHighlight({
    required this.id,
    required this.lines,
    required this.text,
    required this.createdAt,
    required this.colorValue,
  });

  Map<String, dynamic> toJson() => {
        'id': id,
        'lines': lines.map((l) => l.toJson()).toList(),
        'text': text,
        'createdAt': createdAt,
        'color': colorValue,
      };

  factory PdfHighlight.fromJson(Map<String, dynamic> j) => PdfHighlight(
        id: j['id'] as String? ??
            DateTime.now().millisecondsSinceEpoch.toString(),
        lines: (j['lines'] as List? ?? const [])
            .map((e) => PdfHighlightLine.fromJson(e as Map<String, dynamic>))
            .toList(),
        text: j['text'] as String? ?? '',
        createdAt: (j['createdAt'] as int?) ?? 0,
        // 旧データ互換: color が無ければ黄色 (#FFEB3B) をフォールバック
        colorValue: (j['color'] as int?) ?? 0xFFFFEB3B,
      );
}

/// Google検索ダイアログで保存される個別メモ項目。
///
/// PDF メモ (`PdfMemo`) と同じ思想で、 検索しながら気付いたことを項目別に
/// 蓄積していける。 各メモは:
///   - `text` : 本文。 1 行目がタイトル / 2 行目以降が内容、 という慣習。
///   - `snapshotUrl` : メモ作成時に WebView で開いていた URL のスナップショット。
///     「マップに追加」 する時の linkUrl として使う。 null = URL を含めない。
///   - `updatedAtMs` : ソート用 (新しい順表示)。
///
/// SharedPreferences に JSON 配列として永続化。
class GoogleSearchMemo {
  final String id;
  String text;
  String? snapshotUrl;
  int updatedAtMs;

  GoogleSearchMemo({
    required this.id,
    required this.text,
    this.snapshotUrl,
    int? updatedAtMs,
  }) : updatedAtMs = updatedAtMs ?? DateTime.now().millisecondsSinceEpoch;

  Map<String, dynamic> toJson() => {
        'id': id,
        'text': text,
        if (snapshotUrl != null) 'snapshotUrl': snapshotUrl,
        'updatedAtMs': updatedAtMs,
      };

  factory GoogleSearchMemo.fromJson(Map<String, dynamic> j) => GoogleSearchMemo(
        id: j['id'] as String,
        text: j['text'] as String? ?? '',
        snapshotUrl: j['snapshotUrl'] as String?,
        updatedAtMs: j['updatedAtMs'] as int? ?? 0,
      );

  /// 1 行目をタイトル相当に抽出するユーティリティ。 メモ一覧の見出し表示用。
  String get displayTitle {
    final lines = text.split('\n');
    final first = lines.isNotEmpty ? lines.first.trim() : '';
    return first.isEmpty ? '(無題)' : first;
  }
}

/// フラッシュカード 1 枚 (表 = front / 裏 = back)。 folderId でフォルダーに所属。
class Flashcard {
  final String id;
  String front;
  String back;
  String? folderId;
  Flashcard({required this.id, this.front = '', this.back = '', this.folderId});
  Map<String, dynamic> toJson() => {
        'id': id,
        'front': front,
        'back': back,
        if (folderId != null) 'folderId': folderId,
      };
  factory Flashcard.fromJson(Map<String, dynamic> j) => Flashcard(
        id: j['id'] as String? ?? '',
        front: (j['front'] as String?) ?? '',
        back: (j['back'] as String?) ?? '',
        folderId: j['folderId'] as String?,
      );
}

/// フラッシュカードをまとめるフォルダー (= ユーザー要望)。
class FlashcardFolder {
  final String id;
  String name;
  FlashcardFolder({required this.id, this.name = ''});
  Map<String, dynamic> toJson() => {'id': id, 'name': name};
  factory FlashcardFolder.fromJson(Map<String, dynamic> j) => FlashcardFolder(
      id: j['id'] as String? ?? '', name: (j['name'] as String?) ?? '');
}

class MindMapProvider extends ChangeNotifier {
  final List<MindMapPage> _pages = [];

  /// フォルダー一覧（フラット）。ページは `folderId` で所属フォルダーを参照。
  final List<MindMapFolder> _folders = [];
  int _currentPageIndex = 0;
  String? _selectedNodeId;

  /// AI 要約の元になった「資料の文脈」をページ ID をキーに保持する。
  /// `summarizeFileToNewPage` 完了時にここに登録し、
  /// `askAiFollowUpForPage(pageId, question)` で参照する。
  /// アプリ再起動で失われる (永続化していない) — まずは同一セッション内での
  /// 追加質問機能のみ。永続化は将来対応。
  final Map<String, AiPageContext> _aiPageContexts = {};

  /// 指定ページに AI 要約の文脈があれば true。UI 側で「追加質問」ボタンを
  /// 出すかどうかの判定に使う。
  bool hasAiContextForPage(String pageId) =>
      _aiPageContexts.containsKey(pageId);

  /// 指定ページの文脈を返す (無ければ null)。Q&A 履歴の表示等に使う。
  AiPageContext? getAiPageContext(String pageId) => _aiPageContexts[pageId];

  /// Ctrl+1〜9 のショートカットで切り替える際の「基準フォルダー」。
  /// null ならルート (フォルダー外のページ) ではなく、従来通り
  /// `_pages` 全体の絶対インデックスを使う (互換動作)。
  /// フォルダー ID が設定されていれば、そのフォルダーに所属するページの
  /// 上から N 番目を Ctrl+N で開く。
  String? _shortcutFolderId;
  String? get shortcutFolderId => _shortcutFolderId;
  static const _kShortcutFolderId = 'shortcut_folder_id';
  static const _storageKey = 'mindmap_pages_v3';
  static const _foldersStorageKey = 'mindmap_folders_v1';
  final _uuid = const Uuid();

  // ─── カレンダー機能 ────────────────────────────────────────────────
  // 日付文字列 (YYYY-MM-DD) → その日のイベント一覧
  // 端末ローカルに SharedPreferences で保存
  static const String _calendarStorageKey = 'calendar_events_v1';
  final Map<String, List<CalendarEvent>> _calendarEvents = {};
  Map<String, List<CalendarEvent>> get calendarEvents => _calendarEvents;

  // ─── カレンダーのグループ閲覧切替（Maxプラン限定） ────────────────────
  // Maxプランのユーザーは、同じグループ内の Pro 以上のメンバーの
  // カレンダーを「切り替えて」閲覧できる。
  //
  // _calendarViewingUid の値の意味：
  //   - kCalendarViewSelf  ('self')     : 自分のイベントのみ表示（既定）
  //   - kCalendarViewAll   ('*')        : 全員のイベントを統合表示（Max限定）
  //   - 特定のuid文字列                 : そのユーザーのイベントのみ表示（Max限定）
  //
  // Pro プランは「自分のみ」しか選べないので _calendarViewingUid は実質
  // self に固定。Free プランは同期機能自体がないので無関係。
  static const String kCalendarViewSelf = 'self';
  static const String kCalendarViewAll = '*';
  String _calendarViewingUid = kCalendarViewSelf;
  String get calendarViewingUid => _calendarViewingUid;

  /// 「全員」表示中か
  bool get isCalendarViewingAll => _calendarViewingUid == kCalendarViewAll;

  /// 「自分のみ」表示中か
  bool get isCalendarViewingSelf =>
      _calendarViewingUid == kCalendarViewSelf || _calendarViewingUid.isEmpty;

  /// 特定のユーザーを閲覧中の場合、その uid を返す（自分/全員ならnull）
  String? get calendarViewingSpecificUid {
    if (isCalendarViewingSelf || isCalendarViewingAll) return null;
    return _calendarViewingUid;
  }

  Future<void> setCalendarViewingUid(String value) async {
    _calendarViewingUid = value;
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString('calendarViewingUid', value);
    notifyListeners();
  }

  Future<void> _loadCalendarViewingUid() async {
    final prefs = await SharedPreferences.getInstance();
    _calendarViewingUid =
        prefs.getString('calendarViewingUid') ?? kCalendarViewSelf;
  }

  /// グループメンバー情報のキャッシュ（uid → メンバー情報）。
  /// `downloadCalendarEventsFromCloud` で更新される。
  /// Max プランのユーザー切替セレクタに表示する用。
  final Map<String, CalendarMemberInfo> _calendarMembers = {};

  /// Max プラン用: 閲覧可能なメンバー一覧（Pro+ かつ allowSharing=true、自分は除外）。
  /// displayName でソート済み。最大100件。
  List<CalendarMemberInfo> get viewableCalendarMembers {
    final list = _calendarMembers.values
        .where((m) => m.uid != _uid && m.allowSharing && m.isProOrAbove)
        .toList();
    list.sort((a, b) => a.displayName.compareTo(b.displayName));
    return list.take(100).toList(growable: false);
  }

  /// 指定 uid のキャッシュ済みメンバー情報を返す（無ければ null）。
  /// UI の閲覧者ピル等の表示用。
  CalendarMemberInfo? memberInfoForUid(String uid) => _calendarMembers[uid];

  /// 指定日 (YYYY-MM-DD) のイベントを返す。
  /// 現在の閲覧モード (`calendarViewingUid`) に応じてフィルタリングされる。
  List<CalendarEvent> eventsOn(String dateKey) {
    final all = _calendarEvents[dateKey] ?? const [];
    if (all.isEmpty) return all;
    final myUid = _uid;
    final viewing = _calendarViewingUid;

    // Pro プラン以下は他人のイベントを取得していないので、フィルタは
    // 実質「自分のもの」だけになる (= ownerUid == null か自分のもの)。
    // Maxでも「自分のみ」を選んでいる場合はここに入る。
    if (viewing == kCalendarViewSelf || viewing.isEmpty) {
      // ownerUid == null は自分の旧イベント（移行期）として扱う
      return all
          .where((e) => e.ownerUid == null || e.ownerUid == myUid)
          .toList(growable: false);
    }
    // Max プランで「全員」を選んでいる: 自分も他人もそのまま表示
    if (viewing == kCalendarViewAll) {
      return all;
    }
    // 特定のユーザーを選んでいる: そのユーザーのイベントだけ
    return all.where((e) => e.ownerUid == viewing).toList(growable: false);
  }

  // ─── カレンダーのタイムゾーン ───────────────────────────────────────
  // 言語設定によって標準時を変える。複数の標準時がある国 (米国/ロシア等)
  // では、ユーザーがプリセットから選んだりカスタムオフセット (分単位) を
  // 設定できる。null の場合は端末のローカル時刻 (DateTime.now()) を使う。
  /// 現在のオフセット (分単位)。null = 端末ローカル
  int? _calendarTzOffsetMinutes;
  int? get calendarTzOffsetMinutes => _calendarTzOffsetMinutes;

  /// オフセットのラベル (例: 'JST (UTC+9)', 'EST (UTC-5)' など、表示用)
  String _calendarTzLabel = '';
  String get calendarTzLabel => _calendarTzLabel;

  Future<void> setCalendarTimezone(int? offsetMinutes,
      {String label = ''}) async {
    _calendarTzOffsetMinutes = offsetMinutes;
    _calendarTzLabel = label;
    final prefs = await SharedPreferences.getInstance();
    if (offsetMinutes == null) {
      await prefs.remove('calendarTzOffset');
      await prefs.remove('calendarTzLabel');
    } else {
      await prefs.setInt('calendarTzOffset', offsetMinutes);
      await prefs.setString('calendarTzLabel', label);
    }
    notifyListeners();
  }

  /// カレンダーで「今」を表す DateTime を返す。
  /// _calendarTzOffsetMinutes が設定されていれば、UTC 時刻にそのオフセットを
  /// 加えた値を返す (DateTime は naive: ローカル時刻として扱われる)。
  /// null なら端末ローカル時刻。
  DateTime calendarNow() {
    if (_calendarTzOffsetMinutes == null) return DateTime.now();
    final utcNow = DateTime.now().toUtc();
    return utcNow.add(Duration(minutes: _calendarTzOffsetMinutes!));
  }

  /// 言語別の代表的なタイムゾーンプリセット。
  /// 各エントリ: [label, offsetMinutes]
  /// 複数候補がある言語は複数の選択肢を返す。
  /// 実際の標準時/夏時間は厳密に追わず、代表値で扱う (簡易実装)。
  List<List<Object>> presetTimezonesFor(String lang) {
    switch (lang) {
      case 'ja':
        return [
          ['JST (UTC+9)', 9 * 60],
        ];
      case 'en':
        // 英語圏: 米国/英国/カナダ/オーストラリア/インドなど
        return [
          ['US Eastern (UTC-5)', -5 * 60],
          ['US Central (UTC-6)', -6 * 60],
          ['US Mountain (UTC-7)', -7 * 60],
          ['US Pacific (UTC-8)', -8 * 60],
          ['US Alaska (UTC-9)', -9 * 60],
          ['US Hawaii (UTC-10)', -10 * 60],
          ['UK (UTC+0)', 0],
          ['Central Europe (UTC+1)', 60],
          ['India (UTC+5:30)', 5 * 60 + 30],
          ['Australia East (UTC+10)', 10 * 60],
          ['NZ (UTC+12)', 12 * 60],
        ];
      case 'zh':
        return [
          ['CST (UTC+8)', 8 * 60],
          ['HKT (UTC+8)', 8 * 60],
          ['Taipei (UTC+8)', 8 * 60],
        ];
      case 'ko':
        return [
          ['KST (UTC+9)', 9 * 60],
        ];
      case 'es':
        // スペイン本土 / カナリア / ラテンアメリカ各国
        return [
          ['España (UTC+1)', 60],
          ['Canarias (UTC+0)', 0],
          ['México (UTC-6)', -6 * 60],
          ['Argentina (UTC-3)', -3 * 60],
          ['Colombia (UTC-5)', -5 * 60],
          ['Chile (UTC-3)', -3 * 60],
          ['Perú (UTC-5)', -5 * 60],
        ];
      case 'fr':
        return [
          ['France (UTC+1)', 60],
          ['Réunion (UTC+4)', 4 * 60],
          ['Polynésie (UTC-10)', -10 * 60],
          ['Guyane (UTC-3)', -3 * 60],
          ['Québec (UTC-5)', -5 * 60],
        ];
      case 'de':
        return [
          ['Deutschland (UTC+1)', 60],
          ['Österreich (UTC+1)', 60],
          ['Schweiz (UTC+1)', 60],
        ];
      case 'pt':
        // ポルトガル本土 / アゾレス / ブラジル
        return [
          ['Lisboa (UTC+0)', 0],
          ['Açores (UTC-1)', -60],
          ['Brasília (UTC-3)', -3 * 60],
          ['Manaus (UTC-4)', -4 * 60],
          ['Acre (UTC-5)', -5 * 60],
        ];
      case 'ru':
        // ロシアは 11 のタイムゾーン
        return [
          ['Калининград (UTC+2)', 2 * 60],
          ['Москва (UTC+3)', 3 * 60],
          ['Самара (UTC+4)', 4 * 60],
          ['Екатеринбург (UTC+5)', 5 * 60],
          ['Омск (UTC+6)', 6 * 60],
          ['Красноярск (UTC+7)', 7 * 60],
          ['Иркутск (UTC+8)', 8 * 60],
          ['Якутск (UTC+9)', 9 * 60],
          ['Владивосток (UTC+10)', 10 * 60],
          ['Магадан (UTC+11)', 11 * 60],
          ['Камчатка (UTC+12)', 12 * 60],
        ];
    }
    return [];
  }

  // ─── 祝日機能 ───────────────────────────────────────────────────────
  // appLanguage に応じた国の祝日を表示する。実装方針:
  //   * 固定日の祝日 (1月1日の元日など) は static map で返す
  //   * 計算可能な祝日 (米国感謝祭=11月第4木曜日など) は規則関数で計算
  //   * イースター系は computus アルゴリズムで日曜日を算出
  //   * 日本の春分/秋分はユリウス暦近似式で
  // 祝日は「カレンダーイベント」とは別レイヤー扱いで、編集/削除はできない。

  /// 計算した祝日を年単位でキャッシュ (再計算抑制)
  /// key = 'lang-year' 例: 'ja-2025'
  final Map<String, Map<String, String>> _holidayCache = {};

  /// 指定言語/年の祝日マップを返す。{ '2025-01-01': '元日', ... }
  Map<String, String> holidaysFor(String lang, int year) {
    final cacheKey = '$lang-$year';
    final cached = _holidayCache[cacheKey];
    if (cached != null) return cached;
    final map = <String, String>{};
    switch (lang) {
      case 'ja':
        _addJapaneseHolidays(map, year);
        break;
      case 'en':
        _addUSHolidays(map, year);
        break;
      case 'zh':
        _addChineseHolidays(map, year);
        break;
      case 'ko':
        _addKoreanHolidays(map, year);
        break;
      case 'es':
        _addSpanishHolidays(map, year);
        break;
      case 'fr':
        _addFrenchHolidays(map, year);
        break;
      case 'de':
        _addGermanHolidays(map, year);
        break;
      case 'pt':
        _addPortugueseHolidays(map, year);
        break;
      case 'ru':
        _addRussianHolidays(map, year);
        break;
    }
    _holidayCache[cacheKey] = map;
    return map;
  }

  /// 指定日 (YYYY-MM-DD) が祝日ならその名前を返す。違えば null。
  /// 現在のアプリ言語の祝日のみ対象。
  String? holidayNameOn(String dateKey) {
    final parts = dateKey.split('-');
    if (parts.length < 3) return null;
    final year = int.tryParse(parts[0]);
    if (year == null) return null;
    final map = holidaysFor(_appLanguage, year);
    return map[dateKey];
  }

  /// 日付フォーマット用ユーティリティ (YYYY-MM-DD)
  String _fmtDate(int y, int m, int d) {
    final mm = m.toString().padLeft(2, '0');
    final dd = d.toString().padLeft(2, '0');
    return '$y-$mm-$dd';
  }

  /// 復活祭 (イースター) の日曜日を返す。Computus アルゴリズム (Anonymous Gregorian)。
  /// イースターから派生する祝日 (聖金曜日 / 月曜日) で使う。
  DateTime _easterSunday(int year) {
    final a = year % 19;
    final b = year ~/ 100;
    final c = year % 100;
    final d = b ~/ 4;
    final e = b % 4;
    final f = (b + 8) ~/ 25;
    final g = (b - f + 1) ~/ 3;
    final h = (19 * a + b - d - g + 15) % 30;
    final i = c ~/ 4;
    final k = c % 4;
    final l = (32 + 2 * e + 2 * i - h - k) % 7;
    final m = (a + 11 * h + 22 * l) ~/ 451;
    final month = (h + l - 7 * m + 114) ~/ 31;
    final day = ((h + l - 7 * m + 114) % 31) + 1;
    return DateTime(year, month, day);
  }

  /// 指定月の N 番目の指定曜日を返す (例: 11月第4木曜日=米国感謝祭)。
  DateTime _nthWeekdayOfMonth(int year, int month, int nth, int weekday) {
    var date = DateTime(year, month, 1);
    var count = 0;
    while (true) {
      if (date.weekday == weekday) {
        count++;
        if (count == nth) return date;
      }
      date = date.add(const Duration(days: 1));
      if (date.month != month) return DateTime(year, month, 1); // fallback
    }
  }

  /// 指定月の最後の指定曜日を返す (例: 5月最終月曜日=米国メモリアルデー)。
  DateTime _lastWeekdayOfMonth(int year, int month, int weekday) {
    var date = (month == 12)
        ? DateTime(year + 1, 1, 1).subtract(const Duration(days: 1))
        : DateTime(year, month + 1, 1).subtract(const Duration(days: 1));
    while (date.weekday != weekday) {
      date = date.subtract(const Duration(days: 1));
    }
    return date;
  }

  /// ── 日本の祝日 ──
  /// 国民の祝日に関する法律に基づく主要な祝日 (2025年時点)
  void _addJapaneseHolidays(Map<String, String> m, int y) {
    m[_fmtDate(y, 1, 1)] = '元日';
    // 成人の日: 1月第2月曜
    m[_dateKeyOf(_nthWeekdayOfMonth(y, 1, 2, DateTime.monday))] = '成人の日';
    m[_fmtDate(y, 2, 11)] = '建国記念の日';
    m[_fmtDate(y, 2, 23)] = '天皇誕生日';
    // 春分の日 (近似式: 国立天文台公表で確定するが、概ね 3/20 or 3/21)
    final shunbun = _vernalEquinoxJP(y);
    m[_fmtDate(y, 3, shunbun)] = '春分の日';
    m[_fmtDate(y, 4, 29)] = '昭和の日';
    m[_fmtDate(y, 5, 3)] = '憲法記念日';
    m[_fmtDate(y, 5, 4)] = 'みどりの日';
    m[_fmtDate(y, 5, 5)] = 'こどもの日';
    // 海の日: 7月第3月曜
    m[_dateKeyOf(_nthWeekdayOfMonth(y, 7, 3, DateTime.monday))] = '海の日';
    m[_fmtDate(y, 8, 11)] = '山の日';
    // 敬老の日: 9月第3月曜
    m[_dateKeyOf(_nthWeekdayOfMonth(y, 9, 3, DateTime.monday))] = '敬老の日';
    final shubun = _autumnalEquinoxJP(y);
    m[_fmtDate(y, 9, shubun)] = '秋分の日';
    // スポーツの日: 10月第2月曜
    m[_dateKeyOf(_nthWeekdayOfMonth(y, 10, 2, DateTime.monday))] = 'スポーツの日';
    m[_fmtDate(y, 11, 3)] = '文化の日';
    m[_fmtDate(y, 11, 23)] = '勤労感謝の日';
  }

  /// 日本の春分の日 (1900〜2099 の近似式)
  int _vernalEquinoxJP(int y) {
    if (y >= 1900 && y <= 1979) {
      return ((20.8357 + 0.242194 * (y - 1980) - (y - 1980) ~/ 4)).floor();
    } else if (y >= 1980 && y <= 2099) {
      return ((20.8431 + 0.242194 * (y - 1980) - (y - 1980) ~/ 4)).floor();
    } else if (y >= 2100 && y <= 2150) {
      return ((21.851 + 0.242194 * (y - 1980) - (y - 1980) ~/ 4)).floor();
    }
    return 21; // フォールバック
  }

  /// 日本の秋分の日 (1900〜2099 の近似式)
  int _autumnalEquinoxJP(int y) {
    if (y >= 1900 && y <= 1979) {
      return ((23.2588 + 0.242194 * (y - 1980) - (y - 1980) ~/ 4)).floor();
    } else if (y >= 1980 && y <= 2099) {
      return ((23.2488 + 0.242194 * (y - 1980) - (y - 1980) ~/ 4)).floor();
    } else if (y >= 2100 && y <= 2150) {
      return ((24.2488 + 0.242194 * (y - 1980) - (y - 1980) ~/ 4)).floor();
    }
    return 23;
  }

  String _dateKeyOf(DateTime d) => _fmtDate(d.year, d.month, d.day);

  /// ── 米国の祝日 (連邦祝日) ──
  void _addUSHolidays(Map<String, String> m, int y) {
    m[_fmtDate(y, 1, 1)] = "New Year's Day";
    // Martin Luther King Jr. Day: 1月第3月曜
    m[_dateKeyOf(_nthWeekdayOfMonth(y, 1, 3, DateTime.monday))] =
        "Martin Luther King Jr. Day";
    // Presidents' Day: 2月第3月曜
    m[_dateKeyOf(_nthWeekdayOfMonth(y, 2, 3, DateTime.monday))] =
        "Presidents' Day";
    // Memorial Day: 5月最終月曜
    m[_dateKeyOf(_lastWeekdayOfMonth(y, 5, DateTime.monday))] = 'Memorial Day';
    m[_fmtDate(y, 6, 19)] = 'Juneteenth';
    m[_fmtDate(y, 7, 4)] = 'Independence Day';
    // Labor Day: 9月第1月曜
    m[_dateKeyOf(_nthWeekdayOfMonth(y, 9, 1, DateTime.monday))] = 'Labor Day';
    // Columbus Day: 10月第2月曜
    m[_dateKeyOf(_nthWeekdayOfMonth(y, 10, 2, DateTime.monday))] =
        'Columbus Day';
    m[_fmtDate(y, 11, 11)] = 'Veterans Day';
    // Thanksgiving: 11月第4木曜
    m[_dateKeyOf(_nthWeekdayOfMonth(y, 11, 4, DateTime.thursday))] =
        'Thanksgiving';
    m[_fmtDate(y, 12, 25)] = 'Christmas Day';
  }

