  // ─── カレンダーイベントの Undo スタック ──
  // 編集/追加/削除の前に現在の全イベント状態をスナップショット保存
  final List<Map<String, List<CalendarEvent>>> _calendarUndoStack = [];
  static const int _calendarUndoLimit = 50;

  void _pushCalendarUndo() {
    // Deep copy (CalendarEvent は immutable なので Map だけ浅コピー)
    final snap = <String, List<CalendarEvent>>{};
    _calendarEvents.forEach((k, v) {
      snap[k] = List<CalendarEvent>.from(v);
    });
    _calendarUndoStack.add(snap);
    if (_calendarUndoStack.length > _calendarUndoLimit) {
      _calendarUndoStack.removeAt(0);
    }
  }

  /// カレンダー操作を元に戻す
  /// 戻り値: 元に戻せた場合 true
  Future<bool> undoCalendarEvents() async {
    if (_calendarUndoStack.isEmpty) return false;
    final snap = _calendarUndoStack.removeLast();
    _calendarEvents
      ..clear()
      ..addAll(snap);
    await _saveCalendarEvents();
    notifyListeners();
    return true;
  }

  bool get canUndoCalendar => _calendarUndoStack.isNotEmpty;

  // ─── カレンダー同期の送信先設定（初回選択後は永続化）──
  // 値: 'firebase' | 'google' | 'both'
  static const String _calendarSyncDestKey = 'calendar_sync_destination';
  String _calendarSyncDestination = '';
  String get calendarSyncDestination => _calendarSyncDestination;
  Future<void> setCalendarSyncDestination(String dest) async {
    _calendarSyncDestination = dest;
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString(_calendarSyncDestKey, dest);
    } catch (_) {}
    notifyListeners();
  }

  // ダウンロード側の送信元設定（選択後は永続化）
  // 値: 'firebase' | 'google'
  static const String _calendarPullSrcKey = 'calendar_pull_source';
  String _calendarPullSource = '';
  String get calendarPullSource => _calendarPullSource;
  Future<void> setCalendarPullSource(String src) async {
    _calendarPullSource = src;
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString(_calendarPullSrcKey, src);
    } catch (_) {}
    notifyListeners();
  }

  /// 「次回から聞かない」設定をリセット（設定画面から呼べる）
  Future<void> resetCalendarSyncChoices() async {
    _calendarSyncDestination = '';
    _calendarPullSource = '';
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.remove(_calendarSyncDestKey);
      await prefs.remove(_calendarPullSrcKey);
    } catch (_) {}
    notifyListeners();
  }

  /// ────────────────────────────────────────────────────────────
  /// カレンダーイベントの Firebase 同期（Ctrl+S / Ctrl+D 用）
  /// マップと同じ同期グループの下にカレンダーイベントも保存する
  /// ────────────────────────────────────────────────────────────

  /// すべてのカレンダーイベントを Firestore に保存
  /// 戻り値: (success, error?, count)
  ///
  /// ── per-user モデル ──
  /// calendar/{uid} に自分のイベントだけを書き込む。
  /// 共有フラグがOFFなら書き込まない（エラーを返す）。
  /// 他メンバーのイベント（ownerUid != myUid）はスキップ。
  Future<({bool success, String? error, int count})>
      uploadCalendarEventsToCloud() async {
    if (!_firebaseEnabled || _syncGroupId == null || _idToken == null) {
      return (success: false, error: 'not_in_sync_group', count: 0);
    }
    if (_uid == null) {
      return (success: false, error: 'no_uid', count: 0);
    }
    if (!_calendarGroupSharingEnabled) {
      return (success: false, error: 'sharing_disabled', count: 0);
    }
    try {
      await _ensureFreshToken();
      // 自分のイベントだけを抽出（ownerUid == null or ownerUid == _uid）
      // アップロード時に ownerUid を自分の uid で刻印する
      final myUid = _uid!;
      final myEvents = <String, dynamic>{};
      int count = 0;
      _calendarEvents.forEach((dateKey, list) {
        final mine = list
            .where((e) => e.ownerUid == null || e.ownerUid == myUid)
            .map((e) {
          // ownerUid を刻印（既存イベントの移行）
          final stamped = CalendarEvent(
            id: e.id,
            title: e.title,
            memo: e.memo,
            startTime: e.startTime,
            endTime: e.endTime,
            colorArgb: e.colorArgb,
            googleId: e.googleId,
            ownerUid: myUid,
            ownerName: _displayName,
          );
          return stamped.toJson();
        }).toList();
        if (mine.isNotEmpty) {
          myEvents[dateKey] = mine;
          count += mine.length;
        }
      });
      final eventsJson = jsonEncode(myEvents);

      // per-user ドキュメントに書き込み
      final url = '$_firestoreBaseUrl/groups/$_syncGroupId/calendar/$myUid';
      final res = await http.patch(
        Uri.parse('$url?updateMask.fieldPaths=json'
            '&updateMask.fieldPaths=updatedAt'
            '&updateMask.fieldPaths=ownerUid'
            '&updateMask.fieldPaths=ownerName'),
        headers: {
          'Authorization': 'Bearer $_idToken',
          'Content-Type': 'application/json',
        },
        body: jsonEncode({
          'fields': {
            'json': {'stringValue': eventsJson},
            'ownerUid': {'stringValue': myUid},
            'ownerName': {'stringValue': _displayName ?? '匿名'},
            'updatedAt': {
              'timestampValue': DateTime.now().toUtc().toIso8601String(),
            },
          },
        }),
      );
      if (res.statusCode == 200 || res.statusCode == 201) {
        // Google Calendar 側にも未同期イベントをプッシュ
        if (gcalIsAuthenticated && _gcalAutoSyncEnabled) {
          for (final entry in _calendarEvents.entries.toList()) {
            final dk = entry.key;
            for (final ev in List.from(entry.value)) {
              if (ev.googleId != null || ev.isGoogleEvent) continue;
              // 他人のイベントは Google Calendar へ送らない
              if (ev.ownerUid != null && ev.ownerUid != myUid) continue;
              final gid = await _gcalPushCreate(dk, ev);
              if (gid != null) {
                final cur = _calendarEvents[dk];
                if (cur != null) {
                  final idx = cur.indexWhere((e) => e.id == ev.id);
                  if (idx >= 0) {
                    cur[idx] = CalendarEvent(
                      id: ev.id,
                      title: ev.title,
                      memo: ev.memo,
                      startTime: ev.startTime,
                      endTime: ev.endTime,
                      colorArgb: ev.colorArgb,
                      googleId: gid,
                      ownerUid: myUid,
                      ownerName: _displayName,
                    );
                  }
                }
              }
            }
          }
          await _saveCalendarEvents();
          notifyListeners();
        }
        return (success: true, error: null, count: count);
      }
      return (
        success: false,
        error: 'http_${res.statusCode}: ${res.body}',
        count: 0,
      );
    } catch (e) {
      return (success: false, error: e.toString(), count: 0);
    }
  }

  /// Firestore + Google Calendar からカレンダーイベントをダウンロード
  ///
  /// ── per-user モデル ──
  /// 1) groups/{gid}/members を取得 → allowCalendarSharing=true の uid を集める
  /// 2) groups/{gid}/calendar/ サブコレクションを列挙
  /// 3) ownerUid が許可された uid のドキュメントだけをマージ
  /// 4) 自分のイベント（ownerUid == 自分）も含む
  Future<({bool success, String? error, int count})>
      downloadCalendarEventsFromCloud() async {
    if (!_firebaseEnabled || _syncGroupId == null || _idToken == null) {
      // Firebase 未参加でも Google Calendar 認証済みならプル可能
      if (gcalIsAuthenticated) {
        final r = await gcalPullAll();
        return (success: r.success, error: r.error, count: r.eventCount);
      }
      return (success: false, error: 'not_in_sync_group', count: 0);
    }
    try {
      await _ensureFreshToken();
      final gid = _syncGroupId!;
      final myUid = _uid;

      // 1) メンバー一覧取得 → 共有ON の uid セット
      // ここで plan 情報も一緒に取得して `_calendarMembers` を更新する。
      // Max プランのユーザー切替セレクタが Pro+ メンバーを列挙するために使う。
      final allowed = <String>{};
      final nameByUid = <String, String>{};
      _calendarMembers.clear();
      try {
        final membersUrl = '$_firestoreBaseUrl/groups/$gid/members';
        final mRes = await http.get(
          Uri.parse(membersUrl),
          headers: {'Authorization': 'Bearer $_idToken'},
        );
        if (mRes.statusCode == 200) {
          final mData = jsonDecode(mRes.body) as Map<String, dynamic>;
          final docs = mData['documents'] as List<dynamic>? ?? [];
          for (final doc in docs) {
            final fields = doc['fields'] as Map<String, dynamic>? ?? {};
            final uid = _firestoreStr(fields['uid']);
            if (uid == null || uid.isEmpty) continue;
            final allow =
                fields['allowCalendarSharing']?['booleanValue'] as bool? ??
                    false;
            final name = _firestoreStr(fields['displayName']);
            if (name != null && name.isNotEmpty) nameByUid[uid] = name;
            // member doc の plan が無い場合 (旧データ) は 'free' 扱い。
            // 新規/再ログイン時に _registerMember 経由で書き込まれて埋まる。
            final plan = _firestoreStr(fields['plan']) ?? 'free';
            // _calendarMembers にキャッシュ (UI のセレクタ用)
            _calendarMembers[uid] = CalendarMemberInfo(
              uid: uid,
              displayName: name ?? '匿名',
              plan: plan,
              allowSharing: allow,
            );
            // 「allowed」 = サブコレクション列挙時に他人のドキュメントを
            // 取り込む対象。プランによって絞る。
            //   Maxプラン: Pro+ かつ allowSharing=true のメンバーを許可
            //   Pro/Free/その他: 他人は一切取り込まない
            if (allow && uid != myUid) {
              // カレンダーのグループ閲覧は Pro 以上で解禁 (旧仕様は Max 限定)。
              final canViewOthers = isProUnlocked;
              if (canViewOthers) {
                final isProPlus = plan == 'pro' ||
                    plan == 'max' ||
                    plan == 'developer' ||
                    plan == 'coupon';
                if (isProPlus) allowed.add(uid);
              }
            }
          }
        }
      } catch (e) {
        debugPrint('fetchMembers error (download calendar): $e');
      }
      _calendarSharingAllowedUids
        ..clear()
        ..addAll(allowed);

      // 他人のイベントを一切見れないプラン (Free/Pro) の場合、過去に Max
      // 状態でDLして残っている他人のイベントを掃除する。
      // (= ダウングレード後にゴーストイベントが残らないように)
      // カレンダーのグループ閲覧は Pro 以上で解禁 (旧仕様は Max 限定)。
      final canViewOthersNow = isProUnlocked;
      if (!canViewOthersNow) {
        // 「全員」モード/特定ユーザーモードに残っていたら自分のみに戻す
        if (_calendarViewingUid == kCalendarViewAll ||
            (_calendarViewingUid != kCalendarViewSelf &&
                _calendarViewingUid != myUid)) {
          _calendarViewingUid = kCalendarViewSelf;
          // ignore: discarded_futures
          SharedPreferences.getInstance().then(
              (p) => p.setString('calendarViewingUid', kCalendarViewSelf));
        }
      } else {
        // Maxプランで「特定ユーザー」を見ていたが、そのユーザーが
        // グループから抜けた / プランを下げた等で閲覧不可になっていたら自分に戻す
        final viewing = _calendarViewingUid;
        if (viewing != kCalendarViewSelf &&
            viewing != kCalendarViewAll &&
            viewing != myUid) {
          final m = _calendarMembers[viewing];
          if (m == null || !m.allowSharing || !m.isProOrAbove) {
            _calendarViewingUid = kCalendarViewSelf;
            // ignore: discarded_futures
            SharedPreferences.getInstance().then(
                (p) => p.setString('calendarViewingUid', kCalendarViewSelf));
          }
        }
      }

      // 自分のイベントは自分のフラグが ON のときだけ自分の uid も「許可」扱い
      // （= 自分の calendar/{uid} を読んで復元する）
      // OFF のときは自分のクラウドデータを読み込まずローカルに任せる
      if (myUid != null && _calendarGroupSharingEnabled) {
        allowed.add(myUid);
      }

      // 2) calendar/ サブコレクション列挙
      final calUrl = '$_firestoreBaseUrl/groups/$gid/calendar';
      final cRes = await http.get(
        Uri.parse(calUrl),
        headers: {'Authorization': 'Bearer $_idToken'},
      );

      // 3) まず自分のローカルイベント（自分のもの）は保持
      //    クラウドから来た他人のイベントだけ置き換え
      final myLocal = <String, List<CalendarEvent>>{};
      _calendarEvents.forEach((dk, list) {
        final mine = list
            .where((e) => e.ownerUid == null || e.ownerUid == myUid)
            .toList();
        if (mine.isNotEmpty) myLocal[dk] = mine;
      });

      _pushCalendarUndo();
      _gcalAutoSyncEnabled = false;
      int count = 0;
      try {
        _calendarEvents.clear();

        // 自分のローカルイベントを先に戻す
        myLocal.forEach((dk, list) {
          _calendarEvents[dk] = List.from(list);
          count += list.length;
        });

        // 3a) 404 = calendar コレクションがまだ空
        //     200 = ドキュメント列挙成功
        //     それ以外 = エラーだが致命的ではない（レガシー doc を試す）
        if (cRes.statusCode == 200) {
          final cData = jsonDecode(cRes.body) as Map<String, dynamic>;
          final cdocs = cData['documents'] as List<dynamic>? ?? [];
          for (final doc in cdocs) {
            try {
              final name = doc['name'] as String? ?? '';
              // /groups/{gid}/calendar/{uid} の末尾 uid を取得
              final parts = name.split('/');
              final ownerId = parts.isNotEmpty ? parts.last : '';
              if (ownerId.isEmpty || ownerId == 'events') {
                // 'events' はレガシー単一doc → 後で処理
                continue;
              }
              // 自分以外は allowed に入っていないとスキップ
              if (ownerId != myUid && !allowed.contains(ownerId)) continue;
              // 自分のドキュメントは自分がOFFなら無視（すでに myLocal で復元済み）
              if (ownerId == myUid && !_calendarGroupSharingEnabled) {
                continue;
              }
              final fields = doc['fields'] as Map<String, dynamic>? ?? {};
              final jsonStr = _firestoreStr(fields['json']);
              if (jsonStr == null || jsonStr.isEmpty) continue;
              final ownerName = _firestoreStr(fields['ownerName']) ??
                  nameByUid[ownerId] ??
                  '匿名';
              final parsed = jsonDecode(jsonStr) as Map<String, dynamic>;
              parsed.forEach((dateKey, list) {
                if (list is! List) return;
                for (final j in list) {
                  try {
                    final ev =
                        CalendarEvent.fromJson(j as Map<String, dynamic>);
                    // 自分のドキュメントは myLocal として既に置いてあるので
                    // クラウド版で上書き（クラウドが正）
                    final tagged = CalendarEvent(
                      id: ev.id,
                      title: ev.title,
                      memo: ev.memo,
                      startTime: ev.startTime,
                      endTime: ev.endTime,
                      colorArgb: ev.colorArgb,
                      googleId: ev.googleId,
                      ownerUid: ownerId,
                      ownerName: ev.ownerName ?? ownerName,
                    );
                    if (ownerId == myUid) {
                      // 自分: myLocal で入れたものを差し替え
                      final cur =
                          _calendarEvents.putIfAbsent(dateKey, () => []);
                      final idx = cur.indexWhere((x) => x.id == tagged.id);
                      if (idx >= 0) {
                        cur[idx] = tagged;
                      } else {
                        cur.add(tagged);
                        count++;
                      }
                    } else {
                      // 他人: 新規追加
                      final cur =
                          _calendarEvents.putIfAbsent(dateKey, () => []);
                      cur.add(tagged);
                      count++;
                    }
                  } catch (_) {}
                }
              });
            } catch (_) {}
          }
        } else if (cRes.statusCode == 404) {
          // コレクション未作成: レガシー 'calendar/events' を試す
          try {
            final legacyUrl = '$_firestoreBaseUrl/groups/$gid/calendar/events';
            final lRes = await http.get(
              Uri.parse(legacyUrl),
              headers: {'Authorization': 'Bearer $_idToken'},
            );
            if (lRes.statusCode == 200 && _calendarGroupSharingEnabled) {
              final lData = jsonDecode(lRes.body) as Map<String, dynamic>;
              final fields = lData['fields'] as Map<String, dynamic>?;
              final jsonStr = fields?['json']?['stringValue'] as String?;
              if (jsonStr != null) {
                final parsed = jsonDecode(jsonStr) as Map<String, dynamic>;
                parsed.forEach((dateKey, list) {
                  if (list is List) {
                    for (final j in list) {
                      try {
                        final ev =
                            CalendarEvent.fromJson(j as Map<String, dynamic>);
                        // レガシーは自分のものとして扱う
                        final cur =
                            _calendarEvents.putIfAbsent(dateKey, () => []);
                        if (!cur.any((x) => x.id == ev.id)) {
                          cur.add(CalendarEvent(
                            id: ev.id,
                            title: ev.title,
                            memo: ev.memo,
                            startTime: ev.startTime,
                            endTime: ev.endTime,
                            colorArgb: ev.colorArgb,
                            googleId: ev.googleId,
                            ownerUid: myUid,
                            ownerName: _displayName,
                          ));
                          count++;
                        }
                      } catch (_) {}
                    }
                  }
                });
              }
            }
          } catch (_) {}
        }

        // 日付ごとにソート
        _calendarEvents.forEach((_, list) => _sortDayEvents(list));

        await _saveCalendarEvents();
        notifyListeners();
        if (gcalIsAuthenticated) {
          final r = await gcalPullAll();
          return (
            success: true,
            error: null,
            count: count + r.eventCount,
          );
        }
        return (success: true, error: null, count: count);
      } finally {
        _gcalAutoSyncEnabled = true;
      }
    } catch (e) {
      return (success: false, error: e.toString(), count: 0);
    }
  }

  /// イベントを追加
  Future<void> addCalendarEvent(String dateKey, String title,
      {String? memo,
      String? startTime,
      String? endTime,
      int? colorArgb}) async {
    _pushCalendarUndo();
    final list = _calendarEvents.putIfAbsent(dateKey, () => []);
    final newEvent = CalendarEvent(
      id: _uuid.v4(),
      title: title,
      memo: memo,
      startTime: startTime,
      endTime: endTime,
      colorArgb: colorArgb,
      // 所有者を自分として刻印（グループ共有時のフィルタ用）
      ownerUid: _uid,
      ownerName: _displayName,
    );
    list.add(newEvent);
    _sortDayEvents(list);
    await _saveCalendarEvents();
    notifyListeners();
    // Google Calendar に非同期でプッシュ（認証済み & 自動同期 ON のとき）
    if (gcalIsAuthenticated && _gcalAutoSyncEnabled) {
      // 待たずにバックグラウンド実行 → 成功したら googleId を書き戻し
      _gcalPushCreate(dateKey, newEvent).then((gid) async {
        if (gid != null) {
          final cur = _calendarEvents[dateKey];
          if (cur == null) return;
          final idx = cur.indexWhere((e) => e.id == newEvent.id);
          if (idx < 0) return;
          cur[idx] = CalendarEvent(
            id: newEvent.id,
            title: newEvent.title,
            memo: newEvent.memo,
            startTime: newEvent.startTime,
            endTime: newEvent.endTime,
            colorArgb: newEvent.colorArgb,
            googleId: gid,
            ownerUid: _uid,
            ownerName: _displayName,
          );
          await _saveCalendarEvents();
          notifyListeners();
        }
      });
    }
  }

  /// イベントを削除
  /// 他人の（共有されてきた）イベントは削除不可（UI側でも抑止しているが二重チェック）
  Future<void> removeCalendarEvent(String dateKey, String eventId) async {
    final list = _calendarEvents[dateKey];
    if (list == null) return;
    final idx = list.indexWhere((e) => e.id == eventId);
    if (idx < 0) return;
    final target = list[idx];
    if (target.isOthersEvent(_uid)) {
      // 他人のイベントは削除しない（サイレントに無視）
      return;
    }
    _pushCalendarUndo();
    // 削除前に googleId を記録しておく
    final String? googleIdToDelete = target.googleId;
    list.removeAt(idx);
    if (list.isEmpty) {
      _calendarEvents.remove(dateKey);
    }
    await _saveCalendarEvents();
    notifyListeners();
    // Google Calendar 上も削除
    if (googleIdToDelete != null &&
        gcalIsAuthenticated &&
        _gcalAutoSyncEnabled) {
      _gcalPushDelete(googleIdToDelete);
    }
  }

  /// イベントを更新
  /// 他人の（共有されてきた）イベントは更新不可
  Future<void> updateCalendarEvent(String dateKey, String eventId, String title,
      {String? memo,
      String? startTime,
      String? endTime,
      int? colorArgb}) async {
    final list = _calendarEvents[dateKey];
    if (list == null) return;
    final idx = list.indexWhere((e) => e.id == eventId);
    if (idx < 0) return;
    final old = list[idx];
    if (old.isOthersEvent(_uid)) {
      // 他人のイベントは更新しない
      return;
    }
    _pushCalendarUndo();
    final updated = CalendarEvent(
      id: eventId,
      title: title,
      memo: memo,
      startTime: startTime,
      endTime: endTime,
      colorArgb: colorArgb,
      googleId: old.googleId,
      ownerUid: old.ownerUid ?? _uid,
      ownerName: old.ownerName ?? _displayName,
    );
    list[idx] = updated;
    _sortDayEvents(list);
    await _saveCalendarEvents();
    notifyListeners();
    // Google Calendar 上も更新
    if (gcalIsAuthenticated && _gcalAutoSyncEnabled) {
      if (updated.googleId != null) {
        _gcalPushUpdate(dateKey, updated);
      } else {
        // Google 未登録ならプッシュ作成して googleId を書き戻し
        _gcalPushCreate(dateKey, updated).then((gid) async {
          if (gid != null) {
            final cur = _calendarEvents[dateKey];
            if (cur == null) return;
            final i2 = cur.indexWhere((e) => e.id == eventId);
            if (i2 < 0) return;
            cur[i2] = CalendarEvent(
              id: eventId,
              title: title,
              memo: memo,
              startTime: startTime,
              endTime: endTime,
              colorArgb: colorArgb,
              googleId: gid,
              ownerUid: updated.ownerUid,
              ownerName: updated.ownerName,
            );
            await _saveCalendarEvents();
            notifyListeners();
          }
        });
      }
    }
  }

  /// イベントをコピー（同じ日 または 別の日に複製）
  /// 新しい id で独立したイベントとして追加される。
  /// Google Calendar イベントもコピー可能だが、コピー側は「ローカル専用」
  /// （googleId を継承しない）として作成し、既存の Google Calendar イベント
  /// への影響を避ける。
  Future<void> copyCalendarEvent(
      String fromDateKey, String eventId, String toDateKey,
      {String? newStartTime, String? newEndTime}) async {
    final list = _calendarEvents[fromDateKey];
    if (list == null) return;
    final idx = list.indexWhere((e) => e.id == eventId);
    if (idx < 0) return;
    final src = list[idx];
    // addCalendarEvent が内部で _pushCalendarUndo を呼ぶ & Google Calendar への
    // 自動プッシュ（googleId なし扱い）もしてくれるので、そのまま流用する
    await addCalendarEvent(toDateKey, src.title,
        memo: src.memo,
        startTime: newStartTime ?? src.startTime,
        endTime: newEndTime ?? src.endTime,
        colorArgb: src.colorArgb);
  }

  /// イベントを別の日に移動（日付キーを変える）
  /// Google Calendar イベントは書き換え不可なので無視する。
  /// 同じ日の場合は updateCalendarEvent 相当。
  Future<void> moveCalendarEvent(
      String fromDateKey, String eventId, String toDateKey,
      {String? newStartTime, String? newEndTime}) async {
    final list = _calendarEvents[fromDateKey];
    if (list == null) return;
    final idx = list.indexWhere((e) => e.id == eventId);
    if (idx < 0) return;
    final src = list[idx];
    if (src.isGoogleEvent) return; // Google Calendar 側は読み取り専用扱い

    final finalStart = newStartTime ?? src.startTime;
    final finalEnd = newEndTime ?? src.endTime;

    if (fromDateKey == toDateKey) {
      // 同じ日: 時刻のみ更新
      await updateCalendarEvent(fromDateKey, eventId, src.title,
          memo: src.memo,
          startTime: finalStart,
          endTime: finalEnd,
          colorArgb: src.colorArgb);
      return;
    }

    // 日をまたぐ移動: remove → add（新 id で再登録）
    // 既存の編集ダイアログと同じ流儀
    await removeCalendarEvent(fromDateKey, eventId);
    await addCalendarEvent(toDateKey, src.title,
        memo: src.memo,
        startTime: finalStart,
        endTime: finalEnd,
        colorArgb: src.colorArgb);
  }

  void _sortDayEvents(List<CalendarEvent> list) {
    list.sort((a, b) {
      final ta = a.startTime;
      final tb = b.startTime;
      if (ta == null && tb == null) return 0;
      if (ta == null) return 1;
      if (tb == null) return -1;
      return ta.compareTo(tb);
    });
  }

  Future<void> _saveCalendarEvents() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final jsonMap = <String, dynamic>{};
      _calendarEvents.forEach((k, v) {
        jsonMap[k] = v.map((e) => e.toJson()).toList();
      });
      await prefs.setString(_calendarStorageKey, jsonEncode(jsonMap));
    } catch (_) {}
  }

  Future<void> loadCalendarEvents() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      // 同期先選択の復元
      _calendarSyncDestination = prefs.getString(_calendarSyncDestKey) ?? '';
      _calendarPullSource = prefs.getString(_calendarPullSrcKey) ?? '';
      final raw = prefs.getString(_calendarStorageKey);
      if (raw == null || raw.isEmpty) return;
      final decoded = jsonDecode(raw) as Map<String, dynamic>;
      _calendarEvents.clear();
      decoded.forEach((k, v) {
        final list = (v as List)
            .map((e) => CalendarEvent.fromJson(e as Map<String, dynamic>))
            .toList();
        _calendarEvents[k] = list;
      });
      notifyListeners();
    } catch (_) {}
  }

  // ─── Google Calendar 連携 (廃止) ─────────────────────────────────────────
  // 旧来 Google Calendar との双方向同期 (OAuth 2.0 / ICS / API v3) を提供して
  // いたが、Google の OAuth 審査運用が煩雑なため機能ごと撤去した。
  // 同期は Firebase 経由の「同期グループ」(同じアプリ間でのイベント共有) に
  // 一本化する。
  //
  // 後方互換のため、外部から呼ばれていたメソッド/getter のシグネチャは残し、
  // 中身を no-op に置き換える。CalendarEvent.googleId / isGoogleEvent も
  // 旧データ読み込みのために残す (新規イベントでは常に null)。
  //
  // 永続化済みの旧設定 (gcal_ics_url / gcal_*_token 等) はアプリ起動時に
  // 削除して掃除する (loadGoogleCalendarSettings 内)。

  /// (廃止) ICS URL — 常に空文字
  String get gcalIcsUrl => '';

  /// (廃止) 最終同期時刻 — 常に null
  DateTime? get gcalLastSyncedAt => null;

  /// (廃止) Google Calendar OAuth クライアント情報 — 常に空
  String get gcalClientId => '';
  String get gcalClientSecret => '';

  /// (廃止) Google Calendar 認証状態 — 常に false
  /// 既存の `if (gcalIsAuthenticated) { ... }` ブロックは自動的にスキップされる。
  bool get gcalIsAuthenticated => false;

  /// (廃止) 双方向自動同期フラグ — 常に false
  bool get gcalAutoSyncEnabled => false;

  /// (廃止) 内部互換: 旧コードが `_gcalAutoSyncEnabled = true/false` の形で
  /// 直接代入しているため、setter 付きのフィールドとして残す。
  /// 値はどう変えても他の処理 (`gcalIsAuthenticated == false`) で
  /// 全ブロックがスキップされるので意味は無い。
  bool _gcalAutoSyncEnabled = false;

  /// (廃止) 直近のプッシュエラー文言 — 常に null
  String? get gcalLastPushError => null;

  /// (廃止) 旧設定の読み込み兼お掃除。
  /// 旧バージョンが SharedPreferences に保存していた gcal 関連キーを削除する。
  /// 起動時に呼ばれても既に削除済なら何も起こらない。
  Future<void> loadGoogleCalendarSettings() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      // 既知の旧キーを掃除する (将来同名キーを別用途で使う事故を避けるため)
      const legacyKeys = <String>[
        'gcal_ics_url',
        'gcal_client_id',
        'gcal_client_secret',
        'gcal_access_token',
        'gcal_refresh_token',
        'gcal_token_expiry',
        'gcal_auto_sync',
      ];
      for (final k in legacyKeys) {
        await prefs.remove(k);
      }
    } catch (_) {}
  }

  /// (廃止) ICS URL 設定 — no-op
  Future<void> setGoogleCalendarIcsUrl(String url) async {}

  /// (廃止) OAuth クライアント情報設定 — no-op
  Future<void> setGoogleOAuthCredentials(
      String clientId, String clientSecret) async {}

  /// (廃止) サインアウト — 既に未認証なので no-op
  Future<void> gcalSignOut() async {}

  /// (廃止) デスクトップ サインイン — 機能削除済みのためエラーを返す
  Future<({bool success, String? error})> gcalSignInDesktop(
      Future<bool> Function(String url) launchUrlCallback) async {
    return (success: false, error: 'Google Calendar 連携は廃止されました');
