  /// (廃止) モバイル サインインキャンセル — no-op
  void gcalCancelMobileSignIn() {}

  /// (廃止) モバイル サインイン進行中フラグ — 常に false
  bool get gcalMobileSignInPending => false;

  /// (廃止) Google からの全件取得 — 0 件返す
  /// 戻り値の型は旧実装と互換: ({success, error, eventCount})。
  Future<({bool success, String? error, int eventCount})> gcalPullAll() async {
    return (success: false, error: null, eventCount: 0);
  }

  /// (廃止) 双方向同期 — 全 0 件
  Future<({int pulled, int pushed, String? error})>
      gcalSyncBidirectional() async {
    return (pulled: 0, pushed: 0, error: null);
  }

  /// (廃止) 公開イベントとして Google にプッシュ — 失敗扱い
  Future<bool> gcalPushCreatePublic(String dateKey, CalendarEvent ev) async {
