  // ── Firebase REST API 設定（環境変数で上書き可能） ────────────────────────
  // ビルド時に --dart-define=FIREBASE_PROJECT_ID=xxx などで指定
  static const String _firestoreProjectId = String.fromEnvironment(
      'FIREBASE_PROJECT_ID',
      defaultValue: ''); // ← Firebaseプロジェクト名(例: mindmap-b6115)

  // REST APIキーの取得優先順位:
  //   1) FIREBASE_API_KEY_REST (REST API用、最優先)
  //   2) FIREBASE_API_KEY_WINDOWS (Windows向けキー)
  //   3) FIREBASE_API_KEY_ANDROID (Android向けキー)
  //   4) FIREBASE_API_KEY_IOS / WEB / MACOS
  // 通常、firebase_options.dart と同じAPIキーで問題なく動作します
  static const String _authApiKeyRest =
      String.fromEnvironment('FIREBASE_API_KEY_REST', defaultValue: '');
  static const String _authApiKeyWin =
      String.fromEnvironment('FIREBASE_API_KEY_WINDOWS', defaultValue: '');
  static const String _authApiKeyAndroid =
      String.fromEnvironment('FIREBASE_API_KEY_ANDROID', defaultValue: '');
  static const String _authApiKeyIos =
      String.fromEnvironment('FIREBASE_API_KEY_IOS', defaultValue: '');
  static const String _authApiKeyWeb =
      String.fromEnvironment('FIREBASE_API_KEY_WEB', defaultValue: '');
  static const String _authApiKeyMac =
      String.fromEnvironment('FIREBASE_API_KEY_MACOS', defaultValue: '');

  static String get _authApiKey {
    // 非空のものを上から優先して採用
    for (final k in [
      _authApiKeyRest,
      _authApiKeyWin,
      _authApiKeyAndroid,
      _authApiKeyIos,
      _authApiKeyWeb,
      _authApiKeyMac,
    ]) {
      if (k.isNotEmpty) return k;
    }
    return '';
  }

  // 自動生成URL
  static String get _firestoreBaseUrl =>
      'https://firestore.googleapis.com/v1/projects/$_firestoreProjectId/databases/(default)/documents';
  static const String _authUrl =
      'https://identitytoolkit.googleapis.com/v1/accounts:signUp';

  String? _idToken; // Firebase認証トークン
  DateTime? _idTokenExpiry; // ID トークンの有効期限 (= これを過ぎるまで再取得不要)
  String? _uid; // Firebase匿名UID（端末固有）
  String? _displayName; // ユーザー表示名（メッセージング用）
  /// ユーザーが「初回起動のユーザー名入力ダイアログ」をスキップしたか。
  /// true の場合、displayName が空でも自動でダイアログを再表示しない
  /// (= 設定シートから手動で開いた時のみ表示される)。
  /// 一度 setDisplayName で名前を設定すると false に戻す。
  bool _displayNameSkipped = false;
  String? _syncGroupId; // 現在「アクティブ」な同期グループID（後方互換のため残す）
  /// 参加中の同期グループ一覧（複数所属対応）
  final List<String> _joinedGroupIds = [];

  /// ページID → 自動同期するグループID（指定なければアクティブグループを使用）
  final Map<String, String> _pageGroupBindings = {};
  Timer? _syncTimer;
  bool _firestoreSyncing = false;
  bool _firebaseEnabled = false;

  /// fetchCloudPageList 時に一時キャッシュする namedGroups JSON (pageId → JSON文字列)
  final Map<String, String> _cloudPageGroupsCache = {};

  // Firebase Storage
  static const String _storageBucket = 'mindmap-b6115.firebasestorage.app';
  static String get _storageUploadUrl =>
      'https://firebasestorage.googleapis.com/v0/b/$_storageBucket/o';

  // 同期状態の外部公開
  bool get isSyncEnabled => _firebaseEnabled && _syncGroupId != null;
  String? get currentGroupId => _syncGroupId;

  /// 参加中の全グループID
  List<String> get joinedGroupIds => List.unmodifiable(_joinedGroupIds);

  /// ページに紐づくグループID（未設定なら現在のアクティブグループ）
  String? getPageGroupId(String pageId) =>
      _pageGroupBindings[pageId] ?? _syncGroupId;

  /// ページに自動同期グループを紐付け
  Future<void> setPageGroupId(String pageId, String? groupId) async {
    if (groupId == null || groupId.isEmpty) {
      _pageGroupBindings.remove(pageId);
    } else {
      _pageGroupBindings[pageId] = groupId;
    }
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString('pageGroupBindings', jsonEncode(_pageGroupBindings));
    notifyListeners();
  }

  Future<void> _loadJoinedGroups() async {
    final prefs = await SharedPreferences.getInstance();
    final list = prefs.getStringList('joinedGroupIds');
    if (list != null) {
      _joinedGroupIds
        ..clear()
        ..addAll(list);
    }
    // 旧 syncGroupId があれば一覧に含める（後方互換）
    final legacy = prefs.getString('syncGroupId');
    if (legacy != null &&
        legacy.isNotEmpty &&
        !_joinedGroupIds.contains(legacy)) {
      _joinedGroupIds.add(legacy);
    }
    final bindStr = prefs.getString('pageGroupBindings');
    if (bindStr != null) {
      try {
        final m = jsonDecode(bindStr) as Map<String, dynamic>;
        _pageGroupBindings
          ..clear()
          ..addAll(m.map((k, v) => MapEntry(k, v as String)));
      } catch (_) {}
    }
  }

  Future<void> _saveJoinedGroups() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setStringList('joinedGroupIds', _joinedGroupIds);
  }

  // ─── ユーザー名 ────────────────────────────────────────────────────────────

  String get displayName => _displayName ?? '';
  String? get currentUid => _uid;

  /// 初回起動時のユーザー名入力ダイアログを「スキップ」した状態か。
  /// true なら、displayName が空でも _maybePromptUserName から
  /// 自動で再表示されない。設定シートから手動で開いた場合は表示される。
  bool get displayNameSkipped => _displayNameSkipped;

  Future<void> loadDisplayName() async {
    final prefs = await SharedPreferences.getInstance();
    _displayName = prefs.getString('displayName');
    _displayNameSkipped = prefs.getBool('displayNameSkipped') ?? false;
    _userAvatar = prefs.getString('userAvatar');
    _userAvatarImagePath = prefs.getString('userAvatarImage');
    notifyListeners();
  }

  // ── ユーザーアイコン (= ユーザー要望: ユーザーのアイコンをユーザーが
  //    指定できるように) ──
  // 絵文字 1 文字を想定 (例: '😀', '🦊')。 未設定なら displayName の先頭
  //   文字 (グレースケール) を表示にフォールバックする。
  String? _userAvatar;
  String? get userAvatar => _userAvatar;

  Future<void> setUserAvatar(String? emoji) async {
    _userAvatar = emoji;
    final prefs = await SharedPreferences.getInstance();
    if (emoji == null || emoji.isEmpty) {
      await prefs.remove('userAvatar');
    } else {
      await prefs.setString('userAvatar', emoji);
    }
    notifyListeners();
  }

  // ── カスタム画像アバター (= ユーザー要望: アイコンをユーザーが独自に
  //    設定できるように) ──
  // 絵文字テンプレートとは別キーで保持し、 非 null かつファイルが存在すれば
  //   絵文字より優先して画像を表示する。 別キーにすることで、 絵文字前提で
  //   userAvatar を Text 描画している他箇所 (メッセージ画面など) を壊さない。
  String? _userAvatarImagePath;
  String? get userAvatarImagePath => _userAvatarImagePath;

  Future<void> setUserAvatarImage(String? path) async {
    _userAvatarImagePath = (path == null || path.isEmpty) ? null : path;
    final prefs = await SharedPreferences.getInstance();
    if (_userAvatarImagePath == null) {
      await prefs.remove('userAvatarImage');
    } else {
      await prefs.setString('userAvatarImage', _userAvatarImagePath!);
    }
    notifyListeners();
  }

  /// ユーザー名入力ダイアログでスキップが選択された時に呼ぶ。
  /// 以後、起動時の自動再表示をしない。
  Future<void> markDisplayNameSkipped() async {
    if (_displayNameSkipped) return;
    _displayNameSkipped = true;
    final prefs = await SharedPreferences.getInstance();
    await prefs.setBool('displayNameSkipped', true);
    notifyListeners();
  }

  // ─── カレンダーのグループ共有 ──────────────────────────────────────────────
  // true のとき、自分のカレンダーを同期グループ内の他メンバーに公開し、
  // 他メンバーの（同じくONにしている）カレンダーも読み込む。
  // false のとき、カレンダーは完全にローカル（クラウドに上がらず、他人も見ない）。
  // デフォルトは OFF（プライバシー配慮）。
  bool _calendarGroupSharingEnabled = false;
  bool get calendarGroupSharingEnabled => _calendarGroupSharingEnabled;

  /// 「許可された uid のキャッシュ」: グループ内で共有をONにしているメンバー。
  /// downloadCalendarEventsFromCloud 時にメンバー一覧を取得して埋まる。
  final Set<String> _calendarSharingAllowedUids = {};
  Set<String> get calendarSharingAllowedUids =>
      Set.unmodifiable(_calendarSharingAllowedUids);

  Future<void> _loadCalendarGroupSharing() async {
    final prefs = await SharedPreferences.getInstance();
    _calendarGroupSharingEnabled =
        prefs.getBool('calendarGroupSharingEnabled') ?? false;
  }

  Future<void> setCalendarGroupSharingEnabled(bool enabled) async {
    _calendarGroupSharingEnabled = enabled;
    final prefs = await SharedPreferences.getInstance();
    await prefs.setBool('calendarGroupSharingEnabled', enabled);
    notifyListeners();
    // 所属グループ全てに allowCalendarSharing を反映
    if (_firebaseEnabled && _idToken != null && _uid != null) {
      for (final gid in _joinedGroupIds) {
        await _registerMember(gid);
      }
      // OFF にしたときは自分の per-user カレンダードキュメントをクラウドから削除
      if (!enabled) {
        for (final gid in _joinedGroupIds) {
          await _deleteMyCalendarDocOnGroup(gid);
        }
      }
    }
  }

  /// 自分の calendar/{uid} ドキュメントをクラウドから削除
  Future<void> _deleteMyCalendarDocOnGroup(String groupId) async {
    if (_idToken == null || _uid == null) return;
    try {
      await _ensureFreshToken();
      final url = '$_firestoreBaseUrl/groups/$groupId/calendar/$_uid';
      await http.delete(
        Uri.parse(url),
        headers: {'Authorization': 'Bearer $_idToken'},
      );
    } catch (e) {
      debugPrint('delete my calendar doc error: $e');
    }
  }

  /// ユーザー名を保存し、Firestore /users/{uid} にも反映
  Future<void> setDisplayName(String name) async {
    _displayName = name.trim();
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString('displayName', _displayName!);
    // 一度名前を設定したら「スキップ済み」状態は不要 (= 名前ありとして扱われる)。
    // 念のためクリアしておく。
    if (_displayNameSkipped && _displayName!.isNotEmpty) {
      _displayNameSkipped = false;
      await prefs.setBool('displayNameSkipped', false);
    }
    notifyListeners();
    if (_firebaseEnabled && _idToken != null && _uid != null) {
      try {
        await _ensureFreshToken();
        final url = '$_firestoreBaseUrl/users/$_uid';
        await http.patch(
          Uri.parse(
              '$url?updateMask.fieldPaths=displayName&updateMask.fieldPaths=lastSeen'),
          headers: {
            'Authorization': 'Bearer $_idToken',
            'Content-Type': 'application/json',
          },
          body: jsonEncode({
            'fields': {
              'displayName': {'stringValue': _displayName!},
              'lastSeen': {'stringValue': DateTime.now().toIso8601String()},
            },
          }),
        );
        // 各グループメンバー情報も更新
        for (final gid in _joinedGroupIds) {
          await _registerMember(gid);
        }
      } catch (e) {
        debugPrint('displayName 同期エラー: $e');
      }
    }
  }

  // ─── メッセージング ────────────────────────────────────────────────────────

  /// 個別/グループにメッセージを送信
  /// [toUid] 宛先UID（個別送信時）
  /// [toGroupId] 宛先グループID（グループ送信時）
  /// どちらか一方を指定
  ///
  /// `_displayName` が未設定の場合は `_DisplayNameRequiredException` を投げる。
  /// UI 側でキャッチしてユーザー名設定ダイアログを開く。
  Future<bool> sendMessage({
    String? toUid,
    String? toGroupId,
    required String text,
  }) async {
    if (text.trim().isEmpty) return false;
    if (toUid == null && toGroupId == null) return false;
    // ── ユーザー名必須チェック ──
    if ((_displayName ?? '').trim().isEmpty) {
      throw const _DisplayNameRequiredException();
    }
    if (!_firebaseEnabled || _idToken == null || _uid == null) {
      throw Exception('Firebase未接続');
    }
    try {
      await _ensureFreshToken();
      final msgId = _uuid.v4();
      final url = '$_firestoreBaseUrl/messages?documentId=$msgId';
      final fields = <String, Map<String, String>>{
        'fromUid': {'stringValue': _uid!},
        'fromName': {'stringValue': _displayName!},
        'text': {'stringValue': text.trim()},
        'timestamp': {'stringValue': DateTime.now().toUtc().toIso8601String()},
        'read': {'booleanValue': 'false'} as dynamic,
      };
      if (toUid != null) fields['toUid'] = {'stringValue': toUid};
      if (toGroupId != null) fields['toGroupId'] = {'stringValue': toGroupId};
      final body = jsonEncode({'fields': _normalizeFields(fields)});
      final res = await http.post(
        Uri.parse(url),
        headers: {
          'Authorization': 'Bearer $_idToken',
          'Content-Type': 'application/json',
        },
        body: body,
      );
      return res.statusCode == 200;
    } catch (e) {
      debugPrint('sendMessage error: $e');
      rethrow;
    }
  }

  /// Firestore JSONで bool は {'booleanValue': true} として送る必要があるための補助
  Map<String, dynamic> _normalizeFields(Map<String, Map<String, dynamic>> raw) {
    final out = <String, dynamic>{};
    raw.forEach((k, v) {
      // 'booleanValue' を文字列で渡してきた場合は bool に変換
      if (v.containsKey('booleanValue') && v['booleanValue'] is String) {
        out[k] = {'booleanValue': v['booleanValue'] == 'true'};
      } else {
        out[k] = v;
      }
    });
    return out;
  }

  /// 自分宛 + 自分が所属するグループ宛のメッセージを取得（新しい順）
  Future<List<Map<String, dynamic>>> fetchMyMessages({int limit = 50}) async {
    if (!_firebaseEnabled || _idToken == null || _uid == null) return [];
    try {
      await _ensureFreshToken();
      // Firestore REST の structuredQuery で OR 条件は使えないため、
      // 全件 GET → クライアント側でフィルタ（メッセージ数が多くなったら要改善）
      final url = '$_firestoreBaseUrl/messages?pageSize=200';
      final res = await http.get(
        Uri.parse(url),
        headers: {'Authorization': 'Bearer $_idToken'},
      );
      if (res.statusCode != 200) return [];
      final data = jsonDecode(res.body) as Map<String, dynamic>;
      final docs = data['documents'] as List<dynamic>? ?? [];
      final result = <Map<String, dynamic>>[];
      for (final doc in docs) {
        try {
          final docName = doc['name'] as String;
          final msgId = docName.split('/').last;
          final fields = doc['fields'] as Map<String, dynamic>? ?? {};
          final toUid = _firestoreStr(fields['toUid']);
          final toGroupId = _firestoreStr(fields['toGroupId']);
          final fromUid = _firestoreStr(fields['fromUid']) ?? '';
          // 宛先判定: 自分宛 or 自分のグループ宛 or 自分が送信
          final isToMe = toUid == _uid;
          final isToMyGroup =
              toGroupId != null && _joinedGroupIds.contains(toGroupId);
          final isFromMe = fromUid == _uid;
          if (!isToMe && !isToMyGroup && !isFromMe) continue;
          result.add({
            'id': msgId,
            'fromUid': fromUid,
            'fromName': _firestoreStr(fields['fromName']) ?? '匿名',
            'toUid': toUid ?? '',
            'toGroupId': toGroupId ?? '',
            'text': _firestoreStr(fields['text']) ?? '',
            'timestamp': _firestoreStr(fields['timestamp']) ?? '',
            'read': (fields['read']?['booleanValue'] as bool?) ?? false,
            'isFromMe': isFromMe,
          });
        } catch (_) {}
      }
      result.sort((a, b) =>
          (b['timestamp'] as String).compareTo(a['timestamp'] as String));
      if (result.length > limit) result.removeRange(limit, result.length);
      return result;
    } catch (e) {
      debugPrint('fetchMyMessages error: $e');
      return [];
    }
  }

  /// 受信メッセージの ID を覚えておく集合 (セッション中のみ保持)。
  /// 起動後はじめて fetch したときは通知しない (既存メッセージを全部新着扱い
  /// するのを防ぐ)。2 回目以降のポーリングで、前回見てなかった ID が来たら
  /// それを新着として返す。
  final Set<String> _seenMessageIds = {};
  bool _initialMessagesLoaded = false;

  /// 新着メッセージを取得する。
  /// - 起動後最初の呼び出し: 既存メッセージ ID を全部 _seenMessageIds に
  ///   登録して、新着は返さない (空配列を返す)。
  /// - 2 回目以降: 前回から増えたメッセージのうち、自分宛 (= isFromMe=false)
  ///   のものだけを新着として返す。
  ///
  /// UI 側 (mind_map_screen) は定期的にこれを呼び、戻り値が空でなければ
  /// SnackBar で通知する。
  Future<List<Map<String, dynamic>>> checkForNewMessages() async {
    final all = await fetchMyMessages(limit: 50);
    if (!_initialMessagesLoaded) {
      // 初回は全部既知扱いにする
      _seenMessageIds.clear();
      for (final m in all) {
        final id = m['id'] as String?;
        if (id != null) _seenMessageIds.add(id);
      }
      _initialMessagesLoaded = true;
      return const [];
    }
    final newOnes = <Map<String, dynamic>>[];
    for (final m in all) {
      final id = m['id'] as String?;
      if (id == null) continue;
      if (_seenMessageIds.contains(id)) continue;
      _seenMessageIds.add(id);
      // 自分が送ったメッセージ / 既読のものは通知しない
      if (m['isFromMe'] == true) continue;
      if (m['read'] == true) continue;
      newOnes.add(m);
    }
    return newOnes;
  }

  /// メッセージを既読に
  Future<void> markMessageRead(String msgId) async {
    if (!_firebaseEnabled || _idToken == null) return;
    try {
      await _ensureFreshToken();
      final url = '$_firestoreBaseUrl/messages/$msgId'
          '?updateMask.fieldPaths=read';
      await http.patch(
        Uri.parse(url),
        headers: {
          'Authorization': 'Bearer $_idToken',
          'Content-Type': 'application/json',
        },
        body: jsonEncode({
          'fields': {
            'read': {'booleanValue': true}
          },
        }),
      );
    } catch (e) {
      debugPrint('markMessageRead error: $e');
    }
  }

  /// メッセージを削除
  Future<bool> deleteMessage(String msgId) async {
    if (!_firebaseEnabled || _idToken == null) return false;
    try {
      await _ensureFreshToken();
      final url = '$_firestoreBaseUrl/messages/$msgId';
      final res = await http.delete(
        Uri.parse(url),
        headers: {'Authorization': 'Bearer $_idToken'},
      );
      return res.statusCode == 200 || res.statusCode == 204;
    } catch (e) {
      debugPrint('deleteMessage error: $e');
      return false;
    }
  }

  /// 指定グループのメンバー一覧（displayName付き）を取得
  Future<List<Map<String, String>>> fetchGroupMembers(String groupId) async {
    if (!_firebaseEnabled || _idToken == null) return [];
    try {
      await _ensureFreshToken();
      final url = '$_firestoreBaseUrl/groups/$groupId/members';
      final res = await http.get(
        Uri.parse(url),
        headers: {'Authorization': 'Bearer $_idToken'},
      );
      if (res.statusCode != 200) return [];
      final data = jsonDecode(res.body) as Map<String, dynamic>;
      final docs = data['documents'] as List<dynamic>? ?? [];
      final result = <Map<String, String>>[];
      for (final doc in docs) {
        try {
          final fields = doc['fields'] as Map<String, dynamic>? ?? {};
          final uid = _firestoreStr(fields['uid']) ?? '';
          if (uid.isEmpty) continue;
          final name = _firestoreStr(fields['displayName']) ?? '匿名';
          result.add({'uid': uid, 'displayName': name});
        } catch (_) {}
      }
      return result;
    } catch (e) {
      debugPrint('fetchGroupMembers error: $e');
      return [];
    }
  }

  // ── 自動同期（マップ単位）──────────────────────────────────────────
  final Set<String> _autoSyncPageIds = {};
  Timer? _autoSyncDebounce;

  bool isPageAutoSync(String pageId) => _autoSyncPageIds.contains(pageId);

  Future<void> setPageAutoSync(String pageId, bool enabled) async {
    if (enabled) {
      _autoSyncPageIds.add(pageId);
    } else {
      _autoSyncPageIds.remove(pageId);
    }
    final prefs = await SharedPreferences.getInstance();
    await prefs.setStringList('autoSyncPageIds', _autoSyncPageIds.toList());
    notifyListeners();
  }

  Future<void> _loadAutoSyncPageIds() async {
    final prefs = await SharedPreferences.getInstance();
    final ids = prefs.getStringList('autoSyncPageIds');
    if (ids != null) _autoSyncPageIds.addAll(ids);
  }

  /// 自動同期をトリガー（デバウンス付き）
  void _triggerAutoSync() {
    if (!_firebaseEnabled || _syncGroupId == null) return;
    if (_isUploading || _firestoreSyncing) return;
    _autoSyncDebounce?.cancel();
    _autoSyncDebounce = Timer(const Duration(seconds: 3), () {
      _performAutoSync();
    });
  }

  Future<void> _performAutoSync() async {
    if (!_firebaseEnabled || _syncGroupId == null) return;
    if (_isUploading || _firestoreSyncing) return;
    if (_autoSyncPageIds.isEmpty) return;

    // 現在存在するページでautoSync有効なもののみ
    final targets = _pages
        .where((p) => _autoSyncPageIds.contains(p.id))
        .map((p) => p.id)
        .toList();
    if (targets.isEmpty) return;

    try {
      await _ensureFreshToken();
      _firestoreSyncing = true;
      for (final pageId in targets) {
        try {
          await _savePageToFirestore(pageId);
        } on _UploadRestrictedException catch (e) {
          // ── 自動同期中に制限が掛かったマップへ書き込もうとした場合 ──
          // ユーザー要望「クラウドに新しいマップをアップロードする時に
          //   他ユーザーによる再アップロードを制限できる機能」 への対応で、
          //   バックグラウンド自動同期でも同じ pre-check が走る。 制限を
          //   検出したら:
          //     1. UI 側に表示できるよう `lastUploadError` をセット
          //     2. そのページの自動同期を OFF にする (= 数秒ごとに失敗
          //        リトライ → debugPrint スパムを防ぐ)
          //   ユーザーは制限解除を待ってから手動で自動同期を再 ON する。
          lastUploadError =
              '🔒 ${_pages.firstWhere((p) => p.id == pageId, orElse: () => MindMapPage(id: '', name: '')).name}: ${e.message}';
          _autoSyncPageIds.remove(pageId);
          final prefs = await SharedPreferences.getInstance();
          await prefs.setStringList(
              'autoSyncPageIds', _autoSyncPageIds.toList());
        }
      }
    } catch (e) {
      debugPrint('自動同期エラー: $e');
    } finally {
      _firestoreSyncing = false;
      notifyListeners();
    }
  }

  // ── アップロード進捗管理 ──
  /// nodeId → アップロード進捗 (0.0〜1.0)
  final Map<String, double> _uploadProgress = {};

  /// nodeId → アップロード中かどうか
  final Map<String, bool> _uploading = {};

  /// 最新のアップロードエラーメッセージ（SnackBar等で表示用）
  String? lastUploadError;

  /// 直近の同期 (uploadToCloud / downloadFromCloud) で、添付ファイル
  ///   (PDF・画像・動画) の転送が 1 つでも失敗したか。
  /// true の場合、JSON (文字情報) は同期されても PDF 等の中身が欠ける
  ///   ため、画面側で「完了」 ではなくエラーを出して再同期を促す
  ///   (= ユーザー要望「完全にアップロード＆ダウンロードが完了するまで
  ///   メッセージ(完了)を出さない」)。
  bool _lastSyncAttachmentFailed = false;
  bool get lastSyncAttachmentFailed => _lastSyncAttachmentFailed;

  /// 直近の同期で容量/月間上限に達したときの説明メッセージ (= ユーザー要望:
  /// 上限に来ていたらそう表示する)。 null = 上限には達していない。
  String? _lastSyncLimitMessage;
  String? get lastSyncLimitMessage => _lastSyncLimitMessage;

  /// 指定ノードのアップロード進捗を取得（null=アップロードなし）
  double? getUploadProgress(String nodeId) =>
      _uploading[nodeId] == true ? _uploadProgress[nodeId] : null;

  /// アップロード中のノードが 1 つでもあるか (= 端の進捗表示用)。
  bool get isAnyUploading => _uploading.values.any((v) => v);

  /// アップロード中のノード数。
  int get uploadingCount => _uploading.values.where((v) => v).length;

  /// アップロード中ノードの平均進捗 (0.0〜1.0)。 アップロードが無ければ 0。
  double get overallUploadProgress {
    double sum = 0;
    int n = 0;
    _uploading.forEach((id, up) {
      if (up) {
        sum += _uploadProgress[id] ?? 0.0;
        n++;
      }
    });
    return n == 0 ? 0.0 : sum / n;
  }

  // ── Undo/Redo ──
  static const int _maxHistory = 50;
  final Map<String, List<_PageSnapshot>> _undoStacks = {};
  final Map<String, List<_PageSnapshot>> _redoStacks = {};

  /// ページIDごとの最終編集日時（_pushUndo時に更新）
  final Map<String, DateTime> _pageLastEditedAt = {};

  String get _pageId => _pages.isNotEmpty ? _pages[_currentPageIndex].id : '';

  bool get canUndo => (_undoStacks[_pageId]?.length ?? 0) > 0;
  bool get canRedo => (_redoStacks[_pageId]?.length ?? 0) > 0;

  /// 現在のページ状態をUndo履歴に積む（変更前に呼ぶ）
  /// バッチ undo 用の深度カウンタ。 >0 の間は個別の _pushUndo を抑止し、
  /// バッチ開始時に取得した 1 枚のスナップショットだけを undo 対象にする。
  int _undoBatchDepth = 0;

  /// 複数のミューテーションを 1 回の undo でまとめて戻すためのバッチ開始。
  /// 開始時点の状態を 1 枚だけ記録し、 以降の個別 _pushUndo を抑止する。
  /// 必ず [endUndoBatch] と対で呼ぶこと。
  /// 例: 裁断モードで複数リンクを一度に切ったとき、 戻るで 1 回でまとめて
  ///     元に戻せるようにする (= ユーザー要望)。
  void beginUndoBatch() {
    if (_undoBatchDepth == 0) _pushUndo(); // 開始時の状態を 1 枚だけ記録
    _undoBatchDepth++;
  }

  /// [beginUndoBatch] と対で呼ぶバッチ終了。
  void endUndoBatch() {
    if (_undoBatchDepth > 0) _undoBatchDepth--;
  }

  void _pushUndo() {
    if (_undoBatchDepth > 0) return; // バッチ中: 開始時のスナップショットに集約
    final id = _pageId;
    if (id.isEmpty) return;
    _undoStacks.putIfAbsent(id, () => []);
    _redoStacks.putIfAbsent(id, () => []);
    final groups = _namedGroups[id] ?? {};
    _undoStacks[id]!.add(_PageSnapshot.from(currentPage, groups));
    if (_undoStacks[id]!.length > _maxHistory) {
      _undoStacks[id]!.removeAt(0);
    }
    _redoStacks[id]!.clear(); // 新操作でRedoを消す
    _pageLastEditedAt[id] = DateTime.now(); // 編集日時を更新
  }

  void undo() {
    final id = _pageId;
    final stack = _undoStacks[id];
    if (stack == null || stack.isEmpty) return;
    final snap = stack.removeLast();
    _redoStacks.putIfAbsent(id, () => []);
    final groups = _namedGroups[id] ?? {};
    _redoStacks[id]!.add(_PageSnapshot.from(currentPage, groups));
    _applySnapshot(snap, id);
    _saveToStorage();
    _saveNamedGroups(); // 付箋状態も永続化
    notifyListeners();
  }

  void redo() {
    final id = _pageId;
    final stack = _redoStacks[id];
    if (stack == null || stack.isEmpty) return;
    final snap = stack.removeLast();
    _undoStacks.putIfAbsent(id, () => []);
    final groups = _namedGroups[id] ?? {};
    _undoStacks[id]!.add(_PageSnapshot.from(currentPage, groups));
    _applySnapshot(snap, id);
    _saveToStorage();
    _saveNamedGroups(); // 付箋状態も永続化
    notifyListeners();
  }

  void _applySnapshot(_PageSnapshot snap, String pageId) {
    currentPage.nodes
      ..clear()
      ..addAll(snap.nodes);
    currentPage.connections
      ..clear()
      ..addAll(snap.connections);
    currentPage.decorations
      ..clear()
      ..addAll(snap.decorations.map((d) => d.copyWith()));
    _namedGroups[pageId] = Map.fromEntries(
        snap.namedGroups.entries.map((e) => MapEntry(e.key, Set.of(e.value))));
  }

