  // ── チャンネル動画キュー（自動補充用）─────────────────────────────
  // parentNodeId → { 全videoIds, 全titles, 現在表示済みindex }
  final Map<String, ChannelVideoQueue> _channelQueues = {};

  void registerChannelQueue(
      String parentId, List<String> videoIds, List<String> titles) {
    _channelQueues[parentId] =
        ChannelVideoQueue(videoIds: List.of(videoIds), titles: List.of(titles));
    _saveChannelQueues();
  }

  ChannelVideoQueue? getChannelQueue(String parentId) =>
      _channelQueues[parentId];

  Future<void> _saveChannelQueues() async {
    final prefs = await SharedPreferences.getInstance();
    final map = <String, dynamic>{};
    for (final e in _channelQueues.entries) {
      map[e.key] = {
        'videoIds': e.value.videoIds,
        'titles': e.value.titles,
      };
    }
    await prefs.setString('channelQueues', jsonEncode(map));
  }

  Future<void> _loadChannelQueues() async {
    final prefs = await SharedPreferences.getInstance();
    final str = prefs.getString('channelQueues');
    if (str == null) return;
    try {
      final map = jsonDecode(str) as Map<String, dynamic>;
      for (final e in map.entries) {
        final data = e.value as Map<String, dynamic>;
        _channelQueues[e.key] = ChannelVideoQueue(
          videoIds: List<String>.from(data['videoIds'] as List),
          titles: List<String>.from(data['titles'] as List),
        );
      }
    } catch (_) {}
  }

  // ── 視聴完了トラッキング ──────────────────────────────────────────
  final Set<String> _fullyWatchedVideoIds = {};

  /// 動画が最後まで再生された時に呼ぶ（FlutterEndedから）
  void markVideoFullyWatched(String videoId) {
    _fullyWatchedVideoIds.add(videoId);
  }

  /// プレーヤーを閉じた後に呼ぶ: 視聴完了した動画ノードを削除 → 詰めて → 補充
  void processWatchedAndRefill(String? parentId) {
    if (!_autoDeleteWatched) return;
    if (parentId == null) return;
    if (_fullyWatchedVideoIds.isEmpty) return;

    final queue = _channelQueues[parentId];

    // 親の子ノードで視聴完了したものを特定
    final toDelete = <String>[];
    for (final c in currentPage.connections.toList()) {
      if (c.fromId == parentId) {
        final child = currentPage.nodes[c.toId];
        if (child == null) continue;
        final vid = _extractYtVideoId(child.youtubeUrl ?? '');
        if (vid != null && _fullyWatchedVideoIds.contains(vid)) {
          toDelete.add(c.toId);
        }
      }
    }

    if (toDelete.isEmpty) {
      _fullyWatchedVideoIds.clear();
      return;
    }

    _pushUndo();

    // 削除（generatedVideoIdsには残す→再追加を防止）
    for (final id in toDelete) {
      currentPage.nodes.remove(id);
      currentPage.connections
          .removeWhere((c) => c.fromId == id || c.toId == id);
    }

    // 残った子ノードをY座標順にソートして詰め直す
    final parentNode = currentPage.nodes[parentId];
    if (parentNode == null) {
      _fullyWatchedVideoIds.clear();
      _saveToStorage();
      notifyListeners();
      return;
    }

    final remainingChildren = <MindMapNode>[];
    for (final c in currentPage.connections) {
      if (c.fromId == parentId) {
        final child = currentPage.nodes[c.toId];
        if (child != null) remainingChildren.add(child);
      }
    }
    remainingChildren.sort((a, b) => a.position.dy.compareTo(b.position.dy));

    // 先頭の子ノードのY座標を基準に詰め直す
    const gap = 16.0;
    double currentY;
    if (remainingChildren.isNotEmpty) {
      // 元の先頭位置を基準に
      final firstOrigY = remainingChildren.first.position.dy;
      currentY = firstOrigY;
    } else {
      currentY = parentNode.position.dy;
    }

    for (final child in remainingChildren) {
      if ((child.position.dy - currentY).abs() > 0.5) {
        currentPage.nodes[child.id] = child.copyWith(
          position: Offset(child.position.dx, currentY),
        );
      }
      final updatedChild = currentPage.nodes[child.id]!;
      currentY = updatedChild.position.dy + updatedChild.visualHeight + gap;
    }

    // 不足分を下に補充
    if (queue != null) {
      final unwatchedCount = remainingChildren.length;
      final needed = _unwatchedLimit - unwatchedCount;
      if (needed > 0) {
        _refillFromQueueAt(parentId, needed, currentY);
      }
    }

    _fullyWatchedVideoIds.clear();
    _saveToStorage();
    _saveGeneratedIds();
    notifyListeners();
  }

  /// 動画を視聴済みにしてノードを自動削除 & 次の未視聴動画を補充
  void markVideoWatchedAndRefill(String nodeId) {
    if (!_autoDeleteWatched) return;
    final node = currentPage.nodes[nodeId];
    if (node == null) return;
    // YouTube動画ノードでなければ無視
    final ytUrl = node.youtubeUrl ?? '';
    if (ytUrl.isEmpty) return;
    final videoId = _extractYtVideoId(ytUrl);
    if (videoId == null) return;

    // この動画が属する親ノード（チャンネル）を探す
    String? parentId;
    for (final c in currentPage.connections) {
      if (c.toId == nodeId) {
        parentId = c.fromId;
        break;
      }
    }
    // 視聴完了済みとしてマークしてからprocessで処理
    _fullyWatchedVideoIds.add(videoId);
    processWatchedAndRefill(parentId);
  }

  /// キューから未生成の動画をN件、指定Y座標から追加
  void _refillFromQueueAt(String parentId, int count, double startY) {
    final queue = _channelQueues[parentId];
    if (queue == null) return;
    final parentNode = currentPage.nodes[parentId];
    if (parentNode == null) return;

    const gap = 16.0;
    int added = 0;
    double currentY = startY;
    final List<String> newChildIds = [];

    for (int i = 0; i < queue.videoIds.length && added < count; i++) {
      final vid = queue.videoIds[i];
      if (_generatedVideoIds.contains(vid)) continue;

      final childId = _uuid.v4();
      final title = i < queue.titles.length ? queue.titles[i] : 'Video';
      final child = MindMapNode(
        id: childId,
        title: title,
        position: Offset(parentNode.position.dx + 200, currentY),
        youtubeUrl: 'https://www.youtube.com/watch?v=$vid',
        contentType: NodeContentType.youtube,
        color: _childColor(),
      );
      currentPage.nodes[childId] = child;
      newChildIds.add(childId);
      currentPage.connections.add(NodeConnection(
        fromId: parentId,
        fromAnchor: AnchorDirection.east,
        toId: childId,
        toAnchor: AnchorDirection.west,
      ));
      _generatedVideoIds.add(vid);
      currentY += child.visualHeight + gap;
      added++;
    }
    // 親ノードが所属する全グループに、追加した子ノードも同じ所属で加える
    if (newChildIds.isNotEmpty) {
      addChildrenToParentGroups(parentId, newChildIds);
    }
  }

  static String? _extractYtVideoId(String url) {
    for (final p in [
      RegExp(r'[?&]v=([a-zA-Z0-9_-]{11})'),
      RegExp(r'youtu\.be/([a-zA-Z0-9_-]{11})'),
      RegExp(r'/shorts/([a-zA-Z0-9_-]{11})'),
    ]) {
      final m = p.firstMatch(url);
      if (m != null) return m.group(1);
    }
    return null;
  }

