  /// フィルターを適用して動画リストを絞り込む
  /// viewCounts が空なら再生数フィルターはスキップ
  (List<String>, List<String>) filterChannelVideos(
      List<String> videoIds, List<String> titles,
      {List<int>? viewCounts}) {
    final filteredIds = <String>[];
    final filteredTitles = <String>[];
    final incWords = _includeKeywords
        .split(',')
        .map((s) => s.trim().toLowerCase())
        .where((s) => s.isNotEmpty)
        .toList();
    final excWords = _excludeKeywords
        .split(',')
        .map((s) => s.trim().toLowerCase())
        .where((s) => s.isNotEmpty)
        .toList();

    for (int i = 0; i < videoIds.length; i++) {
      final title = i < titles.length ? titles[i] : '';
      final lower = title.toLowerCase();

      // 再生数フィルタ
      if (viewCounts != null &&
          _minViewCount > 0 &&
          i < viewCounts.length &&
          viewCounts[i] >= 0 &&
          viewCounts[i] < _minViewCount) {
        continue;
      }

      // 一致ワードフィルタ（いずれかを含む必要がある）
      if (incWords.isNotEmpty) {
        bool found = false;
        for (final w in incWords) {
          if (lower.contains(w)) {
            found = true;
            break;
          }
        }
        if (!found) continue;
      }

      // 除外ワードフィルタ（いずれかを含んだら除外）
      if (excWords.isNotEmpty) {
        bool excluded = false;
        for (final w in excWords) {
          if (lower.contains(w)) {
            excluded = true;
            break;
          }
        }
        if (excluded) continue;
      }

      filteredIds.add(videoIds[i]);
      filteredTitles.add(title);
    }
    return (filteredIds, filteredTitles);
  }

  // ── AI 用語解説 (網羅モード) のキャンセル / 一時停止 / 再開 ────────────
  // 網羅モードは Plan → Expand (バッチ反復) → Merge という長時間処理になる。
  // ユーザーが SnackBar の「停止」ボタンで止めたとき、それまでに完了した
  // 子テーマぶんは既にページへ書き出した上で、残り未処理を `_pausedExplainSession`
  // に保存して再開できるようにする。
  bool _explainInProgress = false;
  bool get isExplainInProgress => _explainInProgress;
  bool _explainCancelRequested = false;

  PausedExplainSession? _pausedExplainSession;
  PausedExplainSession? get pausedExplainSession => _pausedExplainSession;
  bool get hasPausedExplain => _pausedExplainSession != null;

  /// 進行中の網羅モード解説生成を「次のバッチ境界で停止」要求する。
  /// 即座に止まるわけではなく、現在実行中のバッチ (AI 通信) は完走する。
  /// バッチ完走後、それまでの結果でページを書き出して _pausedExplainSession に保存。
  void requestCancelExplain() {
    if (_explainInProgress) {
      _explainCancelRequested = true;
      notifyListeners();
    }
  }

  /// 一時停止セッションを破棄する (ユーザーが「再開しない」を選んだとき)。
  void discardPausedExplainSession() {
    if (_pausedExplainSession == null) return;
    _pausedExplainSession = null;
    notifyListeners();
  }

