  String _browserAiTarget = 'chatgpt';
  String get browserAiTarget => _browserAiTarget;
  Map<String, String> get browserAiTargetDef => browserAiTargets.firstWhere(
        (e) => e['id'] == _browserAiTarget,
        orElse: () => browserAiTargets.first,
      );
  String get browserAiTargetLabel => browserAiTargetDef['label'] ?? 'AI';
  Future<void> setBrowserAiTarget(String id) async {
    if (browserAiTargets.every((e) => e['id'] != id)) return;
    _browserAiTarget = id;
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString('browser_ai_target', id);
    } catch (_) {}
    notifyListeners();
