  /// ブラウザ版 AI に文字を渡すときに先頭へ付ける「前提条件」
  /// (= ユーザー要望: 「日本語で答えて」 「以下の用語を解説して」 等)。
  String _browserAiPrefix = '';
  String get browserAiPrefix => _browserAiPrefix;
  Future<void> setBrowserAiPrefix(String v) async {
    _browserAiPrefix = v;
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString('browser_ai_prefix', v);
    } catch (_) {}
    notifyListeners();
  }

  /// 前提条件を本文の先頭に付けて返す (前提条件が空なら本文そのまま)。
  /// ブラウザ AI へ文字を渡す全経路 (ノードの AI ボタン・範囲選択など) で使う。
  String browserAiApplyPrefix(String text) {
    final p = _browserAiPrefix.trim();
    if (p.isEmpty) return text;
    return '$p\n\n$text';
  }

  /// ノードタイトル等のクエリを、 現在の ブラウザAI ターゲットの URL に
  /// 埋め込んで返す。 query は URL エンコードされる。
  String browserAiUrlForQuery(String query) {
    final tmpl =
        browserAiTargetDef['url'] ?? 'https://www.google.com/search?q={q}';
    return tmpl.replaceAll('{q}', Uri.encodeQueryComponent(query.trim()));
  }

  /// 現在選択中のプロバイダの「使える状態」 (= API キーが設定済みか)。
  bool get hasActiveAiKey {
    switch (_aiProvider) {
      case 'openai':
        return hasOpenaiKey;
      case 'anthropic':
        return hasAnthropicKey;
      case 'grok':
        return hasGrokKey;
      case 'deepseek':
        return hasDeepseekKey;
      default:
        return hasGeminiKey;
    }
  }

