  // ─── 外部サービス URL 用の地域・言語パラメータ ─────────────────────────────
  //
  // YouTube / Spotify / SoundCloud などの URL を組み立てるとき、ユーザーが
  // アプリで選択した言語に応じた表示・検索結果が出るように、それぞれの
  // サービスが受け付けるパラメータを付与する。
  //
  // - YouTube: `&hl=<lang>&gl=<country>` (公式パラメータ)
  // - Spotify: `intl-<lang>` パスプレフィックス (Spotify 国際化URL)
  // - SoundCloud: URL クエリで言語切替する公式 API は無いため、現状は付与しない
  //
  // すべて `_appLanguage` (en/ja/zh/ko/...) を見て決定する。日本国内からの
  // アクセスでも、これらを明示的に指定すれば日本語ページではなく目的の言語の
  // ページに飛べる。

  /// YouTube 用の `hl=<lang>&gl=<country>` クエリ文字列を返す
  /// (例: `hl=en&gl=US`)。 `?` や `&` のプレフィックスは含めない。
  /// URL 構築側で `&` をつけて連結する想定。
  String youtubeRegionQuery() {
    String hl, gl;
    switch (_appLanguage) {
      case 'ja':
        hl = 'ja';
        gl = 'JP';
        break;
      case 'en':
        hl = 'en';
        gl = 'US';
        break;
      case 'zh':
        hl = 'zh-CN';
        gl = 'CN';
        break;
      case 'ko':
        hl = 'ko';
        gl = 'KR';
        break;
      case 'es':
        hl = 'es';
        gl = 'ES';
        break;
      case 'fr':
        hl = 'fr';
        gl = 'FR';
        break;
      case 'de':
        hl = 'de';
        gl = 'DE';
        break;
      case 'pt':
        hl = 'pt';
        gl = 'BR';
        break; // Brazil dominates pt usage
      case 'ru':
        hl = 'ru';
        gl = 'RU';
        break;
      case 'hi':
        hl = 'hi';
        gl = 'IN';
        break;
      case 'ar':
        hl = 'ar';
        gl = 'SA';
        break;
      case 'bn':
        hl = 'bn';
        gl = 'BD';
        break;
      case 'id':
        hl = 'id';
        gl = 'ID';
        break;
      case 'ur':
        hl = 'ur';
        gl = 'PK';
        break;
      case 'pcm':
        hl = 'en';
        gl = 'NG';
        break; // YouTube に pcm なし → 英語ナイジェリア
      case 'arz':
        hl = 'ar';
        gl = 'EG';
        break;
      case 'mr':
        hl = 'mr';
        gl = 'IN';
        break;
      case 'vi':
        hl = 'vi';
        gl = 'VN';
        break;
      case 'te':
        hl = 'te';
        gl = 'IN';
        break;
      case 'ha':
        hl = 'ha';
        gl = 'NG';
        break;
      case 'tr':
        hl = 'tr';
        gl = 'TR';
        break;
      case 'pnb':
        hl = 'pa';
        gl = 'PK';
        break; // YouTube は pnb→pa にフォールバック
      case 'sw':
        hl = 'sw';
        gl = 'KE';
        break;
      case 'tl':
        hl = 'fil';
        gl = 'PH';
        break; // YouTube は tagalog → fil
      case 'ta':
        hl = 'ta';
        gl = 'IN';
        break;
      case 'yue':
        hl = 'zh-HK';
        gl = 'HK';
        break;
      case 'wuu':
        hl = 'zh-CN';
        gl = 'CN';
        break; // wu 用区別なし
      case 'fa':
        hl = 'fa';
        gl = 'IR';
        break;
      case 'th':
        hl = 'th';
        gl = 'TH';
        break;
      case 'jv':
        hl = 'jv';
        gl = 'ID';
        break;
      default:
        hl = 'en';
        gl = 'US';
        break;
    }
    return 'hl=$hl&gl=$gl';
  }

  /// 既存の YouTube URL に `hl` / `gl` を付与した URL を返す。
  /// クエリパラメータに `hl=` / `gl=` がすでに含まれている場合は上書きしない。
  /// 例: `https://m.youtube.com/results?search_query=hello`
  ///   → `https://m.youtube.com/results?search_query=hello&hl=en&gl=US`
  String localizeYoutubeUrl(String url) {
    // すでに hl= が含まれていれば二重付与を避ける
    if (RegExp(r'[?&]hl=').hasMatch(url)) return url;
    final sep = url.contains('?') ? '&' : '?';
    return '$url$sep${youtubeRegionQuery()}';
  }

  /// Spotify Web の国際化URL用パスプレフィックス (例: `intl-en/`)。
  /// `https://open.spotify.com/<prefix>search/<keyword>` の形で使用。
  /// Spotify は intl- パス無しでも動くが、付けると指定言語のUIで開く。
  /// 末尾にスラッシュを含む形式で返す (空でない場合)。
  String spotifyLocalePath() {
    // Spotify が公式に対応している言語コードに正規化。
    // 公式リスト: en, ja, zh, ko, es, fr, de, pt-BR, ru, ar, hi, id, tr, vi,
    //   th, pl, nl, sv, fi, da, nb, cs, el, he, hu, it, ro, uk, etc.
    // 未対応言語は intl- 無しのデフォルト URL にフォールバック (英語)。
    switch (_appLanguage) {
      case 'ja':
        return 'intl-ja/';
      case 'en':
        return 'intl-en/';
      case 'zh':
        return 'intl-zh/';
      case 'ko':
        return 'intl-ko/';
      case 'es':
        return 'intl-es/';
      case 'fr':
        return 'intl-fr/';
      case 'de':
        return 'intl-de/';
      case 'pt':
        return 'intl-pt/';
      case 'ru':
        return 'intl-ru/';
      case 'ar':
      case 'arz':
        return 'intl-ar/';
      case 'hi':
        return 'intl-hi/';
      case 'id':
      case 'jv':
        return 'intl-id/';
      case 'tr':
        return 'intl-tr/';
      case 'vi':
        return 'intl-vi/';
      case 'th':
        return 'intl-th/';
      // 上記以外は Spotify が intl- を理解しないので付けないでデフォルトへ
      default:
        return '';
    }
  }

  /// Spotify URL を国際化バージョンに書き換える。
  /// `https://open.spotify.com/search/...` → `https://open.spotify.com/intl-ja/search/...`
  /// すでに `intl-` プレフィックスが含まれている場合は上書きしない。
  String localizeSpotifyUrl(String url) {
    final prefix = spotifyLocalePath();
    if (prefix.isEmpty) return url;
    if (url.contains('open.spotify.com/intl-')) return url;
    return url.replaceFirst('open.spotify.com/', 'open.spotify.com/$prefix');
  }

  /// SoundCloud は URL クエリで UI 言語を切り替える公式パラメータが
  /// 提供されていないため、現状は URL を変更せずにそのまま返す。
  /// (将来 SoundCloud が `?locale=` 等を提供したらここで対応する)
  String localizeSoundcloudUrl(String url) => url;

  /// アプリ言語コード。
  ///
  /// 既定値は `'en'`。初回起動で言語ピッカーが出る前 (= プロバイダー初期化中の
  /// 一瞬だけ) はこの値が使われる。SharedPreferences に保存値があれば
  /// `_loadGeminiApiKey` で上書きされる。新規インストール時に
  /// 言語ピッカーの「続ける」をそのまま押した場合の言語は `'en'` になる
  /// (ユーザー要望: ピッカーの初期チェック状態は英語にする)。
  String _appLanguage = 'en';
  String get appLanguage => _appLanguage;
  Future<void> setAppLanguage(String code) async {
    if (!supportedLanguages.contains(code)) return;
    final prev = _appLanguage;
    _appLanguage = code;
    // 言語が変わったら祝日キャッシュをクリア (新しい国の祝日を再計算)
    _holidayCache.clear();
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString('appLanguage', code);
    // ── 既定名のページを新言語に追従させる ──
    // 「マップ N」「Map N」「地图 N」など、ページ名がいずれかの言語の
    // デフォルト書式に合致する場合だけ、新しい言語の同じ番号 N に置き換える。
    // ユーザーがリネームした「My Project」のようなページは触らない。
    if (prev != code) {
      bool changed = false;
      for (final p in _pages) {
        final n = _matchedDefaultPageNumber(p.name);
        if (n != null) {
          final newName = _localizedDefaultPageName(n);
          if (p.name != newName) {
            p.name = newName;
            changed = true;
          }
        }
      }
      if (changed) {
        // ignore: discarded_futures
        _saveToStorage();
      }
    }
    // ── 時計の時差をデフォルト追従 ──
    // ユーザーが時差を明示設定していない場合のみ、 新しい言語の地域時刻に
    // 既定値を合わせ直す (「デフォルトでは設定した言語の時刻」 要望)。
    if (prev != code && !_clockOffsetUserSet) {
      // ignore: discarded_futures
      _setClockOffsetInternal(_defaultClockOffsetForLanguage(), userSet: false);
    }
    notifyListeners();
  }

  /// 言語を即時・軽量に適用する (= ユーザー要望: 言語を選んだら直ぐ反映される
  ///   ように)。 タップ毎に全文書を保存して固まらないよう、 既定名ページの
  ///   リネームや _saveToStorage (= 全ツリー jsonEncode) は行わない。 prefs への
  ///   書き込みは行うので、 選んだ直後にアプリを落としても再起動後に残る
  ///   (= 英語に戻る不具合も防ぐ)。 重い後処理は finalizeAppLanguage で閉じる時に
  ///   1 回だけ行う。
  Future<void> applyAppLanguageLight(String code) async {
    if (!supportedLanguages.contains(code)) return;
    if (_appLanguage == code) return;
    _appLanguage = code;
    _holidayCache.clear();
    notifyListeners(); // 即時に UI を再ローカライズ
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString('appLanguage', code);
    } catch (_) {}
  }

  /// 言語確定時の重い後処理 (既定名ページのリネーム + 時計時差 + 保存)。
  ///   言語ダイアログを閉じる時に 1 回だけ呼ぶ (= per-tap の jsonEncode を回避)。
  Future<void> finalizeAppLanguage() async {
    bool changed = false;
    for (final p in _pages) {
      final n = _matchedDefaultPageNumber(p.name);
      if (n != null) {
        final newName = _localizedDefaultPageName(n);
        if (p.name != newName) {
          p.name = newName;
          changed = true;
        }
      }
    }
    if (!_clockOffsetUserSet) {
      // ignore: discarded_futures
      _setClockOffsetInternal(_defaultClockOffsetForLanguage(), userSet: false);
    }
    if (changed) {
      await _saveToStorage();
    }
    notifyListeners();
  }

  /// 初回設定 (言語/タイムゾーン/ユーザー名) をやり直せるようにする
  ///   (= ユーザー要望: 一度起動して langPickerShown が立つと初回設定が二度と
  ///    出ない。 設定からリセットして再表示できるように)。 呼んだ後に画面側で
  ///    初回設定フローを起動する。
  Future<void> resetOnboarding() async {
    _isFirstLaunch = true;
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.remove('langPickerShown');
    } catch (_) {}
    notifyListeners();
  }

  // ── 音声入力 (Speech-to-Text) 設定 ────────────────────────────────────
  /// 音声入力で「区切り語」 として使う単語。 これを話すとそこでノードが
  /// 分割される。 例: "次" を設定して「赤 次 青」 と話すと "赤" と "青" の
  /// 2 ノードが生成される。 空文字なら分割せず 1 ノードにまとめる。
  String _voiceDelimiter = '';
  String get voiceDelimiter => _voiceDelimiter;
  Future<void> setVoiceDelimiter(String word) async {
    _voiceDelimiter = word.trim();
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString('voiceDelimiter', _voiceDelimiter);
    notifyListeners();
  }

  /// 音声入力で「無音が続いたら区切り (スペース) を入れる」 までの秒数
  /// (ユーザー要望)。 短いほどこまめにスペースが入る。 範囲 1〜10、 既定 3。
  int _voicePauseSeconds = 3;
  int get voicePauseSeconds => _voicePauseSeconds;
  Future<void> setVoicePauseSeconds(int sec) async {
    _voicePauseSeconds = sec.clamp(1, 10);
    final prefs = await SharedPreferences.getInstance();
    await prefs.setInt('voicePauseSeconds', _voicePauseSeconds);
    notifyListeners();
  }

  // ── メニューの時計の「時差」 (端末ローカル時刻からのオフセット・分) ──
  // 右上メニューの「日付 + 時刻 + 天気」 表示の時計に適用する。
  // 0 = 端末の時刻そのまま。 例: +540 (= +9:00) で日本時間を表示。
  // 30 分刻みの地域 (インド +5:30 など) に対応するため分で保持する。
  //
  // デフォルト (= ユーザーが未設定) のときは「設定した言語の地域の時刻」 を
  // 表示する (ユーザー要望)。 そのため初期値は
  //   言語の代表 UTC オフセット − 端末ローカルの UTC オフセット
  // で算出する (端末が JST・言語 ja なら 0 になる)。
  int _clockOffsetMinutes = 0;
  // ユーザーが時差ダイアログで明示的に設定したか。 true なら言語変更時に
  // 自動で言語デフォルトへ戻さない (ユーザー設定を尊重)。
  bool _clockOffsetUserSet = false;
  int get clockOffsetMinutes => _clockOffsetMinutes;

  /// 「設定した言語の地域の時刻」 を表示するための既定オフセット (分)。
  /// = 言語の代表 UTC オフセット − 端末ローカルの UTC オフセット。
  int _defaultClockOffsetForLanguage() {
    final deviceUtcMin = DateTime.now().timeZoneOffset.inMinutes;
    return (_langUtcOffsetMinutes(_appLanguage) - deviceUtcMin)
        .clamp(-720, 840);
  }

  /// 言語コード → その言語圏の代表的な UTC オフセット (分)。
  /// 言語は厳密に 1 タイムゾーンに対応しないので「最も代表的な地域」 の
  /// 標準時を採用する (ユーザーは時差ダイアログで自由に変更可能)。
  static int _langUtcOffsetMinutes(String lang) {
    switch (lang) {
      case 'ja':
        return 540; // JST +9
      case 'ko':
        return 540; // KST +9
      case 'zh':
        return 480; // CST +8
      case 'wuu':
        return 480;
      case 'yue':
        return 480; // HK +8
      case 'tl':
        return 480; // PH +8
      case 'id':
        return 420; // WIB +7
      case 'jv':
        return 420;
      case 'vi':
        return 420; // +7
      case 'th':
        return 420; // +7
      case 'bn':
        return 360; // Bangladesh +6
      case 'hi':
        return 330; // IST +5:30
      case 'mr':
        return 330;
      case 'te':
        return 330;
      case 'ta':
        return 330;
      case 'fa':
        return 210; // Iran +3:30
      case 'ur':
        return 300; // Pakistan +5
      case 'pnb':
        return 300;
      case 'ar':
        return 180; // Riyadh +3 (代表)
      case 'ru':
        return 180; // Moscow +3
      case 'sw':
        return 180; // East Africa +3
      case 'arz':
        return 120; // Egypt +2
      case 'tr':
        return 180; // +3
      case 'es':
        return 60; // Spain +1
      case 'fr':
        return 60;
      case 'de':
        return 60;
      case 'ha':
        return 60; // Nigeria +1
      case 'pcm':
        return 60;
      case 'en':
        return 0; // UTC (London 基準)
      case 'pt':
        return 0; // Lisbon 基準
      default:
        return 0;
    }
  }

  Future<void> setClockOffsetMinutes(int minutes) =>
      _setClockOffsetInternal(minutes, userSet: true);

  Future<void> _setClockOffsetInternal(int minutes,
      {required bool userSet}) async {
    _clockOffsetMinutes = minutes.clamp(-720, 840);
    if (userSet) _clockOffsetUserSet = true;
    final prefs = await SharedPreferences.getInstance();
    await prefs.setInt('clockOffsetMinutes', _clockOffsetMinutes);
    if (userSet) await prefs.setBool('clockOffsetUserSet', true);
    notifyListeners();
  }

  /// 時差を適用した「今の時刻」。 メニューの時計表示に使う。
  DateTime get offsetNow =>
      DateTime.now().add(Duration(minutes: _clockOffsetMinutes));

  /// 現在のアプリ言語 (`_appLanguage`) に対応する音声認識ロケール ID。
  /// speech_to_text の `listen(localeId: ...)` に渡す BCP-47 形式。
  /// 「設定した言語で入力される」 という要望に対応するため、 アプリの
  /// 表示言語をそのまま音声認識言語として使う。
  String get speechLocaleId => _speechLocaleForLang(_appLanguage);
  static String _speechLocaleForLang(String lang) {
    switch (lang) {
      case 'ja':
        return 'ja-JP';
      case 'en':
        return 'en-US';
      case 'zh':
        return 'zh-CN';
      case 'yue':
        return 'zh-HK';
      case 'wuu':
