      case 'ko':
        return 'ko-KR';
      case 'es':
        return 'es-ES';
      case 'fr':
        return 'fr-FR';
      case 'de':
        return 'de-DE';
      case 'pt':
        return 'pt-BR';
      case 'ru':
        return 'ru-RU';
      case 'hi':
        return 'hi-IN';
      case 'ar':
        return 'ar-SA';
      case 'arz':
        return 'ar-EG';
      case 'bn':
        return 'bn-BD';
      case 'id':
        return 'id-ID';
      case 'ur':
        return 'ur-PK';
      case 'mr':
        return 'mr-IN';
      case 'vi':
        return 'vi-VN';
      case 'te':
        return 'te-IN';
      case 'ha':
        return 'ha-NG';
      case 'tr':
        return 'tr-TR';
      case 'pnb':
        return 'pa-PK';
      case 'sw':
        return 'sw-KE';
      case 'tl':
        return 'fil-PH';
      case 'ta':
        return 'ta-IN';
      case 'fa':
        return 'fa-IR';
      case 'th':
        return 'th-TH';
      case 'jv':
        return 'jv-ID';
      case 'pcm':
        return 'en-NG';
      default:
        return 'en-US';
    }
  }

  /// 既定書式は `<prefix><n>` で、prefix は末尾にスペース区切り。
  /// 例: 'ja' → 'マップ ' (3文字)
  ///
  /// 翻訳が確定していない言語は英語の 'Map ' にフォールバックする
  /// (ユーザーがリネームすれば自由。これはあくまで「マップ1」「Map 1」相当の
  /// 自動既定名)。
  static String _defaultPageNamePrefixFor(String langCode) {
    switch (langCode) {
      case 'ja':
        return 'マップ ';
      case 'en':
        return 'Map ';
      case 'zh':
        return '地图 ';
