      case 'bn':
        return 'ম্যাপ ';
      case 'id':
        return 'Peta ';
      case 'ur':
        return 'نقشہ ';
      case 'pcm':
        return 'Map '; // 英語ベースのピジン
      case 'arz':
        return 'خريطة ';
      case 'mr':
        return 'नकाशा ';
      case 'vi':
        return 'Bản đồ ';
      case 'te':
        return 'మ్యాప్ ';
      case 'ha':
        return 'Taswira ';
      case 'tr':
