        return '地图 '; // 簡体字
      case 'fa':
        return 'نقشه ';
      case 'th':
        return 'แผนที่ ';
      case 'jv':
        return 'Peta ';
      default:
        return 'Map ';
    }
  }

  /// 現在の `_appLanguage` で n 番目のデフォルトページ名を返す。
  String _localizedDefaultPageName(int n) =>
      '${_defaultPageNamePrefixFor(_appLanguage)}$n';

  /// `name` が「いずれかの言語のデフォルトページ名」に合致する場合、
  /// その番号 N を返す。合致しなければ null。
  /// 言語切替時の自動リネーム判定で使う。ユーザーがリネームした
  /// オリジナルなページ名はここで null になるので保護される。
  int? _matchedDefaultPageNumber(String name) {
    for (final lang in supportedLanguages) {
      final prefix = _defaultPageNamePrefixFor(lang);
      if (name.startsWith(prefix)) {
        final tail = name.substring(prefix.length).trim();
        final n = int.tryParse(tail);
        if (n != null && n > 0) return n;
      }
    }
    return null;
  }

  /// ページ名が「未設定 (空 or 既定の自動生成名)」かどうか (= ユーザー要望:
  /// 作成時は名前を聞かず、 アップロード時に名前が無ければ求める)。
  bool isDefaultPageName(String name) =>
      name.trim().isEmpty || _matchedDefaultPageNumber(name) != null;

  /// AIプロンプトに付与する言語指示（先頭に挿入）
  String languageInstructionForAi() {
    final name = _languageNameForAi(_appLanguage);
    return 'IMPORTANT: Respond ONLY in $name. All output text must be in $name.\n\n';
  }

