  /// 指定キーの翻訳を現在の言語で返す。
  ///
  /// フォールバックチェーン:
  ///   1. 要求言語 (`_appLanguage`) の翻訳
  ///   2. 英語 (`'en'`) の翻訳
  ///   3. 日本語 (`'ja'`) の翻訳
  ///   4. キー文字列そのもの
  ///
  /// 上位30言語に拡張したが、原9言語以外 (= ヒンディー / アラビア / ベンガル
  /// 等) はまだ全キーの翻訳が揃っていない。未翻訳のキーは英語にフォールバック
  /// するので、ユーザーに「日本語が混じる」現象は起きない。
  String t(String key) {
    final entry = _translations[key];
    if (entry == null) return key;
    return entry[_appLanguage] ?? entry['en'] ?? entry['ja'] ?? key;
  }

  // ── AI生成設定 ──────────────────────────────────────────────────
  /// 生成深さ: 1=子ノードのみ, 2=子＋孫ノード
  int aiDepth = 1;

  /// 子ノード生成数の範囲
  int aiChildMin = 5;
  int aiChildMax = 8;

  /// 孫ノード生成数の範囲（aiDepth==2 の場合のみ使用）
  int aiGrandchildMin = 3;
  int aiGrandchildMax = 5;

  /// 選択モデル: 'flash' または 'pro'
  String aiModelTier = 'flash';

  // ── 使用量トラッキング ──────────────────────────────────────────────────
  /// 直近のリクエストのトークン数とコスト
  int lastInputTokens = 0;
  int lastOutputTokens = 0;
  double lastCostUsd = 0.0;

  /// 累計使用量（永続化）
  int totalInputTokens = 0;
  int totalOutputTokens = 0;
  double totalCostUsd = 0.0;

  /// Gemini API価格（2026年4月時点、USD/1M トークン）
  /// - Flash (gemini-2.5-flash): $0.30 input / $2.50 output
  /// - Pro   (gemini-2.5-pro):   $1.25 input / $10.00 output
  static const Map<String, Map<String, double>> _pricing = {
    'flash': {'input': 0.30, 'output': 2.50},
    'pro': {'input': 1.25, 'output': 10.00},
  };

  /// コスト計算（USD）
  static double calcCostUsd(String tier, int inputTokens, int outputTokens) {
    final p = _pricing[tier] ?? _pricing['flash']!;
    final ic = (inputTokens / 1000000) * p['input']!;
    final oc = (outputTokens / 1000000) * p['output']!;
    return ic + oc;
  }

  /// USDを日本円に概算変換（1 USD ≒ 170円で固定）
  static double usdToJpy(double usd) => usd * 170.0;

  /// 金額を整形（$0.0012 / ¥0.19 のように）
  static String formatCost(double usd) {
    final jpy = usdToJpy(usd);
    if (usd < 0.01) {
      return '\$${usd.toStringAsFixed(4)} (約¥${jpy.toStringAsFixed(2)})';
    }
    return '\$${usd.toStringAsFixed(3)} (約¥${jpy.toStringAsFixed(2)})';
  }

  Future<void> _loadAiSettings() async {
    final prefs = await SharedPreferences.getInstance();
    aiDepth = prefs.getInt('aiDepth') ?? 1;
    aiChildMin = prefs.getInt('aiChildMin') ?? 5;
    aiChildMax = prefs.getInt('aiChildMax') ?? 8;
    aiGrandchildMin = prefs.getInt('aiGrandchildMin') ?? 3;
    aiGrandchildMax = prefs.getInt('aiGrandchildMax') ?? 5;
    aiModelTier = prefs.getString('aiModelTier') ?? 'flash';
    totalInputTokens = prefs.getInt('totalInputTokens') ?? 0;
    totalOutputTokens = prefs.getInt('totalOutputTokens') ?? 0;
    totalCostUsd = prefs.getDouble('totalCostUsd') ?? 0.0;
  }

  Future<void> saveAiSettings() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setInt('aiDepth', aiDepth);
    await prefs.setInt('aiChildMin', aiChildMin);
    await prefs.setInt('aiChildMax', aiChildMax);
    await prefs.setInt('aiGrandchildMin', aiGrandchildMin);
    await prefs.setInt('aiGrandchildMax', aiGrandchildMax);
    await prefs.setString('aiModelTier', aiModelTier);
    notifyListeners();
  }

  /// 累計使用量を永続化
  Future<void> _saveUsageTotals() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setInt('totalInputTokens', totalInputTokens);
    await prefs.setInt('totalOutputTokens', totalOutputTokens);
    await prefs.setDouble('totalCostUsd', totalCostUsd);
  }

  /// 累計使用量をリセット
  Future<void> resetUsageTotals() async {
    totalInputTokens = 0;
    totalOutputTokens = 0;
    totalCostUsd = 0.0;
    await _saveUsageTotals();
    notifyListeners();
  }

  /// 起動時に最優先で読む UI 状態 (= ユーザー報告 (複数回): モバイルで言語
  /// ピッカーが出ない / 言語が英語のまま / 下部ボタンが集中ロックだけで他が空)。
  /// _loadGeminiApiKey の途中で万一ハング/例外が起きても、 これらだけは確実に
  /// 読めるように、 短く各行 try/catch で読み、 初期化 Completer もここで完了
  /// させる (= ピッカー判定を確実に走らせる)。 _loadGeminiApiKey でも同じものを
  /// 読むが冪等。
  Future<void> _loadEssentialUiState() async {
    final SharedPreferences prefs;
    try {
      prefs = await SharedPreferences.getInstance();
    } catch (_) {
      if (!_initialLoadCompleter.isCompleted) {
        _initialLoadCompleter.complete();
      }
      return;
    }
    try {
      _appLanguage = prefs.getString('appLanguage') ?? 'en';
    } catch (_) {}
    try {
      _isFirstLaunch = !(prefs.getBool('langPickerShown') ?? false);
    } catch (_) {}
    // 下部バー 2 段目 (5 スロット): 空なら既定。
    try {
      final j = prefs.getString('customBottomButtons');
      if (j != null && j.isNotEmpty) {
        _customBottomButtons
          ..clear()
          ..addAll((jsonDecode(j) as List)
              .map((e) => e.toString())
              .take(mobileBottomCustomSlots));
      }
    } catch (_) {}
    if (_customBottomButtons.isEmpty) {
      _customBottomButtons.addAll(defaultBottomBottomButtons);
    }
    // 下部バー 1 段目 (6 スロット): 空なら既定。
    try {
      final j = prefs.getString('customBottomTopButtons');
      if (j != null && j.isNotEmpty) {
        _customBottomTopButtons
          ..clear()
          ..addAll((jsonDecode(j) as List)
              .map((e) => e.toString())
              .take(mobileBottomTopCustomSlots));
      }
    } catch (_) {}
    if (_customBottomTopButtons.isEmpty) {
      _customBottomTopButtons.addAll(defaultBottomTopButtons);
    }
    notifyListeners();
    if (!_initialLoadCompleter.isCompleted) {
      _initialLoadCompleter.complete();
    }
  }

  Future<void> _loadGeminiApiKey() async {
    final prefs = await SharedPreferences.getInstance();
    // ★ 最重要 UI フラグは何よりも先に確定させる (= ユーザー報告: モバイルで
    //   初回の言語ピッカーが出ない / 言語が英語のまま変えられない / 下部ボタンが
    //   設定できない)。 この後の読み込みで万一どこかで例外が出ても、 言語と
    //   初回起動フラグだけは確実に読めているよう、 先頭で個別 try/catch して読む。
    //   (後段にも同じ読み込みがあるが冪等。 多重読みのコストは無視できる)。
    try {
      _appLanguage = prefs.getString('appLanguage') ?? 'en';
    } catch (_) {}
    try {
      _isFirstLaunch = !(prefs.getBool('langPickerShown') ?? false);
    } catch (_) {}
    // ── BYOK (Bring Your Own Key) ── (= ユーザー要望)
    // Gemini キーは「利用者が自分で取得して設定画面に入力する」 ものとする。
    // ビルド時に開発者のキーを焼き込まない (逆コンパイルでの抜き取り/不正利用
    // 対策)。 そのため dart-define の GEMINI_API_KEY フォールバックは廃止。
    _geminiApiKey = prefs.getString('gemini_api_key');
    // 他社AI APIキーとプロバイダ・言語設定も読み込む
    _openaiApiKey = prefs.getString('openai_api_key');
    _anthropicApiKey = prefs.getString('anthropic_api_key');
    _aiProvider = prefs.getString('aiProvider') ?? 'gemini';
    _imageGenModel = prefs.getString('imageGenModel') ?? 'auto';
    // Ollama は廃止したため、 旧設定で 'ollama' が選ばれていたら gemini に戻す。
    if (_aiProvider == 'ollama') _aiProvider = 'gemini';
    // Grok (x.ai) / DeepSeek の API キーとモデル
    _grokApiKey = prefs.getString('grok_api_key');
    _grokModel = prefs.getString('grok_model') ?? 'grok-3';
    _deepseekApiKey = prefs.getString('deepseek_api_key');
    _deepseekModel = prefs.getString('deepseek_model') ?? 'deepseek-chat';
    // ノードAIボタンの ブラウザAI ターゲット (ChatGPT/Gemini/…)
    _browserAiTarget = prefs.getString('browser_ai_target') ?? 'chatgpt';
    // 念のため try/catch (= 起動フロー保護: ここで例外が出ても言語/初回起動/
    //   下部ボタンの読み込みが止まらないように)。
    try {
      if (browserAiTargets.every((e) => e['id'] != _browserAiTarget)) {
        _browserAiTarget = 'chatgpt';
      }
    } catch (_) {}
    // ブラウザ AI の前提条件 (= ユーザー要望)
    _browserAiPrefix = prefs.getString('browser_ai_prefix') ?? '';
    // ── PDF 最終ページ記憶のロード ──
    try {
      final lastPagesJson = prefs.getString('lastPdfPages_v1');
      if (lastPagesJson != null) {
        final decoded = jsonDecode(lastPagesJson) as Map<String, dynamic>;
        _lastPdfPages = decoded.map((k, v) => MapEntry(k, (v as num).toInt()));
      }
    } catch (e) {
      debugPrint('lastPdfPages ロード失敗: $e');
    }
    // Ollama 設定の復元 (廃止済み) は削除。 旧 'ollama' プロバイダ選択は
    // 上の _aiProvider 読み込み時に gemini へ移行済み。
    _openaiModel = prefs.getString('openaiModel') ?? 'gpt-4o-mini';
    _anthropicModel = prefs.getString('anthropicModel') ?? 'claude-haiku-4-5';
    _appLanguage = prefs.getString('appLanguage') ?? 'en';
    // 音声入力の区切り語
    _voiceDelimiter = prefs.getString('voiceDelimiter') ?? '';
    _voicePauseSeconds = (prefs.getInt('voicePauseSeconds') ?? 3).clamp(1, 10);
    // メニュー時計の時差 (分)。 保存値があればそれを使い (= ユーザーが
    // 過去に設定済み)、 無ければ「設定言語の地域の時刻」 を既定にする。
    final savedClockOffset = prefs.getInt('clockOffsetMinutes');
    if (savedClockOffset != null) {
      _clockOffsetMinutes = savedClockOffset.clamp(-720, 840);
      // 旧バージョンには userSet フラグが無いので、 保存値があれば
      // ユーザー設定扱いにして言語デフォルトで上書きしない。
      _clockOffsetUserSet = prefs.getBool('clockOffsetUserSet') ?? true;
    } else {
      _clockOffsetMinutes = _defaultClockOffsetForLanguage();
      _clockOffsetUserSet = false;
    }
    // Ctrl+1〜9 のショートカット基準フォルダーの読み込み
    _shortcutFolderId = prefs.getString(_kShortcutFolderId);
    // 初回起動判定: 専用フラグ 'langPickerShown' で追跡
    // （appLanguage と分離することで、既存ユーザーもアップデート後に
    //  言語確認ダイアログを一度表示できる）
    _isFirstLaunch = !(prefs.getBool('langPickerShown') ?? false);
    // ダーク/ライトモード (デフォルト: ライト)
    _isDarkMode = prefs.getBool('isDarkMode') ?? false;
    // PDF ↑↓ ステップ。 デフォルトを 10 (= 1 押下で 1/10 ページ) に。
    // 旧デフォルト 1 (= 1 押下で 1 ページ丸ごと) は「進み過ぎて読みにくい」
    //   というユーザー報告があったため、 細かめの既定値に変更。 既に設定済み
    //   のユーザーの値はそのまま尊重する。
    _pdfArrowStepDivisor =
        (prefs.getInt('pdfArrowStepDivisor') ?? 10).clamp(1, 100);
    _pdfScrollHorizontal = prefs.getBool('pdfScrollHorizontal') ?? false;
    _eventNotifyLeadMinutes =
        (prefs.getInt('eventNotifyLeadMinutes') ?? 15).clamp(0, 1440);
    _nodeSearchUseYoutube = prefs.getBool('nodeSearchUseYoutube') ?? false;
    _nodeLinkUseAttach = prefs.getBool('nodeLinkUseAttach') ?? false;
    _nodeCalendarUseFlashcard =
        prefs.getBool('nodeCalendarUseFlashcard') ?? false;
    // ── ジオフェンス画面ロック設定 ──
    _geofenceLockEnabled = prefs.getBool('geofenceLockEnabled') ?? false;
    _geofenceLat = prefs.getDouble('geofenceLat');
    _geofenceLon = prefs.getDouble('geofenceLon');
    _geofenceRadiusKm =
        (prefs.getDouble('geofenceRadiusKm') ?? 1.0).clamp(0.05, 500.0);
    _geofenceMode = prefs.getString('geofenceMode') ?? 'enter';
    _geofenceLockMinutes =
        (prefs.getInt('geofenceLockMinutes') ?? 30).clamp(1, 24 * 60);
    _pdfAiPanelDefault = prefs.getString('pdfAiPanelDefault') ?? 'chatgpt';
    _pdfFitPageDefault = prefs.getBool('pdfFitPageDefault') ?? true;
    _decoTextAnchorX =
        (prefs.getDouble('decoTextAnchorX') ?? 0.5).clamp(0.0, 1.0);
    _decoTextAnchorY =
        (prefs.getDouble('decoTextAnchorY') ?? 0.5).clamp(0.0, 1.0);
    // PDF ←→ ページジャンプ数 (デフォルト: 1 ページ)
    _pdfPageJumpCount = (prefs.getInt('pdfPageJumpCount') ?? 1).clamp(1, 50);
    // PDF ハイライト (マーカー) の復元
    try {
      final str = prefs.getString('pdfHighlights');
      if (str != null && str.isNotEmpty) {
        final decoded = jsonDecode(str);
        if (decoded is Map) {
          _pdfHighlights.clear();
          decoded.forEach((k, v) {
            if (k is String && v is List) {
              _pdfHighlights[k] = v
                  .whereType<Map>()
                  .map((e) => PdfHighlight.fromJson(e.cast<String, dynamic>()))
                  .toList();
            }
          });
        }
      }
    } catch (_) {}
    // PDF メモフォルダのピン留め状態の復元 (= ユーザー要望)。
    // ★ 起動フロー保護 (= ユーザー報告: モバイルで初回の言語ピッカーが出ない /
    //   言語が英語のまま変えられない / 下部ボタンが設定できない)。 ここで例外が
    //   出ると _loadGeminiApiKey が中断し、 後続の言語/下部ボタン読み込みと
    //   initialLoadDone の完了がスキップされてしまうため、 個別に try/catch で握る。
    try {
      await _loadPdfMemoPinnedFolders();
    } catch (_) {}
    try {
      await _loadPdfMemoFolderTopIndex();
    } catch (_) {}
    // リンク・PDF をアプリ内で開くか (デフォルト: true)
    _openLinksInApp = prefs.getBool('openLinksInApp') ?? true;
    // 画像貼り付けスケール (%): 0 = OFF / 1〜100 = 画像 × (% / 100)
    // 旧キー `pasteImageOriginalSize` (bool) があれば true→100, false→0 で
    // マイグレーション (= 旧バージョンユーザーの設定が壊れないように)。
    final newScale = prefs.getInt('pasteImageScalePercent');
    if (newScale != null) {
      _pasteImageScalePercent = newScale.clamp(0, 100);
    } else {
      final legacyOriginal = prefs.getBool('pasteImageOriginalSize');
      if (legacyOriginal != null) {
        _pasteImageScalePercent = legacyOriginal ? 100 : 0;
        try {
          await prefs.setInt('pasteImageScalePercent', _pasteImageScalePercent);
        } catch (_) {}
      } else {
        _pasteImageScalePercent = 50; // デフォルト 50%
      }
    }
    // ノード生成時にタイトル入力を求めるか (デフォルト: false)
    _promptForTitleOnNodeCreate =
        prefs.getBool('promptForTitleOnNodeCreate') ?? false;
    // ノード分割の区切り文字 (デフォルト: 改行)
    final savedSplitDelim = prefs.getString('nodeSplitDelimiter');
    if (savedSplitDelim != null && savedSplitDelim.isNotEmpty) {
      _nodeSplitDelimiter = savedSplitDelim;
    }
    // 集中ロック設定
    _focusLockHideSeconds = prefs.getBool('focusLockHideSeconds') ?? false;
    _hideEmbedRelated = prefs.getBool('hideEmbedRelated') ?? true;
    _focusLockHideUnlockBtn = prefs.getBool('focusLockHideUnlockBtn') ?? false;
    _focusLockScheduleEnabled =
        prefs.getBool('focusLockScheduleEnabled') ?? false;
    _focusLockScheduleStartMin =
        prefs.getInt('focusLockScheduleStartMin') ?? (22 * 60);
    _focusLockScheduleEndMin =
        prefs.getInt('focusLockScheduleEndMin') ?? (6 * 60);
    try {
      final raw = prefs.getString('focusLockSchedules');
      if (raw != null && raw.isNotEmpty) {
        final list = jsonDecode(raw) as List;
        _focusLockSchedules = list
            .map((e) => FocusLockSchedule.fromJson(e as Map<String, dynamic>))
            .toList();
      }
    } catch (_) {}
    // カスタムヘッダーボタン
    final customButtonsJson = prefs.getString('customHeaderButtons');
    if (customButtonsJson != null && customButtonsJson.isNotEmpty) {
      try {
        final list = jsonDecode(customButtonsJson) as List<dynamic>;
        _customHeaderButtons
          ..clear()
          // 旧バージョンで 'aiSettings' を追加していたユーザー向けの後処理:
          // AI設定は設定シート / ⋮メニューに集約したのでカスタム項目からは除外。
          // ロード時に取り除き、次回保存で永続的に消える。
          ..addAll(
              list.map((e) => e as String).where((id) => id != 'aiSettings'));
        // 新機能 'mapMemo' を既存ユーザーにも 1 度だけヘッダーへ追加する
        //   (= ユーザー要望: デフォルトでマップメモをヘッダーに設定)。
        //   一度実行したら以降はユーザーの配置 (削除含む) を尊重する。
        if (prefs.getBool('mig_mapMemo_header_v1') != true) {
          if (!_customHeaderButtons.contains('mapMemo')) {
            _customHeaderButtons.insert(0, 'mapMemo');
          }
          if (!_customHeaderButtons.contains('shortcuts')) {
            _customHeaderButtons.add('shortcuts');
          }
          prefs.setBool('mig_mapMemo_header_v1', true);
          // 移行結果を永続化しないと次回起動で元の (mapMemo 無し) 値に戻って
          //   しまうため、 ここで保存しておく。
          prefs.setString(
              'customHeaderButtons', jsonEncode(_customHeaderButtons));
        }
      } catch (_) {}
    } else {
      // ── 初回起動時のデフォルト ──
      // ユーザー要望「デフォルトではマップ毎のメモとショートカットキー一覧を
      //   ヘッダーに設定しておいて」。 保存値が無い (= 一度もカスタマイズして
      //   いない) ときだけ mapMemo / shortcuts をヘッダーに配置する。 既に
      //   カスタマイズ済みのユーザーの配置は (空であっても) 尊重する。
      _customHeaderButtons
        ..clear()
        ..add('mapMemo')
        ..add('shortcuts');
    }
    // ギャラリー (normal 以外) ヘッダーボタン。 保存値が「無い」 ときだけ
    //   現状と同じデフォルト構成を入れる。 保存済みの空配列 '[]' は (= 意図的に
    //   全消し) 尊重する (空文字/絶対不在のときのみシード)。
    final galleryButtonsJson = prefs.getString('galleryHeaderButtons');
    if (galleryButtonsJson != null && galleryButtonsJson.isNotEmpty) {
      try {
        final list = jsonDecode(galleryButtonsJson) as List<dynamic>;
        _galleryHeaderButtons
          ..clear()
          ..addAll(list.map((e) => e as String));
      } catch (_) {
        _galleryHeaderButtons
          ..clear()
          ..addAll(defaultGalleryHeaderButtons);
      }
    } else {
      _galleryHeaderButtons
        ..clear()
        ..addAll(defaultGalleryHeaderButtons);
    }
    // モバイル下部バーのカスタム項目（最大 5 スロット）
    final customBottomJson = prefs.getString('customBottomButtons');
    if (customBottomJson != null && customBottomJson.isNotEmpty) {
      try {
        final list = jsonDecode(customBottomJson) as List<dynamic>;
        _customBottomButtons
          ..clear()
          ..addAll(list.map((e) => e as String).take(mobileBottomCustomSlots));
      } catch (_) {}
    }
    // ── 保存値が無い / 空 なら 2 段目デフォルトで初期化 ──
    //   [openYoutube, cutMode, calendar, sync, addPage] (lockScale は別管理)。
    //   (= ユーザー報告: 下部ボタンが「集中ロックだけで他が空」。 過去ビルドで
    //    空配列 "[]" が保存されると、 旧実装は「prefs から読んだ」 扱いにして
    //    既定を入れずに空のままにしていた。 customBottomTopButtons と同じく
    //    「空なら既定」 に統一して、 空配列が残っていても既定が復活するように。)
    if (_customBottomButtons.isEmpty) {
      _customBottomButtons.addAll(defaultBottomBottomButtons);
    }
    // モバイル下部バー 3 行目 (= ユーザー要望: Max のみ。 既定は空 + 無効)。
    _bottomThirdRowEnabled = prefs.getBool('bottomThirdRowEnabled') ?? false;
    final customBottomThirdJson = prefs.getString('customBottomThirdButtons');
    if (customBottomThirdJson != null && customBottomThirdJson.isNotEmpty) {
      try {
        final list = jsonDecode(customBottomThirdJson) as List<dynamic>;
        _customBottomThirdButtons
          ..clear()
          ..addAll(
              list.map((e) => e as String).take(mobileBottomThirdCustomSlots));
      } catch (_) {}
    }
    // モバイル下部バー 1 行目 (6 スロット) - link / file / rangeSelect /
    // addNode / undo / redo がデフォルト。ユーザーが並び替え/差し替え可能。
    // 保存値が無ければデフォルトで初期化する。
    // ── 通常モード (2x6) のロード ──
    final customBottomTopJson = prefs.getString('customBottomTopButtons');
    if (customBottomTopJson != null && customBottomTopJson.isNotEmpty) {
      try {
        final list = jsonDecode(customBottomTopJson) as List<dynamic>;
        _customBottomTopButtons
          ..clear()
          ..addAll(
              list.map((e) => e as String).take(mobileBottomTopCustomSlots));
      } catch (_) {}
    }
    if (_customBottomTopButtons.isEmpty) {
      _customBottomTopButtons.addAll(defaultBottomTopButtons);
    }

    // ── 分割モード (2x2) のロード ──
    // 別キー `customBottomTopButtonsSplit` で独立永続化。
    // 旧バージョンからのアップグレード時はキーが存在せず、 デフォルトを
    // 通常モードからコピーする (= 初期状態は両モード同じ配置)。
    final customBottomTopSplitJson =
        prefs.getString('customBottomTopButtonsSplit');
    if (customBottomTopSplitJson != null) {
      try {
        final list = jsonDecode(customBottomTopSplitJson) as List<dynamic>;
        _customBottomTopButtonsSplit
          ..clear()
          ..addAll(list.map((e) => e.toString()));
      } catch (e) {
        debugPrint('customBottomTopButtonsSplit decode 失敗: $e');
      }
    }
    if (_customBottomTopButtonsSplit.isEmpty) {
      // 初回 (= 旧バージョンから移行): 通常モード設定をコピー
      _customBottomTopButtonsSplit.addAll(_customBottomTopButtons);
    }
    // lockScale ボタン (拡大率) の表示スロット (0=左端=デフォルト)
    _lockScaleBottomSlot = prefs.getInt('lockScaleBottomSlot') ?? 0;
    _lockScaleBottomSlot = _lockScaleBottomSlot.clamp(0, 5);
    // ヘッダーアイコン色: ON状態（右クリック→色変更の永続化）
    final iconColorsJson = prefs.getString('headerIconColors');
    if (iconColorsJson != null && iconColorsJson.isNotEmpty) {
      try {
        final map = jsonDecode(iconColorsJson) as Map<String, dynamic>;
        _headerIconColors
          ..clear()
          ..addAll(map.map((k, v) => MapEntry(k, (v as num).toInt())));
      } catch (_) {}
    }
    // ── ボトムバー専用の色デフォルト適用 ──
    // ユーザーが個別にカスタムしていない ID については、隣接ボタンで色が
    // 被らないよう設計したパレットで初期色を埋める。これにより初回起動時
    // から色のリズムが整って見える。ユーザーが長押し→色変更すると
    // _headerIconColors[id] が上書きされるので、その場合は自動でユーザー
    // 設定が優先される (永続化済み)。
    bool needsSaveDefaultColors = false;
    _defaultButtonColors.forEach((id, color) {
      if (!_headerIconColors.containsKey(id)) {
        _headerIconColors[id] = color;
        needsSaveDefaultColors = true;
      }
    });
    if (needsSaveDefaultColors) {
      // ユーザー設定として書き込んでおくことで、デフォルトを変更しても
      // 既存ユーザーのカスタマイズは尊重される (= 次回以降は保存値が
      // 使われ、_defaultButtonColors を変えても影響しない)。
      // ignore: discarded_futures
      _saveHeaderIconColors();
    }
    // ヘッダーアイコン色: OFF状態（トグル系アイコンがOFFの時に使う色。デフォルトは灰色）
    final iconColorsOffJson = prefs.getString('headerIconColorsOff');
    if (iconColorsOffJson != null && iconColorsOffJson.isNotEmpty) {
      try {
        final map = jsonDecode(iconColorsOffJson) as Map<String, dynamic>;
        _headerIconColorsOff
          ..clear()
          ..addAll(map.map((k, v) => MapEntry(k, (v as num).toInt())));
      } catch (_) {}
    }
    // ── load 完了通知 ──
    // この関数 (_loadGeminiApiKey) は非同期で走るが、コンストラクタでは
    // await されない。そのため、UI の最初の build 時にはここで読み込んだ
    // 値 (例: _headerIconColors のデフォルト色マップ) がまだ反映されない。
    // load 完了したことを Consumer に通知して、再 build をトリガーする。
    notifyListeners();
    // 初期化完了 Future を完了させる。UI 側 (initState の addPostFrameCallback)
    // が `await provider.initialLoadDone` で待っているので、ここで isFirstLaunch
    // などのフラグが確定した状態で UI に判定させる。
    if (!_initialLoadCompleter.isCompleted) {
      _initialLoadCompleter.complete();
    }
  }

  /// 初期化用 Completer。`_loadGeminiApiKey` (= 言語フラグ・色設定など多くの
  /// SharedPreferences 値を読み込む) が完了したら complete される。
  ///
  /// UI 側で `await provider.initialLoadDone` してから `isFirstLaunch` などを
  /// 判定すれば、確実にロード完了後の値で初回起動フローを分岐できる。
  final Completer<void> _initialLoadCompleter = Completer<void>();
  Future<void> get initialLoadDone => _initialLoadCompleter.future;

  /// 初回起動フラグ（言語選択ダイアログ表示に使用）
  bool _isFirstLaunch = false;
