  static const int mobileHeaderCustomSlots = 3;

  // ─── モバイル下部バーのカスタム項目（5 スロット）──────────────────────────
  // レイアウト:
  //   1行目: [link][file][rangeSelect][addNode][undo][redo]  ← 6スロット (デフォルト値)
  //          → _customBottomTopButtons で管理。並び替えやカスタマイズが可能。
  //   2行目: [拡大率(lockScale)] | [custom0][custom1][custom2][custom3][custom4]
  //          → _customBottomButtons で 5 スロットを管理。
  //          + 拡大率ボタンは _lockScaleBottomSlot で位置を記録 (0=左端固定、
  //            1〜5 にすると customBottomButtons の前にいる i 番目に挿入される)
  static const int mobileBottomCustomSlots = 5;
  final List<String> _customBottomButtons = [];
  List<String> get customBottomButtons =>
      List.unmodifiable(_customBottomButtons);

  /// 下部バー 2 行目の lockScale (拡大率ロック) ボタンの位置 (0..5)。
  /// 0 が左端 (デフォルト)。並び替えで他のスロットと交換できる。
  int _lockScaleBottomSlot = 0;
  int get lockScaleBottomSlot => _lockScaleBottomSlot;

  /// 拡大率(lockScale)ボタンと、指定された「見た目スロット」(0..5) にある
  /// カスタムボタンを **見た目上で入れ替える**。
  ///
  /// 内部実装上、lockScale の位置は `_lockScaleBottomSlot` という独立の
  /// インデックスで管理し、残りの 5 スロットを `_customBottomButtons` で
  /// 管理する。視覚上の 6 スロット中で lockScale 位置だけが「飛び地」に
  /// なる構造のため、単純に lockSlot を移動するだけだと、押し出された
  /// ボタンが期待と違う位置に再配置されて見える。
  ///
  /// このメソッドは「ユーザーから見たスワップ」を実現するため、
  ///   1. もともと target 位置にあったカスタムボタンを抜き取り、
  ///   2. 旧 lockSlot 位置 (= visible index 上の旧 lockScale 位置) に
  ///      そのカスタムボタンを差し込み直す
  ///   3. lockSlot を target に書き換える
  /// の 3 ステップを行う。これで「lockScale ↔ そのカスタムボタン」の
  /// 視覚スワップになる。
  Future<void> swapLockScaleWithVisibleSlot(int targetVisibleSlot) async {
    if (targetVisibleSlot < 0 || targetVisibleSlot > 5) return;
    final oldLock = _lockScaleBottomSlot.clamp(0, 5);
    if (targetVisibleSlot == oldLock) return;

    // 視覚スロット → customs[] のインデックス変換
    int? visibleToCustomIdx(int visIdx, int lockSlot) {
      if (visIdx == lockSlot) return null; // lockScale 位置は customs にない
      return visIdx > lockSlot ? visIdx - 1 : visIdx;
    }

    final targetCustomIdx = visibleToCustomIdx(targetVisibleSlot, oldLock);
    final oldLockCustomIdxInNewLayout =
        visibleToCustomIdx(oldLock, targetVisibleSlot);

    if (targetCustomIdx == null || oldLockCustomIdxInNewLayout == null) {
      // ロジック上ここには来ないはず (target != oldLock を確認済み)
      _lockScaleBottomSlot = targetVisibleSlot;
      final prefs = await SharedPreferences.getInstance();
      await prefs.setInt('lockScaleBottomSlot', _lockScaleBottomSlot);
      notifyListeners();
      return;
    }

    // ① target 位置にあったカスタムボタンを抜き取る
    if (targetCustomIdx >= _customBottomButtons.length) {
      // target が空スロットだった場合: lockScale だけを移動して終了
      _lockScaleBottomSlot = targetVisibleSlot;
    } else {
      final movedCustom = _customBottomButtons.removeAt(targetCustomIdx);
      // ② 新 lockSlot=target における「旧 lockScale 視覚位置」の customIdx に挿入
      final insertAt =
          oldLockCustomIdxInNewLayout.clamp(0, _customBottomButtons.length);
      _customBottomButtons.insert(insertAt, movedCustom);
      // ③ lockSlot を更新
      _lockScaleBottomSlot = targetVisibleSlot;
      // 永続化 (customs 側も変更したので両方保存)
      await _saveCustomBottomButtons();
    }
    final prefs = await SharedPreferences.getInstance();
    await prefs.setInt('lockScaleBottomSlot', _lockScaleBottomSlot);
    notifyListeners();
  }

  // ─── モバイル下部バー 1 行目 (6 スロット) ────────────────────────────────
