  ///
  /// 色配置:
  ///   1段目: 🔵link / 🟢file / 🟠rangeSelect / 🟣addNode / 💙undo / 💙redo
  ///   2段目: 🟠lockScale / 🔴openYoutube / 🟣cutMode / 💙calendar / 🟢sync / 🔵addPage
  /// (戻る/進むは意味的に対なので同じ色にする。YouTubeはブランド色の赤。)
  ///
  /// 確認:
  ///   左右(1段目): 🔵🟢 / 🟢🟠 / 🟠🟣 / 🟣💙 / 💙💙(意図的に同色)
  ///   左右(2段目): 🟠🔴 / 🔴🟣 / 🟣💙 / 💙🟢 / 🟢🔵 → どの隣接も別色
  ///   上下: 🔵↔🟠 / 🟢↔🔴 / 🟠↔🟣 / 🟣↔💙 / 💙↔🟢 / 💙↔🔵 → 全部別色
  static const Map<String, int> _defaultButtonColors = {
    // 1段目
    'link': 0xFF4FC3F7, // 🔵
    'file': 0xFF43B97F, // 🟢
    'rangeSelect': 0xFFFFB347, // 🟠
    'addNode': 0xFFBA68C8, // 🟣
    'undo': 0xFF6C63FF, // 💙
    'redo': 0xFF6C63FF, // 💙 (戻る/進む は意味的に対なので同色)
    // 2段目
    'lockScale': 0xFFFFB347, // 🟠
    'openYoutube': 0xFFFF6B6B, // 🔴 (YouTube ブランドカラー)
    'cutMode': 0xFFBA68C8, // 🟣
    'calendar': 0xFF6C63FF, // 💙
    'sync': 0xFF43B97F, // 🟢
    'addPage': 0xFF4FC3F7, // 🔵
  };

  // ─── モバイル下部バー 1 行目: 通常モード (2x6 = 6 スロット) と
