  // ─── PDF ←→ キーのページジャンプ数 ───
  /// PDF ビューアで ← / → キーを 1 回押下したとき何ページ分進む / 戻るか。
  /// デフォルト 1 (= 通常のページ送り)。 範囲は 1〜50。
  /// 大きい論文・教科書をざっと飛ばし読みする用途を想定。
  int _pdfPageJumpCount = 1;
  int get pdfPageJumpCount => _pdfPageJumpCount;
  Future<void> setPdfPageJumpCount(int value) async {
    final v = value.clamp(1, 50);
