  // ─── PDF ハイライト (マーカー) の永続化 ───
  /// ノード ID → そのノードに紐づく PDF のハイライト一覧。
  /// 同じノードを開き直したとき、 同じ場所にマーカーが復元される。
  final Map<String, List<PdfHighlight>> _pdfHighlights = {};

  /// 指定ノードに保存されているハイライト一覧を取得 (読み取り専用)。
  List<PdfHighlight> getPdfHighlights(String nodeId) =>
      List.unmodifiable(_pdfHighlights[nodeId] ?? const []);

  /// ノードにハイライトを 1 件追加。
  Future<void> addPdfHighlight(String nodeId, PdfHighlight h) async {
    _pdfHighlights.putIfAbsent(nodeId, () => []).add(h);
    await _savePdfHighlights();
    notifyListeners();
  }

  /// 指定 ID のハイライトを削除。
  Future<void> removePdfHighlight(String nodeId, String highlightId) async {
    final list = _pdfHighlights[nodeId];
    if (list == null) return;
    list.removeWhere((h) => h.id == highlightId);
    if (list.isEmpty) _pdfHighlights.remove(nodeId);
    await _savePdfHighlights();
    notifyListeners();
  }

  /// 指定ノードのハイライトを全削除。
  Future<void> clearPdfHighlights(String nodeId) async {
    if (_pdfHighlights.remove(nodeId) == null) return;
    await _savePdfHighlights();
    notifyListeners();
  }

  /// SharedPreferences に保存 (全ノードのハイライトを 1 つの JSON として)。
  Future<void> _savePdfHighlights() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final encoded = jsonEncode(
        _pdfHighlights.map(
          (k, v) => MapEntry(k, v.map((h) => h.toJson()).toList()),
        ),
      );
      await prefs.setString('pdfHighlights', encoded);
    } catch (_) {}
  }

  /// ── PDF メモフォルダのピン留め (= ユーザー要望) ──
  /// PdfMemo / MindMapNode モデルを変更せずに済むよう、 ピン留め状態は
  /// ノード ID → ピン留めフォルダ名の集合として provider のメモリ Map +
  /// SharedPreferences に保持する (= pdfHighlights と同じサイドデータ方式)。
  final Map<String, Set<String>> _pdfMemoPinnedFolders = {};

  /// SharedPreferences に保存。
  Future<void> _savePdfMemoPinnedFolders() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final encoded = jsonEncode(
        _pdfMemoPinnedFolders.map((k, v) => MapEntry(k, v.toList())),
      );
      await prefs.setString('pdfMemoPinnedFolders_v1', encoded);
    } catch (_) {}
  }

  /// SharedPreferences から読み込み (アプリ起動時)。
  Future<void> _loadPdfMemoPinnedFolders() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final str = prefs.getString('pdfMemoPinnedFolders_v1');
      if (str == null || str.isEmpty) return;
      final decoded = jsonDecode(str) as Map<String, dynamic>;
      _pdfMemoPinnedFolders.clear();
      decoded.forEach((k, v) {
        _pdfMemoPinnedFolders[k] = (v as List).map((e) => e as String).toSet();
      });
    } catch (_) {}
  }

  // ─── PDF メモ: フォルダの top 位置 (= メモ間の挿入位置) ──
  // (= ユーザー要望: フォルダーをドラッグで未分類メモの上に上げたり下げたり
  // 自由に並び替えできるように)。 整数値はその時点での「unfiltered メモ数
  // 0..N」 の挿入位置を意味する。 未設定 = N (= リスト末尾、 デフォルト挙動)。
  final Map<String, Map<String, int>> _pdfMemoFolderTopIndex = {};

  Future<void> _savePdfMemoFolderTopIndex() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final encoded = jsonEncode(_pdfMemoFolderTopIndex);
      await prefs.setString('pdfMemoFolderTopIndex_v1', encoded);
    } catch (_) {}
  }

  Future<void> _loadPdfMemoFolderTopIndex() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final str = prefs.getString('pdfMemoFolderTopIndex_v1');
      if (str == null || str.isEmpty) return;
      final decoded = jsonDecode(str) as Map<String, dynamic>;
      _pdfMemoFolderTopIndex.clear();
      decoded.forEach((k, v) {
        final m = <String, int>{};
        (v as Map<String, dynamic>).forEach((f, idx) {
          if (idx is int) m[f] = idx;
        });
        _pdfMemoFolderTopIndex[k] = m;
      });
    } catch (_) {}
  }

  /// 指定フォルダの top 位置 (= unfiltered メモ列の 0..N の挿入位置) を取得。
  /// null = 未設定 (= デフォルトはリスト末尾扱い)。
  int? getPdfMemoFolderTopIndex(String nodeId, String folder) {
    return _pdfMemoFolderTopIndex[nodeId]?[folder];
  }

  /// 指定フォルダの top 位置をセット。 [topIndex] は 0..(unfiltered メモ数) の範囲。
  void setPdfMemoFolderTopIndex(String nodeId, String folder, int topIndex) {
    final m = _pdfMemoFolderTopIndex.putIfAbsent(nodeId, () => <String, int>{});
    m[folder] = topIndex;
    _savePdfMemoFolderTopIndex();
    notifyListeners();
  }

  /// 指定フォルダの top 位置をクリア (= フォルダ削除時など)。
  void clearPdfMemoFolderTopIndex(String nodeId, String folder) {
    final m = _pdfMemoFolderTopIndex[nodeId];
    if (m == null) return;
    m.remove(folder);
    if (m.isEmpty) _pdfMemoFolderTopIndex.remove(nodeId);
    _savePdfMemoFolderTopIndex();
  }

  /// フォルダの親を変更する (= ユーザー要望: フォルダーにフォルダーを
  /// ドラッグ&ドロップで入れられるように)。
  /// [folder] のフォルダ名 (= slash 区切り) の最後のセグメントだけ残し、
  ///   先頭を [newParent] に置き換える。 [newParent] が null/空ならルート
  ///   レベルに戻す。
  /// 子孫を循環参照させようとした場合 (= newParent が folder 自身か
  ///   その子孫) は何もせず return。
  void movePdfFolderInto(String nodeId, String folder, String? newParent) {
    if (folder == newParent) return;
    if (newParent != null && newParent.isNotEmpty) {
      // 循環チェック: newParent が folder 自身の子孫ならダメ
      if (newParent == folder || newParent.startsWith('$folder/')) return;
    }
    final node = nodes[nodeId];
    if (node == null) return;
    final lastSeg = folder.contains('/')
        ? folder.substring(folder.lastIndexOf('/') + 1)
        : folder;
    final newName = (newParent == null || newParent.isEmpty)
        ? lastSeg
        : '$newParent/$lastSeg';
    // 既に同じ位置なら何もしない
    if (newName == folder) return;
    _pushUndo();
    // ── フォルダ自身 + 子孫 (= prefix が folder + '/' で始まるもの) を
    //    リネーム ──
    final renames = <String, String>{folder: newName};
    if (node.pdfMemoFolders != null) {
      for (final f in node.pdfMemoFolders!) {
        if (f.startsWith('$folder/')) {
          renames[f] = newName + f.substring(folder.length);
        }
      }
    }
    // pdfMemoFolders を更新 (= folder 宣言リスト)
    if (node.pdfMemoFolders != null) {
      node.pdfMemoFolders =
          node.pdfMemoFolders!.map((f) => renames[f] ?? f).toList();
    }
    // メモの folder フィールドも更新
    if (node.pdfMemos != null) {
      for (int i = 0; i < node.pdfMemos!.length; i++) {
        final m = node.pdfMemos![i];
        final mf = m.folder;
        if (mf != null && renames.containsKey(mf)) {
          node.pdfMemos![i] = m.copyWith(folder: renames[mf]!);
        }
      }
    }
    // topIndex のキーも追従させる
    final tmap = _pdfMemoFolderTopIndex[nodeId];
    if (tmap != null) {
      final newMap = <String, int>{};
      tmap.forEach((k, v) {
        newMap[renames[k] ?? k] = v;
      });
      _pdfMemoFolderTopIndex[nodeId] = newMap;
      _savePdfMemoFolderTopIndex();
    }
    // ピン留めのキーも追従
    final pinned = _pdfMemoPinnedFolders[nodeId];
    if (pinned != null) {
      _pdfMemoPinnedFolders[nodeId] =
          pinned.map((f) => renames[f] ?? f).toSet();
      _savePdfMemoPinnedFolders();
    }
    _saveToStorageLocal();
    _triggerAutoSync();
    notifyListeners();
  }

  /// PDF メモフォルダの名前 (= 最後のセグメント) を変更する (= ユーザー要望:
  /// 右クリックでフォルダー名を変更)。 子孫フォルダの prefix も追従する。
  void renamePdfMemoFolder(String nodeId, String folder, String newSegment) {
    final seg = newSegment.trim();
    if (seg.isEmpty || seg.contains('/')) return;
    final node = nodes[nodeId];
    if (node == null) return;
    final lastSlash = folder.lastIndexOf('/');
    final parent = lastSlash < 0 ? '' : folder.substring(0, lastSlash);
    final newName = parent.isEmpty ? seg : '$parent/$seg';
    if (newName == folder) return;
    _pushUndo();
    final renames = <String, String>{folder: newName};
    if (node.pdfMemoFolders != null) {
      for (final f in node.pdfMemoFolders!) {
        if (f.startsWith('$folder/')) {
          renames[f] = newName + f.substring(folder.length);
        }
      }
      node.pdfMemoFolders =
          node.pdfMemoFolders!.map((f) => renames[f] ?? f).toList();
    }
    if (node.pdfMemos != null) {
      for (int i = 0; i < node.pdfMemos!.length; i++) {
        final m = node.pdfMemos![i];
        final mf = m.folder;
        if (mf != null && renames.containsKey(mf)) {
          node.pdfMemos![i] = m.copyWith(folder: renames[mf]!);
        }
      }
    }
    final tmap = _pdfMemoFolderTopIndex[nodeId];
    if (tmap != null) {
      final newMap = <String, int>{};
      tmap.forEach((k, v) {
        newMap[renames[k] ?? k] = v;
      });
      _pdfMemoFolderTopIndex[nodeId] = newMap;
      _savePdfMemoFolderTopIndex();
    }
    final pinned = _pdfMemoPinnedFolders[nodeId];
    if (pinned != null) {
      _pdfMemoPinnedFolders[nodeId] =
          pinned.map((f) => renames[f] ?? f).toSet();
      _savePdfMemoPinnedFolders();
    }
    _saveToStorageLocal();
    _triggerAutoSync();
    notifyListeners();
  }

  // ─── リンク・PDF をアプリ内で開くか ──
  /// true (デフォルト): URL や PDF をアプリ内ビューア (WebView) で開く。
