  ///  Android: 標準 WebView は PDF 非対応のため fallback で外部アプリ起動)。
  bool _openLinksInApp = true;
  bool get openLinksInApp => _openLinksInApp;
  Future<void> setOpenLinksInApp(bool v) async {
    _openLinksInApp = v;
