  /// スケジュールロックの開始 / 終了時刻 (0時からの分。 例: 22:00 = 1320)。
  int _focusLockScheduleStartMin = 22 * 60; // 22:00
  int _focusLockScheduleEndMin = 6 * 60; // 06:00
  int get focusLockScheduleStartMin => _focusLockScheduleStartMin;
  int get focusLockScheduleEndMin => _focusLockScheduleEndMin;
  Future<void> setFocusLockSchedule(int startMin, int endMin) async {
    _focusLockScheduleStartMin = startMin % 1440;
    _focusLockScheduleEndMin = endMin % 1440;
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setInt(
          'focusLockScheduleStartMin', _focusLockScheduleStartMin);
      await prefs.setInt('focusLockScheduleEndMin', _focusLockScheduleEndMin);
    } catch (_) {}
    notifyListeners();
  }

  // ─── 集中ロック スケジュール (複数 + 曜日指定) (ユーザー要望) ───
  /// 曜日まで指定したスケジュールを複数登録できる。 `focusLockScheduleEnabled`
  /// が ON のとき、 この一覧のいずれかの枠に入っていれば自動ロックする。
  List<FocusLockSchedule> _focusLockSchedules = [];
  List<FocusLockSchedule> get focusLockSchedules =>
      List.unmodifiable(_focusLockSchedules);

  Future<void> _persistFocusLockSchedules() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final raw =
          jsonEncode(_focusLockSchedules.map((s) => s.toJson()).toList());
      await prefs.setString('focusLockSchedules', raw);
    } catch (_) {}
  }

  Future<void> addFocusLockSchedule(FocusLockSchedule s) async {
    _focusLockSchedules.add(s);
    await _persistFocusLockSchedules();
    notifyListeners();
  }

  Future<void> updateFocusLockSchedule(FocusLockSchedule s) async {
    final i = _focusLockSchedules.indexWhere((e) => e.id == s.id);
    if (i < 0) return;
    _focusLockSchedules[i] = s;
    await _persistFocusLockSchedules();
    notifyListeners();
  }

  Future<void> removeFocusLockSchedule(String id) async {
    _focusLockSchedules.removeWhere((e) => e.id == id);
    await _persistFocusLockSchedules();
    notifyListeners();
  }

  Future<void> toggleFocusLockSchedule(String id, bool enabled) async {
    final i = _focusLockSchedules.indexWhere((e) => e.id == id);
    if (i < 0) return;
    _focusLockSchedules[i].enabled = enabled;
    await _persistFocusLockSchedules();
    notifyListeners();
  }

  // ─── PDF / 添付メモ ──
  /// 指定ノードに新しい PDF / URL メモを追加して返す。
  /// 戻り値: 追加された PdfMemo (id を呼び出し元で参照したい場合に使用)。
  PdfMemo addPdfMemo(String nodeId,
      {String text = '',
      int? pageNumber,
      String? url,
      double? scrollY,
      double? xRatio,
      double? yRatio,
      int colorValue = 0xFFFFC107,
      String? folder,
      bool pinned = false}) {
    final node = nodes[nodeId];
    final memo = PdfMemo(
      id: 'pm_${DateTime.now().microsecondsSinceEpoch}_'
          '${(text.hashCode & 0xFFFF).toRadixString(16)}',
      text: text,
      pageNumber: pageNumber,
      url: url,
      scrollY: scrollY,
      xRatio: xRatio,
      yRatio: yRatio,
      colorValue: colorValue,
      folder: folder,
      pinned: pinned,
    );
    if (node != null) {
      _pushUndo();
      node.pdfMemos = [...?node.pdfMemos, memo];
      _saveToStorageLocal();
      // クラウド同期: メモ内容も含めて全文 PATCH したいので、 通常の
      // 変更フラグルートに乗せる
      _triggerAutoSync();
      notifyListeners();
    }
    return memo;
  }

  /// 既存メモを更新。 fields は null でない値だけを反映する。
  /// 位置や URL を「クリアしたい」 ケースでは
  /// `clearXRatio: true` のような明示フラグを使う (null と未指定の区別)。
  void updatePdfMemo(String nodeId, String memoId,
      {String? text,
      int? pageNumber,
      String? url,
      double? scrollY,
      double? xRatio,
      double? yRatio,
      int? colorValue,
      bool clearXY = false,
      bool clearUrl = false,
      bool clearScrollY = false}) {
    final node = nodes[nodeId];
    if (node == null || node.pdfMemos == null) return;
    final idx = node.pdfMemos!.indexWhere((m) => m.id == memoId);
    if (idx < 0) return;
    final old = node.pdfMemos![idx];
    _pushUndo();
    node.pdfMemos![idx] = old.copyWith(
      text: text,
      pageNumber: pageNumber,
      url: clearUrl ? null : url,
      scrollY: clearScrollY ? null : scrollY,
      xRatio: clearXY ? null : xRatio,
      yRatio: clearXY ? null : yRatio,
      colorValue: colorValue,
      updatedAtMs: DateTime.now().toUtc().millisecondsSinceEpoch,
    );
    _saveToStorageLocal();
    _triggerAutoSync();
    notifyListeners();
  }

  /// 1 件削除
  void removePdfMemo(String nodeId, String memoId) {
    final node = nodes[nodeId];
    if (node == null || node.pdfMemos == null) return;
    if (!node.pdfMemos!.any((m) => m.id == memoId)) return;
    _pushUndo();
    // ── undo で復元できるように、リストを in-place で変更しない ──
    // copyWith() は pdfMemos を同じリスト参照で共有するため、removeWhere
    //   で in-place 削除すると undo スナップショット側のリストも一緒に
    //   壊れて復元できない。新しいリストを代入してスナップショットの
    //   旧リストを温存する (= ユーザー要望「Ctrl+Z で削除メモを復元」)。
    final remaining = node.pdfMemos!.where((m) => m.id != memoId).toList();
    node.pdfMemos = remaining.isEmpty ? null : remaining;
    _saveToStorageLocal();
    _triggerAutoSync();
    notifyListeners();
  }

  /// PdfMemo のフォルダ名を設定する。
  /// [folder] が null または '' なら未分類 (= フォルダから外す) 扱い。
  /// 同じノード内の複数メモを一括で移動するなら [setPdfMemosFolder] を使う。
  void setPdfMemoFolder(String nodeId, String memoId, String? folder) {
    final node = nodes[nodeId];
    if (node == null || node.pdfMemos == null) return;
    final idx = node.pdfMemos!.indexWhere((m) => m.id == memoId);
    if (idx == -1) return;
    final f = (folder == null || folder.trim().isEmpty) ? null : folder.trim();
    _pushUndo();
    node.pdfMemos![idx] = node.pdfMemos![idx].copyWith(folder: f);
    _saveToStorageLocal();
    _triggerAutoSync();
    notifyListeners();
  }

  /// 複数メモを一括でフォルダ移動 (= 選択 → フォルダ変更 UI 用)。
  void setPdfMemosFolder(String nodeId, Set<String> memoIds, String? folder) {
    if (memoIds.isEmpty) return;
    final node = nodes[nodeId];
    if (node == null || node.pdfMemos == null) return;
    final f = (folder == null || folder.trim().isEmpty) ? null : folder.trim();
    bool changed = false;
    _pushUndo();
    for (int i = 0; i < node.pdfMemos!.length; i++) {
      if (memoIds.contains(node.pdfMemos![i].id)) {
        node.pdfMemos![i] = node.pdfMemos![i].copyWith(folder: f);
        changed = true;
      }
    }
    if (!changed) return;
    _saveToStorageLocal();
    _triggerAutoSync();
    notifyListeners();
  }

  /// ドラッグ&ドロップでメモを移動 / 並び替えする (= ユーザー要望
  ///   「ドラッグで自由にメモの階層や位置を移動できるように」)。
  /// [memoId] を [folder] (null/'' = 未分類) に移し、[beforeId] の直前へ挿入。
  /// [beforeId] が null なら、その folder グループの末尾に置く。
  void movePdfMemo(String nodeId, String memoId,
      {String? folder, String? beforeId}) {
    final node = nodes[nodeId];
    if (node == null || node.pdfMemos == null) return;
    final list = node.pdfMemos!;
    final idx = list.indexWhere((m) => m.id == memoId);
    if (idx < 0) return;
    if (beforeId == memoId) return; // 自分の前 = 変化なし
    final f = (folder == null || folder.trim().isEmpty) ? null : folder.trim();
    _pushUndo();
    var memo = list.removeAt(idx);
    if (memo.folder != f) memo = memo.copyWith(folder: f);
    int insertAt;
    if (beforeId != null) {
      insertAt = list.indexWhere((m) => m.id == beforeId);
      if (insertAt < 0) insertAt = list.length;
    } else {
      // 同じ folder を持つ最後のメモの直後 (= フォルダ末尾)。無ければ全体末尾。
      insertAt = list.length;
      for (int i = list.length - 1; i >= 0; i--) {
        if ((list[i].folder ?? '') == (f ?? '')) {
          insertAt = i + 1;
          break;
        }
      }
    }
    insertAt = insertAt.clamp(0, list.length);
    list.insert(insertAt, memo);
    _saveToStorageLocal();
    _triggerAutoSync();
    notifyListeners();
  }

  /// メモを同じフォルダ内で 1 つ上へ移動 (= ユーザー要望「メモの上下を
  ///   入れ替えられるように」)。
  void movePdfMemoUp(String nodeId, String memoId) {
    final node = nodes[nodeId];
    if (node == null || node.pdfMemos == null) return;
    final list = node.pdfMemos!;
    final idx = list.indexWhere((m) => m.id == memoId);
    if (idx < 0) return;
    final f = list[idx].folder ?? '';
    int prev = -1;
    for (int i = idx - 1; i >= 0; i--) {
      if ((list[i].folder ?? '') == f) {
        prev = i;
        break;
      }
    }
    if (prev < 0) return; // 既に先頭
    _pushUndo();
    final m = list.removeAt(idx);
    list.insert(prev, m);
    _saveToStorageLocal();
    _triggerAutoSync();
    notifyListeners();
  }

  /// メモを未分類リストの中で任意の位置へ移動 (= ユーザー要望: メモを
  /// ドラッグで自由に上下を入れ替えられるように)。
  /// [targetUnfilteredIdx] は **未分類メモ列** での挿入位置 (0..unfiltered の長さ)。
  /// 移動対象は未分類でない場合は折りたたまれているのでドラッグ範囲外。
  void reorderPdfMemoToUnfilteredIndex(
      String nodeId, String memoId, int targetUnfilteredIdx) {
    final node = nodes[nodeId];
    if (node == null || node.pdfMemos == null) return;
    final list = node.pdfMemos!;
    final fullIdx = list.indexWhere((m) => m.id == memoId);
    if (fullIdx < 0) return;
    final memo = list[fullIdx];
    // 未分類メモ列を構築 (= folder == null/empty のもののみ)
    final unfilteredFullIndices = <int>[];
    for (int i = 0; i < list.length; i++) {
      final fol = list[i].folder;
      if (fol == null || fol.isEmpty) unfilteredFullIndices.add(i);
    }
    // 移動先の full index を計算
    int targetFullIdx;
    if (targetUnfilteredIdx >= unfilteredFullIndices.length) {
      // 末尾追加: 最後の未分類メモの直後
      if (unfilteredFullIndices.isEmpty) {
        targetFullIdx = 0;
      } else {
        targetFullIdx = unfilteredFullIndices.last + 1;
      }
    } else {
      targetFullIdx = unfilteredFullIndices[targetUnfilteredIdx];
    }
    if (fullIdx == targetFullIdx) return;
    _pushUndo();
    // 移動対象がフォルダ内だった場合は未分類化する。
    final updated = (memo.folder == null || memo.folder!.isEmpty)
        ? memo
        : memo.copyWith(folder: null);
    list.removeAt(fullIdx);
    // 削除後インデックスがずれる
    final adj = fullIdx < targetFullIdx ? targetFullIdx - 1 : targetFullIdx;
    list.insert(adj.clamp(0, list.length), updated);
    _saveToStorageLocal();
    _triggerAutoSync();
    notifyListeners();
  }

  /// メモを「一番下」 (= 最下段のフォルダーよりさらに下) へ移動する。
  /// (= ユーザー要望: メモとフォルダの表示順で、 メモを最下段のフォルダー
  ///   より下に持ってこれるように)。
  ///
  /// 表示は `for i in 0..L { フォルダ@i; メモ[i] }` の順で描画され、 末尾
  ///   (topIndex == 未分類件数 L) に貼り付いたフォルダの「下」 にはメモ用の
  ///   スロットが存在しない。 そのため、 メモを未分類末尾へ動かしたうえで、
  ///   末尾に居る root フォルダを「最後のメモの直前 (= L-1)」 まで引き下げて、
  ///   メモが最下段に来るようにする。
  void moveMemoToVeryBottom(String nodeId, String memoId) {
    // まず未分類リストの末尾へ (= reorder 内で undo / 保存 / 通知も実施)。
    reorderPdfMemoToUnfilteredIndex(nodeId, memoId, 0x7FFFFFFF);
    final node = nodes[nodeId];
    if (node == null) return;
    final unfilteredLen = (node.pdfMemos ?? const <PdfMemo>[])
        .where((m) => (m.folder ?? '').isEmpty)
        .length;
    if (unfilteredLen == 0) return;
    // 末尾 (topIndex >= L、 未設定も既定で末尾扱い) の root フォルダを、
    //   最後の未分類メモの直前 (= L-1) に引き下げる。
    final tmap =
        _pdfMemoFolderTopIndex.putIfAbsent(nodeId, () => <String, int>{});
    var changed = false;
    for (final f in getPdfMemoFolders(nodeId)) {
      if (f.contains('/')) continue; // root フォルダのみ対象
      final t = tmap[f] ?? unfilteredLen; // 未設定はデフォルト末尾
      if (t >= unfilteredLen) {
        tmap[f] = unfilteredLen - 1;
        changed = true;
      }
    }
    if (changed) {
      _savePdfMemoFolderTopIndex();
      notifyListeners();
    }
  }

  /// メモを「一番上」 (= 最上段のフォルダーよりさらに上) へ移動する。
  /// (= ユーザー要望: メモを直接一番上まで持っていけるように)。
  ///
  /// `moveMemoToVeryBottom` の対称。 先頭 (topIndex == 0) に貼り付いた
  ///   フォルダの「上」 にはメモ用のスロットが無いので、 メモを未分類先頭へ
  ///   動かしたうえで、 先頭に居る root フォルダを「最初のメモの直後 (= 1)」
  ///   まで押し下げて、 メモが最上段に来るようにする。
  void moveMemoToVeryTop(String nodeId, String memoId) {
    // まず未分類リストの先頭へ (= reorder 内で undo / 保存 / 通知も実施)。
    reorderPdfMemoToUnfilteredIndex(nodeId, memoId, 0);
    final node = nodes[nodeId];
    if (node == null) return;
    final unfilteredLen = (node.pdfMemos ?? const <PdfMemo>[])
        .where((m) => (m.folder ?? '').isEmpty)
        .length;
    if (unfilteredLen == 0) return;
    // 先頭 (topIndex <= 0) の root フォルダを、 最初のメモの直後 (= 1) に
    //   押し下げて、 メモが一番上に来るようにする。
    final tmap =
        _pdfMemoFolderTopIndex.putIfAbsent(nodeId, () => <String, int>{});
    var changed = false;
    for (final f in getPdfMemoFolders(nodeId)) {
      if (f.contains('/')) continue; // root フォルダのみ対象
      final t = tmap[f] ?? unfilteredLen; // 未設定はデフォルト末尾 (= 上には居ない)
      if (t <= 0) {
        tmap[f] = 1.clamp(0, unfilteredLen);
        changed = true;
      }
    }
    if (changed) {
      _savePdfMemoFolderTopIndex();
      notifyListeners();
    }
  }

  /// メモを同じフォルダ内で 1 つ下へ移動。
  void movePdfMemoDown(String nodeId, String memoId) {
    final node = nodes[nodeId];
    if (node == null || node.pdfMemos == null) return;
    final list = node.pdfMemos!;
    final idx = list.indexWhere((m) => m.id == memoId);
    if (idx < 0) return;
    final f = list[idx].folder ?? '';
    int next = -1;
    for (int i = idx + 1; i < list.length; i++) {
      if ((list[i].folder ?? '') == f) {
        next = i;
        break;
      }
    }
    if (next < 0) return; // 既に末尾
    _pushUndo();
    final m = list.removeAt(idx);
    // removeAt で next が 1 つ手前にずれるので、その位置へ insert すると
    // 元の next 要素の直後に入る。
    list.insert(next.clamp(0, list.length), m);
    _saveToStorageLocal();
    _triggerAutoSync();
    notifyListeners();
  }

  /// PdfMemo のピン止め状態を切り替え (= ピンアイコンタップ用)。
  void togglePdfMemoPinned(String nodeId, String memoId) {
    final node = nodes[nodeId];
    if (node == null || node.pdfMemos == null) return;
    final idx = node.pdfMemos!.indexWhere((m) => m.id == memoId);
    if (idx == -1) return;
    _pushUndo();
    final old = node.pdfMemos![idx];
    node.pdfMemos![idx] = old.copyWith(pinned: !old.pinned);
    _saveToStorageLocal();
    _triggerAutoSync();
    notifyListeners();
  }

  /// 指定ノード内の全フォルダ名 (重複除去 + 名前順) を取得する。
  /// メモ一覧 UI のフォルダ一覧 / 移動先選択ドロップダウンで使用。
  /// メモ由来のフォルダに加え、明示作成された「空フォルダ」 も含める。
  List<String> getPdfMemoFolders(String nodeId) {
    final node = nodes[nodeId];
    if (node == null) return const [];
    // ── ユーザーがドラッグで決めた並び順を尊重する (= ユーザー要望:
    //    フォルダー同士の順番替えがうまくいかないバグの修正) ──
    // 以前は set にまとめて ..sort() でアルファベット順に潰していたため、
    //   reorderPdfMemoFolders で node.pdfMemoFolders を並び替えても表示順に
    //   反映されなかった。 明示宣言された順序 (= 並び替え結果) を最優先で
    //   保持し、 メモから推測されただけの未宣言フォルダは末尾にアルファベット
    //   順で足す。
    final result = <String>[];
    final seen = <String>{};
    // 1. 明示フォルダ (= 宣言順 = reorder で並び替えた順) を尊重。
    for (final f in node.pdfMemoFolders ?? const <String>[]) {
      if (f.isNotEmpty && seen.add(f)) result.add(f);
    }
    // 2. メモにだけ存在する未宣言フォルダを末尾に追加 (決定的にソート)。
    final derived = <String>[];
    for (final m in node.pdfMemos ?? const <PdfMemo>[]) {
      final f = m.folder;
      if (f != null && f.isNotEmpty && seen.add(f)) derived.add(f);
    }
    derived.sort();
    result.addAll(derived);
    return result;
  }

  /// 空のフォルダを明示的に作成する (= ユーザー要望「空のフォルダーも
  ///   作成できるように」)。同名が既にあれば何もしない。
  void createPdfMemoFolder(String nodeId, String name) {
    final f = name.trim();
    if (f.isEmpty) return;
    final node = nodes[nodeId];
    if (node == null) return;
    final folders = [...?node.pdfMemoFolders];
    if (folders.contains(f)) return;
    folders.add(f);
    _pushUndo();
    node.pdfMemoFolders = folders;
    _saveToStorageLocal();
    _triggerAutoSync();
    notifyListeners();
  }

  /// フォルダを削除する。中のメモは未分類 (folder=null) に戻し、明示フォルダ
  /// リストからも除く。
  void deletePdfMemoFolder(String nodeId, String name) {
    final node = nodes[nodeId];
    if (node == null) return;
    _pushUndo();
    // 中のメモを未分類へ
    if (node.pdfMemos != null) {
      for (int i = 0; i < node.pdfMemos!.length; i++) {
        if (node.pdfMemos![i].folder == name) {
          node.pdfMemos![i] = node.pdfMemos![i].copyWith(folder: null);
        }
      }
    }
    // 明示フォルダリストからも除去
    if (node.pdfMemoFolders != null) {
      final remaining = node.pdfMemoFolders!.where((f) => f != name).toList();
      node.pdfMemoFolders = remaining.isEmpty ? null : remaining;
    }
    // top 位置記録もクリア
    clearPdfMemoFolderTopIndex(nodeId, name);
    _saveToStorageLocal();
    _triggerAutoSync();
    notifyListeners();
  }

  /// PDF メモフォルダの順序を変更する (= ユーザー要望: フォルダーがドラッグ
  /// で位置移動できるように)。 [from] を [to] の位置へ移動。
  void reorderPdfMemoFolders(String nodeId, String from, String to,
      {bool placeAfter = false}) {
    if (from == to) return;
    final node = nodes[nodeId];
    if (node == null) return;
    _pushUndo();
    // ── 未登録フォルダ (= メモから自動推測されただけで pdfMemoFolders に
    //    まだ載っていないもの) も並び替えできるよう、 from/to の両方を
    //    必要に応じて自動で登録してから順序操作する (= ユーザー要望:
    //    フォルダーの並びをドラッグで自由に変えられるように) ──
    // 既存実装は indexOf == -1 を理由に return しており、 自動推測フォルダ
    //   のドラッグ並び替えが効かなかった。
    final list = [...?node.pdfMemoFolders];
    // 中のメモから推測されるフォルダ名 (=「メモは存在するがフォルダは未登録」)
    //   を補完するため、 メモを走査して未登録名を末尾に追加する。
    final memoFolderNames = <String>{};
    if (node.pdfMemos != null) {
      for (final m in node.pdfMemos!) {
        final f = m.folder;
        if (f != null && f.isNotEmpty && !list.contains(f)) {
          memoFolderNames.add(f);
        }
      }
    }
    list.addAll(memoFolderNames);
    if (!list.contains(from)) list.add(from);
    if (!list.contains(to)) list.add(to);
    final fromIdx = list.indexOf(from);
    final toIdx = list.indexOf(to);
    if (fromIdx < 0 || toIdx < 0 || fromIdx == toIdx) return;
    final item = list.removeAt(fromIdx);
    // 削除後の to のインデックスは、 from < to のときに 1 つズレるので調整
    final adjustedTo = fromIdx < toIdx ? toIdx - 1 : toIdx;
    // placeAfter=true なら to の「直後」 に挿入 (= ユーザー要望: 下ラインで
    //   フォルダの下に並べたい)。
    final insertAt = placeAfter ? adjustedTo + 1 : adjustedTo;
    list.insert(insertAt.clamp(0, list.length), item);
    node.pdfMemoFolders = list;
    _saveToStorageLocal();
    _triggerAutoSync();
    notifyListeners();
  }

  /// PDF メモフォルダのピン留め状態を取得 (= ユーザー要望「フォルダーも
  /// ピン留めできるように」)。
  /// 注: PdfMemo / MindMapNode モデルを変更せずに済むよう、 ピン留め状態は
  ///   ノードモデルではなく provider のメモリ Map + SharedPreferences に
  ///   保持する (= pdfHighlights と同じサイドデータ方式)。
  bool isPdfMemoFolderPinned(String nodeId, String folder) {
    return _pdfMemoPinnedFolders[nodeId]?.contains(folder) ?? false;
  }

  /// ピン留めされた PDF メモフォルダ名の一覧を取得。
  List<String> getPdfMemoPinnedFolders(String nodeId) {
    return List<String>.from(_pdfMemoPinnedFolders[nodeId] ?? const <String>{});
  }

  /// PDF メモフォルダのピン留めをトグルする。 ピン留めされたフォルダは
  /// メモパネルの一覧上部に固定表示される。
  void togglePdfMemoFolderPinned(String nodeId, String folder) {
    final set = _pdfMemoPinnedFolders.putIfAbsent(nodeId, () => <String>{});
    if (set.contains(folder)) {
      set.remove(folder);
    } else {
      set.add(folder);
    }
    if (set.isEmpty) _pdfMemoPinnedFolders.remove(nodeId);
    _savePdfMemoPinnedFolders();
    notifyListeners();
  }

  /// PDF メモフォルダを「マップ上の親子ノード」 として外に出す
  /// (= ユーザー要望「マップに出す時はフォルダー名が親ノード、 メモ内容が
  ///   子ノードになるように」)。
  ///
  /// 1. フォルダ名をタイトルにした親ノードを、 PDF/URL ノードの右側に作る。
  /// 2. フォルダ内の各メモを子ノードにして親ノードの右側にぶら下げる。
  /// 3. PDF ノード → フォルダ親ノード、 フォルダ親ノード → 各メモ子ノードを
  ///    接続する。
  ///
  /// 戻り値: 作成した親ノード (失敗時 null)。
  MindMapNode? addPdfMemoFolderAsNodes({
    required String parentNodeId,
    required String folder,
    required List<PdfMemo> memos,
  }) {
    final parent = nodes[parentNodeId];
    if (parent == null) return null;
    const colGap = 100.0;
    const rowGap = 80.0;
    // ── フォルダ親ノードの位置: PDF ノードの右側カラムの下端の下 ──
    final folderX = parent.position.dx + parent.width + colGap;
    double maxBottom = parent.position.dy;
    for (final n in nodes.values) {
      if ((n.position.dx - folderX).abs() < 20) {
        final b = n.position.dy + n.height;
        if (b > maxBottom) maxBottom = b;
      }
    }
    final folderPos = Offset(folderX, maxBottom + rowGap);
    _pushUndo();
    // フォルダ親ノード (= フォルダ名)
    final folderNode = MindMapNode(
      id: 'n_${DateTime.now().microsecondsSinceEpoch}',
      title: folder.isEmpty ? 'フォルダ' : folder,
      position: folderPos,
      color: const Color(0xFF6C63FF), // フォルダの紫で統一
    );
    currentPage.nodes[folderNode.id] = folderNode;
    // PDF ノード → フォルダ親ノード
    currentPage.connections.add(
      NodeConnection(
        fromId: parentNodeId,
        toId: folderNode.id,
        fromAnchor: AnchorDirection.east,
        toAnchor: AnchorDirection.west,
        showArrow: true,
      ),
    );
    // ── 各メモを子ノードにして、 フォルダ親ノードの右側に縦積み ──
    // ユーザー要望: 「親要素が中央の高さで子要素が上下に均等に展開される
    //   ように」 → 子ノード群の縦方向中央が親フォルダノードの中央と
    //   揃うよう、 先頭の Y を計算する。
    final childX = folderNode.position.dx + folderNode.width + colGap;
    // 子ノードの想定高さを一度ダミー作成で実測 (default constructor 値)。
    // ダミーは nodes に追加しないので副作用なし。
    final sample = MindMapNode(
      id: 'tmp_sample',
      title: '',
      position: Offset.zero,
    );
    final childHeight = sample.height;
    final n = memos.length;
    final totalHeight = n == 0 ? 0.0 : n * childHeight + (n - 1) * rowGap;
    final folderMidY = folderNode.position.dy + folderNode.height / 2;
    double childY = folderMidY - totalHeight / 2;
    int i = 0;
    const String kMemoImgPrefix2 = '__MMIMG__::';
    for (final memo in memos) {
      // 画像マーカーを除去してタイトル化 + 文字長で幅可変 (160〜300)。
      final rawText = memo.text;
      final markerNl =
          rawText.startsWith(kMemoImgPrefix2) ? rawText.indexOf('\n') : -1;
      final visibleText = markerNl >= 0
          ? rawText.substring(markerNl + 1)
          : (rawText.startsWith(kMemoImgPrefix2) ? '' : rawText);
      final title = visibleText.isEmpty
          ? (memo.pageNumber != null ? '[p.${memo.pageNumber}]' : 'メモ')
          : (memo.pageNumber != null
              ? '[p.${memo.pageNumber}] $visibleText'
              : visibleText);
      int visualUnits = 0;
      for (final line in title.split('\n')) {
        int units = 0;
        for (final cu in line.codeUnits) {
          if ((cu >= 0x20 && cu < 0x7F) || (cu >= 0xFF61 && cu <= 0xFF9F)) {
            units += 1;
          } else {
            units += 2;
          }
        }
        if (units > visualUnits) visualUnits = units;
      }
      final estimatedW = (visualUnits * 7.5 + 32).clamp(160.0, 300.0);
      final childNode = MindMapNode(
        id: 'n_${DateTime.now().microsecondsSinceEpoch}_$i',
        title: title,
        position: Offset(childX, childY),
        color: Color(memo.colorValue),
        width: estimatedW,
      );
      currentPage.nodes[childNode.id] = childNode;
      currentPage.connections.add(
        NodeConnection(
          fromId: folderNode.id,
          toId: childNode.id,
          fromAnchor: AnchorDirection.east,
          toAnchor: AnchorDirection.west,
          showArrow: true,
        ),
      );
      childY += childNode.height + rowGap;
      i++;
    }
    _saveToStorageLocal();
    _triggerAutoSync();
    notifyListeners();
    return folderNode;
  }

  /// 複数 PdfMemo を一括削除 (ノード内の複数選択削除用)。
  /// undo は 1 回分のスナップショットだけ積むので、 ひとつの操作として
  /// 戻せる。 [memoIds] のうち、 指定ノードに存在しないものは無視。
  void removePdfMemos(String nodeId, Set<String> memoIds) {
    if (memoIds.isEmpty) return;
    final node = nodes[nodeId];
    if (node == null || node.pdfMemos == null) return;
    final before = node.pdfMemos!.length;
    final remaining =
        node.pdfMemos!.where((m) => !memoIds.contains(m.id)).toList();
    if (remaining.length == before) return; // 変化なし
    _pushUndo();
    node.pdfMemos = remaining.isEmpty ? null : remaining;
    _saveToStorageLocal();
    _triggerAutoSync();
    notifyListeners();
  }

  /// マップ上のノードを PDF/URL ノードへドラッグ&ドロップしたときに、
  /// ソースノードのテキストを PdfMemo としてターゲットに追加する。
  /// 戻り値: 追加された PdfMemo (失敗時 null)。
  /// 色はソースノードの色を引き継ぐ (= 視覚的に「どのアイデアから来たか」 が
  /// 一目で分かる)。
  PdfMemo? addPdfMemoFromDroppedNode({
    required String targetNodeId,
    required String sourceNodeId,
  }) {
    final target = nodes[targetNodeId];
    final source = nodes[sourceNodeId];
    if (target == null || source == null) return null;
    if (target.id == source.id) return null;
    final colorInt = _colorToInt(source.color);
    return addPdfMemo(
      targetNodeId,
      text: source.title,
      colorValue: colorInt,
    );
  }

  /// Color → int (ARGB 32bit) ヘルパ。 PdfMemo.colorValue 用。
  int _colorToInt(Color c) {
    return ((c.a * 255).round() << 24) |
        ((c.r * 255).round() << 16) |
        ((c.g * 255).round() << 8) |
        (c.b * 255).round();
  }

  /// PdfMemo を「マップ上の子ノード」 として外に出す共通処理。
  /// 親 PDF/URL ノードの右側に colGap=100 / rowGap=80 で並べる。
  MindMapNode? addPdfMemoAsNode({
    required String parentNodeId,
    required PdfMemo memo,
    Offset? fallbackPosition,
  }) {
    final parent = nodes[parentNodeId];
    if (parent == null) return null;
    // 配置: 親ノードの右側で、 既存の子ノード群の下端の下にスタック
    const colGap = 100.0;
    const rowGap = 80.0;
    final baseX = parent.position.dx + parent.width + colGap;
    double maxBottom = parent.position.dy;
    for (final n in nodes.values) {
      // 親ノードの右側エリア (= 同じカラム) にあるノードの下端を集計
      if ((n.position.dx - baseX).abs() < 20) {
        final b = n.position.dy + n.height;
        if (b > maxBottom) maxBottom = b;
      }
    }
    final pos = Offset(baseX, maxBottom + rowGap);
    _pushUndo();
    // タイトル文字列を組み立て、 画像マーカーは表示には不要なので除外。
    // ── タイトル文字列を構築 ──
    // 画像マーカー (`__MMIMG__::<path>\n<body>`) があれば body 部分だけ使う。
    const String kMemoImgPrefix = '__MMIMG__::';
    final rawText = memo.text;
    final markerNl =
        rawText.startsWith(kMemoImgPrefix) ? rawText.indexOf('\n') : -1;
    final visibleText = markerNl >= 0
        ? rawText.substring(markerNl + 1)
        : (rawText.startsWith(kMemoImgPrefix) ? '' : rawText);
    final title = visibleText.isEmpty
        ? (memo.pageNumber != null ? '[p.${memo.pageNumber}]' : 'メモ')
        : (memo.pageNumber != null
            ? '[p.${memo.pageNumber}] $visibleText'
            : visibleText);
    // ── 文字の長さに合わせて幅を 160〜300 の範囲で可変 (= ユーザー要望:
    //    メモを外に出すと横幅が常に 160 で出力されるけど、 文字の長さに
    //    合わせて 300 まで自在に大きさが変動するように) ──
    // 最長行の見た目幅 (= 全角は 2、 半角は 1) で見積もる。 全角文字は
    //   約 7.5px、 半角は約 3.75px と仮定し、 padding を加算してクランプ。
    int visualUnits = 0;
    for (final line in title.split('\n')) {
      int units = 0;
      for (final cu in line.codeUnits) {
        // 半角 (ASCII / 半角カナ) は 1、 それ以外 (全角) は 2 単位として扱う
        if ((cu >= 0x20 && cu < 0x7F) || (cu >= 0xFF61 && cu <= 0xFF9F)) {
          units += 1;
        } else {
          units += 2;
        }
      }
      if (units > visualUnits) visualUnits = units;
    }
    final estimatedW = (visualUnits * 7.5 + 32).clamp(160.0, 300.0);
    final node = MindMapNode(
      id: 'n_${DateTime.now().microsecondsSinceEpoch}',
      title: title,
      position: pos,
      color: Color(memo.colorValue),
      width: estimatedW,
    );
    currentPage.nodes[node.id] = node;
    // 親 → 子 の接続を追加
    currentPage.connections.add(
      NodeConnection(
        fromId: parentNodeId,
        toId: node.id,
        fromAnchor: AnchorDirection.east,
        toAnchor: AnchorDirection.west,
        showArrow: true,
      ),
    );
    // ── ギャラリー(本棚): PDF ビューワーから外に出したメモも、 親ノードの
    //    「隣のブロック」 に 1 つずつ埋め込む (= ユーザー要望)。 親セルの
    //    右隣を 1 ブロック確保し (既に要素があれば右へずらして挿入)、 そこへ
    //    配置する。 接続線はギャラリー描画側で非表示にしている。 ──
    if (currentPage.pageType == 'bookshelf') {
      final pc = shelfCellOf(parentNodeId);
      if (pc != null) {
        _reserveShelfCells(pc[1], pc[0] + 1, 1);
        _shelfCells[node.id] = [pc[0] + 1, pc[1]];
        _saveShelfCells();
      }
      _arrangeAsBookshelfBody(currentPage);
    }
    _saveToStorageLocal();
    _triggerAutoSync();
    notifyListeners();
    return node;
  }

  /// 現在のページの全 PDF メモを一覧で取得 (= マップ外パネル用)。
  /// 戻り値は [(nodeId, memo)] のリスト。 更新日時の降順。
  List<({String nodeId, PdfMemo memo})> get currentPagePdfMemos {
    final out = <({String nodeId, PdfMemo memo})>[];
    for (final entry in nodes.entries) {
      final list = entry.value.pdfMemos;
      if (list == null || list.isEmpty) continue;
      for (final m in list) {
        out.add((nodeId: entry.key, memo: m));
      }
    }
    out.sort((a, b) => b.memo.updatedAtMs.compareTo(a.memo.updatedAtMs));
    return out;
  }

  /// 全マップ (全ページ) の PDF / サイトメモを、 マップ情報付きで返す
  /// (= ユーザー要望: 他のマップで書いたメモも参照・編集、 場所毎にグループ化)。
  List<({String pageId, String pageName, String nodeId, PdfMemo memo})>
      get allPdfMemos {
    final out =
        <({String pageId, String pageName, String nodeId, PdfMemo memo})>[];
    for (final p in _pages) {
      for (final entry in p.nodes.entries) {
        final list = entry.value.pdfMemos;
        if (list == null || list.isEmpty) continue;
        for (final m in list) {
          out.add((
            pageId: p.id,
            pageName: p.name,
            nodeId: entry.key,
            memo: m,
          ));
        }
      }
    }
    out.sort((a, b) => b.memo.updatedAtMs.compareTo(a.memo.updatedAtMs));
    return out;
  }

  /// 指定ページ・ノードの PDF メモを更新する (= メモ一覧から他マップのメモも
  /// 編集できるように)。 他ページが対象のため current-page 専用の undo は積まない。
  void updatePdfMemoOnPage(String pageId, String nodeId, String memoId,
      {String? text, int? pageNumber, String? url, int? colorValue}) {
    // 現在ページが対象なら undo 付きの通常版に委譲。
    if (pageId == _pageId) {
      updatePdfMemo(nodeId, memoId,
          text: text, pageNumber: pageNumber, url: url, colorValue: colorValue);
      return;
    }
    MindMapPage? page;
    for (final p in _pages) {
      if (p.id == pageId) {
        page = p;
        break;
      }
    }
    final node = page?.nodes[nodeId];
    if (node == null || node.pdfMemos == null) return;
    final idx = node.pdfMemos!.indexWhere((m) => m.id == memoId);
    if (idx < 0) return;
    node.pdfMemos![idx] = node.pdfMemos![idx].copyWith(
      text: text,
      pageNumber: pageNumber,
      url: url,
      colorValue: colorValue,
      updatedAtMs: DateTime.now().toUtc().millisecondsSinceEpoch,
    );
    _saveToStorageLocal();
    _triggerAutoSync();
    notifyListeners();
  }

  /// 指定ページ・ノードの PDF メモを 1 件削除する (= メモ一覧から他マップの
  /// メモも削除)。
  void removePdfMemoOnPage(String pageId, String nodeId, String memoId) {
    if (pageId == _pageId) {
      removePdfMemo(nodeId, memoId);
      return;
    }
    MindMapPage? page;
    for (final p in _pages) {
      if (p.id == pageId) {
        page = p;
        break;
      }
    }
    final node = page?.nodes[nodeId];
    if (node == null || node.pdfMemos == null) return;
    if (!node.pdfMemos!.any((m) => m.id == memoId)) return;
    final remaining = node.pdfMemos!.where((m) => m.id != memoId).toList();
    node.pdfMemos = remaining.isEmpty ? null : remaining;
    _saveToStorageLocal();
    _triggerAutoSync();
    notifyListeners();
  }

  Future<void> _saveCustomHeaderButtons() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString(
        'customHeaderButtons', jsonEncode(_customHeaderButtons));
  }

  /// コマンドIDをヘッダーに追加
  /// 重複は拒否（同じ項目を複数追加しない）。
  /// ヘッダーと下部バーは独立して扱うため、下部バーに同じ項目があっても OK。
  /// (= ユーザー要望: ヘッダーとフッターで同じカスタム項目を設定できるように)
  /// モバイル側の「3 つまで」の制限は UI (設定シート) 側で enabled フラグ制御
  /// しているため、ここでは上限チェックはしない (将来デスクトップは
  /// 無制限のまま使えるように)。
  Future<void> addHeaderButton(String commandId) async {
    if (_customHeaderButtons.contains(commandId)) return;
    _customHeaderButtons.add(commandId);
    await _saveCustomHeaderButtons();
    notifyListeners();
  }

  /// コマンドIDをヘッダーから削除
  Future<void> removeHeaderButton(String commandId) async {
    _customHeaderButtons.remove(commandId);
    await _saveCustomHeaderButtons();
    notifyListeners();
  }

  /// ヘッダーボタンの並び替え
  Future<void> reorderHeaderButtons(int oldIndex, int newIndex) async {
    if (oldIndex < 0 || oldIndex >= _customHeaderButtons.length) return;
    final item = _customHeaderButtons.removeAt(oldIndex);
    final adjusted = newIndex > oldIndex ? newIndex - 1 : newIndex;
    _customHeaderButtons.insert(
        adjusted.clamp(0, _customHeaderButtons.length), item);
    await _saveCustomHeaderButtons();
    notifyListeners();
  }

