  /// 1 行目スロットの並び替え。 _splitMode に応じて自動で対応 List を操作。
  Future<void> reorderBottomTopButtons(int oldIndex, int newIndex) async {
    final list = _currentBottomTopList;
    if (oldIndex < 0 || oldIndex >= list.length) return;
    final item = list.removeAt(oldIndex);
    final adjusted = newIndex > oldIndex ? newIndex - 1 : newIndex;
    list.insert(adjusted.clamp(0, list.length), item);
    await _saveCustomBottomTopButtons();
    notifyListeners();
  }

  /// 1 行目の特定スロットを別のコマンドに差し替える。
  /// _splitMode に応じて自動で対応 List を操作。
  Future<void> replaceBottomTopButton(
      int slotIndex, String newCommandId) async {
    if (slotIndex < 0 || slotIndex >= mobileBottomTopCustomSlots) return;
    final list = _currentBottomTopList;
    while (list.length <= slotIndex) {
      list.add('');
    }
    final existing = list.indexOf(newCommandId);
    if (existing >= 0 && existing != slotIndex) {
      final old = list[slotIndex];
      list[slotIndex] = newCommandId;
      list[existing] = old;
    } else {
      list[slotIndex] = newCommandId;
    }
    await _saveCustomBottomTopButtons();
    notifyListeners();
  }

  /// 2 行目 (下段) の指定スロットを別コマンドに置き換える。
  /// 上段の replaceBottomTopButton と同じ挙動 (既存位置にあれば入れ替え)。
