  /// 1 行目をデフォルト (link/file/rangeSelect/addNode/undo/redo) にリセット
  /// 現在のモード (= _splitMode) のリストのみリセット。
  Future<void> resetBottomTopButtons() async {
    _currentBottomTopList
      ..clear()
      ..addAll(defaultBottomTopButtons);
    await _saveCustomBottomTopButtons();
    notifyListeners();
  }

  /// 2 段目をデフォルト
  /// (lockScale[左端] + openYoutube/cutMode/calendar/sync/addPage) にリセット。
  /// lockScale はスロット 0 (左端) に戻す。
  Future<void> resetBottomBottomButtons() async {
    _customBottomButtons
      ..clear()
      ..addAll(defaultBottomBottomButtons);
    _lockScaleBottomSlot = 0;
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString(
        'customBottomButtons', jsonEncode(_customBottomButtons));
    await prefs.setInt('lockScaleBottomSlot', 0);
    notifyListeners();
  }

  /// 1 段目 + 2 段目の全ボタン色を、隣接被り無しのデフォルト色に戻す。
  /// `_defaultButtonColors` で定義された 12 ID 分が対象。
  /// ユーザーが個別に変えた色も含めて全部上書きされる点に注意。
  Future<void> resetBottomBarColors() async {
    _defaultButtonColors.forEach((id, color) {
      _headerIconColors[id] = color;
    });
    await _saveHeaderIconColors();
    notifyListeners();
  }

  /// OFF状態のデフォルト色（全アイコン共通）
  /// トグル系アイコン（例: snapToggle）がOFFの時に、ユーザー上書きが無ければ
  /// この色（灰色）が使われる
  static const int headerIconDefaultOffArgb = 0xFF9E9E9E;

  /// ユーザーが右クリックで上書きしたヘッダーアイコンのON状態色
  /// キー: commandId / 値: Color の ARGB32 int
  /// 未設定ならコマンド定義のデフォルト色を使う
  final Map<String, int> _headerIconColors = {};

  /// ユーザーが右クリックで上書きしたヘッダーアイコンのOFF状態色
  /// 未設定なら [headerIconDefaultOffArgb]（灰色）が使われる
  final Map<String, int> _headerIconColorsOff = {};

  /// [commandId] のON状態ユーザー上書き色を返す（未設定なら null）
  int? getHeaderIconColorValue(String commandId) =>
      _headerIconColors[commandId];

  /// [commandId] のOFF状態ユーザー上書き色を返す（未設定なら null）
  int? getHeaderIconColorOffValue(String commandId) =>
      _headerIconColorsOff[commandId];

  /// [commandId] のON状態色を上書き保存
  Future<void> setHeaderIconColor(String commandId, int argb) async {
    _headerIconColors[commandId] = argb;
    await _saveHeaderIconColors();
    notifyListeners();
  }

  /// [commandId] のOFF状態色を上書き保存
  Future<void> setHeaderIconColorOff(String commandId, int argb) async {
    _headerIconColorsOff[commandId] = argb;
    await _saveHeaderIconColorsOff();
    notifyListeners();
  }

  /// [commandId] のON状態色上書きを解除（デフォルト色に戻す）
  Future<void> resetHeaderIconColor(String commandId) async {
    if (_headerIconColors.remove(commandId) != null) {
      await _saveHeaderIconColors();
      notifyListeners();
    }
  }

  /// [commandId] のOFF状態色上書きを解除（灰色に戻す）
  Future<void> resetHeaderIconColorOff(String commandId) async {
    if (_headerIconColorsOff.remove(commandId) != null) {
      await _saveHeaderIconColorsOff();
      notifyListeners();
    }
  }

  Future<void> _saveHeaderIconColors() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString('headerIconColors', jsonEncode(_headerIconColors));
  }

  Future<void> _saveHeaderIconColorsOff() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString(
        'headerIconColorsOff', jsonEncode(_headerIconColorsOff));
  }

  /// ── Gemini モデルの動的取得 ──
  /// Google API の v1beta/models で生きているモデルを列挙する。
  /// 通信失敗時は組み込みのフォールバック (`_fallbackFlashModels` /
  /// `_fallbackProModels`) を使う。一度取得に成功した結果は
  /// SharedPreferences にキャッシュし、次回起動時は即時にキャッシュを
  /// 表示しつつ裏でリフレッシュ (旧 UI を見せない)。
  ///
  /// Flash 系: モデル ID に "flash" を含むもの
  /// Pro 系  : モデル ID に "pro" を含むもの
  /// generateContent 対応のものだけを残す (Embedding / TTS は除外)。
  static const List<String> _fallbackFlashModels = [
    'gemini-2.5-flash',
    'gemini-2.0-flash',
  ];
  static const List<String> _fallbackProModels = [
    'gemini-2.5-pro',
    'gemini-1.5-pro',
  ];

  /// 動的に取得した Gemini モデル一覧 (空ならフォールバックを使う)
  List<String> _dynamicFlashModels = [];
  List<String> _dynamicProModels = [];

  /// 最後にモデル一覧を取得した時刻 (1 日 1 回程度に間隔を絞る)
  DateTime? _lastGeminiModelsFetch;

  /// Flashモデル一覧 (動的取得 → フォールバックの順)
  List<String> get _flashModels => _dynamicFlashModels.isNotEmpty
      ? _dynamicFlashModels
      : _fallbackFlashModels;

  /// Proモデル一覧 (動的取得 → フォールバックの順)
  List<String> get _proModels =>
      _dynamicProModels.isNotEmpty ? _dynamicProModels : _fallbackProModels;

  /// 現在選択中のtierに対応するモデル一覧
  List<String> get _geminiModels =>
      aiModelTier == 'pro' ? _proModels : _flashModels;

  /// 公開ゲッター (UI 側でモデル選択 UI を作るため)。
  /// Flash / Pro の最新リストをそれぞれ返す。
  List<String> get availableFlashModels => List.unmodifiable(_flashModels);
  List<String> get availableProModels => List.unmodifiable(_proModels);

  // ── OpenAI/Claude モデル選択 ─────────────────────────────────────────
  /// OpenAI の組み込みフォールバックモデル
  /// 動的取得が成功すればこれは使われない。
  static const List<Map<String, String>> _fallbackOpenaiModels = [
    {'id': 'gpt-4o-mini', 'label': 'GPT-4o mini (fast / cheap)'},
    {'id': 'gpt-4o', 'label': 'GPT-4o'},
    {'id': 'gpt-4.1-mini', 'label': 'GPT-4.1 mini'},
    {'id': 'gpt-4.1', 'label': 'GPT-4.1'},
    {'id': 'o4-mini', 'label': 'o4-mini (reasoning)'},
  ];

  /// Claude の組み込みフォールバックモデル
  /// (Anthropic は公式の models 一覧 API があるので動的取得が成功すれば
  ///  これは使われない)
  static const List<Map<String, String>> _fallbackClaudeModels = [
    {'id': 'claude-haiku-4-5', 'label': 'Claude Haiku 4.5 (fast / cheap)'},
    {'id': 'claude-sonnet-4-5', 'label': 'Claude Sonnet 4.5'},
    {'id': 'claude-opus-4-7', 'label': 'Claude Opus 4.7 (most capable)'},
  ];

  /// 動的に取得した OpenAI / Claude モデル一覧
  List<Map<String, String>> _dynamicOpenaiModels = [];
  List<Map<String, String>> _dynamicClaudeModels = [];
  DateTime? _lastOpenaiModelsFetch;
  DateTime? _lastClaudeModelsFetch;

  /// UI 用ゲッター: 動的取得 → フォールバック
  List<Map<String, String>> get openaiAvailableModels =>
