  // ─── AI モデル一覧の動的取得 ────────────────────────────────────────────
  //
  // 各 AI プロバイダーは新モデルを頻繁にリリースするため、コードを書き直さ
  // なくても自動でリストが更新されるよう、各社の API から最新モデル一覧を
  // 取得する。失敗した場合 (ネットワーク・認証問題等) は組み込みフォール
  // バックを使うので致命的にはならない。
  //
  // 実行頻度: 1 日 1 回程度を目安に内部で間隔を絞る (毎起動で API を叩くと
  // 無駄な通信になるため)。SharedPreferences にキャッシュしておき、次回
  // 起動時はキャッシュをそのまま表示しつつ裏で更新する形にする。

  /// アプリ起動直後に呼ぶ初期化。SharedPreferences からキャッシュを復元し、
  /// 24 時間以上前なら裏で API を叩いて更新する。
  Future<void> initializeAvailableModels() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      // ── キャッシュ復元 ──
      final flashJson = prefs.getString('cached_flash_models');
      if (flashJson != null && flashJson.isNotEmpty) {
        try {
          _dynamicFlashModels = (jsonDecode(flashJson) as List).cast<String>();
        } catch (_) {}
      }
      final proJson = prefs.getString('cached_pro_models');
      if (proJson != null && proJson.isNotEmpty) {
        try {
          _dynamicProModels = (jsonDecode(proJson) as List).cast<String>();
        } catch (_) {}
      }
      final openaiJson = prefs.getString('cached_openai_models');
      if (openaiJson != null && openaiJson.isNotEmpty) {
        try {
          _dynamicOpenaiModels = (jsonDecode(openaiJson) as List)
              .map((e) => Map<String, String>.from(e as Map))
              .toList();
        } catch (_) {}
      }
      final claudeJson = prefs.getString('cached_claude_models');
      if (claudeJson != null && claudeJson.isNotEmpty) {
        try {
          _dynamicClaudeModels = (jsonDecode(claudeJson) as List)
              .map((e) => Map<String, String>.from(e as Map))
              .toList();
        } catch (_) {}
      }
      // ── 取得時刻も復元 ──
      final geminiTs = prefs.getInt('models_fetch_gemini_ts');
      if (geminiTs != null) {
        _lastGeminiModelsFetch = DateTime.fromMillisecondsSinceEpoch(geminiTs);
      }
      final openaiTs = prefs.getInt('models_fetch_openai_ts');
      if (openaiTs != null) {
        _lastOpenaiModelsFetch = DateTime.fromMillisecondsSinceEpoch(openaiTs);
      }
      final claudeTs = prefs.getInt('models_fetch_claude_ts');
      if (claudeTs != null) {
        _lastClaudeModelsFetch = DateTime.fromMillisecondsSinceEpoch(claudeTs);
      }
      notifyListeners();
      // ── 24 時間以上経っているプロバイダーは裏で更新 ──
      // (await はしない: アプリ起動を阻害したくないので fire-and-forget)
      // 失敗しても問題ないので unawaited 扱い。
      _maybeRefreshGeminiModels();
      _maybeRefreshOpenaiModels();
      _maybeRefreshClaudeModels();
    } catch (e) {
      debugPrint('initializeAvailableModels: $e');
    }
  }

  /// 24h 以上経過していれば Gemini モデル一覧を再取得
  Future<void> _maybeRefreshGeminiModels() async {
    if (_lastGeminiModelsFetch != null &&
        DateTime.now().difference(_lastGeminiModelsFetch!).inHours < 24) {
      return;
    }
    await refreshGeminiModels();
  }

  Future<void> _maybeRefreshOpenaiModels() async {
    if (_lastOpenaiModelsFetch != null &&
        DateTime.now().difference(_lastOpenaiModelsFetch!).inHours < 24) {
      return;
    }
    await refreshOpenaiModels();
  }

  Future<void> _maybeRefreshClaudeModels() async {
    if (_lastClaudeModelsFetch != null &&
        DateTime.now().difference(_lastClaudeModelsFetch!).inHours < 24) {
      return;
    }
    await refreshClaudeModels();
  }

  /// Google Generative Language API の v1beta/models で最新モデルを取得。
  /// API キーが無いと公開モデル一覧が取れないので、キーが設定されている時
  /// だけ実行する。失敗しても黙ってフォールバックを使い続ける。
  Future<void> refreshGeminiModels() async {
    final key = _effectiveGeminiKey();
    if (key == null || key.isEmpty) return;
    try {
      final url =
          'https://generativelanguage.googleapis.com/v1beta/models?key=$key';
      final res =
          await http.get(Uri.parse(url)).timeout(const Duration(seconds: 8));
      if (res.statusCode != 200) return;
      final data = jsonDecode(res.body) as Map<String, dynamic>;
      final list = data['models'] as List? ?? const [];

      final flash = <String>[];
      final pro = <String>[];
      for (final m in list) {
        final mm = m as Map<String, dynamic>;
        final name = (mm['name'] as String?) ?? '';
        // name は "models/gemini-2.5-flash" 形式で来る → 末尾だけ取り出す
        final modelId = name.startsWith('models/') ? name.substring(7) : name;
        final methods =
            (mm['supportedGenerationMethods'] as List?)?.cast<String>() ??
                const [];
        // generateContent をサポートする = テキスト生成可能なモデル
        if (!methods.contains('generateContent')) continue;
        // gemini モデルだけに絞る (Embedding / TTS などを除外)
        if (!modelId.startsWith('gemini')) continue;
        // プレビュー版 / 学習用変種は除く
        if (modelId.contains('embedding') || modelId.contains('aqa')) continue;
        if (modelId.contains('flash')) {
          flash.add(modelId);
        } else if (modelId.contains('pro')) {
          pro.add(modelId);
        }
      }
      // 重複除去 + バージョン番号で降順ソート (新しいバージョンを先頭に)
      // 単純な文字列降順で大体うまく行く: gemini-2.5-flash > gemini-2.0-flash
      final flashSet = flash.toSet().toList()..sort((a, b) => b.compareTo(a));
      final proSet = pro.toSet().toList()..sort((a, b) => b.compareTo(a));

      _dynamicFlashModels = flashSet;
      _dynamicProModels = proSet;
      _lastGeminiModelsFetch = DateTime.now();
      // 永続化
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString('cached_flash_models', jsonEncode(flashSet));
      await prefs.setString('cached_pro_models', jsonEncode(proSet));
      await prefs.setInt('models_fetch_gemini_ts',
          _lastGeminiModelsFetch!.millisecondsSinceEpoch);
      notifyListeners();
    } catch (e) {
      debugPrint('refreshGeminiModels: $e');
    }
  }

  /// OpenAI の /v1/models から取得。
  /// 認証ヘッダに API キーが必要なので、キー未設定なら何もしない。
  Future<void> refreshOpenaiModels() async {
    final key = _openaiApiKey;
    if (key == null || key.isEmpty) return;
    try {
      final res = await http.get(
        Uri.parse('https://api.openai.com/v1/models'),
        headers: {'Authorization': 'Bearer $key'},
      ).timeout(const Duration(seconds: 8));
      if (res.statusCode != 200) return;
      final data = jsonDecode(res.body) as Map<String, dynamic>;
      final list = (data['data'] as List?) ?? const [];

      // テキスト生成系モデルだけに絞る (チャット完了対応)。
      // ID プレフィックスで雑にフィルタ: gpt-* / o1-* / o3-* / o4-* / chatgpt-*
      // 現実には Embeddings / Whisper 等も同じエンドポイントから返ってくる。
      bool isChatLike(String id) {
        return id.startsWith('gpt-') ||
            id.startsWith('o1') ||
            id.startsWith('o3') ||
            id.startsWith('o4') ||
            id.startsWith('chatgpt');
      }

      final models = <Map<String, String>>[];
      for (final m in list) {
        final mm = m as Map<String, dynamic>;
        final id = (mm['id'] as String?) ?? '';
        if (id.isEmpty || !isChatLike(id)) continue;
        // 日付サフィックス付きのスナップショット (例: gpt-4o-mini-2024-07-18)
        // は隠す: ベース ID だけ表示する方が分かりやすい。
        if (RegExp(r'-\d{4}-\d{2}-\d{2}').hasMatch(id)) continue;
        // ラベルは ID をそのまま使う (人間可読フォーマットを取得する API は無い)
        models.add({'id': id, 'label': id});
      }
      // ID で昇順ソート (gpt-3.5 → gpt-4 → gpt-4.1 → gpt-4o → o1 → o4)
      models.sort((a, b) => a['id']!.compareTo(b['id']!));

      _dynamicOpenaiModels = models;
      _lastOpenaiModelsFetch = DateTime.now();
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString('cached_openai_models', jsonEncode(models));
      await prefs.setInt('models_fetch_openai_ts',
          _lastOpenaiModelsFetch!.millisecondsSinceEpoch);
      notifyListeners();
    } catch (e) {
      debugPrint('refreshOpenaiModels: $e');
    }
  }

  /// Anthropic の /v1/models から取得。
  /// 認証ヘッダ x-api-key が必要なのでキー未設定なら何もしない。
  Future<void> refreshClaudeModels() async {
    final key = _anthropicApiKey;
    if (key == null || key.isEmpty) return;
    try {
      final res = await http.get(
        Uri.parse('https://api.anthropic.com/v1/models?limit=100'),
        headers: {
          'x-api-key': key,
          'anthropic-version': '2023-06-01',
        },
      ).timeout(const Duration(seconds: 8));
      if (res.statusCode != 200) return;
      final data = jsonDecode(res.body) as Map<String, dynamic>;
      final list = (data['data'] as List?) ?? const [];

      final models = <Map<String, String>>[];
      for (final m in list) {
        final mm = m as Map<String, dynamic>;
        final id = (mm['id'] as String?) ?? '';
        // display_name が API 側で用意されていればそれを使う
        // (例: "Claude Sonnet 4.5"). 無ければ ID をそのまま使う。
        final displayName =
            (mm['display_name'] as String?)?.trim().isNotEmpty == true
                ? mm['display_name'] as String
                : id;
        if (id.isEmpty) continue;
        models.add({'id': id, 'label': displayName});
      }
      // ID で降順ソート (新しい "claude-opus-4-7" が先頭に来るように)
      models.sort((a, b) => b['id']!.compareTo(a['id']!));

      _dynamicClaudeModels = models;
      _lastClaudeModelsFetch = DateTime.now();
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString('cached_claude_models', jsonEncode(models));
      await prefs.setInt('models_fetch_claude_ts',
          _lastClaudeModelsFetch!.millisecondsSinceEpoch);
      notifyListeners();
    } catch (e) {
      debugPrint('refreshClaudeModels: $e');
    }
  }

  /// Gemini API キーの実効値。
  /// BYOK (= ユーザー要望): 利用者が設定画面で入力した自分のキーのみを使う。
  /// 開発者のグローバルキーへのフォールバックは廃止 (キーを配布しない方針)。
  String? _effectiveGeminiKey() {
    if (_geminiApiKey != null && _geminiApiKey!.isNotEmpty) {
      return _geminiApiKey;
    }
    return null;
  }

  /// 全プロバイダーのモデル一覧を強制リフレッシュする。
  /// 設定画面の「モデル一覧を更新」ボタンから呼ぶ用。
  /// 24h 制限を無視して即時に API を叩く。
  Future<void> forceRefreshAllAvailableModels() async {
    // 並列実行: それぞれ独立した API 呼び出しなので待ち時間を短縮できる。
    await Future.wait([
      refreshGeminiModels(),
      refreshOpenaiModels(),
      refreshClaudeModels(),
    ]);
  }

  // ── 開発者モード ──────────────────────────────────────────────────────────
  bool _developerMode = false;
  bool get developerMode => _developerMode;

  /// グローバルAPIキー（開発者が全ユーザー向けに設定）
  String? _globalGeminiApiKey;
  String? get globalGeminiApiKey => _globalGeminiApiKey;

  /// 問い合わせ先メールアドレス（開発者が設定）
  String _inquiryEmail = '';
  String get inquiryEmail => _inquiryEmail;

  // ─── Pro プラン (有料機能) ────────────────────────────────────────────
  //
  // 無料プランでは 2 ページまで作成可能。3 ページ目以降は Pro プラン加入か
  // 有効なクーポンコード適用が必要。仕組み:
  //
  // - `_proSubscribed`        : 通常のサブスク加入済み (永続)
  // - `_appliedCouponCode`    : 現在適用中のクーポンコード
  // - `_couponDiscountPercent`: クーポンの割引率 (0-100)
  // - `_couponExpiry`         : クーポンの有効期限 (UTC)
  //
  // ページ作成時は `canCreateNewPage` をチェック。クーポンが期限切れに
  // なっていたら自動的に `_appliedCouponCode` をクリアする。

  /// 無料プランで作成可能な最大ページ数。これを超えるとペイウォール表示。
  static const int kFreePageLimit = 2;

  /// プラン月額価格 (USD)。 ペイウォール / プラン紹介画面で表示する用。
  /// 実課金接続時はストア (App Store / Google Play / RevenueCat) 側の
  /// 価格表示を優先するが、 オフライン時の参考表示やマーケティング文言用に
  /// アプリ側でも保持しておく。
  static const String kProMonthlyPriceUsd = r'$9.99';
  static const String kMaxMonthlyPriceUsd = r'$19.99';

  /// プランごとの自動削除猶予期間。
  ///   Free: アップロードから 3 日でファイル単位に削除
  ///   Pro/Max: 契約終了から 30 日で全データ削除
  static const Duration kFreeAutoDeleteGrace = Duration(days: 3);
  static const Duration kPaidAutoDeleteGrace = Duration(days: 30);

  /// 画面分割 (PDF/動画/Web/Office の分割表示) を無料プランで開ける回数の上限。
  /// 無料プランは 2 回まで分割を開けて、3 回目以降は Pro 以上のプランが必要。
  /// Pro/Max/クーポン/開発者モードは無制限。
  static const int kFreeSplitViewLimit = 2;

  bool _proSubscribed = false;
  bool get proSubscribed => _proSubscribed;

  /// 実課金で確定した具体プラン (pro / max)。free = 未加入。
  /// 上の SubscriptionPlan のコメントどおり、購入結果をこの enum に書き込む。
  /// `_proSubscribed` は「Pro 以上に加入しているか」の後方互換フラグとして併存。
  SubscriptionPlan _purchasedPlan = SubscriptionPlan.free;
  SubscriptionPlan get purchasedPlan => _purchasedPlan;

  /// RevenueCat 連携サービス。onPlanChanged で購入結果を provider に反映する。
  /// env.json から public キー等を注入 (シークレットは持たせない)。
  late final BillingService _billing = BillingService(
    apiKeyMobile: const String.fromEnvironment('REVENUECAT_API_KEY_ANDROID',
        defaultValue: ''),
    restApiKey: const String.fromEnvironment('REVENUECAT_API_KEY_REST',
        defaultValue: ''),
    webLinkPro: const String.fromEnvironment('REVENUECAT_WEB_PURCHASE_LINK_PRO',
        defaultValue: ''),
    webLinkMax: const String.fromEnvironment('REVENUECAT_WEB_PURCHASE_LINK_MAX',
        defaultValue: ''),
    onPlanChanged: applyBillingPlanByName,
  );
  BillingService get billing => _billing;

  /// Pro / Max の契約が解除された日時 (UTC)。
  /// 課金状態が `_proSubscribed = true → false` に切り替わった瞬間に
  /// `setProSubscription(false)` 経由でセットされる。 この日付から 30 日が
  /// 経過すると、 起動時の `pruneExpiredCloudData()` で
  /// 該当グループの Storage 全データが自動削除される (= 復活猶予期間)。
  DateTime? _subscriptionEndedAt;
  DateTime? get subscriptionEndedAt => _subscriptionEndedAt;

  /// 実課金 (RevenueCat / IAP) からのフックで Pro 状態を切り替えるエントリ。
  /// false に切り替える瞬間に「契約終了タイムスタンプ」を記録するので、
  /// 30 日後の自動削除タイマーが動き出す。 true に戻れば終了時刻はクリア。
  /// 後方互換: bool フックは pro として扱う。
  /// (旧コードの `setProSubscription(true/false)` 呼び出しをそのまま活かす)
  Future<void> setProSubscription(bool subscribed) async {
    await applyBillingPlan(
        subscribed ? SubscriptionPlan.pro : SubscriptionPlan.free);
  }

  /// billing_service からの文字列 ('free'/'pro'/'max') を受けるブリッジ。
  /// BillingService.onPlanChanged に渡している。
  void applyBillingPlanByName(String name) {
    final plan = SubscriptionPlan.values.firstWhere(
      (p) => p.name == name,
      orElse: () => SubscriptionPlan.free,
    );
    // ignore: discarded_futures
    applyBillingPlan(plan);
  }

  /// 実課金 (RevenueCat) からのフックで確定プランを適用する正式エントリ。
  /// free に落ちた瞬間に「契約終了タイムスタンプ」を記録するので、30 日後の
  /// 自動削除タイマーが動き出す。pro/max に戻れば終了時刻はクリア。
  Future<void> applyBillingPlan(SubscriptionPlan plan) async {
    final nextPro = plan != SubscriptionPlan.free;
    if (_purchasedPlan == plan && _proSubscribed == nextPro) return;
    _purchasedPlan = plan;
    _proSubscribed = nextPro;
    final prefs = await SharedPreferences.getInstance();
    await prefs.setBool('pro_subscribed', nextPro);
    await prefs.setString('purchased_plan', plan.name);
    if (!nextPro) {
      // 解除された → 30 日後の自動削除起算点を保存
      _subscriptionEndedAt = DateTime.now().toUtc();
      await prefs.setInt('subscription_ended_at_ms',
          _subscriptionEndedAt!.millisecondsSinceEpoch);
    } else {
      _subscriptionEndedAt = null;
      await prefs.remove('subscription_ended_at_ms');
    }
    notifyListeners();
    // Firestore 側の plan も更新 (他ユーザーからの見え方を即時反映)
    // ignore: discarded_futures
    _syncPlanToUserDoc();
  }

  /// 現在適用中のクーポンが解放するプラン種別。
  /// 既定は `pro` (互換性: 過去のクーポンは plan フィールドが無いので pro 扱い)。
  /// Max 用クーポンを引き換えると `max` になる。
  SubscriptionPlan _couponPlan = SubscriptionPlan.pro;
  SubscriptionPlan get couponPlan => _couponPlan;

  /// ─── 月次容量制限 (アップロード / ダウンロード) ────────────────────────
  /// プランごとの月間上限:
  ///   free : アップロード 5 MB,   ダウンロード 20 MB
  ///   pro  : アップロード 5 GB,   ダウンロード 20 GB
  ///   max  : アップロード 25 GB,  ダウンロード 100 GB
  ///
  /// バイト数の累積を SharedPreferences に保存し、 月 (yyyy-MM) が
  /// 変わったら自動リセット。 端末ローカル管理なので 100% 厳密ではないが、
  /// 通常利用での暴走防止には十分。
  int _monthlyUploadBytes = 0;
  int _monthlyDownloadBytes = 0;
  String _billingMonthYm = ''; // 'yyyy-MM' 形式
  /// 累積ストレージ使用量 (バイト)。 Firebase Storage に保持しているファイルの
  /// 合計サイズ。 アップロード成功で加算、 ファイル削除で減算する。
  /// 端末ローカル管理 (SharedPreferences) なので 100% 厳密ではないが、
  /// 通常運用では暴走防止に十分。
  int _totalStorageBytes = 0;
  int get monthlyUploadBytes {
    _resetMonthlyIfNeeded();
    return _monthlyUploadBytes;
  }

  int get monthlyDownloadBytes {
    _resetMonthlyIfNeeded();
    return _monthlyDownloadBytes;
  }

  /// 開発者モード時に各上限へ返す「実質無制限」 値 (約 1 PB)。
  static const int kUnlimitedBytes = 1 << 50;

  /// 各上限が「実質無制限 (= 開発者モード)」 かどうか。 UI 表示で使う。
  bool get isStorageUnlimited => _developerMode;

  /// プランごとのアップロード月上限 (バイト)。 0 は無制限の意味でも使えるが、
  /// 現状はすべて有限値。
  int get monthlyUploadLimit {
    if (_developerMode) return kUnlimitedBytes; // 開発者モードは実質無制限
    switch (currentPlan) {
      case SubscriptionPlan.free:
        return 5 * 1024 * 1024; // 5 MB
      case SubscriptionPlan.pro:
        return 5 * 1024 * 1024 * 1024; // 5 GB
      case SubscriptionPlan.max:
        return 25 * 1024 * 1024 * 1024; // 25 GB
    }
  }

  /// プランごとのダウンロード月上限 (バイト)。
  int get monthlyDownloadLimit {
    if (_developerMode) return kUnlimitedBytes; // 開発者モードは実質無制限
    switch (currentPlan) {
      case SubscriptionPlan.free:
        return 20 * 1024 * 1024; // 20 MB (無料プランのクラウドDL上限)
      case SubscriptionPlan.pro:
        return 20 * 1024 * 1024 * 1024; // 20 GB
      case SubscriptionPlan.max:
        return 100 * 1024 * 1024 * 1024; // 100 GB
    }
  }

  /// プランごとの累積ストレージ容量上限 (バイト)。
  /// Firebase Storage 上に同時に保持できるファイル合計サイズの上限。
  ///   free : 5 MB   (極小: 機能体験用、 1週間で自動削除)
  ///   pro  : 20 GB
  ///   max  : 100 GB
  int get totalStorageLimit {
    if (_developerMode) return kUnlimitedBytes; // 開発者モードは実質無制限
    switch (currentPlan) {
      case SubscriptionPlan.free:
        return 5 * 1024 * 1024; // 5 MB
      case SubscriptionPlan.pro:
        return 20 * 1024 * 1024 * 1024; // 20 GB
      case SubscriptionPlan.max:
        return 100 * 1024 * 1024 * 1024; // 100 GB
    }
  }

  int get totalStorageBytes => _totalStorageBytes;
  int get totalStorageRemaining {
    final r = totalStorageLimit - _totalStorageBytes;
    return r < 0 ? 0 : r;
  }

  /// `bytes` バイトをストレージに追加して問題ないかチェック。
  bool canUseStorageBytes(int bytes) =>
      _totalStorageBytes + bytes <= totalStorageLimit;

  /// 今月の残りアップロード可能バイト (>= 0)。
  int get monthlyUploadRemaining {
    final r = monthlyUploadLimit - monthlyUploadBytes;
    return r < 0 ? 0 : r;
  }

  /// 今月の残りダウンロード可能バイト。
  int get monthlyDownloadRemaining {
    final r = monthlyDownloadLimit - monthlyDownloadBytes;
    return r < 0 ? 0 : r;
  }

  /// `bytes` バイトのアップロードを開始して問題ないかチェック。
  /// 上限超過なら false。 上限到達ぎりぎり (例: 残り 1MB) のときも、
  /// 部分的に通すのではなく false にして UI 側で上限案内を出させる。
  bool canUseUploadBytes(int bytes) =>
      monthlyUploadBytes + bytes <= monthlyUploadLimit;

  /// `bytes` バイトのダウンロードを開始して問題ないかチェック。
  bool canUseDownloadBytes(int bytes) =>
      monthlyDownloadBytes + bytes <= monthlyDownloadLimit;

  /// 月をまたいだ場合に累積をリセットする。 SharedPreferences に保存する処理は
  /// 副作用無しで呼びたい場面 (ゲッター) でも呼ばれるので、 同期で書込む
  /// 代わりにフラグだけ更新し、次回 `_persistMonthlyUsage` 時に確定させる。
  void _resetMonthlyIfNeeded() {
    final now = DateTime.now();
    final ym = '${now.year.toString().padLeft(4, '0')}-'
        '${now.month.toString().padLeft(2, '0')}';
    if (_billingMonthYm != ym) {
      _billingMonthYm = ym;
      _monthlyUploadBytes = 0;
      _monthlyDownloadBytes = 0;
      // 永続化は async の都合上 fire-and-forget
      // ignore: discarded_futures
      _persistMonthlyUsage();
    }
  }

  Future<void> _persistMonthlyUsage() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString('billingMonthYm', _billingMonthYm);
    await prefs.setInt('monthlyUploadBytes', _monthlyUploadBytes);
    await prefs.setInt('monthlyDownloadBytes', _monthlyDownloadBytes);
    await prefs.setInt('totalStorageBytes', _totalStorageBytes);
  }

  /// アップロード成功時に使用量を加算 (永続化込み)。
  void recordUploadBytes(int bytes) {
    _resetMonthlyIfNeeded();
    if (bytes <= 0) return;
    _monthlyUploadBytes += bytes;
    // 累積ストレージにも加算 (アップロード = Storage に新規ファイル登録)
    _totalStorageBytes += bytes;
    // ignore: discarded_futures
    _persistMonthlyUsage();
    notifyListeners();
  }

  /// ダウンロード成功時に使用量を加算 (永続化込み)。
  void recordDownloadBytes(int bytes) {
    _resetMonthlyIfNeeded();
    if (bytes <= 0) return;
    _monthlyDownloadBytes += bytes;
    // ignore: discarded_futures
    _persistMonthlyUsage();
    notifyListeners();
  }

  /// Storage からファイルを削除した時に累積使用量を減算する。
  /// 自動削除 (期限切れ) や手動削除の両方から呼ばれる。
  void releaseStorageBytes(int bytes) {
    if (bytes <= 0) return;
    _totalStorageBytes -= bytes;
    if (_totalStorageBytes < 0) _totalStorageBytes = 0;
    // ignore: discarded_futures
    _persistMonthlyUsage();
    notifyListeners();
  }

  /// Ctrl+S (クラウドアップロード) で「URL のみ上げる」をユーザーが選んだ
  /// ときに 1 回だけ動画ファイルアップロードをスキップするためのフラグ。
  /// `_uploadPageAttachments` 内でローカル動画ジョブの追加可否を判定し、
  /// アップロード処理の最後でリセットされる (ワンショット動作)。
  /// デフォルトは false (= 従来通り動画ファイルもアップロード)。
  bool skipVideoUploadOnce = false;

  String? _appliedCouponCode;
  String? get appliedCouponCode => _appliedCouponCode;

  int _couponDiscountPercent = 0;
  int get couponDiscountPercent => _couponDiscountPercent;

  DateTime? _couponExpiry;
  DateTime? get couponExpiry => _couponExpiry;

  /// 有効なクーポンが適用されているかどうか (期限内 + 100%引き = Pro 同等)。
  /// 部分割引クーポンは将来の課金導入用に値だけ持っておくが、
  /// 現状のページ制限解放には「100% 割引」(= 完全無料化) のクーポンを使う。
  bool get hasActiveCoupon {
    if (_appliedCouponCode == null) return false;
    if (_couponExpiry != null && DateTime.now().isAfter(_couponExpiry!)) {
      return false;
    }
    // 割引率 100% (= 完全無料化) は Pro 同等扱いでページ作成解放。
    // それ未満は将来の課金時に金額差し引き用。
    return _couponDiscountPercent >= 100;
  }

  /// 開発者モード時に「演じる」プラン。Free/Pro/Max を切り替えて
  /// 各プランでの UI / 機能制限の挙動をテストできる。
  /// デフォルトは `pro` (= 開発者モードに入った瞬間に Pro として扱われる)。
  /// `_developerMode == false` のときは無視され、`_proSubscribed` /
  /// `hasActiveCoupon` で実際の状態を判定する。
  SubscriptionPlan _devImpersonatePlan = SubscriptionPlan.pro;
  SubscriptionPlan get devImpersonatePlan => _devImpersonatePlan;

  /// 開発者モードでの演じるプランを変更。SharedPreferences に永続化し、
  /// Firestore の `/users/{uid}.plan` も即座に新プラン名へ書き換える。
  /// 後者を更新しないと、他のユーザーから「DEV のまま」に見えてしまう
  /// (`currentPlanLabel()` の戻り値ベースで Firestore に同期される設計)。
  Future<void> setDevImpersonatePlan(SubscriptionPlan plan) async {
    _devImpersonatePlan = plan;
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString('dev_impersonate_plan', plan.name);
    notifyListeners();
    // ── Firestore 側にも反映 (他ユーザーからの見え方を即時に切り替える) ──
    // 開発者モード中に Pro/Max を演じる時、自分の users ドキュメントを
    // 同じプラン名に更新する。これでカレンダー共有やインボックスソート等、
    // 他人が plan フィールドを参照する箇所がきちんと連動する。
    // ignore: discarded_futures
    _syncPlanToUserDoc();
  }

  /// 現在のプラン種別 (UI 表示や機能切り分け用)。
  /// 開発者モード時は `_devImpersonatePlan` を返し、それ以外は実際の購入状態
  /// (proSubscribed → pro / クーポン → couponPlan / それ以外 → free) を返す。
  /// クーポンの種類 (Pro / Max) は `_couponPlan` で識別。
  SubscriptionPlan get currentPlan {
    if (_developerMode) return _devImpersonatePlan;
    // 実課金プラン (pro / max) を最優先で反映
    if (_purchasedPlan != SubscriptionPlan.free) return _purchasedPlan;
    if (hasActiveCoupon) return _couponPlan;
    return SubscriptionPlan.free;
  }

  /// Pro / クーポン / 開発者モード によってページ無制限になっているか。
  /// UI 側のペイウォール出し分けで使う。
  /// 開発者モードは演じプラン (`_devImpersonatePlan`) で切り替わるので、
  /// Free を演じている場合は無料プラン同等の制限が適用される。
  bool get hasUnlimitedPages => currentPlan != SubscriptionPlan.free;

  /// Pro 機能 (= 動画ダウンロード・大容量同期・無制限ページ等) が
  /// 解放されているか。中身は `hasUnlimitedPages` と同じだが、ページ枚数
  /// 以外の文脈で使う場合に意味が分かるよう別名で公開する。
  bool get isProUnlocked => currentPlan != SubscriptionPlan.free;

  /// 新ページを作成して良いか。
  /// 無料プラン + Pro 未加入 + クーポン無効 の場合、現在のページ数が
  /// `kFreePageLimit` 未満かどうかを返す。
  bool get canCreateNewPage {
    if (hasUnlimitedPages) return true;
    return _pages.length < kFreePageLimit;
  }

  /// ─── 画面分割の無料利用回数 ───────────────────────────────────────────
  /// 無料プランは画面分割を `kFreeSplitViewLimit` (= 2) 回まで無料で開ける。
  /// 3 回目以降は Pro 以上が必要。SharedPreferences に累積回数を保存する。
  int _splitViewUseCount = 0;
  int get splitViewUseCount => _splitViewUseCount;

  /// 残りの無料分割回数 (>= 0)。Pro 以上かどうかは `canUseSplitView` で判定。
  int get splitViewFreeRemaining {
    final r = kFreeSplitViewLimit - _splitViewUseCount;
    return r < 0 ? 0 : r;
  }

  /// 画面分割を新規に開いて良いか。Pro 以上は常に true、
  /// 無料プランは累積利用回数が上限未満なら true。
  bool get canUseSplitView =>
      isProUnlocked || _splitViewUseCount < kFreeSplitViewLimit;

  /// 画面分割を 1 回開いたことを記録 (無料枠を 1 消費)。Pro 以上では呼ばない。
  /// SharedPreferences に永続化する (fire-and-forget)。
  /// notifyListeners は呼ばない: setState/build 内から呼ばれる可能性があり、
  /// ビルド中の通知を避けるため。残数表示は次回ダイアログ表示時に最新化される。
  void recordSplitViewUse() {
    _splitViewUseCount++;
    // ignore: discarded_futures
    _persistSplitViewUse();
  }

  Future<void> _persistSplitViewUse() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setInt('splitViewUseCount', _splitViewUseCount);
  }

  /// Pro / クーポン状態をローカルから復元。
  /// クーポンは期限切れなら自動クリア。
  /// 加えて開発者モード用の演じプラン (Free/Pro/Max) も復元する。
  Future<void> _loadProState() async {
    final prefs = await SharedPreferences.getInstance();
    _proSubscribed = prefs.getBool('pro_subscribed') ?? false;
    // 実課金プラン (pro/max) を復元。旧バージョン互換: 無ければ bool から導出。
    final purchasedPlanStr = prefs.getString('purchased_plan');
    if (purchasedPlanStr != null) {
      _purchasedPlan = SubscriptionPlan.values.firstWhere(
        (p) => p.name == purchasedPlanStr,
        orElse: () => SubscriptionPlan.free,
      );
    } else if (_proSubscribed) {
      _purchasedPlan = SubscriptionPlan.pro;
    }
    _splitViewUseCount = prefs.getInt('splitViewUseCount') ?? 0;
    final endedMs = prefs.getInt('subscription_ended_at_ms');
    if (endedMs != null) {
      _subscriptionEndedAt = DateTime.fromMillisecondsSinceEpoch(endedMs);
    }
    _appliedCouponCode = prefs.getString('applied_coupon_code');
    _couponDiscountPercent = prefs.getInt('coupon_discount_percent') ?? 0;
    final expiryMs = prefs.getInt('coupon_expiry_ms');
    if (expiryMs != null) {
      _couponExpiry = DateTime.fromMillisecondsSinceEpoch(expiryMs);
    }
    // 適用中クーポンが解放するプラン (pro / max)
    final couponPlanStr = prefs.getString('coupon_plan');
    if (couponPlanStr != null) {
      _couponPlan = SubscriptionPlan.values.firstWhere(
        (p) => p.name == couponPlanStr,
        orElse: () => SubscriptionPlan.pro,
      );
    }
    // 期限切れクーポンの自動クリア
    if (_couponExpiry != null &&
        DateTime.now().isAfter(_couponExpiry!) &&
        _appliedCouponCode != null) {
      await _clearCoupon();
    }
    // 開発者モードの演じプラン復元
    final planStr = prefs.getString('dev_impersonate_plan');
    if (planStr != null) {
      _devImpersonatePlan = SubscriptionPlan.values.firstWhere(
        (p) => p.name == planStr,
        orElse: () => SubscriptionPlan.pro,
      );
    }
    // 月次容量カウンタ復元 (月またぎなら自動で 0 リセット)
    _billingMonthYm = prefs.getString('billingMonthYm') ?? '';
    _monthlyUploadBytes = prefs.getInt('monthlyUploadBytes') ?? 0;
    _monthlyDownloadBytes = prefs.getInt('monthlyDownloadBytes') ?? 0;
    // 累積ストレージ使用量 (月またぎでもリセットしない)
    _totalStorageBytes = prefs.getInt('totalStorageBytes') ?? 0;
    _resetMonthlyIfNeeded();
  }

  Future<void> _clearCoupon() async {
    _appliedCouponCode = null;
    _couponDiscountPercent = 0;
    _couponExpiry = null;
    _couponPlan = SubscriptionPlan.pro;
    final prefs = await SharedPreferences.getInstance();
    await prefs.remove('applied_coupon_code');
    await prefs.remove('coupon_discount_percent');
    await prefs.remove('coupon_expiry_ms');
    await prefs.remove('coupon_plan');
    notifyListeners();
  }

  /// クーポンコードを適用する。
  /// Firestore 上のクーポンドキュメントを取得し、有効なら適用、
  /// 無効なら理由を含むエラーメッセージを返す。
  ///
  /// 戻り値 null = 成功、それ以外 = エラーメッセージ (ローカライズ済み)
  String? _deviceIdCache;

  /// 端末固有ID（クーポンの端末別不正利用防止に使用）。
  /// Windows はマシン GUID（アンインストールしても維持される）。
  /// Android は取得可能なハードウェア情報の合成（ANDROID_ID は
  ///   device_info_plus v11 では取得不可のため、厳密な一意性は保証されない
  ///   ＝ベストエフォート）。iOS/macOS/Linux はベンダー/システム ID。
  Future<String> _deviceId() async {
    if (_deviceIdCache != null) return _deviceIdCache!;
    String id = '';
    try {
      if (!kIsWeb) {
        final info = DeviceInfoPlugin();
        if (Platform.isWindows) {
          id = (await info.windowsInfo).deviceId;
        } else if (Platform.isAndroid) {
          final a = await info.androidInfo;
          id =
              '${a.brand}_${a.device}_${a.model}_${a.board}_${a.hardware}_${a.id}';
        } else if (Platform.isIOS) {
          id = (await info.iosInfo).identifierForVendor ?? '';
        } else if (Platform.isMacOS) {
          id = (await info.macOsInfo).systemGUID ?? '';
        } else if (Platform.isLinux) {
          id = (await info.linuxInfo).machineId ?? '';
        }
      }
    } catch (_) {}
    // Firestore のドキュメント ID に使えるようにサニタイズ
    id = id.replaceAll(RegExp(r'[^A-Za-z0-9_-]'), '');
    if (id.isEmpty) id = 'unknown';
    if (id.length > 100) id = id.substring(0, 100);
    _deviceIdCache = id;
    return id;
  }

  Future<String?> applyCoupon(String code) async {
    final trimmed = code.trim().toUpperCase();
    if (trimmed.isEmpty) return t('coupon.errEmpty');
    // Firebase が無効でも開発者モードのテストクーポンは効くようにしておく
    // 必要があるので、まず Firestore を試して無理ならローカル検証。
    if (_firebaseEnabled && _idToken != null) {
      try {
        final url = '$_firestoreBaseUrl/coupons/$trimmed';
        final res = await http.get(
          Uri.parse(url),
          headers: {'Authorization': 'Bearer $_idToken'},
        );
        if (res.statusCode == 404) {
          return t('coupon.errNotFound');
        }
        if (res.statusCode != 200) {
          return t('coupon.errNetwork');
        }
        final data = jsonDecode(res.body) as Map<String, dynamic>;
        final fields = data['fields'] as Map<String, dynamic>?;
        if (fields == null) return t('coupon.errInvalid');

        final discount = (() {
          // discountPercent は Firestore で integerValue として保存している。
          // 過去のテストデータ等で stringValue に入っているケースに備えて
          // 両方をチェックする。
          final intStr = (fields['discountPercent']
              as Map<String, dynamic>?)?['integerValue'] as String?;
          if (intStr != null) {
            return int.tryParse(intStr) ?? 0;
          }
          final s = _firestoreStr(fields['discountPercent']) ?? '';
          return int.tryParse(s) ?? 0;
        })();
        final expiryStr = _firestoreStr(fields['expiresAt']);
        final maxUsesStr = ((fields['maxUses']
                as Map<String, dynamic>?)?['integerValue'] as String?) ??
            '0';
        final currentUsesStr = ((fields['currentUses']
                as Map<String, dynamic>?)?['integerValue'] as String?) ??
            '0';
        final maxUses = int.tryParse(maxUsesStr) ?? 0;
        final currentUses = int.tryParse(currentUsesStr) ?? 0;

        DateTime? expiry;
        if (expiryStr != null && expiryStr.isNotEmpty) {
          expiry = DateTime.tryParse(expiryStr);
        }
        if (expiry != null && DateTime.now().isAfter(expiry)) {
          return t('coupon.errExpired');
        }
        if (maxUses > 0 && currentUses >= maxUses) {
          return t('coupon.errMaxUsed');
        }

        // ── 端末別の重複利用チェック (= ユーザー要望: アンインストール後の
        //    再利用などの不正を防ぐ。端末固有 ID をキーに Firestore へ利用
        //    履歴を残し、同じ端末での再利用を不可にする) ──
        // coupons/{code}/redemptions/{deviceId} が既に存在すれば利用済み。
        final devId = await _deviceId();
        try {
          final redRes = await http.get(
            Uri.parse('$_firestoreBaseUrl/coupons/$trimmed/redemptions/$devId'),
            headers: {'Authorization': 'Bearer $_idToken'},
          );
          if (redRes.statusCode == 200) {
            return t('coupon.errDeviceUsed');
          }
        } catch (_) {/* ネットワーク不調時は従来どおり続行 */}

        // 適用 + 永続化
        _appliedCouponCode = trimmed;
        _couponDiscountPercent = discount;
        _couponExpiry = expiry;
        // クーポンが解放するプランを Firestore の plan フィールドから決める
        // (互換性: フィールドがなければ pro 扱い)
        final planStr = _firestoreStr(fields['plan']);
        _couponPlan =
            (planStr == 'max') ? SubscriptionPlan.max : SubscriptionPlan.pro;
        final prefs = await SharedPreferences.getInstance();
        await prefs.setString('applied_coupon_code', trimmed);
        await prefs.setInt('coupon_discount_percent', discount);
        await prefs.setString('coupon_plan', _couponPlan.name);
        if (expiry != null) {
          await prefs.setInt('coupon_expiry_ms', expiry.millisecondsSinceEpoch);
        } else {
          await prefs.remove('coupon_expiry_ms');
        }
        // 使用回数をインクリメント (失敗しても適用自体は成功扱い)
        try {
          await http.patch(
            Uri.parse(
                '$_firestoreBaseUrl/coupons/$trimmed?updateMask.fieldPaths=currentUses'),
            headers: {
              'Authorization': 'Bearer $_idToken',
              'Content-Type': 'application/json',
            },
            body: jsonEncode({
              'fields': {
                'currentUses': {'integerValue': (currentUses + 1).toString()}
              }
            }),
          );
        } catch (_) {}
        // 端末別の利用履歴を記録 (= 次回以降この端末では再利用不可にする)。
        try {
          await http.patch(
            Uri.parse('$_firestoreBaseUrl/coupons/$trimmed/redemptions/$devId'),
            headers: {
              'Authorization': 'Bearer $_idToken',
              'Content-Type': 'application/json',
            },
            body: jsonEncode({
              'fields': {
                'usedAt': {
                  'timestampValue': DateTime.now().toUtc().toIso8601String()
                },
                'uid': {'stringValue': _uid ?? ''},
              }
            }),
          );
        } catch (_) {}
        // /users/{uid} のプランフィールドを同期 (失敗してもユーザー体験は損なわない)
        await _syncPlanToUserDoc();
        notifyListeners();
        return null; // success
      } catch (e) {
        debugPrint('applyCoupon error: $e');
        return t('coupon.errNetwork');
      }
    }
    return t('coupon.errNotFound');
  }

  // ─── 開発者モード: クーポン管理 ──────────────────────────────────────
  // Firestore の /coupons/{code} ドキュメント構造:
  //   { code, discountPercent, expiresAt (ISO), maxUses, currentUses,
  //     createdAt, note }
  // クーポンコードは大文字英数 8 文字。重複しないようランダム生成。

  /// 8 文字のランダム英数字コード生成 (大文字 + 数字、紛らわしい O/0/I/1 除外)
  String _generateCouponCode() {
    const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
    final rand = math.Random.secure();
    return List.generate(8, (_) => chars[rand.nextInt(chars.length)]).join();
  }

  /// 開発者モード専用: 新規クーポンを生成して Firestore に保存
  /// 戻り値: 生成されたコード (成功時)
  /// 失敗時は Exception を throw してエラー詳細を呼び出し側に伝える。
  ///
  /// `plan`: クーポンが解放するプラン種別。
  ///   - SubscriptionPlan.pro  (既定): Pro プラン相当 (5GB up / 20GB dl)
  ///   - SubscriptionPlan.max          : Max プラン相当 (25GB up / 100GB dl)
  /// それ以外の値は Pro として扱う。
  ///
  /// 失敗パターン:
  /// - 開発者モード未認証 → "開発者モードが有効になっていません"
  /// - Firebase 未初期化 → "Firebase に接続できていません"
  /// - HTTP エラー → "Firestore: HTTP {code} {body}" (権限不足など)
  Future<String?> createCoupon({
    required int discountPercent,
    DateTime? expiresAt,
    int maxUses = 0, // 0 = 無制限
    String note = '',
    SubscriptionPlan plan = SubscriptionPlan.pro,
  }) async {
    if (!_developerMode) {
      throw Exception('開発者モードが有効になっていません');
    }
    // トークン期限切れの可能性があるので、明示的にリフレッシュ
    if (!_firebaseEnabled || _idToken == null) {
      try {
        await _initFirebase();
      } catch (e) {
        throw Exception('Firebase 初期化に失敗しました: $e');
      }
    }
    if (!_firebaseEnabled || _idToken == null) {
      throw Exception('Firebase に接続できていません (オフライン or 設定不足)');
    }
    try {
      await _ensureFreshToken();
    } catch (e) {
      debugPrint('createCoupon: token refresh failed: $e');
      // refresh 失敗してもダメ元で送ってみる
    }
    final code = _generateCouponCode();
    try {
      // plan 値の正規化: max のみ受け入れ、 それ以外は pro として保存
      final planStr = plan == SubscriptionPlan.max ? 'max' : 'pro';
      final fields = <String, dynamic>{
        'code': {'stringValue': code},
        'discountPercent': {'integerValue': discountPercent.toString()},
        'maxUses': {'integerValue': maxUses.toString()},
        'currentUses': {'integerValue': '0'},
        'createdAt': {
          'timestampValue': DateTime.now().toUtc().toIso8601String()
        },
        'note': {'stringValue': note},
        'plan': {'stringValue': planStr},
      };
      if (expiresAt != null) {
        fields['expiresAt'] = {
          'stringValue': expiresAt.toUtc().toIso8601String()
        };
      }
      final res = await http.patch(
        Uri.parse('$_firestoreBaseUrl/coupons/$code'),
        headers: {
          'Authorization': 'Bearer $_idToken',
          'Content-Type': 'application/json',
        },
        body: jsonEncode({'fields': fields}),
      );
      if (res.statusCode >= 200 && res.statusCode < 300) {
        return code;
      }
      // HTTP エラーは body 込みでログ + 例外
      // 典型例:
      //   403 PERMISSION_DENIED  → Firestore セキュリティルールが書込拒否
      //   401 UNAUTHENTICATED    → IDトークン期限切れ (再起動でリフレッシュ)
      //   400 INVALID_ARGUMENT   → fields の型不一致
      debugPrint('createCoupon failed: ${res.statusCode} ${res.body}');
      String hint = '';
      if (res.statusCode == 403) {
        hint = ' (Firestore セキュリティルールで /coupons への書込が許可されていません)';
      } else if (res.statusCode == 401) {
        hint = ' (認証トークン期限切れ。アプリを再起動してください)';
      }
      throw Exception('Firestore: HTTP ${res.statusCode}$hint');
    } catch (e) {
      debugPrint('createCoupon error: $e');
      // 既に Exception ならそのまま rethrow、それ以外も Exception 化
      if (e is Exception) rethrow;
      throw Exception('createCoupon: $e');
    }
  }

  /// 開発者モード専用: 既存クーポン一覧を取得
  Future<List<Map<String, dynamic>>> listCoupons() async {
    if (!_developerMode || !_firebaseEnabled || _idToken == null) return [];
    try {
      // トークン更新を保険で実行 (期限切れだと 401 で空配列が返るのを防ぐ)
      await _ensureFreshToken();
      final res = await http.get(
        Uri.parse('$_firestoreBaseUrl/coupons?pageSize=100'),
        headers: {'Authorization': 'Bearer $_idToken'},
      );
      if (res.statusCode != 200) {
        debugPrint('listCoupons failed: ${res.statusCode} ${res.body}');
        return [];
      }
      final data = jsonDecode(res.body) as Map<String, dynamic>;
      final docs = data['documents'] as List<dynamic>? ?? [];
      final result = <Map<String, dynamic>>[];
      for (final d in docs) {
        final m = d as Map<String, dynamic>;
        final fields = m['fields'] as Map<String, dynamic>? ?? {};
        result.add({
          'code': _firestoreStr(fields['code']) ?? '',
          'discountPercent': int.tryParse(((fields['discountPercent']
                      as Map<String, dynamic>?)?['integerValue'] as String?) ??
                  '0') ??
              0,
          'maxUses': int.tryParse(((fields['maxUses']
                      as Map<String, dynamic>?)?['integerValue'] as String?) ??
                  '0') ??
              0,
          'currentUses': int.tryParse(((fields['currentUses']
                      as Map<String, dynamic>?)?['integerValue'] as String?) ??
                  '0') ??
              0,
          'expiresAt': _firestoreStr(fields['expiresAt']) ?? '',
          'note': _firestoreStr(fields['note']) ?? '',
        });
      }
      // 新しい順にソート (expires が空 = 無期限を一番下に)
      result.sort((a, b) {
        final aExp = a['expiresAt'] as String;
        final bExp = b['expiresAt'] as String;
        if (aExp.isEmpty && bExp.isEmpty) return 0;
        if (aExp.isEmpty) return 1;
        if (bExp.isEmpty) return -1;
        return bExp.compareTo(aExp);
      });
      return result;
    } catch (e) {
      debugPrint('listCoupons: $e');
      return [];
    }
  }

  /// 開発者モード専用: クーポンを削除
  Future<bool> deleteCoupon(String code) async {
    if (!_developerMode || !_firebaseEnabled || _idToken == null) return false;
    try {
      final res = await http.delete(
        Uri.parse('$_firestoreBaseUrl/coupons/$code'),
        headers: {'Authorization': 'Bearer $_idToken'},
      );
      return res.statusCode >= 200 && res.statusCode < 300;
    } catch (e) {
      debugPrint('deleteCoupon: $e');
      return false;
    }
  }

  /// 開発者モード専用: 既存クーポンの note (= 発券時に付ける任意の名前/メモ)
  /// を後から編集する。Firestore 上の note フィールドだけを書き換える。
  ///
  /// updateMask クエリパラメータで `note` のみ指定することで、他のフィールド
  /// (discountPercent / expiresAt / currentUses 等) を巻き戻さずに済む。
  /// ない場合 PATCH は「指定したフィールドだけ」更新するが、 Firestore REST
  /// の挙動は updateMask があると「マスクに無いフィールドを温存」、 無いと
  /// 「fields 全体で置換」 とドキュメント上は微妙なので、 安全側で常に
  /// updateMask を付ける。
  ///
  /// 戻り値: 成功なら true、失敗なら false。
  Future<bool> updateCouponNote(String code, String newNote) async {
    if (!_developerMode || !_firebaseEnabled || _idToken == null) return false;
    try {
      await _ensureFreshToken();
      final body = {
        'fields': {
          'note': {'stringValue': newNote},
        }
      };
      final res = await http.patch(
        Uri.parse(
            '$_firestoreBaseUrl/coupons/$code?updateMask.fieldPaths=note'),
        headers: {
          'Authorization': 'Bearer $_idToken',
          'Content-Type': 'application/json',
        },
        body: jsonEncode(body),
      );
      if (res.statusCode >= 200 && res.statusCode < 300) {
        return true;
      }
      debugPrint('updateCouponNote failed: ${res.statusCode} ${res.body}');
      return false;
    } catch (e) {
      debugPrint('updateCouponNote: $e');
      return false;
    }
  }

  // ─── ライセンス引き継ぎ (リストアコード方式) ────────────────────────────
  //
  // 端末A: 「リストアコード発行」→ 8 桁コードと現在のライセンス内容を
  //        Firestore /licenses/{code} に書き込む。
  // 端末B: 「リストアコード入力」→ コードを入力するとローカルに反映。
  //        consumedAt を記録して二重適用を防ぐ。
  //
  // /licenses/{code} のフィールド:
  //   proSubscribed, appliedCouponCode?, couponDiscountPercent,
  //   couponExpiry?, sourceUid, createdAt, expiresAt (発行から 7 日),
  //   consumedAt?, consumedByUid?

  String _generateRestoreCode() {
    const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
    final rand = math.Random.secure();
    return List.generate(8, (_) => chars[rand.nextInt(chars.length)]).join();
  }

  /// 現在のライセンス状態を Firestore に書き出して 8 桁コードを返す。
  /// 失敗時は null。引き継げるライセンスがない場合も null。
  ///
  /// 開発者モード時は `_devImpersonatePlan` を実プランとみなして発行する
  /// (= UI のテストや動作確認のためにライセンス引継ぎを実演できる)。
  /// 演じプランが Free の場合のみ「引き継げるライセンスなし」となる。
  Future<String?> issueLicenseRestoreCode() async {
    if (!_firebaseEnabled || _idToken == null) return null;
    // 引継ぎ可否判定: Pro 以上 (Free でない) なら発行可能。
    // currentPlan getter は (1) 開発者モードで演じているプラン、
    // (2) 実 _proSubscribed、(3) hasActiveCoupon (Max クーポン含む) の
    // いずれかが Free 以外なら Pro/Max を返すので、これ 1 つで全プランを
    // カバーできる。
    // 旧実装は `_proSubscribed || hasActiveCoupon || (dev && != free)` の
    // OR 連結だったが、Max クーポン適用中 (hasActiveCoupon=true で
    // _couponPlan=max) のような複合状態でロジックが分かりにくく、
    // ユーザー報告の「Max なのに引継ぎ発行できない」原因の推定要因。
    // currentPlan ベースに揃えれば UI 表示と判定が一致する。
    if (currentPlan == SubscriptionPlan.free) return null;
    // Firestore に書き込む `proSubscribed` は実状態 OR 開発者モードで
    // pro/max を演じている = 引継ぎ先で Pro 扱いされる、という意味。
    final hasDev =
        _developerMode && _devImpersonatePlan != SubscriptionPlan.free;
    final hasReal = _proSubscribed || hasActiveCoupon;
    final effectiveProSubscribed = _proSubscribed || hasDev;
    try {
      await _ensureFreshToken();
      final code = _generateRestoreCode();
      final now = DateTime.now().toUtc();
      final expiresAt = now.add(const Duration(days: 7));
      // 引継ぎ先で Pro / Max を区別できるよう、現在のプラン名を一緒に書き出す。
      // currentPlan が pro / max のとき、その文字列をそのまま保存。
      // (free にはここまで来ない、上の判定で弾かれている)
      final planStr = currentPlan == SubscriptionPlan.max ? 'max' : 'pro';
      final fields = <String, dynamic>{
        'proSubscribed': {'booleanValue': effectiveProSubscribed},
        'plan': {'stringValue': planStr},
        'couponDiscountPercent': {
          'integerValue': _couponDiscountPercent.toString()
        },
        'sourceUid': {'stringValue': _uid ?? ''},
        'createdAt': {'timestampValue': now.toIso8601String()},
        'expiresAt': {'timestampValue': expiresAt.toIso8601String()},
      };
      // 開発者モード由来かどうかをトレースするためのフラグ (引継ぎ先での
      // 課金トラブル切り分け用、UI には出さない)
      if (hasDev && !hasReal) {
        fields['sourceWasDev'] = {'booleanValue': true};
      }
      if (_appliedCouponCode != null) {
        fields['appliedCouponCode'] = {'stringValue': _appliedCouponCode!};
      }
      if (_couponExpiry != null) {
        fields['couponExpiry'] = {
          'timestampValue': _couponExpiry!.toUtc().toIso8601String()
        };
      }
      final res = await http.patch(
        Uri.parse('$_firestoreBaseUrl/licenses/$code'),
        headers: {
          'Authorization': 'Bearer $_idToken',
          'Content-Type': 'application/json',
        },
        body: jsonEncode({'fields': fields}),
      );
      if (res.statusCode >= 200 && res.statusCode < 300) {
        return code;
      }
      debugPrint('issueLicenseRestoreCode failed: '
          '${res.statusCode} ${res.body}');
      return null;
    } catch (e) {
      debugPrint('issueLicenseRestoreCode error: $e');
      return null;
    }
  }

  /// リストアコードを使ってライセンスを引き継ぐ。
  /// 戻り値 null = 成功、それ以外 = エラーメッセージ (ローカライズ済み)
  /// 同じライセンスは最大 [kLicenseMaxDevices] 端末まで使い回せる。
  /// 同じ端末 (uid) で再 redeem しても重複カウントしない。
  static const int kLicenseMaxDevices = 4;

  Future<String?> redeemLicenseRestoreCode(String code) async {
    final trimmed = code.trim().toUpperCase();
    if (trimmed.isEmpty) return t('restore.errEmpty');
    if (!_firebaseEnabled || _idToken == null) {
      return t('restore.errNetwork');
    }
    try {
      await _ensureFreshToken();
      final url = '$_firestoreBaseUrl/licenses/$trimmed';
      final res = await http.get(
        Uri.parse(url),
        headers: {'Authorization': 'Bearer $_idToken'},
      );
      if (res.statusCode == 404) return t('restore.errNotFound');
      if (res.statusCode != 200) return t('restore.errNetwork');

      final data = jsonDecode(res.body) as Map<String, dynamic>;
      final fields = data['fields'] as Map<String, dynamic>?;
      if (fields == null) return t('restore.errInvalid');

      final expiresStr = _firestoreStr(fields['expiresAt']);
      if (expiresStr != null && expiresStr.isNotEmpty) {
        final exp = DateTime.tryParse(expiresStr);
        if (exp != null && DateTime.now().toUtc().isAfter(exp)) {
          return t('restore.errExpired');
        }
      }

      // ── 端末数チェック (最大 4 端末) ──
      // consumedByUids は arrayValue で保存。旧データ (single use の
      // consumedAt + consumedByUid) との後方互換のため両方を吸収する。
      final List<String> consumedUids = [];
      // 新形式: arrayValue
      final arrField = fields['consumedByUids'] as Map<String, dynamic>?;
      if (arrField != null) {
        final arrVal = arrField['arrayValue'] as Map<String, dynamic>?;
        final values = arrVal?['values'] as List<dynamic>? ?? [];
        for (final v in values) {
          final s = (v as Map<String, dynamic>)['stringValue'] as String?;
          if (s != null && s.isNotEmpty) consumedUids.add(s);
        }
      }
      // 旧形式: 単一 consumedByUid
      final legacyUid = _firestoreStr(fields['consumedByUid']);
      if (legacyUid != null &&
          legacyUid.isNotEmpty &&
          !consumedUids.contains(legacyUid)) {
        consumedUids.add(legacyUid);
      }

      final myUid = _uid ?? '';
      // 既に自分の端末で消費済みなら、上限に達していても再適用 OK
      // (ライセンス情報の再ダウンロード用途)
      final alreadyConsumed = consumedUids.contains(myUid);
      if (!alreadyConsumed && consumedUids.length >= kLicenseMaxDevices) {
        return t('restore.errMaxDevices');
      }

      final pro = ((fields['proSubscribed']
              as Map<String, dynamic>?)?['booleanValue'] as bool?) ??
          false;
      final discountStr = ((fields['couponDiscountPercent']
              as Map<String, dynamic>?)?['integerValue'] as String?) ??
          '0';
      final discount = int.tryParse(discountStr) ?? 0;
      final couponCode = _firestoreStr(fields['appliedCouponCode']);
      final couponExpiryStr = _firestoreStr(fields['couponExpiry']);
      DateTime? couponExpiry;
      if (couponExpiryStr != null && couponExpiryStr.isNotEmpty) {
        couponExpiry = DateTime.tryParse(couponExpiryStr);
      }
      // ── プラン情報 (pro / max) を引継ぎ ──
      // 旧 (plan フィールド無し) の引継ぎコードでは pro 扱いにフォールバック。
      // 新コードは issueLicenseRestoreCode 側で必ず "pro" or "max" が入る。
      final planStr = _firestoreStr(fields['plan']) ?? 'pro';
      final isMaxPlan = planStr == 'max';

      final prefs = await SharedPreferences.getInstance();
      _proSubscribed = pro;
      await prefs.setBool('pro_subscribed', pro);
      if (couponCode != null && couponCode.isNotEmpty) {
        _appliedCouponCode = couponCode;
        _couponDiscountPercent = discount;
        _couponExpiry = couponExpiry;
        // Max ライセンスを引き継ぐときは _couponPlan も Max にする。
        // currentPlan getter が Max を返すようになり、 引継ぎ先で
        // 月間 25GB 上限などの Max 特典が解放される。
        _couponPlan = isMaxPlan ? SubscriptionPlan.max : SubscriptionPlan.pro;
        await prefs.setString('applied_coupon_code', couponCode);
        await prefs.setInt('coupon_discount_percent', discount);
        await prefs.setString('coupon_plan', isMaxPlan ? 'max' : 'pro');
        if (couponExpiry != null) {
          await prefs.setInt(
              'coupon_expiry_ms', couponExpiry.millisecondsSinceEpoch);
        } else {
          await prefs.remove('coupon_expiry_ms');
        }
      } else if (isMaxPlan && pro) {
        // 引継ぎ元が「実 _proSubscribed=true かつ Max」の場合: クーポンコード
        // は無いが、 引継ぎ先でも Max を維持したい。 _couponPlan を Max に
        // セットして、 hasActiveCoupon が常に true 扱いになるよう
        // _appliedCouponCode に内部マーカーを入れる方式は副作用が大きいので、
        // ここではシンプルに _couponPlan だけ更新する (notifyListeners で UI
        // 反映)。 引継ぎ先で実 max 課金を独立に扱う仕組みは別途実装。
        _couponPlan = SubscriptionPlan.max;
        await prefs.setString('coupon_plan', 'max');
      }

      // consumedByUids にこの端末を追加 (重複ガード済み)
      // ベストエフォート: 失敗してもユーザー側は成功扱い。
      if (!alreadyConsumed) {
        try {
          consumedUids.add(myUid);
          await http.patch(
            Uri.parse(
                '$url?updateMask.fieldPaths=consumedByUids&updateMask.fieldPaths=lastConsumedAt'),
            headers: {
              'Authorization': 'Bearer $_idToken',
              'Content-Type': 'application/json',
            },
            body: jsonEncode({
              'fields': {
                'consumedByUids': {
                  'arrayValue': {
                    'values':
                        consumedUids.map((u) => {'stringValue': u}).toList(),
                  }
                },
                'lastConsumedAt': {
                  'timestampValue': DateTime.now().toUtc().toIso8601String()
                },
              }
            }),
          );
        } catch (_) {}
      }

      await _syncPlanToUserDoc();
      notifyListeners();
      return null;
    } catch (e) {
      debugPrint('redeemLicenseRestoreCode error: $e');
      return t('restore.errNetwork');
    }
  }

  /// 現在のプラン状態を文字列で返す ('pro' / 'max' / 'free' / 'coupon')。
  ///
  /// 開発者モード時は `_devImpersonatePlan` を反映する (FREE/PRO/MAX)。
  /// 「自分は Pro として振る舞っているのに、他のユーザーから DEV として
  /// 見える」というのを避けるため、演じプランをそのまま返す。
  /// 真の開発者権限の有無は `_developerMode` フラグそのもので判定する。
  ///
  /// `_proSubscribed` が true の通常ユーザーは 'pro' を、クーポン適用中は
  /// 'coupon' を返す。それ以外は 'free'。
  String currentPlanLabel() {
    if (_developerMode)
      return _devImpersonatePlan.name; // 'free' / 'pro' / 'max'
    // 実課金プランは pro/max を区別して返す (Max が 'pro' に丸められないように)
    if (_purchasedPlan != SubscriptionPlan.free) return _purchasedPlan.name;
    if (hasActiveCoupon) return 'coupon';
    return 'free';
  }

  /// /users/{uid} ドキュメントの plan / lastSeen / couponCode を更新する。
  /// プラン状態が変わったタイミングと、起動時 (_initFirebase) に呼ばれる。
  Future<void> _syncPlanToUserDoc() async {
    if (!_firebaseEnabled || _idToken == null || _uid == null) return;
    try {
      await _ensureFreshToken();
      final url = '$_firestoreBaseUrl/users/$_uid';
      final fields = <String, dynamic>{
        'plan': {'stringValue': currentPlanLabel()},
        'lastSeen': {'stringValue': DateTime.now().toUtc().toIso8601String()},
        'couponCode': {'stringValue': _appliedCouponCode ?? ''},
      };
      await http.patch(
        Uri.parse(
            '$url?updateMask.fieldPaths=plan&updateMask.fieldPaths=lastSeen&updateMask.fieldPaths=couponCode'),
        headers: {
          'Authorization': 'Bearer $_idToken',
          'Content-Type': 'application/json',
        },
        body: jsonEncode({'fields': fields}),
      );
      // 所属グループのメンバードキュメントにも plan を反映する。
      // (Max プランのユーザー切替セレクタが member doc の plan で
      //  Pro+ メンバーを絞り込むため、ここを更新しないと古いまま残る)
      for (final gid in _joinedGroupIds) {
        try {
          await _registerMember(gid);
        } catch (_) {}
      }
    } catch (e) {
      debugPrint('_syncPlanToUserDoc error: $e');
    }
  }

  // ─── 開発者モード: ユーザー一覧 (プラン別) ─────────────────────────────
  /// /users コレクションを最大 1000 件まで取得し、
  /// {uid, displayName, plan, lastSeen, couponCode} のリストを返す。
  Future<List<Map<String, dynamic>>> listAllUsers() async {
    if (!_developerMode || !_firebaseEnabled || _idToken == null) return [];
    try {
      await _ensureFreshToken();
      final result = <Map<String, dynamic>>[];
      String? pageToken;
      for (int page = 0; page < 10; page++) {
        final urlBuf = StringBuffer('$_firestoreBaseUrl/users?pageSize=100');
        if (pageToken != null) {
          urlBuf.write('&pageToken=$pageToken');
        }
        final res = await http.get(
          Uri.parse(urlBuf.toString()),
          headers: {'Authorization': 'Bearer $_idToken'},
        );
        if (res.statusCode != 200) break;
        final data = jsonDecode(res.body) as Map<String, dynamic>;
        final docs = data['documents'] as List<dynamic>? ?? [];
        for (final d in docs) {
          final m = d as Map<String, dynamic>;
          final fields = m['fields'] as Map<String, dynamic>? ?? {};
          final docName = (m['name'] as String?) ?? '';
          final uid =
              docName.contains('/users/') ? docName.split('/users/').last : '';
          result.add({
            'uid': uid,
            'displayName': _firestoreStr(fields['displayName']) ?? '',
            'plan': _firestoreStr(fields['plan']) ?? 'free',
            'lastSeen': _firestoreStr(fields['lastSeen']) ?? '',
            'couponCode': _firestoreStr(fields['couponCode']) ?? '',
          });
        }
        pageToken = data['nextPageToken'] as String?;
        if (pageToken == null || pageToken.isEmpty) break;
      }
      // lastSeen で新しい順にソート
      result.sort((a, b) {
        final aL = a['lastSeen'] as String;
        final bL = b['lastSeen'] as String;
        if (aL.isEmpty && bL.isEmpty) return 0;
        if (aL.isEmpty) return 1;
        if (bL.isEmpty) return -1;
        return bL.compareTo(aL);
      });
      return result;
    } catch (e) {
      debugPrint('listAllUsers error: $e');
      return [];
    }
  }

  /// 開発者モードを有効化（永続化）。
  ///
  /// 永続化の挙動: SharedPreferences の `developer_mode=true` フラグを
  /// セットするので、アプリを閉じて再起動してもこの状態は維持される。
  /// 解除するには明示的に `deactivateDeveloperMode()` を呼ぶ必要がある
  /// (= UI 側の「開発者モードを解除」ボタン)。ダイアログを単に閉じても
  /// 解除されない。
  Future<bool> activateDeveloperMode(String password) async {
    if (password == 'Darksan114514') {
      _developerMode = true;
      final prefs = await SharedPreferences.getInstance();
      await prefs.setBool('developer_mode', true);
      await _loadDeveloperSettings();
      notifyListeners();
      // /users/{uid} の plan を演じプラン (free/pro/max のいずれか) に
      // 即同期する。これで他のユーザーから見たときに、開発者が演じている
      // プラン通りに振る舞う (= カレンダー共有等の動作確認が現実的になる)。
      _syncPlanToUserDoc();
      return true;
    }
    return false;
  }

  void deactivateDeveloperMode() {
    _developerMode = false;
    SharedPreferences.getInstance()
        .then((p) => p.setBool('developer_mode', false));
    notifyListeners();
    // 開発者モード解除後、本来のプラン (pro/coupon/free) に戻す
    _syncPlanToUserDoc();
  }

