  /// 開発者モード：全グループの一覧を取得
  Future<List<Map<String, dynamic>>> fetchAllGroups() async {
    if (!_developerMode || !_firebaseEnabled || _idToken == null) return [];
    try {
      final url = '$_firestoreBaseUrl/groups';
      final res = await http.get(
        Uri.parse(url),
        headers: {'Authorization': 'Bearer $_idToken'},
      );
      if (res.statusCode != 200) return [];
      final data = jsonDecode(res.body) as Map<String, dynamic>;
      final docs = data['documents'] as List<dynamic>? ?? [];
      final result = <Map<String, dynamic>>[];
      for (final doc in docs) {
        final name = doc['name'] as String?;
        final updateTime = doc['updateTime'] as String?;
        final createTime = doc['createTime'] as String?;
        if (name != null) {
          final groupId = name.split('/').last;
          result.add({
            'groupId': groupId,
            'updateTime': updateTime,
            'createTime': createTime,
          });
        }
      }
      return result;
    } catch (e) {
      debugPrint('全グループ取得エラー: $e');
      return [];
    }
  }

