  // ── 問い合わせ機能 ────────────────────────────────────────────────────────

  /// ユーザーが問い合わせを送信する
  /// Firestore REST API: inquiries コレクションに問い合わせを保存
  /// ルール allow write: if true なので認証トークン不要
  ///
  /// レート制限: 1 ユーザー (この端末) につき 1 日 (直近 24 時間) で 5 件まで。
  /// SharedPreferences['inquiry_send_log'] に直近のタイムスタンプを保存し、
  /// 24 時間より前のものは自動でクリアする。上限超過時は例外を投げる。
  static const int kInquiryDailyLimit = 5;

  /// 過去 24 時間以内に送信した問い合わせ数を返す。
  /// 古いタイムスタンプは自動的にクリーンアップする。
  Future<int> _purgeAndCountInquirySendLog() async {
    final prefs = await SharedPreferences.getInstance();
    final raw = prefs.getString('inquiry_send_log') ?? '[]';
    List<dynamic> arr;
    try {
      arr = jsonDecode(raw) as List<dynamic>;
    } catch (_) {
      arr = [];
    }
    final now = DateTime.now();
    final cutoff = now.subtract(const Duration(hours: 24));
    final kept = <String>[];
    for (final ts in arr) {
      if (ts is! String) continue;
      final d = DateTime.tryParse(ts);
      if (d == null) continue;
      if (d.isAfter(cutoff)) kept.add(ts);
    }
    if (kept.length != arr.length) {
      await prefs.setString('inquiry_send_log', jsonEncode(kept));
    }
    return kept.length;
  }

  /// 本日 (直近 24 時間) の残り送信可能回数。
  /// UI で残量表示に使う。
  /// 開発者モードでは無制限 (-1) を返し、UI 側でそれを「∞」として扱う。
  Future<int> remainingInquirySendCount() async {
    if (_developerMode) return -1; // -1 = 無制限
    final used = await _purgeAndCountInquirySendLog();
    final remaining = kInquiryDailyLimit - used;
    return remaining < 0 ? 0 : remaining;
  }

  Future<String?> sendInquiry(String message) async {
    if (message.trim().isEmpty) return null;
    // ── ユーザー名 (displayName) 必須チェック ──
    // 問い合わせは送信者を識別する必要があるため、displayName 未設定では
    // 送信不可。UI 側でこの例外をキャッチしてユーザー名設定ダイアログを
    // 開くフローに繋げる。
    if ((_displayName ?? '').trim().isEmpty) {
      throw const _DisplayNameRequiredException();
    }

    // ── レート制限チェック (開発者モードは免除) ──
    if (!_developerMode) {
      final used = await _purgeAndCountInquirySendLog();
      if (used >= kInquiryDailyLimit) {
        throw Exception(t('inquiry.rateLimit'));
      }
    }

    final prefs = await SharedPreferences.getInstance();
    // UIDはローカル保存されたものを使う（匿名認証の有無に依存しない）
    String uid = _uid ?? prefs.getString('firebase_uid') ?? '';
    if (uid.isEmpty) {
      uid = _uuid.v4(); // 匿名UIDを生成してローカルに保存
      await prefs.setString('firebase_uid', uid);
    }
    final msgId = _uuid.v4();
    final now = DateTime.now().toIso8601String();

    // ローカルにも保存
    final existing = prefs.getString('my_inquiries') ?? '[]';
    final list =
        (jsonDecode(existing) as List<dynamic>).cast<Map<String, dynamic>>();
    list.add({
      'id': msgId,
      'message': message.trim(),
      'timestamp': now,
      'reply': '',
      'replyTimestamp': '',
      'status': 'open',
    });
    await prefs.setString('my_inquiries', jsonEncode(list));

    // Firestore REST API: POST でドキュメント作成
    // 認証トークンを取得してから送信（ルールが request.auth != null の場合に対応）
    try {
      if (!_firebaseEnabled || _idToken == null) await _initFirebase();
      await _ensureFreshToken();
    } catch (_) {}

    final url = '$_firestoreBaseUrl/inquiries?documentId=$msgId';
    try {
      final res = await http
          .post(
            Uri.parse(url),
            headers: {
              'Content-Type': 'application/json',
              if (_idToken != null) 'Authorization': 'Bearer $_idToken',
            },
            body: jsonEncode({
              'fields': {
                'uid': {'stringValue': uid},
                'message': {'stringValue': message.trim()},
                'timestamp': {'stringValue': now},
                'reply': {'stringValue': ''},
                'replyTimestamp': {'stringValue': ''},
                'status': {'stringValue': 'open'},
                // 受信ボックスの優先度ソート用にプランを刻印しておく。
                // Cloud Function で開発者メールへ転送するときにも使える。
                'senderPlan': {'stringValue': currentPlanLabel()},
                'senderName': {'stringValue': _displayName ?? ''},
                // 開発者モードで設定したメールアドレス (admin/settings.inquiryEmail)
                // を「転送先」として刻印しておく。Cloud Function 側で
                // この forwardEmail を読んでメール送信するように繋げる想定。
                // クライアント側は別途 mailto: でも開く (UI 側で対応)。
                'forwardEmail': {'stringValue': _inquiryEmail},
              },
            }),
          )
          .timeout(const Duration(seconds: 15));
      if (res.statusCode == 200 || res.statusCode == 201) {
        debugPrint('問い合わせ送信完了: $msgId');
      } else {
        final code = res.statusCode;
        final body = res.body;
        debugPrint('問い合わせ送信失敗: $code $body');
        throw Exception('送信失敗 (HTTP $code): $body');
      }
    } catch (e) {
      debugPrint('問い合わせ送信エラー: $e');
      rethrow;
    }

    // ── 送信成功 → レート制限ログにタイムスタンプを追加 ──
    try {
      final raw = prefs.getString('inquiry_send_log') ?? '[]';
      final arr = (jsonDecode(raw) as List<dynamic>).cast<String>();
      arr.add(now);
      await prefs.setString('inquiry_send_log', jsonEncode(arr));
    } catch (_) {}

    return msgId;
  }

  /// ユーザー自身の問い合わせを削除（ローカル＋Firestore）

  /// 自分が送った問い合わせ一覧を取得（ローカルキャッシュ＋Firestoreマージ）
  Future<List<Map<String, dynamic>>> fetchMyInquiries() async {
    final prefs = await SharedPreferences.getInstance();
    final existing = prefs.getString('my_inquiries') ?? '[]';
    final localList =
        (jsonDecode(existing) as List<dynamic>).cast<Map<String, dynamic>>();

    // Firebase未初期化なら初期化してトークンを取得
    if (!_firebaseEnabled || _idToken == null) {
      try {
        await _initFirebase();
      } catch (_) {}
    }
    if (!_firebaseEnabled || _idToken == null)
      return localList.reversed.toList();

    try {
      await _ensureFreshToken();
      final updated = <Map<String, dynamic>>[];
      for (final local in localList) {
        final msgId = local['id'] as String;
        final url = '$_firestoreBaseUrl/inquiries/$msgId';
        final res = await http.get(
          Uri.parse(url),
          headers: {'Authorization': 'Bearer $_idToken'},
        );
        if (res.statusCode == 200) {
          final data = jsonDecode(res.body) as Map<String, dynamic>;
          final fields = data['fields'] as Map<String, dynamic>? ?? {};
          updated.add({
            'id': msgId,
            'message': _firestoreStr(fields['message']) ?? local['message'],
            'timestamp':
                _firestoreStr(fields['timestamp']) ?? local['timestamp'],
            'reply': _firestoreStr(fields['reply']) ?? '',
            'replyTimestamp': _firestoreStr(fields['replyTimestamp']) ?? '',
            'status': _firestoreStr(fields['status']) ?? 'open',
          });
        } else {
          updated.add(local);
        }
      }
      await prefs.setString('my_inquiries', jsonEncode(updated));
      return updated.reversed.toList();
    } catch (e) {
      debugPrint('問い合わせ取得エラー: $e');
      return localList.reversed.toList();
    }
  }

  /// 開発者専用：全ユーザーの問い合わせ一覧を取得
  Future<List<Map<String, dynamic>>> fetchAllInquiries() async {
    if (!_developerMode) return [];
    // Firebase未初期化なら初期化してトークンを取得
    if (!_firebaseEnabled || _idToken == null) {
      try {
        await _initFirebase();
      } catch (_) {}
    }
    try {
      await _ensureFreshToken();
    } catch (_) {}

    final url = '$_firestoreBaseUrl/inquiries';
    final res = await http.get(
      Uri.parse(url),
      headers: {
        'Content-Type': 'application/json',
        if (_idToken != null) 'Authorization': 'Bearer $_idToken',
      },
    );
    debugPrint('fetchAllInquiries: HTTP ${res.statusCode}');
    if (res.statusCode == 401 || res.statusCode == 403) {
      // トークンを再取得してリトライ
      try {
        await _ensureFreshToken();
        final retry = await http.get(
          Uri.parse(url),
          headers: {
            'Content-Type': 'application/json',
            if (_idToken != null) 'Authorization': 'Bearer $_idToken',
          },
        );
        debugPrint('fetchAllInquiries retry: HTTP ${retry.statusCode}');
        if (retry.statusCode != 200) {
          throw Exception(
              'Firestore読み取りエラー (HTTP ${retry.statusCode}): ${retry.body}');
        }
        return _parseInquiriesDocs(retry.body);
      } catch (e) {
        throw Exception('問い合わせ取得失敗: $e');
      }
    }
    try {
      if (res.statusCode != 200) {
        throw Exception(
            'Firestore読み取りエラー (HTTP \${res.statusCode}): \${res.body}');
      }
      final data = jsonDecode(res.body) as Map<String, dynamic>;
      final docs = data['documents'] as List<dynamic>? ?? [];
      final result = <Map<String, dynamic>>[];
      for (final doc in docs) {
        try {
          final docName = doc['name'] as String;
          final msgId = docName.split('/').last;
          final fields = doc['fields'] as Map<String, dynamic>? ?? {};
          result.add({
            'id': msgId,
            'uid': _firestoreStr(fields['uid']) ?? '',
            'message': _firestoreStr(fields['message']) ?? '',
            'timestamp': _firestoreStr(fields['timestamp']) ?? '',
            'reply': _firestoreStr(fields['reply']) ?? '',
            'replyTimestamp': _firestoreStr(fields['replyTimestamp']) ?? '',
            'status': _firestoreStr(fields['status']) ?? 'open',
            // 送信時に刻印された senderPlan / senderName を読み出す。
            // 旧データは無いので空文字 → あとで /users/{uid}.plan で補完。
            'senderPlan': _firestoreStr(fields['senderPlan']) ?? '',
            'senderName': _firestoreStr(fields['senderName']) ?? '',
          });
        } catch (_) {}
      }
      // ── senderPlan が空の旧レコードに対して /users/{uid}.plan を補完 ──
      // 同じ uid に対して何度もリクエストしないようキャッシュする。
      final uidsNeedingPlan = <String>{
        for (final r in result)
          if ((r['senderPlan'] as String).isEmpty &&
              (r['uid'] as String).isNotEmpty)
            r['uid'] as String,
      };
      if (uidsNeedingPlan.isNotEmpty) {
        final planByUid = await _fetchUserPlansByUids(uidsNeedingPlan);
        for (final r in result) {
          if ((r['senderPlan'] as String).isEmpty) {
            final uid = r['uid'] as String;
            r['senderPlan'] = planByUid[uid] ?? 'free';
          }
        }
      }
      // ── ソート: プラン優先 (Max → developer/coupon → Pro → Free) → 新しい順 ──
      result.sort((a, b) {
        final aR = _planSortRank(a['senderPlan'] as String);
        final bR = _planSortRank(b['senderPlan'] as String);
        if (aR != bR) return aR.compareTo(bR);
        return (b['timestamp'] as String).compareTo(a['timestamp'] as String);
      });
      return result;
    } catch (e) {
      debugPrint('全問い合わせ取得エラー: $e');
      rethrow; // UIでエラーを表示するためrethrow
    }
  }

  /// 受信ボックスのソート優先度。値が小さいほど上に表示される。
  ///   max       : 0 (最優先)
  ///   developer : 1
  ///   pro       : 2
  ///   coupon    : 3
  ///   free      : 4
  ///   その他    : 5
  static int _planSortRank(String plan) {
    switch (plan) {
      case 'max':
        return 0;
      case 'developer':
        return 1;
      case 'pro':
        return 2;
      case 'coupon':
        return 3;
      case 'free':
        return 4;
      default:
        return 5;
    }
  }

  /// /users/{uid} ドキュメントの plan を一括取得 (uid → plan のマップ)。
  /// 旧仕様の問い合わせ (senderPlan が空) を補完するため。
  /// Firestore REST API は単発 GET しかないので並列リクエストする。
  /// 失敗 / 取得不能なものは結果マップに含めない (呼び出し側で 'free' に
  /// フォールバック)。
  Future<Map<String, String>> _fetchUserPlansByUids(Set<String> uids) async {
    final result = <String, String>{};
    if (!_firebaseEnabled || _idToken == null || uids.isEmpty) return result;
    try {
      await _ensureFreshToken();
    } catch (_) {}
    // 並列で取得 (最大同時 8 件くらいに絞る)
    final uidList = uids.toList();
    const chunkSize = 8;
    for (int i = 0; i < uidList.length; i += chunkSize) {
      final chunk = uidList.sublist(
          i, (i + chunkSize > uidList.length) ? uidList.length : i + chunkSize);
      await Future.wait(chunk.map((uid) async {
        try {
          final r = await http.get(
            Uri.parse('$_firestoreBaseUrl/users/$uid'),
            headers: {
              if (_idToken != null) 'Authorization': 'Bearer $_idToken',
            },
          );
          if (r.statusCode == 200) {
            final d = jsonDecode(r.body) as Map<String, dynamic>;
            final fields = d['fields'] as Map<String, dynamic>? ?? {};
            final plan = _firestoreStr(fields['plan']);
            if (plan != null && plan.isNotEmpty) result[uid] = plan;
          }
        } catch (_) {}
      }));
    }
    return result;
  }

  /// Firestore inquiriesドキュメント一覧をパース (401/403 リトライ用)。
  /// senderPlan が空のドキュメントは 'free' 扱いでソートされる
  /// (リトライ系なので /users/{uid}.plan の補完までは行わず素早く返す)。
  List<Map<String, dynamic>> _parseInquiriesDocs(String body) {
    final data = jsonDecode(body) as Map<String, dynamic>;
    final docs = data['documents'] as List<dynamic>? ?? [];
    final result = <Map<String, dynamic>>[];
    for (final doc in docs) {
      try {
        final docName = doc['name'] as String;
        final msgId = docName.split('/').last;
        final fields = doc['fields'] as Map<String, dynamic>? ?? {};
        result.add({
          'id': msgId,
          'uid': _firestoreStr(fields['uid']) ?? '',
          'message': _firestoreStr(fields['message']) ?? '',
          'timestamp': _firestoreStr(fields['timestamp']) ?? '',
          'reply': _firestoreStr(fields['reply']) ?? '',
          'replyTimestamp': _firestoreStr(fields['replyTimestamp']) ?? '',
          'status': _firestoreStr(fields['status']) ?? 'open',
          'senderPlan': _firestoreStr(fields['senderPlan']) ?? '',
          'senderName': _firestoreStr(fields['senderName']) ?? '',
        });
      } catch (_) {}
    }
    result.sort((a, b) {
      final aR = _planSortRank(a['senderPlan'] as String);
      final bR = _planSortRank(b['senderPlan'] as String);
      if (aR != bR) return aR.compareTo(bR);
      return (b['timestamp'] as String).compareTo(a['timestamp'] as String);
    });
    return result;
  }

  /// 開発者専用：問い合わせに返信する
  Future<bool> replyToInquiry(String msgId, String replyText) async {
    if (!_developerMode) return false;
    try {
      if (_firebaseEnabled && _idToken == null) await _ensureFreshToken();
      final now = DateTime.now().toIso8601String();
      final url = '$_firestoreBaseUrl/inquiries/$msgId'
          '?updateMask.fieldPaths=reply'
          '&updateMask.fieldPaths=replyTimestamp'
          '&updateMask.fieldPaths=status';
      final res = await http.patch(
        Uri.parse(url),
        headers: {
          if (_idToken != null) 'Authorization': 'Bearer $_idToken',
          'Content-Type': 'application/json',
        },
        body: jsonEncode({
          'fields': {
            'reply': {'stringValue': replyText.trim()},
            'replyTimestamp': {'stringValue': now},
            'status': {'stringValue': 'replied'},
          },
        }),
      );
      return res.statusCode == 200;
    } catch (e) {
      debugPrint('返信エラー: $e');
      return false;
    }
  }

  /// 開発者専用：問い合わせを削除
  Future<bool> deleteInquiry(String msgId) async {
    if (!_developerMode) return false;
    try {
      if (_firebaseEnabled && _idToken == null) await _ensureFreshToken();
      final url = '$_firestoreBaseUrl/inquiries/$msgId';
      final res = await http.delete(
        Uri.parse(url),
        headers: {
          if (_idToken != null) 'Authorization': 'Bearer $_idToken',
        },
      );
      return res.statusCode == 200 || res.statusCode == 204;
    } catch (e) {
      return false;
    }
  }

  Future<bool> deleteMyInquiry(String msgId) async {
    // ローカルから削除
    final prefs = await SharedPreferences.getInstance();
    final existing = prefs.getString('my_inquiries') ?? '[]';
    final list =
        (jsonDecode(existing) as List<dynamic>).cast<Map<String, dynamic>>();
    list.removeWhere((e) => e['id'] == msgId);
    await prefs.setString('my_inquiries', jsonEncode(list));

    // Firestoreからも削除（ベストエフォート）
    try {
      await _ensureFreshToken();
      final url = '$_firestoreBaseUrl/inquiries/$msgId';
      final res = await http.delete(
        Uri.parse(url),
        headers: {
          if (_idToken != null) 'Authorization': 'Bearer $_idToken',
        },
      );
      debugPrint('Firestore削除: ${res.statusCode}');
    } catch (e) {
      debugPrint('自分の問い合わせ削除エラー: $e');
    }
    return true; // ローカル削除は成功
  }

  // ─── AI キャンセル機構 ────────────────────────────────────────────────
  // AI 生成実行中フラグ。UI は aiInProgress を監視して進行中の場合は「停止」
  // ボタンを出す。cancelAi() が呼ばれると _aiCancelled が立ち、AI メソッド側で
  // 次のチェックポイントで早期 return（ノードには何も反映されない）。
  //
  // 加えて、AI 開始時点での各ページの Undo スタックサイズを記録する
  // (`_aiStartUndoSize`)。これは Ctrl+Z の挙動を「AI 開始後にユーザーが
  // 行った別作業を先に取り消し、それが無くなった時点で AI 自体をキャンセル」
  // とするため。これにより AI はバックグラウンドで動作し続け、別作業と
  // 並行できる。
  bool _aiInProgress = false;
  bool get aiInProgress => _aiInProgress;
  bool _aiCancelled = false;
  bool get aiCancelled => _aiCancelled;

  /// AI 開始時点での各ページの Undo スタックサイズ。
  /// AI 開始後にユーザーが編集すると _undoStacks に新しいスナップショットが
  /// 積まれ、サイズが増える。Ctrl+Z は increment 分を先に取り消し、
  /// すべて取り消し終わってからの追加 Ctrl+Z で AI 自体をキャンセルする。
  final Map<String, int> _aiStartUndoSize = {};

  void _beginAi() {
    _aiInProgress = true;
    _aiCancelled = false;
    // 全ページの現在の Undo スタックサイズをスナップショット
    _aiStartUndoSize.clear();
    for (final entry in _undoStacks.entries) {
      _aiStartUndoSize[entry.key] = entry.value.length;
    }
    notifyListeners();
  }

  void _endAi() {
    _aiInProgress = false;
    _aiStartUndoSize.clear();
    notifyListeners();
  }

  /// 進行中の AI 生成をキャンセル。実行中の HTTP リクエスト自体は止められないが、
  /// 完了後に結果がノードへ反映されるのを防ぐ。
  void cancelAi() {
    if (_aiInProgress) {
      _aiCancelled = true;
      notifyListeners();
    }
  }

  /// AI 開始後にユーザーが Undo 可能な操作を行ったか判定。
  /// true の場合、Ctrl+Z は AI のキャンセルではなく通常の undo を実行すべき
  /// （AI 開始後の別作業を先に取り消す）。
  /// false の場合（AI 開始後に何も操作していない）、Ctrl+Z で AI をキャンセル。
  bool get hasUserActionsAfterAiStart {
    if (!_aiInProgress) return false;
    for (final entry in _undoStacks.entries) {
      final startSize = _aiStartUndoSize[entry.key] ?? 0;
      if (entry.value.length > startSize) return true;
    }
    return false;
  }

  /// ── AI 呼び出し統一ディスパッチャ ──
  /// `aiProvider` の設定に従い Gemini / OpenAI / Claude に振り分ける
  Future<String> askAi(String prompt) async {
    switch (_aiProvider) {
      case 'openai':
        return askOpenAi(prompt);
      case 'anthropic':
        return askClaude(prompt);
      case 'grok':
        return askGrok(prompt);
      case 'deepseek':
        return askDeepseek(prompt);
      case 'gemini':
      default:
        return askGemini(prompt);
    }
  }

  // ════════ AI 生成スタジオ (画像 / スライド) = ユーザー要望 ════════

  /// プロンプトから画像を 1 枚生成して PNG/JPEG バイト列を返す。
  /// 画像生成は Gemini の image モデルのみ対応 (= 他プロバイダ選択時も
  /// Gemini キーがあれば動く)。 失敗時は分かりやすい例外を投げる。
  Future<Uint8List> generateAiImage(String prompt) async {
    if (!hasGeminiKey) {
      throw Exception('画像生成には Gemini APIキーが必要です（設定で登録してください）');
    }
    final p = prompt.trim();
    if (p.isEmpty) throw Exception('プロンプトを入力してください');
    // 画像対応モデルを優先順に試す (利用可否はキー/リージョンで変わる)。
    // 選択モデル (auto 以外) があれば先頭に持ってくる (= ユーザー要望: 切替)。
    final base = [
      'gemini-2.5-flash-image',
      'gemini-2.5-flash-image-preview',
      'gemini-2.0-flash-preview-image-generation',
    ];
    final imageModels =
        (_imageGenModel != 'auto' && base.contains(_imageGenModel))
            ? [_imageGenModel, ...base.where((m) => m != _imageGenModel)]
            : base;
    Object? lastErr;
    for (final model in imageModels) {
      final url = 'https://generativelanguage.googleapis.com/v1beta/models/'
          '$model:generateContent?key=$_geminiApiKey';
      try {
        final res = await http
            .post(
              Uri.parse(url),
              headers: {'Content-Type': 'application/json'},
              body: jsonEncode({
                'contents': [
                  {
                    'parts': [
                      {'text': p}
                    ]
                  }
                ],
                'generationConfig': {
                  'responseModalities': ['IMAGE', 'TEXT']
                },
              }),
            )
            .timeout(const Duration(seconds: 90));
        if (res.statusCode == 404 || res.statusCode == 400) {
          // このモデルは使えない → 次の候補へ。
          lastErr = Exception('モデル $model 利用不可 (${res.statusCode})');
          continue;
        }
        if (res.statusCode == 403) {
          throw Exception('Gemini APIキーが無効か、画像生成が許可されていません');
        }
        if (res.statusCode == 429) {
          throw Exception('レート制限です。しばらく待ってから再試行してください');
        }
        if (res.statusCode != 200) {
          lastErr = Exception('画像生成エラー: ${res.statusCode}');
          continue;
        }
        final data = jsonDecode(res.body) as Map<String, dynamic>;
        final candidates = data['candidates'] as List<dynamic>?;
        if (candidates == null || candidates.isEmpty) {
          lastErr = Exception('画像が返りませんでした');
          continue;
        }
        final content =
            (candidates.first as Map)['content'] as Map<String, dynamic>?;
        final parts = content?['parts'] as List<dynamic>?;
        if (parts != null) {
          for (final part in parts) {
            final m = part as Map<String, dynamic>;
            final inline =
                (m['inlineData'] ?? m['inline_data']) as Map<String, dynamic>?;
            final b64 = inline?['data'] as String?;
            if (b64 != null && b64.isNotEmpty) {
              return base64Decode(b64);
            }
          }
        }
        lastErr = Exception('応答に画像が含まれていません');
      } on TimeoutException {
        lastErr = Exception('画像生成がタイムアウトしました');
      }
    }
    throw lastErr is Exception
        ? lastErr as Exception
        : Exception('画像生成に失敗しました');
  }

  /// トピックからプレゼン用スライド構成を AI に作らせて返す。
  /// 各スライド = (見出し, 箇条書きリスト)。 pptx 生成に使う (= ユーザー要望)。
  Future<List<({String title, List<String> bullets})>> generateSlideOutline(
      String topic,
      {int slides = 6}) async {
    if (!hasActiveAiKey) {
      throw Exception('スライド生成には AI APIキーが必要です（設定で登録してください）');
    }
    final t = topic.trim();
    if (t.isEmpty) throw Exception('トピックを入力してください');
    final n = slides.clamp(3, 20);
    final prompt = '''次のトピックについて、プレゼン用スライドを$n枚作成してください。
トピック: $t

出力は次の形式の JSON 配列のみ（前後の説明やマークダウン記号は一切付けない）:
[{"title":"スライドの見出し","bullets":["要点1","要点2","要点3"]}]

ルール:
- 1枚目はタイトル/概要スライド。
- 各スライドの bullets は2〜5個、各要点は簡潔な一文。
- 全体で$n枚ちょうど。''';
    final raw = await askAiForJson(prompt);
    final list = _parseSlideJson(raw);
    if (list.isEmpty) throw Exception('スライド構成の生成に失敗しました');
    return list;
  }

  List<({String title, List<String> bullets})> _parseSlideJson(String raw) {
    // ```json ... ``` フェンスや前後ノイズを除去して配列部分を取り出す。
    var s = raw.trim();
    final start = s.indexOf('[');
    final end = s.lastIndexOf(']');
    if (start >= 0 && end > start) s = s.substring(start, end + 1);
    final out = <({String title, List<String> bullets})>[];
    try {
      final decoded = jsonDecode(s);
      if (decoded is List) {
        for (final e in decoded) {
          if (e is Map) {
            final title = (e['title'] ?? e['heading'] ?? '').toString();
            final rawB = e['bullets'] ?? e['points'] ?? e['body'];
            final bullets = <String>[];
            if (rawB is List) {
              for (final b in rawB) {
                final bs = b.toString().trim();
                if (bs.isNotEmpty) bullets.add(bs);
              }
            } else if (rawB is String && rawB.trim().isNotEmpty) {
              bullets.add(rawB.trim());
            }
            if (title.isNotEmpty || bullets.isNotEmpty) {
              out.add((title: title, bullets: bullets));
            }
          }
        }
      }
    } catch (_) {/* パース不可なら空 */}
    return out;
  }

  /// ── JSON 構造を期待する AI 呼び出し ──
  ///
  /// 内部で次の事をやる:
  /// - Gemini なら `responseMimeType: application/json` で確実に JSON を返してもらう
  /// - OpenAI なら `response_format: json_object` で同上
  /// - Claude は専用 JSON モードが無いので素直に投げる
  /// - 出力トークン上限を 4096〜8192 に増やして「JSON が途中で切れる」事故を防ぐ
  ///   (旧来 2048 上限で長い解説がよく途中で切れて parse 失敗していた)
  ///
  /// [detailed] が true のときは更に大きいトークンを許可する (詳しい解説向け)。
  Future<String> askAiForJson(String prompt, {bool detailed = false}) async {
    final maxTokens = detailed ? 8192 : 4096;
    switch (_aiProvider) {
      case 'openai':
        return askOpenAi(prompt, jsonMode: true, maxTokensOverride: maxTokens);
      case 'anthropic':
        return askClaude(prompt, maxTokensOverride: maxTokens);
      case 'grok':
        return askGrok(prompt, jsonMode: true, maxTokensOverride: maxTokens);
      case 'deepseek':
        return askDeepseek(prompt,
            jsonMode: true, maxTokensOverride: maxTokens);
      case 'gemini':
      default:
        return askGemini(prompt, jsonMode: true, maxTokensOverride: maxTokens);
    }
  }

  /// AI に JSON 構造を要求し、解釈失敗時は 1 度だけ「JSON だけ返して」と
  /// 再試行してから諦める。最終的に失敗したら、AI が実際に返した文字列の
  /// 冒頭をエラーメッセージに含めて投げる (デバッグしやすくするため)。
  ///
  /// このヘルパは summarize / explain 共通で利用する。
  Future<Map<String, dynamic>> _askAiForJsonStructure(String prompt,
      {bool detailed = false}) async {
    String text;
    try {
      text = await askAiForJson(prompt, detailed: detailed);
    } catch (e) {
      // ネットワーク等のエラーはそのまま投げる (UI 側でメッセージ表示)
      rethrow;
    }
    Map<String, dynamic>? parsed = _extractJsonStructure(text);
    if (parsed != null) return parsed;

    // ── 1 回だけ「JSON のみで再出力して」とリトライ ──
    debugPrint('AI 出力 1 回目で JSON 抽出失敗。retry します。'
        '\n--- raw (head) ---\n${text.substring(0, text.length > 400 ? 400 : text.length)}');
    final retryPrompt = '''
あなたが直前に返した出力は有効な JSON ではありませんでした。
再度、有効な JSON オブジェクト 1 つだけを返してください。
コードフェンス、前置き、後置き、解説文、 // コメント、末尾カンマは
一切付けないでください。
内容が長くなりそうなら、項目数や文字数を減らして構造を簡潔にしてください。

直前の出力 (壊れた JSON):
$text
''';
    try {
      text = await askAiForJson(retryPrompt, detailed: detailed);
    } catch (e) {
      rethrow;
    }
    parsed = _extractJsonStructure(text);
    if (parsed != null) return parsed;

    // ── それでも失敗 → ユーザーに見える範囲で AI の応答を含めて throw ──
    final preview = text.length > 240 ? '${text.substring(0, 240)}…' : text;
    throw Exception('AI 出力から構造を取得できませんでした\n--- AI の応答 (冒頭) ---\n$preview');
  }

  /// http(s) URL かどうかをざっくり検証して返す。空文字や無効なら null。
  /// AI が `link_url` 等に何でも書いてくる可能性があるので、ノードに
  /// 入れる前にここで弾く。
  String? _validatedHttpUrl(dynamic v) {
    if (v == null) return null;
    if (v is! String) return null;
    final s = v.trim();
    if (s.isEmpty) return null;
    if (!s.startsWith('http://') && !s.startsWith('https://')) return null;
    return s;
  }

  /// URL が **実際に開けるか** を軽く確認する。
  ///
  /// AI は YouTube や Wikipedia の URL をそれっぽく作って返すことがある
  /// (ハルシネーション)。クリックすると 404 になる「飛べないリンク」を
  /// ノードに残しても害悪なので、ノード作成前にここで実在チェックする。
  ///
  /// - YouTube は HEAD だと「動画が無い」状態でも 200 を返してくる
  ///   (テンプレ HTML を返すだけ)。代わりに **oembed エンドポイント**
  ///   `https://www.youtube.com/oembed?url=...` を叩く。これは存在する
  ///   動画だけ 200 を返し、無い/非公開なら 401/404 を返す。
  /// - その他の URL は HEAD で statusCode を見る。HEAD を許さない (405) や
  ///   一部サイト (403 Forbidden) には GET でフォールバック。
  /// - 4xx と判定 / タイムアウト / DNS 失敗等は **すべて「実在しない」扱い**
  ///   (ユーザーは「正確に開けるリンクだけ欲しい」と明言している)。
  /// - 5xx は一時障害の可能性が高いので「実在する」として残す。
  Future<bool> _isUrlReachable(String url) async {
    try {
      final lower = url.toLowerCase();
      final isYoutube =
          lower.contains('youtube.com') || lower.contains('youtu.be');
      if (isYoutube) {
        final api = 'https://www.youtube.com/oembed?'
            'url=${Uri.encodeQueryComponent(url)}&format=json';
        final res =
            await http.get(Uri.parse(api)).timeout(const Duration(seconds: 5));
        return res.statusCode == 200;
      }
      // 一般 URL: HEAD → 405/403 なら GET フォールバック
      var res =
          await http.head(Uri.parse(url)).timeout(const Duration(seconds: 5));
      if (res.statusCode == 405 || res.statusCode == 403) {
        res =
            await http.get(Uri.parse(url)).timeout(const Duration(seconds: 7));
      }
      // 4xx は無効、5xx は一時障害扱いで残す
      if (res.statusCode >= 400 && res.statusCode < 500) return false;
      return true;
    } catch (_) {
      // タイムアウト・DNS 失敗 etc → 飛べない URL とみなす
      return false;
    }
  }

  /// AI が返した構造の中の `youtube_url` / `link_url` / `image_url` を
  /// 並列に reachability 確認して、**飛べないものは Map から削除**する。
  /// `_buildPageFromAiStructure` の直前で呼ぶ。
  Future<int> _validateUrlsInStructure(Map<String, dynamic> structure) async {
    // ノードの URL スロットを再帰的に集める
    final slots = <_UrlSlot>[];
    void scan(dynamic n) {
      if (n is Map) {
        for (final f in const [
          'youtube_url',
          'link_url',
          'image_url',
        ]) {
          final v = n[f];
          if (v is String && _validatedHttpUrl(v) != null) {
            slots.add(_UrlSlot(node: n, field: f, url: v.trim()));
          }
        }
        final c = n['children'];
        if (c is List) {
          for (final x in c) scan(x);
        }
        final r = n['roots'];
        if (r is List) {
          for (final x in r) scan(x);
        }
      }
    }

    scan(structure);
    if (slots.isEmpty) return 0;

    // 並列に reachability チェック (各 URL ごとに自前で 5〜7s timeout)
    final results = await Future.wait(
      slots.map((s) async {
        try {
          return await _isUrlReachable(s.url);
        } catch (_) {
          return false;
        }
      }),
    );

    // 飛べない URL は Map から削除
    int stripped = 0;
    for (int i = 0; i < slots.length; i++) {
      if (!results[i]) {
        slots[i].node.remove(slots[i].field);
        stripped++;
        debugPrint('URL validation: 飛べないため削除 ${slots[i].url}');
      }
    }
    return stripped;
  }

  /// AI に JSON 構造マップを生成してもらう共通プロンプトテンプレ。
  /// summarize と explain で同じスキーマを使うことで、後段の
  /// `_buildPageFromAiStructure` が両方の出力に対応できるようにする。
  ///
  /// [introLines] は機能ごとの「役割文」(例: "あなたは資料を構造化要約する..."
  /// "あなたは博識な解説者です..." 等)。
  /// [detail] は 'rough' | 'standard' | 'detailed' で、ノード数や階層の深さを変える。
  /// [userInstruction] はユーザーから入力された追加指示 (省略可)。
  String _buildAiStructurePrompt({
    required String introLines,
    required String detail,
    String userInstruction = '',
  }) {
    String detailGuide;
    switch (detail) {
      case 'rough':
        detailGuide = '''
詳細レベル: 「分かり易く (要点のみ、初心者向け)」
- 主要トピックは 3〜5 個
- 階層は最大 2 階層 (深掘りはせず、まず全体像)
- 平易な言葉で、専門用語が出るときは memo で 1 文補足
- memo は 1 文程度に短く
''';
        break;
      case 'detailed':
        detailGuide = '''
詳細レベル: 「詳しい (深掘り)」
- 主要トピックは 6〜10 個
- 階層は 3〜4 階層、可能なら具体例ノードまで含める
- memo は 1〜3 文 (要点 + 具体例)
''';
        break;
      default:
        detailGuide = '''
詳細レベル: 「標準」
- 主要トピックは 4〜8 個
- 階層は 2〜3 階層
- memo は 1〜3 文の要点
''';
    }

    final instruction = userInstruction.trim().isNotEmpty
        ? '\nユーザーからの追加指示: ${userInstruction.trim()}'
        : '';

    // 注意: 旧版は schema 例を [...] でぼかしていたため、AI が literal で
    // [...] を書いてきて JSON が壊れる事例があった。schema 例は
    // 完全に有効な JSON として書き、「これは構造の参考」とルール文で明示する。
    return '''
$introLines

出力は **必ず JSON オブジェクト 1 つのみ** とし、コードフェンス (\`\`\`)、
前置き、後置き、解説文、 // コメントは一切含めないでください。

JSON の形は次のとおり:
- トップに "title" (文字列、ページ全体のタイトル) を入れる。
- 内容は次の **どちらか** の形で表現する:
  * 単一ツリー型: トップに "children" (ノード配列) を直接付ける。
  * 複数ツリー型: トップに "roots" (ノード配列) を入れ、各要素を独立した
    マインドマップのルートとして扱う。1 つの親に無理にまとめなくて良い。
- 各ノードは次のフィールドを持つ:
  * "title": 必須・文字列
  * "memo": 任意・文字列 (1〜3 文の補足)
  * "children": 任意・同じ形のノード配列
  * "youtube_url": 任意・文字列 (http(s):// で始まる YouTube 動画 URL)
  * "link_url": 任意・文字列 (Wikipedia など参考 web ページの URL)
  * "image_url": 任意・文字列 (画像の URL、link_url と同じ扱い)

例 (構造の参考。実際の内容は対象に合わせて差し替えること):
{
  "title": "ページ全体のタイトル",
  "roots": [
    {
      "title": "観点A",
      "memo": "概要",
      "children": [
        {"title": "詳細1", "memo": "短い説明",
         "link_url": "https://ja.wikipedia.org/wiki/Example"},
        {"title": "詳細2",
         "youtube_url": "https://www.youtube.com/watch?v=dQw4w9WgXcQ"}
      ]
    },
    {"title": "観点B", "memo": "別軸の見方"}
  ]
}

$detailGuide
ルール:
- title は短く (15〜25文字目安)。
- **冗長な前置き・繰り返しは禁止**:
  * 子ノードの title に親や全体のテーマ名を再度含めない
    (例: テーマが「都道府県の有名人」で子が「茨城県」なら、
     "都道府県の有名人のうち茨城県の有名人" ではなく単に「茨城県」と書く)。
  * memo に「ここでは…を解説します」「本項では…」のような前置きを入れない。
    内容そのものを 1〜3 文で簡潔に書く。
- youtube_url / link_url / image_url は **書かない方が安全**。本当に実在し、
  かつ自分の記憶で URL を正しく覚えているとほぼ確信できる時にだけ書くこと。
  少しでも不安なら省略してください。**架空の URL は絶対に書かないこと**
  (出力後に実在チェックを行い、飛べないリンクは自動で破棄されます)。
- YouTube URL を書く場合は、有名なチャンネルの代表的な動画など、出力時に
  実在を強く確信できるものに限定すること。
- 1 つにまとめづらいテーマは "roots" 形式で 2〜4 個のツリーに分割可。
- 文字列内のダブルクォートは必ず \\ でエスケープすること。
- 末尾カンマや // コメントは絶対に書かないこと。$instruction
''';
  }

  /// AI 構造 JSON (top: {title, roots? | children?, ...}) からノードを配置する
  /// 共通の後段処理。summarize / explain 両方から呼ばれる。
  ///
  /// 「単一ツリー型」(top.children) も「複数ツリー型」(top.roots) も両対応。
  /// 複数ツリー型の場合、各ツリーは縦に積んで配置 (X は同じ列、Y を順に下げる)。
  /// 1 つでも複数でも同じレイアウト関数 [_placeAiSummaryChildren] を再利用する。
  ///
  /// [structure] は AI が返した JSON。`_extractJsonStructure` の戻り値。
  /// [fallbackTitle] は title が無かった時のページ名 (ファイル名 or 用語名)。
  AiMapResult _buildPageFromAiStructure({
    required Map<String, dynamic> structure,
    required String fallbackTitle,
    required bool addToCurrentPage,
    required Offset rootPosition,
    // ファイル要約モードでは true。AI が返した roots/children を全て
    // [fallbackTitle] (= ファイル名) を頂点とする 1 つのツリーの子としてぶら下げる。
    // ユーザー要望: 「読み込ませたファイルが一番上の親ノードになるように」
    bool wrapWithFileTitle = false,
  }) {
    // ── ルート群を抽出 ──
    // 新フォーマット: top.roots が配列 → そのまま採用
    // 旧/単一: top.children を持つ → 全体を 1 ルートとして扱う
    final rootEntries = <Map<String, dynamic>>[];
    final rootsRaw = structure['roots'];
    if (rootsRaw is List && rootsRaw.isNotEmpty) {
      for (final r in rootsRaw) {
        if (r is Map) {
          rootEntries.add(r.map((k, v) => MapEntry(k.toString(), v)));
        }
      }
    }
    if (rootEntries.isEmpty) {
      // top の title/memo/children/url を「単一ルート」と見立てる
      rootEntries.add(<String, dynamic>{
        'title': structure['title'] ?? fallbackTitle,
        'memo': structure['memo'],
        'children': structure['children'] ?? const [],
        'youtube_url': structure['youtube_url'],
        'link_url': structure['link_url'],
        'image_url': structure['image_url'],
      });
    }

    // ── ファイル要約モード: ファイル名を頂点として全 roots を子として束ねる ──
    // wrap 後は rootEntries が 1 つだけになり、その children が元の roots。
    // 旧構造から fileName をルートに変える効果と、AI が複数 roots を返したとき
    // それらが「セクション」のように頂点ファイル名にぶら下がる効果がある。
    if (wrapWithFileTitle) {
      final wrappedChildren =
          rootEntries.map((r) => Map<String, dynamic>.from(r)).toList();
      rootEntries
        ..clear()
        ..add(<String, dynamic>{
          'title': fallbackTitle,
          'memo': null,
          'children': wrappedChildren,
        });
    }

    // ── ページ名: ファイル要約モードは fallbackTitle (= ファイル名) を採用 ──
    // wrap した時に root が fileName になっているので、ページ名もそれに揃える。
    String pageTitle;
    if (wrapWithFileTitle) {
      pageTitle = fallbackTitle;
    } else {
      final topTitle = (structure['title'] as String?)?.trim();
      if (topTitle != null && topTitle.isNotEmpty) {
        pageTitle = topTitle;
      } else {
        final firstT = (rootEntries[0]['title'] as String?)?.trim();
        pageTitle =
            (firstT != null && firstT.isNotEmpty) ? firstT : fallbackTitle;
      }
    }

    if (!addToCurrentPage) {
      addPage(name: pageTitle);
    }
    final pageIdx = _currentPageIndex;

    const minVerticalGap = 40.0;
    const interRootGap = 80.0; // ルートツリー間に追加で空ける
    const rootW = 220.0;
    const rootH = 60.0;

    // 各ルートの占有高さを事前計算
    final rootHeights = rootEntries
        .map((r) => _computeAiSubtreeHeight(r, minVerticalGap))
        .toList();

    // 全体の縦方向合計
    double totalH = 0;
    for (int i = 0; i < rootHeights.length; i++) {
      totalH += rootHeights[i];
      if (i < rootHeights.length - 1) totalH += interRootGap;
    }

    // 中心揃え: 「ルート全体の縦中心」を「rootPosition の縦中心 (= rootPos.dy + rootH/2)」
    // に合わせる。これで単一ルートだった時と複数ルートだった時で、ユーザーから見た
    // 出現位置が大きくぶれない。
    final anchorCenterY = rootPosition.dy + rootH / 2;
    double currentY = anchorCenterY - totalH / 2;

    String? firstRootId;
    Offset firstRootTopLeft = rootPosition;

    for (int i = 0; i < rootEntries.length; i++) {
      final entry = rootEntries[i];
      final subH = rootHeights[i];

      final title = (entry['title'] as String?)?.trim() ?? '';
      if (title.isEmpty) {
        currentY += subH + interRootGap;
        continue;
      }
      final memo = (entry['memo'] as String?)?.trim();
      final ytUrl = _validatedHttpUrl(entry['youtube_url']);
      final linkUrl = _validatedHttpUrl(entry['link_url']) ??
          _validatedHttpUrl(entry['image_url']);
      final children = (entry['children'] as List<dynamic>?) ?? const [];

      // このルートのスロット中心 (孫もここを基準に上下対称化)
      final slotCenterY = currentY + subH / 2;
      final rootTopLeft = Offset(rootPosition.dx, slotCenterY - rootH / 2);

      // contentType: youtube > link > memo > none の優先順
      NodeContentType ct = NodeContentType.none;
      if (ytUrl != null) {
        ct = NodeContentType.youtube;
      } else if (linkUrl != null) {
        ct = NodeContentType.link;
      } else if (memo != null && memo.isNotEmpty) {
        ct = NodeContentType.memo;
      }

      final root = MindMapNode(
        id: _uuid.v4(),
        title: title.length > 30 ? '${title.substring(0, 30)}…' : title,
        position: rootTopLeft,
        width: rootW,
        height: rootH,
        color: const Color(0xFF6C63FF),
        memoText: memo,
        youtubeUrl: ytUrl,
        linkUrl: linkUrl,
        contentType: ct,
      );
      currentPage.nodes[root.id] = root;
      if (firstRootId == null) {
        firstRootId = root.id;
        firstRootTopLeft = rootTopLeft;
      }

      if (children.isNotEmpty) {
        // 複数ルートの場合、ルートごとに違う「色シード」で開始する。
        // 単一ルート (= ファイル要約 wrap モード) の場合は i=0 で始まる。
        // 係数 3 はパレット長 8 と互いに素 (i*3 が散らせる)。
        _placeAiSummaryChildren(
          parent: root,
          childrenJson: children,
          depth: 1,
          siblingsCount: children.length,
          parentSlotCenterY: slotCenterY,
          parentColorIdx: (i * 3) % 8,
        );
      }

      currentY += subH + interRootGap;
    }

    _saveToStorage();
    notifyListeners();
    return AiMapResult(
      pageIndex: pageIdx,
      rootId: firstRootId ?? '',
      rootPosition: firstRootTopLeft,
      addedToCurrentPage: addToCurrentPage,
    );
  }

  /// ── ファイル要約 → マインドマップ化 ──
  /// 与えられたファイルの内容を AI で要約し、階層構造を取り出して
  /// マインドマップとして配置する。
  ///
  /// [addToCurrentPage] が true の場合は新規ページを作らず、現在ページに
  /// 追加する。false の場合は新規ページを作って配置する (旧来の動作)。
  /// [rootPosition] はルートノードを置く canvas 座標 (左上)。
  /// 「現在ページに追加」モードで「画面に映っている領域」に置きたい時は
  /// 画面側で viewport 中心の canvas 座標を計算して渡す。
  ///
  /// 対応形式:
  ///   - テキスト系 (.txt/.md/.csv/.json/.log/.py/.dart など): UTF-8 として直接読む
  ///   - PDF/docx/pptx: Gemini に inline_data で渡す or Claude にドキュメント
  ///                    として渡す (両 API ともネイティブ対応)
  ///                    OpenAI は対応外なので一時的に Gemini にフォールバック。
  ///
  /// 戻り値: AiMapResult (どのページの どの canvas 位置に作ったか)。
  /// エラーは throw する (UI 側で SnackBar に表示)。
  Future<AiMapResult> summarizeFileToNewPage({
    required String filePath,
    required String fileName,
    String? userInstruction,
    bool addToCurrentPage = false,
    Offset rootPosition = const Offset(2000, 2000),
    String detail = 'standard', // 'rough' | 'standard' | 'detailed'
    String? pretext, // = ユーザー要望: 抽出済みテキスト (非 Gemini で PDF 等)
  }) async {
    final f = File(filePath);
    if (!await f.exists()) {
      throw Exception('File not found: $filePath');
    }
    // 拡張子で形式を判定
    final dot = fileName.lastIndexOf('.');
    final ext = dot >= 0 ? fileName.substring(dot + 1).toLowerCase() : '';
    const textExts = {
      'txt',
      'md',
      'markdown',
      'csv',
      'tsv',
      'json',
      'log',
      'dart',
      'py',
      'js',
      'ts',
      'java',
      'kt',
      'cpp',
      'c',
      'h',
      'hpp',
      'cs',
      'go',
      'rb',
      'rs',
      'swift',
      'sh',
      'yml',
      'yaml',
      'xml',
      'html',
      'htm',
      'css',
    };
    const binaryDocExts = {'pdf', 'docx', 'pptx'};

    // 統一プロンプトテンプレ + ファイル要約用の役割文
    final structurePrompt = _buildAiStructurePrompt(
      introLines: 'あなたは資料を構造化要約するアシスタントです。\n'
          '渡された資料 ($fileName) の内容を読み、要旨を階層的なマインドマップに変換してください。',
      detail: detail,
      userInstruction: userInstruction ?? '',
    );

    // ── AI 呼び出し: バイナリ系は専用経路、テキスト系/その他は本文を結合 ──
    Map<String, dynamic> structure;
    // 追加質問機能 (askAiFollowUpForPage) で再利用するための「資料の文脈」を
    // ここで掴んでおく。テキスト系なら本文 (truncate 済み) を、バイナリ系なら
    // ファイルパスだけを保持する。
    String? capturedTextContent;
    String? capturedBinaryPath;

    if (pretext != null && pretext.trim().isNotEmpty) {
      // = ユーザー要望: 抽出済みテキスト (PDF 等) を選択中プロバイダで要約。
      //   Gemini 以外はバイナリを直接読めないため、 呼び出し側でテキスト抽出。
      var content = pretext;
      const int kMaxChars = 60000;
      if (content.length > kMaxChars) {
        content = '${content.substring(0, kMaxChars)}\n... [truncated]';
      }
      capturedTextContent = content;
      structure = await _askAiForJsonStructure(
          '$structurePrompt\n\n--- 資料の内容 ---\n$content',
          detailed: detail == 'detailed');
    } else if (textExts.contains(ext)) {
      // ── テキスト直接読み込み ──
      String content;
      try {
        content = await f.readAsString();
      } catch (_) {
        // UTF-8 で読めなかった場合 (Shift-JIS など) はバイトから latin1 経由で
        final bytes = await f.readAsBytes();
        content = String.fromCharCodes(bytes);
      }
      // 巨大ファイルは AI コンテキスト制限を超えるので 60,000 文字に制限
      const int kMaxChars = 60000;
      if (content.length > kMaxChars) {
        content = '${content.substring(0, kMaxChars)}\n... [truncated]';
      }
      capturedTextContent = content;
      final fullPrompt = '$structurePrompt\n\n--- 資料の内容 ---\n$content';
      // 構造化 JSON 取得 (失敗時は内部で 1 度自動再試行)
      structure = await _askAiForJsonStructure(fullPrompt,
          detailed: detail == 'detailed');
    } else if (binaryDocExts.contains(ext)) {
      // ── バイナリドキュメント (PDF/docx/pptx) ──
      // バイナリ送信は jsonMode の生 HTTP 経路と互換しないので、
      // 旧来通り askAi 経由で投げ、_extractJsonStructure で救済する。
      // (大半のケースで OK; 失敗した場合は手動で再試行を促すメッセージが出る)
      capturedBinaryPath = filePath;
      final aiResponseText = await _askAiWithBinaryDoc(
        filePath: filePath,
        fileName: fileName,
        ext: ext,
        prompt: structurePrompt,
      );
      final parsed = _extractJsonStructure(aiResponseText);
      if (parsed == null) {
        debugPrint('AI 出力 (JSON抽出失敗): $aiResponseText');
        final preview = aiResponseText.length > 240
            ? '${aiResponseText.substring(0, 240)}…'
            : aiResponseText;
        throw Exception('AI 出力から構造を取得できませんでした\n--- AI の応答 (冒頭) ---\n$preview');
      }
      structure = parsed;
    } else {
      // それ以外 (画像など) はテキスト読み込みを試行 → 失敗ならエラー
      try {
        final content = await f.readAsString();
        final truncated = content.length > 60000
            ? '${content.substring(0, 60000)}\n... [truncated]'
            : content;
        capturedTextContent = truncated;
        structure = await _askAiForJsonStructure(
            '$structurePrompt\n\n--- 資料の内容 ---\n$truncated',
            detailed: detail == 'detailed');
      } catch (_) {
        throw Exception('未対応のファイル形式です: .$ext');
      }
    }

    // ── URL 実在チェック (飛べないリンクをノードに残さない) ──
    // AI が hallucinate した YouTube/Wikipedia URL をここで弾く。
    // 並列に reachability 確認 → 飛べないものは structure から削除。
    await _validateUrlsInStructure(structure);

    // ── 構造をページに展開 (単一ツリー / 複数ツリー両対応) ──
    // ユーザー要望: ファイル要約はファイル名を一番上の親ノードに置き、
    // AI が返したセクション群をその子としてぶら下げる。
    final result = _buildPageFromAiStructure(
      structure: structure,
      fallbackTitle: fileName,
      addToCurrentPage: addToCurrentPage,
      rootPosition: rootPosition,
      wrapWithFileTitle: true,
    );

    // ── 追加質問用の文脈を保存 ──
    // 配置されたページ (新規 or 現在) の id をキーにして資料情報を保持。
    // ユーザーが後で「資料に関する追加質問」をしたら askAiFollowUpForPage が参照する。
    if (result.pageIndex >= 0 && result.pageIndex < _pages.length) {
      final pageId = _pages[result.pageIndex].id;
      _aiPageContexts[pageId] = AiPageContext(
        fileName: fileName,
        textContent: capturedTextContent,
        filePath: capturedBinaryPath,
        ext: ext,
      );
    }
    return result;
  }

  /// ── 用語・概念を AI に解説させてマインドマップ化 ──
  /// summarizeFileToNewPage のテキスト版/対話版。ファイルではなくユーザーが
  /// 入力した用語 (例: "オートエンコーダ" "三段論法") を AI に解説させ、
  /// その階層構造をマインドマップに展開する。
  ///
  /// [addToCurrentPage] が true なら新規ページを作らず現在ページに追加。
  /// [rootPosition] はルートノードを置く canvas 座標。
  /// [detail] は 'rough' | 'standard' | 'detailed' で、解説の深さを変える。
  /// [comprehensive] が true の場合は **網羅モード**: 1 回の AI 出力に
  /// 収まらないテーマ (例: "都道府県毎の有名人") を複数回に分けて生成し、
  /// 最後に 1 ページに統合する。詳細は `_explainConceptComprehensive` 参照。
  /// [onProgress] は網羅モード中の進捗通知 (current, total, currentLabel)。
  /// 戻り値: AiMapResult。
  /// エラーは throw する (UI 側で SnackBar に表示)。
  Future<AiMapResult> explainConceptToNewPage({
    required String term,
    String? userInstruction,
    bool addToCurrentPage = false,
    Offset rootPosition = const Offset(2000, 2000),
    String detail = 'standard',
    bool comprehensive = false,
    void Function(int current, int total, String currentLabel)? onProgress,
  }) async {
    if (term.trim().isEmpty) {
      throw Exception('用語・概念が空です');
    }
    final cleanTerm = term.trim();

    if (comprehensive) {
      // 網羅モード: 単発の AI 呼び出しでは出力トークン上限で全項目を埋め切れない
      // 場合に、計画 → 分割実行 → マージ の 3 段階で完全網羅を狙う。
      return _explainConceptComprehensive(
        term: cleanTerm,
        userInstruction: userInstruction ?? '',
        addToCurrentPage: addToCurrentPage,
        rootPosition: rootPosition,
        detail: detail,
        onProgress: onProgress,
      );
    }

    // 統一プロンプトテンプレ + 用語解説用の役割文
    final structurePrompt = _buildAiStructurePrompt(
      introLines: 'あなたは博識な解説者です。\n'
          'ユーザーから提示された用語・概念「$cleanTerm」を、初学者にも理解できるように\n'
          '階層的なマインドマップに整理して解説してください。\n'
          '内容に応じて「概要」「主な構成要素・仕組み」「応用例」「関連概念」「歴史」'
          '「メリット/デメリット」「よくある誤解」などの観点を適宜含めること。\n'
          '1 つの親に無理にまとめづらいテーマは、複数のルート (roots 形式) に分けて構わない。',
      detail: detail,
      userInstruction: userInstruction ?? '',
    );

    // JSON 構造を取得 (失敗時は内部で 1 度自動再試行 + 詳細エラー)
    final structure = await _askAiForJsonStructure(structurePrompt,
        detailed: detail == 'detailed');

    // URL 実在チェック (飛べないリンクは structure から削除)
    await _validateUrlsInStructure(structure);

    // 構造をページに展開 (単一ツリー / 複数ツリー両対応 + URL/画像対応)
    return _buildPageFromAiStructure(
      structure: structure,
      fallbackTitle: cleanTerm,
      addToCurrentPage: addToCurrentPage,
      rootPosition: rootPosition,
    );
  }

  /// 網羅モードの本体。
  ///
  /// 設計思想:
  /// 「都道府県毎の有名人」「世界の主要都市」「全大統領」のような **対象が
  /// 多く 1 回の AI 出力では出力トークン上限で途中切れする** トピックを、
  /// 計画 (Plan) → 分割実行 (Expand) → 統合 (Merge) の 3 段階で確実に網羅する。
  ///
  /// 1. **Plan フェーズ**:
  ///    AI に「このテーマを網羅するなら、何を子テーマとして列挙すべき?」と
  ///    だけ聞き、平坦な配列で返してもらう。schema は
  ///    `{ "title": "...", "subjects": [ { "name": "..." }, ... ] }` 形式。
  ///    都道府県なら 47 個、国連加盟国なら 193 個といった具合。
  ///
  /// 2. **Expand フェーズ**:
  ///    Plan で得た subjects を batch サイズ (デフォルト 4) で区切り、
  ///    各バッチについて「これらの子テーマ <X1, X2, ...> について
  ///    それぞれ階層的な内容を JSON で返して」と AI に問い合わせる。
  ///    各バッチの応答は roots 配列 (バッチ内で 1 root = 1 subject) として
  ///    返ってくる前提。バッチが小さいことで出力上限切れを避けられる。
  ///
  /// 3. **Merge フェーズ**:
  ///    全バッチの roots を 1 つの親ルート (term) の children として連結し、
  ///    `_buildPageFromAiStructure` で配置する。これによりユーザー視点では
  ///    「1 つの大きなマインドマップ」として見える。
  ///
  /// [onProgress] は (current=完了済 subject 数, total=全 subject 数, label=現在処理中の subject)
  /// で UI へ進捗を通知 (省略可能)。
  Future<AiMapResult> _explainConceptComprehensive({
    required String term,
    required String userInstruction,
    required bool addToCurrentPage,
    required Offset rootPosition,
    required String detail,
    void Function(int current, int total, String currentLabel)? onProgress,
  }) async {
    // 二重起動を防ぐ。直前の生成がまだ in-flight ならエラーで弾く。
    if (_explainInProgress) {
      throw Exception('別の AI 解説生成が進行中です。完了/停止してから再実行してください。');
    }
    _explainInProgress = true;
    _explainCancelRequested = false;
    notifyListeners();

    try {
      final hint = userInstruction.trim().isNotEmpty
          ? '\nユーザーからの追加指示: ${userInstruction.trim()}'
          : '';

      // ── (1) Plan フェーズ: 子テーマを列挙させる ──
      onProgress?.call(0, 0, '計画中…');
      final planPrompt = '''
あなたはマインドマップを設計するアシスタントです。
ユーザーが与えるテーマ「$term」を **網羅的に** 解説するマインドマップを作る
ための、最初の枝分かれ (子テーマ) を列挙してください。

例:
- テーマが「都道府県毎の有名人」なら 47 都道府県すべてを列挙
- テーマが「世界の通貨」なら主要通貨を 30〜80 件
- テーマが「人体の臓器」なら主要臓器を 15〜30 件
- テーマが「日本史の時代区分」なら全時代区分を漏れなく

返却は JSON 1 個のみ。コードフェンス、前置き、後置き等は禁止:
{
  "title": "$term",
  "subjects": [
    {"name": "子テーマ1の名前"},
    {"name": "子テーマ2の名前"}
  ]
}

ルール:
- subjects の各 name は短く (15〜25文字目安)。
- **網羅性最優先**: 知っている限り全部列挙すること。
  「など」「ほか」「主要なもののみ」で省略してはいけない。
- name は対象そのものの呼び名 ("茨城県" "ドル" など) のみで、
  テーマ名 ("$term") を再度含めない (重複表示は禁止)。
- 順序は分かりやすい順 (五十音/北→南/古→新 等) で。
- 数が膨大すぎる場合は 200 件で打ち切り、その旨は出力しない (黙って先頭 200)。$hint
''';

      final plan = await _askAiForJsonStructure(planPrompt, detailed: true);
      final subjectsRaw = plan['subjects'];
      if (subjectsRaw is! List || subjectsRaw.isEmpty) {
        throw Exception('AI が網羅対象を列挙できませんでした (subjects が空)');
      }
      final subjects = <String>[];
      for (final s in subjectsRaw) {
        if (s is Map) {
          final n = (s['name'] as String?)?.trim();
          if (n != null && n.isNotEmpty) subjects.add(n);
        } else if (s is String) {
          if (s.trim().isNotEmpty) subjects.add(s.trim());
        }
      }
      if (subjects.isEmpty) {
        throw Exception('AI が網羅対象を列挙できませんでした (有効な name が無い)');
      }
      debugPrint('網羅モード: ${subjects.length} 件の subject を計画');

      // ── (2) Expand フェーズ: バッチごとに詳細展開 ──
      // batch サイズは detail に応じて調整。詳しいモードはバッチを小さくして
      // 出力切れを避ける。
      final batchSize = detail == 'detailed' ? 3 : (detail == 'rough' ? 6 : 4);

      final allRoots = <Map<String, dynamic>>[];
      int processed = 0;
      final total = subjects.length;

      // キャンセル発生時にどこで止めたかを記録 (これ以降の subject は
      // 再開セッションに保存される)。
      int cancelAtIndex = -1;

      for (int i = 0; i < subjects.length; i += batchSize) {
        // 各バッチの直前で停止リクエストをチェック。
        // 現在のバッチが既に AI 通信を開始していたら最後まで完走させ、
        // 次のバッチの直前でループを抜ける。
        if (_explainCancelRequested) {
          cancelAtIndex = i;
          debugPrint('網羅モード: キャンセル要求を検知。$i 件目以降を保留に。');
          break;
        }

        final batchEnd = (i + batchSize).clamp(0, subjects.length);
        final batch = subjects.sublist(i, batchEnd);
        onProgress?.call(processed, total, batch.first);

        // バッチ用プロンプト: 各 subject を独立した root にして、その下に
        // 詳細を階層展開する。
        final batchPrompt = _buildBatchExpandPrompt(
          masterTheme: term,
          batchSubjects: batch,
          detail: detail,
          userInstruction: userInstruction,
        );

        Map<String, dynamic>? batchStruct;
        try {
          batchStruct = await _askAiForJsonStructure(batchPrompt,
              detailed: detail == 'detailed');
        } catch (e) {
          // 1 バッチ失敗しても他のバッチは続行 (網羅モードの目的は最大限カバー)
          debugPrint('網羅モード: バッチ失敗 [$batch] → スキップ: $e');
          processed = batchEnd;
          continue;
        }

        // 各 subject を root として取り出して allRoots に追加
        // batchStruct.roots がある場合はそれを使用。無ければ subject ごとに
        // 「name に一致する root」を探して追加。
        final batchRoots = batchStruct['roots'];
        if (batchRoots is List) {
          for (final r in batchRoots) {
            if (r is Map) {
              allRoots.add(r.map((k, v) => MapEntry(k.toString(), v)));
            }
          }
        } else {
          // フォールバック: top.children をそのまま使う (1 root しか作れなかった場合)
          if (batchStruct['children'] is List) {
            allRoots.add(<String, dynamic>{
              'title': batchStruct['title'] ?? batch.first,
              'children': batchStruct['children'],
            });
          }
        }
        processed = batchEnd;
        onProgress?.call(processed, total, batch.last);
      }

      // 何 1 つも完了する前にキャンセルされた場合: 配置するものが無いので
      // セッションを保存せずに例外を投げる (ユーザーに「停止しました」とだけ伝える)。
      if (allRoots.isEmpty) {
        if (cancelAtIndex == 0) {
          throw Exception('停止しました (まだ何も生成されていません)');
        }
        throw Exception('AI が網羅展開に失敗しました (全バッチがエラー)');
      }

      // ── (3) Merge フェーズ: 全 root を 1 つの親 (term) 配下にまとめる ──
      // top.title = テーマ全体名、children = 各 subject の root を平坦化したもの
      // (各 subject root の title/memo/youtube_url/link_url/image_url/children を保持)
      final mergedStructure = <String, dynamic>{
        'title': term,
        'children': allRoots,
      };

      // URL 実在チェック (飛べないリンクは削除)
      await _validateUrlsInStructure(mergedStructure);

      final result = _buildPageFromAiStructure(
        structure: mergedStructure,
        fallbackTitle: term,
        addToCurrentPage: addToCurrentPage,
        rootPosition: rootPosition,
      );

      // キャンセルされていた場合は、残りの subject を再開セッションとして保存。
      if (cancelAtIndex >= 0 && cancelAtIndex < subjects.length) {
        final remaining = subjects.sublist(cancelAtIndex);
        if (remaining.isNotEmpty &&
            result.pageIndex >= 0 &&
            result.pageIndex < _pages.length) {
          final page = _pages[result.pageIndex];
          _pausedExplainSession = PausedExplainSession(
            term: term,
            userInstruction: userInstruction,
            detail: detail,
            pageIndex: result.pageIndex,
            pageId: page.id,
            parentRootId: result.rootId,
            remainingSubjects: remaining,
            doneCount: cancelAtIndex,
            totalCount: subjects.length,
          );
          debugPrint('網羅モード: 一時停止セッションを保存 (残 ${remaining.length} 件)');
        }
      } else {
        // 完走した場合は古いセッションをクリア (もし残ってれば)
        _pausedExplainSession = null;
      }

      return result;
    } finally {
      _explainInProgress = false;
      _explainCancelRequested = false;
      notifyListeners();
    }
  }

  /// 一時停止された網羅モード解説を続きから再開する。
  ///
  /// `_pausedExplainSession` が無い場合は throw。
  /// 既存のページの parent root の子としてさらに subject roots を追記する。
  /// 全ての残り subject を完了したらセッションは破棄、再度途中停止された場合は
  /// セッションを更新して保持する。
  ///
  /// 戻り値: AiMapResult (該当ページの index と parent root の id を返す)。
  Future<AiMapResult> resumeExplainConcept({
    void Function(int current, int total, String currentLabel)? onProgress,
  }) async {
    final session = _pausedExplainSession;
    if (session == null) {
      throw Exception('再開できる解説セッションがありません');
    }
    if (_explainInProgress) {
      throw Exception('別の AI 解説生成が進行中です');
    }

    // セッション保存時のページが現存することを確認 (id ベース)
    int pageIdx = -1;
    for (int i = 0; i < _pages.length; i++) {
      if (_pages[i].id == session.pageId) {
        pageIdx = i;
        break;
      }
    }
    if (pageIdx < 0) {
      _pausedExplainSession = null;
      notifyListeners();
      throw Exception('解説の保存先ページが見つかりません (削除された可能性)');
    }
    final page = _pages[pageIdx];
    final parentRoot = page.nodes[session.parentRootId];
    if (parentRoot == null) {
      _pausedExplainSession = null;
      notifyListeners();
      throw Exception('解説の親ノードが見つかりません');
    }

    _explainInProgress = true;
    _explainCancelRequested = false;
    notifyListeners();

    try {
      final remaining = List<String>.from(session.remainingSubjects);
      final batchSize = session.detail == 'detailed'
          ? 3
          : (session.detail == 'rough' ? 6 : 4);

      // 「残り全体」に対する進捗を doneCount/totalCount で表示するため、
      // baseDone = 既に完了済の件数。
      int processedInThisRun = 0;
      int cancelAtInRemaining = -1;
      final newRoots = <Map<String, dynamic>>[];

      for (int i = 0; i < remaining.length; i += batchSize) {
        if (_explainCancelRequested) {
          cancelAtInRemaining = i;
          debugPrint('再開: キャンセル要求を検知。残 ${remaining.length - i} 件をさらに保留に。');
          break;
        }

        final batchEnd = (i + batchSize).clamp(0, remaining.length);
        final batch = remaining.sublist(i, batchEnd);
        onProgress?.call(session.doneCount + processedInThisRun,
            session.totalCount, batch.first);

        final batchPrompt = _buildBatchExpandPrompt(
          masterTheme: session.term,
          batchSubjects: batch,
          detail: session.detail,
          userInstruction: session.userInstruction,
        );

        Map<String, dynamic>? batchStruct;
        try {
          batchStruct = await _askAiForJsonStructure(batchPrompt,
              detailed: session.detail == 'detailed');
        } catch (e) {
          debugPrint('再開: バッチ失敗 [$batch] → スキップ: $e');
          processedInThisRun = batchEnd;
          continue;
        }

        final batchRoots = batchStruct['roots'];
        if (batchRoots is List) {
          for (final r in batchRoots) {
            if (r is Map) {
              newRoots.add(r.map((k, v) => MapEntry(k.toString(), v)));
            }
          }
        } else if (batchStruct['children'] is List) {
          newRoots.add(<String, dynamic>{
            'title': batchStruct['title'] ?? batch.first,
            'children': batchStruct['children'],
          });
        }
        processedInThisRun = batchEnd;
        onProgress?.call(session.doneCount + processedInThisRun,
            session.totalCount, batch.last);
      }

      // URL 実在チェック (新規分のみ)
      if (newRoots.isNotEmpty) {
        // _validateUrlsInStructure は top に children を持つ構造を前提とするので
        // 一時的にラップしてチェック。
        await _validateUrlsInStructure(<String, dynamic>{
          'title': session.term,
          'children': newRoots,
        });

        // 既存の親 root の子として追記
        _appendAiRootsToParent(
          pageIndex: pageIdx,
          parentNodeId: session.parentRootId,
          newRoots: newRoots,
        );
      }

      // セッション更新
      if (cancelAtInRemaining >= 0 && cancelAtInRemaining < remaining.length) {
        final stillRemaining = remaining.sublist(cancelAtInRemaining);
        _pausedExplainSession = session.copyWith(
          pageIndex: pageIdx,
          remainingSubjects: stillRemaining,
          doneCount: session.doneCount + cancelAtInRemaining,
        );
      } else {
        // 全て完了 → セッション破棄
        _pausedExplainSession = null;
      }

      _saveToStorage();
      notifyListeners();

      return AiMapResult(
        pageIndex: pageIdx,
        rootId: session.parentRootId,
        rootPosition: parentRoot.position,
        addedToCurrentPage: pageIdx == _currentPageIndex,
      );
    } finally {
      _explainInProgress = false;
      _explainCancelRequested = false;
      notifyListeners();
    }
  }

  /// 再開時に、新規 subject roots を既存の親ノードの子として追記する。
  ///
  /// 配置方針: 親 root の右側に縦に並んでいる既存の子 subject roots の
  /// 最下端よりさらに下に新しい子を積む。これにより既存ノードと重ならず、
  /// 「ページの下方向に伸びていく」自然な見た目になる。
  void _appendAiRootsToParent({
    required int pageIndex,
    required String parentNodeId,
    required List<Map<String, dynamic>> newRoots,
  }) {
    if (newRoots.isEmpty) return;
    if (pageIndex < 0 || pageIndex >= _pages.length) return;
    final page = _pages[pageIndex];
    final parent = page.nodes[parentNodeId];
    if (parent == null) return;

    // 既存の子ノード (parent から east → west で繋がっているノード) の
    // 縦範囲を計算。
    double bottomMost = parent.position.dy + parent.height;
    final existingChildIds = <String>{};
    for (final c in page.connections) {
      if (c.fromId == parentNodeId &&
          c.fromAnchor == AnchorDirection.east &&
          c.toAnchor == AnchorDirection.west) {
        existingChildIds.add(c.toId);
      }
    }
    for (final cid in existingChildIds) {
      final child = page.nodes[cid];
      if (child == null) continue;
      final childBottom = child.position.dy + child.visualHeight;
      if (childBottom > bottomMost) bottomMost = childBottom;
    }

    // 新規 root の配置位置 (親と同じ x の右側)。Y は既存の最下端の少し下から開始。
    const double horizontalGap = 280.0;
    const double minVerticalGap = 40.0;
    final childX = parent.position.dx + parent.width + horizontalGap;

    // 各新規 root の必要高さを事前計算
    final subtreeHeights = newRoots
        .map((r) => _computeAiSubtreeHeight(r, minVerticalGap))
        .toList();

    // 既存の最下端から開始 (重ならないよう minVerticalGap を空ける)
    double currentY = bottomMost + minVerticalGap;

    // 色パレットは _placeAiSummaryChildren と同じ
    const palette = <Color>[
      Color(0xFF4FC3F7),
      Color(0xFF43B97F),
      Color(0xFFFFB347),
      Color(0xFFBA68C8),
      Color(0xFFFF6B6B),
      Color(0xFF26C6DA),
      Color(0xFFFFD54F),
      Color(0xFF9CCC65),
    ];

    // 既存の子の数を数えて、新規はその次の色から始める (色の連続性)
    final colorOffset = existingChildIds.length;

    for (int i = 0; i < newRoots.length; i++) {
      final raw = newRoots[i];
      final title = (raw['title'] as String?)?.trim() ?? '';
      if (title.isEmpty) continue;
      final memo = (raw['memo'] as String?)?.trim();
      final grandChildren = (raw['children'] as List<dynamic>?) ?? const [];

      final subH = subtreeHeights[i];
      // ── 高さ: NodeWidget の `node.height + memoExtraH` 仕様に合わせる ──
      // node.height は「タイトル領域だけ」。メモは下に自動で伸びる。
      final w = (title.length * 14.0 + 40).clamp(180.0, 340.0);
      const double h = 50.0;
      double displayH = h;
      if (memo != null && memo.isNotEmpty) {
        const memoFontSize = 11.0;
        final lineCount =
            (memo.length / (w / memoFontSize * 1.2)).ceil().clamp(1, 20);
        displayH += lineCount * (memoFontSize + 3);
      }

      final childSlotCenter = currentY + subH / 2;
      final childPos = Offset(childX, childSlotCenter - displayH / 2);

      // 色: 既存の子に続く順番で coprime 巡回 (_placeAiSummaryChildren 参照)
      final colorIdx = ((colorOffset + i) * 3 + 1) % palette.length;
      final color = palette[colorIdx];

      final ytUrl = _validatedHttpUrl(raw['youtube_url']);
      final linkUrl = _validatedHttpUrl(raw['link_url']) ??
          _validatedHttpUrl(raw['image_url']);
      NodeContentType ct = NodeContentType.none;
      if (ytUrl != null) {
        ct = NodeContentType.youtube;
      } else if (linkUrl != null) {
        ct = NodeContentType.link;
      } else if (memo != null && memo.isNotEmpty) {
        ct = NodeContentType.memo;
      }

      final child = MindMapNode(
        id: _uuid.v4(),
        title: title,
        memoText: memo,
        position: childPos,
        width: w.toDouble(),
        height: h,
        color: color,
        youtubeUrl: ytUrl,
        linkUrl: linkUrl,
        contentType: ct,
      );
      page.nodes[child.id] = child;
      page.connections.add(NodeConnection(
        fromId: parent.id,
        fromAnchor: AnchorDirection.east,
        toId: child.id,
        toAnchor: AnchorDirection.west,
      ));

      // 孫を再帰配置 (= _placeAiSummaryChildren と同じ処理を、
      // ただし currentPage のかわりに対象ページの nodes へ書き出す)。
      // 簡単のためにページが現在ページなら _placeAiSummaryChildren を流用、
      // そうでなければ一時的に _currentPageIndex を切り替える。
      if (grandChildren.isNotEmpty) {
        final savedIdx = _currentPageIndex;
        _currentPageIndex = pageIndex;
        try {
          _placeAiSummaryChildren(
            parent: child,
            childrenJson: grandChildren,
            depth: 1,
            siblingsCount: grandChildren.length,
            parentSlotCenterY: childSlotCenter,
            parentColorIdx: colorIdx,
          );
        } finally {
          _currentPageIndex = savedIdx;
        }
      }

      currentY += subH + minVerticalGap;
    }

    page.lastModifiedAt = DateTime.now();
  }

  /// 網羅モード Expand フェーズ用プロンプト。
  /// 1 バッチ ([batchSubjects] 個) 分の詳細展開を要求する。
  String _buildBatchExpandPrompt({
    required String masterTheme,
    required List<String> batchSubjects,
    required String detail,
    required String userInstruction,
  }) {
    String detailGuide;
    switch (detail) {
      case 'rough':
        detailGuide = '各 subject につき、子要素は 2〜4 個、階層は 1〜2 段、'
            'memo は 1 文程度に短く。';
        break;
      case 'detailed':
        detailGuide = '各 subject につき、子要素は 5〜8 個、階層は 2〜3 段、'
            '具体例ノードまで含める。memo は 1〜3 文。';
        break;
      default:
        detailGuide = '各 subject につき、子要素は 3〜6 個、階層は 1〜2 段、'
            'memo は 1〜2 文の要点。';
    }
    final hint = userInstruction.trim().isNotEmpty
        ? '\nユーザーからの追加指示: ${userInstruction.trim()}'
        : '';
    final subjectList = batchSubjects.map((s) => '- $s').join('\n');

    return '''
あなたは博識な解説者です。テーマ「$masterTheme」のマインドマップ全体のうち、
今回はその一部を担当します。次に挙げる subject (枝) について、それぞれ
階層的なマインドマップを作成してください。

担当する subject (${batchSubjects.length} 件):
$subjectList

返却は JSON 1 個のみ。コードフェンス、前置き、後置き、解説文、 // コメント、
末尾カンマは一切禁止。schema は次のとおり:
{
  "roots": [
    {
      "title": "${batchSubjects.first}",
      "memo": "1〜3 文の概要",
      "children": [
        {"title": "..", "memo": "..", "children": [...]}
      ]
    }
  ]
}

各ノードは title (必須), memo (任意), children (任意, 同形配列),
youtube_url (任意), link_url (任意), image_url (任意) を持てる。

ルール:
- roots は **必ず ${batchSubjects.length} 個** にし、上記の subject に
  1:1 対応させること。順番もリスト順に揃える。
- $detailGuide
- **title は subject 名そのものを使う** (上の例なら「${batchSubjects.first}」)。
  「$masterTheme のうち ◯◯」「$masterTheme の ◯◯」のように
  マスターテーマ名を含めて冗長にしない (重複表示で読みづらくなるため)。
- 子ノード (children) の title も短く 15〜25 文字目安。
  「◯◯ について」「◯◯ の説明」のような飾りは付けず、項目名そのものを書く。
- memo も冗長な前置き ("ここでは…を説明します", "本項では…")
  を入れず、内容そのものを 1〜3 文で簡潔に書く。
- youtube_url / link_url / image_url は本当に実在を確信できる時のみ。
  少しでも不安なら省略 (架空 URL は禁止、出力後に実在チェックされ削除されます)。
- 文字列内のダブルクォートは必ず \\ でエスケープ。$hint
''';
  }

  /// ── AI 追加質問 (要約済み資料に対する Q&A) ──
  ///
  /// `summarizeFileToNewPage` でマップ化したページに対して、ユーザーが
  /// 「この資料の中で〇〇についてもう少し説明して」のような追加質問を
  /// 投げると、当時の資料 (テキスト本文 or バイナリファイル) を再添付して
  /// AI に答えさせる。
  ///
  /// 戻り値: 回答テキスト。同時に `_aiPageContexts[pageId].qaHistory` に
  /// 履歴として追加され、UI 側で会話ログ風に表示できる。
  /// 文脈が無いページに対して呼ぶと throw。
  Future<String> askAiFollowUpForPage(String pageId, String question) async {
    final ctx = _aiPageContexts[pageId];
    if (ctx == null) {
      throw Exception('このページには AI 要約の文脈がありません');
    }
    final cleanQ = question.trim();
    if (cleanQ.isEmpty) {
      throw Exception('質問が空です');
    }

    // ── プロンプト組立 ──
    // テキスト系なら本文を埋め込む (60K 文字に切り詰め済みのものを使う)。
    // これまでの Q&A 履歴も含めて、文脈の継続性を保つ。
    final contentPart = (ctx.textContent != null && ctx.textContent!.isNotEmpty)
        ? '--- 資料の内容 ---\n${ctx.textContent}\n\n'
        : '';

    String historyPart = '';
    if (ctx.qaHistory.isNotEmpty) {
      // 履歴が長くなりすぎるとコンテキスト圧迫するので、直近 6 ターンに制限
      const int kMaxHistoryTurns = 6;
      final recent = ctx.qaHistory.length > kMaxHistoryTurns
          ? ctx.qaHistory.sublist(ctx.qaHistory.length - kMaxHistoryTurns)
          : ctx.qaHistory;
      historyPart = '--- これまでの Q&A 履歴 ---\n';
      for (final e in recent) {
        historyPart += 'Q: ${e.question}\nA: ${e.answer}\n\n';
      }
    }

    final prompt = '''
あなたは資料「${ctx.fileName}」について質問に答えるアシスタントです。
資料の内容を踏まえて、簡潔かつ正確に答えてください。

以下のルールを必ず守ってください:
- 資料に書かれていない事は推測ではなく「資料に明示的な記載はありません」と答えること。
- 「ご質問ありがとうございます」のような前置きは省き、要点から答え始めること。
- 回答は通常 2〜6 文程度に簡潔にまとめる。長くなる場合は箇条書きを使う。
- ユーザーが事実関係について質問していて資料外の一般知識から補足する場合は、
  「資料外の補足:」と明示してから書くこと。

$contentPart$historyPart--- 新しい質問 ---
$cleanQ
''';

    // バイナリ系 (PDF/docx/pptx) は textContent が無いので毎回再添付。
    // ファイルが移動・削除されている場合は、フォールバックでテキストなし問い合わせ。
    String answer;
    final isBinary = ctx.filePath != null &&
        (ctx.ext == 'pdf' || ctx.ext == 'docx' || ctx.ext == 'pptx');
    if (isBinary) {
      final f = File(ctx.filePath!);
      if (await f.exists()) {
        answer = await _askAiWithBinaryDoc(
          filePath: ctx.filePath!,
          fileName: ctx.fileName,
          ext: ctx.ext!,
          prompt: prompt,
        );
      } else {
        debugPrint('追加質問: 資料ファイルが見つからない (${ctx.filePath}) → テキスト無しで問い合わせ');
        answer = await askAi(prompt);
      }
    } else {
      answer = await askAi(prompt);
    }

    // 履歴に追加 (UI が listen している)
    ctx.qaHistory.add(AiQAEntry(
      question: cleanQ,
      answer: answer.trim(),
      ts: DateTime.now(),
    ));
    notifyListeners();
    return answer.trim();
  }

  /// AI 追加質問の特定ターンを履歴から削除 (ユーザーがやり直したい時用)。
  void deleteAiFollowUpEntry(String pageId, int index) {
    final ctx = _aiPageContexts[pageId];
    if (ctx == null) return;
    if (index < 0 || index >= ctx.qaHistory.length) return;
    ctx.qaHistory.removeAt(index);
    notifyListeners();
  }

  /// AI に PDF/docx/pptx を直接添付して問い合わせる。
  /// Gemini: inline_data で base64 を渡す
  /// Claude: document タイプで base64 を渡す
  /// OpenAI: 直接対応がないので Gemini にフォールバック (要 Gemini キー)
  Future<String> _askAiWithBinaryDoc({
    required String filePath,
    required String fileName,
    required String ext,
    required String prompt,
  }) async {
    final bytes = await File(filePath).readAsBytes();
    final b64 = base64Encode(bytes);
    final lower = ext.toLowerCase();
    // 画像系も Gemini の inline_data でそのまま投げられる。
    // (Claude も documents/images の content type で受けられるが、ここでは
    //  Gemini に統一しておく方が docx/pptx と扱いを揃えられて単純)
    String mimeFor(String e) {
      switch (e) {
        case 'pdf':
          return 'application/pdf';
        case 'docx':
          return 'application/vnd.openxmlformats-officedocument.wordprocessingml.document';
        case 'pptx':
          return 'application/vnd.openxmlformats-officedocument.presentationml.presentation';
        case 'jpg':
        case 'jpeg':
          return 'image/jpeg';
        case 'png':
          return 'image/png';
        case 'gif':
          return 'image/gif';
        case 'webp':
          return 'image/webp';
        case 'heic':
          return 'image/heic';
        case 'heif':
          return 'image/heif';
        default:
          return 'application/octet-stream';
      }
    }

    final mime = mimeFor(lower);
    final isImage = mime.startsWith('image/');

    final effectivePrompt = languageInstructionForAi() + prompt;

    // どの AI プロバイダーを使うか決定 (現状の設定 → ファイル対応外なら Gemini)
    String useProvider = _aiProvider;
    if (useProvider == 'openai') useProvider = 'gemini';

    if (useProvider == 'anthropic') {
      if (!hasAnthropicKey) {
        throw Exception('Claude APIキーが設定されていません');
      }
      // Claude Messages API: documents 対応 (PDF のみネイティブ)
      // Claude Messages API: PDF は documents で送信、画像は image type で送信。
      // docx/pptx は base64 のままだと処理できないため Gemini にフォールバック。
      if (lower != 'pdf' && !isImage) {
        useProvider = 'gemini';
      } else {
        final contentBlock = isImage
            ? <String, dynamic>{
                'type': 'image',
                'source': {
                  'type': 'base64',
                  'media_type': mime,
                  'data': b64,
                },
              }
            : <String, dynamic>{
                'type': 'document',
                'source': {
                  'type': 'base64',
                  'media_type': mime,
                  'data': b64,
                },
              };
        final res = await http
            .post(
              Uri.parse('https://api.anthropic.com/v1/messages'),
              headers: {
                'Content-Type': 'application/json',
                'x-api-key': _anthropicApiKey!,
                'anthropic-version': '2023-06-01',
              },
              body: jsonEncode({
                'model': _anthropicModel,
                'max_tokens': 4096,
                'messages': [
                  {
                    'role': 'user',
                    'content': [
                      contentBlock,
                      {'type': 'text', 'text': effectivePrompt},
                    ],
                  },
                ],
              }),
            )
            .timeout(const Duration(seconds: 120));
        if (res.statusCode != 200) {
          throw Exception('Claude API エラー: ${res.statusCode} ${res.body}');
        }
        final data =
            jsonDecode(utf8.decode(res.bodyBytes)) as Map<String, dynamic>;
        final content = (data['content'] as List?) ?? const [];
        final buf = StringBuffer();
        for (final c in content) {
          if (c is Map && c['type'] == 'text') {
            buf.write(c['text']);
          }
        }
        return buf.toString();
      }
    }

    if (useProvider == 'gemini') {
      if (!hasGeminiKey) {
        throw Exception('Gemini APIキーが設定されていません');
      }
      // Gemini API: inline_data で各種 mime に対応 (PDF, docx, pptx 含む)
      final model = _geminiModels.first;
      final url =
          'https://generativelanguage.googleapis.com/v1beta/models/$model:generateContent?key=$_geminiApiKey';
      final res = await http
          .post(
            Uri.parse(url),
            headers: {'Content-Type': 'application/json'},
            body: jsonEncode({
              'contents': [
                {
                  'parts': [
                    {
                      'inline_data': {
                        'mime_type': mime,
                        'data': b64,
                      },
                    },
                    {'text': effectivePrompt},
                  ],
                },
              ],
              'generationConfig': {
                'temperature': 0.4,
                'maxOutputTokens': 8192,
              },
            }),
          )
          .timeout(const Duration(seconds: 180));
      if (res.statusCode != 200) {
        throw Exception('Gemini API エラー: ${res.statusCode} ${res.body}');
      }
      final data =
          jsonDecode(utf8.decode(res.bodyBytes)) as Map<String, dynamic>;
      final candidates = data['candidates'] as List?;
      if (candidates == null || candidates.isEmpty) {
        throw Exception('Gemini API: レスポンスが空でした');
      }
      final parts =
          ((candidates.first as Map)['content'] as Map?)?['parts'] as List?;
      final buf = StringBuffer();
      for (final part in parts ?? const []) {
        if (part is Map && part['text'] != null) {
          buf.write(part['text']);
        }
      }
      return buf.toString();
    }

    throw Exception('利用可能な AI プロバイダーがありません');
  }

  /// AI 出力テキストから JSON 構造を抽出する。
  /// AI 出力から JSON オブジェクトを取り出す。
  ///
  /// AI は以下のような形式で返してくることがあるので、それぞれに対応する:
  ///   - ` ```json ... ``` ` でラップ
  ///   - JSON の前に「以下が結果です:」のような前置き
  ///   - JSON の後に「以上です」のような後置き
  ///   - 末尾カンマ等の軽微な構文崩れ
  ///   - 文字列内に `{` や `}` を含む (Japanese などで括弧が出る)
  ///   - **トークン上限で途中で切れた JSON** (閉じ括弧が足りない)
  ///   - 全角カンマ・コロン・引用符が混入
  ///
  /// 旧実装は「最初の `{` 〜 最後の `}` を切り出して jsonDecode」だけだった
  /// ため、説明文に `}` が含まれると JSON が壊れて `null` を返していた。
  /// 新実装は次の段階を踏んで成功率を上げる:
  ///   1) ``` フェンスを剥がす
  ///   2) 全体をそのまま jsonDecode
  ///   3) 最初の `{` から **文字列を考慮した括弧バランス** で対応する `}` を
  ///      探して切り出し、parse を試みる
  ///   4) 失敗したら末尾カンマを掃除して再試行
  ///   5) それでも失敗したら、その位置の次から同じ手順で別の JSON を探す
  ///   6) **どこも閉じる `}` が見つからなかった場合 (= 途中で切れた)**:
  ///      最後の `{` から walk して足りない `}` `]` を補って強制的に閉じてみる
  Map<String, dynamic>? _extractJsonStructure(String text) {
    if (text.isEmpty) return null;

    // (1) 先頭/末尾の空白とフェンスを除去。フェンス内に複数あった場合は
    //     最初の 1 つだけ取り出す (実用上問題ない)。
    String s = text.trim();
    final fenceMatch =
        RegExp(r'```(?:json|JSON)?[\s\r\n]*([\s\S]*?)[\s\r\n]*```')
            .firstMatch(s);
    if (fenceMatch != null && (fenceMatch.group(1) ?? '').isNotEmpty) {
      s = fenceMatch.group(1)!.trim();
    }

    // (2) そのまま全体を parse できればそれが最速
    final whole = _tryParseJsonMap(s);
    if (whole != null) return whole;

    // (3) 最初の `{` から括弧バランスで末尾を探す。
    //     文字列リテラル "..." 内の `{` `}` は無視する。
    int searchStart = 0;
    while (true) {
      final firstOpen = s.indexOf('{', searchStart);
      if (firstOpen < 0) break;
      int depth = 0;
      bool inStr = false;
      bool escape = false;
      int? endIdx;
      for (int i = firstOpen; i < s.length; i++) {
        final c = s[i];
        if (escape) {
          escape = false;
          continue;
        }
        if (inStr) {
          if (c == '\\') {
            escape = true;
            continue;
          }
          if (c == '"') inStr = false;
          continue;
        }
        if (c == '"') {
          inStr = true;
          continue;
        }
        if (c == '{') {
          depth++;
        } else if (c == '}') {
          depth--;
          if (depth == 0) {
            endIdx = i;
            break;
          }
        }
      }
      if (endIdx == null) break; // 閉じる括弧が見つからない → (6) の救済へ

      final candidate = s.substring(firstOpen, endIdx + 1);
      final r1 = _tryParseJsonMap(candidate);
      if (r1 != null) return r1;

      // (4) 末尾カンマ救済 (例: "...,}")
      final cleaned = candidate.replaceAllMapped(
          RegExp(r',(\s*[}\]])'), (m) => m.group(1)!);
      final r2 = _tryParseJsonMap(cleaned);
      if (r2 != null) return r2;

      // (5) この `{` で見つかった範囲では parse できなかった
      //     → さらに先に別の JSON 候補があるか探す
      searchStart = endIdx + 1;
    }

    // (6) ── 閉じ括弧が足りない (途中で切れた) ケースの救済 ──
    // トークン上限で出力が途切れた時に発生。最後の `{` まで戻って walk し直し、
    // 「未閉じの `[`/`{` の数だけ閉じ括弧を末尾に足す」「文字列の途中なら
    //   `"` で閉じる」を試す。
    final firstOpenForFix = s.indexOf('{');
    if (firstOpenForFix >= 0) {
      final tail = s.substring(firstOpenForFix);
      final fixed = _attemptCloseTruncatedJson(tail);
      if (fixed != null) {
        // 閉じた候補を末尾カンマ掃除と組み合わせて再 parse 試行
        final r3 = _tryParseJsonMap(fixed);
        if (r3 != null) return r3;
        final cleaned3 =
            fixed.replaceAllMapped(RegExp(r',(\s*[}\]])'), (m) => m.group(1)!);
        final r4 = _tryParseJsonMap(cleaned3);
        if (r4 != null) return r4;
      }
    }

    return null;
  }

  /// 途中で切れた JSON を強制的に閉じる。
  ///
  /// 入力テキストを文字列を考慮しながら walk し、終端時点での
  /// (a) 文字列の途中なら `"` を補う
  /// (b) 開いている `[` `{` の数だけ末尾カンマを掃除して `]` `}` を補う
  /// (c) 末尾の不完全なキー/値 (": null まで打って終わってる等) も穴埋め
  ///
  /// 100% の success ではないが、長い JSON が途中で切れたパターンの大半を
  /// 救える。
  String? _attemptCloseTruncatedJson(String s) {
    if (s.isEmpty || s[0] != '{') return null;
    final stack = <String>[]; // '{' or '['
    bool inStr = false;
    bool escape = false;
    for (int i = 0; i < s.length; i++) {
      final c = s[i];
      if (escape) {
        escape = false;
        continue;
      }
      if (inStr) {
        if (c == '\\') {
          escape = true;
          continue;
        }
        if (c == '"') inStr = false;
        continue;
      }
      if (c == '"') {
        inStr = true;
        continue;
      }
      if (c == '{' || c == '[') {
        stack.add(c);
      } else if (c == '}') {
        if (stack.isNotEmpty && stack.last == '{') stack.removeLast();
      } else if (c == ']') {
        if (stack.isNotEmpty && stack.last == '[') stack.removeLast();
      }
    }

    final buf = StringBuffer(s);
    if (inStr) {
      // 文字列の途中で切れている → `"` で閉じる
      buf.write('"');
    }
    // 末尾の不完全カンマや空属性は除去するため、文字列化してから後処理
    String partial = buf.toString();
    // ": <途中まで> のような形になっている可能性: 直前トークンが
    //   - キーだけ ("foo") → null を割り当てる
    //   - キー + : ("foo":) → null を割り当てる
    // を雑に救済する
    final trimmed = partial.trimRight();
    final lastNonWs = trimmed.isNotEmpty ? trimmed[trimmed.length - 1] : '';
    if (lastNonWs == ':') {
      partial = '${trimmed}null';
    } else if (lastNonWs == ',') {
      partial = trimmed.substring(0, trimmed.length - 1);
    }

    // 開いているスコープを順に閉じる。閉じる前に直前のカンマを掃除しておく。
    while (stack.isNotEmpty) {
      final tr = partial.trimRight();
      final lastCh = tr.isNotEmpty ? tr[tr.length - 1] : '';
      if (lastCh == ',') {
        partial = tr.substring(0, tr.length - 1);
      }
      final open = stack.removeLast();
      final closer = open == '{' ? '}' : ']';
      partial = partial + closer;
    }
    return partial;
  }

  /// jsonDecode して Map<String, dynamic> なら返す。失敗/型違いなら null。
  Map<String, dynamic>? _tryParseJsonMap(String s) {
    try {
      final p = jsonDecode(s);
      if (p is Map<String, dynamic>) return p;
      // jsonDecode は実装によって Map<dynamic, dynamic> を返すこともある
      if (p is Map) return p.map((k, v) => MapEntry(k.toString(), v));
    } catch (_) {}
    return null;
  }

  /// 階層的な AI 要約構造を新規ページのノードに変換して配置する再帰関数。
  ///
  /// 配置方針:
  /// - 親ノードから右側にツリー状に展開
  /// - **各子のサブツリーが必要とする縦方向のスペースを事前計算してから配置**
  ///   することで、同じ列のノードはもちろん、孫世代も他の枝と重ならない。
  ///   (旧実装は固定 120px 間隔だったため、孫が多い枝と少ない枝が混ざると
  ///    隣の枝の孫と重なって読めなくなっていた)
  /// - 色は **兄弟順** に変える (同じ親の下にある複数の子は別の色)。階層を
  ///   またいでも同じ色の繰り返しにならないよう depth でオフセットを足す。
  ///
  /// [parentSlotCenterY] は呼び出し側の再帰で「親が割り当てられた縦スロットの
  /// 中心」を渡すための任意引数。null の場合は parent.position から計算する
  /// (= ルート直下の最初の呼び出し)。
  void _placeAiSummaryChildren({
    required MindMapNode parent,
    required List<dynamic> childrenJson,
    required int depth,
    required int siblingsCount,
    double? parentSlotCenterY,
    // 親ノードの色 index (palette 内のインデックス)。子の色をここから
    // 相対的にずらして決めることで、孫ノードが親グループごとに違う色に
    // なる。ルートからの初回呼び出しは 0 (palette[0] = 水色) を起点にする。
    int parentColorIdx = 0,
  }) {
    if (childrenJson.isEmpty) return;

    // 兄弟順に色を変えるパレット。depth でオフセットを足して、階層をまたいでも
    // 同じ色が縦に並ばないようにする。
    // ユーザー要望（要約マップが「緑/オレンジ/紫」の3色固定で見える問題）対応:
    // 兄弟インデックス i を そのまま使うと、i=0,1,2 のとき必ず連続3色
    // (palette[d], palette[d+1], palette[d+2]) になり、見た目が単調になる。
    // パレット長 8 と互いに素な係数 3 を掛けることで、兄弟3つでも
    // palette[d], palette[d+3], palette[d+6] のように離れた色になり、
    // 8兄弟すべて違う色になるように回る (coprime 巡回)。
    const palette = <Color>[
      Color(0xFF4FC3F7), // 水色
      Color(0xFF43B97F), // 緑
      Color(0xFFFFB347), // オレンジ
      Color(0xFFBA68C8), // 紫ピンク
      Color(0xFFFF6B6B), // 赤
      Color(0xFF26C6DA), // 青緑
      Color(0xFFFFD54F), // 黄
      Color(0xFF9CCC65), // 黄緑
    ];

    const double horizontalGap = 280.0;
    // 兄弟サブツリー間の最低空きスペース。小さすぎると窮屈、大きすぎるとマップが
    // 縦方向に伸びて見渡しづらくなるので 40 で固定。
    const double minVerticalGap = 40.0;

    // ── 各子サブツリーの必要高さを事前計算 ──
    // 高さは「自分のノード高さ」と「孫サブツリー群の合計高さ」の大きい方。
    // この値で兄弟同士の縦スロットを割り当てるので、どの子の枝が大きくても
    // 隣に押し出されて重ならない。
    final subtreeHeights = <double>[];
    for (final c in childrenJson) {
      if (c is! Map) {
        subtreeHeights.add(0.0);
      } else {
        subtreeHeights.add(_computeAiSubtreeHeight(c, minVerticalGap));
      }
    }

    // 兄弟全体を縦に並べた合計高さ (空要素はスキップ)
    double totalH = 0;
    bool first = true;
    for (int i = 0; i < subtreeHeights.length; i++) {
      if (subtreeHeights[i] <= 0) continue;
      if (!first) totalH += minVerticalGap;
      totalH += subtreeHeights[i];
      first = false;
    }

    // 親が「与えられたスロット中心」(または自分のノード中心) を中心に
    // 子群を上下対称に配置する。
    final centerY =
        parentSlotCenterY ?? (parent.position.dy + parent.height / 2);
    double currentY = centerY - totalH / 2;
    bool firstPlaced = true;

    for (int i = 0; i < childrenJson.length; i++) {
      final raw = childrenJson[i];
      if (raw is! Map) continue;
      final title = (raw['title'] as String?)?.trim() ?? '';
      if (title.isEmpty) continue;
      final memo = (raw['memo'] as String?)?.trim();
      final grandChildren = (raw['children'] as List<dynamic>?) ?? const [];

      if (!firstPlaced) currentY += minVerticalGap;
      firstPlaced = false;

      final subH = subtreeHeights[i];
      // ── ノード幅・高さの計算 ──
      // 重要: NodeWidget は `bodyH = node.height + memoExtraH` で描画する。
      // つまり node.height は「タイトル領域だけ」を指し、メモ分は自動的に
      // 下に伸ばされる。height にメモ分も足すと二重に余白が確保され、
      // ノードに大きな空白が残る (ユーザー報告のメモ欄余白問題の原因)。
      // → height は 50.0 固定。レイアウトの縦スロット計算用に「実表示高さ」
      //   displayH を別に出して subH と比較する。
      final w = (title.length * 14.0 + 40).clamp(180.0, 340.0);
      const double h = 50.0;
      double displayH = h;
      if (memo != null && memo.isNotEmpty) {
        // NodeWidget と同じ式: lineCount = len / (w / memoFontSize * 1.2)
        const memoFontSize = 11.0; // defaultMemoFontSize 想定
        final lineCount =
            (memo.length / (w / memoFontSize * 1.2)).ceil().clamp(1, 20);
        displayH += lineCount * (memoFontSize + 3);
      }

      // 子のスロット中心 (孫もこの中心に合わせて再帰配置される)
      final childSlotCenter = currentY + subH / 2;

      // 子ノード自身は親の右側にあり、自分のスロット中心に縦中心 (= 表示高ベース) を置く
      final childPos = Offset(
        parent.position.dx + parent.width + horizontalGap,
        childSlotCenter - displayH / 2,
      );

      // 兄弟順 + 親色を起点に色を選ぶ。
      // 旧実装 `palette[(i * 3 + depth) % len]` は depth しか考慮せず、
      // どの親の子であろうと孫の i=0,1,2 が必ず同じ 3 色になっていた
      // (ユーザー報告: 孫ノードがほぼ同じ色)。親の colorIdx を起点に
      // することで、各親グループの孫が散らばった色になる。
      // 係数 3 はパレット長 8 と互いに素なので、兄弟 8 つまで全色違い。
      final colorIdx = (parentColorIdx + i * 3 + 1) % palette.length;
      final color = palette[colorIdx];

      // 任意フィールド: youtube_url / link_url / image_url。
      // image_url は専用フィールドが無いので link_url 相当にフォールバック。
      // contentType は youtube > link > memo > none の優先で決める。
      final ytUrl = _validatedHttpUrl(raw['youtube_url']);
      final linkUrl = _validatedHttpUrl(raw['link_url']) ??
          _validatedHttpUrl(raw['image_url']);
      NodeContentType ct = NodeContentType.none;
      if (ytUrl != null) {
        ct = NodeContentType.youtube;
      } else if (linkUrl != null) {
        ct = NodeContentType.link;
      } else if (memo != null && memo.isNotEmpty) {
        ct = NodeContentType.memo;
      }

      final child = MindMapNode(
        id: _uuid.v4(),
        title: title,
        memoText: memo,
        position: childPos,
        width: w.toDouble(),
        height: h,
        color: color,
        youtubeUrl: ytUrl,
        linkUrl: linkUrl,
        contentType: ct,
      );
      currentPage.nodes[child.id] = child;
      // 親 → 子 接続 (east → west)
      currentPage.connections.add(NodeConnection(
        fromId: parent.id,
        fromAnchor: AnchorDirection.east,
        toId: child.id,
        toAnchor: AnchorDirection.west,
      ));

      // 再帰で孫を配置 (childSlotCenter を渡して、孫もこの中心を基準に上下対称化)
      // colorIdx を parentColorIdx として伝えると、孫の色がこのノードの色を
      // 起点に散らされる (= 親グループごとに違う色相になる)。
      if (grandChildren.isNotEmpty) {
        _placeAiSummaryChildren(
          parent: child,
          childrenJson: grandChildren,
          depth: depth + 1,
          siblingsCount: grandChildren.length,
          parentSlotCenterY: childSlotCenter,
          parentColorIdx: colorIdx,
        );
      }

      // 次の兄弟スロットへ進む (gap は次ループ冒頭で加算)
      currentY += subH;
    }
  }

  /// AI 要約 JSON ノードのサブツリーが占める縦方向の高さを再帰計算する。
  /// = max(自ノードの高さ, 孫サブツリーの合計高さ + 孫間の隙間)
  ///
  /// `_placeAiSummaryChildren` で兄弟スロットを割り当てる前にこの値を取り、
  /// 兄弟同士が重ならないようにするために使う。
  double _computeAiSubtreeHeight(Map node, double minVerticalGap) {
    // 配置側 _placeAiSummaryChildren と同じ「実表示高さ」を見積もる。
    // NodeWidget は node.height + memoExtraH で描画するので、ここでも同じ式で。
    // ここがズレるとレイアウトが詰まる/間延びする。
    final memo = (node['memo'] as String?)?.trim();
    final title = (node['title'] as String?)?.trim() ?? '';
    final w = (title.length * 14.0 + 40).clamp(180.0, 340.0);
    double selfH = 50.0; // タイトル領域 (= node.height)
    if (memo != null && memo.isNotEmpty) {
      const memoFontSize = 11.0;
      final lineCount =
          (memo.length / (w / memoFontSize * 1.2)).ceil().clamp(1, 20);
      selfH += lineCount * (memoFontSize + 3);
    }
    final children = (node['children'] as List<dynamic>?) ?? const [];
    if (children.isEmpty) return selfH;

    double childrenH = 0;
    bool firstC = true;
    for (final c in children) {
      if (c is! Map) continue;
      if (!firstC) childrenH += minVerticalGap;
      childrenH += _computeAiSubtreeHeight(c, minVerticalGap);
      firstC = false;
    }
    return childrenH > selfH ? childrenH : selfH;
  }

  /// OpenAI Chat Completions API
  Future<String> askOpenAi(String prompt,
      {int retryCount = 0,
      bool jsonMode = false,
      int? maxTokensOverride}) async {
    if (!hasOpenaiKey) throw Exception('OpenAI APIキーが設定されていません');
    final effectivePrompt = languageInstructionForAi() + prompt;
    final model = _openaiModel;
    final isReasoning = model.startsWith('o'); // o4-mini 等は reasoning 系
    debugPrint('OpenAI リクエスト: model=$model, retry=$retryCount, '
        'lang=$_appLanguage, jsonMode=$jsonMode');

    // reasoning モデルは max_completion_tokens / temperature 制限あり
    final body = <String, dynamic>{
      'model': model,
      'messages': [
        {'role': 'user', 'content': effectivePrompt},
      ],
    };
    if (isReasoning) {
      body['max_completion_tokens'] = maxTokensOverride ?? 4096;
    } else {
      body['temperature'] = 0.7;
      body['max_tokens'] = maxTokensOverride ?? 2048;
    }
    // OpenAI Chat Completions の JSON mode。これを付けると応答が必ず
    // 有効な JSON オブジェクトになる (構造化出力でパース失敗を激減できる)。
    // ただしプロンプトに "JSON" の語が含まれている必要がある (OpenAI の要件)。
    if (jsonMode) {
      body['response_format'] = {'type': 'json_object'};
    }

    final http.Response res;
    try {
      res = await http
          .post(
            Uri.parse('https://api.openai.com/v1/chat/completions'),
            headers: {
              'Content-Type': 'application/json',
              'Authorization': 'Bearer $_openaiApiKey',
            },
            body: jsonEncode(body),
          )
          .timeout(Duration(seconds: isReasoning ? 120 : 60));
    } on TimeoutException {
      throw Exception('OpenAI API: 接続がタイムアウトしました。ネットワークを確認してください');
    }

    if (res.statusCode == 429) {
      if (retryCount < 3) {
        final wait = Duration(seconds: 3 + retryCount * 5);
        debugPrint(
            'OpenAI 429 → ${wait.inSeconds}秒後にリトライ (${retryCount + 1}/3)');
        await Future.delayed(wait);
        return askOpenAi(prompt,
            retryCount: retryCount + 1,
            jsonMode: jsonMode,
            maxTokensOverride: maxTokensOverride);
      }
      throw Exception('OpenAI API: レート制限に達しました');
    }
    if (res.statusCode == 401) {
      throw Exception('OpenAI API: APIキーが無効です');
    }
    if (res.statusCode == 404) {
      throw Exception('OpenAI API: モデル「$model」が見つかりません。設定でモデルを変更してください');
    }
    if (res.statusCode != 200) {
      debugPrint('OpenAI API エラー: ${res.statusCode} ${res.body}');
      String detail = '';
      try {
        final errData = jsonDecode(res.body) as Map<String, dynamic>;
        detail = errData['error']?['message'] as String? ?? '';
      } catch (_) {}
      if (res.statusCode >= 500 && retryCount < 2) {
        await Future.delayed(Duration(seconds: 2 + retryCount * 3));
        return askOpenAi(prompt,
            retryCount: retryCount + 1,
            jsonMode: jsonMode,
            maxTokensOverride: maxTokensOverride);
      }
      throw Exception(
          'OpenAI API エラー: ${res.statusCode}${detail.isEmpty ? '' : '\n$detail'}');
    }

    final data = jsonDecode(utf8.decode(res.bodyBytes)) as Map<String, dynamic>;
    final choices = data['choices'] as List<dynamic>?;
    if (choices == null || choices.isEmpty) {
      throw Exception('OpenAI: 回答がありません');
    }

    // 使用量記録
    final usage = data['usage'] as Map<String, dynamic>?;
    if (usage != null) {
      lastInputTokens = (usage['prompt_tokens'] as num?)?.toInt() ?? 0;
      lastOutputTokens = (usage['completion_tokens'] as num?)?.toInt() ?? 0;
      totalInputTokens += lastInputTokens;
      totalOutputTokens += lastOutputTokens;
      // コスト計算（概算）: $0.15/1M input, $0.60/1M output for gpt-4o-mini
      lastCostUsd =
          (lastInputTokens * 0.15 + lastOutputTokens * 0.60) / 1000000;
      totalCostUsd += lastCostUsd;
      _saveUsageTotals();
    }

    final msg = choices[0]['message'] as Map<String, dynamic>?;
    final content = msg?['content'] as String? ?? '';
    if (content.trim().isEmpty) {
      throw Exception('OpenAI: 空の応答が返されました');
    }
    return content.trim();
  }

  /// OpenAI 互換 Chat Completions API への共通リクエスト。
  /// Grok (x.ai) と DeepSeek はどちらも OpenAI 互換なので、 エンドポイント /
  /// API キー / モデルだけ差し替えて使う。
  Future<String> _askOpenAiCompatible({
    required String prompt,
    required String endpoint,
    required String apiKey,
    required String model,
    required String label,
    int retryCount = 0,
    bool jsonMode = false,
    int? maxTokensOverride,
  }) async {
    if (apiKey.isEmpty) throw Exception('$label APIキーが設定されていません');
    final effectivePrompt = languageInstructionForAi() + prompt;
    debugPrint('$label リクエスト: model=$model, retry=$retryCount, '
        'lang=$_appLanguage, jsonMode=$jsonMode');
    final body = <String, dynamic>{
      'model': model,
      'messages': [
        {'role': 'user', 'content': effectivePrompt},
      ],
      'temperature': 0.7,
      'max_tokens': maxTokensOverride ?? 2048,
    };
    if (jsonMode) {
      body['response_format'] = {'type': 'json_object'};
    }

    final http.Response res;
    try {
      res = await http
          .post(
            Uri.parse(endpoint),
            headers: {
              'Content-Type': 'application/json',
              'Authorization': 'Bearer $apiKey',
            },
            body: jsonEncode(body),
          )
          .timeout(const Duration(seconds: 90));
    } on TimeoutException {
      throw Exception('$label API: 接続がタイムアウトしました。ネットワークを確認してください');
    }

    if (res.statusCode == 429) {
      if (retryCount < 3) {
        await Future.delayed(Duration(seconds: 3 + retryCount * 5));
        return _askOpenAiCompatible(
            prompt: prompt,
            endpoint: endpoint,
            apiKey: apiKey,
            model: model,
            label: label,
            retryCount: retryCount + 1,
            jsonMode: jsonMode,
            maxTokensOverride: maxTokensOverride);
      }
      throw Exception('$label API: レート制限に達しました');
    }
    if (res.statusCode == 401) {
      throw Exception('$label API: APIキーが無効です');
    }
    if (res.statusCode == 404) {
      throw Exception('$label API: モデル「$model」が見つかりません。設定でモデル名を変更してください');
    }
    if (res.statusCode != 200) {
      debugPrint('$label API エラー: ${res.statusCode} ${res.body}');
      String detail = '';
      try {
        final errData = jsonDecode(res.body) as Map<String, dynamic>;
        detail = errData['error']?['message'] as String? ?? '';
      } catch (_) {}
      if (res.statusCode >= 500 && retryCount < 2) {
        await Future.delayed(Duration(seconds: 2 + retryCount * 3));
        return _askOpenAiCompatible(
            prompt: prompt,
            endpoint: endpoint,
            apiKey: apiKey,
            model: model,
            label: label,
            retryCount: retryCount + 1,
            jsonMode: jsonMode,
            maxTokensOverride: maxTokensOverride);
      }
      throw Exception(
          '$label API エラー: ${res.statusCode}${detail.isEmpty ? '' : '\n$detail'}');
    }

    final data = jsonDecode(utf8.decode(res.bodyBytes)) as Map<String, dynamic>;
    final choices = data['choices'] as List<dynamic>?;
    if (choices == null || choices.isEmpty) {
      throw Exception('$label: 回答がありません');
    }
    final usage = data['usage'] as Map<String, dynamic>?;
    if (usage != null) {
      lastInputTokens = (usage['prompt_tokens'] as num?)?.toInt() ?? 0;
      lastOutputTokens = (usage['completion_tokens'] as num?)?.toInt() ?? 0;
      totalInputTokens += lastInputTokens;
      totalOutputTokens += lastOutputTokens;
      _saveUsageTotals();
    }
    final msg = choices[0]['message'] as Map<String, dynamic>?;
    final content = msg?['content'] as String? ?? '';
    if (content.trim().isEmpty) {
      throw Exception('$label: 空の応答が返されました');
    }
    return content.trim();
  }

  /// Grok (x.ai) に質問。 OpenAI 互換エンドポイント。
  Future<String> askGrok(String prompt,
      {bool jsonMode = false, int? maxTokensOverride}) {
    return _askOpenAiCompatible(
      prompt: prompt,
      endpoint: 'https://api.x.ai/v1/chat/completions',
      apiKey: _grokApiKey ?? '',
      model: _grokModel,
      label: 'Grok',
      jsonMode: jsonMode,
      maxTokensOverride: maxTokensOverride,
    );
  }

  /// DeepSeek に質問。 OpenAI 互換エンドポイント。
  Future<String> askDeepseek(String prompt,
      {bool jsonMode = false, int? maxTokensOverride}) {
    return _askOpenAiCompatible(
      prompt: prompt,
      endpoint: 'https://api.deepseek.com/v1/chat/completions',
      apiKey: _deepseekApiKey ?? '',
      model: _deepseekModel,
      label: 'DeepSeek',
      jsonMode: jsonMode,
      maxTokensOverride: maxTokensOverride,
    );
  }

  /// [maxTokensOverride] が null でなければ max_tokens をそれで上書きする。
  /// (Claude には専用の "JSON mode" は無いが、出力を大きく取れば JSON が
  ///  途中で切れて parse 失敗する事故を抑えられる)
  Future<String> askClaude(String prompt,
      {int retryCount = 0, int? maxTokensOverride}) async {
    if (!hasAnthropicKey) throw Exception('Claude APIキーが設定されていません');
    final effectivePrompt = languageInstructionForAi() + prompt;
    final model = _anthropicModel;
    debugPrint(
        'Claude リクエスト: model=$model, retry=$retryCount, lang=$_appLanguage');

    final http.Response res;
    try {
      res = await http
          .post(
            Uri.parse('https://api.anthropic.com/v1/messages'),
            headers: {
              'Content-Type': 'application/json',
              'x-api-key': _anthropicApiKey ?? '',
              'anthropic-version': '2023-06-01',
            },
            body: jsonEncode({
              'model': model,
              'max_tokens': maxTokensOverride ?? 4096,
              'messages': [
                {'role': 'user', 'content': effectivePrompt},
              ],
            }),
          )
          .timeout(const Duration(seconds: 90));
    } on TimeoutException {
      throw Exception('Claude API: 接続がタイムアウトしました。ネットワークを確認してください');
    }

    if (res.statusCode == 429) {
      if (retryCount < 3) {
        final wait = Duration(seconds: 3 + retryCount * 5);
        debugPrint(
            'Claude 429 → ${wait.inSeconds}秒後にリトライ (${retryCount + 1}/3)');
        await Future.delayed(wait);
        return askClaude(prompt,
            retryCount: retryCount + 1, maxTokensOverride: maxTokensOverride);
      }
      throw Exception('Claude API: レート制限に達しました');
    }
    if (res.statusCode == 401) {
      throw Exception('Claude API: APIキーが無効です');
    }
    if (res.statusCode == 404) {
      throw Exception('Claude API: モデル「$model」が見つかりません。設定でモデルを変更してください');
    }
    if (res.statusCode != 200) {
      debugPrint('Claude API エラー: ${res.statusCode} ${res.body}');
      String detail = '';
      try {
        final errData = jsonDecode(res.body) as Map<String, dynamic>;
        detail = errData['error']?['message'] as String? ?? '';
      } catch (_) {}
      if (res.statusCode >= 500 && retryCount < 2) {
        await Future.delayed(Duration(seconds: 2 + retryCount * 3));
        return askClaude(prompt,
            retryCount: retryCount + 1, maxTokensOverride: maxTokensOverride);
      }
      throw Exception(
          'Claude API エラー: ${res.statusCode}${detail.isEmpty ? '' : '\n$detail'}');
    }

    final data = jsonDecode(utf8.decode(res.bodyBytes)) as Map<String, dynamic>;
    final contentList = data['content'] as List<dynamic>?;
    if (contentList == null || contentList.isEmpty) {
      throw Exception('Claude: 回答がありません');
    }

    // 使用量記録
    final usage = data['usage'] as Map<String, dynamic>?;
    if (usage != null) {
      lastInputTokens = (usage['input_tokens'] as num?)?.toInt() ?? 0;
      lastOutputTokens = (usage['output_tokens'] as num?)?.toInt() ?? 0;
      totalInputTokens += lastInputTokens;
      totalOutputTokens += lastOutputTokens;
      // コスト計算（概算、Haiku 4.5 基準）: $1.0/1M input, $5.0/1M output
      lastCostUsd = (lastInputTokens * 1.0 + lastOutputTokens * 5.0) / 1000000;
      totalCostUsd += lastCostUsd;
      _saveUsageTotals();
    }

    // content は [{type: 'text', text: '...'}, ...] のリスト
    final textParts = contentList
        .whereType<Map<String, dynamic>>()
        .where((c) => c['type'] == 'text')
        .map((c) => c['text'] as String? ?? '')
        .join('\n')
        .trim();
    if (textParts.isEmpty) {
      throw Exception('Claude: 空の応答が返されました');
    }
    return textParts;
  }

  /// Gemini API にプロンプトを送信してテキスト回答を取得
  ///
  /// [jsonMode] が true の場合、`responseMimeType: 'application/json'` を付けて
  /// JSON だけを返すよう Gemini 側に強制する。これは AI 要約や用語解説のように
  /// 構造化出力を期待する用途に使う。
  /// [maxTokensOverride] は出力トークンの上限を上書き。null なら従来通り
  /// (Pro=8192 / Flash=2048)。長い JSON が途中で切れて parse 失敗する事故を
  /// 避けるため、構造化出力では大きめに指定する。
  Future<String> askGemini(String prompt,
      {int retryCount = 0,
      int modelIndex = 0,
      bool jsonMode = false,
      int? maxTokensOverride}) async {
    if (!hasGeminiKey) throw Exception('Gemini APIキーが設定されていません');

    // 言語指示を先頭に付与（AI出力を appLanguage に合わせる）
    final effectivePrompt = languageInstructionForAi() + prompt;

    final models = _geminiModels;
    final model = modelIndex < models.length ? models[modelIndex] : models.last;
    final url = 'https://generativelanguage.googleapis.com/v1beta/models/'
        '$model:generateContent?key=$_geminiApiKey';

    debugPrint('Gemini API リクエスト: model=$model, tier=$aiModelTier, '
        'retry=$retryCount, lang=$_appLanguage, jsonMode=$jsonMode');

    // Pro(思考モデル)は maxOutputTokens を大きく取る
    final isProTier = aiModelTier == 'pro';
    final maxTokens = maxTokensOverride ?? (isProTier ? 8192 : 2048);

    // generationConfig: jsonMode の時は responseMimeType を付けて
    // 「JSON 以外の応答が返らない」モードに切り替える
    final generationConfig = <String, dynamic>{
      'temperature': 0.7,
      'maxOutputTokens': maxTokens,
    };
    if (jsonMode) {
      generationConfig['responseMimeType'] = 'application/json';
    }

    final http.Response res;
    try {
      res = await http
          .post(
            Uri.parse(url),
            headers: {'Content-Type': 'application/json'},
            body: jsonEncode({
              'contents': [
                {
                  'parts': [
                    {'text': effectivePrompt}
                  ]
                }
              ],
              'generationConfig': generationConfig,
            }),
          )
          .timeout(Duration(seconds: isProTier ? 120 : 30));
    } on TimeoutException {
      if (modelIndex + 1 < models.length) {
        debugPrint('Gemini タイムアウト ($model) → 次のモデルへフォールバック');
        return askGemini(prompt,
            retryCount: retryCount,
            modelIndex: modelIndex + 1,
            jsonMode: jsonMode,
            maxTokensOverride: maxTokensOverride);
      }
      throw Exception('Gemini API: 接続がタイムアウトしました。ネットワークを確認してください');
    }

    if (res.statusCode == 404) {
      debugPrint('Gemini 404 ($model) → 次のモデルへフォールバック');
      if (modelIndex + 1 < models.length) {
        return askGemini(prompt,
            retryCount: retryCount,
            modelIndex: modelIndex + 1,
            jsonMode: jsonMode,
            maxTokensOverride: maxTokensOverride);
      }
      throw Exception('Gemini API: 利用可能なモデルが見つかりません。APIキーを確認してください');
    }
    if (res.statusCode == 429) {
      if (retryCount < 3) {
        final wait = Duration(seconds: 3 + retryCount * 5);
        debugPrint(
            'Gemini 429 → ${wait.inSeconds}秒後にリトライ (${retryCount + 1}/3)');
        await Future.delayed(wait);
        return askGemini(prompt,
            retryCount: retryCount + 1,
            modelIndex: modelIndex,
            jsonMode: jsonMode,
            maxTokensOverride: maxTokensOverride);
      }
      throw Exception('APIのレート制限です。しばらく待ってから再試行してください');
    }
    if (res.statusCode == 403) {
      throw Exception(
          'Gemini API: APIキーが無効か、Generative Language APIが有効化されていません');
    }
    if (res.statusCode != 200) {
      debugPrint('Gemini API エラー: ${res.statusCode} ${res.body}');
      if (res.statusCode == 400) {
        String detail = '';
        try {
          final errData = jsonDecode(res.body) as Map<String, dynamic>;
          final errMsg = errData['error']?['message'] as String?;
          if (errMsg != null) detail = '\n詳細: $errMsg';
        } catch (_) {}
        throw Exception('Gemini API: リクエスト形式エラー (400)$detail');
      }
      if (res.statusCode >= 500 && retryCount < 2) {
        await Future.delayed(Duration(seconds: 2 + retryCount * 3));
        return askGemini(prompt,
            retryCount: retryCount + 1,
            modelIndex: modelIndex,
            jsonMode: jsonMode,
            maxTokensOverride: maxTokensOverride);
      }
      throw Exception('Gemini API エラー: ${res.statusCode}');
    }

    final data = jsonDecode(res.body) as Map<String, dynamic>;
    final candidates = data['candidates'] as List<dynamic>?;
    if (candidates == null || candidates.isEmpty) {
      throw Exception('Gemini: 回答がありません');
    }

    // ── 使用量を記録 ──
    final usage = data['usageMetadata'] as Map<String, dynamic>?;
    int inT = 0, outT = 0;
    if (usage != null) {
      inT = (usage['promptTokenCount'] as num?)?.toInt() ?? 0;
      outT = (usage['candidatesTokenCount'] as num?)?.toInt() ?? 0;
    } else {
      inT = (prompt.length * 0.5).round();
    }
    final cost = calcCostUsd(aiModelTier, inT, outT);
    lastInputTokens = inT;
    lastOutputTokens = outT;
    lastCostUsd = cost;
    totalInputTokens += inT;
    totalOutputTokens += outT;
    totalCostUsd += cost;
    _saveUsageTotals();

    // Pro版: finishReasonとcontentのnullチェック
    final firstCandidate = candidates[0] as Map<String, dynamic>?;
    if (firstCandidate == null) throw Exception('Gemini: 候補がありません');

    final finishReason = firstCandidate['finishReason'] as String?;
    if (finishReason == 'SAFETY') {
      throw Exception('Gemini: 安全フィルターにより応答がブロックされました。プロンプトを変更してください');
    }
    if (finishReason == 'RECITATION') {
      throw Exception('Gemini: 著作権保護のため応答がブロックされました');
    }

    final content = firstCandidate['content'] as Map<String, dynamic>?;
    if (content == null) {
      throw Exception('Gemini: 応答コンテンツがありません（finishReason: $finishReason）');
    }
    final parts = content['parts'] as List<dynamic>?;
    if (parts == null || parts.isEmpty) {
      if (finishReason == 'MAX_TOKENS') {
        throw Exception('Gemini Pro: トークン上限に達しました。Flash モデルをお試しください');
      }
      throw Exception('Gemini: 回答がありません (finishReason: $finishReason)');
    }

    // 思考ログ (thought: true) を除外
    final answerParts = parts.where((p) {
      final map = p as Map<String, dynamic>;
      return (map['thought'] as bool? ?? false) == false;
    }).toList();

    final answer = answerParts
        .map((p) => (p as Map<String, dynamic>)['text'] as String? ?? '')
        .join('\n')
        .trim();

    if (answer.isEmpty) {
      if (aiModelTier == 'pro' && modelIndex == 0) {
        debugPrint('Gemini Pro: 回答が空 → Flash にフォールバック');
        final savedTier = aiModelTier;
        aiModelTier = 'flash';
        try {
          return await askGemini(prompt, retryCount: 0, modelIndex: 0);
        } finally {
          aiModelTier = savedTier;
        }
      }
      throw Exception(
          'Gemini Pro: 思考トークンが枯渇し回答を生成できませんでした。\nFlash モデルに切り替えてください');
    }
    return answer;
  }

  /// ノードに紐づく添付画像/ファイルを考慮して AI に問い合わせる共通ヘルパ。
  ///
  /// 動作:
  ///  - ノードに `attachmentPath` があり、かつ実ファイルが存在する場合は
  ///    `_askAiWithBinaryDoc` (画像/PDF/docx/pptx をバイナリのまま AI に
  ///    送り込める経路) を使い、AI が中身を見た上で答えるようにする。
  ///  - ない場合は単純に [askAi] を呼ぶ (従来どおり)。
  ///
  /// [prompt] には「対象ノードの題材文 + ユーザーの質問」を全て埋め込んだ
  /// 完成済みの本文を渡す。添付ファイルの説明 (「対象ノードには画像が添付
  /// されています…」のような前置き) はこのヘルパが自動で付与する。
  Future<String> _askAiAboutNode(MindMapNode node, String prompt) async {
    final ap = node.attachmentPath;
    if (ap == null || ap.isEmpty) {
      return askAi(prompt);
    }
    // 拡張子で対応可否を判定
    final dotIdx = ap.lastIndexOf('.');
    if (dotIdx < 0) return askAi(prompt);
    final ext = ap.substring(dotIdx + 1).toLowerCase();
    const supported = <String>{
      'pdf',
      'docx',
      'pptx',
      'jpg',
      'jpeg',
      'png',
      'gif',
      'webp',
      'heic',
      'heif',
    };
    if (!supported.contains(ext)) {
      return askAi(prompt);
    }
    // ファイル実在確認 (パスが残っていてもファイルが消えているケースに備える)
    try {
      final f = File(ap);
      if (!await f.exists()) {
        debugPrint('AI: 添付ファイルが見つからない (${ap}) → 添付なしで問い合わせ');
        return askAi(prompt);
      }
    } catch (_) {
      return askAi(prompt);
    }
    // 添付がある旨を AI に明示するための前置きを付ける。
    // 画像かドキュメントかでメッセージを変えると AI が回答方針を立てやすい。
    final isImage = const {'jpg', 'jpeg', 'png', 'gif', 'webp', 'heic', 'heif'}
        .contains(ext);
    final fileName = node.attachmentName ?? ap.split(RegExp(r'[/\\]')).last;
    // 旧バージョンは "画像の内容も踏まえて回答してください" とだけ書いていたが、
    // それだと AI が画像を「説明する」モードに入ってしまい、ユーザーが
    // 「1+1 の画像を貼って答えを 2 と返してほしい」と思っているのに
    // "丸い角のボタンが描かれています…" と書き出すケースが発生した。
    //
    // 解決策: 添付物に問題/質問/課題が書かれている時は「直接解いて答えを
    // 返す」ことを最優先指示として明示する。具体例 (1+1→2 / 英文→訳 /
    // コード→修正版) を出して挙動を強制する。
    final attachmentHint = isImage
        ? '【最重要指示】このノードには画像が添付されています。\n'
            '・画像内に問題・課題・数式・質問・指示が書かれている場合は、'
            '画像を「説明」せず、その問題を直接解いて答えだけを返してください。\n'
            '  例) 画像が「1+1」→ 答えは「2」 / '
            '画像が英文の問題 → その訳と解答 / '
            '画像がコードのバグ → 修正したコード\n'
            '・画像が単に図解・参考資料・グラフの場合のみ、'
            'その情報を踏まえて以下の指示に答えてください。\n\n'
        : '【最重要指示】このノードにはファイル「$fileName」が添付されています。\n'
            '・ファイル内に問題・課題・質問・指示が書かれている場合は、'
            'ファイルを「説明」せず、その問題を直接解いて答えだけを返してください。\n'
            '・ファイルが単に参考資料の場合のみ、'
            'その情報を踏まえて以下の指示に答えてください。\n\n';
    try {
      return await _askAiWithBinaryDoc(
        filePath: ap,
        fileName: fileName,
        ext: ext,
        prompt: attachmentHint + prompt,
      );
    } catch (e) {
      // 添付経路で失敗したらテキストのみで再試行 (添付が原因でユーザーが
      // 何の回答も得られないのは避けたい)
      debugPrint('AI: 添付付き問い合わせ失敗 → テキストのみで再試行: $e');
      return askAi(prompt);
    }
  }

  /// AI: ノードに説明文を追加（同一ノードのメモとして展開）
  Future<void> aiExplainNode(String nodeId) async {
    final node = currentPage.nodes[nodeId];
    if (node == null) return;
    _beginAi();
    try {
      final raw = await _askAiAboutNode(
          node,
          '「${node.title}」について3〜5文で簡潔に説明してください。\n'
          '【重要】\n'
          '・「はい」「承知しました」「もちろん」などの冒頭の挨拶は一切不要です\n'
          '・説明文だけを直接書いてください\n'
          '・各文は句点（。）で終わらせてください\n'
          '・改行は文の区切り（句点の直後）だけに入れてください');
      if (_aiCancelled) return; // キャンセル済み → 結果を反映しない
      // 文末（。）で改行を整える
      final answer = _formatExplanationText(raw);
      _pushUndo();
      // 幅を 300 (自動拡張の上限) に広げてメモとして展開
      currentPage.nodes[nodeId] = node.copyWith(
        memoText: answer,
        contentType: NodeContentType.memo,
        width: 300.0,
      );
      _saveToStorage();
      notifyListeners();
    } finally {
      _endAi();
    }
  }

  /// 説明文を句点ごとに改行して読みやすく整形
  static String _formatExplanationText(String raw) {
    // 連続空白・余計な改行を除去
    var text = raw
        .replaceAll(RegExp(r'[ \t]+'), ' ')
        .replaceAll(RegExp(r'\n{2,}'), '\n')
        .trim();
    // 句点の直後に改行を挿入（すでに改行がある場合は重複しない）
    text = text.replaceAllMapped(
      RegExp(r'。(?!\n)'),
      (m) => '。\n',
    );
    // 最後の余分な改行を除去
    return text.trimRight();
  }

  /// AI: タイトルから子ノードを複数作成（設定に基づく深さ・数）
  Future<void> aiGenerateChildren(String nodeId) async {
    final node = currentPage.nodes[nodeId];
    if (node == null) return;
    _beginAi();
    try {
      final cMin = aiChildMin.clamp(1, 50);
      final cMax = aiChildMax.clamp(cMin, 50);

      final answer = await _askAiAboutNode(
          node,
          '「${node.title}」を構成する具体的な要素・項目・対象を$cMin〜$cMax個列挙してください。\n'
          '\n'
          '【ルール】\n'
          '- 抽象的な分類名（例: "歴史", "種類", "特徴"）ではなく、具体的な固有名詞・実例・アイテム名を出すこと\n'
          '- 例: 「日本の城」→「姫路城」「松本城」「熊本城」（×「天守閣の構造」「立地」）\n'
          '- 例: 「Flutterパッケージ」→「provider」「riverpod」「dio」（×「状態管理」「HTTP通信」）\n'
          '- 例: 「JavaScriptフレームワーク」→「React」「Vue」「Svelte」「Angular」\n'
          '- 各項目は20文字以内\n'
          '- 1行ずつ箇条書き、先頭の記号や番号は付けない\n'
          '- 説明や補足は一切不要、項目名だけ\n'
          '- 重複や類似項目は避け、可能な限り多様性を持たせる');
      if (_aiCancelled) return; // キャンセル済み → ノードを作らずに終了
      final lines = answer
          .split('\n')
          .map((l) => l.replaceAll(RegExp(r'^[\-\*・●▶\d.、\s]+'), '').trim())
          .where((l) => l.isNotEmpty && l.length < 40)
          .toList();
      if (lines.isEmpty) return;

      // 子ノードの仮データを作成
      final childTempNodes = <MindMapNode>[];
      for (final title in lines) {
        childTempNodes.add(MindMapNode(
          id: _uuid.v4(),
          title: title,
          position: Offset.zero,
          color: _childColor(),
        ));
      }

      // ── 孫ノード生成が必要な場合は先にすべてのタイトルを取得 ──
      // childIndex → 孫ノード仮データリスト
      final Map<int, List<MindMapNode>> grandchildMap = {};
      if (aiDepth >= 2) {
        final gMin = aiGrandchildMin.clamp(1, 50);
        final gMax = aiGrandchildMax.clamp(gMin, 50);
        for (int i = 0; i < childTempNodes.length; i++) {
          try {
            final gcAnswer = await askAi(
                '「${childTempNodes[i].title}」を構成する具体的な要素・項目・対象を$gMin〜$gMax個列挙してください。\n'
                '\n'
                '【ルール】\n'
                '- 抽象的な分類名ではなく、具体的な固有名詞・実例・アイテム名を出すこと\n'
                '- 各項目は20文字以内\n'
                '- 1行ずつ箇条書き、先頭の記号や番号は付けない\n'
                '- 説明や補足は一切不要、項目名だけ\n'
                '- 重複や類似項目は避け、可能な限り多様性を持たせる');
            if (_aiCancelled) return; // キャンセル済み → 以降のノード生成をスキップ
            final gcLines = gcAnswer
                .split('\n')
                .map((l) =>
                    l.replaceAll(RegExp(r'^[\-\*・●▶\d.、\s]+'), '').trim())
                .where((l) => l.isNotEmpty && l.length < 40)
                .toList();
            if (gcLines.isNotEmpty) {
              grandchildMap[i] = gcLines
                  .map((t) => MindMapNode(
                        id: _uuid.v4(),
                        title: t,
                        position: Offset.zero,
                        color: _childColor(),
                      ))
                  .toList();
            }
          } catch (e) {
            debugPrint('孫ノード取得エラー (${childTempNodes[i].title}): $e');
          }
        }
      }

      // ── 各子ノードに必要な縦スペースを計算（子自身 vs 孫グループ） ──
      const gap = 16.0;
      final slotHeights = <double>[]; // 子ノードごとの占有高さ
      for (int i = 0; i < childTempNodes.length; i++) {
        final childH = childTempNodes[i].visualHeight;
        final gcNodes = grandchildMap[i];
        if (gcNodes != null && gcNodes.isNotEmpty) {
          double gcTotalH = 0;
          for (final gc in gcNodes) {
            gcTotalH += gc.visualHeight;
          }
          gcTotalH += gap * (gcNodes.length - 1);
          // この子ノードが占有するスロット = 子自身か孫グループの大きい方
          slotHeights.add(gcTotalH > childH ? gcTotalH : childH);
        } else {
          slotHeights.add(childH);
        }
      }

      // 全スロットの合計高さ
      double totalH = 0;
      for (final h in slotHeights) {
        totalH += h;
      }
      totalH += gap * (slotHeights.length - 1);

      // ── 配置 ──
      _pushUndo();
      final childX = node.position.dx + node.width + 80;
      final parentCenterY = node.position.dy + node.visualHeight / 2;
      double slotY = (parentCenterY - totalH / 2).clamp(0.0, 20000.0);
      // 親がグループ所属なら、生成した子孫も同じグループに入れる
      final List<String> newDescendantIds = [];

      for (int i = 0; i < childTempNodes.length; i++) {
        final slotH = slotHeights[i];
        // 子ノードはスロットの縦中央に配置
        final childVH = childTempNodes[i].visualHeight;
        final childY = slotY + (slotH - childVH) / 2;
        final childPos = Offset(childX, childY.clamp(0.0, 20000.0));
        final child = childTempNodes[i].copyWith(position: childPos);
        currentPage.nodes[child.id] = child;
        newDescendantIds.add(child.id);
        currentPage.connections.add(NodeConnection(
          fromId: nodeId,
          fromAnchor: AnchorDirection.east,
          toId: child.id,
          toAnchor: AnchorDirection.west,
        ));

        // 孫ノードを配置（スロットの縦中央にグループ全体を配置）
        final gcNodes = grandchildMap[i];
        if (gcNodes != null && gcNodes.isNotEmpty) {
          double gcTotalH = 0;
          for (final gc in gcNodes) {
            gcTotalH += gc.visualHeight;
          }
          gcTotalH += gap * (gcNodes.length - 1);

          final gcX = childPos.dx + child.width + 80;
          final gcStartY = (slotY + (slotH - gcTotalH) / 2).clamp(0.0, 20000.0);
          double gcY = gcStartY;
          for (final gcTemp in gcNodes) {
            final gc = gcTemp.copyWith(position: Offset(gcX, gcY));
            currentPage.nodes[gc.id] = gc;
            newDescendantIds.add(gc.id);
            currentPage.connections.add(NodeConnection(
              fromId: child.id,
              fromAnchor: AnchorDirection.east,
              toId: gc.id,
              toAnchor: AnchorDirection.west,
            ));
            gcY += gc.visualHeight + gap;
          }
        }

        slotY += slotH + gap;
      }
      // 親のグループに子孫ノードも追加
      if (newDescendantIds.isNotEmpty) {
        addChildrenToParentGroups(nodeId, newDescendantIds);
      }
      _saveToStorage();
      notifyListeners();
    } finally {
      _endAi();
    }
  }

  /// AI: カスタムプロンプトの回答を子ノードとして追加
  Future<void> aiCustomPrompt(String nodeId, String userPrompt) async {
    final node = currentPage.nodes[nodeId];
    if (node == null) return;
    _beginAi();
    try {
      final ctx = '対象: 「${node.title}」\n\nユーザーの質問: $userPrompt\n\n'
          '【重要】「はい」「承知しました」「もちろん」などの冒頭の挨拶は不要です。'
          '回答だけを直接書いてください。';
      final answer = await _askAiAboutNode(node, ctx);
      if (_aiCancelled) return; // キャンセル済み → 結果を反映しない
      _pushUndo();
      // 同一ノードのメモとして追記（既存メモがあれば改行で連結）
      final existing = (node.memoText ?? '').trim();
      final newMemo =
          existing.isEmpty ? answer : '$existing\n\n【$userPrompt】\n$answer';
      currentPage.nodes[nodeId] = node.copyWith(
        memoText: newMemo,
        contentType: NodeContentType.memo,
      );
      _saveToStorage();
      notifyListeners();
    } finally {
      _endAi();
    }
  }

  /// 親ノードの真下に付箋ノードを置く位置を返す（重なり回避付き）
  Offset _findBelowPosition(MindMapNode parent, {double childWidth = 240.0}) {
    const gap = 16.0;
    // 親ノードの中央X、真下Y を基準に
    final baseX = parent.position.dx + (parent.width - childWidth) / 2;
    double baseY = parent.position.dy + parent.visualHeight + gap;

    // 既に真下に付箋があれば、さらに下にずらす
    for (final c in currentPage.connections) {
      if (c.fromId == parent.id && c.fromAnchor == AnchorDirection.south) {
        final existing = currentPage.nodes[c.toId];
        if (existing != null) {
          final bottom = existing.position.dy + existing.visualHeight + gap;
          if (bottom > baseY) baseY = bottom;
        }
      }
    }

    // 他ノードとの重なりを回避（最大10回）
    Offset candidate = Offset(baseX, baseY);
    for (int i = 0; i < 10; i++) {
      bool overlap = false;
      for (final n in currentPage.nodes.values) {
        if (n.id == parent.id) continue;
        if (_nodesOverlap(candidate, childWidth, 42.0, n, gap)) {
          overlap = true;
          candidate = Offset(candidate.dx,
              (n.position.dy + n.visualHeight + gap).clamp(0.0, 20000.0));
          break;
        }
      }
      if (!overlap) break;
    }
    return candidate;
  }

  /// 親ノードの右側に空きスペースを探して子ノードの位置を返す
  Offset _findChildPosition(MindMapNode parent,
      {double childWidth = 200.0, double childHeight = 42.0}) {
    const gap = 20.0;
    final baseX = parent.position.dx + parent.width + 80;
    double baseY = parent.position.dy;
    // 既存の子ノードの最下部を求める（visualHeightを考慮）
    for (final c in currentPage.connections) {
      if (c.fromId == parent.id) {
        final child = currentPage.nodes[c.toId];
        if (child != null) {
          final bottom = child.position.dy + child.visualHeight + gap;
          if (bottom > baseY) baseY = bottom;
        }
      }
    }
    // 他のノードとの重なりを回避
    Offset candidate = Offset(baseX, baseY);
    for (int i = 0; i < 30; i++) {
      bool overlap = false;
      for (final n in currentPage.nodes.values) {
        if (_nodesOverlap(candidate, childWidth, childHeight, n, gap)) {
          overlap = true;
          candidate = Offset(
              candidate.dx,
              (n.position.dy + n.visualHeight + gap)
                  .clamp(gap, 20000.0 - childHeight - gap));
          break;
        }
      }
      if (!overlap) break;
    }
    return candidate;
  }

