  /// 現在ページの装飾図形リスト (= 直線/矢印/長方形/楕円)。
  ///
  /// ユーザー要望「直線や矢印線、 長方形等の図形を挿入できるようにして」 への
  /// 対応で導入された [MapDecoration] を読み取り専用で公開。
  List<MapDecoration> get decorations =>
      List.unmodifiable(currentPage.decorations);
  String? get selectedNodeId => _selectedNodeId;
  MindMapNode? get selectedNode =>
      _selectedNodeId != null ? currentPage.nodes[_selectedNodeId] : null;

  // ── 装飾図形の操作メソッド ──
  // すべての変更で notifyListeners + currentPage.lastModifiedAt を更新して
  // UI 即時反映 + 永続化トリガー。 _saveToStorage は呼び出し側で適宜。

  /// 新規装飾を追加。 [id] は呼び出し側が一意な値を渡す (= timestamp 等)。
  void addMapDecoration(MapDecoration deco) {
    _pushUndo(); // Ctrl+Z で図形作成前に戻せるようにする
    currentPage.decorations.add(deco);
    currentPage.lastModifiedAt = DateTime.now();
    _saveToStorage();
    notifyListeners();
  }

  /// 装飾を ID で削除。
  void removeMapDecoration(String id) {
    _pushUndo();
    currentPage.decorations.removeWhere((d) => d.id == id);
    currentPage.lastModifiedAt = DateTime.now();
    _saveToStorage();
    notifyListeners();
  }

  /// 装飾の位置や形を更新 (= ドラッグ移動・端点移動・色/太さ/種類の変更など)。
  void updateMapDecoration(MapDecoration updated) {
    final idx = currentPage.decorations.indexWhere((d) => d.id == updated.id);
    if (idx < 0) return;
    _pushUndo();
    currentPage.decorations[idx] = updated;
    currentPage.lastModifiedAt = DateTime.now();
    _saveToStorage();
    notifyListeners();
  }

  // ── 装飾図形のハンドルドラッグ (移動 / リサイズ) ──
  // ドラッグ中は毎フレーム dragDecorationBy が呼ばれるため、 undo / save は
  // フレーム毎には行わない。 開始時に 1 度だけ undo スナップショットを積み
  // (beginDecorationDrag)、 終了時に 1 度だけ保存する (endDecorationDrag)。

  /// ハンドルドラッグ開始: 直前の状態を undo に積む (Ctrl+Z 1 回で戻せる)。
  void beginDecorationDrag() {
    _pushUndo();
  }

  /// ドラッグ中の差分適用 (start / end をデルタ分ずらす)。 save も undo もしない。
  void dragDecorationBy(String id,
      {Offset startDelta = Offset.zero, Offset endDelta = Offset.zero}) {
    final idx = currentPage.decorations.indexWhere((d) => d.id == id);
    if (idx < 0) return;
    final d = currentPage.decorations[idx];
    d.start = d.start + startDelta;
    d.end = d.end + endDelta;
    notifyListeners();
  }

  /// ハンドルドラッグ終了: 1 度だけ保存。
  void endDecorationDrag() {
    currentPage.lastModifiedAt = DateTime.now();
    _saveToStorage();
    notifyListeners();
  }

  /// 図形内テキストの位置 (正規化アンカー) をドラッグ中に更新。 save / undo はしない
  /// (= ドラッグ開始時 beginDecorationDrag、 終了時 endDecorationDrag でまとめる)。
  void dragDecorationTextAnchor(String id, double ax, double ay) {
    final idx = currentPage.decorations.indexWhere((d) => d.id == id);
    if (idx < 0) return;
    final d = currentPage.decorations[idx];
    d.textAnchorX = ax.clamp(0.0, 1.0);
    d.textAnchorY = ay.clamp(0.0, 1.0);
    notifyListeners();
  }

  MindMapProvider() {
    // ★ 最優先: 言語/初回起動/下部ボタンを確実に読んで initialLoadDone を
    //   完了させる (= ユーザー報告の再発防止: 言語ピッカーが出ない / 英語固定 /
    //   下部ボタンが空)。 他のロードがハングしても起動フローが進む。
    _loadEssentialUiState();
    _loadFromStorage().then((_) {
      // ロード完了後に最後に開いたページを復元
      // (= 起動時に前回作業していたマップが自動で開く)
      _restoreLastOpenedPage();
      _generateAllMissingThumbnails();
    }).catchError((Object e, StackTrace st) {
      // ★ 起動ハング対策: ロードが reject されても永久ローディングにしない。
      debugPrint('起動ロードチェーンでエラー (復旧): $e\n$st');
      if (_pages.isEmpty) {
        try {
          _addDefaultPage();
        } catch (_) {}
        _currentPageIndex = 0;
      }
      notifyListeners();
    });
    // ★ 最終安全網: 何らかの理由 (プラグイン応答なし等) で 8 秒経っても
    //   ページが 1 枚も無い＝ローディングのままなら、 強制的にデフォルトページを
    //   作って UI を出す。 これで「ずっと読み込み中」が物理的に起こり得なくなる。
    Future.delayed(const Duration(seconds: 8), () {
      if (_pages.isEmpty) {
        debugPrint('起動安全網: 8秒経過してもページ空 → デフォルトページを強制作成');
        try {
          _addDefaultPage();
        } catch (_) {}
        _currentPageIndex = 0;
        notifyListeners();
      }
    });
    _loadFontSettings();
    _loadGeneratedIds();
    _loadShelfCells();
    _loadHeaderAndBookshelfSettings();
    _loadFlashcards();
    _loadVideoPositions();
    // ★ initialLoadDone は _loadGeminiApiKey の末尾で complete される。 万一
    //   この関数が途中で例外を投げても、 initialLoadDone を必ず完了させる
    //   (= 初回の言語ピッカーが永久に出ない不具合を防ぐ。 ユーザー報告)。
    _loadGeminiApiKey()
        .catchError((Object e) => debugPrint('初期ロードで例外 (続行): $e'))
        .whenComplete(() {
      if (!_initialLoadCompleter.isCompleted) {
        _initialLoadCompleter.complete();
        notifyListeners();
      }
    });
    _loadAiSettings();
    _loadChannelFilterSettings();
    _loadChannelQueues();
    _loadAutoSyncPageIds();
    _loadNamedGroups();
    _loadDeveloperModeState();
    _loadJoinedGroups();
    _loadColorSettings();
    loadDisplayName();
    _loadCalendarGroupSharing();
    _loadCalendarViewingUid();
    // 非表示ページ / お気に入りページ の永続化状態を復元
    _loadHiddenPages();
    _loadFavoritePages();
    // PDF ページレベルの非表示リスト
    _loadHiddenPdfPages();
    // Web ページ用メモ (= Qiita 等の URL に紐づくメモ)
    _loadWebPageMemos();
    // Qiita ブロック投稿者リストを復元
    _loadQiitaBlocked();
    // Pro / クーポン状態の復元 (期限切れクーポンの自動クリア込み)
    _loadProState();
    // Google検索ダイアログの永続化状態 (ドラフトメモ + 保存済みメモ) を復元
    loadGoogleSearchMemoState();
    // クイズ重複回避の設定と過去質問履歴を復元 (PDF → AI 一問一答)
    _loadQuizSettings();
    // AI モデル一覧の初期化 (キャッシュ復元 + 24h 経過なら裏で再取得)。
    // API キーの読み込みが完了してから呼ばないと、認証が必要な OpenAI /
    // Claude の models エンドポイントが叩けないので、_loadAiSettings の
    // 直後に呼ぶ。失敗しても問題ないので fire-and-forget。
    initializeAvailableModels();
    _initFirebase().then((_) => loadInquiryEmailFromCloud());
  }

  // ── Firebase REST API 実装 ──────────────────────────────────────────────────

  // ── Firebase 同期メソッド ─────────────────────────────────────────────────

  /// 起動時にFirebase匿名認証を行う（グループ参加は別途）
  /// Firebase初期化時の失敗理由（UIで表示できるよう保持）
  String? _firebaseInitError;
  String? get firebaseInitError => _firebaseInitError;

  /// Firebaseの設定が揃っているか（実際に通信できるかは別）
  bool get isFirebaseConfigured =>
      _firestoreProjectId.isNotEmpty && _authApiKey.isNotEmpty;

  Future<void> _initFirebase() async {
    if (_firestoreProjectId.isEmpty || _authApiKey.isEmpty) {
      final missing = <String>[];
      if (_firestoreProjectId.isEmpty) missing.add('FIREBASE_PROJECT_ID');
      if (_authApiKey.isEmpty)
        missing.add('FIREBASE_API_KEY (REST/WINDOWS/ANDROID等いずれか)');
      _firebaseInitError =
          'Firebase設定が不足しています。ビルド時に --dart-define-from-file=env.json で以下を指定してください:\n'
          '${missing.join(", ")}';
      debugPrint('Firebase未設定 → オフラインモード ($_firebaseInitError)');
      return;
    }
    // ── ① 認証 (ここの成否だけが _firebaseEnabled を決める) ──
    try {
      await _signInAnonymously();
      _firebaseEnabled = true;
      _firebaseInitError = null;
    } catch (e) {
      _firebaseEnabled = false;
      _firebaseInitError = '匿名認証に失敗しました: $e';
      debugPrint('Firebase init failed (offline): $e');
      return; // 認証失敗時はここで終了
    }
    // ── ② 認証成功後の処理 (= ハートビート/課金/期限削除) ──
    // 重要: ここでの失敗 (ネットワーク・タイムアウト等) で Firebase 自体を
    // 無効化してはいけない。 以前は _registerMember のタイムアウトが
    // catch に落ちて「匿名認証に失敗しました」 と誤表示し、 同期全体が無効化
    // (同期グループも消えたように見える) されていた (= ユーザー報告)。
    // 認証は成功しているので、 これらは失敗しても無視して同期は有効のまま。
    try {
      // RevenueCat 初期化 (モバイルのみ。 Windows 等は no-op)。
      if (_uid != null) {
        await _billing.configure(appUserId: _uid!);
      }
      _syncPlanToUserDoc();
      // 保存済みグループIDがあれば復元（自動同期はしない）
      final prefs = await SharedPreferences.getInstance();
      final savedGroup = prefs.getString('syncGroupId');
      if (savedGroup != null && savedGroup.isNotEmpty) {
        // グループは registerMember より先に復元しておく
        // (ハートビートが失敗してもグループ所属は維持される)。
        _syncGroupId = savedGroup;
        await _registerMember(savedGroup);
        final lastPruneMs = prefs.getInt('lastPruneAtMs') ?? 0;
        final now = DateTime.now().millisecondsSinceEpoch;
        if (now - lastPruneMs > Duration(hours: 24).inMilliseconds) {
          await prefs.setInt('lastPruneAtMs', now);
          // ignore: discarded_futures
          pruneExpiredCloudData();
        }
      }
    } catch (e) {
      // 認証は成功済み → 同期は有効のまま。 ハートビート等の失敗は無視。
      debugPrint('Firebase post-auth step failed (sync still enabled): $e');
    }
  }

  /// Firebase再初期化（同期グループ参加前に自動リトライ）
  Future<void> retryFirebaseInit() async {
    if (_firebaseEnabled) return;
    await _initFirebase();
    notifyListeners();
  }

  Future<void> _signInAnonymously() async {
    // 保存済みリフレッシュトークンがあればそれを使う
    final prefs = await SharedPreferences.getInstance();
    final savedRefresh = prefs.getString('firebase_refresh_token');
    if (savedRefresh != null && savedRefresh.isNotEmpty) {
      final ok = await _refreshIdToken(savedRefresh);
      if (ok) return;
    }
    // なければ新規匿名ユーザー作成
    final res = await http
        .post(
          Uri.parse('$_authUrl?key=$_authApiKey'),
          headers: {'Content-Type': 'application/json'},
          body: jsonEncode({'returnSecureToken': true}),
          // 新規匿名ユーザー作成。 短すぎると認証失敗→同期無効化になるため余裕を。
        )
        .timeout(const Duration(seconds: 60));
    if (res.statusCode == 200) {
      final data = jsonDecode(res.body) as Map<String, dynamic>;
      _idToken = data['idToken'] as String?;
      _uid = data['localId'] as String?;
      final expiresIn = int.tryParse('${data['expiresIn'] ?? 3600}') ?? 3600;
      _idTokenExpiry = DateTime.now().add(Duration(seconds: expiresIn));
      final refresh = data['refreshToken'] as String?;
      if (refresh != null) {
        await prefs.setString('firebase_refresh_token', refresh);
      }
      if (_uid != null) {
        await prefs.setString('firebase_uid', _uid!);
      }
    } else {
      throw Exception('Auth failed: ${res.body}');
    }
  }

  /// リフレッシュトークンで新しいIDトークンを取得
  Future<bool> _refreshIdToken(String refreshToken) async {
    try {
      final res = await http
          .post(
            Uri.parse(
                'https://securetoken.googleapis.com/v1/token?key=$_authApiKey'),
            headers: {'Content-Type': 'application/x-www-form-urlencoded'},
            body: 'grant_type=refresh_token&refresh_token=$refreshToken',
            // 認証は少し遅いことがあるので余裕を持たせる (短すぎると「匿名認証に
            // 失敗しました」 で同期全体が無効化される = ユーザー報告)。
          )
          .timeout(const Duration(seconds: 45));
      if (res.statusCode == 200) {
        final data = jsonDecode(res.body) as Map<String, dynamic>;
        _idToken = data['id_token'] as String?;
        _uid = data['user_id'] as String?;
        final expiresIn = int.tryParse('${data['expires_in'] ?? 3600}') ?? 3600;
        _idTokenExpiry = DateTime.now().add(Duration(seconds: expiresIn));
        final newRefresh = data['refresh_token'] as String?;
        if (newRefresh != null) {
          final prefs = await SharedPreferences.getInstance();
          await prefs.setString('firebase_refresh_token', newRefresh);
        }
        return _idToken != null;
      }
    } catch (e) {
      debugPrint('Token refresh failed: $e');
    }
    return false;
  }

  /// トークンをリフレッシュしてリトライ可能にする
  Future<void> _ensureFreshToken({bool force = false}) async {
    // トークンがまだ十分に有効なら更新をスキップして高速化する
    // (= ユーザー報告: Ctrl+D の読み込みが毎回のトークン更新往復で遅い)。
    // force=true (401/403 リトライ時) は必ず再取得する。
    if (!force &&
        _idToken != null &&
        _idTokenExpiry != null &&
        DateTime.now()
            .isBefore(_idTokenExpiry!.subtract(const Duration(minutes: 5)))) {
      return;
    }
    final prefs = await SharedPreferences.getInstance();
    final savedRefresh = prefs.getString('firebase_refresh_token');
    if (savedRefresh != null && savedRefresh.isNotEmpty) {
      await _refreshIdToken(savedRefresh);
    } else {
      await _signInAnonymously();
    }
  }

  // ── グループ管理 ──────────────────────────────────────────────────────────

  /// 一度に参加できる同期グループの最大数
  static const int maxJoinedGroups = 5;

  /// 新しいグループを作成してホストになる
  /// 戻り値: 他のユーザーに共有する8桁のグループコード
  Future<String> createGroup() async {
    if (!_firebaseEnabled) {
      await _initFirebase(); // 1回リトライ
    }
    if (!_firebaseEnabled) {
      throw Exception(_firebaseInitError ?? 'Firebase未設定');
    }
    if (_joinedGroupIds.length >= maxJoinedGroups) {
      throw Exception('参加できるグループは最大$maxJoinedGroupsつまでです');
    }
    // 8桁英数字のグループコードを生成
    final code = _uuid.v4().replaceAll('-', '').substring(0, 8).toUpperCase();
    await _writeGroupMeta(code);
    await joinGroup(code);
    return code;
  }

  /// グループコードを入力して参加（グループIDを保存 + メンバー登録）
  /// 同じコードで再度参加しても重複しない
  Future<void> joinGroup(String groupCode) async {
    if (!_firebaseEnabled) {
      await _initFirebase(); // 1回リトライ
    }
    if (!_firebaseEnabled) {
      throw Exception(_firebaseInitError ?? 'Firebase未設定');
    }
    final code = groupCode.trim().toUpperCase();
    // 既に参加中のグループでなければ上限チェック
    if (!_joinedGroupIds.contains(code) &&
        _joinedGroupIds.length >= maxJoinedGroups) {
      throw Exception('参加できるグループは最大$maxJoinedGroupsつまでです');
    }
    _syncGroupId = code;
    if (!_joinedGroupIds.contains(code)) {
      _joinedGroupIds.add(code);
    }
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString('syncGroupId', code);
    await _saveJoinedGroups();
    await _registerMember(code);
    notifyListeners();
  }

  /// アクティブな同期グループを切替（参加済みのものから選択）
  Future<void> setActiveGroup(String? groupCode) async {
    if (groupCode != null && !_joinedGroupIds.contains(groupCode)) return;
    _syncGroupId = groupCode;
    final prefs = await SharedPreferences.getInstance();
    if (groupCode == null) {
      await prefs.remove('syncGroupId');
    } else {
      await prefs.setString('syncGroupId', groupCode);
    }
    notifyListeners();
  }

  /// 特定のグループから離脱（複数所属対応）
  Future<void> leaveSpecificGroup(String groupCode) async {
    final code = groupCode.trim().toUpperCase();
    _joinedGroupIds.remove(code);
    // ページ紐付けからも削除
    _pageGroupBindings.removeWhere((_, gid) => gid == code);
    if (_syncGroupId == code) {
      _syncGroupId = _joinedGroupIds.isNotEmpty ? _joinedGroupIds.first : null;
    }
    final prefs = await SharedPreferences.getInstance();
    if (_syncGroupId == null) {
      await prefs.remove('syncGroupId');
    } else {
      await prefs.setString('syncGroupId', _syncGroupId!);
    }
    await _saveJoinedGroups();
    await prefs.setString('pageGroupBindings', jsonEncode(_pageGroupBindings));
    notifyListeners();
    if (_firebaseEnabled) {
      await _unregisterMember(code);
      await _cleanupGroupIfEmpty(code);
    }
  }

  /// グループから離脱（ローカル専用に戻る）— 互換維持
  Future<void> leaveGroup() async {
    _syncTimer?.cancel();
    final leavingGroupId = _syncGroupId;
    if (leavingGroupId != null) {
      await leaveSpecificGroup(leavingGroupId);
    } else {
      _syncGroupId = null;
      final prefs = await SharedPreferences.getInstance();
      await prefs.remove('syncGroupId');
      notifyListeners();
    }
  }

  // ── グループメンバー管理 ──────────────────────────────────────────────────

  /// メンバーとしてFirestoreに登録（タイムスタンプ付き）
  Future<void> _registerMember(String groupCode) async {
    if (_idToken == null || _uid == null) return;
    try {
      final url = '$_firestoreBaseUrl/groups/$groupCode/members/$_uid';
      await http
          .patch(
            Uri.parse(
                '$url?updateMask.fieldPaths=lastSeen&updateMask.fieldPaths=uid&updateMask.fieldPaths=displayName&updateMask.fieldPaths=allowCalendarSharing&updateMask.fieldPaths=plan'),
            headers: {
              'Authorization': 'Bearer $_idToken',
              'Content-Type': 'application/json',
            },
            body: jsonEncode({
              'fields': {
                'uid': {'stringValue': _uid!},
                'displayName': {'stringValue': _displayName ?? '匿名'},
                'lastSeen': {'stringValue': DateTime.now().toIso8601String()},
                'allowCalendarSharing': {
                  'booleanValue': _calendarGroupSharingEnabled,
                },
                // plan を一緒に書いておく。Max プランのユーザー切替セレクタが
                // メンバードキュメントから plan を読んで Pro+ のみ列挙できるようにする。
                'plan': {'stringValue': currentPlanLabel()},
              },
            }),
          )
          .timeout(const Duration(seconds: 20)); // ハング防止 (= ユーザー報告)
      debugPrint('グループ $groupCode にメンバー登録完了: $_uid');
    } catch (e) {
      debugPrint('メンバー登録エラー: $e');
    }
  }

  /// メンバー登録を削除
  Future<void> _unregisterMember(String groupCode) async {
    if (_idToken == null || _uid == null) return;
    try {
      final url = '$_firestoreBaseUrl/groups/$groupCode/members/$_uid';
      await http.delete(
        Uri.parse(url),
        headers: {'Authorization': 'Bearer $_idToken'},
      );
      debugPrint('グループ $groupCode からメンバー解除: $_uid');
    } catch (e) {
      debugPrint('メンバー解除エラー: $e');
    }
  }

  /// メンバーがいるか確認し、0人ならグループ全データを削除
  Future<void> _cleanupGroupIfEmpty(String groupCode) async {
    if (_idToken == null) return;
    try {
      // メンバー一覧を取得
      final membersUrl = '$_firestoreBaseUrl/groups/$groupCode/members';
      final res = await http.get(
        Uri.parse(membersUrl),
        headers: {'Authorization': 'Bearer $_idToken'},
      );
      if (res.statusCode != 200) return;
      final data = jsonDecode(res.body) as Map<String, dynamic>;
      final docs = data['documents'] as List<dynamic>? ?? [];

      // 7日以上アクセスのないメンバーは無効とみなす
      final now = DateTime.now();
      int activeMembers = 0;
      final staleIds = <String>[];
      for (final doc in docs) {
        try {
          final fields = doc['fields'] as Map<String, dynamic>;
          final lastSeenStr = _firestoreStr(fields['lastSeen']);
          if (lastSeenStr != null) {
            final lastSeen = DateTime.tryParse(lastSeenStr);
            if (lastSeen != null && now.difference(lastSeen).inDays <= 7) {
              activeMembers++;
              continue;
            }
          }
          // 古いメンバーのドキュメントパスを抽出
          final docName = doc['name'] as String?;
          if (docName != null) staleIds.add(docName);
        } catch (_) {}
      }

      // 古いメンバーを削除
      for (final docPath in staleIds) {
        try {
          final deleteUrl = 'https://firestore.googleapis.com/v1/$docPath';
          await http.delete(
            Uri.parse(deleteUrl),
            headers: {'Authorization': 'Bearer $_idToken'},
          );
        } catch (_) {}
      }

      debugPrint('グループ $groupCode: アクティブメンバー=$activeMembers');

      if (activeMembers > 0) return;

      // ── メンバー0人 → グループ全データ削除 ──
      debugPrint('グループ $groupCode: メンバー0人 → データ削除開始');

      // 1. pages サブコレクション削除
      await _deleteSubcollection(groupCode, 'pages');

      // 2. members サブコレクション削除（残りがあれば）
      await _deleteSubcollection(groupCode, 'members');

      // 3. Storage の添付ファイル削除
      await _deleteGroupStorage(groupCode);

      // 4. グループドキュメント自体を削除
      try {
        final groupDocUrl = '$_firestoreBaseUrl/groups/$groupCode';
        await http.delete(
          Uri.parse(groupDocUrl),
          headers: {'Authorization': 'Bearer $_idToken'},
        );
      } catch (_) {}

      debugPrint('グループ $groupCode: データ削除完了');
    } catch (e) {
      debugPrint('グループクリーンアップエラー: $e');
    }
  }

  /// Firestoreサブコレクション内の全ドキュメントを削除
  Future<void> _deleteSubcollection(String groupCode, String collection) async {
    if (_idToken == null) return;
    try {
      final url = '$_firestoreBaseUrl/groups/$groupCode/$collection';
      final res = await http.get(
        Uri.parse(url),
        headers: {'Authorization': 'Bearer $_idToken'},
      );
      if (res.statusCode != 200) return;
      final data = jsonDecode(res.body) as Map<String, dynamic>;
      final docs = data['documents'] as List<dynamic>? ?? [];
      for (final doc in docs) {
        final docName = doc['name'] as String?;
        if (docName == null) continue;
        try {
          final deleteUrl = 'https://firestore.googleapis.com/v1/$docName';
          await http.delete(
            Uri.parse(deleteUrl),
            headers: {'Authorization': 'Bearer $_idToken'},
          );
        } catch (_) {}
      }
    } catch (e) {
      debugPrint('サブコレクション $collection 削除エラー: $e');
    }
  }

  /// 期限切れクラウドデータの自動削除。
  ///
  /// プランに応じて:
  ///   - Free  : アップロードから **7 日経過** したファイルを削除
  ///   - Pro/Max : 契約終了 (`_subscriptionEndedAt`) から **30 日経過**
  ///              していたら、 該当グループの全データを削除
  ///   - Pro/Max 契約中 (`_subscriptionEndedAt == null`) : 何もしない
  ///
  /// 起動時に呼び出される想定 (バックグラウンド処理、 失敗しても無視)。
  /// 削除した分は `releaseStorageBytes()` で累積使用量から差し引く。
  Future<void> pruneExpiredCloudData() async {
    if (!_firebaseEnabled || _syncGroupId == null || _idToken == null) return;
    final now = DateTime.now().toUtc();

    if (currentPlan == SubscriptionPlan.free) {
      // Free: 7 日より古いファイルを個別に削除
      final cutoff = now.subtract(kFreeAutoDeleteGrace);
      await _pruneFilesOlderThan(cutoff);
    } else {
      // Pro/Max: 契約終了から 30 日経過なら全データ削除
      final endedAt = _subscriptionEndedAt;
      if (endedAt == null) return; // 契約中なので保持
      final deleteAt = endedAt.add(kPaidAutoDeleteGrace);
      if (now.isBefore(deleteAt)) return; // まだ猶予期間中
      try {
        await _deleteGroupStorage(_syncGroupId!);
        // 全削除したので累積使用量を 0 にリセット
        _totalStorageBytes = 0;
        // ignore: discarded_futures
        _persistMonthlyUsage();
        notifyListeners();
      } catch (e) {
        debugPrint('pruneExpiredCloudData (full) error: $e');
      }
    }
  }

  /// `cutoff` より古い `updated` メタデータを持つファイルを Storage から削除。
  Future<void> _pruneFilesOlderThan(DateTime cutoff) async {
    if (_idToken == null || _syncGroupId == null) return;
    try {
      final prefix = Uri.encodeComponent('groups/$_syncGroupId/');
      final listUrl = '$_storageUploadUrl?prefix=$prefix';
      final res = await http.get(
        Uri.parse(listUrl),
        headers: {'Authorization': 'Bearer $_idToken'},
      );
      if (res.statusCode != 200) return;
      final data = jsonDecode(res.body) as Map<String, dynamic>;
      final items = data['items'] as List<dynamic>? ?? [];
      int releasedBytes = 0;
      for (final item in items) {
        final m = item as Map<String, dynamic>;
        final name = m['name'] as String?;
        final updatedStr = m['updated'] as String?; // ISO8601
        final sizeStr = m['size'] as String?;
        if (name == null || updatedStr == null) continue;
        final updated = DateTime.tryParse(updatedStr);
        if (updated == null) continue;
        if (updated.isAfter(cutoff)) continue; // 期限内 → 保持
        // 期限切れ → 削除
        try {
          final encoded = Uri.encodeComponent(name);
          final deleteUrl = '$_storageUploadUrl/$encoded';
          final dr = await http.delete(
            Uri.parse(deleteUrl),
            headers: {'Authorization': 'Bearer $_idToken'},
          );
          if (dr.statusCode >= 200 && dr.statusCode < 300) {
            releasedBytes += int.tryParse(sizeStr ?? '0') ?? 0;
            debugPrint('Auto-prune: $name (uploaded $updatedStr)');
          }
        } catch (_) {}
      }
      if (releasedBytes > 0) {
        releaseStorageBytes(releasedBytes);
      }
    } catch (e) {
      debugPrint('_pruneFilesOlderThan error: $e');
    }
  }

  /// Firebase Storage のグループフォルダ内ファイルを削除
  Future<void> _deleteGroupStorage(String groupCode) async {
    if (_idToken == null) return;
    try {
      // Storage REST API: prefix でリストしてから各オブジェクトを削除
      final prefix = Uri.encodeComponent('groups/$groupCode/');
      final listUrl = '$_storageUploadUrl?prefix=$prefix';
      final res = await http.get(
        Uri.parse(listUrl),
        headers: {'Authorization': 'Bearer $_idToken'},
      );
      if (res.statusCode != 200) return;
      final data = jsonDecode(res.body) as Map<String, dynamic>;
      final items = data['items'] as List<dynamic>? ?? [];
      for (final item in items) {
        final name = item['name'] as String?;
        if (name == null) continue;
        try {
          final encoded = Uri.encodeComponent(name);
          final deleteUrl = '$_storageUploadUrl/$encoded';
          await http.delete(
            Uri.parse(deleteUrl),
            headers: {'Authorization': 'Bearer $_idToken'},
          );
          debugPrint('Storage削除: $name');
        } catch (_) {}
      }
    } catch (e) {
      debugPrint('Storageクリーンアップエラー: $e');
    }
  }

  /// グループのメタ情報をFirestoreに書き込む
  Future<void> _writeGroupMeta(String groupCode) async {
    if (_idToken == null) return;
    final url = '$_firestoreBaseUrl/groups/$groupCode';
    await http.patch(
      Uri.parse(
          '$url?updateMask.fieldPaths=createdAt&updateMask.fieldPaths=host'),
      headers: {
        'Authorization': 'Bearer $_idToken',
        'Content-Type': 'application/json',
      },
      body: jsonEncode({
        'fields': {
          'createdAt': {'stringValue': DateTime.now().toIso8601String()},
          'host': {'stringValue': _uid ?? ''},
        },
      }),
    );
  }

  // ── Firestoreデータ読み書き ───────────────────────────────────────────────

  /// グループの全ページをFirestoreから取得してローカルに反映
  Future<void> _fetchGroupPages() async {
    if (!_firebaseEnabled || _syncGroupId == null || _idToken == null) return;
    try {
      final url = '$_firestoreBaseUrl/groups/$_syncGroupId/pages';
      final res = await http.get(
        Uri.parse(url),
        headers: {'Authorization': 'Bearer $_idToken'},
      );
      if (res.statusCode == 200) {
        final data = jsonDecode(res.body) as Map<String, dynamic>;
        final docs = data['documents'] as List<dynamic>? ?? [];
        bool changed = false;
        for (final doc in docs) {
          try {
            final fields = doc['fields'] as Map<String, dynamic>;
            final jsonStr = _firestoreStr(fields['json']);
            if (jsonStr == null) continue;
            final pageData = jsonDecode(jsonStr) as Map<String, dynamic>;
            final page = MindMapPage.fromJson(pageData);
            // ── 再アップロード制限フィールドをクラウドから取り込む ──
            // ユーザー要望「他ユーザーによる再アップロードを制限できる機能」
            //   の一部。 クラウド側 (= 制限を掛けたユーザーの最新状態) を
            //   ローカルに反映することで、 他のメンバーが UI 上でロック状態
            //   を正しく認識できる (= 制限解除されたらすぐに反映される)。
            final restrictedFld =
                fields['uploadRestricted'] as Map<String, dynamic>?;
            if (restrictedFld != null) {
              page.uploadRestricted = restrictedFld['booleanValue'] == true;
            }
            final restrictedByFld =
                fields['restrictedByUid'] as Map<String, dynamic>?;
            if (restrictedByFld != null) {
              page.restrictedByUid = restrictedByFld['stringValue'] as String?;
            }
            // 添付ファイル・画像をStorageからダウンロード
            await _downloadPageAttachments(page);
            final idx = _pages.indexWhere((p) => p.id == page.id);
            if (idx < 0) {
              _pages.add(page);
              changed = true;
            } else if (!_firestoreSyncing) {
              _pages[idx].nodes
                ..clear()
                ..addAll(page.nodes);
              _pages[idx].connections
                ..clear()
                ..addAll(page.connections);
              // 制限フラグはローカルにも反映 (= UI で表示できるよう)
              _pages[idx].uploadRestricted = page.uploadRestricted;
              _pages[idx].restrictedByUid = page.restrictedByUid;
              changed = true;
            }
            // 付箋（namedGroups）を復元
            final ngJson = _firestoreStr(fields['namedGroupsJson']);
            if (ngJson != null && ngJson.isNotEmpty) {
              _applyNamedGroupsJson(page.id, ngJson);
              changed = true;
            }
          } catch (_) {}
        }
        if (changed) {
          await _saveToStorageLocal();
          await _saveNamedGroups(); // 付箋情報も永続化
          notifyListeners();
        }
      } else if (res.statusCode == 401) {
        await _signInAnonymously();
      }
    } catch (e) {
      debugPrint('Firestore fetch error: $e');
    }
  }

  String? _firestoreStr(dynamic val) {
    if (val == null) return null;
    if (val is Map) return val['stringValue'] as String?;
    return null;
  }

  /// ページをFirestoreのグループに保存
  Future<void> _savePageToFirestore(String pageId,
      {bool retried = false,
      void Function(double progress)? onPageProgress}) async {
    if (!_firebaseEnabled || _syncGroupId == null || _idToken == null) return;
    final idx = _pages.indexWhere((p) => p.id == pageId);
    if (idx < 0) return;
    _firestoreSyncing = true;
    try {
      // ── 他ユーザーによる再アップロード制限のチェック ──
      // ユーザー要望「クラウドに新しいマップをアップロードする時に他ユーザー
      //   による再アップロードを制限できる機能を作って」 への対応。
      //
      // Firestore から既存ドキュメントを GET し、 uploadRestricted == true で
      // restrictedByUid が現在のユーザー (_uid) と異なる場合は拒否する。
      // 自分が制限を掛けている場合は、 自分は引き続き上書き可能。
      // 初回アップロード (= 404) ならスキップ。
      try {
        final getUrl = '$_firestoreBaseUrl/groups/$_syncGroupId/pages/$pageId';
        final getRes = await http.get(
          Uri.parse(getUrl),
          headers: {'Authorization': 'Bearer $_idToken'},
        ).timeout(const Duration(seconds: 25)); // ハング防止 (= ユーザー報告)
        if (getRes.statusCode == 200) {
          final data = jsonDecode(getRes.body) as Map<String, dynamic>;
          final remoteFields = data['fields'] as Map<String, dynamic>? ?? {};
          final restrictedFld =
              remoteFields['uploadRestricted'] as Map<String, dynamic>?;
          final remoteRestricted =
              restrictedFld != null && restrictedFld['booleanValue'] == true;
          final restrictedByFld =
              remoteFields['restrictedByUid'] as Map<String, dynamic>?;
          final remoteRestrictedBy = restrictedByFld != null
              ? restrictedByFld['stringValue'] as String?
              : null;
          if (remoteRestricted &&
              remoteRestrictedBy != null &&
              remoteRestrictedBy.isNotEmpty &&
              remoteRestrictedBy != _uid) {
            // ローカル状態にも反映 (= UI で制限を表示できるよう)
            _pages[idx].uploadRestricted = true;
            _pages[idx].restrictedByUid = remoteRestrictedBy;
            notifyListeners();
            throw _UploadRestrictedException(
              'このマップは他のユーザーによって再アップロード制限が掛かっています',
            );
          }
        }
        // 404 (ドキュメント未作成) はスルー (= 初回アップロード)
      } on _UploadRestrictedException {
        rethrow;
      } catch (e) {
        // それ以外のエラーは無視して通常アップロードを試みる
        debugPrint('uploadRestricted pre-check skipped: $e');
      }

      // ── 添付ファイル (画像/PDF/動画) を Firebase Storage にアップロード ──
      // 旧実装はここで `_uploadPageAttachments(pageId)` を await せず
      // fire-and-forget していたため、ファイル本体が 90% 程度送信中でも
      // メタデータの PATCH が先に完了し、UI 上「アップロード完了」と
      // 表示されてしまうバグがあった (大きな動画ファイルで顕著)。
      //
      // 修正: await を追加してファイル送信が完全に終わってから
      // メタデータ JSON を Firestore に PATCH するように変更。
      // ただし _uploadPageAttachments の中で attachmentStorageUrl が
      // 書き換わるので、その値が反映された後で pageJson をシリアライズする。
      //
      // さらに onPageProgress を介して、添付ファイル送信進捗を呼び出し元
      // (uploadToCloud) に伝える。これによりプログレスバーが実際の
      // バイト送信状況に追従し、巨大な動画でも 90% で固まる現象を防ぐ。
      // ファイルアップロードに進捗の 95% 分を割り当て、メタデータ PATCH に
      // 残り 5% を割り当てる (経験的にメタデータは数百ミリ秒で終わる)。
      await _uploadPageAttachments(pageId, onPageProgress: (p) {
        onPageProgress?.call(p * 0.95);
      });

      onPageProgress?.call(0.95);
      final pageJson = jsonEncode(_pages[idx].toJson());
      // 付箋（namedGroups）も同期
      final namedGroupsJson = _serializeNamedGroupsForPage(pageId);
      final url = '$_firestoreBaseUrl/groups/$_syncGroupId/pages/$pageId';
      // ── 無料プランは 1 週間で自動削除 ──
      // クラウドストレージのコスト・データ滞留対策として、無料プランの
      // ユーザーがアップロードしたページは 7 日後に自動削除されるよう
      // `expiresAt` フィールドを Firestore に書き込む。
      // Firestore Console 側で TTL ポリシーを `expiresAt` フィールドに
      // 対して有効化しておくと、Google Cloud が自動で削除してくれる。
      // (TTL 設定: Firestore Console → TTL → Add Policy → Collection
      //  group: pages, Timestamp field: expiresAt)
      // Pro / クーポンユーザーの場合は `expiresAt` を null で書き込んで
      // 既存の期限を解除する (= 永久保存)。
      final fields = <String, dynamic>{
        'json': {'stringValue': pageJson},
        'namedGroupsJson': {'stringValue': namedGroupsJson},
      };
      final updateMaskParts = <String>[
        'json',
        'namedGroupsJson',
        'expiresAt',
        // 再アップロード制限フィールドも更新対象に追加
        'uploadRestricted',
        'restrictedByUid',
      ];
      // ── 再アップロード制限フィールドの書き込み ──
      // ローカル状態 (= MindMapPage.uploadRestricted) を Firestore に反映。
      // ユーザーが UI で制限を ON にした → アップロード時に Firestore に
      //   uploadRestricted: true, restrictedByUid: <self> が書かれる
      //   → 他のユーザーが上書きしようとすると上の pre-check で拒否される。
      // ユーザーが OFF に戻した → uploadRestricted: false が書かれる
      //   → 制限解除されて誰でも上書き可能に戻る。
      final localRestricted = _pages[idx].uploadRestricted;
      fields['uploadRestricted'] = {'booleanValue': localRestricted};
      if (localRestricted) {
        // 自分が制限を掛ける場合、 自分の UID を書く
        // (= 既存のローカル restrictedByUid があってもアップロード時は自分の
        //   UID で上書きする = 自分が「正当な所有者」 として認識される)
        _pages[idx].restrictedByUid = _uid;
        fields['restrictedByUid'] = {'stringValue': _uid ?? ''};
      } else {
        // 制限解除: restrictedByUid をクリア
        _pages[idx].restrictedByUid = null;
        fields['restrictedByUid'] = {'nullValue': null};
      }
      if (isProUnlocked) {
        // Pro: expiresAt を null にして TTL 削除対象から外す
        fields['expiresAt'] = {'nullValue': null};
      } else {
        // Free: 7 日後に自動削除
        final expiry = DateTime.now()
            .add(const Duration(days: 7))
            .toUtc()
            .toIso8601String();
        fields['expiresAt'] = {'timestampValue': expiry};
      }
      final maskQuery =
          updateMaskParts.map((f) => 'updateMask.fieldPaths=$f').join('&');
      final res = await http
          .patch(
            Uri.parse('$url?$maskQuery'),
            headers: {
              'Authorization': 'Bearer $_idToken',
              'Content-Type': 'application/json',
            },
            body: jsonEncode({'fields': fields}),
          )
          .timeout(const Duration(seconds: 30)); // ハング防止 (= ユーザー報告)
      if ((res.statusCode == 401 || res.statusCode == 403) && !retried) {
        await _ensureFreshToken(force: true);
        _firestoreSyncing = false;
        return _savePageToFirestore(pageId,
            retried: true, onPageProgress: onPageProgress);
      }
      if (res.statusCode == 200) {
        // アップロード成功: 日時を記録
        final prefs = await SharedPreferences.getInstance();
        await prefs.setString(
            'page_uploaded_$pageId', DateTime.now().toUtc().toIso8601String());
        // ── 差分アップロード用にページ内容のハッシュも記録 (= ユーザー要望:
        //    Ctrl+S で差分だけアップロード)。 次回 Ctrl+S 時にこのハッシュと
        //    現在内容を比較し、 変わっていなければアップロードをスキップする。
        try {
          MindMapPage? up;
          for (final p in _pages) {
            if (p.id == pageId) {
              up = p;
              break;
            }
          }
          if (up != null) {
            await prefs.setString('page_uploaded_hash_$pageId',
                jsonEncode(up.toJson()).hashCode.toString());
          }
        } catch (_) {}
        onPageProgress?.call(1.0);
      } else {
        // ── 200 以外 = ページ保存失敗 ──
        // (= ユーザー報告:「アップロードしました」 と出るのに実際は上がって
        //   いない)。 握りつぶさず失敗フラグを立て、 UI に「完了しませんでした」
        //   を出させて false success を防ぐ。
        debugPrint('Firestore save non-200: ${res.statusCode} ${res.body}');
        _lastSyncAttachmentFailed = true;
      }
    } on _UploadRestrictedException {
      rethrow;
    } catch (e) {
      // タイムアウト/通信エラー等。 ここで握りつぶすと「完了」 と誤表示される
      // ため、 失敗フラグを立てる (= ユーザー報告)。
      debugPrint('Firestore save error: $e');
      _lastSyncAttachmentFailed = true;
    } finally {
      _firestoreSyncing = false;
    }
  }

  /// ページの再アップロード制限を切り替える (= ユーザー要望「クラウドに
  ///   新しいマップをアップロードする時に他ユーザーによる再アップロードを
  ///   制限できる機能」 の公開 API)。
  ///
  /// [restricted] が true なら、 次回アップロード時に自分の UID をロックとして
  /// 書き込み、 他ユーザーからの上書きを拒否する。 false なら制限を解除。
  ///
  /// ローカル状態を即座に変更して notifyListeners する。 Firestore への反映
  /// は次のアップロード時 (= ユーザーがアップロードボタンを押した時) に発生。
  /// 「制限の変更だけを即時クラウドに反映したい」 場合は [syncImmediately] を
  /// true にすると、 そのページを単独で _savePageToFirestore する。
  /// ─── マップ背景画像 (= ユーザー要望「マップの背景画像を自由に
  ///   カスタマイズ」) ────────────────────────────────────────────────
  /// 指定ページの背景画像パスをセットして永続化する。 `path` が null なら
  /// 背景画像を解除 (= グリッドのみに戻す)。
  Future<void> setPageBackgroundImage(String pageId, String? path) async {
    final idx = _pages.indexWhere((p) => p.id == pageId);
    if (idx < 0) return;
    _pushUndo();
    _pages[idx].backgroundImagePath = path;
    _pages[idx].lastModifiedAt = DateTime.now();
    notifyListeners();
    await _saveToStorageLocal();
    _triggerAutoSync();
  }

  /// 指定ページの背景画像の不透明度 (0〜100) をセットして永続化する。
  Future<void> setPageBackgroundOpacity(String pageId, int percent) async {
    final idx = _pages.indexWhere((p) => p.id == pageId);
    if (idx < 0) return;
    final clamped = percent.clamp(0, 100);
    if (_pages[idx].backgroundOpacityPercent == clamped) return;
    _pages[idx].backgroundOpacityPercent = clamped;
    _pages[idx].lastModifiedAt = DateTime.now();
    notifyListeners();
    await _saveToStorageLocal();
    _triggerAutoSync();
  }

  /// 指定ページの背景画像の表示モード ('cover' / 'contain' / 'tile') を
  /// セットして永続化する。
  Future<void> setPageBackgroundFit(String pageId, String fit) async {
    if (fit != 'cover' && fit != 'contain' && fit != 'tile') return;
    final idx = _pages.indexWhere((p) => p.id == pageId);
    if (idx < 0) return;
    if (_pages[idx].backgroundFit == fit) return;
    _pages[idx].backgroundFit = fit;
    _pages[idx].lastModifiedAt = DateTime.now();
    notifyListeners();
    await _saveToStorageLocal();
    _triggerAutoSync();
  }

  Future<void> setPageUploadRestricted(String pageId, bool restricted,
      {bool syncImmediately = false}) async {
    final idx = _pages.indexWhere((p) => p.id == pageId);
    if (idx < 0) return;
    // 他ユーザーが制限している場合は変更不可
    if (_pages[idx].uploadRestricted &&
        _pages[idx].restrictedByUid != null &&
        _pages[idx].restrictedByUid!.isNotEmpty &&
        _pages[idx].restrictedByUid != _uid) {
      throw _UploadRestrictedException('このマップは他のユーザーが制限を掛けています');
    }
    _pages[idx].uploadRestricted = restricted;
    if (restricted) {
      _pages[idx].restrictedByUid = _uid;
    } else {
      _pages[idx].restrictedByUid = null;
    }
    notifyListeners();
    // ローカルにも保存 (= アプリ再起動後も保持されるよう)
    try {
      await _saveToStorageLocal();
    } catch (_) {}
    if (syncImmediately &&
        _firebaseEnabled &&
        _syncGroupId != null &&
        _idToken != null) {
      // クラウドに即反映 (= 他ユーザーがすぐに制限を認識できるよう)
      await _savePageToFirestore(pageId);
    }
  }

  /// 指定ページが他のユーザーによってアップロード制限されているか。
  /// 自分が制限を掛けている場合は false (= 自分は上書き可能)。
  bool isPageRestrictedByOthers(String pageId) {
    final idx = _pages.indexWhere((p) => p.id == pageId);
    if (idx < 0) return false;
    final p = _pages[idx];
    if (!p.uploadRestricted) return false;
    if (p.restrictedByUid == null || p.restrictedByUid!.isEmpty) return false;
    return p.restrictedByUid != _uid;
  }

  /// ページをFirestoreのグループから削除
  Future<void> _deletePageFromFirestore(String pageId) async {
    if (!_firebaseEnabled || _syncGroupId == null || _idToken == null) return;
    try {
      final url = '$_firestoreBaseUrl/groups/$_syncGroupId/pages/$pageId';
      await http.delete(
        Uri.parse(url),
        headers: {'Authorization': 'Bearer $_idToken'},
      );
    } catch (e) {
      debugPrint('Firestore delete error: $e');
    }
  }

  // ── Firebase Storage: 添付ファイル・画像の同期 ─────────────────────────────

  /// ファイルをFirebase Storageにアップロード（dart:io HttpClientでストリーミング送信）
  ///
  /// プランごとの月間アップロード容量上限 (free 5MB / pro 5GB / max 25GB) を
  /// 超過する場合は ``MapLimitException`` 系の `Exception` を投げて中断する
  /// (上位 UI 側でユーザー向けエラーメッセージを表示する責務)。
  Future<String?> uploadAttachmentToStorage(String localPath, String fileName,
      {void Function(double progress)? onProgress}) async {
    if (!_firebaseEnabled || _syncGroupId == null || _idToken == null)
      return null;
    try {
      final file = File(localPath);
      if (!await file.exists()) {
        debugPrint('Storage upload: file not found: $localPath');
        return null;
      }
      final fileLength = await file.length();
      if (fileLength == 0) {
        debugPrint('Storage upload: file is empty: $localPath');
        return null;
      }

      // ── 月間アップロード容量チェック ──
      // 上限を超える場合は早期リターン (UI 側でエラー表示)。
      // recordUploadBytes は成功時のみ呼ぶので、 ここで先にチェックする
      // ことで「上限超過時に部分転送だけ走って失敗」を防ぐ。
      if (!canUseUploadBytes(fileLength)) {
        final limitGb =
            (monthlyUploadLimit / 1024 / 1024 / 1024).toStringAsFixed(1);
        _lastSyncLimitMessage = '今月のアップロード上限 ($limitGb GB) に達しました。来月まで待つか、'
            '上位プラン (開発者モードなら無制限) をご検討ください。';
        throw Exception(_lastSyncLimitMessage);
      }
      // ── 累積ストレージ容量チェック ──
      // Pro: 20 GB / Max: 100 GB を超える場合は不要ファイルを削除してから
      // やり直してもらう。
      if (!canUseStorageBytes(fileLength)) {
        final limitGb =
            (totalStorageLimit / 1024 / 1024 / 1024).toStringAsFixed(1);
        final usedGb =
            (_totalStorageBytes / 1024 / 1024 / 1024).toStringAsFixed(2);
        _lastSyncLimitMessage =
            'クラウドストレージ容量上限 ($limitGb GB) に達しました (現在 $usedGb GB)。'
            '不要なファイル/動画を削除するか、上位プラン (開発者モードなら無制限) を'
            'ご検討ください。';
        throw Exception(_lastSyncLimitMessage);
      }

      final ext = fileName.split('.').last.toLowerCase();
      String ct = 'application/octet-stream';
      if (ext == 'jpg' || ext == 'jpeg')
        ct = 'image/jpeg';
      else if (ext == 'png')
        ct = 'image/png';
      else if (ext == 'pdf')
        ct = 'application/pdf';
      else if (ext == 'mp4')
        ct = 'video/mp4';
      else if (ext == 'mov')
        ct = 'video/quicktime';
      else if (ext == 'm4v') ct = 'video/x-m4v';

      final storagePath = 'groups/$_syncGroupId/attachments/$fileName';
      final encoded = Uri.encodeComponent(storagePath);
      final uploadUrl = '$_storageUploadUrl/$encoded?uploadType=media';

      debugPrint(
          'Storage upload start: $fileName (${(fileLength / 1024 / 1024).toStringAsFixed(1)}MB)');

      // dart:io HttpClient でストリーミング送信（メモリに全体を載せない）
      final client = HttpClient();
      // 接続確立のタイムアウト。 旧 10 分は長すぎて、 通信不良時に「0% の
      // まま 10 分間固まる」 原因になっていた (= ユーザー報告)。 60 秒に短縮。
      client.connectionTimeout = const Duration(seconds: 60);
      Timer? stallTimer;
      try {
        final request = await client.postUrl(Uri.parse(uploadUrl));
        request.headers.set('Authorization', 'Bearer $_idToken');
        request.headers.set('Content-Type', ct);
        request.contentLength = fileLength;

        // ── ファイルをストリーム送信 ──
        // 注意: 以前は `await for ... request.add(chunk)` と書いていたが、
        // request.add() は内部バッファに足すだけで非同期送信を待たない。
        // そのため bytesSent はすぐに 100% に達し、実際の送信完了より
        // 早く「アップロード完了」と表示されてしまう問題があった
        // (PDF 等のサイズが大きいファイルで、完了表示後にダウンロードすると
        //  ファイルが壊れて読めない症状)。
        //
        // 修正: addStream() を使い、実際にバッファが流された分だけ進捗を
        // 報告する。さらに request.close() 後に response を受け取るまで
        // 「ファイル本体の送信が完了した」とは見なさない。
        int bytesSent = 0;
        // ── ストール検知 (= ユーザー報告: アップロードが 0% のまま進まない) ──
        // 一定時間バイト送信が進まなければ通信ハングとみなして接続を強制切断し、
        // 下の catch でエラー (null) として返す。 これで永久に固まらない。
        int lastSentSnapshot = 0;
        int stalledTicks = 0;
        stallTimer = Timer.periodic(const Duration(seconds: 15), (t) {
          if (bytesSent > lastSentSnapshot) {
            lastSentSnapshot = bytesSent;
            stalledTicks = 0;
          } else {
            stalledTicks++;
            if (stalledTicks >= 6) {
              // 約 90 秒間まったく進まなければハングと判断して打ち切る。
              t.cancel();
              try {
                client.close(force: true);
              } catch (_) {}
            }
          }
        });
        final progressStream = file.openRead().transform<List<int>>(
          StreamTransformer.fromHandlers(
            handleData: (chunk, sink) {
              sink.add(chunk);
              bytesSent += chunk.length;
              // 進捗は 0.0 〜 0.85 の範囲で報告
              // (残り 0.85 〜 1.0 はサーバー処理 + レスポンス受信の時間に充てる)
              final progress = (bytesSent / fileLength * 0.85).clamp(0.0, 0.85);
              onProgress?.call(progress);
            },
          ),
        );
        await request.addStream(progressStream);

        // ── サーバーへの送信完了 → レスポンス受信 ──
        // ここに来た時点でもまだサーバーは内容を処理中の可能性がある。
        // close() を await することでサーバーが 200 を返すまで待つ。
        onProgress?.call(0.90);
        final response = await request.close();
        final responseBody = await response
            .transform(
              const Utf8Decoder(allowMalformed: true),
            )
            .join();

        // サーバーが正常応答を返した時点で初めて 100% にする
        if (response.statusCode == 200) {
          // 月間アップロード使用量を記録 (永続化込み)
          recordUploadBytes(fileLength);
          // レスポンスからdownloadTokensを取得（公開URLアクセス用）
          String? finalUrl;
          try {
            final resJson = jsonDecode(responseBody) as Map<String, dynamic>;
            // ── サーバー応答の整合性確認 ──
            // size フィールドが返っていれば、 我々が送ったバイト数と一致するか
            // チェック。 PDF などで「途中まで送れたが Storage 側がトリミングして
            // 受領した」 ようなレアケースを検出して null 返却に倒す。
            final remoteSize = (resJson['size'] is String)
                ? int.tryParse(resJson['size'] as String)
                : (resJson['size'] as num?)?.toInt();
            if (remoteSize != null &&
                remoteSize > 0 &&
                remoteSize != fileLength) {
              debugPrint(
                  'Storage upload size mismatch: $fileName local=$fileLength remote=$remoteSize');
              return null;
            }
            final token = resJson['downloadTokens'] as String?;
            if (token != null && token.isNotEmpty) {
              finalUrl = '$_storageUploadUrl/$encoded?alt=media&token=$token';
            }
          } catch (_) {}
          finalUrl ??= '$_storageUploadUrl/$encoded?alt=media';
          // 100% は「URL を返す直前」 に出す。 これより前で 100% を出すと
          // 呼び出し元が attachmentStorageUrl の確定前に
          // 「アップロード完了」 と判定する余地が生まれる。
          onProgress?.call(1.0);
          debugPrint('Storage upload OK: $fileName ($fileLength bytes)');
          return finalUrl;
        } else {
          debugPrint(
              'Storage upload failed: ${response.statusCode} $responseBody');
          return null;
        }
      } finally {
        stallTimer?.cancel();
        client.close();
      }
    } catch (e) {
      debugPrint('Storage upload error: $e');
      return null;
    }
  }

  /// Firebase Storageからファイルをダウンロードしてローカルに保存
  ///
  /// プランごとの月間ダウンロード容量上限を超過する場合は Exception を投げる。
  /// チェック順序: メタデータでサイズを先取り → 上限内なら本体取得 → 成功時に
  /// 使用量記録。
  ///
  /// ── 整合性検証 ──
  /// PDF などのバイナリで「ファイル名だけダウンロードされて中が開けない」
  /// 不具合 (ユーザー報告) を防ぐため、 受信本体のサイズと Content-Length
  /// ヘッダー / レスポンスメタの size が食い違う場合は破損とみなして
  /// ローカルの部分書き込みを削除し null を返す。 これによりダウンロード
  /// 完了表示の後で開けないファイルが残るのを防ぐ。
  Future<String?> downloadAttachmentFromStorage(String fileName) async {
    if (!_firebaseEnabled || _syncGroupId == null || _idToken == null)
      return null;
    try {
      final storagePath = 'groups/$_syncGroupId/attachments/$fileName';
      final encoded = Uri.encodeComponent(storagePath);
      final downloadUrl = '$_storageUploadUrl/$encoded?alt=media';

      // タイムアウト無しだと通信不良時に「0% のまま固まる」 ので 4 分で打ち切る
      // (= ユーザー報告)。 大きな PDF/動画でも 4 分あれば足りる想定。
      final res = await http.get(
        Uri.parse(downloadUrl),
        headers: {'Authorization': 'Bearer $_idToken'},
      ).timeout(const Duration(minutes: 4));
      if (res.statusCode == 200) {
        // ── 月間ダウンロード容量チェック ──
        final size = res.bodyBytes.length;
        if (!canUseDownloadBytes(size)) {
          final limitGb =
              (monthlyDownloadLimit / 1024 / 1024 / 1024).toStringAsFixed(1);
          _lastSyncLimitMessage = '今月のダウンロード上限 ($limitGb GB) に達しました。来月まで待つか、'
              '上位プラン (開発者モードなら無制限) をご検討ください。';
          throw Exception(_lastSyncLimitMessage);
        }

        // ── Content-Length 整合性チェック ──
        // ヘッダーが付いていない (Firebase Storage の単純 GET では大抵
        // 付いている) ケースでは検証をスキップ。 付いていてサイズが
        // 一致しない場合は途中切断と判断して null を返す。
        final clHeader = res.headers['content-length'];
        if (clHeader != null) {
          final expected = int.tryParse(clHeader);
          if (expected != null && expected > 0 && expected != size) {
            debugPrint(
                'Storage download size mismatch: $fileName expected=$expected got=$size');
            return null;
          }
        }
        // 完全に空のレスポンスは PDF として開けない → 破損扱い
        if (size == 0) {
          debugPrint('Storage download: empty body for $fileName');
          return null;
        }

        final appDir = await getApplicationDocumentsDirectory();
        final attachDir = Directory('${appDir.path}/attachments');
        if (!await attachDir.exists()) {
          await attachDir.create(recursive: true);
        }
        final localPath = '${attachDir.path}/$fileName';
        // ── 書き込みは一旦 .part に行い、 完了後 rename ──
        // 書き込み途中で別の処理がローカルパスを参照しても、 「壊れた本体」
        // を掴ませない。 完成した時点で原子的に rename することで
        // 「中身が空 / 途中まで」状態が UI に露出するのを防ぐ。
        final tempFile = File('$localPath.part');
        await tempFile.writeAsBytes(res.bodyBytes, flush: true);

        // 書き出したファイルサイズと受信バイト数が一致するか最終確認
        final writtenLen = await tempFile.length();
        if (writtenLen != size) {
          debugPrint(
              'Storage download write mismatch: $fileName received=$size written=$writtenLen');
          try {
            await tempFile.delete();
          } catch (_) {}
          return null;
        }
        // 旧ファイルがあれば削除してから rename (Windows 対策)
        final finalFile = File(localPath);
        if (await finalFile.exists()) {
          try {
            await finalFile.delete();
          } catch (_) {}
        }
        await tempFile.rename(localPath);

        // 月間ダウンロード使用量を記録
        recordDownloadBytes(size);
        debugPrint('Storage download OK: $fileName → $localPath ($size bytes)');
        return localPath;
      } else {
        debugPrint('Storage download: ${res.statusCode} ($fileName)');
        return null;
      }
    } catch (e) {
      debugPrint('Storage download error: $e');
      return null;
    }
  }

  /// ページ内の添付ファイル・ローカル動画をすべてStorageにアップロード
  /// アップロード完了後、ノードのパスをStorage URLに書き換えてFirestoreに再保存
  Future<void> _uploadPageAttachments(String pageId,
      {void Function(double progress)? onPageProgress}) async {
    if (!_firebaseEnabled || _syncGroupId == null) return;
    final idx = _pages.indexWhere((p) => p.id == pageId);
    if (idx < 0) return;

    bool anyUpdated = false;

    // ── 進捗計算用に、まず「アップロード対象のファイル」を列挙する ──
    // 1 ページ内に複数の添付があると、ファイル A の進捗が 100% で報告された後、
    // ファイル B の送信が始まるが、A の進捗値だけを上に通知すると B の送信中は
    // 「99% でずっと止まっている」ように見える。
    // → 事前にファイルのバイト数合計を取り、累計バイト数 / 合計バイト数 で
    //   ページ全体の進捗を計算する。
    final List<_AttachmentToUpload> jobs = [];
    for (final nodeId in _pages[idx].nodes.keys.toList()) {
      final node = _pages[idx].nodes[nodeId];
      if (node == null) continue;
      // 画像/PDF添付
      if ((node.attachmentPath ?? '').isNotEmpty &&
          !node.attachmentPath!.startsWith('http') &&
          (node.attachmentStorageUrl ?? '').isEmpty) {
        final name = node.attachmentName ??
            node.attachmentPath!.split('/').last.split('\\').last;
        int size = 0;
        try {
          final f = File(node.attachmentPath!);
          if (await f.exists()) size = await f.length();
        } catch (_) {}
        jobs.add(_AttachmentToUpload(
            nodeId: nodeId,
            kind: _AttachmentKind.image,
            localPath: node.attachmentPath!,
            name: name,
            sizeBytes: size));
      }
      // ローカル動画ファイル
      // skipVideoUploadOnce が立っていれば動画ファイルはアップロード
      // しない (= URL のみアップロードモード)。Ctrl+S 時の選択で立つ。
      if ((node.youtubeUrl ?? '').isNotEmpty &&
          !node.youtubeUrl!.startsWith('http') &&
          !node.youtubeUrl!.startsWith('https') &&
          (node.videoStorageUrl ?? '').isEmpty &&
          !skipVideoUploadOnce) {
        final name = node.youtubeUrl!.split('/').last.split('\\').last;
        int size = 0;
        try {
          final f = File(node.youtubeUrl!);
          if (await f.exists()) size = await f.length();
        } catch (_) {}
        jobs.add(_AttachmentToUpload(
            nodeId: nodeId,
            kind: _AttachmentKind.video,
            localPath: node.youtubeUrl!,
            name: name,
            sizeBytes: size));
      }
    }

    // skipVideoUploadOnce はワンショット。動画ジョブ収集が終わったら
    // 直ちにリセットしておく (アップロード処理の途中で別ページの
    // 同期が走った場合に予期せず影響しないように)。
    skipVideoUploadOnce = false;

    // 添付なし → 即 100% を通知して終わる
    if (jobs.isEmpty) {
      onPageProgress?.call(1.0);
      return;
    }

    // 進捗計算: 全ジョブの合計バイト数を分母、各ジョブの寄与は
    // (累計済み + 現在送信中バイト) / 合計バイト
    int totalBytes = jobs.fold(0, (s, j) => s + j.sizeBytes);
    if (totalBytes <= 0) totalBytes = jobs.length; // 全ファイルが 0 byte の保険
    int completedBytes = 0;

    for (final job in jobs) {
      final node = _pages[idx].nodes[job.nodeId];
      if (node == null) {
        completedBytes += job.sizeBytes;
        continue;
      }
      _uploading[job.nodeId] = true;
      _uploadProgress[job.nodeId] = 0.0;
      notifyListeners();

      final storageUrl = await uploadAttachmentToStorage(
        job.localPath,
        job.name,
        onProgress: (p) {
          // p は単一ファイル内の 0.0〜1.0 進捗
          _uploadProgress[job.nodeId] = p;
          // ページ全体: 完了済みバイト + 現在ファイルの進捗バイト
          final size = job.sizeBytes > 0 ? job.sizeBytes : 1;
          final pageProgress =
              ((completedBytes + p * size) / totalBytes).clamp(0.0, 1.0);
          onPageProgress?.call(pageProgress);
          notifyListeners();
        },
      );

      _uploading.remove(job.nodeId);
      _uploadProgress.remove(job.nodeId);
      completedBytes += job.sizeBytes;

      if (storageUrl != null) {
        if (job.kind == _AttachmentKind.image) {
          node.attachmentStorageUrl = storageUrl;
        } else {
          node.videoStorageUrl = storageUrl;
        }
        anyUpdated = true;
      } else {
        // 添付の送信に失敗 → このページは「文字情報だけ」 がクラウドに
        //   残る状態になりかねないので、失敗フラグを立てて画面側で
        //   「完了」 ではなくエラーを出す (= 再同期を促す)。
        _lastSyncAttachmentFailed = true;
        lastUploadError = job.kind == _AttachmentKind.image
            ? 'ファイルのアップロードに失敗しました: ${job.name}'
            : '動画のアップロードに失敗しました: ${job.name}';
      }
      // ジョブ終了時点でこのジョブ分は完全に転送済みなので、
      // 進捗を「completedBytes / totalBytes」に揃える
      onPageProgress?.call((completedBytes / totalBytes).clamp(0.0, 1.0));
      notifyListeners();
    }

    // URLが更新されたらFirestoreに再保存（ループ防止のため直接PATCH）
    if (anyUpdated) {
      await _saveToStorageLocal();
      await _resyncPageToFirestore(pageId);
    }
    onPageProgress?.call(1.0);
  }

  /// ページの namedGroups 全データを JSON 文字列にシリアライズ
  String _serializeNamedGroupsForPage(String pageId) {
    final groups = _namedGroups[pageId] ?? {};
    final colors = _groupColors[pageId] ?? {};
    final fontSizes = _groupFontSizes[pageId] ?? {};
    final fontFamilies = _groupFontFamilies[pageId] ?? {};
    return jsonEncode({
      'groups': groups.map((k, v) => MapEntry(k, v.toList())),
      'colors': colors,
      'fontSizes': fontSizes.map((k, v) => MapEntry(k, v)),
      'fontFamilies': fontFamilies,
    });
  }

  /// シリアライズされた namedGroups JSON をページに適用
  void _applyNamedGroupsJson(String pageId, String jsonStr) {
    try {
      final data = jsonDecode(jsonStr) as Map<String, dynamic>;
      // groups
      final gRaw = data['groups'] as Map<String, dynamic>? ?? {};
      final groups = <String, Set<String>>{};
      for (final e in gRaw.entries) {
        groups[e.key] = Set<String>.from(e.value as List);
      }
      _namedGroups[pageId] = groups;
      // colors
      final cRaw = data['colors'] as Map<String, dynamic>? ?? {};
      _groupColors[pageId] =
          cRaw.map((k, v) => MapEntry(k, (v as num).toInt()));
      // fontSizes
      final fsRaw = data['fontSizes'] as Map<String, dynamic>? ?? {};
      _groupFontSizes[pageId] =
          fsRaw.map((k, v) => MapEntry(k, (v as num).toDouble()));
      // fontFamilies
      final ffRaw = data['fontFamilies'] as Map<String, dynamic>? ?? {};
      _groupFontFamilies[pageId] =
          ffRaw.map((k, v) => MapEntry(k, v as String));
    } catch (e) {
      debugPrint('namedGroups デシリアライズエラー: $e');
    }
  }

  /// Firestoreにページを直接再保存（_uploadPageAttachmentsからのループ防止用）
  Future<void> _resyncPageToFirestore(String pageId) async {
    if (!_firebaseEnabled || _syncGroupId == null || _idToken == null) return;
    final idx = _pages.indexWhere((p) => p.id == pageId);
    if (idx < 0) return;
    try {
      final pageJson = jsonEncode(_pages[idx].toJson());
      final url = '$_firestoreBaseUrl/groups/$_syncGroupId/pages/$pageId';
      await http.patch(
        Uri.parse('$url?updateMask.fieldPaths=json'),
        headers: {
          'Authorization': 'Bearer $_idToken',
          'Content-Type': 'application/json',
        },
        body: jsonEncode({
          'fields': {
            'json': {'stringValue': pageJson}
          },
        }),
      );
      debugPrint('Resync to Firestore OK (after upload): $pageId');
    } catch (e) {
      debugPrint('Resync to Firestore error: $e');
    }
  }

  /// リモートからフェッチしたページの添付ファイルをローカルにダウンロード
  Future<void> _downloadPageAttachments(MindMapPage page) async {
    if (!_firebaseEnabled || _syncGroupId == null) return;
    for (final node in page.nodes.values) {
      // 画像/PDF添付: Storage URLがあればそれを使ってダウンロード
      if ((node.attachmentStorageUrl ?? '').isNotEmpty) {
        final name = node.attachmentName ??
            Uri.decodeComponent(
                node.attachmentStorageUrl!.split('/').last.split('?').first);
        // ローカルにファイルがなければダウンロード
        bool needDownload = true;
        if ((node.attachmentPath ?? '').isNotEmpty) {
          final localFile = File(node.attachmentPath!);
          if (localFile.existsSync()) needDownload = false;
        }
        if (needDownload) {
          // PDF・画像も進捗付きでダウンロード (整合性検証込み)。
          // ファイル名だけ降りてきて中身が開けない不具合への対策で、
          // 100% 表示後にしか attachmentPath を更新しない。
          _uploading[node.id] = true;
          _uploadProgress[node.id] = 0.0;
          notifyListeners();
          final downloaded =
              await _downloadAttachmentWithProgress(name, node.id);
          _uploading.remove(node.id);
          _uploadProgress.remove(node.id);
          if (downloaded != null) {
            node.attachmentPath = downloaded;
          } else {
            // PDF/画像の中身が取得できなかった → 失敗フラグを立て、
            //   画面側で「完了」 ではなくエラーを出す (= 再DLを促す)。
            _lastSyncAttachmentFailed = true;
          }
          notifyListeners();
        }
      } else if ((node.attachmentPath ?? '').isNotEmpty &&
          (node.attachmentName ?? '').isNotEmpty) {
        // レガシー: Storage URLなしだが名前がある場合
        final localFile = File(node.attachmentPath!);
        if (!localFile.existsSync()) {
          _uploading[node.id] = true;
          _uploadProgress[node.id] = 0.0;
          notifyListeners();
          final downloaded = await _downloadAttachmentWithProgress(
              node.attachmentName!, node.id);
          _uploading.remove(node.id);
          _uploadProgress.remove(node.id);
          if (downloaded != null) {
            node.attachmentPath = downloaded;
          } else {
            _lastSyncAttachmentFailed = true;
          }
          notifyListeners();
        }
      }

      // 動画: Storage URLがあればそれを使ってダウンロード
      if ((node.videoStorageUrl ?? '').isNotEmpty) {
        final name = Uri.decodeComponent(node.videoStorageUrl!
            .split('/attachments%2F')
            .last
            .split('?')
            .first);
        bool needDownload = true;
        if ((node.youtubeUrl ?? '').isNotEmpty &&
            !node.youtubeUrl!.startsWith('http')) {
          final localFile = File(node.youtubeUrl!);
          if (localFile.existsSync()) needDownload = false;
        }
        if (needDownload) {
          _uploading[node.id] = true;
          _uploadProgress[node.id] = 0.0;
          notifyListeners();

          final downloaded = await _downloadAttachmentWithProgress(
            name,
            node.id,
          );

          _uploading.remove(node.id);
          _uploadProgress.remove(node.id);

          if (downloaded != null) {
            node.youtubeUrl = downloaded;
          }
          notifyListeners();
        }
      } else if ((node.youtubeUrl ?? '').isNotEmpty &&
          !node.youtubeUrl!.startsWith('http') &&
          !node.youtubeUrl!.startsWith('https')) {
        // レガシー: ローカルパスだがファイルがない場合
        final localFile = File(node.youtubeUrl!);
        if (!localFile.existsSync()) {
          final name = node.youtubeUrl!.split('/').last.split('\\').last;
          final downloaded = await downloadAttachmentFromStorage(name);
          if (downloaded != null) {
            node.youtubeUrl = downloaded;
          }
        }
      }
    }
  }

  /// 進捗付きダウンロード
  ///
  /// 整合性検証: Content-Length と受信バイト数を最後に突き合わせ、 食い違う
  /// 場合は破損とみなして部分書き込みを破棄する (downloadAttachmentFromStorage
  /// と同じ方針)。 これにより「進捗 100% 表示後にファイルが開けない」現象を
  /// 防ぐ。
  Future<String?> _downloadAttachmentWithProgress(
      String fileName, String nodeId) async {
    if (!_firebaseEnabled || _syncGroupId == null || _idToken == null)
      return null;
    try {
      final storagePath = 'groups/$_syncGroupId/attachments/$fileName';
      final encoded = Uri.encodeComponent(storagePath);
      final downloadUrl = '$_storageUploadUrl/$encoded?alt=media';

      final request = http.Request('GET', Uri.parse(downloadUrl));
      request.headers['Authorization'] = 'Bearer $_idToken';
      final streamedRes = await request.send();

      if (streamedRes.statusCode == 200) {
        final contentLength = streamedRes.contentLength ?? 0;
        final appDir = await getApplicationDocumentsDirectory();
        final attachDir = Directory('${appDir.path}/attachments');
        if (!await attachDir.exists()) {
          await attachDir.create(recursive: true);
        }
        final localPath = '${attachDir.path}/$fileName';
        // 一旦 .part に書く (途中ファイルが UI から参照されないように)
        final tempPath = '$localPath.part';
        final sink = File(tempPath).openWrite();
        int received = 0;
        bool sinkOk = true;

        try {
          await for (final chunk in streamedRes.stream) {
            sink.add(chunk);
            received += chunk.length;
            // 進捗報告は実際のバイト数のみで進める。 95% 以上には乗せず、
            // 残りはサーバー応答クローズ + flush + rename の確定後に
            // 100% へ進める (Upload 側と同じ思想)。
            if (contentLength > 0) {
              _uploadProgress[nodeId] =
                  (received / contentLength * 0.95).clamp(0.0, 0.95);
              notifyListeners();
            }
          }
        } catch (e) {
          debugPrint('Storage download stream error: $e');
          sinkOk = false;
        } finally {
          // flush で OS バッファまで吐き出してから close。
          // close は flush も内部で行うが、 念のため明示する
          // (古い実装で「close は呼んだが書き込み中のチャンクが残る」
          //  ように見える挙動があったため)。
          try {
            await sink.flush();
          } catch (_) {}
          await sink.close();
        }

        if (!sinkOk) {
          try {
            await File(tempPath).delete();
          } catch (_) {}
          return null;
        }

        // ── サイズ検証 ──
        final tempFile = File(tempPath);
        final writtenLen = await tempFile.length();
        if (writtenLen == 0) {
          debugPrint('Storage download: empty file for $fileName');
          try {
            await tempFile.delete();
          } catch (_) {}
          return null;
        }
        if (contentLength > 0 && writtenLen != contentLength) {
          debugPrint(
              'Storage download size mismatch: $fileName expected=$contentLength written=$writtenLen');
          try {
            await tempFile.delete();
          } catch (_) {}
          return null;
        }

        // 旧ファイルを置き換え (Windows では既存ファイルがあると
        // rename が失敗するので先に削除)
        final finalFile = File(localPath);
        if (await finalFile.exists()) {
          try {
            await finalFile.delete();
          } catch (_) {}
        }
        await tempFile.rename(localPath);

        _uploadProgress[nodeId] = 1.0;
        notifyListeners();

        debugPrint(
            'Storage download OK: $fileName → $localPath ($writtenLen bytes)');
        return localPath;
      } else {
        debugPrint('Storage download: ${streamedRes.statusCode} ($fileName)');
        return null;
      }
    } catch (e) {
      debugPrint('Storage download error: $e');
      return null;
    }
  }

  /// 手動: 選択したページをクラウドにアップロード
  bool _isUploading = false;
  bool get isUploading => _isUploading;
  // ── 連打ガードのフラグが「死んだまま」 残って永久ブロックするのを防ぐ ──
  // (= ユーザー報告: 連打無効化を入れた辺りから Ctrl+S/D が効かなくなった)。
  // フラグを立てた時刻を記録し、 一定時間 (3 分) 経っても解除されていなければ
  // 前の処理は死んだものとみなして新しい操作を許可する。
  DateTime? _uploadStartedAt;
  DateTime? _downloadStartedAt;
  static const Duration _kSyncStaleAfter = Duration(minutes: 3);

  /// 進行中とされる同期が「生きている (= まだタイムアウト範囲内)」 か。
  /// どちらも生きていなければ stale とみなしてガードを解除してよい。
  bool _syncFlagsAreStale() {
    final now = DateTime.now();
    final upAlive = _isUploading &&
        _uploadStartedAt != null &&
        now.difference(_uploadStartedAt!) <= _kSyncStaleAfter;
    final downAlive = _isDownloading &&
        _downloadStartedAt != null &&
        now.difference(_downloadStartedAt!) <= _kSyncStaleAfter;
    return !(upAlive || downAlive);
  }

  // ── Esc で同期 (アップロード/ダウンロード) を中断する (= ユーザー要望) ──
  // ループ各ページの先頭でこのフラグを見て break する。
  bool _syncCancelRequested = false;
  bool get isSyncing => _isUploading || _isDownloading;
  void cancelSync() {
    if (_isUploading || _isDownloading) {
      _syncCancelRequested = true;
      _syncStatusText = 'キャンセル中…';
      notifyListeners();
    }
  }

  double _syncProgress = 0.0;
  double get syncProgress => _syncProgress;
  String _syncStatusText = '';
  String get syncStatusText => _syncStatusText;

  Future<void> uploadToCloud(List<String> pageIds) async {
    // ── 連打/二重実行ガード (= ユーザー要望: Ctrl+S を連打しても、 最初の
    //    アップロードが完了するまで以降を無視する) ──
    if (_isUploading || _isDownloading) {
      // 生きている同期がある間だけブロック。 死んだフラグ (stale) なら解除して続行。
      if (!_syncFlagsAreStale()) return;
      _isUploading = false;
      _isDownloading = false;
    }
    if (!_firebaseEnabled || _syncGroupId == null) {
      throw Exception('同期グループに参加してください');
    }
    // await の前にフラグを立てて再入を防ぐ。
    _isUploading = true;
    _uploadStartedAt = DateTime.now();
    _syncCancelRequested = false;
    _syncProgress = 0.0;
    _lastSyncAttachmentFailed = false; // この同期での添付転送失敗を初期化
    _lastSyncLimitMessage = null; // 上限到達メッセージも初期化
    notifyListeners();
    try {
      // ── ネットワークが固まると 0% から進まなくなる対策 (= ユーザー要望:
      //    Ctrl+S で転送が 0% から永遠に変わらない) ──
      // タイムアウトを付けて、 ハングではなくエラーで finally に抜けて進捗を
      // リセットする (= バーが永久に 0% で止まらない)。
      await _ensureFreshToken().timeout(const Duration(seconds: 25));
      // メンバーのハートビート更新は「おまけ」 なので、 失敗しても
      // アップロード本体は続行する (= ハートビートのタイムアウトで
      // アップロードが止まらないように) (= ユーザー報告)。
      try {
        await _registerMember(_syncGroupId!)
            .timeout(const Duration(seconds: 25));
      } catch (e) {
        debugPrint('registerMember failed (continuing upload): $e');
      }
      for (int i = 0; i < pageIds.length; i++) {
        if (_syncCancelRequested) break; // Esc でキャンセル
        final pageId = pageIds[i];
        final idx = _pages.indexWhere((p) => p.id == pageId);
        if (idx < 0) continue;
        _syncStatusText =
            '${_pages[idx].name} をアップロード中... (${i + 1}/${pageIds.length})';
        // 各ページに「全体の進捗の 1/pageIds.length 分」を割り当てる。
        // ページ内の添付ファイル送信進捗 (0.0〜1.0) を、その配分内に
        // マッピングして反映する。これによりバーが「90% で長時間止まって
        // から突然 100% & Complete」になる問題を解消し、巨大な動画ファイル
        // でも実際のバイト送信進捗に追従するようになる。
        final pageBase = i / pageIds.length;
        final pageSlice = 1.0 / pageIds.length;
        _syncProgress = pageBase;
        notifyListeners();
        await _savePageToFirestore(pageId, onPageProgress: (p) {
          // p は 0.0〜1.0 のページ内進捗。全体に変換して syncProgress を更新。
          _syncProgress = (pageBase + p * pageSlice).clamp(0.0, 1.0);
          notifyListeners();
        });
      }
      _syncProgress = 1.0;
      _syncStatusText = '';
      notifyListeners();
    } finally {
      _isUploading = false;
      _syncProgress = 0.0;
      _syncStatusText = '';
      notifyListeners();
    }
  }

  /// 手動: 現在のページをクラウドにアップロード
  Future<void> syncCurrentPageToCloud() async {
    if (!_firebaseEnabled || _syncGroupId == null) {
      throw Exception('同期グループに参加してください');
    }
    await _ensureFreshToken();
    await _savePageToFirestore(currentPage.id);
  }

  /// Ctrl+R: クラウドと比較して新しければ現在ページをダウンロード
  /// 戻り値: 'downloaded' | 'up_to_date' | 'not_synced' | 'error:...'
  /// 現在のマップが前回アップロード時から内容が変わっているか (= 差分があるか)。
  /// ページ内容のハッシュを前回アップロード時のものと比較する (= ユーザー要望:
  /// Ctrl+S で差分だけアップロード。 変わっていなければアップロードをスキップ)。
  Future<bool> isCurrentPageUploadNeeded() async {
    try {
      final pageId = currentPage.id;
      final h = jsonEncode(currentPage.toJson()).hashCode.toString();
      final prefs = await SharedPreferences.getInstance();
      final stored = prefs.getString('page_uploaded_hash_$pageId');
      if (stored == null) return true; // 未記録 → アップロードが必要
      return stored != h; // 変わっていれば必要
    } catch (_) {
      return true; // 不明なときは安全側でアップロード
    }
  }

  Future<String> autoSyncCurrentPage() async {
    if (!isSyncEnabled) return 'not_synced';
    try {
      if (!_firebaseEnabled || _idToken == null) {
        try {
          await _initFirebase();
        } catch (_) {}
      }
      await _ensureFreshToken();
      final pageId = currentPage.id;
      final url = '$_firestoreBaseUrl/groups/$_syncGroupId/pages/$pageId';
      final res = await http.get(
        Uri.parse(url),
        headers: {'Authorization': 'Bearer $_idToken'},
      );
      if (res.statusCode != 200) return 'not_synced';
      final data = jsonDecode(res.body) as Map<String, dynamic>;
      // Firestoreドキュメントの最終更新時刻 = 最後にアップロードされた時刻
      final cloudUpdateTimeStr = data['updateTime'] as String?;
      if (cloudUpdateTimeStr == null) return 'up_to_date';
      final cloudUpdateTime = DateTime.tryParse(cloudUpdateTimeStr);
      if (cloudUpdateTime == null) return 'up_to_date';
      // ローカルの最終アップロード日時
      final prefs = await SharedPreferences.getInstance();
      final localUploadedStr = prefs.getString('page_uploaded_$pageId');
      final localUploadedAt =
          localUploadedStr != null ? DateTime.tryParse(localUploadedStr) : null;
      // クラウドの方が新しい場合のみダウンロード
      if (localUploadedAt == null || cloudUpdateTime.isAfter(localUploadedAt)) {
        // undo履歴に積む（Ctrl+Zで戻れるように）
        _undoStacks.putIfAbsent(pageId, () => []);
        _redoStacks.putIfAbsent(pageId, () => []);
        final groups = _namedGroups[pageId] ?? {};
        _undoStacks[pageId]!.add(_PageSnapshot.from(currentPage, groups));
        if (_undoStacks[pageId]!.length > _maxHistory) {
          _undoStacks[pageId]!.removeAt(0);
        }
        _redoStacks[pageId]!.clear();
        // ページデータを適用
        final fields = data['fields'] as Map<String, dynamic>? ?? {};
        final jsonStr = _firestoreStr(fields['json']);
        if (jsonStr == null) return 'up_to_date';
        final cloudPage =
            MindMapPage.fromJson(jsonDecode(jsonStr) as Map<String, dynamic>);
        final idx = _pages.indexWhere((p) => p.id == pageId);
        if (idx >= 0) {
          _pages[idx].name = cloudPage.name;
          _pages[idx].nodes
            ..clear()
            ..addAll(cloudPage.nodes);
          _pages[idx].connections
            ..clear()
            ..addAll(cloudPage.connections);
        }
        final ngJson = _firestoreStr(fields['namedGroupsJson']);
        if (ngJson != null && ngJson.isNotEmpty) {
          _applyNamedGroupsJson(pageId, ngJson);
        }
        await _saveToStorageLocal();
        await _saveNamedGroups();
        // アップロード日時をクラウドのupdateTimeに合わせる
        await prefs.setString('page_uploaded_$pageId', cloudUpdateTimeStr);
        notifyListeners();
        return 'downloaded';
      }
      return 'up_to_date';
    } catch (e) {
      return 'error:$e';
    }
  }

  /// 画面を強制再描画（互換用）
  void refresh() => notifyListeners();

  /// 手動: クラウドからページ一覧を取得（ダウンロードせずにリスト返却）
  Future<List<MindMapPage>> fetchCloudPageList({bool retried = false}) async {
    if (!_firebaseEnabled || _syncGroupId == null) {
      throw Exception('同期グループに参加してください');
    }
    await _ensureFreshToken();
    final url = '$_firestoreBaseUrl/groups/$_syncGroupId/pages';
    // タイムアウト無しだと「読み込み中」 のまま固まる (= ユーザー報告)。
    final res = await http.get(
      Uri.parse(url),
      headers: {'Authorization': 'Bearer $_idToken'},
    ).timeout(const Duration(seconds: 60),
        onTimeout: () => throw Exception('クラウド一覧の取得がタイムアウトしました (60秒)。通信環境、 または'
            'クラウド上のページ数/サイズが大きすぎないか確認してください。'));
    if ((res.statusCode == 401 || res.statusCode == 403) && !retried) {
      // トークンをリフレッシュしてリトライ (401/403 は必ず再取得)
      await _ensureFreshToken(force: true);
      return fetchCloudPageList(retried: true);
    }
    if (res.statusCode != 200) {
      if (res.statusCode == 403) {
        throw Exception('アクセス権限エラー(403)。Firebase ConsoleでFirestoreルールを確認してください。'
            'プロジェクト「$_firestoreProjectId」のルールタブで read/write を許可してください。');
      }
      throw Exception('データ取得失敗: ${res.statusCode}');
    }
    final data = jsonDecode(res.body) as Map<String, dynamic>;
    final docs = data['documents'] as List<dynamic>? ?? [];
    final result = <MindMapPage>[];
    _cloudPageGroupsCache.clear();
    final now = DateTime.now().toUtc();
    for (final doc in docs) {
      try {
        final fields = doc['fields'] as Map<String, dynamic>;
        // ── 期限切れチェック (無料プランで 7 日経過) ──
        // Firestore TTL ポリシーが完全に動くまでのフェイルセーフ。
        // expiresAt が過去ならクライアント側でも無視 + 即削除を試みる。
        final expiresAtStr = _firestoreStr(fields['expiresAt']);
        if (expiresAtStr != null && expiresAtStr.isNotEmpty) {
          final expiresAt = DateTime.tryParse(expiresAtStr);
          if (expiresAt != null && expiresAt.isBefore(now)) {
            // 期限切れドキュメントは結果に含めない + バックエンドからも削除
            try {
              final docName = doc['name'] as String?;
              if (docName != null && docName.isNotEmpty) {
                // doc['name'] は "projects/.../documents/groups/.../pages/PAGE_ID"
                // 形式。Firestore REST API で DELETE する。
                final deleteUrl =
                    'https://firestore.googleapis.com/v1/$docName';
                http.delete(
                  Uri.parse(deleteUrl),
                  headers: {'Authorization': 'Bearer $_idToken'},
                ).catchError((_) {
                  // 削除失敗は無視 (TTL ポリシーで後ほど消える)
                  return http.Response('', 0);
                });
              }
            } catch (_) {}
            continue;
          }
        }
        final jsonStr = _firestoreStr(fields['json']);
        if (jsonStr == null) continue;
        final pageData = jsonDecode(jsonStr) as Map<String, dynamic>;
        final page = MindMapPage.fromJson(pageData);
        // namedGroups を一時キャッシュ
        final ngJson = _firestoreStr(fields['namedGroupsJson']);
        if (ngJson != null && ngJson.isNotEmpty) {
          _cloudPageGroupsCache[page.id] = ngJson;
        }
        result.add(page);
      } catch (_) {}
    }
    return result;
  }

  /// 手動: 選択したクラウドページをダウンロード（ローカルに追加or上書き）
  bool _isDownloading = false;
  bool get isDownloading => _isDownloading;

  Future<void> downloadFromCloud(
      List<MindMapPage> cloudPages, List<String> selectedIds) async {
    // ── 連打/二重実行ガード (= ユーザー要望: Ctrl+D を連打しても、 最初の
    //    ダウンロードが完了するまで以降を無視する) ──
    if (_isUploading || _isDownloading) {
      // 生きている同期がある間だけブロック。 死んだフラグ (stale) なら解除して続行。
      if (!_syncFlagsAreStale()) return;
      _isUploading = false;
      _isDownloading = false;
    }
    if (!_firebaseEnabled || _syncGroupId == null) {
      throw Exception('同期グループに参加してください');
    }
    // await の前にフラグを立てて再入を防ぐ。
    _isDownloading = true;
    _downloadStartedAt = DateTime.now();
    _syncCancelRequested = false;
    _syncProgress = 0.0;
    _lastSyncAttachmentFailed = false; // この同期での添付転送失敗を初期化
    _lastSyncLimitMessage = null; // 上限到達メッセージも初期化
    notifyListeners();
    try {
      // メンバーのハートビート更新は「おまけ」 なので、 失敗しても
      // ダウンロード本体は続行する (= ユーザー報告: ハートビート失敗で
      // ダウンロードが止まらないように)。
      try {
        await _registerMember(_syncGroupId!)
            .timeout(const Duration(seconds: 25));
      } catch (e) {
        debugPrint('registerMember failed (continuing download): $e');
      }
      // ── ダウンロード前に上書き対象ページをUndo履歴に積む ──
      for (final pageId in selectedIds) {
        final idx = _pages.indexWhere((p) => p.id == pageId);
        if (idx >= 0) {
          final page = _pages[idx];
          _undoStacks.putIfAbsent(pageId, () => []);
          _redoStacks.putIfAbsent(pageId, () => []);
          final groups = _namedGroups[pageId] ?? {};
          _undoStacks[pageId]!.add(_PageSnapshot.from(page, groups));
          if (_undoStacks[pageId]!.length > _maxHistory) {
            _undoStacks[pageId]!.removeAt(0);
          }
          _redoStacks[pageId]!.clear();
        }
      }
      final selected =
          cloudPages.where((p) => selectedIds.contains(p.id)).toList();
      for (int i = 0; i < selected.length; i++) {
        if (_syncCancelRequested) break; // Esc でキャンセル
        final page = selected[i];
        _syncStatusText =
            '${page.name} をダウンロード中... (${i + 1}/${selected.length})';
        _syncProgress = i / selected.length;
        notifyListeners();
        // 添付ファイルをダウンロード
        await _downloadPageAttachments(page);
        // ローカルに反映
        final idx = _pages.indexWhere((p) => p.id == page.id);
        if (idx < 0) {
          _pages.add(page);
        } else {
          _pages[idx].name = page.name;
          _pages[idx].nodes
            ..clear()
            ..addAll(page.nodes);
          _pages[idx].connections
            ..clear()
            ..addAll(page.connections);
        }
        // 付箋（namedGroups）をキャッシュから復元
        final cachedNg = _cloudPageGroupsCache[page.id];
        if (cachedNg != null && cachedNg.isNotEmpty) {
          _applyNamedGroupsJson(page.id, cachedNg);
        }
      }
      _syncProgress = 1.0;
      _syncStatusText = '';
      await _saveToStorageLocal();
      await _saveNamedGroups(); // 付箋情報も永続化
      notifyListeners();
    } finally {
      _isDownloading = false;
      _syncProgress = 0.0;
      _syncStatusText = '';
      notifyListeners();
    }
  }

  /// クラウド上の指定ページを削除
  Future<void> deleteCloudPages(List<String> pageIds) async {
    if (!_firebaseEnabled || _syncGroupId == null) {
      throw Exception('同期グループに参加してください');
    }
    await _ensureFreshToken();
    for (final pageId in pageIds) {
      final url = '$_firestoreBaseUrl/groups/$_syncGroupId/pages/$pageId';
      final res = await http.delete(
        Uri.parse(url),
        headers: {'Authorization': 'Bearer $_idToken'},
      );
      if (res.statusCode != 200 && res.statusCode != 204) {
        debugPrint('クラウド削除エラー (pageId=$pageId): ${res.statusCode}');
      }
    }
  }

  // ─── マップ容量計算 ───────────────────────────────────────────────────
  /// マップ（ページ）の合計データサイズをバイト単位で返す
  /// JSON + ローカル存在するファイル（添付・動画・サムネイル）の合計
  int calculatePageSizeBytes(MindMapPage page) {
    int total = 0;
    try {
      total += utf8.encode(jsonEncode(page.toJson())).length;
    } catch (_) {}
    for (final node in page.nodes.values) {
      // 添付ファイル（画像・PDF等）
      final ap = node.attachmentPath ?? '';
      if (ap.isNotEmpty && !ap.startsWith('http')) {
        try {
          final f = File(ap);
          if (f.existsSync()) total += f.lengthSync();
        } catch (_) {}
      }
      // 動画サムネイル
      final vth = node.videoThumbnailPath ?? '';
      if (vth.isNotEmpty) {
        try {
          final f = File(vth);
          if (f.existsSync()) total += f.lengthSync();
        } catch (_) {}
      }
      // ローカル動画ファイル（mp4等が youtubeUrl にローカルパスで入る場合）
      final yu = node.youtubeUrl ?? '';
      if (yu.isNotEmpty && !yu.startsWith('http') && !yu.startsWith('https')) {
        try {
          final f = File(yu);
          if (f.existsSync()) total += f.lengthSync();
        } catch (_) {}
      }
    }
    return total;
  }

  /// バイト数を読みやすい単位 (B / KB / MB / GB) に整形
  static String formatBytes(int bytes) {
    if (bytes < 1024) return '$bytes B';
    if (bytes < 1024 * 1024) {
      return '${(bytes / 1024).toStringAsFixed(1)} KB';
    }
    if (bytes < 1024 * 1024 * 1024) {
      return '${(bytes / (1024 * 1024)).toStringAsFixed(1)} MB';
    }
    return '${(bytes / (1024 * 1024 * 1024)).toStringAsFixed(2)} GB';
  }

  /// クラウドページの合計サイズ（バイト）を取得（HEADで実ファイルサイズも合算）
  /// 重い処理なのでダウンロードダイアログで一度だけ呼ぶ想定
  Future<int> fetchCloudPageSizeBytes(MindMapPage page) async {
    int total = 0;
    try {
      total += utf8.encode(jsonEncode(page.toJson())).length;
    } catch (_) {}
    if (_idToken == null) return total;
    // 重複URLを排除
    final urls = <String>{};
    for (final node in page.nodes.values) {
      final asu = node.attachmentStorageUrl ?? '';
      if (asu.isNotEmpty) urls.add(asu);
      final vsu = node.videoStorageUrl ?? '';
      if (vsu.isNotEmpty) urls.add(vsu);
    }
    for (final u in urls) {
      try {
        final res = await http.head(
          Uri.parse(u),
          headers: {'Authorization': 'Bearer $_idToken'},
        );
        final cl = res.headers['content-length'];
        if (cl != null) {
          final n = int.tryParse(cl);
          if (n != null) total += n;
        }
      } catch (_) {}
    }
    return total;
  }

  @override
  void dispose() {
    _syncTimer?.cancel();
    super.dispose();
  }

  /// ★ 起動ハング対策 (= ユーザー報告: Android で「ずっと読み込み中」のまま) ★
  /// 画面は `pages.isEmpty` の間ずっとローディング (くるくる) を出すので、
  /// この関数が「何があっても」必ず最後に pages を 1 枚以上にして
  /// notifyListeners() を呼ぶことが死活的に重要。 そのため:
  ///   1. 全体を try/catch で囲み、 例外が外へ漏れて Future が reject されない
  ///      (= reject すると constructor 側で notify されず永久ローディング) ようにする。
  ///   2. ページは 1 枚ずつ独立にパースし、 1 枚壊れても残りは読む
  ///      (= 旧実装は途中で throw すると全ページ破棄 → データ全消失だった)。
  ///   3. クラウド/ディスク保存 (_saveToStorage) は notifyListeners の「後」に
  ///      await せず行う (= ネットワーク待ちで UI が出ないのを防ぐ)。
  Future<void> _loadFromStorage() async {
    try {
      // フォルダー一覧を先に読む（ページ読み込み時に検証で使う）。
      // ここで失敗してもページ読み込みは続行する。
      try {
        await _loadFoldersFromStorage();
      } catch (_) {}

      final prefs = await SharedPreferences.getInstance();

      // v3 → 失敗(0枚)なら v2 から移行。 いずれも 1 枚ずつ復元する。
      bool loaded = _tryLoadPagesFrom(prefs.getString(_storageKey));
      bool migratedFromV2 = false;
      if (!loaded) {
        loaded = _tryLoadPagesFrom(prefs.getString('mindmap_pages_v2'));
        migratedFromV2 = loaded;
      }

      final bool freshOrEmpty = _pages.isEmpty;
      if (freshOrEmpty) _addDefaultPage();
      _currentPageIndex = 0;

      // ★ まず UI を出す（ここまで来れば必ず pages は 1 枚以上）。
      notifyListeners();

      // v2 からの移行 / 新規デフォルト作成時のみ、 UI 表示後に保存する
      // (await しない = ネットワーク自動同期で起動が固まらないように)。
      if (migratedFromV2 || freshOrEmpty) {
        // ignore: discarded_futures
        _saveToStorage();
      }
    } catch (e, st) {
      debugPrint('_loadFromStorage 致命的エラー (ローディング固まり防止のため復旧): $e\n$st');
      // 最後の砦: 何が起きても使える UI を保証する。
      if (_pages.isEmpty) {
        try {
          _addDefaultPage();
        } catch (_) {}
        _currentPageIndex = 0;
      }
      notifyListeners();
    }
  }

  /// 保存済みページ JSON 文字列を 1 ページずつ `_pages` に復元する。
  /// 1 ページの fromJson が throw しても、 そのページだけスキップして残りを
  /// 読む (= 1 枚の破損で全データを失わない)。 1 枚以上読めたら true。
  bool _tryLoadPagesFrom(String? jsonStr) {
    if (jsonStr == null || jsonStr.isEmpty) return false;
    List<dynamic> list;
    try {
      final decoded = jsonDecode(jsonStr);
      if (decoded is! List) return false;
      list = decoded;
    } catch (_) {
      return false;
    }
    final int before = _pages.length;
    for (final item in list) {
      try {
        _pages.add(MindMapPage.fromJson(item as Map<String, dynamic>));
      } catch (e) {
        debugPrint('破損ページをスキップ: $e');
      }
    }
    if (_pages.length > before) {
      // 存在しないフォルダーIDを参照しているページは folderId を null に戻す
      _sanitizePageFolderIds();
      return true;
    }
    return false;
  }

  /// フォルダー一覧を SharedPreferences から読み込み
  Future<void> _loadFoldersFromStorage() async {
    final prefs = await SharedPreferences.getInstance();
    final raw = prefs.getString(_foldersStorageKey);
    if (raw == null) return;
    try {
      final List<dynamic> list = jsonDecode(raw) as List<dynamic>;
      _folders.clear();
      for (final item in list) {
        _folders.add(MindMapFolder.fromJson(item as Map<String, dynamic>));
      }
    } catch (_) {}
  }

  /// フォルダー一覧の保存
  Future<void> _saveFoldersToStorage() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString(_foldersStorageKey,
        jsonEncode(_folders.map((f) => f.toJson()).toList()));
  }

  /// 存在しないフォルダーIDを参照しているページの folderId を null に戻す
  void _sanitizePageFolderIds() {
    final ids = _folders.map((f) => f.id).toSet();
    for (final p in _pages) {
      if (p.folderId != null && !ids.contains(p.folderId)) {
        p.folderId = null;
      }
    }
  }

  Future<void> _loadFontSettings() async {
    final prefs = await SharedPreferences.getInstance();
    defaultTitleFontSize = prefs.getDouble('defaultTitleFontSize') ?? 15.0;
    defaultMemoFontSize = prefs.getDouble('defaultMemoFontSize') ?? 12.0;
    _snapEnabled = prefs.getBool('snapEnabled') ?? true;
    // メモ欄一括折りたたみ (デフォルト false = 従来通り全文表示)
    _memoCollapsedGlobal = prefs.getBool('memoCollapsedGlobal') ?? false;
    // 動画ノードの重複生成許可フラグ (デフォルト false)
    _allowDuplicateVideoNodes =
        prefs.getBool('allowDuplicateVideoNodes') ?? false;
    // 旧設定からの移行
    _channelMode = prefs.getString('channelMode') ??
        ((prefs.getBool('includeShorts') ?? false) ? 'both' : 'videos');
  }

  Future<void> _loadChannelFilterSettings() async {
    final prefs = await SharedPreferences.getInstance();
    _autoDeleteWatched = prefs.getBool('autoDeleteWatched') ?? false;
    // 連番オートフィル: デフォルト ON (= 親切寄り)
    _autofillSequenceEnabled = prefs.getBool('autofillSequenceEnabled') ?? true;
    _unwatchedLimit = prefs.getInt('unwatchedLimit') ?? 5;
    _minViewCount = prefs.getInt('minViewCount') ?? 0;
    _includeKeywords = prefs.getString('chFilterInclude') ?? '';
    _excludeKeywords = prefs.getString('chFilterExclude') ?? '';
    // 動画再生倍率の上限 (1.5〜16.0)
    _videoMaxRate = (prefs.getDouble('videoMaxRate') ?? 4.0).clamp(1.5, 16.0);
    // オフライン動画の左右キーのシーク秒数 (1〜60、 既定 10)
    _videoSeekSeconds = (prefs.getInt('videoSeekSeconds') ?? 10).clamp(1, 60);
    // 直近の動画再生倍率 (起動を跨いで引き継ぐ)。
    // 1.0 〜 videoMaxRate の範囲にクランプ (videoMaxRate を後から下げた
    // ケースで前回値がそれを超えていたら丸める)。
    _lastVideoPlaybackRate = (prefs.getDouble('lastVideoPlaybackRate') ?? 1.0)
        .clamp(1.0, _videoMaxRate);
    // クイック子要素生成数 (Ctrl+Shift+A) の復元
    _quickAddChildrenCount =
        (prefs.getInt('quickAddChildrenCount') ?? 5).clamp(1, 30);
    // バックグラウンド再生 (画面オフ時の継続再生) フラグ
    _backgroundPlaybackEnabled =
        prefs.getBool('backgroundPlaybackEnabled') ?? false;
    // PiP ミニプレイヤーの拡大率 (0.5〜2.0)
    _pipScale = (prefs.getDouble('pipScale') ?? 1.0).clamp(0.5, 2.0);
    // カレンダーのタイムゾーン (オプション、未設定なら null = 端末ローカル)
    if (prefs.containsKey('calendarTzOffset')) {
      _calendarTzOffsetMinutes = prefs.getInt('calendarTzOffset');
      _calendarTzLabel = prefs.getString('calendarTzLabel') ?? '';
    }
  }

  Future<void> _saveToStorage() async {
    // 現在ページの最終更新日時を更新(編集のたびに呼ばれる経路)
    if (_pages.isNotEmpty &&
        _currentPageIndex >= 0 &&
        _currentPageIndex < _pages.length) {
      _pages[_currentPageIndex].lastModifiedAt = DateTime.now();
    }
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString(
        _storageKey, jsonEncode(_pages.map((p) => p.toJson()).toList()));
    await prefs.setDouble('defaultTitleFontSize', defaultTitleFontSize);
    await prefs.setDouble('defaultMemoFontSize', defaultMemoFontSize);
    // 自動同期が有効なページがあればデバウンス付きで同期
    _triggerAutoSync();
    // ── linkedDir フォルダーへの自動書き出し ──
    // 現在のページが「ディスク連動フォルダー」に属していれば、
    // 編集内容を JSON として自動保存する。失敗しても黙殺 (UI を妨げない)。
    if (_pages.isNotEmpty &&
        _currentPageIndex >= 0 &&
        _currentPageIndex < _pages.length) {
      // await しない (UI への影響を避けるため fire-and-forget)
      autoSavePageIfLinked(_pages[_currentPageIndex].id);
    }
  }

  /// Firestoreからの受信時に使用（ループ防止のためFirestore書き込みをしない）
  Future<void> _saveToStorageLocal() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString(
        _storageKey, jsonEncode(_pages.map((p) => p.toJson()).toList()));
  }

  /// ページ種別ごとの既定名プレフィックス (= ユーザー要望: ビデオエディター
  /// なのに「マップ10」 と付くのはおかしい → 種類毎に名前/番号を付ける)。
  /// normal は従来の言語別「マップ/Map」。 それ以外は ja/en の短い接頭辞。
  static String _typePagePrefix(String pageType, String lang) {
    final ja = lang == 'ja';
    switch (pageType) {
      case 'videoEditor':
        return ja ? 'ビデオ ' : 'Video ';
      case 'paint':
        return ja ? 'ペイント ' : 'Paint ';
      case 'document':
        return ja ? 'ノート ' : 'Note ';
      case 'gantt':
        return ja ? 'ガント ' : 'Gantt ';
      case 'bookshelf':
        return ja ? 'ギャラリー ' : 'Gallery ';
      case 'aiStudio':
        return ja ? 'AI生成 ' : 'AI ';
      case 'memberSchedule':
        return ja ? '予定表 ' : 'Schedule ';
      default:
        return _defaultPageNamePrefixFor(lang);
    }
  }

  /// 同じ pageType の既存ページ数 + 1 (= 種類毎の連番)。
  int _nextTypeNumber(String pageType) {
    int c = 0;
    for (final p in _pages) {
      if (p.pageType == pageType) c++;
    }
    return c + 1;
  }

  void _addDefaultPage(
      {String? name, String? folderId, String pageType = 'normal'}) {
    // 名前が指定されていない場合は種別+言語に合わせた既定名を使う。
    // normal は従来どおり全ページ通し番号 (言語切替で自動追従)。
    // それ以外は「ビデオ N」「お絵かき N」 など種類毎の連番。
    final n =
        pageType == 'normal' ? _pages.length + 1 : _nextTypeNumber(pageType);
    final defaultName = '${_typePagePrefix(pageType, _appLanguage)}$n';
    final page = MindMapPage(
        id: _uuid.v4(),
        name: name ?? defaultName,
        folderId: folderId,
        pageType: pageType);
    // 仕様変更(2026-04):
    // メインテーマ(ルート)ノードは作成しない。完全に空のマップから開始する。
    // ユーザーは + ボタン / FAB / Ctrl+1 などで好きなノードから組み立てる。
    _pages.add(page);
  }

  void addPage({String? name, String? folderId}) {
    _addDefaultPage(name: name, folderId: folderId);
    _currentPageIndex = _pages.length - 1;
    _selectedNodeId = null;
    _saveToStorage();
    notifyListeners();
    // 新規ページが連動フォルダーに属していれば即座にディスクへ書き出す
    if (folderId != null) {
      autoSavePageIfLinked(_pages.last.id);
    }
  }

