  void switchPage(int index) {
    if (index < 0 || index >= _pages.length) return;
    _currentPageIndex = index;
    _selectedNodeId = null;
    // 最後に開いたページ ID を永続化 (起動時の復元用)
    _persistLastOpenedPageId(_pages[index].id);
    notifyListeners();
  }

  /// 最後に開いていたマップページ ID を SharedPreferences に保存。
  /// 次回起動時にこの ID で switchPage して、 前回の作業を続けられるようにする。
  Future<void> _persistLastOpenedPageId(String pageId) async {
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString('last_opened_page_id', pageId);
    } catch (_) {}
  }

  /// 起動時に last_opened_page_id を読み出して該当ページに切り替える。
  /// 該当ページが見つからない (= 削除済み等) なら 0 番目のページを開く。
  /// 初回起動 (= 保存値なし) も 0 番目を開く。
  Future<void> _restoreLastOpenedPage() async {
    try {
      // ── ホーム画面/デスクトップのショートカットから起動された場合 ──
      // そのマップ(ページ)を最優先で開く (= ユーザー要望: マップごとに
      //   アプリ風ショートカットを作って直接そのマップを開けるように)。
      final shortcutId = await HomeShortcutService.initialPageId();
      if (shortcutId != null && shortcutId.isNotEmpty) {
        final sidx = _pages.indexWhere((p) => p.id == shortcutId);
        if (sidx >= 0) {
          _currentPageIndex = sidx;
          notifyListeners();
          return;
        }
      }
      final prefs = await SharedPreferences.getInstance();
      final saved = prefs.getString('last_opened_page_id');
      if (saved == null || saved.isEmpty) return;
      final idx = _pages.indexWhere((p) => p.id == saved);
      if (idx >= 0 && idx < _pages.length) {
        _currentPageIndex = idx;
        notifyListeners();
      }
    } catch (_) {}
  }

  /// ページ ID を指定してそのページへ切り替える (ショートカットからの起動・
  /// 起動中タップで使用)。 見つからなければ何もしない。
  void openPageById(String pageId) {
    final idx = _pages.indexWhere((p) => p.id == pageId);
    if (idx >= 0 && idx < _pages.length) {
      _currentPageIndex = idx;
      _selectedNodeId = null;
      notifyListeners();
    }
  }

  void renamePage(int index, String name) {
    if (index < 0 || index >= _pages.length) return;
    _pages[index].name = name;
    _saveToStorage();
    notifyListeners();
  }

  void deletePage(int index) {
    if (_pages.length <= 1) return;
    final deletedId = _pages[index].id;
    _pages.removeAt(index);
    _currentPageIndex = _currentPageIndex.clamp(0, _pages.length - 1);
    _selectedNodeId = null;
    // AI 追加質問の文脈もページ削除と同時に消す (孤立データを残さない)
    _aiPageContexts.remove(deletedId);
    _deletePageFromFirestore(deletedId);
    _saveToStorage();
    notifyListeners();
  }

  /// ページ並び替え（Drawerからのドラッグ＆ドロップ）
  /// Ctrl+1〜9 ショートカットの「ルート(フォルダー外のページ群)」を表す
  /// 特殊な ID。実際のフォルダー ID と衝突しないよう __ プレフィックス付き。
  static const String shortcutRootSentinel = '__ROOT__';

  /// Ctrl+1〜9 ショートカットの基準フォルダーを設定する。
  /// - 通常のフォルダー ID: そのフォルダー内のページが対象
  /// - shortcutRootSentinel ('__ROOT__'): ルート (フォルダー外のページ) が対象
  /// - null: 全ページ (従来動作にリセット)
  /// フォルダー ID が無効な場合は ignore する (削除済みなど)。
  Future<void> setShortcutFolder(String? folderId) async {
    if (folderId != null &&
        folderId != shortcutRootSentinel &&
        !_folders.any((f) => f.id == folderId)) {
      return;
    }
    _shortcutFolderId = folderId;
    final prefs = await SharedPreferences.getInstance();
    if (folderId == null) {
      await prefs.remove(_kShortcutFolderId);
    } else {
      await prefs.setString(_kShortcutFolderId, folderId);
    }
    notifyListeners();
  }

  /// Ctrl+1〜9 のショートカットで切り替えるべきページを返す。
  /// _shortcutFolderId の値:
  ///   - null: ルート (フォルダー外のページ) から N 番目 ※既定動作
  ///   - shortcutRootSentinel: ルートから N 番目 (null と同じ)
  ///   - 通常のフォルダー ID: そのフォルダー内の N 番目
  ///   - 不正/削除済み ID: ルートにフォールバック
  /// 該当ページが無ければ null を返す。
  ///
  /// 既定 (null) を「ルートのみ」とすることで、ユーザーから見ると
  /// 「フォルダーの中のマップに Ctrl+1〜9 が勝手に割り振られる」事故が起きない。
  /// 個別フォルダーを基準にしたい場合は、フォルダー右クリックから
  /// 「Ctrl+1〜9 の基準にする」を選んで明示的に設定できる。
  MindMapPage? pageForShortcutSlot(int idx) {
    if (idx < 0) return null;
    // ★ ドロワーの表示順と一致させる (= ユーザー要望: 上から Ctrl+1,2,3…)。
    //   pagesInFolder はピン留め(お気に入り)を先頭に寄せる並びなので、
    //   ここでも同じ pagesInFolder を使わないと「一番上のマップに Ctrl+2」
    //   のような番号ずれが起きる。
    final List<MindMapPage> scope;
    if (_shortcutFolderId != null &&
        _shortcutFolderId != shortcutRootSentinel &&
        _folders.any((f) => f.id == _shortcutFolderId)) {
      // 指定フォルダー内のページが対象
      scope = pagesInFolder(_shortcutFolderId);
    } else {
      // null / sentinel / 不正 ID → ルート (フォルダー外) のページのみ
      scope = pagesInFolder(null);
    }
    if (idx >= scope.length) return null;
    return scope[idx];
  }

  void reorderPages(int oldIndex, int newIndex) {
    if (oldIndex < 0 || oldIndex >= _pages.length) return;
    if (newIndex > _pages.length) newIndex = _pages.length;
    if (newIndex > oldIndex) newIndex -= 1;
    if (newIndex == oldIndex) return;
    final currentId = _pages.isNotEmpty ? _pages[_currentPageIndex].id : null;
    final page = _pages.removeAt(oldIndex);
    _pages.insert(newIndex, page);
    if (currentId != null) {
      final newCurrent = _pages.indexWhere((p) => p.id == currentId);
      if (newCurrent >= 0) _currentPageIndex = newCurrent;
    }
    _saveToStorage();
    notifyListeners();
  }

  // ─── フォルダー操作 ─────────────────────────────────────────────────────
  /// フォルダー一覧（読み取り専用）
  List<MindMapFolder> get folders => List.unmodifiable(_folders);

  /// 新規フォルダーを作成して、その ID を返す
  String addFolder({String? name, String? linkedDirPath}) {
    final id = _uuid.v4();
    _folders.add(MindMapFolder(
      id: id,
      name: name ?? 'フォルダー ${_folders.length + 1}',
      linkedDirPath: linkedDirPath,
    ));
    _saveFoldersToStorage();
    notifyListeners();
    return id;
  }

  /// 既存フォルダーに連動ディレクトリを設定 / 解除する
  Future<void> setFolderLinkedDir(String folderId, String? path) async {
    final f = _folders.firstWhere((e) => e.id == folderId,
        orElse: () => MindMapFolder(id: '', name: ''));
    if (f.id.isEmpty) return;
    f.linkedDirPath = path;
    _saveFoldersToStorage();
    notifyListeners();
  }

  /// 指定フォルダーのページを連動ディレクトリへ自動書き出しする。
  /// linkedDirPath が設定されていなければ no-op。
  /// 各ページが個別の .json として保存される (ファイル名はページ名 .sanitize)。
  /// 既存ファイルは上書き。同期方向は「アプリ → ディスク」のみ。
  /// ページの toJson() 結果を「ポータブル」化する。
  /// 各ノードの attachmentPath がローカルファイル絶対パスを指している場合、
  /// そのファイルを読み込んで data:URL (base64 + mime) に変換し、JSON に
  /// 埋め込む。これにより別環境(別 PC やパスが変わった環境)でも画像/PDF
  /// が表示できるようになる。
  /// data:URL や http(s)://、空のものはそのまま。
  Future<Map<String, dynamic>> _pageToPortableJson(MindMapPage p) async {
    final json = p.toJson();
    final nodes = json['nodes'];
    if (nodes is! List) return json;
    for (final n in nodes) {
      if (n is! Map) continue;
      final path = n['attachmentPath'] as String?;
      if (path == null || path.isEmpty) continue;
      // 既に埋め込み済み or リモート URL ならスキップ
      if (path.startsWith('data:') ||
          path.startsWith('http://') ||
          path.startsWith('https://')) continue;
      try {
        final f = File(path);
        if (!await f.exists()) continue;
        final bytes = await f.readAsBytes();
        // 拡張子から MIME を推定
        final ext = path.toLowerCase().split('.').last;
        final mime = _mimeFromExt(ext);
        final b64 = base64Encode(bytes);
        n['attachmentPath'] = 'data:$mime;base64,$b64';
        // attachmentName が無ければファイル名を補完
        if ((n['attachmentName'] as String?)?.isEmpty ?? true) {
          n['attachmentName'] = path.split(Platform.pathSeparator).last;
        }
      } catch (_) {
        // 読み込み失敗はスキップ (元のパスのまま)
      }
    }
    return json;
  }

  /// 拡張子 → MIME タイプの簡易マッピング (画像/PDF/動画/オーディオ)
  String _mimeFromExt(String ext) {
    switch (ext) {
      case 'jpg':
      case 'jpeg':
        return 'image/jpeg';
      case 'png':
        return 'image/png';
      case 'gif':
        return 'image/gif';
      case 'webp':
        return 'image/webp';
      case 'svg':
        return 'image/svg+xml';
      case 'pdf':
        return 'application/pdf';
      case 'mp4':
        return 'video/mp4';
      case 'webm':
        return 'video/webm';
      case 'mov':
        return 'video/quicktime';
      case 'mp3':
        return 'audio/mpeg';
      case 'wav':
        return 'audio/wav';
      case 'zip':
        return 'application/zip';
      case 'json':
        return 'application/json';
      case 'txt':
        return 'text/plain';
      case 'csv':
        return 'text/csv';
    }
    return 'application/octet-stream';
  }

  Future<void> syncFolderToLinkedDir(String folderId) async {
    final f = _folders.firstWhere((e) => e.id == folderId,
        orElse: () => MindMapFolder(id: '', name: ''));
    if (f.id.isEmpty) return;
    final dirPath = f.linkedDirPath;
    if (dirPath == null) return;
    try {
      final dir = Directory(dirPath);
      if (!await dir.exists()) return;
      for (final p in _pages.where((e) => e.folderId == folderId)) {
        // ページ名から不正文字を除去してファイル名に
        var safeName = p.name.replaceAll(RegExp(r'[\\/:*?"<>|]'), '_').trim();
        if (safeName.isEmpty) safeName = p.id;
        final filePath = '$dirPath${Platform.pathSeparator}$safeName.json';
        // 単一ページを { pages: [...] } 形式で書き出す。
        // 画像/PDF などの添付は data:URL として埋め込み (ポータブル化)。
        final pageJson = await _pageToPortableJson(p);
        final json = jsonEncode({
          'version': 3,
          'pages': [pageJson],
        });
        await File(filePath).writeAsString(json);
      }
    } catch (e) {
      debugPrint('syncFolderToLinkedDir failed: $e');
    }
  }

  /// 指定ページが「連動ディレクトリのフォルダー」に所属しているなら、
  /// そのページだけを単独で保存する。新規ページ作成 / 編集後に呼ばれる。
  Future<void> autoSavePageIfLinked(String pageId) async {
    final p = _pages.firstWhere((e) => e.id == pageId,
        orElse: () => MindMapPage(id: '', name: ''));
    if (p.id.isEmpty || p.folderId == null) return;
    final f = _folders.firstWhere((e) => e.id == p.folderId,
        orElse: () => MindMapFolder(id: '', name: ''));
    if (f.id.isEmpty || f.linkedDirPath == null) return;
    try {
      final dir = Directory(f.linkedDirPath!);
      if (!await dir.exists()) return;
      var safeName = p.name.replaceAll(RegExp(r'[\\/:*?"<>|]'), '_').trim();
      if (safeName.isEmpty) safeName = p.id;
      final filePath =
          '${f.linkedDirPath}${Platform.pathSeparator}$safeName.json';
      // 画像/PDF をポータブルな data:URL に埋め込んで書き出す
      final pageJson = await _pageToPortableJson(p);
      final json = jsonEncode({
        'version': 3,
        'pages': [pageJson],
      });
      await File(filePath).writeAsString(json);
    } catch (e) {
      debugPrint('autoSavePageIfLinked failed: $e');
    }
  }

  /// フォルダー名を変更
  void renameFolder(String folderId, String newName) {
    final f = _folders.firstWhere((e) => e.id == folderId,
        orElse: () => MindMapFolder(id: '', name: ''));
    if (f.id.isEmpty) return;
    f.name = newName;
    _saveFoldersToStorage();
    notifyListeners();
  }

  /// フォルダーの展開/折り畳み状態を切り替え
  void toggleFolderExpanded(String folderId) {
    final f = _folders.firstWhere((e) => e.id == folderId,
        orElse: () => MindMapFolder(id: '', name: ''));
    if (f.id.isEmpty) return;
    f.expanded = !f.expanded;
    _saveFoldersToStorage();
    notifyListeners();
  }

  /// フォルダーを削除（中のページはルートに戻す。中身のページは削除しない）
  void deleteFolder(String folderId, {bool deletePages = false}) {
    final idx = _folders.indexWhere((e) => e.id == folderId);
    if (idx < 0) return;
    if (deletePages) {
      // フォルダー内のページも削除
      final toDelete = _pages.where((p) => p.folderId == folderId).toList();
      for (final p in toDelete) {
        final i = _pages.indexOf(p);
        if (i >= 0 && _pages.length > 1) {
          _pages.removeAt(i);
          _deletePageFromFirestore(p.id);
        }
      }
      _currentPageIndex = _currentPageIndex.clamp(0, _pages.length - 1);
    } else {
      // 中のページはルートに戻す
      for (final p in _pages) {
        if (p.folderId == folderId) p.folderId = null;
      }
    }
    _folders.removeAt(idx);
    // 削除したフォルダーが Ctrl+1〜9 の基準なら null にリセット
    if (_shortcutFolderId == folderId) {
      _shortcutFolderId = null;
      SharedPreferences.getInstance()
          .then((prefs) => prefs.remove(_kShortcutFolderId));
    }
    _saveFoldersToStorage();
    _saveToStorage();
    notifyListeners();
  }

  /// 複数のフォルダー & ページを一括削除する。
  /// - フォルダー削除時、その中のページも一緒に削除
  /// - 既存の deleteFolder/deletePage を内部で再利用するが、notifyListeners は
  ///   最後に 1 回だけ発火する (UI のチラつき防止)
  /// - 削除後に最低 1 ページ残るよう自動で保護する
  void bulkDeletePagesAndFolders({
    required List<String> folderIds,
    required List<String> pageIds,
  }) {
    if (folderIds.isEmpty && pageIds.isEmpty) return;
    // 削除対象ページ ID を集計 (重複なし)
    final allTargetPages = <String>{};
    allTargetPages.addAll(pageIds);
    for (final fid in folderIds) {
      for (final p in _pages.where((e) => e.folderId == fid)) {
        allTargetPages.add(p.id);
      }
    }
    // ── ページ削除 ──
    // 最低 1 ページは残す (currentPage アクセスでクラッシュしないため)
    for (final pid in allTargetPages) {
      if (_pages.length <= 1) break;
      final i = _pages.indexWhere((e) => e.id == pid);
      if (i < 0) continue;
      _pages.removeAt(i);
      _deletePageFromFirestore(pid);
    }
    _currentPageIndex = _currentPageIndex.clamp(0, _pages.length - 1);
    // ── フォルダー削除 ──
    for (final fid in folderIds) {
      _folders.removeWhere((f) => f.id == fid);
      // 残ったページがそのフォルダーを参照していたらルートに戻す
      for (final p in _pages) {
        if (p.folderId == fid) p.folderId = null;
      }
    }
    // ショートカット基準フォルダーが削除されていたら null に戻す
    if (_shortcutFolderId != null && folderIds.contains(_shortcutFolderId)) {
      _shortcutFolderId = null;
      SharedPreferences.getInstance()
          .then((prefs) => prefs.remove(_kShortcutFolderId));
    }
    _saveFoldersToStorage();
    _saveToStorage();
    notifyListeners();
  }

  /// 指定ページを指定フォルダーに移動（folderId が null ならルートに戻す）
  void movePageToFolder(String pageId, String? folderId) {
    final p = _pages.firstWhere((e) => e.id == pageId,
        orElse: () => MindMapPage(id: '', name: ''));
    if (p.id.isEmpty) return;
    // 存在しないフォルダーIDなら拒否
    if (folderId != null && !_folders.any((f) => f.id == folderId)) {
      return;
    }
    p.folderId = folderId;
    _saveToStorage();
    notifyListeners();
    // 移動先が連動フォルダーなら、そのページもディスクに書き出す
    if (folderId != null) autoSavePageIfLinked(pageId);
  }

  /// 複数ページを一括で指定フォルダーに移動 (notifyListeners は最後に 1 回)。
  /// drawer の複数選択 → Ctrl+G で新規フォルダー作成 → そこへ全部入れる、
  /// という操作で使用。
  void movePagesToFolder(Iterable<String> pageIds, String? folderId) {
    bool changed = false;
    final movedIds = <String>[];
    for (final id in pageIds) {
      final idx = _pages.indexWhere((e) => e.id == id);
      if (idx < 0) continue;
      if (folderId != null && !_folders.any((f) => f.id == folderId)) {
        continue;
      }
      _pages[idx].folderId = folderId;
      movedIds.add(id);
      changed = true;
    }
    if (changed) {
      _saveToStorage();
      notifyListeners();
      // 移動先が連動フォルダーなら、移動した全ページをディスクに書き出す
      if (folderId != null) {
        for (final id in movedIds) {
          autoSavePageIfLinked(id);
        }
      }
    }
  }

  /// 指定フォルダーに所属するページのリスト（ページ並び順を保持）
  List<MindMapPage> pagesInFolder(String? folderId) {
    final list = _pages.where((p) => p.folderId == folderId).toList();
    // ── ピン止め (お気に入り) されたマップを先頭に ──
    // ユーザー要望「ピンで留めたマップが一番上に出るように」 への対応。
    // 安定ソート: ピン同士・非ピン同士は元の _pages 順 (= 作成/並べ替え順)
    // を維持したまま、 ピンされたものだけをグループ先頭へ寄せる。
    if (_favoritePageIds.isEmpty) return list;
    final pinned = <MindMapPage>[];
    final others = <MindMapPage>[];
    for (final p in list) {
      if (_favoritePageIds.contains(p.id)) {
        pinned.add(p);
      } else {
        others.add(p);
      }
    }
    return [...pinned, ...others];
  }

  // ─── JSON エクスポート / インポート ─────────────────────────────────────
  /// 単一ページを JSON 文字列にエクスポート
  String exportPageAsJson(String pageId) {
    final p = _pages.firstWhere((e) => e.id == pageId,
        orElse: () => MindMapPage(id: '', name: ''));
    if (p.id.isEmpty) return '{}';
    return _jsonEncodePretty({
      'type': 'mindmap_page',
      'version': 1,
      'exportedAt': DateTime.now().millisecondsSinceEpoch,
      'page': p.toJson(),
    });
  }

  /// フォルダー（とその中のページ全部）を JSON 文字列にエクスポート
  String exportFolderAsJson(String folderId) {
    final f = _folders.firstWhere((e) => e.id == folderId,
        orElse: () => MindMapFolder(id: '', name: ''));
    if (f.id.isEmpty) return '{}';
    final pages = _pages.where((p) => p.folderId == folderId).toList();
    return _jsonEncodePretty({
      'type': 'mindmap_folder',
      'version': 1,
      'exportedAt': DateTime.now().millisecondsSinceEpoch,
      'folder': f.toJson(),
      'pages': pages.map((p) => p.toJson()).toList(),
    });
  }

  /// JSON 文字列からインポート。
  /// - 'mindmap_page' タイプ: 1 ページとして追加
  /// - 'mindmap_folder' タイプ: フォルダーを新規作成して中身ページを全部追加
  /// 戻り値: インポート結果を表す Map
  ///   { 'success': bool, 'addedPages': int, 'addedFolders': int,
  ///     'firstPageId': String?, 'message': String? }
  /// 自己完結 HTML プレビュー (= ユーザー要望のエクスポート形式) から、
  /// 埋め込まれたマップ JSON を取り出す。 生 JSON はそのまま返す。
  String _extractEmbeddedMapJson(String s) {
    final t = s.trimLeft();
    if (!t.startsWith('<')) return s; // 生 JSON
    const marker = 'id="mindmap-data"';
    final mi = s.indexOf(marker);
    if (mi < 0) return s;
    final open = s.indexOf('>', mi);
    if (open < 0) return s;
    final close = s.indexOf('</script>', open);
    if (close < 0) return s;
    return s.substring(open + 1, close).replaceAll('<\\/', '</').trim();
  }

  Map<String, dynamic> importFromJsonString(String jsonStr,
      {String? targetFolderId}) {
    try {
      // 自己完結 HTML プレビュー形式で出力された場合は埋め込み JSON を抽出。
      jsonStr = _extractEmbeddedMapJson(jsonStr);
      final dynamic raw = jsonDecode(jsonStr);
      if (raw is! Map) {
        return {
          'success': false,
          'addedPages': 0,
          'addedFolders': 0,
          'message': 'JSON が不正です',
        };
      }
      final m = raw.cast<String, dynamic>();
      final type = m['type'] as String?;
      if (type == 'mindmap_page') {
        final pageData = m['page'] as Map<String, dynamic>?;
        if (pageData == null) {
          return {
            'success': false,
            'addedPages': 0,
            'addedFolders': 0,
            'message': 'page フィールドがありません',
          };
        }
        final page = _importSinglePage(pageData, targetFolderId);
        _saveToStorage();
        notifyListeners();
        return {
          'success': true,
          'addedPages': 1,
          'addedFolders': 0,
          'firstPageId': page.id,
        };
      } else if (type == 'mindmap_folder') {
        // フォルダー新規作成
        final folderData = m['folder'] as Map<String, dynamic>?;
        final folderName = (folderData?['name'] as String?) ?? 'インポートフォルダー';
        final newFolderId = addFolder(name: folderName);
        final pageList = m['pages'] as List<dynamic>? ?? [];
        int added = 0;
        String? firstId;
        for (final item in pageList) {
          if (item is Map) {
            final p =
                _importSinglePage(item.cast<String, dynamic>(), newFolderId);
            firstId ??= p.id;
            added++;
          }
        }
        _saveToStorage();
        notifyListeners();
        return {
          'success': true,
          'addedPages': added,
          'addedFolders': 1,
          'firstPageId': firstId,
        };
      } else {
        // 単独 page オブジェクトを直接渡された場合の互換
        if (m.containsKey('nodes')) {
          final page = _importSinglePage(m, targetFolderId);
          _saveToStorage();
          notifyListeners();
          return {
            'success': true,
            'addedPages': 1,
            'addedFolders': 0,
            'firstPageId': page.id,
          };
        }
        return {
          'success': false,
          'addedPages': 0,
          'addedFolders': 0,
          'message': '未対応の type: $type',
        };
      }
    } catch (e) {
      return {
        'success': false,
        'addedPages': 0,
        'addedFolders': 0,
        'message': 'JSON 解析エラー: $e',
      };
    }
  }

  /// 内部: page JSON を読み取って _pages に追加
  MindMapPage _importSinglePage(
      Map<String, dynamic> pageJson, String? folderId) {
    var page = MindMapPage.fromJson(pageJson);
    // ID 衝突チェック: 同じ ID のページが既にあれば新しい ID を振る
    if (_pages.any((p) => p.id == page.id)) {
      // ノード/接続はそのまま、ID だけ振り直す
      final newId = _uuid.v4();
      page = MindMapPage(
        id: newId,
        name: page.name,
        nodes: page.nodes,
        connections: page.connections,
        lastModifiedAt: page.lastModifiedAt,
        folderId: folderId,
      );
    } else {
      page.folderId = folderId;
    }
    _pages.add(page);
    return page;
  }

  /// 整形済み JSON 文字列を生成（読みやすさ重視。サイズは少し大きくなる）
  String _jsonEncodePretty(Object obj) {
    const encoder = JsonEncoder.withIndent('  ');
    return encoder.convert(obj);
  }

  void selectNode(String? id) {
    _selectedNodeId = id;
    notifyListeners();
  }

  /// FABから呼ばれる：指定位置に単独ノードを追加
  void addNodeAtCenter(Offset position) {
    addNodeAtCenterReturning(position);
  }

  /// addNodeAtCenter と同じだが、生成した MindMapNode を返す
  MindMapNode addNodeAtCenterReturning(Offset position) {
    const nodeW = 160.0;
    const nodeH = 42.0;
    const gap = 24.0;
    const canvasW = 20000.0;
    const canvasH = 20000.0;
    final nodeMap = currentPage.nodes;

    Offset candidate = Offset(
      position.dx.clamp(gap, canvasW - nodeW - gap),
      position.dy.clamp(gap, canvasH - nodeH - gap),
    );
    for (int i = 0; i < 30; i++) {
      bool overlap = false;
      for (final n in nodeMap.values) {
        if (_nodesOverlap(candidate, nodeW, nodeH, n, gap)) {
          overlap = true;
          candidate = Offset(
              candidate.dx,
              (n.position.dy + n.visualHeight + gap)
                  .clamp(gap, canvasH - nodeH - gap));
          break;
        }
      }
      if (!overlap) break;
    }
    final newNode = MindMapNode(
      id: _uuid.v4(),
      title: '',
      position: candidate,
      color: _childColor(),
    );
    _pushUndo();
    nodeMap[newNode.id] = newNode;
    _selectedNodeId = newNode.id;
    // ギャラリーページなら追加直後にタイル整列 (= ユーザー要望: 自動で並ぶ)。
    _autoArrangeIfBookshelf();
    _saveToStorage();
    notifyListeners();
    return newNode;
  }

  /// 音声入力で得たタイトル群から複数ノードを一括生成する (1 つの undo)。
  /// `center` 付近に縦に積んで配置する。 戻り値は生成したノード ID 一覧。
  ///
  /// 区切り語による分割は呼び出し側 (音声入力ダイアログ) で済ませて、
  /// ここには「ノードにするタイトルの配列」 を渡す。
  List<String> addNodesFromVoice(List<String> titles, Offset center) {
    final clean =
        titles.map((t) => t.trim()).where((t) => t.isNotEmpty).toList();
    if (clean.isEmpty) return [];
    const nodeW = 160.0;
    const nodeH = 42.0;
    const gap = 16.0;
    const canvasW = 20000.0;
    const canvasH = 20000.0;
    _pushUndo();
    final ids = <String>[];
    final x = center.dx.clamp(gap, canvasW - nodeW - gap);
    double y = center.dy.clamp(gap, canvasH - nodeH - gap);
    for (final title in clean) {
      final node = MindMapNode(
        id: _uuid.v4(),
        title: title,
        position: Offset(x, y),
        color: _childColor(),
      );
      currentPage.nodes[node.id] = node;
      ids.add(node.id);
      y = (y + nodeH + gap).clamp(gap, canvasH - nodeH - gap);
    }
    if (ids.isNotEmpty) _selectedNodeId = ids.last;
    _saveToStorage();
    notifyListeners();
    return ids;
  }

  /// 関連動画を親ノードの子として一括追加する。
  /// `videos` は `[{'videoId': 'XXX', 'title': '動画タイトル'}, ...]` の List。
  /// 親ノードの右側に縦に並べて追加し、それぞれを親と接続する。
  ///
  /// 戻り値: 追加できた件数。
  int addRelatedVideoChildrenForNode(
      String parentNodeId, List<Map<String, String>> videos) {
    final parentNode = currentPage.nodes[parentNodeId];
    if (parentNode == null) return 0;
    if (videos.isEmpty) return 0;
    _pushUndo();
    const gap = 16.0;
    // 親の右隣 (200px 右) に縦に並べる
    double currentY = parentNode.position.dy;
    final List<String> newChildIds = [];
    int added = 0;
    for (final v in videos) {
      final vid = v['videoId'] ?? '';
      if (vid.isEmpty) continue;
      // 既に同じ videoId のノードがあれば重複追加しない
      final exists = currentPage.nodes.values.any((n) {
        final url = n.youtubeUrl ?? '';
        return url.contains(vid);
      });
      if (exists) continue;

      final childId = _uuid.v4();
      final title = (v['title'] ?? '').isNotEmpty ? v['title']! : 'Video';
      final child = MindMapNode(
        id: childId,
        title: title,
        position: Offset(parentNode.position.dx + 200, currentY),
        youtubeUrl: 'https://m.youtube.com/watch?v=$vid',
        contentType: NodeContentType.youtube,
        color: _childColor(),
      );
      currentPage.nodes[childId] = child;
      newChildIds.add(childId);
      currentPage.connections.add(NodeConnection(
        fromId: parentNodeId,
        fromAnchor: AnchorDirection.east,
        toId: childId,
        toAnchor: AnchorDirection.west,
      ));
      currentY += child.visualHeight + gap;
      added++;
    }
    // 親が所属しているグループに子も同じ所属で加える (チャンネル動画と同じ振る舞い)
    // `_namedGroups` は `Map<pageId, Map<groupName, Set<nodeId>>>` の構造で、
    // entry.value が直接 nodeId の Set。
    if (newChildIds.isNotEmpty) {
      final groups = _namedGroups[currentPage.id];
      if (groups != null) {
        for (final entry in groups.entries) {
          if (entry.value.contains(parentNodeId)) {
            entry.value.addAll(newChildIds);
          }
        }
      }
    }
    _saveToStorage();
    notifyListeners();
    return added;
  }

  // ─── 動画視聴中メモ → メモノードとして追加 ────────────────────────────────
  //
  /// 動画視聴中に取ったメモをマップ上に「メモノード」 として追加する。
  ///
  /// 動作:
  /// 1. 同じ動画 (= 同じ YouTube videoId、 または同じローカルファイルパス) の
  ///    既存ノードを探す。 見つかれば「親」 とみなしてその子として接続する。
  /// 2. 親が見つからなければ、 [fallbackPosition] (= 通常はビューポート中央)
  ///    に単独で配置する。
  /// 3. ノードは [NodeContentType.memo] + [memoText] で作成。 既存のメモ
  ///    レンダリング (アンバー枠 / 全文展開) がそのまま効く。
  /// 4. 親が所属するグループにも子として加える (動画ノード追加と同じ挙動)。
  ///
  /// 引数:
  /// - [memoText]: メモ本文 (必須、 空文字なら何もしない)
  /// - [videoUrl]: 親探索用の動画 URL (YouTube watch URL / m.youtube URL /
  ///   youtu.be / shorts、 またはローカルファイルパス)
  /// - [memoTitleHeader]: ノードタイトルに入れる短い見出し (例: "[3:24]")。
  ///   null や空文字ならタイトル無し。
  /// - [fallbackPosition]: 親動画ノードが見つからなかったときに配置する位置。
  ///
  /// 戻り値: 生成したメモノード。 [memoText] が空なら null を返して何もしない。
  MindMapNode? addVideoMemoNode({
    required String memoText,
    required String videoUrl,
    String? memoTitleHeader,
    required Offset fallbackPosition,
    // 画像メモ (= ユーザー要望: 動画メモに Ctrl+V で画像を貼り付け)。
    // 指定された場合、 作成したノードを画像添付ノードにする。
    String? attachmentPath,
    String? attachmentName,
  }) {
    final bool hasImage =
        attachmentPath != null && attachmentPath.trim().isNotEmpty;
    if (memoText.trim().isEmpty && !hasImage) return null;

    // ── 親動画ノード探索 ──
    // YouTube は videoId 一致、 ローカルは絶対パス完全一致で判定。
    String? extractVid(String url) {
      for (final p in [
        RegExp(r'youtu\.be/([a-zA-Z0-9_-]{11})'),
        RegExp(r'youtube\.com/watch\?.*v=([a-zA-Z0-9_-]{11})'),
        RegExp(r'youtube\.com/embed/([a-zA-Z0-9_-]{11})'),
        RegExp(r'youtube\.com/shorts/([a-zA-Z0-9_-]{11})'),
        RegExp(r'm\.youtube\.com/watch\?.*v=([a-zA-Z0-9_-]{11})'),
      ]) {
        final m = p.firstMatch(url);
        if (m != null) return m.group(1);
      }
      return null;
    }

    final targetVid = extractVid(videoUrl);
    String? parentId;
    for (final n in currentPage.nodes.values) {
      final nUrl = n.youtubeUrl ?? '';
      if (nUrl.isEmpty) continue;
      if (targetVid != null) {
        final nVid = extractVid(nUrl);
        if (nVid != null && nVid == targetVid) {
          parentId = n.id;
          break;
        }
      } else {
        // ローカル動画は完全一致で判定 (ノード側もローカルパスで保存される)
        if (nUrl == videoUrl) {
          parentId = n.id;
          break;
        }
      }
    }

    // ── 配置位置決定 ──
    Offset position;
    if (parentId != null) {
      final parent = currentPage.nodes[parentId]!;
      // 既存の子ノード数を数えて、 縦方向のオフセットを決める
      // (既に複数メモがある場合、 重ならないよう順次下にずらす)
      int existingChildren = 0;
      for (final c in currentPage.connections) {
        if (c.fromId == parentId) existingChildren++;
      }
      // colGap: 「親動画ノードの **右端** からメモノードの左端までの空間」
      // を表す絶対値 (px)。 計算式は `親左端 + 親幅 + colGap` なので、
      // 親ノードの幅 (= タイトル長やサムネ幅で変動する `node.width`) が
      // 変わってもメモは「親右端から colGap 離れた位置」 に常に配置され、
      // リンク線の長さは見かけ上一定になる。
      //
      // ユーザー要望「もう少し短く」 を受けて 220 → 100 に追加調整。
      // (旧 220 でもまだ長く感じるとの指摘)。
      const colGap = 100.0;
      // = ユーザー要望: メモを縦一列に積み続けると下に伸び続けて全体レイアウト
      //   が崩れる。 横に並べ、 1 行 (kCols 個) が埋まったら次の行へ折り返す
      //   グリッド配置にする。 既存子ノード数を index として行/列を算出。
      const int kCols = 4; // 1 行あたりのメモ数
      const double colStep = 270.0; // 横ピッチ (メモ幅240 + 余白)
      const double rowStep = 140.0; // 縦ピッチ (メモ高さ + 余白)
      final int col = existingChildren % kCols;
      final int row = existingChildren ~/ kCols;
      position = Offset(
        // 親の右端 + colGap が 1 列目の左端。 そこから col 個ぶん右へずらす。
        parent.position.dx + parent.width + colGap + col * colStep,
        parent.position.dy + row * rowStep,
      );
      // 0 〜 20000 の範囲にクランプ (キャンバス境界を超えないように)
      position = Offset(
        position.dx.clamp(20.0, 20000.0 - 240.0),
        position.dy.clamp(20.0, 20000.0 - 100.0),
      );
    } else {
      // ── 親動画ノードが無い場合 (= 動画がマップ上にノードとして存在しない) ──
      // 以前は呼び出し側の fallbackPosition (画面外の遠い固定座標) に置いて
      // いたため「追加できない (見えない所に行く)」 状態だった。 既存ノードの
      // 中心付近の見える位置に単独メモノードとして置く
      // (= ユーザー要望: 親ノードが無くても動画メモをマップに追加できるように)。
      if (currentPage.nodes.isEmpty) {
        position = const Offset(400, 300);
      } else {
        double sx = 0, sy = 0;
        for (final n in currentPage.nodes.values) {
          sx += n.position.dx;
          sy += n.position.dy;
        }
        final cx = sx / currentPage.nodes.length;
        final cy = sy / currentPage.nodes.length;
        // 既存メモ数に応じて配置する。 旧実装は 26px の斜めずらしだけで、 多数
        //   追加すると重なっていた。 = ユーザー要望: 横に並べて 1 行 (kCols 個)
        //   が埋まったら次の行へ折り返すグリッドにし、 重なりを防ぐ。
        // 画像メモは contentType==attachment で追加されるため、 グリッドの
        //   index 計算では memo と attachment の両方を数える (= 画像メモの
        //   直後にテキストメモが同じセルに重なるのを防ぐ)。 色用カウンタ
        //   (memoColor) は従来どおり memo のみで数える点に注意。
        int memoNodes = 0;
        for (final n in currentPage.nodes.values) {
          if (n.contentType == NodeContentType.memo ||
              n.contentType == NodeContentType.attachment) {
            memoNodes++;
          }
        }
        const int kCols = 4;
        const double colStep = 270.0;
        const double rowStep = 140.0;
        final int col = memoNodes % kCols;
        final int row = memoNodes ~/ kCols;
        position = Offset(
          cx + 40 + col * colStep,
          cy + row * rowStep,
        );
      }
      position = Offset(
        position.dx.clamp(20.0, 20000.0 - 240.0),
        position.dy.clamp(20.0, 20000.0 - 100.0),
      );
    }

    // ── ノード生成 ──
    // タイトル / メモ本文の役割:
    //   - title: ユーザーが書いたメモ本文 (キャンバス上で目に入るキーワード)
    //   - memoText: タイムスタンプ "[mm:ss]" などの補助情報
    // ユーザー要望: 「メモの中身がタイトル、 タイムスタンプがメモになる
    // ようにして」 → 旧実装は逆 (タイムスタンプが title、 本文が memoText)
    // だったので入れ替え。 これでマップ上ではメモの中身が見出しとして
    // 大きく見え、 タイムスタンプは補助テキストとして横に並ぶ。
    //
    // 色はメモごとに変えて視認性を上げる:
    // 旧実装はパレット先頭がアンバー (黄色) で、 既存メモが 0 のときに
    // 必ず黄色から始まる問題があった (= ユーザー報告「必ず最初に黄色のノードが
    // 出てくるのもおかしい」)。
    // 改善:
    //   1. パレット先頭をピンクに変更し、 アンバー (黄色) を最後尾に追いやる
    //   2. 動画 URL のハッシュをシードにして開始 index を決定 → 同じ動画
    //      なら毎回同じ色から始まり、 違う動画なら異なる色から始まる
    //      (= 動画ごとにメモ色グループが分かれて識別しやすい)
    final memoPalette = <Color>[
      const Color(0xFFFF8FA3), // ピンク (新たに先頭)
      const Color(0xFF7FD8A0), // ミントグリーン
      const Color(0xFF6BB7E8), // ライトブルー
      const Color(0xFFC79CE0), // パープル
      const Color(0xFFFF9F7A), // コーラル
      const Color(0xFF8FCFD1), // ターコイズ
      const Color(0xFFE8C16F), // ゴールド
      const Color(0xFFFFB347), // アンバー (旧 1 番目を後ろに)
    ];
    int memoCount = 0;
    for (final n in currentPage.nodes.values) {
      if (n.contentType == NodeContentType.memo) memoCount++;
    }
    // 動画 URL の hashCode をシードにして開始 index をバラけさせる
    final startIndex = videoUrl.hashCode.abs() % memoPalette.length;
    final memoColor =
        memoPalette[(startIndex + memoCount) % memoPalette.length];

    _pushUndo();
    final node = MindMapNode(
      id: _uuid.v4(),
      title: memoText.trim(),
      position: position,
      color: memoColor,
      contentType: NodeContentType.memo,
      // ── マップ上のメモノードはタイムスタンプを表示しない ──
      // 旧実装は memoTitleHeader (= `[mm:ss]`) を memoText に入れて
      // ハイパーリンク表示していたが、 ユーザーから「履歴一覧の中だけ
      // タイムラインを表示して、 外に出す時は文章だけ出すようにして」
      // という要望があったため、 マップ上ノードでは timestamp を非表示化。
      // タイムスタンプ自体は呼び出し側 (_VideoMemoEntry.timestampSec) に
      // 保持されており、 履歴一覧 UI 内での表示と履歴クリックでの
      // ジャンプ機能は引き続き動作する。
      memoText: null,
      // メモは横幅を少し広めにとっておく (本文がよく長くなるため)
      width: hasImage ? 180.0 : 240.0,
    );
    // 画像メモなら添付ノードに変換する (= ユーザー要望: Ctrl+V で画像貼り付け)。
    currentPage.nodes[node.id] = hasImage
        ? node.copyWith(
            attachmentPath: attachmentPath,
            attachmentName: attachmentName ?? 'image',
            contentType: NodeContentType.attachment,
          )
        : node;

    // ── 親があれば接続 ──
    if (parentId != null) {
      currentPage.connections.add(NodeConnection(
        fromId: parentId,
        fromAnchor: AnchorDirection.east,
        toId: node.id,
        toAnchor: AnchorDirection.west,
      ));
      // 親と同じグループに参加させる (動画ノード追加と同じポリシー)
      final groups = _namedGroups[currentPage.id];
      if (groups != null) {
        for (final entry in groups.entries) {
          if (entry.value.contains(parentId)) {
            entry.value.add(node.id);
          }
        }
      }
    }

    // ── ギャラリー: メモは動画の「隣のブロック」 に 1 つずつ配置する
    //    (= ユーザー要望)。 動画ノードのセルの右隣を 1 ブロック確保し
    //    (既に要素があればその要素を右へずらして間に挿入)、 そこへ置く。
    if (currentPage.pageType == 'bookshelf' && parentId != null) {
      final pc = shelfCellOf(parentId);
      if (pc != null) {
        _reserveShelfCells(pc[1], pc[0] + 1, 1);
        _shelfCells[node.id] = [pc[0] + 1, pc[1]];
        _saveShelfCells();
      }
      _arrangeAsBookshelfBody(currentPage);
    }

    _saveToStorage();
    notifyListeners();
    return node;
  }

  /// 2つのノード矩形が重なっているか判定（gap分の余白含む）
  bool _nodesOverlap(
      Offset pos, double w, double h, MindMapNode other, double gap) {
    final l1 = pos.dx - gap;
    final r1 = pos.dx + w + gap;
    final t1 = pos.dy - gap;
    final b1 = pos.dy + h + gap;
    final l2 = other.position.dx;
    final r2 = other.position.dx + other.width;
    final t2 = other.position.dy;
    final b2 = other.position.dy + other.visualHeight;
    return !(r1 <= l2 || r2 <= l1 || b1 <= t2 || b2 <= t1);
  }

  // ─── 自動整列 ─────────────────────────────────────────────────────────────

  /// 全ノードをツリー構造に基づいて自動整列し、接続線を最適化する
  ///
  /// [referencePos] 整列の中心座標（省略時は `Offset(900, 900)`）。
  /// ルートツリー群を正方形に近い行×列で **ref を中心** に配置する。
  /// 各行はその行の実幅で中央揃えされるため、行ごとに横幅が違っても ref を中心に保てる。
  /// 個々のツリーは横方向に展開（親→右へ子）。
  ///
  /// グループ処理:
  /// - 子ノードを並べる際、同じグループのメンバーを隣接させる（グループ幅の縮小に貢献）
  /// - 非メンバーノードがグループ領域に侵入していたら下へ押し出す
  /// - 2つのグループが重なっている場合、共通メンバーを持たない時のみ下方向に解消
  void autoLayoutTree({Offset? referencePos}) {
    final nodeMap = currentPage.nodes;
    final conns = currentPage.connections;
    if (nodeMap.isEmpty) return;

    _pushUndo();

    final Offset ref = referencePos ?? const Offset(900, 900);

    // ── 1. ツリー構造を解析 ──
    final toIds = conns.map((c) => c.toId).toSet();
    final rootIds = nodeMap.keys.where((id) => !toIds.contains(id)).toList();
    if (rootIds.isEmpty) rootIds.addAll(nodeMap.keys);

    final childrenOf = <String, List<String>>{};
    for (final c in conns) {
      childrenOf.putIfAbsent(c.fromId, () => []);
      if (!childrenOf[c.fromId]!.contains(c.toId)) {
        childrenOf[c.fromId]!.add(c.toId);
      }
    }

    // ── グループ所属判定ヘルパ ──
    // 同じ親の子ノードを並べる時、グループ所属でソート → 同じグループは隣接配置
    // → グループ外接矩形が横に広がらず、グループ内の無駄な空間を削減できる。
    final nodeGroupKey = <String, String>{};
    for (final e in namedGroups.entries) {
      for (final mid in e.value) {
        nodeGroupKey.putIfAbsent(mid, () => e.key);
      }
    }
    String kidSortKey(String id) {
      // グループ所属 → 所属グループ名、未所属 → '~~none' で末尾へ
      return nodeGroupKey[id] ?? '~~none';
    }

    // 子ノードリストをグループ所属でソート（同グループが連続するように）
    for (final parent in childrenOf.keys) {
      final kids = childrenOf[parent]!;
      kids.sort((a, b) => kidSortKey(a).compareTo(kidSortKey(b)));
    }

    // ── 2. サブツリーの高さ/幅を計算 ──
    // 間隔を以下のように定義:
    //   vGap         : 通常の子ノード間の縦方向の間隔
    //   vGapSameGroup: 同じグループのメンバー間は密に並べる（半分）
    //   hGap         : 親 → 子の横方向の間隔
    // ユーザーからの要望「グループ内のノードを無駄に離さない」に対応。
    const double vGap = 24.0;
    const double vGapSameGroup = 12.0;
    const double hGap = 48.0;
    final subtreeH = <String, double>{};
    final subtreeW = <String, double>{};
    final visited = <String>{};

    // 子間の合計ギャップ（同グループ連続は狭いギャップ）
    double gapBetween(String kidA, String kidB) {
      final ga = nodeGroupKey[kidA];
      final gb = nodeGroupKey[kidB];
      if (ga != null && ga == gb) return vGapSameGroup;
      return vGap;
    }

    // ── 多くの子ノードを 2 列で右側に配置するかどうかの判定 ──
    // 子が多く、かつ全てリーフ（孫なし）の場合のみ 2 列配置を使う。
    // 孫がいる場合は通常の右側横展開を使う（2 列にすると孫のツリーと衝突するため）。
    const int twoColKidThreshold = 8;
    bool useTwoColumnFanout(String id) {
      final kids = childrenOf[id] ?? const <String>[];
      if (kids.length <= twoColKidThreshold) return false;
      for (final k in kids) {
        final gk = childrenOf[k] ?? const <String>[];
        if (gk.isNotEmpty) return false;
      }
      return true;
    }

    // 2 列配置のサイズを概算で返す（calcH / calcW 用）
    // 1 列目と 2 列目の最大幅 + 各列の高さ（同グループ隣接はギャップ短縮）。
    ({double width, double height}) twoColFanoutSize(String id) {
      final kids = childrenOf[id] ?? const <String>[];
      if (kids.isEmpty) return (width: 0, height: 0);
      final perCol = (kids.length / 2).ceil();
      double maxKidW = 0;
      for (final k in kids) {
        final n = nodeMap[k];
        if (n == null) continue;
        if (n.width > maxKidW) maxKidW = n.width;
      }
      // 列の高さ計算（左列 = kids[0..perCol]、右列 = kids[perCol..]）
      double colHeight(int start, int end) {
        double h = 0;
        for (int i = start; i < end; i++) {
          final n = nodeMap[kids[i]];
          if (n == null) continue;
          h += n.visualHeight;
          if (i + 1 < end) h += gapBetween(kids[i], kids[i + 1]);
        }
        return h;
      }

      final leftH = colHeight(0, perCol);
      final rightH = colHeight(perCol, kids.length);
      return (
        width: maxKidW * 2 + hGap,
        height: math.max(leftH, rightH),
      );
    }

    double calcH(String id) {
      if (subtreeH.containsKey(id)) return subtreeH[id]!;
      if (visited.contains(id)) {
        subtreeH[id] = 42.0;
        return 42.0;
      }
      visited.add(id);
      final node = nodeMap[id];
      if (node == null) {
        subtreeH[id] = 42.0;
        return 42.0;
      }
      final kids = childrenOf[id] ?? [];
      if (kids.isEmpty) {
        subtreeH[id] = node.visualHeight;
        return node.visualHeight;
      }
      if (useTwoColumnFanout(id)) {
        final sz = twoColFanoutSize(id);
        subtreeH[id] = math.max(node.visualHeight, sz.height);
        return subtreeH[id]!;
      }
      double total = 0;
      for (final kid in kids) {
        total += calcH(kid);
      }
      // 子間の合計ギャップ（同グループ連続は狭いギャップ）
      for (int i = 0; i + 1 < kids.length; i++) {
        total += gapBetween(kids[i], kids[i + 1]);
      }
      final h = total > node.visualHeight ? total : node.visualHeight;
      subtreeH[id] = h;
      return h;
    }

    double calcW(String id) {
      if (subtreeW.containsKey(id)) return subtreeW[id]!;
      final node = nodeMap[id];
      if (node == null) {
        subtreeW[id] = 160.0;
        return 160.0;
      }
      final kids = childrenOf[id] ?? [];
      if (kids.isEmpty) {
        subtreeW[id] = node.width;
        return node.width;
      }
      if (useTwoColumnFanout(id)) {
        final sz = twoColFanoutSize(id);
        subtreeW[id] = node.width + hGap + sz.width;
        return subtreeW[id]!;
      }
      double maxKidW = 0;
      for (final kid in kids) {
        final kw = calcW(kid);
        if (kw > maxKidW) maxKidW = kw;
      }
      final w = node.width + hGap + maxKidW;
      subtreeW[id] = w;
      return w;
    }

    for (final rid in rootIds) {
      calcH(rid);
      calcW(rid);
    }

    // ── グリッド配置用: ツリーにグループメンバーが含まれるなら、
    //     グループ矩形のパディング分を subtreeW/H に上乗せして
    //     隣のツリーとの距離を確保する（_pushOutOfForeignGroups の過剰作動を防ぐ）
    const double groupPadAllowance = 60.0; // pad(28) + 余裕(32)
    final Map<String, bool> treeContainsGroupMember = {};
    bool treeHasGroupMember(String rid) {
      if (treeContainsGroupMember.containsKey(rid)) {
        return treeContainsGroupMember[rid]!;
      }
      bool has = nodeGroupKey.containsKey(rid);
      if (!has) {
        for (final kid in childrenOf[rid] ?? const <String>[]) {
          if (treeHasGroupMember(kid)) {
            has = true;
            break;
          }
        }
      }
      treeContainsGroupMember[rid] = has;
      return has;
    }

    // 各ツリーの effective サイズを計算して使うためのヘルパ
    double effectiveW(String rid) =>
        (subtreeW[rid] ?? 160.0) +
        (treeHasGroupMember(rid) ? groupPadAllowance : 0.0);
    double effectiveH(String rid) =>
        (subtreeH[rid] ?? 42.0) +
        (treeHasGroupMember(rid) ? groupPadAllowance : 0.0);
    // ── 3. 正方形に近いグリッド構造で行分割 ──
    // cols = ceil(sqrt(n)) → 4ルートなら2列、9ルートなら3列、16なら4列
    // 各行は「実際のツリー幅の合計」で中央揃えするため、行ごとに幅が違っても
    // ref を中心に見える（列幅を固定せず、行内の横位置を動的に決める）。
    const double blockMargin = 80.0;
    final blockCount = rootIds.length;
    final cols = math.max(1, math.sqrt(blockCount).ceil());
    final rowCount = (blockCount / cols).ceil();

    // 各行の情報: 含まれるインデックス / 実幅合計 / 最大高さ
    final rowIndices = <List<int>>[];
    final rowWidths = <double>[];
    final rowHeights = <double>[];
    for (int r = 0; r < rowCount; r++) {
      final indices = <int>[];
      double rowW = 0;
      double rowMaxH = 0;
      for (int c = 0; c < cols; c++) {
        final i = r * cols + c;
        if (i >= blockCount) break;
        indices.add(i);
        // グループを含むツリーはパディング分を効いたサイズで計算
        final w = effectiveW(rootIds[i]);
        final h = effectiveH(rootIds[i]);
        rowW += w;
        if (h > rowMaxH) rowMaxH = h;
      }
      rowW += blockMargin * (indices.length - 1).clamp(0, double.infinity);
      rowIndices.add(indices);
      rowWidths.add(rowW);
      rowHeights.add(rowMaxH);
    }

    double totalH = rowHeights.fold(0.0, (a, b) => a + b) +
        blockMargin * (rowCount - 1).clamp(0, double.infinity);

    // ── 4. ノードを配置 ──
    void layoutNode(String id, double x, double y, double slotH) {
      final node = nodeMap[id];
      if (node == null) return;
      final nodeY = y + (slotH - node.visualHeight) / 2;
      nodeMap[id] = node.copyWith(
        position: Offset(x.clamp(0.0, 20000.0), nodeY.clamp(0.0, 20000.0)),
        anchorMode: NodeAnchorMode.fourWay,
      );
      final kids = childrenOf[id] ?? [];
      if (kids.isEmpty) return;

      // 子ノードが多くリーフなら 2 列で右側に配置（縦長の1列を避ける）
      if (useTwoColumnFanout(id)) {
        final perCol = (kids.length / 2).ceil();
        double maxKidW = 0;
        for (final k in kids) {
          final n = nodeMap[k];
          if (n == null) continue;
          if (n.width > maxKidW) maxKidW = n.width;
        }
        // 各列の高さを計算
        double colHeight(int start, int end) {
          double h = 0;
          for (int i = start; i < end; i++) {
            final n = nodeMap[kids[i]];
            if (n == null) continue;
            h += n.visualHeight;
            if (i + 1 < end) h += gapBetween(kids[i], kids[i + 1]);
          }
          return h;
        }

        final leftH = colHeight(0, perCol);
        final rightH = colHeight(perCol, kids.length);
        // 各列の X 座標: 1列目は親の右隣、2列目はさらに右
        final col1X = x + node.width + hGap;
        final col2X = col1X + maxKidW + hGap;
        final parentCenterY = nodeY + node.visualHeight / 2;

        // 1列目: kids[0..perCol]
        double curY = parentCenterY - leftH / 2;
        for (int i = 0; i < perCol && i < kids.length; i++) {
          final kn = nodeMap[kids[i]];
          if (kn == null) continue;
          nodeMap[kids[i]] = kn.copyWith(
            position: Offset(
              col1X.clamp(0.0, 20000.0),
              curY.clamp(0.0, 20000.0),
            ),
            anchorMode: NodeAnchorMode.fourWay,
          );
          curY += kn.visualHeight;
          if (i + 1 < perCol && i + 1 < kids.length) {
            curY += gapBetween(kids[i], kids[i + 1]);
          }
        }
        // 2列目: kids[perCol..]
        curY = parentCenterY - rightH / 2;
        for (int i = perCol; i < kids.length; i++) {
          final kn = nodeMap[kids[i]];
          if (kn == null) continue;
          nodeMap[kids[i]] = kn.copyWith(
            position: Offset(
              col2X.clamp(0.0, 20000.0),
              curY.clamp(0.0, 20000.0),
            ),
            anchorMode: NodeAnchorMode.fourWay,
          );
          curY += kn.visualHeight;
          if (i + 1 < kids.length) {
            curY += gapBetween(kids[i], kids[i + 1]);
          }
        }
        return;
      }

      // 通常配置: 親の右側に縦方向スタック
      final childX = x + node.width + hGap;
      double kidsTotalH = 0;
      for (final kid in kids) {
        kidsTotalH += calcH(kid);
      }
      for (int i = 0; i + 1 < kids.length; i++) {
        kidsTotalH += gapBetween(kids[i], kids[i + 1]);
      }
      double childY = y + (slotH - kidsTotalH) / 2;
      for (int i = 0; i < kids.length; i++) {
        final kid = kids[i];
        final kidH = calcH(kid);
        layoutNode(kid, childX, childY, kidH);
        childY += kidH;
        if (i + 1 < kids.length) childY += gapBetween(kid, kids[i + 1]);
      }
    }

    // ref を中心に：各行はその行の実幅でセンタリング、全体は縦方向で ref.dy を中心に
    double accY = ref.dy - totalH / 2;
    for (int r = 0; r < rowCount; r++) {
      // この行の実幅でセンタリング（行ごとに幅が違っても ref.dx を中心に見える）
      final rowW = rowWidths[r];
      final rowMaxH = rowHeights[r];
      double accX = ref.dx - rowW / 2;
      for (final i in rowIndices[r]) {
        final rid = rootIds[i];
        final w = effectiveW(rid);
        final h = subtreeH[rid] ?? 42.0;
        // effectiveW/H はグループパディング込み。ツリー自体はセル左寄せだが、
        // グループを含む場合は pad 分を左側に確保（グループラベルの表示領域）
        final padLeft = treeHasGroupMember(rid) ? 36.0 : 0.0;
        final padTop = treeHasGroupMember(rid) ? 36.0 : 0.0;
        final slotY = accY + (rowMaxH - h) / 2 + padTop;
        layoutNode(rid, accX + padLeft, slotY, h);
        accX += w + blockMargin;
      }
      accY += rowMaxH + blockMargin;
    }

    // 孤立ノード（どのツリーにも属さない）を下に並べる
    final laidOut = <String>{};
    void collectLaid(String id) {
      laidOut.add(id);
      for (final kid in childrenOf[id] ?? []) {
        collectLaid(kid);
      }
    }

    for (final rid in rootIds) {
      collectLaid(rid);
    }
    // 行の最下端 + マージン から孤立ノード帯開始
    double orphanY = ref.dy + totalH / 2 + 40;
    final orphanBandW = rowWidths.isEmpty ? 0.0 : rowWidths.reduce(math.max);
    double orphanX = ref.dx - orphanBandW / 2;
    final orphanStartX = orphanX;
    final orphanEndX = ref.dx + orphanBandW / 2;
    for (final node in nodeMap.values.toList()) {
      if (!laidOut.contains(node.id)) {
        nodeMap[node.id] = node.copyWith(
          position: Offset(
            orphanX.clamp(0.0, 20000.0),
            orphanY.clamp(0.0, 20000.0),
          ),
        );
        orphanX += node.width + hGap;
        if (orphanX > orphanEndX) {
          orphanX = orphanStartX;
          orphanY += 60;
        }
      }
    }

    // ── 5. グループ領域への侵入を解消（既存機能）──
    _pushOutOfForeignGroups();

    // ── 6. 重なっているグループ同士を解消 ──
    //     共通メンバーを持つグループ間は意図的な重なりとして除外
    _resolveGroupOverlaps();

    // ── 7. グループ内の孤立メンバー（外れ値）を仲間の近くへ引き寄せる ──
    //     ある付箋グループのメンバーが、他のメンバーから大きく離れた位置にいる場合、
    //     その子孫サブツリーごと「仲間の集まりの直下」に再配置する。
    _compactGroupOutliers();

    // ── 8. 名前付きグループのメンバーをグリッド状に詰め直す ──
    //     グループの外接矩形の左上から、行 → 列の順にノードを並べて
    //     なるべく正方形になるようにパッキングする
    _packGroupMembersIntoGrid();

    // ── 9. 接続のアンカー方向を最適化 ──
    _optimizeConnectionAnchors();

    // ── 10. 完全な重なり(埋もれ)の最終解消 ──
    //   ユーザー要望: ノード同士が完全に重なって見えなくなることがないよう、
    //   ほぼ完全に被っているペアだけを最小限ずらす (部分的な重なりは温存)。
    _separateBuriedNodes();

    _saveToStorage();
    notifyListeners();
  }

  /// 名前付きグループのメンバーで、他のメンバーから大きく離れた位置にあるものを
  /// 「本体クラスター」の直下に引き寄せる。外れ値の子孫サブツリーも一緒に移動。
  ///
  /// アルゴリズム:
  /// 1. 各グループのメンバーの中心座標を計算
  /// 2. メディアン中心（外れ値に強い）を求める
  /// 3. 各メンバーのメディアン中心までの距離を取り、
  ///    その距離のメディアンの [outlierFactor] 倍 or [minOutlierAbsDist] を
  ///    超えるものを「外れ値」と判定
  /// 4. 非外れ値の外接矩形（本体クラスター）を計算
  /// 5. 外れ値とその子孫サブツリーを、本体クラスターの真下に縦に並べ直す
  void _compactGroupOutliers() {
    final nodeMap = currentPage.nodes;
    final conns = currentPage.connections;
    if (namedGroups.isEmpty) return;

    // 親→子のマップ（サブツリー移動用）
    final childrenOf = <String, List<String>>{};
    for (final c in conns) {
      childrenOf.putIfAbsent(c.fromId, () => []);
      if (!childrenOf[c.fromId]!.contains(c.toId)) {
        childrenOf[c.fromId]!.add(c.toId);
      }
    }
    Set<String> collectSubtree(String rootId) {
      final result = <String>{rootId};
      final queue = <String>[rootId];
      int safety = 0;
      while (queue.isNotEmpty && safety < 10000) {
        safety++;
        final cur = queue.removeAt(0);
        for (final kid in childrenOf[cur] ?? const <String>[]) {
          if (result.add(kid)) queue.add(kid);
        }
      }
      return result;
    }

    // メンバーが 3 つ未満のグループは外れ値判定不可のためスキップ
    const outlierFactor = 2.5;
    const minOutlierAbsDist = 400.0;
    const gapBelowCluster = 50.0;

    for (final entry in namedGroups.entries) {
      final members =
          entry.value.where((id) => nodeMap.containsKey(id)).toList();
      if (members.length < 3) continue;

      // 各メンバーの中心座標
      final centers = <String, Offset>{};
      for (final id in members) {
        final n = nodeMap[id]!;
        centers[id] = Offset(
          n.position.dx + n.width / 2,
          n.position.dy + n.visualHeight / 2,
        );
      }

      // メディアン中心（X / Y 独立に中央値を取る）
      final xs = centers.values.map((p) => p.dx).toList()..sort();
      final ys = centers.values.map((p) => p.dy).toList()..sort();
      final medianCenter = Offset(
        xs[xs.length ~/ 2],
        ys[ys.length ~/ 2],
      );

      // 各メンバーの メディアン中心までの距離
      final distances = <String, double>{};
      for (final e in centers.entries) {
        distances[e.key] = (e.value - medianCenter).distance;
      }

      // 距離のメディアン
      final sortedDists = distances.values.toList()..sort();
      final medianDist = sortedDists[sortedDists.length ~/ 2];
      final threshold = math.max(minOutlierAbsDist, medianDist * outlierFactor);

      // 外れ値の抽出
      final outliers = <String>[];
      for (final e in distances.entries) {
        if (e.value > threshold) outliers.add(e.key);
      }
      if (outliers.isEmpty) continue;

      // 非外れ値（本体クラスター）の外接矩形
      final nonOutliers =
          members.where((id) => !outliers.contains(id)).toList();
      if (nonOutliers.isEmpty) continue;
      double minX = double.infinity, minY = double.infinity;
      double maxX = -double.infinity, maxY = -double.infinity;
      for (final id in nonOutliers) {
        final n = nodeMap[id]!;
        if (n.position.dx < minX) minX = n.position.dx;
        if (n.position.dy < minY) minY = n.position.dy;
        final r = n.position.dx + n.width;
        final b = n.position.dy + n.visualHeight;
        if (r > maxX) maxX = r;
        if (b > maxY) maxY = b;
      }
      if (minX == double.infinity) continue;

      // 本体の水平中心の真下に外れ値を順番に積む
      final clusterCenterX = (minX + maxX) / 2;
      double placeY = maxY + gapBelowCluster;
      final movedIds = <String>{};

      for (final oid in outliers) {
        if (movedIds.contains(oid)) continue;
        final subtree = collectSubtree(oid);
        final head = nodeMap[oid]!;
        // サブツリー全体を delta だけ平行移動
        final targetX = clusterCenterX - head.width / 2;
        final delta = Offset(
          targetX - head.position.dx,
          placeY - head.position.dy,
        );
        for (final sid in subtree) {
          if (movedIds.contains(sid)) continue;
          final m = nodeMap[sid];
          if (m == null) continue;
          nodeMap[sid] = m.copyWith(
            position: Offset(
              (m.position.dx + delta.dx).clamp(0.0, 20000.0),
              (m.position.dy + delta.dy).clamp(0.0, 20000.0),
            ),
          );
          movedIds.add(sid);
        }
        placeY += head.visualHeight + gapBelowCluster;
      }
    }
  }

  /// 名前付きグループの各メンバーを、グループの外接矩形の左上から
  /// 「行 → 列」の順で並べ直し、なるべく正方形に近い格子状に詰める。
  ///
  /// 目的:
  /// - グループ内でスカスカに散らばっているノードを視覚的にまとめる
  /// - グループ矩形を計算しやすく、他グループとの衝突も起きにくくなる
  ///
  /// アルゴリズム:
  /// 1. 現在のメンバーの外接矩形の左上を基点とする
  /// 2. `cols = ceil(sqrt(N))` で列数を決め、行数は自動（正方形寄り）
  /// 3. 各セルの幅 = メンバーの最大幅 + 列間ギャップ
  ///    各セルの高さ = メンバーの最大高さ + 行間ギャップ
  /// 4. 左上から順番にメンバーを配置（行が埋まったら次の行へ）
  void _packGroupMembersIntoGrid() {
    final nodeMap = currentPage.nodes;
    if (namedGroups.isEmpty) return;

    // 付箋パディング（見た目の左上余白）。_GroupBackgroundPainter の pad に合わせる
    const double innerTopLeftPadding = 14.0;
    const double colGap = 28.0;
    const double rowGap = 24.0;

    for (final entry in namedGroups.entries) {
      final members =
          entry.value.where((id) => nodeMap.containsKey(id)).toList();
      if (members.length < 2) continue;

      // 現在の外接矩形の左上（基点）を取得
      double minX = double.infinity, minY = double.infinity;
      for (final id in members) {
        final n = nodeMap[id]!;
        if (n.position.dx < minX) minX = n.position.dx;
        if (n.position.dy < minY) minY = n.position.dy;
      }
      if (minX == double.infinity) continue;

      // セルサイズ（最大のノード幅・高さを採用 = 揃った見た目）
      double maxW = 0, maxH = 0;
      for (final id in members) {
        final n = nodeMap[id]!;
        if (n.width > maxW) maxW = n.width;
        if (n.visualHeight > maxH) maxH = n.visualHeight;
      }
      // 極端に大きいノードを除外したい場合の上限（UI 破壊防止）
      maxW = math.min(maxW, 400.0);
      maxH = math.min(maxH, 200.0);

      // 正方形寄りのグリッド
      final n = members.length;
      final cols = math.max(1, math.sqrt(n).ceil());

      // 元の並び順を保持（ユーザーが触った順序を尊重）
      // 必要に応じて position で上→下 / 左→右 ソートしても良い
      for (int i = 0; i < members.length; i++) {
        final id = members[i];
        final node = nodeMap[id];
        if (node == null) continue;
        final row = i ~/ cols;
        final col = i % cols;
        final newX = minX + innerTopLeftPadding + col * (maxW + colGap);
        final newY = minY + innerTopLeftPadding + row * (maxH + rowGap);
        nodeMap[id] = node.copyWith(
          position: Offset(
            newX.clamp(0.0, 20000.0),
            newY.clamp(0.0, 20000.0),
          ),
        );
      }
    }
  }

  /// グループ同士の外接矩形が重なっている場合、片方を下方向に押し出して解消する。
  /// 2つのグループが共通メンバーを持つ場合は意図的な重なりとして尊重し、動かさない。
  /// 最大5パス繰り返す。
  void _resolveGroupOverlaps() {
    final nodeMap = currentPage.nodes;
    if (namedGroups.length < 2) return;

    Rect? groupRect(Set<String> memberIds) {
      double minX = double.infinity, minY = double.infinity;
      double maxX = -double.infinity, maxY = -double.infinity;
      for (final mid in memberIds) {
        final m = nodeMap[mid];
        if (m == null) continue;
        if (m.position.dx < minX) minX = m.position.dx;
        if (m.position.dy < minY) minY = m.position.dy;
        final r = m.position.dx + m.width;
        final b = m.position.dy + m.visualHeight;
        if (r > maxX) maxX = r;
        if (b > maxY) maxY = b;
      }
      if (minX == double.infinity) return null;
      const pad = 28.0;
      const labelH = 28.0;
      return Rect.fromLTRB(
          minX - pad, minY - pad - labelH, maxX + pad, maxY + pad);
    }

    for (int pass = 0; pass < 5; pass++) {
      bool anyMoved = false;
      final entries = namedGroups.entries.toList();
      // 各グループの有効メンバー集合
      final validMembers = <String, Set<String>>{};
      for (final e in entries) {
        final ids = e.value.where((id) => nodeMap.containsKey(id)).toSet();
        if (ids.isNotEmpty) validMembers[e.key] = ids;
      }

      final names = validMembers.keys.toList();
      for (int i = 0; i < names.length; i++) {
        for (int j = i + 1; j < names.length; j++) {
          final gA = names[i];
          final gB = names[j];
          final aMembers = validMembers[gA]!;
          final bMembers = validMembers[gB]!;

          // 共通メンバー = 意図的な重なり → スキップ
          if (aMembers.any((id) => bMembers.contains(id))) continue;

          final rectA = groupRect(aMembers);
          final rectB = groupRect(bMembers);
          if (rectA == null || rectB == null) continue;
          if (!rectA.overlaps(rectB)) continue;

          // B の方が上にあるなら A を下に押す、そうでなければ B を下に押す
          final aCenter = rectA.center.dy;
          final bCenter = rectB.center.dy;
          final pushTargetMembers = aCenter <= bCenter ? bMembers : aMembers;
          final fromRect = aCenter <= bCenter ? rectA : rectB;
          final toRect = aCenter <= bCenter ? rectB : rectA;
          final dy = fromRect.bottom - toRect.top + 24.0;

          for (final mid in pushTargetMembers) {
            final m = nodeMap[mid];
            if (m == null) continue;
            nodeMap[mid] = m.copyWith(
              position: Offset(
                m.position.dx.clamp(0.0, 20000.0),
                (m.position.dy + dy).clamp(0.0, 20000.0),
              ),
            );
          }
          anyMoved = true;
        }
      }
      if (!anyMoved) break;
    }
  }

  /// 各グループの外接矩形を計算し、
  /// そのグループに属さないノードが領域内に侵入していたら、
  /// **サブツリー全体を下方向に**移動させる（個別移動でツリーが断片化するのを防ぐ）。
  ///
  /// [conns] が渡されない場合は currentPage.connections を使う。
  void _pushOutOfForeignGroups() {
    final nodeMap = currentPage.nodes;
    final conns = currentPage.connections;
    if (namedGroups.isEmpty) return;

    // サブツリーを収集するためのヘルパ（親→子のツリー辿り）
    final childrenOf = <String, List<String>>{};
    for (final c in conns) {
      childrenOf.putIfAbsent(c.fromId, () => []);
      if (!childrenOf[c.fromId]!.contains(c.toId)) {
        childrenOf[c.fromId]!.add(c.toId);
      }
    }
    // 入力 ID を根として、到達可能な全ノード ID を返す（循環対策付き）
    Set<String> collectSubtree(String rootId) {
      final result = <String>{rootId};
      final queue = <String>[rootId];
      int safety = 0;
      while (queue.isNotEmpty && safety < 10000) {
        safety++;
        final id = queue.removeAt(0);
        for (final kid in childrenOf[id] ?? const <String>[]) {
          if (result.add(kid)) queue.add(kid);
        }
      }
      return result;
    }

    // グループごとに最大3回繰り返してもつれを解消
    for (int pass = 0; pass < 3; pass++) {
      bool moved = false;
      for (final entry in namedGroups.entries) {
        final memberIds =
            entry.value.where((id) => nodeMap.containsKey(id)).toSet();
        if (memberIds.isEmpty) continue;

        // グループの外接矩形（付箋のpaddingを含む）
        double minX = double.infinity, minY = double.infinity;
        double maxX = -double.infinity, maxY = -double.infinity;
        for (final mid in memberIds) {
          final m = nodeMap[mid];
          if (m == null) continue;
          if (m.position.dx < minX) minX = m.position.dx;
          if (m.position.dy < minY) minY = m.position.dy;
          final r = m.position.dx + m.width;
          final b = m.position.dy + m.visualHeight;
          if (r > maxX) maxX = r;
          if (b > maxY) maxY = b;
        }
        if (minX == double.infinity) continue;
        const pad = 28.0;
        const labelH = 28.0;
        final groupRect = Rect.fromLTRB(
          minX - pad,
          minY - pad - labelH,
          maxX + pad,
          maxY + pad,
        );

        // 侵入しているメンバー外ノードを検出し、**サブツリーごと**下へ押し出す
        // 同一サブツリーを1パスで重複処理しないように済みセットを持つ
        final processedThisPass = <String>{};
        for (final n in nodeMap.values.toList()) {
          if (memberIds.contains(n.id)) continue;
          if (processedThisPass.contains(n.id)) continue;
          final nodeRect = Rect.fromLTWH(
            n.position.dx,
            n.position.dy,
            n.width,
            n.visualHeight,
          );
          if (!nodeRect.overlaps(groupRect)) continue;

          // このノードを含むサブツリー（同じ色の接続で繋がれた一連の子孫）
          final subtree = collectSubtree(n.id);
          // サブツリー全体に同じ delta を適用 → ツリー形状を維持したまま下へ
          final delta = (groupRect.bottom + 16.0) - n.position.dy;
          if (delta <= 0) {
            processedThisPass.addAll(subtree);
            continue;
          }
          for (final sid in subtree) {
            final s = nodeMap[sid];
            if (s == null) continue;
            // メンバーは動かさない（他のグループのメンバーかもしれない）
            if (memberIds.contains(sid)) continue;
            nodeMap[sid] = s.copyWith(
              position: Offset(
                s.position.dx.clamp(0.0, 20000.0),
                (s.position.dy + delta).clamp(0.0, 20000.0),
              ),
            );
          }
          processedThisPass.addAll(subtree);
          moved = true;
        }
      }
      if (!moved) break;
    }
  }

  /// 全接続のアンカー方向を、ノード位置に基づいて最適な直線に最も近い方向に再設定する
  void _optimizeConnectionAnchors() {
    final nodeMap = currentPage.nodes;
    final conns = currentPage.connections;
    final newConns = <NodeConnection>[];

    for (final conn in conns) {
      final from = nodeMap[conn.fromId];
      final to = nodeMap[conn.toId];
      if (from == null || to == null) {
        newConns.add(conn);
        continue;
      }
      final fc = from.center;
      final tc = to.center;
      final dx = tc.dx - fc.dx;
      final dy = tc.dy - fc.dy;

      AnchorDirection fromDir;
      AnchorDirection toDir;

      if (dx.abs() > dy.abs() * 1.5) {
        // 横方向が圧倒的 → east/west で水平直線
        if (dx > 0) {
          fromDir = AnchorDirection.east;
          toDir = AnchorDirection.west;
        } else {
          fromDir = AnchorDirection.west;
          toDir = AnchorDirection.east;
        }
      } else if (dy.abs() > dx.abs() * 1.5) {
        // 縦方向が圧倒的 → north/south で垂直直線
        if (dy > 0) {
          fromDir = AnchorDirection.south;
          toDir = AnchorDirection.north;
        } else {
          fromDir = AnchorDirection.north;
          toDir = AnchorDirection.south;
        }
      } else {
        // 斜め → 横主体で接続（ツリーは横に広がるため）
        if (dx > 0) {
          fromDir = AnchorDirection.east;
          toDir = AnchorDirection.west;
        } else {
          fromDir = AnchorDirection.west;
          toDir = AnchorDirection.east;
        }
      }

      newConns.add(NodeConnection(
        fromId: conn.fromId,
        fromAnchor: fromDir,
        toId: conn.toId,
        toAnchor: toDir,
      ));
    }

    conns
      ..clear()
      ..addAll(newConns);
  }

  /// 指定ノードの位置を確定し、重なる周囲ノードを上下に押しのける
  void pushSurroundingNodes(String placedNodeId) {
    final nodeMap = currentPage.nodes;
    final placed = nodeMap[placedNodeId];
    if (placed == null) return;

    // ── ノード同士のマージン (= ユーザー要望: ノード同士が見かけ以上に
    //    接近することができなくて離れていくの変だから、 被らない程度には
    //    近づけるように) ──
    // 以前は 16px の余白を取って早めに「押しのけ」 が発動していたが、
    //   ユーザーは「ぴったり接触に近いところまで近づけたい」 ので、 マージン
    //   は 2px だけにする (= 浮動小数点の誤差吸収用)。
    const double pad = 2.0;
    final movedIds = <String>{placedNodeId}; // 移動済みID（再処理防止）
    // 処理キュー: 押しのけ元のノードIDリスト
    final queue = <String>[placedNodeId];

    int iterations = 0;
    while (queue.isNotEmpty && iterations < 200) {
      iterations++;
      final srcId = queue.removeAt(0);
      final src = nodeMap[srcId];
      if (src == null) continue;

      // 当たり判定はタイトル本体 (height) のみで行う。 visualHeight を使うと
      // 動画/画像で伸びた分まで「重なり」 とみなして押しのけてしまい、 動画を
      // 埋め込んだノードなど大きいノード同士が近づけない (= ユーザー報告の
      // バグ)。 _avoidOverlap と同じくタイトル本体のみを当たり判定に使う。
      final srcTop = src.position.dy;
      final srcBottom = src.position.dy + src.height;
      final srcCenterY = srcTop + src.height / 2;
      final srcLeft = src.position.dx;
      final srcRight = src.position.dx + src.width;

      for (final other in nodeMap.values.toList()) {
        if (movedIds.contains(other.id)) continue;
        // X方向で重なっていなければスキップ
        final otherRight = other.position.dx + other.width;
        if (srcLeft >= otherRight + pad || srcRight + pad <= other.position.dx)
          continue;
        // Y方向で重なっていなければスキップ
        final otherBottom = other.position.dy + other.height;
        if (srcTop >= otherBottom + pad || srcBottom + pad <= other.position.dy)
          continue;

        // 重なっている → 押す方向を決定
        final otherCenterY = other.position.dy + other.height / 2;
        double newY;
        if (otherCenterY >= srcCenterY) {
          // 相手が下寄り → 下に押す
          newY = srcBottom + pad;
        } else {
          // 相手が上寄り → 上に押す
          newY = srcTop - other.height - pad;
          if (newY < 0) newY = 0;
        }
        final delta = newY - other.position.dy;
        if (delta.abs() < 0.5) continue;

        // 押されるノードのすべての子孫も一緒に移動
        final subtreeIds = _collectDescendants(other.id);
        subtreeIds.add(other.id);
        for (final sid in subtreeIds) {
          final sn = nodeMap[sid];
          if (sn == null) continue;
          nodeMap[sid] = sn.copyWith(
            position: Offset(
              sn.position.dx,
              (sn.position.dy + delta).clamp(0.0, 20000.0),
            ),
          );
          movedIds.add(sid);
        }
        // 押されたノードとその子孫もキューに追加してカスケード
        for (final sid in subtreeIds) {
          queue.add(sid);
        }
      }
    }
    _saveToStorage();
    notifyListeners();
  }

  /// ノードの子孫（接続先を再帰的にたどる）IDを収集
  Set<String> _collectDescendants(String nodeId) {
    final result = <String>{};
    final stack = <String>[nodeId];
    while (stack.isNotEmpty) {
      final id = stack.removeLast();
      for (final conn in currentPage.connections) {
        if (conn.fromId == id && !result.contains(conn.toId)) {
          result.add(conn.toId);
          stack.add(conn.toId);
        }
      }
    }
    return result;
  }

  /// 2ノードを接続。最も近いアンカーペアを自動選択。
  void connectNodes(String fromId, String toId, AnchorDirection fromAnchor,
      AnchorDirection toAnchor) {
    if (fromId == toId) return;
    final nodeMap = currentPage.nodes;
    if (!nodeMap.containsKey(fromId) || !nodeMap.containsKey(toId)) return;

    // 既に同じ接続があれば何もしない
    final conns = currentPage.connections;
    final exists = conns.any((c) =>
        (c.fromId == fromId && c.toId == toId) ||
        (c.fromId == toId && c.toId == fromId));
    if (exists) return;

    _pushUndo();
    conns.add(NodeConnection(
      fromId: fromId,
      fromAnchor: fromAnchor,
      toId: toId,
      toAnchor: toAnchor,
    ));
    // 折りたたみ中の親に子を繋いだら親を展開して子を見えるようにする。
    _expandIfCollapsed(fromId);
    _saveToStorage();
    notifyListeners();
  }

  /// 範囲選択された複数ノードを 1 つのターゲットノードへ「子」として一括接続。
  ///
  /// - [targetId] が「親」、[sourceIds] の各ノードが「子」になる。
  /// - 移動 (delta) も同時に適用するので、ドラッグ&ドロップで複数まとめて
  ///   既存ノードに紐付ける UX を 1 操作 (= Undo 1 回ぶん) で実現できる。
  /// - 既に接続済み / target 自身 / 存在しない id はスキップする。
  /// - delta が `Offset.zero` でも正常に動く (= 接続のみ作りたい場合)。
  void moveAndConnectToTarget(
    Set<String> sourceIds,
    Offset delta,
    String targetId, {
    required AnchorDirection sourceAnchor,
    required AnchorDirection targetAnchor,
  }) {
    final nodeMap = currentPage.nodes;
    if (!nodeMap.containsKey(targetId)) return;
    if (sourceIds.isEmpty) return;
    _pushUndo();

    // 1. 移動
    if (delta != Offset.zero) {
      for (final id in sourceIds) {
        final node = nodeMap[id];
        if (node == null) continue;
        nodeMap[id] = node.copyWith(
          position: Offset(
            (node.position.dx + delta.dx).clamp(0.0, 20000.0 - node.width),
            (node.position.dy + delta.dy).clamp(0.0, 20000.0 - node.height),
          ),
        );
      }
    }

    // 2. 接続作成 (target → source の向き)
    final conns = currentPage.connections;
    for (final id in sourceIds) {
      if (id == targetId) continue;
      if (!nodeMap.containsKey(id)) continue;
      final exists = conns.any((c) =>
          (c.fromId == targetId && c.toId == id) ||
          (c.fromId == id && c.toId == targetId));
      if (exists) continue;
      conns.add(NodeConnection(
        fromId: targetId,
        fromAnchor: targetAnchor,
        toId: id,
        toAnchor: sourceAnchor,
      ));
    }
    // 折りたたみ中のターゲットへ繋いだら展開して子を見えるようにする。
    _expandIfCollapsed(targetId);

    _saveToStorage();
    notifyListeners();
  }

  // ─── 右クリック「子ノードを追加」/ 複数選択「親ノードを追加」 ────────────────
  /// 指定した親ノードに、空の子ノードを `count` 個生成して接続する。
  /// 配置: 親の右側 (east) に縦方向に均等配置。
  /// AI を介さず即座に作るので、ユーザーがすぐにタイトルを編集できる。
  ///
  /// 戻り値: 生成した子ノードの ID リスト
  List<String> addChildrenWithCount(String parentId, int count,
      {bool skipUndo = false}) {
    if (count <= 0) return const [];
    final nodeMap = currentPage.nodes;
    final parent = nodeMap[parentId];
    if (parent == null) return const [];

    // skipUndo は「外側で 1 回まとめて _pushUndo() を呼びたい」ケース用
    // (例: addChildrenToMultipleParents から複数親に対してループで呼ぶとき)
    if (!skipUndo) _pushUndo();
    const gap = 16.0;
    const childW = 160.0;
    const childH = 42.0;
    final totalH = childH * count + gap * (count - 1);
    final startX =
        (parent.position.dx + parent.width + 80).clamp(0.0, 20000.0 - childW);
    final parentCenterY = parent.position.dy + parent.visualHeight / 2;

    // ── 既存の子ノードを取得し、新規ノードと位置が被らないようにする ──
    // この親から伸びている既存の接続先 (= 既存の子ノード) を集める。
    // 既存の addChildrenWithCount で作られた子は fromId == parentId の
    // 接続を持っているので、その toId 群を「子」として扱う。
    // (逆向きに引かれた手動接続もカバーするため、toId == parentId で
    //  parent より右に置かれているものも子相当として扱う)
    final existingChildren = <MindMapNode>[];
    final seen = <String>{};
    for (final c in currentPage.connections) {
      String? otherId;
      if (c.fromId == parentId) {
        otherId = c.toId;
      } else if (c.toId == parentId) {
        otherId = c.fromId;
      }
      if (otherId == null || seen.contains(otherId)) continue;
      final n = nodeMap[otherId];
      if (n == null) continue;
      seen.add(otherId);
      existingChildren.add(n);
    }

    // 既定: 親の中央 Y に揃えて縦に積む
    double y = (parentCenterY - totalH / 2).clamp(0.0, 20000.0 - childH);

    // 新規ノードを置く X 範囲 [startX, startX + childW] と
    // 横方向に重なる既存の子だけを抽出する。
    // (上下に離れているだけで横方向に重ならなければ、衝突しないので無視)
    final overlapColumn = <MindMapNode>[];
    for (final ec in existingChildren) {
      final ecLeft = ec.position.dx;
      final ecRight = ec.position.dx + ec.width;
      // X 軸での重なり判定 (隙間ゼロでも触れていれば重なりとみなす)
      if (ecRight < startX || ecLeft > startX + childW) continue;
      overlapColumn.add(ec);
    }

    if (overlapColumn.isNotEmpty) {
      // 既定の Y 範囲 [y, y+totalH] が、X が重なる既存子の Y と
      // 重なるかを判定。重なる場合は最も低い既存子の下にまとめて配置する。
      bool overlapsExisting() {
        final endY = y + totalH;
        for (final ec in overlapColumn) {
          final ecTop = ec.position.dy;
          final ecBot = ec.position.dy + ec.visualHeight;
          if (ecBot < y || ecTop > endY) continue; // 完全に上下に離れている
          return true;
        }
        return false;
      }

      if (overlapsExisting()) {
        // X が重なる既存子の中で最も下端が低いものを基準に、
        // その下に gap を空けて新規ノード群を縦に並べる。
        double lowestBottom = double.negativeInfinity;
        for (final ec in overlapColumn) {
          final b = ec.position.dy + ec.visualHeight;
          if (b > lowestBottom) lowestBottom = b;
        }
        y = (lowestBottom + gap).clamp(0.0, 20000.0 - childH);
      }
    }

    final newIds = <String>[];
    for (int i = 0; i < count; i++) {
      final id = _uuid.v4();
      final child = MindMapNode(
        id: id,
        title: '',
        position: Offset(startX, y),
        color: _childColor(),
        width: childW,
        height: childH,
      );
      nodeMap[id] = child;
      currentPage.connections.add(NodeConnection(
        fromId: parentId,
        fromAnchor: AnchorDirection.east,
        toId: id,
        toAnchor: AnchorDirection.west,
      ));
      newIds.add(id);
      y += childH + gap;
    }
    // 親がグループ所属なら、生成した子もグループに入れる
    if (newIds.isNotEmpty) {
      addChildrenToParentGroups(parentId, newIds);
    }
    _saveToStorage();
    notifyListeners();
    return newIds;
  }

  /// 複数の親ノードそれぞれに count 個の子ノードを一括生成する。
  /// Undo は 1 回分にまとめる (skipUndo を使い、外側で 1 度だけ _pushUndo()
  /// を呼ぶことで、Ctrl+Z 一発でまとめて巻き戻せる)。
  ///
  /// 戻り値: 生成した全子ノードの ID 一覧 (親ごとに連続)
  List<String> addChildrenToMultipleParents(
      Iterable<String> parentIds, int count) {
    if (count <= 0) return const [];
    final ids = parentIds.toList();
    if (ids.isEmpty) return const [];
    // 1 回だけ Undo を積む (各親への呼び出しでは skipUndo: true で省略)
    _pushUndo();
    final allNew = <String>[];
    for (final pid in ids) {
      allNew.addAll(addChildrenWithCount(pid, count, skipUndo: true));
    }
    return allNew;
  }

  /// ノードのタイトルを [delimiter] で分割し、 複数ノードを生成する。
  /// (= ユーザー要望: ノード内に "a 改行 b" のように区切って書いて分割すると、
  ///  a と b の 2 ノードができる。 区切り文字は指定可能)。
  ///
  /// - 先頭の値は元ノードのタイトルとしてそのまま残す (= 接続も維持)。
  /// - 2 個目以降は元ノードの **兄弟** (= 元ノードと同じ親に接続) として、
  ///   元ノードの下に縦に並べて新規生成する。 親が無ければ独立ノードとして
  ///   下に積む。
  /// - トリム後に非空の値が 2 個未満なら何もせず空リストを返す。
  ///
  /// 戻り値: 新規生成したノード ID 一覧 (= 2 個目以降の分)。
  List<String> splitNodeByDelimiter(String id, String delimiter) {
    final node = currentPage.nodes[id];
    if (node == null) return const [];
    final delim = delimiter.isEmpty ? '\n' : delimiter;
    // 改行区切りのときは \r\n / \r も改行として正規化してから分割する。
    final source = delim == '\n'
        ? node.title.replaceAll('\r\n', '\n').replaceAll('\r', '\n')
        : node.title;
    final parts = source
        .split(delim)
        .map((s) => s.trim())
        .where((s) => s.isNotEmpty)
        .toList();
    if (parts.length < 2) return const [];
    _pushUndo();
    final nodeMap = currentPage.nodes;

    // 元ノードの親 (= toId == id の接続の相手) を集める。 兄弟ノードは
    // これらの親にもぶら下げて、 見た目上の「同列のノード」 にする。
    final parentIds = <String>[];
    final seenParents = <String>{};
    for (final c in currentPage.connections) {
      if (c.toId == id &&
          nodeMap.containsKey(c.fromId) &&
          !seenParents.contains(c.fromId)) {
        seenParents.add(c.fromId);
        parentIds.add(c.fromId);
      }
    }

    // ── 先頭値を元ノードへ反映 (テキストに合わせて自動サイズ) ──
    final firstSizes = _computeAutoSizeForText(
      title: parts.first,
      memo: node.memoText ?? '',
      currentWidth: node.width,
      currentHeight: node.height,
      titleFontSize: node.titleFontSize ?? defaultTitleFontSize,
      memoFontSize: node.memoFontSize ?? defaultMemoFontSize,
    );
    nodeMap[id] = node.copyWith(
      title: parts.first,
      width: firstSizes.$1,
      height: firstSizes.$2,
    );

    // ── 2 個目以降を兄弟ノードとして元ノードの下に縦に並べる ──
    const gap = 16.0;
    double y =
        node.position.dy + (nodeMap[id]?.visualHeight ?? node.height) + gap;
    final newIds = <String>[];
    for (int i = 1; i < parts.length; i++) {
      final nid = _uuid.v4();
      final sizes = _computeAutoSizeForText(
        title: parts[i],
        memo: '',
        currentWidth: 160.0,
        currentHeight: 42.0,
        titleFontSize: node.titleFontSize ?? defaultTitleFontSize,
        memoFontSize: node.memoFontSize ?? defaultMemoFontSize,
      );
      final newNode = MindMapNode(
        id: nid,
        title: parts[i],
        position: Offset(node.position.dx, y),
        color: node.color,
        width: sizes.$1,
        height: sizes.$2,
        titleFontSize: node.titleFontSize,
        memoFontSize: node.memoFontSize,
      );
      nodeMap[nid] = newNode;
      for (final pid in parentIds) {
        currentPage.connections.add(NodeConnection(
          fromId: pid,
          fromAnchor: AnchorDirection.east,
          toId: nid,
          toAnchor: AnchorDirection.west,
        ));
      }
      newIds.add(nid);
      y += newNode.visualHeight + gap;
    }

    // 親がグループ所属なら、 生成した兄弟もそのグループに入れる。
    if (newIds.isNotEmpty && parentIds.isNotEmpty) {
      for (final pid in parentIds) {
        addChildrenToParentGroups(pid, newIds);
      }
    }
    _saveToStorage();
    notifyListeners();
    return newIds;
  }

  /// 指定した複数のノード群を、新規に作成した親ノード 1 個から繋ぐ。
  /// 配置: 選択ノード群の中央左 (各ノードの最も左端より更に左 80px) に親を置き、
  /// 親 (east) → 各子 (west) で接続する。
  ///
  /// 戻り値: 生成した親ノードの ID（失敗したら null）
  String? addParentToNodes(Set<String> childIds) {
    if (childIds.isEmpty) return null;
    final nodeMap = currentPage.nodes;
    // 存在チェック + バウンディングボックス計算
    double minX = double.infinity, maxX = -double.infinity;
    double minY = double.infinity, maxY = -double.infinity;
    final validIds = <String>[];
    for (final id in childIds) {
      final n = nodeMap[id];
      if (n == null) continue;
      validIds.add(id);
      if (n.position.dx < minX) minX = n.position.dx;
      if (n.position.dx + n.width > maxX) maxX = n.position.dx + n.width;
      if (n.position.dy < minY) minY = n.position.dy;
      final bottom = n.position.dy + n.visualHeight;
      if (bottom > maxY) maxY = bottom;
    }
    if (validIds.isEmpty) return null;

    _pushUndo();
    const parentW = 180.0;
    const parentH = 50.0;
    final parentX = (minX - 80 - parentW).clamp(0.0, 20000.0 - parentW);
    final parentY =
        ((minY + maxY) / 2 - parentH / 2).clamp(0.0, 20000.0 - parentH);

    final parentId = _uuid.v4();
    final parent = MindMapNode(
      id: parentId,
      title: '',
      position: Offset(parentX, parentY),
      color: _childColor(),
      width: parentW,
      height: parentH,
    );
    nodeMap[parentId] = parent;
    for (final cid in validIds) {
      currentPage.connections.add(NodeConnection(
        fromId: parentId,
        fromAnchor: AnchorDirection.east,
        toId: cid,
        toAnchor: AnchorDirection.west,
      ));
    }
    _saveToStorage();
    notifyListeners();
    return parentId;
  }

  /// 2ノード間の接続を解除
  void disconnectNodes(String id1, String id2) {
    _pushUndo();
    currentPage.connections.removeWhere((c) =>
        (c.fromId == id1 && c.toId == id2) ||
        (c.fromId == id2 && c.toId == id1));
    _saveToStorage();
    notifyListeners();
  }

  /// 接続のプロパティを更新（太さ・矢印表示・矢印先端サイズ）
  void updateConnection(String fromId, String toId,
      {double? strokeWidth, bool? showArrow, double? arrowHeadScale}) {
    final conns = currentPage.connections;
    final idx = conns.indexWhere((c) => c.fromId == fromId && c.toId == toId);
    if (idx == -1) return;
    _pushUndo();
    conns[idx] = conns[idx].copyWith(
      strokeWidth: strokeWidth,
      showArrow: showArrow,
      arrowHeadScale: arrowHeadScale,
    );
    _saveToStorage();
    notifyListeners();
  }

  /// 複数の接続を一括更新（同じ値を全てに適用、Undoは1回分にまとめる）
  void updateConnections(
    List<NodeConnection> targets, {
    double? strokeWidth,
    bool? showArrow,
    double? arrowHeadScale,
    bool? bidirectional,
    String? label,
    bool clearLabel = false,
  }) {
    if (targets.isEmpty) return;
    final conns = currentPage.connections;
    bool changed = false;
    _pushUndo();
    for (final t in targets) {
      final idx =
          conns.indexWhere((c) => c.fromId == t.fromId && c.toId == t.toId);
      if (idx == -1) continue;
      conns[idx] = conns[idx].copyWith(
        strokeWidth: strokeWidth,
        showArrow: showArrow,
        arrowHeadScale: arrowHeadScale,
        bidirectional: bidirectional,
        label: label,
        clearLabel: clearLabel,
      );
      changed = true;
    }
    if (changed) {
      _saveToStorage();
      notifyListeners();
    }
  }

  /// 接続の方向を反転（A→B を B→A に）
  void reverseConnection(String fromId, String toId) {
    final conns = currentPage.connections;
    final idx = conns.indexWhere((c) => c.fromId == fromId && c.toId == toId);
    if (idx == -1) return;
    _pushUndo();
    final old = conns[idx];
    conns[idx] = NodeConnection(
      fromId: old.toId,
      fromAnchor: old.toAnchor,
      toId: old.fromId,
      toAnchor: old.fromAnchor,
      strokeWidth: old.strokeWidth,
      showArrow: old.showArrow,
      arrowHeadScale: old.arrowHeadScale,
    );
    _saveToStorage();
    notifyListeners();
  }

  // ── 名前付きグループ ──────────────────────────────────────────────────
  /// ページID → { グループ名 → ノードIDリスト }
  final Map<String, Map<String, Set<String>>> _namedGroups = {};

  /// ページID → { グループ名 → カラーインデックス }
  final Map<String, Map<String, int>> _groupColors = {};

  /// ページID → { グループ名 → フォントサイズ }
  final Map<String, Map<String, double>> _groupFontSizes = {};

  /// ページID → { グループ名 → フォントファミリー }
  final Map<String, Map<String, String>> _groupFontFamilies = {};

  /// ページID → { グループ名 → 整列行数 }
  final Map<String, Map<String, int>> _groupLayoutRows = {};

  /// ページID → { グループ名 → 整列モード } 'row'=行数指定 / 'col'=列数指定
  final Map<String, Map<String, String>> _groupLayoutModes = {};

  /// ページID → { グループ名 → 枠の追加パディング [left, top, right, bottom] }
  final Map<String, Map<String, List<double>>> _groupPadding = {};

  /// 現在のページの名前付きグループ一覧
  Map<String, Set<String>> get namedGroups => _namedGroups[_pageId] ?? {};

  /// グループのカラーインデックスを取得（-1なら自動）
  int getGroupColorIndex(String name) => _groupColors[_pageId]?[name] ?? -1;

  /// グループのカラーインデックスを設定
  void setGroupColor(String name, int colorIndex) {
    final id = _pageId;
    _groupColors.putIfAbsent(id, () => {});
    _groupColors[id]![name] = colorIndex;
    _saveNamedGroups();
    notifyListeners();
  }

  /// グループのフォントサイズを取得（null = デフォルト13）
  double getGroupFontSize(String name) =>
      _groupFontSizes[_pageId]?[name] ?? 13.0;

  void setGroupFontSize(String name, double size) {
    final id = _pageId;
    _groupFontSizes.putIfAbsent(id, () => {});
    _groupFontSizes[id]![name] = size;
    _saveNamedGroups();
    notifyListeners();
  }

  /// グループのフォントファミリーを取得（空 = デフォルト）
  String getGroupFontFamily(String name) =>
      _groupFontFamilies[_pageId]?[name] ?? '';

  void setGroupFontFamily(String name, String family) {
    final id = _pageId;
    _groupFontFamilies.putIfAbsent(id, () => {});
    _groupFontFamilies[id]![name] = family;
    _saveNamedGroups();
    notifyListeners();
  }

  /// グループの整列行数を取得（デフォルト3）
  int getGroupLayoutRows(String name) => _groupLayoutRows[_pageId]?[name] ?? 3;

  void setGroupLayoutRows(String name, int rows) {
    final id = _pageId;
    _groupLayoutRows.putIfAbsent(id, () => {});
    _groupLayoutRows[id]![name] = rows.clamp(1, 20);
    _saveNamedGroups();
    notifyListeners();
  }

  /// グループの整列モード ('row'=行数指定 / 'col'=列数指定)
  String getGroupLayoutMode(String name) =>
      _groupLayoutModes[_pageId]?[name] ?? 'row';

  void setGroupLayoutMode(String name, String mode) {
    final id = _pageId;
    _groupLayoutModes.putIfAbsent(id, () => {});
    _groupLayoutModes[id]![name] = (mode == 'col') ? 'col' : 'row';
    _saveNamedGroups();
    notifyListeners();
  }

  /// グループの枠の追加パディング [left, top, right, bottom]
  List<double> getGroupPadding(String name) =>
      _groupPadding[_pageId]?[name] ?? const [0.0, 0.0, 0.0, 0.0];

  void setGroupPadding(String name, List<double> padding) {
    final id = _pageId;
    _groupPadding.putIfAbsent(id, () => {});
    // 負値を許可しない
    final p = List<double>.generate(
        4, (i) => (i < padding.length ? padding[i] : 0.0).clamp(0.0, 10000.0));
    _groupPadding[id]![name] = p;
    _saveNamedGroups();
    notifyListeners();
  }

  /// グループ内のノードをグリッド状に整列
  /// mode が 'row' なら行数固定、'col' なら列数固定
  void arrangeGroup(String groupName,
      {double gapX = 40.0, double gapY = 40.0}) {
    final ids = namedGroups[groupName];
    if (ids == null || ids.isEmpty) return;
    final nodeList = ids
        .map((id) => currentPage.nodes[id])
        .whereType<MindMapNode>()
        .toList();
    if (nodeList.isEmpty) return;
    _pushUndo();
    // 基準位置 = グループ内の最左上のノード
    double baseX = double.infinity, baseY = double.infinity;
    for (final n in nodeList) {
      if (n.position.dx < baseX) baseX = n.position.dx;
      if (n.position.dy < baseY) baseY = n.position.dy;
    }
    final target = getGroupLayoutRows(groupName);
    final mode = getGroupLayoutMode(groupName);
    final int cols;
    if (mode == 'col') {
      // 列数指定モード
      cols = target;
    } else {
      // 行数指定モード → 列数を自動算出
      cols = (nodeList.length / target).ceil();
    }
    // 列幅は最大幅、行高は最大visualHeightを基準
    double maxW = 0, maxH = 0;
    for (final n in nodeList) {
      if (n.width > maxW) maxW = n.width;
      if (n.visualHeight > maxH) maxH = n.visualHeight;
    }
    for (int i = 0; i < nodeList.length; i++) {
      final row = i ~/ cols;
      final col = i % cols;
      final pos = Offset(
        baseX + col * (maxW + gapX),
        baseY + row * (maxH + gapY),
      );
      final n = nodeList[i];
      currentPage.nodes[n.id] = n.copyWith(position: pos);
    }
    _saveToStorage();
    notifyListeners();
  }

  // ─── ギャラリー整列 (= ユーザー要望: PDF/画像/動画を等間隔・同寸タイルで並べる) ───
  /// ギャラリータイル 1 枚の幅 (px)。 (= ユーザー要望: もう少し大きく)
  static const double kShelfTileW = 190.0;

  /// 1 段(行)あたりの既定タイル数 (shelfPerRow が 0 = 自動 の時に使う)。
  static const int kShelfDefaultPerRow = 10;

  /// 表紙の自然比が取れない添付ノードのフォールバック比 (= 幅/高さ、 縦長)。
  static const double kShelfFallbackAr = 0.71;

  /// ギャラリータイル間の間隔。
  static const double kShelfGap = 16.0;

  /// 中身の周りに確保する余白 (= 中央寄せ + 端の余裕)。
  static const double kShelfPad = 80.0;

  /// ギャラリーキャンバスの最小サイズ。 中身が少なくても中央付近に見えるように、
  /// この大きさは確保して中身を中央に置く (= ユーザー要望: 中央開始)。
  static const double kShelfMinCanvasW = 1100.0;
  static const double kShelfMinCanvasH = 720.0;

  // ── ギャラリー 自由グリッド (= ユーザー要望: 埋めたセルの下と右に +ボックスが
  //    増える 2D 配置)。 各ノードのセル (col,row) を明示的に保持し、 挿入順で
  //    再パックせず、 セルに従って配置する。 セルは prefs に永続化する。 ──
  final Map<String, List<int>> _shelfCells = {};

  /// ギャラリータイルの行ピッチ算出用の行高 (= 最大 visualHeight)。
  double _shelfRowH(MindMapPage page) {
    double rowH = 0;
    for (final n in page.nodes.values) {
      if (n.visualHeight > rowH) rowH = n.visualHeight;
    }
    // 空のギャラリー (= +ボックスだけ) の代表行高。 (= ユーザー要望: +ブロックの
    //   縦の長さをもう少し小さく。 旧 190/0.71+42=310 → 約 209)。
    if (rowH <= 0) rowH = kShelfTileW * 1.1;
    return rowH;
  }

  /// セル (col,row) の左上座標。
  Offset _shelfCellPos(int col, int row, double rowH) => Offset(
      kShelfGap + col * (kShelfTileW + kShelfGap),
      kShelfGap + row * (rowH + kShelfGap));

  /// セル (col,row) の矩形。
  Rect _shelfCellRect(int col, int row, double rowH) {
    final p = _shelfCellPos(col, row, rowH);
    return Rect.fromLTWH(p.dx, p.dy, kShelfTileW, rowH);
  }

  // ── 可変サイズ格子 (= ユーザー要望 #4/#5) ───────────────────────────────
  //  各列の幅は「+ボックス幅 (kShelfTileW)」 を下限に、 その列で最も広い要素の
  //  幅まで広がる。 各行の高さも同様に visualHeight 基準。 列間/行間の隙間
  //  (kShelfGap) は要素の大小に関わらず一定。 これで「要素を大きくしても
  //  重ならず一定間隔」 (#4)、 「小さい要素も +ボックスの大きさで表示」 (#5)。
  ({List<double> colX, List<double> rowY, List<double> colW, List<double> rowH})
      _buildShelfGrid(MindMapPage page) {
    const double bw = kShelfTileW; // 列幅の下限 (= +ボックス幅)
    const double gap = kShelfGap;
    final double defRowH = bw * 1.1; // 行高の下限 (= 空セルの代表値)
    int maxCol = -1, maxRow = -1;
    _shelfCells.forEach((id, c) {
      if (!page.nodes.containsKey(id)) return;
      if (c[0] > maxCol) maxCol = c[0];
      if (c[1] > maxRow) maxRow = c[1];
    });
    // グリッドは「設定された縦横の要素数」 (= +ボックスの範囲) を下限にし、
    //   手動でその外へ置かれた要素 (maxCol/maxRow) も収まるよう拡張する
    //   (= ユーザー要望: +ボックスは勝手に増えないが、 はみ出し要素も描画できる)。
    final int gridCols = _shelfGridCols(page);
    final int gridRows = _shelfGridRows(page);
    int cols = maxCol + 1 > gridCols ? maxCol + 1 : gridCols;
    int rows = maxRow + 1 > gridRows ? maxRow + 1 : gridRows;
    final colW = List<double>.filled(cols, bw);
    final rowH = List<double>.filled(rows, defRowH);
    _shelfCells.forEach((id, c) {
      final n = page.nodes[id];
      if (n == null) return;
      final col = c[0], row = c[1];
      if (col >= 0 && col < cols) {
        final w = n.width < bw ? bw : n.width; // #5: 下限は +ボックス幅
        if (w > colW[col]) colW[col] = w;
      }
      if (row >= 0 && row < rows) {
        final h = n.visualHeight;
        if (h > rowH[row]) rowH[row] = h;
      }
    });
    final colX = List<double>.filled(cols + 1, 0);
    colX[0] = gap;
    for (int c = 0; c < cols; c++) {
      colX[c + 1] = colX[c] + colW[c] + gap;
    }
    final rowY = List<double>.filled(rows + 1, 0);
    rowY[0] = gap;
    for (int r = 0; r < rows; r++) {
      rowY[r + 1] = rowY[r] + rowH[r] + gap;
    }
    return (colX: colX, rowY: rowY, colW: colW, rowH: rowH);
  }

  // 格子の範囲外 (フロンティアの更に外側) は既定サイズで外挿する。
  double _gridX(
      ({List<double> colX, List<double> rowY, List<double> colW, List<double> rowH}) g,
      int col) {
    final n = g.colW.length;
    if (col >= 0 && col <= n) return g.colX[col];
    if (col < 0) return kShelfGap + col * (kShelfTileW + kShelfGap);
    return g.colX[n] + (col - n) * (kShelfTileW + kShelfGap);
  }

  double _gridY(
      ({List<double> colX, List<double> rowY, List<double> colW, List<double> rowH}) g,
      int row) {
    final n = g.rowH.length;
    final defRowH = kShelfTileW * 1.1;
    if (row >= 0 && row <= n) return g.rowY[row];
    if (row < 0) return kShelfGap + row * (defRowH + kShelfGap);
    return g.rowY[n] + (row - n) * (defRowH + kShelfGap);
  }

  double _gridW(
      ({List<double> colX, List<double> rowY, List<double> colW, List<double> rowH}) g,
      int col) =>
      (col >= 0 && col < g.colW.length) ? g.colW[col] : kShelfTileW;

  double _gridH(
      ({List<double> colX, List<double> rowY, List<double> colW, List<double> rowH}) g,
      int row) =>
      (row >= 0 && row < g.rowH.length) ? g.rowH[row] : kShelfTileW * 1.1;

  Offset _shelfCellPos2(
          ({List<double> colX, List<double> rowY, List<double> colW, List<double> rowH}) g,
          int col,
          int row) =>
      Offset(_gridX(g, col), _gridY(g, row));

  Rect _shelfCellRect2(
      ({List<double> colX, List<double> rowY, List<double> colW, List<double> rowH}) g,
      int col,
      int row) =>
      Rect.fromLTWH(_gridX(g, col), _gridY(g, row), _gridW(g, col), _gridH(g, row));

  /// ドロップ X 座標に最も近い列番号 (= セル中心との距離で判定)。
  int _nearestShelfCol(
      ({List<double> colX, List<double> rowY, List<double> colW, List<double> rowH}) g,
      double x) {
    int best = 0;
    double bestD = double.infinity;
    final limit = g.colW.length + 4;
    for (int c = 0; c < limit; c++) {
      final center = _gridX(g, c) + _gridW(g, c) / 2;
      final d = (x - center).abs();
      if (d < bestD) {
        bestD = d;
        best = c;
      }
    }
    return best;
  }

  int _nearestShelfRow(
      ({List<double> colX, List<double> rowY, List<double> colW, List<double> rowH}) g,
      double y) {
    int best = 0;
    double bestD = double.infinity;
    final limit = g.rowH.length + 4;
    for (int r = 0; r < limit; r++) {
      final center = _gridY(g, r) + _gridH(g, r) / 2;
      final d = (y - center).abs();
      if (d < bestD) {
        bestD = d;
        best = r;
      }
    }
    return best;
  }

  /// 指定ノードのギャラリーセル。 未割り当てなら null。
  List<int>? shelfCellOf(String nodeId) {
    final c = _shelfCells[nodeId];
    return c == null ? null : [c[0], c[1]];
  }

  /// 指定ノードにギャラリーセルを割り当てる (= +ボックスに的確にドロップ/追加した
  /// 時にその位置へ置く)。
  void setShelfCell(String nodeId, int col, int row) {
    _shelfCells[nodeId] = [col, row];
    _saveShelfCells();
  }

  /// ギャラリーの (fromCol,row) に [count] 個ぶんの空きセルを確保する
  /// (= ユーザー要望: 動画の数分ブロックを確保 / 既存要素をずらして間に挿入)。
  /// 同じ行で col が fromCol 以上の既存セルを右へ count ずらす。 これで
  /// [fromCol, fromCol+count) が空き、 そこへ新要素を重ならず置ける。
  void _reserveShelfCells(int row, int fromCol, int count) {
    if (count <= 0) return;
    _shelfCells.forEach((id, c) {
      if (c[1] == row && c[0] >= fromCol) {
        c[0] = c[0] + count;
      }
    });
  }

  /// 範囲選択したギャラリー要素を、 ドラッグ量ぶんセル単位でまとめて移動する
  /// (= ユーザー要望: ギャラリーの要素を範囲選択してまとめて移動できるように)。
  /// ピクセルの移動量をセル数に換算して、 各要素の (col,row) をその分ずらす。
  void moveShelfCellsByDelta(Set<String> ids, Offset pixelDelta) {
    final page = currentPage;
    if (page.pageType != 'bookshelf' || ids.isEmpty) return;
    final rowH = _shelfRowH(page);
    final stepX = kShelfTileW + kShelfGap;
    final stepY = rowH + kShelfGap;
    final dCol = (pixelDelta.dx / stepX).round();
    final dRow = (pixelDelta.dy / stepY).round();
    if (dCol != 0 || dRow != 0) {
      for (final id in ids) {
        final c = _shelfCells[id];
        if (c != null) {
          c[0] = (c[0] + dCol) < 0 ? 0 : c[0] + dCol;
          c[1] = (c[1] + dRow) < 0 ? 0 : c[1] + dRow;
        }
      }
      // 既存 (非選択) 要素と重なる場合は、 既存要素を横 (右) のブロックへずらす
      //   (= ユーザー要望: 既存要素の上に置くと複数重なるのを回避)。
      _resolveShelfCollisions(ids);
      _saveShelfCells();
    }
    // セルから位置を再導出 (ドラッグ中の生位置を確定セル位置へ戻す)。
    _arrangeAsBookshelfBody(page);
    _saveToStorage();
    notifyListeners();
  }

  /// 同じセルに複数要素がある時、 [keep] のセルを固定し、 それ以外 (既存要素) を
  /// 同じ行で右の空きセルへ押しのける (= ユーザー要望: 範囲選択した要素を既存の
  /// 上に置いたら既存が横へずれる)。
  void _resolveShelfCollisions(Set<String> keep) {
    final page = currentPage;
    final byRow = <int, List<MapEntry<String, List<int>>>>{};
    for (final e in _shelfCells.entries) {
      if (!page.nodes.containsKey(e.key)) continue;
      byRow.putIfAbsent(e.value[1], () => []).add(e);
    }
    byRow.forEach((row, entries) {
      // keep (移動した要素) の列は固定として予約。
      final taken = <int>{};
      for (final e in entries) {
        if (keep.contains(e.key)) taken.add(e.value[0]);
      }
      // 非 keep を col 昇順に、 予約/使用済みを避けて右へ詰め直す。
      final others = entries.where((e) => !keep.contains(e.key)).toList()
        ..sort((a, b) => a.value[0] - b.value[0]);
      for (final e in others) {
        int col = e.value[0] < 0 ? 0 : e.value[0];
        while (taken.contains(col)) {
          col++;
        }
        e.value[0] = col;
        taken.add(col);
      }
    });
  }

  /// ギャラリーで要素が削除された後、 各行のセルを左詰めして gap を除去する。
  /// (= ユーザー要望: 要素を詰めるのは「同じ行内だけ」 にする。 行をまたいで
  ///  要素が動くと、 削除のたびに別の段から要素が飛んできて「変な位置に動いた」
  ///  ように見えてしまうため。)
  /// 行番号 (row) は一切変えず、 各行の中だけで col を昇順に 0,1,2... と
  /// 振り直して隙間を詰める。 ある行が空になっても、 下の段は繰り上げない。
  void compactShelfCells() {
    final page = currentPage;
    if (page.pageType != 'bookshelf') return;
    // 既に存在しないノードのセル情報を掃除。
    _shelfCells.removeWhere((id, _) => !page.nodes.containsKey(id));
    if (_shelfCells.isEmpty) return;
    // 行ごとにグループ化し、 その行内の列だけを左詰めする。
    final byRow = <int, List<MapEntry<String, List<int>>>>{};
    for (final e in _shelfCells.entries) {
      byRow.putIfAbsent(e.value[1], () => []).add(e);
    }
    bool changed = false;
    byRow.forEach((row, list) {
      list.sort((a, b) => a.value[0] - b.value[0]);
      for (int i = 0; i < list.length; i++) {
        final cur = _shelfCells[list[i].key]!;
        if (cur[0] != i || cur[1] != row) {
          _shelfCells[list[i].key] = [i, row];
          changed = true;
        }
      }
    });
    if (changed) {
      _saveShelfCells();
      notifyListeners();
    }
  }

  /// ギャラリーの要素を行優先 (row-major) で隙間なく詰め直す
  /// (= ユーザー要望: 動画を見終わって削除されたら「行単位」 で要素を詰める)。
  /// compactShelfCells は行内の列詰めだけで行をまたぐ穴を埋めないため、 こちらは
  /// 全要素を [0,0],[1,0]..[cols-1,0],[0,1].. と再配置して穴 (空セル) を消す。
  /// 表紙に隠れている (hiddenInContainer != null) メンバーはセルを占有しないので
  /// 除外し、 表紙コンテナ (isContainer) 自体は通常の占有要素として含める。
  void repackShelfCellsRowMajor([MindMapPage? p]) {
    final page = p ?? currentPage;
    if (page.pageType != 'bookshelf') return;
    _shelfCells.removeWhere((id, _) => !page.nodes.containsKey(id));
    final occupants = _shelfCells.entries.where((e) {
      final n = page.nodes[e.key];
      return n != null && n.hiddenInContainer == null;
    }).toList()
      // 現在の見た目の並び (上→下、 左→右) を保ったまま詰める。
      ..sort((a, b) {
        final dr = a.value[1].compareTo(b.value[1]);
        return dr != 0 ? dr : a.value[0].compareTo(b.value[0]);
      });
    final cols = _shelfGridCols(page);
    bool changed = false;
    for (int i = 0; i < occupants.length; i++) {
      final col = i % cols;
      final row = i ~/ cols;
      final cur = _shelfCells[occupants[i].key]!;
      if (cur[0] != col || cur[1] != row) {
        _shelfCells[occupants[i].key] = [col, row];
        changed = true;
      }
    }
    if (changed) {
      _saveShelfCells();
      notifyListeners();
    }
  }

  /// セル未割り当てのギャラリーノードを「下段の右」へ順に割り当てる
  /// (= ユーザー要望: 適当にドロップしたら今出てる下の段に右方向に並べる)。
  /// ギャラリーの既定グリッド (= ユーザー要望: デフォルト 5 行 × 5 列)。
  static const int kShelfDefaultGridCols = 5;
  static const int kShelfDefaultGridRows = 5;

  /// ギャラリーの有効な列数 (= 横の要素数)。 shelfPerRow が 0 なら既定値 (5)。
  int _shelfGridCols([MindMapPage? p]) {
    final page = p ?? currentPage;
    final v = page.shelfPerRow > 0 ? page.shelfPerRow : kShelfDefaultGridCols;
    return v.clamp(1, 50);
  }

  /// ギャラリーの有効な段数 (= 縦の要素数)。 shelfRows が 0 なら既定値 (5)。
  /// ただし要素が指定段数を超えたら +ボックスを 1 段ぶん出せるよう拡張する
  /// (= ユーザー要望: 既定 5×5、 勝手には増えないが満杯時は追加できる)。
  int _shelfGridRows([MindMapPage? p]) {
    final page = p ?? currentPage;
    final cols = _shelfGridCols(page);
    // 表紙 (格納コンテナ) に隠れている要素はセルを占有しないので除外して数える
    // (= 大量取り込みを 1 表紙にまとめてもグリッドが膨らまないように)。
    final visible =
        page.nodes.values.where((n) => n.hiddenInContainer == null).length;
    final needed = (visible / cols).ceil();
    final base = page.shelfRows > 0 ? page.shelfRows : kShelfDefaultGridRows;
    final rows = base > needed ? base : needed + 1;
    return rows.clamp(1, 9999);
  }

  /// ギャラリーのグリッド総セル数 (横 × 縦) を返す (= 既定 5×5 = 25)。
  /// 画面側の「25 要素超で拡張確認」 判定に使う。
  /// (列数の公開アクセサは既存の getter `shelfGridCols` を使う)
  int shelfGridCapacity([MindMapPage? p]) =>
      _shelfGridCols(p) * _shelfGridRows(p);

  /// 表紙に隠れていない (= グリッドのセルを占有する) 要素数。
  int shelfVisibleCount([MindMapPage? p]) => (p ?? currentPage)
      .nodes
      .values
      .where((n) => n.hiddenInContainer == null)
      .length;

  /// row-major で最初の空きセルを探す (cols 列で折り返し、 占有セルはスキップ)。
  /// [occ] に既存の占有セル ("col,row") を渡すと差分計算を省ける。
  List<int> _nextFreeShelfCell(Set<String> occ, {int fromCol = 0, int fromRow = 0}) {
    final cols = _shelfGridCols();
    int col = fromCol < 0 ? 0 : (fromCol >= cols ? 0 : fromCol);
    int row = fromRow < 0 ? 0 : fromRow;
    while (occ.contains('$col,$row')) {
      col++;
      if (col >= cols) {
        col = 0;
        row++;
      }
    }
    return [col, row];
  }

  /// セルが未割り当てのノードを row-major で詰める (= ユーザー要望: 横に
  /// 入りきらない場合は次の行の 1 列目から右へ、 既にある所はスキップ)。
  void _ensureShelfCells(MindMapPage page) {
    final occ = <String>{};
    for (final id in page.nodes.keys) {
      final c = _shelfCells[id];
      if (c != null) occ.add('${c[0]},${c[1]}');
    }
    bool changed = false;
    for (final id in page.nodes.keys) {
      if (_shelfCells.containsKey(id)) continue;
      final cell = _nextFreeShelfCell(occ);
      _shelfCells[id] = [cell[0], cell[1]];
      occ.add('${cell[0]},${cell[1]}');
      changed = true;
    }
    if (changed) _saveShelfCells();
  }

  /// ギャラリーの「+ボックス」 セル群 (= ユーザー要望: +ボックスが勝手に増えず、
  /// 設定した縦横の要素数のグリッド内の空きセルだけを返す)。 グリッド幅は
  /// 列数 (横)、 高さは段数 (縦) に固定。 これにより右方向への際限ない増殖を防ぐ。
  List<List<int>> bookshelfFrontierCells() {
    final page = currentPage;
    if (page.pageType != 'bookshelf') return const [];
    final occ = <String>{};
    for (final id in page.nodes.keys) {
      final c = _shelfCells[id];
      if (c != null) occ.add('${c[0]},${c[1]}');
    }
    final cols = _shelfGridCols(page);
    final rows = _shelfGridRows(page);
    final out = <List<int>>[];
    for (int row = 0; row < rows; row++) {
      for (int col = 0; col < cols; col++) {
        if (!occ.contains('$col,$row')) out.add([col, row]);
      }
    }
    return out;
  }

  /// ギャラリーの +ボックス矩形群 (描画 + ドロップ判定用)。
  List<Rect> bookshelfFrontierRects() {
    final page = currentPage;
    if (page.pageType != 'bookshelf') return const [];
    final grid = _buildShelfGrid(page);
    return bookshelfFrontierCells()
        .map((c) => _shelfCellRect2(grid, c[0], c[1]))
        .toList();
  }

  /// 指定キャンバス座標が +ボックス上ならそのセル、 そうでなければ null。
  List<int>? bookshelfFrontierCellAt(Offset canvasPos) {
    final page = currentPage;
    if (page.pageType != 'bookshelf') return null;
    final grid = _buildShelfGrid(page);
    for (final c in bookshelfFrontierCells()) {
      if (_shelfCellRect2(grid, c[0], c[1]).contains(canvasPos)) return c;
    }
    return null;
  }

  Future<void> _saveShelfCells() async {
    final prefs = await SharedPreferences.getInstance();
    final m = <String, dynamic>{};
    _shelfCells.forEach((k, v) => m[k] = [v[0], v[1]]);
    await prefs.setString('shelfCells_v1', jsonEncode(m));
  }

  Future<void> _loadShelfCells() async {
    final prefs = await SharedPreferences.getInstance();
    final s = prefs.getString('shelfCells_v1');
    if (s == null || s.isEmpty) return;
    try {
      final m = jsonDecode(s) as Map<String, dynamic>;
      _shelfCells.clear();
      m.forEach((k, v) {
        if (v is List && v.length >= 2) {
          _shelfCells[k] = [(v[0] as num).toInt(), (v[1] as num).toInt()];
        }
      });
    } catch (_) {}
    notifyListeners();
  }

  /// ギャラリーの列数を求める。 ギャラリー全体の整列では末尾の常設 +ボックス 1 枠も
  /// 数に含めて、 +ボックスが本の隣 (同じ行) に収まるようにする。
  int _shelfCols(MindMapPage page, int itemCount,
      {int? perRow, bool wholeShelf = true}) {
    final raw = perRow ??
        (page.shelfPerRow > 0 ? page.shelfPerRow : kShelfDefaultPerRow);
    final slots = wholeShelf ? itemCount + 1 : itemCount;
    return raw.clamp(1, slots < 1 ? 1 : slots);
  }

  /// ギャラリーの格子ジオメトリ (整列・キャンバス寸法・+ボックス位置で共用)。
  /// 中身 (+ボックス 1 枠を含む) をキャンバス中央に配置する。
  ({int cols, double canvasW, double canvasH, double baseX, double baseY})
      _shelfGeometry(MindMapPage page, int itemCount, double rowH) {
    const double bw = kShelfTileW;
    const double gap = kShelfGap;
    final cols = _shelfCols(page, itemCount, wholeShelf: true);
    final total = itemCount + 1; // 末尾の +ボックス
    final rows = (total / cols).ceil();
    final colsForWidth = rows > 1 ? cols : (total < cols ? total : cols);
    final contentW = colsForWidth * bw + (colsForWidth - 1) * gap;
    final contentH = rows * rowH + (rows - 1) * gap;
    final canvasW = (contentW + 2 * kShelfPad).clamp(kShelfMinCanvasW, 20000.0);
    final canvasH = (contentH + 2 * kShelfPad).clamp(kShelfMinCanvasH, 20000.0);
    final baseX = ((canvasW - contentW) / 2).clamp(0.0, canvasW);
    final baseY = ((canvasH - contentH) / 2).clamp(0.0, canvasH);
    return (
      cols: cols,
      canvasW: canvasW,
      canvasH: canvasH,
      baseX: baseX,
      baseY: baseY,
    );
  }

  /// ギャラリーの「+ボックス」 (= 次の空きスロット) の矩形。 現在ページがギャラリーで
  /// なければ null。 整列済みの既存タイルと同じ格子計算で次のセルを返す。
  Rect? bookshelfAddSlotRect() {
    final page = currentPage;
    if (page.pageType != 'bookshelf') return null;
    const double bw = kShelfTileW;
    const double gap = kShelfGap;
    final list = page.nodes.values.toList();
    double rowH = 0;
    for (final n in list) {
      if (n.visualHeight > rowH) rowH = n.visualHeight;
    }
    if (rowH <= 0) rowH = bw * 1.1; // 空のギャラリーの代表値 (= 縦を少し小さく)
    final geo = _shelfGeometry(page, list.length, rowH);
    final i = list.length;
    final row = i ~/ geo.cols;
    final col = i % geo.cols;
    return Rect.fromLTWH(
        geo.baseX + col * (bw + gap), geo.baseY + row * (rowH + gap), bw, rowH);
  }

  /// ギャラリーキャンバスの実寸 (= 中身を中央に置いたサイズ)。 これより外へは
  /// パンできないようにするための寸法 (= ユーザー要望)。
  Size bookshelfCanvasSize() {
    final page = currentPage;
    // 中身 (タイル) + 末端の +ボックス群を囲む矩形 + ごく僅かな余白だけを
    // パン可能範囲にする (= ユーザー要望: 要素のない所には出られないように。
    // 大きな最小サイズで余白を作ると画面外に出て戻れなくなるため廃止)。
    double maxX = 0, maxY = 0;
    void acc(double right, double bottom) {
      if (right > maxX) maxX = right;
      if (bottom > maxY) maxY = bottom;
    }

    for (final n in page.nodes.values) {
      acc(n.position.dx + n.width, n.position.dy + n.visualHeight);
    }
    for (final r in bookshelfFrontierRects()) {
      acc(r.right, r.bottom);
    }
    const pad = kShelfGap * 2; // 端の僅かな余白 (32px)
    return Size(
        (maxX + pad).clamp(400.0, 20000.0), (maxY + pad).clamp(300.0, 20000.0));
  }

  /// 選択ノード or ページ全体を「ギャラリー」 のように同寸タイルで整列する。
  /// [pageId] 省略時は現在ページ。 [onlyIds] 指定時はその集合だけを対象に
  /// する (= 通常ページで選択を整列する用途)。 [perRow] 省略時はページの
  /// shelfPerRow (0 なら自動)。 公開メソッドは Undo を 1 つ積む。
  void arrangeAsBookshelf(
      {String? pageId, Set<String>? onlyIds, int? perRow, double gap = 16.0}) {
    final page = pageId == null
        ? currentPage
        : _pages.firstWhere((p) => p.id == pageId, orElse: () => currentPage);
    final ids = onlyIds ?? page.nodes.keys.toSet();
    if (!ids.any((id) => page.nodes[id] != null)) return;
    _pushUndo();
    _arrangeAsBookshelfBody(page, onlyIds: onlyIds, perRow: perRow, gap: gap);
    _saveToStorage();
    notifyListeners();
    autoSavePageIfLinked(page.id);
  }

  /// ギャラリーページを Undo を積まずに整列し直す (= ページを開いた直後に中身を
  /// きれいに並べ直す用途。 Undo 履歴を汚さない)。
  void reflowBookshelf() {
    final page = currentPage;
    if (page.pageType != 'bookshelf') return;
    _arrangeAsBookshelfBody(page);
    _saveToStorage();
    notifyListeners();
  }

  /// ギャラリーの縦横の要素数 (列数 / 段数) を手動設定する (= ユーザー要望:
  /// +ボックスが勝手に増えないよう、 設定から縦横を固定できる)。 0 で自動。
  void setShelfGrid({int? cols, int? rows}) {
    final page = currentPage;
    if (page.pageType != 'bookshelf') return;
    if (cols != null) page.shelfPerRow = cols < 0 ? 0 : cols.clamp(0, 50);
    if (rows != null) page.shelfRows = rows < 0 ? 0 : rows.clamp(0, 200);
    _arrangeAsBookshelfBody(page);
    _saveToStorage();
    notifyListeners();
  }

  /// 現在のギャラリーの有効な列数 / 段数 (UI 表示用)。
  int get shelfGridCols => _shelfGridCols();
  int get shelfGridRows => currentPage.shelfRows;

  /// ギャラリーで見終わった動画ノードを削除する (= ユーザー要望: 見終わった動画を
  /// 削除する設定。 autoDeleteWatched が ON のときだけ動く)。 動画プレイヤーが
  /// 閉じた後に呼ぶ。
  void cleanupWatchedBookshelfVideos() {
    if (!_autoDeleteWatched) return;
    final page = currentPage;
    if (page.pageType != 'bookshelf') return;
    final toDelete = <String>[];
    for (final n in page.nodes.values) {
      final vid = _extractYtVideoId(n.youtubeUrl ?? '');
      if (vid != null && _fullyWatchedVideoIds.contains(vid)) {
        toDelete.add(n.id);
      }
    }
    if (toDelete.isEmpty) return;
    _pushUndo();
    for (final id in toDelete) {
      page.nodes.remove(id);
      page.connections.removeWhere((c) => c.fromId == id || c.toId == id);
      _shelfCells.remove(id);
    }
    // 削除で空いたセルを行優先で詰めて穴を消す (= ユーザー要望: 見終わって削除
    //   されたら行単位で要素を詰める)。 repack 内で _saveShelfCells/notify する。
    repackShelfCellsRowMajor(page);
    _arrangeAsBookshelfBody(page);
    _saveShelfCells();
    _saveToStorage();
    notifyListeners();
  }

  /// ドラッグでドロップしたブロックを最寄りのグリッドセルにスナップする
  /// (= ユーザー要望: ギャラリーでは自由配置ではなく候補区画のみに置ける)。
  /// 移動先セルが他のブロックで埋まっていれば元の位置のまま整列だけし直す。
  /// ドラッグ中、 [draggedId] を [droppedPos] に置いたとき入れ替わる先の
  /// 要素 id を返す (空セルなら null)。 [snapNodeToShelfCell] の占有判定と
  /// 同じロジックの読み取り専用版で、 ドラッグ中のハイライト表示に使う
  /// (= ユーザー要望: どこと入れ替わるか枠で分かるように)。
  String? shelfSwapTargetAt(String draggedId, Offset droppedPos) {
    final page = currentPage;
    if (page.pageType != 'bookshelf') return null;
    if (!page.nodes.containsKey(draggedId)) return null;
    final grid = _buildShelfGrid(page);
    int col = _nearestShelfCol(grid, droppedPos.dx);
    int row = _nearestShelfRow(grid, droppedPos.dy);
    if (col < 0) col = 0;
    if (row < 0) row = 0;
    for (final entry in _shelfCells.entries) {
      if (entry.key == draggedId) continue;
      if (!page.nodes.containsKey(entry.key)) continue;
      if (entry.value[0] == col && entry.value[1] == row) return entry.key;
    }
    return null;
  }

  /// ドロップ点に最も近い「+ブロック」 (フロンティアセル) を返す (無ければ null)。
  List<int>? _nearestFrontierCell(Offset pos) {
    final page = currentPage;
    if (page.pageType != 'bookshelf') return null;
    final grid = _buildShelfGrid(page);
    final cells = bookshelfFrontierCells();
    List<int>? best;
    double bestD = double.infinity;
    for (final c in cells) {
      final center = _shelfCellRect2(grid, c[0], c[1]).center;
      final d = (center - pos).distanceSquared;
      if (d < bestD) {
        bestD = d;
        best = c;
      }
    }
    return best;
  }

  void snapNodeToShelfCell(String nodeId, Offset droppedPos) {
    final page = currentPage;
    if (page.pageType != 'bookshelf') return;
    if (!page.nodes.containsKey(nodeId)) return;
    // 可変サイズ格子 (#4/#5) に合わせ、 セル中心との距離で最寄り列/行を求める。
    final grid = _buildShelfGrid(page);
    int col = _nearestShelfCol(grid, droppedPos.dx);
    int row = _nearestShelfRow(grid, droppedPos.dy);
    if (col < 0) col = 0;
    if (row < 0) row = 0;
    // 移動先セルを占有している他ノードを探す。
    String? occupantId;
    for (final entry in _shelfCells.entries) {
      if (entry.key == nodeId) continue;
      if (!page.nodes.containsKey(entry.key)) continue;
      if (entry.value[0] == col && entry.value[1] == row) {
        occupantId = entry.key;
        break;
      }
    }
    final myCell = _shelfCells[nodeId];
    // 自分の元セルへ戻す (= ほぼ同じ位置にドロップ) なら何もしない。
    if (occupantId == null &&
        myCell != null &&
        myCell[0] == col &&
        myCell[1] == row) {
      _arrangeAsBookshelfBody(page);
      notifyListeners();
      return;
    }
    _pushUndo();
    if (occupantId != null) {
      // ── 占有セルへドロップ → 2 要素の位置を入れ替える ──
      // (= ユーザー要望: ギャラリーで要素同士の位置を変えられるように)。
      _shelfCells[nodeId] = [col, row];
      if (myCell != null) {
        _shelfCells[occupantId] = [myCell[0], myCell[1]];
      }
    } else {
      // ── 空きへのドロップは必ず「+ブロック」 (フロンティアセル) に吸着させる ──
      //   (= ユーザー要望: +ブロック以外の所に要素が配置されるとバグるため、
      //   グリッド外の勝手なセルではなく、 ドロップ点に最も近い +ボックスへ置く)。
      final target = _nearestFrontierCell(droppedPos);
      _shelfCells[nodeId] = target ?? (myCell ?? [col, row]);
    }
    _saveShelfCells();
    _arrangeAsBookshelfBody(page);
    _saveToStorage();
    notifyListeners();
  }

  /// ギャラリー整列の本体 (Undo/保存/通知を行わない)。 ノード追加直後の自動整列
  /// フックから呼ぶ場合は、 呼び出し側が既に Undo を積み保存/通知するので、
  /// 二重 Undo を避けるためこちらを使う。
  void _arrangeAsBookshelfBody(MindMapPage page,
      {Set<String>? onlyIds, int? perRow, double gap = 16.0}) {
    final ids = onlyIds ?? page.nodes.keys.toSet();
    final list =
        ids.map((id) => page.nodes[id]).whereType<MindMapNode>().toList();
    if (list.isEmpty) return;

    // ギャラリーページ全体の整列か (= 末尾に常設の +ボックスを置く対象)。
    final bool wholeShelf = onlyIds == null && page.pageType == 'bookshelf';

    const double bw = kShelfTileW; // 統一幅

    bool isImagePath(String? p) {
      if (p == null || p.isEmpty) return false;
      var s = p;
      final q = s.indexOf('?');
      if (q >= 0) s = s.substring(0, q);
      final h = s.indexOf('#');
      if (h >= 0) s = s.substring(0, h);
      final dot = s.lastIndexOf('.');
      final ext = dot >= 0 ? s.substring(dot + 1).toLowerCase() : '';
      return ext == 'jpg' ||
          ext == 'jpeg' ||
          ext == 'png' ||
          ext == 'gif' ||
          ext == 'webp' ||
          ext == 'bmp';
    }

    // 「表紙系」 = 動画 / 画像 / PDF・pptx サムネを持つノード。
    bool isCover(MindMapNode n) {
      final hasVideo = (n.youtubeUrl ?? '').isNotEmpty &&
          n.contentType == NodeContentType.youtube;
      final hasThumb = (n.attachmentThumbPath ?? '').isNotEmpty;
      return hasVideo || hasThumb || isImagePath(n.attachmentPath);
    }

    double? naturalAr(MindMapNode n) {
      final yt = n.youtubeUrl ?? '';
      if (yt.isNotEmpty && n.contentType == NodeContentType.youtube) {
        final isShort = yt.contains('/shorts/') || yt.contains('_shorts_');
        return isShort ? 9 / 16 : 16 / 9;
      }
      if (isImagePath(n.attachmentPath) ||
          (n.attachmentThumbPath ?? '').isNotEmpty) {
        final ar = n.attachmentAspectRatio;
        return (ar != null && ar > 0) ? ar : kShelfFallbackAr;
      }
      return null;
    }

    // 表紙系の自然比の中央値を統一アスペクト比にする (= 全タイル同寸)。
    final ars = list.map(naturalAr).whereType<double>().toList()..sort();
    double? ar;
    if (ars.isNotEmpty) {
      final mid = ars.length ~/ 2;
      final med = ars.length.isOdd ? ars[mid] : (ars[mid - 1] + ars[mid]) / 2;
      ar = med.clamp(0.4, 2.0);
    }

    final double tileH = (ar != null) ? bw / ar : bw * 9 / 16;

    // 非表紙 (メモ/テキスト) ノードを「目標高さ」 に合わせてサイズする。
    //   - 横幅は箱幅 (bw) に固定し、 長文はまず縦に折り返して埋める。
    //   - targetH に収まる短文は height を盛って箱ぴったりに (= ユーザー要望:
    //     文量が少なくても +ボックスいっぱいに埋めて見栄えを良くする)。
    //   - targetH に入り切らない長文は縦に伸ばし、 それでも伸びすぎる場合だけ
    //     横幅を少しずつ広げて (最大 2×bw) 高さを抑える。
    // visualHeight は width 依存・height 加算式 (= height + テキスト付加分) なので、
    //   最小 height で測った値から「テキスト付加分」 を求め、 targetH ぴったり /
    //   超過時のみ伸長、 を逆算する。
    MindMapNode sizeTextNode(MindMapNode n, double targetH) {
      const double minBase = 28.0;
      double extraAt(double ww) {
        final ch = n.copyWith(width: ww, height: minBase).visualHeight;
        final e = ch - minBase;
        return e > 0 ? e : 0.0;
      }

      double w = bw;
      double extra = extraAt(w);
      final double maxW = bw * 2.0;
      final double tallThreshold = targetH * 3.0;
      while (extra > tallThreshold && w < maxW) {
        w += bw * 0.5;
        if (w > maxW) w = maxW;
        extra = extraAt(w);
      }
      // height + extra = max(targetH, minBase + extra) になるよう height を決める。
      final double effH =
          (targetH - extra) > minBase ? (targetH - extra) : minBase;
      return n.copyWith(width: w, height: effH);
    }

    // 1 パス目: サイズ適用 + 行ピッチ用に最大 visualHeight を測る。
    // 非表紙は暫定的に tileH を目標にする (= 行高 rowH を確定させるため)。
    // wholeShelf ではこの後グリッドの行高に合わせて埋め直す (下記)。
    final updated = <MindMapNode>[];
    double rowH = 0;
    for (final n in list) {
      final MindMapNode u;
      if (isCover(n)) {
        // 表紙系 (動画/画像/PDF サムネ): タイトルバーは小さい高さ (42) に統一し、
        //   表紙画像は統一比率で同寸に。 ギャラリー全体配置では +ボックス幅を
        //   下限に元の幅を維持する (大きくした表紙はその幅のまま)。
        final double effW = wholeShelf ? (n.width < bw ? bw : n.width) : bw;
        u = n.copyWith(width: effW, height: 42.0, attachmentAspectRatio: ar);
      } else {
        u = sizeTextNode(n, tileH);
      }
      updated.add(u);
      if (u.visualHeight > rowH) rowH = u.visualHeight;
    }
    if (rowH <= 0) rowH = tileH;

    if (wholeShelf) {
      // ギャラリー全体: 各ノードのセル (col,row) に従って配置する (= 自由 2D グリッド)。
      // セル未割り当てのもの (= 適当ドロップ等) は下段の右へ順に割り当てる。
      _ensureShelfCells(page);
      // 先にサイズだけ反映 → 可変サイズ格子の列幅/行高を実サイズで算出する (#4/#5)。
      for (final u in updated) {
        page.nodes[u.id] = u;
      }
      final grid = _buildShelfGrid(page);
      // ── 非表紙 (テキスト/メモ) をセル (= +ボックス) の高さいっぱいに広げる ──
      //   (= ユーザー要望: 文量が少なくても見栄えのため +ボックスいっぱいに埋める)。
      //   行高 rowH は暫定サイズで確定済みなので、 それを目標に height だけ底上げ
      //   する (幅は暫定パスで決めた折り返し幅を維持。 ここで幅を測り直すと長文で
      //   セル高さを超えてはみ出すため)。 visualHeight(height=0) = テキスト等の
      //   付加分なので、 effH = cellH - 付加分 にすれば visualHeight≒cellH になる。
      //   伸ばした高さは grid に反映させない (= 次回 arrange も暫定 tileH から
      //   行高を組むので rowH が膨張し続けない / 安定する)。 表紙は元から比率で
      //   セルを埋めるので対象外。
      const double fillMinBase = 28.0;
      for (final u in updated) {
        final node = page.nodes[u.id];
        if (node == null || isCover(node)) continue;
        final c = _shelfCells[u.id] ?? [0, 0];
        final double cellH = _gridH(grid, c[1]);
        final double extra = node.copyWith(height: 0.0).visualHeight;
        final double effH =
            (cellH - extra) > fillMinBase ? (cellH - extra) : fillMinBase;
        page.nodes[u.id] = node.copyWith(height: effH);
      }
      for (final u in updated) {
        final c = _shelfCells[u.id] ?? [0, 0];
        final p = _shelfCellPos2(grid, c[0], c[1]);
        page.nodes[u.id] = page.nodes[u.id]!.copyWith(
            position:
                Offset(p.dx.clamp(0.0, 20000.0), p.dy.clamp(0.0, 20000.0)));
      }
      page.lastModifiedAt = DateTime.now();
      return;
    }

    // 通常ページの選択整列: その場 (選択範囲の最左上) を基点に詰める。
    final cols =
        _shelfCols(page, list.length, perRow: perRow, wholeShelf: false);
    double baseX = double.infinity, baseY = double.infinity;
    for (final n in list) {
      if (n.position.dx < baseX) baseX = n.position.dx;
      if (n.position.dy < baseY) baseY = n.position.dy;
    }
    if (!baseX.isFinite) baseX = gap;
    if (!baseY.isFinite) baseY = gap;
    for (int i = 0; i < updated.length; i++) {
      final row = i ~/ cols;
      final col = i % cols;
      final pos = Offset(
        (baseX + col * (bw + gap)).clamp(0.0, 20000.0),
        (baseY + row * (rowH + gap)).clamp(0.0, 20000.0),
      );
      page.nodes[updated[i].id] = updated[i].copyWith(position: pos);
    }
    page.lastModifiedAt = DateTime.now();
  }

  /// 対象ページがギャラリーなら自動整列する (= ノード追加 / 貼り付け / 取り込みの
  /// 後に呼ぶフック)。 呼び出し側で既に Undo を積み保存/通知される前提なので、
  /// 二重 Undo を避けるため body を直接呼ぶ。
  void _autoArrangeIfBookshelf([String? pageId]) {
    final page = pageId == null
        ? currentPage
        : _pages.firstWhere((p) => p.id == pageId, orElse: () => currentPage);
    if (page.pageType != 'bookshelf') return;
    _arrangeAsBookshelfBody(page);
  }

  /// ギャラリーページに YouTube 動画をフラットに (親ノード/接続線なしで) 追加して
  /// タイル整列する (= ユーザー要望: チャンネル/プレイリストから動画を並べる)。
  /// 既に生成済みの動画は _allowDuplicateVideoNodes が false ならスキップ。
  /// 戻り値は実際に追加した件数。
  int addVideosToBookshelf(List<String> videoIds, List<String> titles,
      {List<int>? cell}) {
    if (videoIds.isEmpty) return 0;
    final toAdd = <int>[];
    for (int i = 0; i < videoIds.length; i++) {
      final vid = videoIds[i];
      if (vid.isEmpty) continue;
      if (!_allowDuplicateVideoNodes && _generatedVideoIds.contains(vid)) {
        continue;
      }
      toAdd.add(i);
    }
    if (toAdd.isEmpty) return 0;
    _pushUndo();
    final nodeMap = currentPage.nodes;
    // ── 配置 (= ユーザー要望: 横に入りきらない場合は次の行の 1 列目から右へ、
    //    既に要素がある所はスキップして詰める) ──
    // 占有セルを集めておき、 row-major で空きへ順に入れる。 cell 指定があれば
    //   そのセルから、 無ければ (0,0) から探し始める。
    final occ = <String>{};
    for (final id in currentPage.nodes.keys) {
      final c = _shelfCells[id];
      if (c != null) occ.add('${c[0]},${c[1]}');
    }
    int curCol = cell != null ? cell[0] : 0;
    int curRow = cell != null ? cell[1] : 0;
    for (final i in toAdd) {
      final vid = videoIds[i];
      final node = MindMapNode(
        id: _uuid.v4(),
        title: (i < titles.length && titles[i].isNotEmpty)
            ? titles[i]
            : 'Video ${i + 1}',
        position: Offset.zero, // 直後の整列で再配置される
        youtubeUrl: 'https://www.youtube.com/watch?v=$vid',
        contentType: NodeContentType.youtube,
        color: _childColor(),
      );
      nodeMap[node.id] = node;
      final free = _nextFreeShelfCell(occ, fromCol: curCol, fromRow: curRow);
      _shelfCells[node.id] = [free[0], free[1]];
      occ.add('${free[0]},${free[1]}');
      // 次の探索開始位置を 1 つ進める (row-major)。
      curCol = free[0] + 1;
      curRow = free[1];
      if (curCol >= _shelfGridCols()) {
        curCol = 0;
        curRow++;
      }
      _generatedVideoIds.add(vid);
    }
    _arrangeAsBookshelfBody(currentPage);
    _saveShelfCells();
    _saveGeneratedIds();
    _saveToStorage();
    notifyListeners();
    return toAdd.length;
  }

  /// ギャラリーページに 1 本の動画/リンクを追加してタイル整列する。
  /// YouTube URL なら動画ノード、 そうでなければ通常リンクノードにする。
  void addVideoToBookshelf(String url, {List<int>? cell}) {
    final u = url.trim();
    if (u.isEmpty) return;
    _pushUndo();
    final isYoutube = u.contains('youtu.be/') || u.contains('youtube.com/');
    final node = MindMapNode(
      id: _uuid.v4(),
      title: '',
      position: Offset.zero,
      youtubeUrl: isYoutube ? u : null,
      linkUrl: isYoutube ? null : u,
      contentType: isYoutube ? NodeContentType.youtube : NodeContentType.link,
      color: _childColor(),
    );
    currentPage.nodes[node.id] = node;
    // cell 指定があればその位置へ (1 セル確保して既存を右へずらす = 重なり防止)。
    //   無ければ整列時に下段の右へ割り当てられる。
    if (cell != null) {
      _reserveShelfCells(cell[1], cell[0], 1);
      _shelfCells[node.id] = [cell[0], cell[1]];
    }
    _arrangeAsBookshelfBody(currentPage);
    _saveShelfCells();
    _saveToStorage();
    notifyListeners();
  }

  /// ギャラリーページにテキストノートを 1 枚追加してタイル整列する
  /// (= ユーザー要望: 箱にテキストを直接入力できるように)。
  void addTextNoteToBookshelf(String text, {List<int>? cell}) {
    final t = text.trim();
    if (t.isEmpty) return;
    _pushUndo();
    // タイトルは空にし、 本文はメモにだけ入れる (= ユーザー要望: タイトルと
    // メモに同じ文章が二重に入るのを防ぐ)。
    final node = MindMapNode(
      id: _uuid.v4(),
      title: '',
      position: Offset.zero,
      memoText: t,
      contentType: NodeContentType.memo,
      color: _childColor(),
    );
    currentPage.nodes[node.id] = node;
    if (cell != null) _shelfCells[node.id] = [cell[0], cell[1]];
    _arrangeAsBookshelfBody(currentPage);
    _saveShelfCells();
    _saveToStorage();
    notifyListeners();
  }

  /// 名前付きグループを追加・更新
  void setNamedGroup(String name, Set<String> nodeIds) {
    final id = _pageId;
    _pushUndo();
    _namedGroups.putIfAbsent(id, () => {});
    _namedGroups[id]![name] = Set.of(nodeIds);
    _saveNamedGroups();
    notifyListeners();
  }

  /// 指定ノードが所属している全てのグループ名を返す
  List<String> groupsContainingNode(String nodeId) {
    final id = _pageId;
    final groups = _namedGroups[id];
    if (groups == null) return const [];
    return groups.entries
        .where((e) => e.value.contains(nodeId))
        .map((e) => e.key)
        .toList();
  }

  /// parentId が所属する全グループに、追加された childIds を同じ所属として入れる。
  /// （AI生成子ノード / チャンネル動画の一括追加等で呼ぶ）
  /// 保存と通知は行うが、Undoは積まない（呼び出し側が既に _pushUndo 済みの前提）
  void addChildrenToParentGroups(String parentId, Iterable<String> childIds) {
    final id = _pageId;
    final groups = _namedGroups[id];
    if (groups == null || groups.isEmpty) return;
    bool changed = false;
    for (final entry in groups.entries) {
      if (entry.value.contains(parentId)) {
        for (final cid in childIds) {
          if (entry.value.add(cid)) changed = true;
        }
      }
    }
    if (changed) {
      _saveNamedGroups();
      notifyListeners();
    }
  }

  /// 名前付きグループを削除
  void removeNamedGroup(String name) {
    final id = _pageId;
    _pushUndo();
    _namedGroups[id]?.remove(name);
    _groupColors[id]?.remove(name);
    _groupFontSizes[id]?.remove(name);
    _groupFontFamilies[id]?.remove(name);
    _groupLayoutRows[id]?.remove(name);
    _groupLayoutModes[id]?.remove(name);
    _groupPadding[id]?.remove(name);
    _saveNamedGroups();
    notifyListeners();
  }

  /// ── 格納ノード API ────────────────────────────────────────────────
  /// 選択した複数のノードを 1 つの「格納ノード」にまとめる (Ctrl+G)。
  /// 各ノードに `hiddenInContainer = <container.id>` を設定して画面から隠し、
  /// 格納ノードは `isContainer = true` + `containedNodeIds = [...]` を持つ代表として残る。
  String? createContainerFromNodes(List<String> nodeIds) {
    if (nodeIds.isEmpty) return null;
    final nodeMap = currentPage.nodes;
    final valid = nodeIds.where((id) => nodeMap.containsKey(id)).toList();
    if (valid.isEmpty) return null;
    _pushUndo();

    // 格納対象ノードの中心位置（重心）を計算して格納ノードをそこに配置
    double cx = 0, cy = 0;
    for (final id in valid) {
      final n = nodeMap[id]!;
      cx += n.position.dx + n.width / 2;
      cy += n.position.dy + n.visualHeight / 2;
    }
    cx /= valid.length;
    cy /= valid.length;

    // 格納対象の各ノードを「隠し」状態にする
    final containerId = _uuid.v4();
    for (final id in valid) {
      final n = nodeMap[id]!;
      nodeMap[id] = n.copyWith(hiddenInContainer: containerId);
    }

    // 格納ノード本体を作成（タイトル: 格納 (N)）
    final container = MindMapNode(
      id: containerId,
      title: '📦 ${valid.length}',
      position: Offset(cx - 70, cy - 20),
      width: 140,
      height: 42,
      color: const Color(0xFFFFA726), // オレンジ系で目立たせる
      isContainer: true,
      containedNodeIds: List<String>.from(valid),
    );
    nodeMap[containerId] = container;

    _saveToStorage();
    notifyListeners();
    return containerId;
  }

  /// ギャラリー用: 取り込んだ複数動画を 1 つの「表紙ブロック」 (= 格納
  /// コンテナ) にまとめる (= ユーザー要望: YouTube リスト/チャンネルから
  /// 取り込んだら表紙ブロックを作り、 クリックで格納/展開を切り替え)。
  /// 中の動画は hiddenInContainer で隠し、 ギャラリーの枠も解放する。
  /// 表紙のクリックは既存の格納展開ポップアップ (`_showContainerExpandPopup`)
  /// が処理する。
  String? createBookshelfCover(List<String> nodeIds, String title,
      {List<int>? cell}) {
    final valid =
        nodeIds.where((id) => currentPage.nodes.containsKey(id)).toList();
    if (valid.length < 2) return null;
    // 表紙を置くセル: 指定 > 先頭動画のセル > フロンティア先頭。
    final frontier = bookshelfFrontierCells();
    List<int> target = cell ??
        _shelfCells[valid.first] ??
        (frontier.isNotEmpty ? frontier.first : const [0, 0]);
    target = [target[0], target[1]];
    final coverId = createContainerFromNodes(valid);
    if (coverId == null) return null;
    // 中の動画のセルを解放 (隠れている間はギャラリーの枠を占有しない)。
    for (final id in valid) {
      _shelfCells.remove(id);
    }
    _shelfCells[coverId] = target;
    final n = currentPage.nodes[coverId];
    if (n != null) {
      final t = title.trim().isEmpty ? '動画' : title.trim();
      currentPage.nodes[coverId] = n.copyWith(title: '📺 $t (${valid.length})');
    }
    compactShelfCells();
    _saveShelfCells();
    _saveToStorage();
    notifyListeners();
    return coverId;
  }

  /// 格納ノードを解除して、元のノードを復元する。
  /// 格納ノードは削除される。
  void unpackContainer(String containerId) {
    final nodeMap = currentPage.nodes;
    final container = nodeMap[containerId];
    if (container == null || !container.isContainer) return;
    final ids = container.containedNodeIds ?? const <String>[];
    _pushUndo();
    for (final id in ids) {
      final n = nodeMap[id];
      if (n == null) continue;
      // hiddenInContainer を解除することで再度画面に現れる
      nodeMap[id] = n.copyWith(hiddenInContainer: null);
    }
    nodeMap.remove(containerId);
    _saveToStorage();
    notifyListeners();
  }

  /// ギャラリーの「表紙」 (= 格納コンテナ) の展開/格納をトグルする
  /// (= ユーザー要望: 動画を格納している表紙は展開しても消えず、 再び押すと
  ///  格納できる)。 unpackContainer と違い表紙ノードは削除しない。 展開時は
  /// 中の動画を表示してギャラリーの空きセルへ順に配置し、 格納時は再び隠して
  /// セルを解放する。
  void toggleBookshelfCover(String coverId) {
    final page = currentPage;
    if (page.pageType != 'bookshelf') return;
    final nodeMap = page.nodes;
    final cover = nodeMap[coverId];
    if (cover == null || !cover.isContainer) return;
    final ids = (cover.containedNodeIds ?? const <String>[])
        .where((id) => nodeMap.containsKey(id))
        .toList();
    if (ids.isEmpty) return;
    _pushUndo();
    // メンバーが 1 つでも表示されていれば「展開中」 とみなす。
    final expanded = ids.any((id) => nodeMap[id]?.hiddenInContainer == null);
    if (expanded) {
      // 折りたたむ: メンバーを隠してギャラリーの枠を解放 (表紙は残す)。
      for (final id in ids) {
        final n = nodeMap[id]!;
        nodeMap[id] = n.copyWith(hiddenInContainer: coverId);
        _shelfCells.remove(id);
      }
    } else {
      // 展開する: メンバーを表示してフロンティアへ順次配置 (表紙は残す)。
      for (final id in ids) {
        final n = nodeMap[id]!;
        nodeMap[id] = n.copyWith(hiddenInContainer: null);
      }
      for (final id in ids) {
        final frontier = bookshelfFrontierCells();
        _shelfCells[id] =
            frontier.isNotEmpty ? List<int>.from(frontier.first) : [0, 0];
      }
    }
    compactShelfCells();
    _saveShelfCells();
    _saveToStorage();
    notifyListeners();
  }

  /// ── 裁断モード API ───────────────────────────────────────────────
  /// 指定された接続を削除する（裁断モード中にカーソルが横切った接続）。
  void severConnection({
    required String fromId,
    required String toId,
  }) {
    final conns = currentPage.connections;
    final before = conns.length;
    conns.removeWhere((c) =>
        (c.fromId == fromId && c.toId == toId) ||
        (c.fromId == toId && c.toId == fromId));
    if (conns.length != before) {
      _pushUndo();
      _saveToStorage();
      notifyListeners();
    }
  }

  /// グループ名の **表示用** に内部キーから不可視マーカー (U+200B / ZWSP) を
  /// 取り除いた文字列を返す。`splitNamedGroup` で「同じ名前の付箋を 2 つに
  /// 分けたい」を実現するため、内部的には ZWSP を末尾に付けてキーを一意化
  /// しているが、ユーザーには元の名前そのままに見せる。
  ///
  /// 例:
  ///   `'foo'` → `'foo'`
  ///   `'foo\u200B'` → `'foo'`  (1 回分割した右側)
  ///   `'foo\u200B\u200B'` → `'foo'`  (もう 1 回分割)
  static String groupDisplayName(String internalName) =>
      internalName.replaceAll('\u200B', '');

  /// `groups` 上で衝突しないキーを `desired` から作る。すでに存在する場合は
  /// 末尾に ZWSP を 1 個ずつ追加していく。`splitNamedGroup` と
  /// `renameNamedGroup` の両方から呼ばれる。
  String _uniqueGroupKey(Map<String, Set<String>> groups, String desired) {
    String key = desired;
    while (groups.containsKey(key)) {
      key = '$key\u200B';
    }
    return key;
  }

  /// 付箋（名前付きグループ）を左右の 2 つに分割する。
  /// [groupName] の全メンバーのうち、[leftIds] に含まれるノードは現在のグループに残し、
  /// [rightIds] のノードは新しいグループに移す。
  /// 裁断モード中、カーソルがグループを外→内→外と横切ったときに呼ばれる想定。
  ///
  /// 命名: 新グループは元と同じ表示名を持つように、内部キーには不可視
  /// マーカー (ZWSP) を 1 個以上付与する。これでユーザーから見ると両方が
  /// 同じ名前 (例: "foo" と "foo") に見え、`-2` のような番号は付かない。
  String? splitNamedGroup({
    required String groupName,
    required Set<String> leftIds,
    required Set<String> rightIds,
    Offset? cutStart,
    Offset? cutEnd,
  }) {
    final id = _pageId;
    final groups = _namedGroups[id];
    if (groups == null || !groups.containsKey(groupName)) return null;
    final allMembers = groups[groupName]!;
    final leftKept = leftIds.intersection(allMembers);
    final rightKept = rightIds.intersection(allMembers);
    if (leftKept.isEmpty || rightKept.isEmpty) return null;

    _pushUndo();

    // 1つだけのメンバーになるグループは「グループ無し」として扱い削除する
    // （付箋は最低2ノードで意味があるため）
    void cleanupAttrsFor(String name) {
      _groupColors[id]?.remove(name);
      _groupFontSizes[id]?.remove(name);
      _groupFontFamilies[id]?.remove(name);
      _groupLayoutRows[id]?.remove(name);
      _groupLayoutModes[id]?.remove(name);
      _groupPadding[id]?.remove(name);
    }

    // 既存グループ: leftKept を保持。メンバー 1 個以下なら解除
    if (leftKept.length < 2) {
      groups.remove(groupName);
      cleanupAttrsFor(groupName);
    } else {
      groups[groupName] = Set.of(leftKept);
    }

    // 新グループ: rightKept を入れる。メンバー 1 個以下なら作らずに捨てる。
    // 表示名は元と同じ (= groupDisplayName で ZWSP を除去) になるよう、
    // 内部キーには ZWSP を付与した一意な文字列を使う。
    String? newName;
    if (rightKept.length >= 2) {
      // groupName の表示名に ZWSP を 1 個ずつ追加して衝突回避。
      // 例: groupName="foo" なら "foo\u200B"、それも在れば "foo\u200B\u200B"…
      newName = _uniqueGroupKey(groups, '$groupName\u200B');
      groups[newName] = Set.of(rightKept);

      // 色とフォント属性を新グループにもコピー
      final colorIdx = _groupColors[id]?[groupName];
      if (colorIdx != null) {
        _groupColors.putIfAbsent(id, () => {});
        _groupColors[id]![newName] = colorIdx;
      }
      final fs = _groupFontSizes[id]?[groupName];
      if (fs != null) {
        _groupFontSizes.putIfAbsent(id, () => {});
        _groupFontSizes[id]![newName] = fs;
      }
      final ff = _groupFontFamilies[id]?[groupName];
      if (ff != null) {
        _groupFontFamilies.putIfAbsent(id, () => {});
        _groupFontFamilies[id]![newName] = ff;
      }
      final pad = _groupPadding[id]?[groupName];
      if (pad != null) {
        _groupPadding.putIfAbsent(id, () => {});
        _groupPadding[id]![newName] = pad;
      }

      // 分割後の 2 グループが重ならないように、裁断線に垂直な方向へ引き離す。
      // 裁断線情報がない場合は従来の主軸分離にフォールバック。
      _separateSplitGroups(
        groupA: groupName,
        groupB: newName!,
        membersA: leftKept,
        membersB: rightKept,
        cutStart: cutStart,
        cutEnd: cutEnd,
      );
    }

    _saveNamedGroups();
    notifyListeners();
    return newName;
  }

  /// 分割で生まれた 2 グループの外接矩形が重なっていたら引き離す。
  /// [cutStart] と [cutEnd] が与えられていれば、**裁断線に垂直な方向**に引き離す
  /// （裁断面で重ならないよう確実に分ける）。与えられていなければ従来通り
  /// 重心の相対位置に基づく主軸方向で引き離す。
  void _separateSplitGroups({
    required String groupA,
    required String groupB,
    required Set<String> membersA,
    required Set<String> membersB,
    Offset? cutStart,
    Offset? cutEnd,
  }) {
    final nodeMap = currentPage.nodes;

    Rect? boundingRectOf(Set<String> ids) {
      double minX = double.infinity, minY = double.infinity;
      double maxX = -double.infinity, maxY = -double.infinity;
      for (final id in ids) {
        final n = nodeMap[id];
        if (n == null) continue;
        if (n.position.dx < minX) minX = n.position.dx;
        if (n.position.dy < minY) minY = n.position.dy;
        final r = n.position.dx + n.width;
        final b = n.position.dy + n.visualHeight;
        if (r > maxX) maxX = r;
        if (b > maxY) maxY = b;
      }
      if (minX == double.infinity) return null;
      const pad = 28.0;
      const labelH = 28.0;
      return Rect.fromLTRB(
          minX - pad, minY - pad - labelH, maxX + pad, maxY + pad);
    }

    final rectA = boundingRectOf(membersA);
    final rectB = boundingRectOf(membersB);
    if (rectA == null || rectB == null) return;
    if (!rectA.overlaps(rectB)) return;

    const double extraGap = 24.0;

    double moveDx = 0;
    double moveDy = 0;

    // 裁断線が与えられた場合: 線に垂直な方向へ引き離す
    if (cutStart != null && cutEnd != null) {
      // 裁断線の法線ベクトル（単位ベクトル）
      final lineDx = cutEnd.dx - cutStart.dx;
      final lineDy = cutEnd.dy - cutStart.dy;
      final lineLen = math.sqrt(lineDx * lineDx + lineDy * lineDy);
      if (lineLen > 0.01) {
        // 法線 = 線を90度回転: (-dy, dx) / len
        final nx = -lineDy / lineLen;
        final ny = lineDx / lineLen;
        // groupA の重心が法線方向で負か正か確認し、
        // groupB を逆側（反対向き）へ押し出す
        final centerA = rectA.center;
        final centerB = rectB.center;
        final signB =
            (centerB.dx - centerA.dx) * nx + (centerB.dy - centerA.dy) * ny;
        // 法線方向への現在の投影距離（負なら groupA 側）
        // 2 矩形が法線方向でどれくらい重なっているかを計算し、それを解消する量を決定
        //
        // 4 隅の射影の min/max を使うと簡単に「法線方向の占有範囲」が出せる
        double projOnN(Offset p) => p.dx * nx + p.dy * ny;
        double projMin(Rect r) {
          return math.min(math.min(projOnN(r.topLeft), projOnN(r.topRight)),
              math.min(projOnN(r.bottomLeft), projOnN(r.bottomRight)));
        }

        double projMax(Rect r) {
          return math.max(math.max(projOnN(r.topLeft), projOnN(r.topRight)),
              math.max(projOnN(r.bottomLeft), projOnN(r.bottomRight)));
        }

        final aMin = projMin(rectA);
        final aMax = projMax(rectA);
        final bMin = projMin(rectB);
        final bMax = projMax(rectB);
        final overlap = math.min(aMax, bMax) - math.max(aMin, bMin);
        if (overlap > 0) {
          final shift = overlap + extraGap;
          final sign = signB >= 0 ? 1.0 : -1.0;
          moveDx = nx * shift * sign;
          moveDy = ny * shift * sign;
        }
      }
    }

    // 裁断線の情報がない場合、または裁断線由来の移動量がゼロの場合は
    // 従来通りの「主軸分離」にフォールバック
    if (moveDx == 0 && moveDy == 0) {
      final overlapX =
          math.min(rectA.right, rectB.right) - math.max(rectA.left, rectB.left);
      final overlapY =
          math.min(rectA.bottom, rectB.bottom) - math.max(rectA.top, rectB.top);
      final centerA = rectA.center;
      final centerB = rectB.center;
      final dx = centerB.dx - centerA.dx;
      final dy = centerB.dy - centerA.dy;
      if (dx.abs() >= dy.abs()) {
        final shift = overlapX + extraGap;
        moveDx = dx >= 0 ? shift : -shift;
      } else {
        final shift = overlapY + extraGap;
        moveDy = dy >= 0 ? shift : -shift;
      }
    }

    // groupB のメンバー全員に移動を適用
    for (final id in membersB) {
      final n = nodeMap[id];
      if (n == null) continue;
      nodeMap[id] = n.copyWith(
        position: Offset(
          (n.position.dx + moveDx).clamp(0.0, 20000.0),
          (n.position.dy + moveDy).clamp(0.0, 20000.0),
        ),
      );
    }
    _saveToStorage();
  }

  /// 名前付きグループの名前を変更（色・フォントサイズ・フォントファミリーを引き継ぐ）
  void renameNamedGroup(String oldName, String newName) {
    if (oldName == newName) return;
    final id = _pageId;
    final groups = _namedGroups[id];
    if (groups == null || !groups.containsKey(oldName)) return;

    // ── 衝突処理 ──
    // ユーザーが指定した newName が既に存在する場合 (= 別の付箋グループに
    // 同じ表示名を付けたい場合)、ZWSP マーカーを追加して内部キーを一意化する。
    // splitNamedGroup と同じ考え方。表示時は groupDisplayName で ZWSP を
    // 取り除くので、ユーザーから見ると複数のグループが同じ名前で見える。
    String resolvedNew = newName;
    if (groups.containsKey(resolvedNew)) {
      resolvedNew = _uniqueGroupKey(groups, '$newName\u200B');
    }

    // ノードIDセットを引き継ぎ
    final nodeIds = groups[oldName]!;
    groups[resolvedNew] = Set.of(nodeIds);
    groups.remove(oldName);

    // 色を引き継ぎ
    final colorIdx = _groupColors[id]?[oldName];
    if (colorIdx != null) {
      _groupColors.putIfAbsent(id, () => {});
      _groupColors[id]![resolvedNew] = colorIdx;
      _groupColors[id]!.remove(oldName);
    }

    // フォントサイズを引き継ぎ
    final fontSize = _groupFontSizes[id]?[oldName];
    if (fontSize != null) {
      _groupFontSizes.putIfAbsent(id, () => {});
      _groupFontSizes[id]![resolvedNew] = fontSize;
      _groupFontSizes[id]!.remove(oldName);
    }

    // フォントファミリーを引き継ぎ
    final family = _groupFontFamilies[id]?[oldName];
    if (family != null) {
      _groupFontFamilies.putIfAbsent(id, () => {});
      _groupFontFamilies[id]![resolvedNew] = family;
      _groupFontFamilies[id]!.remove(oldName);
    }

    // 整列行数を引き継ぎ
    final rows = _groupLayoutRows[id]?[oldName];
    if (rows != null) {
      _groupLayoutRows.putIfAbsent(id, () => {});
      _groupLayoutRows[id]![resolvedNew] = rows;
      _groupLayoutRows[id]!.remove(oldName);
    }

    // 整列モードを引き継ぎ
    final mode = _groupLayoutModes[id]?[oldName];
    if (mode != null) {
      _groupLayoutModes.putIfAbsent(id, () => {});
      _groupLayoutModes[id]![resolvedNew] = mode;
      _groupLayoutModes[id]!.remove(oldName);
    }

    // パディングを引き継ぎ
    final pad = _groupPadding[id]?[oldName];
    if (pad != null) {
      _groupPadding.putIfAbsent(id, () => {});
      _groupPadding[id]![resolvedNew] = List<double>.of(pad);
      _groupPadding[id]!.remove(oldName);
    }

    _saveNamedGroups();
    notifyListeners();
  }

  Future<void> _saveNamedGroups() async {
    final prefs = await SharedPreferences.getInstance();
    final map = <String, dynamic>{};
    for (final e in _namedGroups.entries) {
      final groups = <String, dynamic>{};
      for (final g in e.value.entries) {
        groups[g.key] = g.value.toList();
      }
      map[e.key] = groups;
    }
    await prefs.setString('namedGroups', jsonEncode(map));
    // カラー保存
    final cMap = <String, dynamic>{};
    for (final e in _groupColors.entries) {
      cMap[e.key] = e.value;
    }
    await prefs.setString('groupColors', jsonEncode(cMap));
    // フォントサイズ保存
    final fsMap = <String, dynamic>{};
    for (final e in _groupFontSizes.entries) {
      fsMap[e.key] = e.value;
    }
    await prefs.setString('groupFontSizes', jsonEncode(fsMap));
    // フォントファミリー保存
    final ffMap = <String, dynamic>{};
    for (final e in _groupFontFamilies.entries) {
      ffMap[e.key] = e.value;
    }
    await prefs.setString('groupFontFamilies', jsonEncode(ffMap));
    // 整列行数保存
    final lrMap = <String, dynamic>{};
    for (final e in _groupLayoutRows.entries) {
      lrMap[e.key] = e.value;
    }
    await prefs.setString('groupLayoutRows', jsonEncode(lrMap));
    // 整列モード保存
    final lmMap = <String, dynamic>{};
    for (final e in _groupLayoutModes.entries) {
      lmMap[e.key] = e.value;
    }
    await prefs.setString('groupLayoutModes', jsonEncode(lmMap));
    // パディング保存
    final pdMap = <String, dynamic>{};
    for (final e in _groupPadding.entries) {
      pdMap[e.key] = e.value;
    }
    await prefs.setString('groupPadding', jsonEncode(pdMap));
  }

  Future<void> _loadNamedGroups() async {
    final prefs = await SharedPreferences.getInstance();
    final str = prefs.getString('namedGroups');
    if (str == null) return;
    try {
      final map = jsonDecode(str) as Map<String, dynamic>;
      for (final e in map.entries) {
        final groups = <String, Set<String>>{};
        final gMap = e.value as Map<String, dynamic>;
        for (final g in gMap.entries) {
          groups[g.key] = Set<String>.from(g.value as List);
        }
        _namedGroups[e.key] = groups;
      }
    } catch (_) {}
    // カラー読込
    final cStr = prefs.getString('groupColors');
    if (cStr != null) {
      try {
        final cMap = jsonDecode(cStr) as Map<String, dynamic>;
        for (final e in cMap.entries) {
          _groupColors[e.key] = Map<String, int>.from(e.value as Map);
        }
      } catch (_) {}
    }
    // フォントサイズ読込
    final fsStr = prefs.getString('groupFontSizes');
    if (fsStr != null) {
      try {
        final fsMap = jsonDecode(fsStr) as Map<String, dynamic>;
        for (final e in fsMap.entries) {
          _groupFontSizes[e.key] = Map<String, double>.from((e.value as Map)
              .map((k, v) => MapEntry(k as String, (v as num).toDouble())));
        }
      } catch (_) {}
    }
    // フォントファミリー読込
    final ffStr = prefs.getString('groupFontFamilies');
    if (ffStr != null) {
      try {
        final ffMap = jsonDecode(ffStr) as Map<String, dynamic>;
        for (final e in ffMap.entries) {
          _groupFontFamilies[e.key] = Map<String, String>.from(e.value as Map);
        }
      } catch (_) {}
    }
    // 整列行数読込
    final lrStr = prefs.getString('groupLayoutRows');
    if (lrStr != null) {
      try {
        final lrMap = jsonDecode(lrStr) as Map<String, dynamic>;
        for (final e in lrMap.entries) {
          _groupLayoutRows[e.key] = Map<String, int>.from((e.value as Map)
              .map((k, v) => MapEntry(k as String, (v as num).toInt())));
        }
      } catch (_) {}
    }
    // 整列モード読込
    final lmStr = prefs.getString('groupLayoutModes');
    if (lmStr != null) {
      try {
        final lmMap = jsonDecode(lmStr) as Map<String, dynamic>;
        for (final e in lmMap.entries) {
          _groupLayoutModes[e.key] = Map<String, String>.from(e.value as Map);
        }
      } catch (_) {}
    }
    // パディング読込
    final pdStr = prefs.getString('groupPadding');
    if (pdStr != null) {
      try {
        final pdMap = jsonDecode(pdStr) as Map<String, dynamic>;
        for (final e in pdMap.entries) {
          final innerMap = <String, List<double>>{};
          for (final inner in (e.value as Map).entries) {
            innerMap[inner.key as String] = List<double>.from(
                (inner.value as List).map((x) => (x as num).toDouble()));
          }
          _groupPadding[e.key] = innerMap;
        }
      } catch (_) {}
    }
  }

  /// ノード作成時に使用する10色パレット（順番に循環）
  static const List<Color> nodePalette = [
    Color(0xFF6C63FF), // 紫
    Color(0xFF43B97F), // 緑
    Color(0xFFFF6B6B), // 赤
    Color(0xFFFFB347), // オレンジ
    Color(0xFF4FC3F7), // 水色
    Color(0xFFBA68C8), // ピンク紫
    Color(0xFFE53935), // 濃い赤
    Color(0xFF00897B), // ティール
    Color(0xFFF06292), // ピンク（旧 黄: ダーク背景でもライト背景でも見やすい）
    Color(0xFF78909C), // グレー青
  ];

  /// 新規ノード作成時のカラー挙動
  /// 'cycle': 作成ごとにパレットを順番に循環
  /// 'fixed': 常に _fixedColorIndex の色を使う
  String _colorMode = 'cycle';
  String get colorMode => _colorMode;

  /// 'fixed' モード時に使用するパレット内のインデックス
  int _fixedColorIndex = 0;
  int get fixedColorIndex => _fixedColorIndex;
  Color get fixedColor =>
      nodePalette[_fixedColorIndex.clamp(0, nodePalette.length - 1)];

  /// ノード作成時の色選択カウンタ（cycleモード時に使用）
  int _cycleCounter = 0;

  Future<void> setColorMode(String mode) async {
    if (mode != 'cycle' && mode != 'fixed') return;
    _colorMode = mode;
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString('colorMode', mode);
    notifyListeners();
  }

  Future<void> setFixedColorIndex(int index) async {
    _fixedColorIndex = index.clamp(0, nodePalette.length - 1);
    final prefs = await SharedPreferences.getInstance();
    await prefs.setInt('fixedColorIndex', _fixedColorIndex);
    notifyListeners();
  }

  Future<void> _loadColorSettings() async {
    final prefs = await SharedPreferences.getInstance();
    _colorMode = prefs.getString('colorMode') ?? 'cycle';
    _fixedColorIndex = prefs.getInt('fixedColorIndex') ?? 0;
    _cycleCounter = prefs.getInt('colorCycleCounter') ?? 0;
  }

  Future<void> _saveCycleCounter() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setInt('colorCycleCounter', _cycleCounter);
  }

  Color _childColor() {
    if (_colorMode == 'fixed') {
      return fixedColor;
    }
    // cycle モード: 作成順に循環（ページ間でも一貫した順序）
    final c = nodePalette[_cycleCounter % nodePalette.length];
    _cycleCounter++;
    _saveCycleCounter();
    return c;
  }

  void updateNodeTitle(String id, String title, {bool reflow = false}) {
    final node = currentPage.nodes[id];
    if (node == null) return;
    _pushUndo();
    // テキストが収まるように width / height を自動で伸ばす (収縮はしない)
    final sizes = _computeAutoSizeForText(
      title: title,
      memo: node.memoText ?? '',
      currentWidth: node.width,
      currentHeight: node.height,
      titleFontSize: node.titleFontSize ?? defaultTitleFontSize,
      memoFontSize: node.memoFontSize ?? defaultMemoFontSize,
    );
    currentPage.nodes[id] = node.copyWith(
      title: title,
      width: sizes.$1,
      height: sizes.$2,
    );
    // ユーザー要望: ノード編集でテキストが伸びて周囲と重なり見えなくなる
    //   問題への対応。 手動編集 (reflow=true) のときだけ、 伸びた分で
    //   重なった周囲のノードを押しのける。 AI 生成など一括処理では呼ばない
    //   (= レイアウトを壊さないため)。
    if (reflow) {
      _resolveOverlapsAround(id);
    }
    // ユーザー要望: テキストが伸びて子/兄弟ノードと「完全に」重なって
    //   見えなくなる問題への対応。reflow の有無に関わらず、ほぼ完全に
    //   埋もれたノードだけは必ず分離する (意図的な部分的重なりは
    //   coverFrac しきい値で温存し、レイアウトは極力壊さない)。
    _separateBuriedNodesAround(id);
    _saveToStorage();
    notifyListeners();
  }

  /// 公開版: [id] の周囲の重なりを解消して保存・通知する (手動編集の確定後に
  /// 呼ぶ。 ユーザー要望)。
  void resolveNodeOverlaps(String id) {
    final before = currentPage.nodes.length;
    _resolveOverlapsAround(id);
    if (before > 0) {
      _saveToStorage();
      notifyListeners();
    }
  }

  /// [id] のノードと重なっている他ノードを、 最小限だけ押しのけて重なりを
  /// 解消する (ユーザー要望: 編集でテキストが伸びても周囲と重ならないように)。
  /// 編集したノード自身は動かさず、 周囲を退避させる。 連鎖は数回まで。
  void _resolveOverlapsAround(String id, {double gap = 12.0}) {
    final page = currentPage;
    final target = page.nodes[id];
    if (target == null) return;
    Rect rectOf(MindMapNode n) =>
        Rect.fromLTWH(n.position.dx, n.position.dy, n.width, n.visualHeight);
    for (int iter = 0; iter < 5; iter++) {
      final tRect = rectOf(target).inflate(gap / 2);
      bool movedThisPass = false;
      for (final other in page.nodes.values.toList()) {
        if (other.id == id) continue;
        final oRect = rectOf(other);
        final inter = tRect.intersect(oRect);
        if (inter.width <= 0 || inter.height <= 0) continue; // 重なってない
        // 重なり量が小さい軸に沿って退避 (動きを最小化)。
        Offset newPos;
        if (inter.height <= inter.width) {
          final pushDown = oRect.center.dy >= tRect.center.dy;
          final dy = pushDown ? inter.height : -inter.height;
          newPos = Offset(other.position.dx, other.position.dy + dy);
        } else {
          final pushRight = oRect.center.dx >= tRect.center.dx;
          final dx = pushRight ? inter.width : -inter.width;
          newPos = Offset(other.position.dx + dx, other.position.dy);
        }
        page.nodes[other.id] = other.copyWith(position: newPos);
        movedThisPass = true;
      }
      if (!movedThisPass) break;
    }
  }

  /// ノード同士が「ほぼ完全に重なっている」(= 一方が他方にほぼ埋もれて
  /// 見えなくなっている) ペアだけを検出し、最小限ずらして必ず一部が見える
  /// ようにする。意図的な部分的重なりは温存するため、被覆率が [coverFrac]
  /// を超えるペアのみを対象にする (= ユーザー要望「ノード同士は完全には
  /// 重ならないように」)。[id] のノードは動かさず、相手側を退避させる。
  void _separateBuriedNodesAround(String id,
      {double coverFrac = 0.55, double gap = 12.0}) {
    final page = currentPage;
    final target = page.nodes[id];
    if (target == null) return;
    Rect rectOf(MindMapNode n) =>
        Rect.fromLTWH(n.position.dx, n.position.dy, n.width, n.visualHeight);
    final ra = rectOf(target); // 編集したノード自身は固定
    final areaA = ra.width * ra.height;
    for (int pass = 0; pass < 4; pass++) {
      bool moved = false;
      for (final other in page.nodes.values.toList()) {
        if (other.id == id) continue;
        final rb = rectOf(other);
        final inter = ra.intersect(rb);
        if (inter.width <= 0 || inter.height <= 0) continue;
        final interArea = inter.width * inter.height;
        final areaB = rb.width * rb.height;
        final minArea = math.min(areaA, areaB);
        if (minArea <= 0) continue;
        // 小さい方の面積の coverFrac 以上が覆われている = 埋もれている
        if (interArea < minArea * coverFrac) continue;
        // 重なり量が小さい軸に沿って、被りが完全に解消するまで退避
        Offset newPos;
        if (inter.height <= inter.width) {
          final pushDown = rb.center.dy >= ra.center.dy;
          newPos = Offset(other.position.dx,
              other.position.dy + (pushDown ? 1 : -1) * (inter.height + gap));
        } else {
          final pushRight = rb.center.dx >= ra.center.dx;
          newPos = Offset(
              other.position.dx + (pushRight ? 1 : -1) * (inter.width + gap),
              other.position.dy);
        }
        page.nodes[other.id] = other.copyWith(
          position: Offset(
              newPos.dx.clamp(0.0, 20000.0), newPos.dy.clamp(0.0, 20000.0)),
        );
        moved = true;
      }
      if (!moved) break;
    }
  }

  /// 現在ページ全体を走査し、「ほぼ完全に重なっている」ペアだけを最小限ずらす。
  /// レイアウト処理 (autoLayoutTree) の最終段で呼び、意図しない完全な埋もれを
  /// 防ぐ。被覆率が [coverFrac] 未満の部分的な重なりは温存する。
  void _separateBuriedNodes({double coverFrac = 0.55, double gap = 12.0}) {
    final page = currentPage;
    final ids = page.nodes.keys.toList();
    if (ids.length < 2) return;
    Rect rectOf(MindMapNode n) =>
        Rect.fromLTWH(n.position.dx, n.position.dy, n.width, n.visualHeight);
    for (int pass = 0; pass < 4; pass++) {
      bool moved = false;
      for (int i = 0; i < ids.length; i++) {
        final a = page.nodes[ids[i]];
        if (a == null) continue;
        final ra = rectOf(a);
        final areaA = ra.width * ra.height;
        for (int j = i + 1; j < ids.length; j++) {
          final b = page.nodes[ids[j]];
          if (b == null) continue;
          final rb = rectOf(b);
          final inter = ra.intersect(rb);
          if (inter.width <= 0 || inter.height <= 0) continue;
          final interArea = inter.width * inter.height;
          final areaB = rb.width * rb.height;
          final minArea = math.min(areaA, areaB);
          if (minArea <= 0) continue;
          if (interArea < minArea * coverFrac) continue;
          // 後ろ側 (b) を最小軸方向へ退避させる
          Offset newPos;
          if (inter.height <= inter.width) {
            final pushDown = rb.center.dy >= ra.center.dy;
            newPos = Offset(b.position.dx,
                b.position.dy + (pushDown ? 1 : -1) * (inter.height + gap));
          } else {
            final pushRight = rb.center.dx >= ra.center.dx;
            newPos = Offset(
                b.position.dx + (pushRight ? 1 : -1) * (inter.width + gap),
                b.position.dy);
          }
          page.nodes[ids[j]] = b.copyWith(
            position: Offset(
                newPos.dx.clamp(0.0, 20000.0), newPos.dy.clamp(0.0, 20000.0)),
          );
          moved = true;
        }
      }
      if (!moved) break;
    }
  }

  /// 連番オートフィル一括サジェスト計算。
  ///
  /// `anchorNodeId` は今しがたユーザーがタイトルを保存したノードの ID。
  /// その兄弟ノードの中から「タイトルが空」のものを抽出し、 anchor の連番を
  /// 起点として `nextSequenceTitle` を順に適用してサジェスト一覧を返す。
  ///
  /// 「兄弟」 の定義 (厳格版):
  ///   - **anchor が誰かの子ノードの場合のみ**、 同じ親の他の子ノードを
  ///     兄弟扱い (= 接続でつながっている直接の兄弟だけ)。
  ///   - anchor が「親なし」 (= 接続の to に出てこないルート相当) の場合は
  ///     **何もしない**。 独立して画面上に置かれているだけのノード群が
  ///     関係なくオートフィル対象になってしまうのを防ぐため。
  ///
  /// 戻り値: `(空ノードの ID, サジェストされたタイトル)` のリスト。
  /// `autofillSequenceEnabled` が OFF の場合は空リスト。
  /// anchor のタイトルから連番が認識できなければ空リスト。
  /// anchor が独立ノード (親無し) なら空リスト。
  ///
  /// 兄弟ノードを `position.dy` (上から下) で安定ソートし、 anchor の位置を
  /// 見つけて、 そこから後ろにある「空タイトル」 のノードに対して 1 個目から
  /// 順に連番をサジェストする。
  List<({String nodeId, String suggestedTitle})> computeBulkAutofillForSiblings(
      String anchorNodeId) {
    if (!_autofillSequenceEnabled) return const [];
    final page = currentPage;
    final nodes = page.nodes;
    final anchor = nodes[anchorNodeId];
    if (anchor == null) return const [];
    final anchorTitle = anchor.title.trim();
    if (anchorTitle.isEmpty) return const [];

    // 親 ID を解決
    String? parentId;
    for (final c in page.connections) {
      if (c.toId == anchorNodeId) {
        parentId = c.fromId;
        break;
      }
    }
    // 親が無い (= 独立ノード / ルート相当) なら何もしない
    if (parentId == null) return const [];

    // 親 -> 子 の接続を集めて兄弟集合を確定
    final pid = parentId;
    final childIds = page.connections
        .where((c) => c.fromId == pid)
        .map((c) => c.toId)
        .toSet();
    final siblings = childIds.map((id) => nodes[id]).whereType<MindMapNode>();

    // 位置ソート (上から下)。 同じ y の場合は x で安定化。
    final sorted = siblings.toList()
      ..sort((a, b) {
        final dy = a.position.dy.compareTo(b.position.dy);
        if (dy != 0) return dy;
        return a.position.dx.compareTo(b.position.dx);
      });

    // anchor の位置を探す。 anchor 以降の空ノードに連番を順次サジェスト。
    final anchorIndex = sorted.indexWhere((n) => n.id == anchorNodeId);
    if (anchorIndex < 0) return const [];

    final suggestions = <({String nodeId, String suggestedTitle})>[];
    String currentTitle = anchorTitle;
    for (int i = anchorIndex + 1; i < sorted.length; i++) {
      final sib = sorted[i];
      // 既にタイトルが入っているノードはスキップ (上書きしない)
      if (sib.title.trim().isNotEmpty) continue;
      final next = nextSequenceTitle(currentTitle);
      if (next == null) break;
      suggestions.add((nodeId: sib.id, suggestedTitle: next));
      currentTitle = next;
    }
    return suggestions;
  }

  /// `computeBulkAutofillForSiblings` で得られたサジェストを一括適用する。
  /// undo 用の単一スナップショットとして記録 (= ひとつの操作で undo 1 回で
  /// 全部戻せる)。
  void applyBulkAutofillTitles(
      List<({String nodeId, String suggestedTitle})> entries) {
    if (entries.isEmpty) return;
    _pushUndo();
    final page = currentPage;
    for (final e in entries) {
      final node = page.nodes[e.nodeId];
      if (node == null) continue;
      final sizes = _computeAutoSizeForText(
        title: e.suggestedTitle,
        memo: node.memoText ?? '',
        currentWidth: node.width,
        currentHeight: node.height,
        titleFontSize: node.titleFontSize ?? defaultTitleFontSize,
        memoFontSize: node.memoFontSize ?? defaultMemoFontSize,
      );
      page.nodes[e.nodeId] = node.copyWith(
        title: e.suggestedTitle,
        width: sizes.$1,
        height: sizes.$2,
      );
    }
    _saveToStorage();
    notifyListeners();
  }

  /// ノードに「埋め込みサブマップ」 のページ ID を設定する。
  /// `pageId == null` または空文字なら埋め込みを解除する。
  /// 自分自身のページを指定しても何もしない (= 自己参照防止)。
  /// 存在しないページ ID も無視する。
  void updateNodeLinkedPage(String id, String? pageId) {
    final node = currentPage.nodes[id];
    if (node == null) return;
    final normalized = (pageId ?? '').trim();
    if (normalized == currentPage.id) return;
    if (normalized.isNotEmpty && !_pages.any((p) => p.id == normalized)) {
      return;
    }
    _pushUndo();
    currentPage.nodes[id] = node.copyWith(
      linkedPageId: normalized.isEmpty ? null : normalized,
    );
    _saveToStorage();
    notifyListeners();
  }

  void updateNodePosition(String id, Offset position) {
    final node = currentPage.nodes[id];
    if (node == null) return;
    _pushUndo();
    currentPage.nodes[id] = node.copyWith(position: position);
    _saveToStorage();
    notifyListeners();
  }

  // ─── PDF ページ非表示 (= 個別ページのスキップ) ───────────────────
  /// PDF キー (URL or ローカルパス) → 非表示にしたページ番号の集合。
  /// SfPdfViewer の onPageChanged フックでこの集合にあるページを検出すると、
  /// 進行方向に応じて次の表示可能ページに自動でジャンプする。
  /// 例: 2 ページ目を非表示リストに追加 → 1 ページ目から進むと 3 ページ目へ。
  final Map<String, Set<int>> _hiddenPdfPages = {};
  Map<String, Set<int>> get hiddenPdfPages => _hiddenPdfPages;

  /// 指定 PDF / ページの非表示状態を確認。
  bool isPdfPageHidden(String pdfKey, int pageNumber) {
    return _hiddenPdfPages[pdfKey]?.contains(pageNumber) ?? false;
  }

  /// 指定 PDF の非表示ページ番号セット (= 読み取り専用イメージ)。
  Set<int> hiddenPdfPagesFor(String pdfKey) {
    return _hiddenPdfPages[pdfKey] ?? const <int>{};
  }

  // ─── PDF 最終ページ記憶 (= 再オープン時に前回位置から復帰) ──────────
  // ユーザー要望: 「PDF を再度開き直す時に一番最後に開いたページから
  // スタートするようにして欲しい」。
  //
  // ファイルパス → 最終閲覧ページ番号 のマップ。
  // PDF を閉じてもアプリが保持し、 SharedPreferences に永続化する。
  // PDFビューア側の onPageChanged で逐次更新、 onDocumentLoaded で
  // ジャンプ復元する。
  Map<String, int> _lastPdfPages = {};

  /// [path] の PDF の最終閲覧ページ番号 (1-based)。 未記録なら null。
  int? lastPdfPageFor(String path) => _lastPdfPages[path];

  /// [path] の PDF の最終閲覧ページを更新。
  /// PDFビューアの onPageChanged コールバックから毎ページ呼ばれる想定。
  /// 同期書き込みではないため、 連続呼び出しで負荷にならないよう
  /// SharedPreferences への保存は async で投げっぱなし。
  Future<void> setLastPdfPage(String path, int page) async {
    if (page < 1) return;
    if (path.isEmpty) return;
    // 値が変わらないなら書かない (= 書き込み頻度削減)
    if (_lastPdfPages[path] == page) return;
    _lastPdfPages[path] = page;
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString('lastPdfPages_v1', jsonEncode(_lastPdfPages));
    } catch (e) {
      debugPrint('setLastPdfPage 永続化失敗: $e');
    }
    // notifyListeners 不要 (UI が反応する必要なし、 次回 open 時に使うだけ)
  }

  /// 指定 PDF の指定ページを非表示にする。
  void hidePdfPage(String pdfKey, int pageNumber) {
    _hiddenPdfPages.putIfAbsent(pdfKey, () => <int>{}).add(pageNumber);
    _persistHiddenPdfPages();
    notifyListeners();
  }

  /// 指定 PDF の指定ページの非表示を解除。
  void unhidePdfPage(String pdfKey, int pageNumber) {
    final set = _hiddenPdfPages[pdfKey];
    if (set == null) return;
    if (set.remove(pageNumber)) {
      if (set.isEmpty) _hiddenPdfPages.remove(pdfKey);
      _persistHiddenPdfPages();
      notifyListeners();
    }
  }

  /// 指定 PDF の非表示を全てリセット。
  void resetHiddenPdfPages(String pdfKey) {
    if (_hiddenPdfPages.remove(pdfKey) != null) {
      _persistHiddenPdfPages();
      notifyListeners();
    }
  }

  Future<void> _persistHiddenPdfPages() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final encoded = <String, List<int>>{};
      _hiddenPdfPages.forEach((k, v) => encoded[k] = v.toList());
      await prefs.setString('hidden_pdf_pages', jsonEncode(encoded));
    } catch (_) {}
  }

  Future<void> _loadHiddenPdfPages() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final str = prefs.getString('hidden_pdf_pages');
      if (str == null || str.isEmpty) return;
      final decoded = jsonDecode(str) as Map<String, dynamic>;
      _hiddenPdfPages.clear();
      decoded.forEach((k, v) {
        _hiddenPdfPages[k] = (v as List).cast<int>().toSet();
      });
    } catch (_) {}
  }

  // ─── Web ページ用メモ (= Qiita 等の URL に紐づくメモ) ────────────
  /// URL → メモテキストのリスト。 同じ URL に複数メモを取れる。
  /// PDF のような細かい位置情報 (= ページ番号、 ハイライト) はなく、
  /// シンプルに「このページに対するメモ」 として記録する。
  final Map<String, List<String>> _webPageMemos = {};
  Map<String, List<String>> get webPageMemos => _webPageMemos;

  /// 指定 URL のメモ一覧を取得 (= 読み取り専用)。
  List<String> webMemosFor(String url) {
    return List<String>.unmodifiable(_webPageMemos[url] ?? const []);
  }

  /// メモを追加 (= URL 末尾のメモリストに append)。
  void addWebMemo(String url, String memo) {
    final trimmed = memo.trim();
    if (trimmed.isEmpty) return;
    _webPageMemos.putIfAbsent(url, () => <String>[]).add(trimmed);
    _persistWebPageMemos();
    notifyListeners();
  }

  /// 指定 URL のメモを編集。
  void updateWebMemo(String url, int index, String memo) {
    final list = _webPageMemos[url];
    if (list == null || index < 0 || index >= list.length) return;
    final trimmed = memo.trim();
    if (trimmed.isEmpty) {
      removeWebMemo(url, index);
      return;
    }
    list[index] = trimmed;
    _persistWebPageMemos();
    notifyListeners();
  }

  /// 指定 URL の特定インデックスのメモを削除。
  void removeWebMemo(String url, int index) {
    final list = _webPageMemos[url];
    if (list == null || index < 0 || index >= list.length) return;
    list.removeAt(index);
    if (list.isEmpty) _webPageMemos.remove(url);
    _persistWebPageMemos();
    notifyListeners();
  }

  Future<void> _persistWebPageMemos() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString('web_page_memos', jsonEncode(_webPageMemos));
    } catch (_) {}
  }

  Future<void> _loadWebPageMemos() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final str = prefs.getString('web_page_memos');
      if (str == null || str.isEmpty) return;
      final decoded = jsonDecode(str) as Map<String, dynamic>;
      _webPageMemos.clear();
      decoded.forEach((k, v) {
        _webPageMemos[k] = (v as List).cast<String>();
      });
    } catch (_) {}
  }

  // ─── 親ノードの子要素整列 ─────────────────────────────────────────────
  /// 指定ノードの直接の子ノード達を、 親の右側に縦一列に等間隔で配置する。
  /// シンプルな整列 (= autoLayoutTree のサブセット)。
  /// 子の子 (= 孫) は動かさない (= 1 段だけ)。
  ///
  /// ユーザー要望「子要素を整列を押した時に画像が入ったノードがあると
  ///   画像部分と他のノードが下部って (= 被って) しまうから画像部分の
  ///   大きさも考慮した配置がされるようにして、 加えて少しきついから
  ///   もう少しリンクを伸ばしてゆとりを持たせて」 への対応:
  ///   * 旧仕様: 固定間隔 80px、 親→子の横距離 60px
  ///   * 改修1: `child.height` で累積配置 → 通常ノードは OK だが、
  ///     画像入りノードは `height` が「枠線まで」 で画像描画分を含まず
  ///     被ることがあった
  ///   * 改修2 (今回): 画像入り (= `attachmentAspectRatio` がセット) なら
  ///     `width / attachmentAspectRatio` で画像の表示高さを推定して加算。
  ///     ギャップも 36 → 50 に少し増やす。
  void alignChildrenOf(String parentId) {
    final parent = currentPage.nodes[parentId];
    if (parent == null) return;
    final children = currentPage.connections
        .where((c) => c.fromId == parentId)
        .map((c) => c.toId)
        .toSet()
        .toList();
    if (children.isEmpty) return;
    _pushUndo();

    final childNodes = <MindMapNode>[];
    for (final id in children) {
      final n = currentPage.nodes[id];
      if (n != null) childNodes.add(n);
    }
    if (childNodes.isEmpty) return;

    // ノードの「描画上の実高さ」 を求めるヘルパー。 画像入りノードは
    // テキスト枠 (= n.height) の下に画像が追加描画されるため、
    // attachmentAspectRatio から画像の高さを推定して加算する。
    double effectiveHeight(MindMapNode n) {
      double h = n.height;
      final ar = n.attachmentAspectRatio;
      if (ar != null && ar > 0) {
        // 画像幅 ≈ ノード幅。 高さ = 幅 / アスペクト比
        h += n.width / ar;
      }
      return h;
    }

    // 親→子のリンク長 (= 横方向のオフセット)
    final px = parent.position.dx + parent.width + 110.0;
    // ノード間のギャップ (画像入りでも目視で被らない余裕を持たせる)
    const double gap = 50.0;

    // 全子ノードの合計表示高さ + ギャップ
    double totalHeight = 0;
    for (final n in childNodes) {
      totalHeight += effectiveHeight(n);
    }
    totalHeight += gap * (childNodes.length - 1);

    final parentCenterY = parent.position.dy + parent.height / 2;
    double currentY = parentCenterY - totalHeight / 2;

    for (final child in childNodes) {
      currentPage.nodes[child.id] = child.copyWith(
        position: Offset(px, currentY),
      );
      currentY += effectiveHeight(child) + gap;
    }
    _saveToStorage();
    notifyListeners();
  }

  // ─── ページの非表示管理 ───────────────────────────────────────────────
  /// 非表示にされたページ ID の集合。 マップ一覧 (Drawer) からは隠される。
  final Set<String> _hiddenPageIds = <String>{};
  Set<String> get hiddenPageIds => _hiddenPageIds;
  bool isPageHidden(String id) => _hiddenPageIds.contains(id);

  /// ページを非表示にする。
  void hidePage(String pageId) {
    if (_hiddenPageIds.add(pageId)) {
      _persistHiddenPages();
      notifyListeners();
    }
  }

  /// 全ての非表示ページを再表示する (= リセット)。
  void resetHiddenPages() {
    if (_hiddenPageIds.isEmpty) return;
    _hiddenPageIds.clear();
    _persistHiddenPages();
    notifyListeners();
  }

  /// 指定ページの非表示を解除。
  void unhidePage(String pageId) {
    if (_hiddenPageIds.remove(pageId)) {
      _persistHiddenPages();
      notifyListeners();
    }
  }

  Future<void> _persistHiddenPages() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setStringList('hidden_page_ids', _hiddenPageIds.toList());
    } catch (_) {}
  }

  Future<void> _loadHiddenPages() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final list = prefs.getStringList('hidden_page_ids');
      if (list != null) {
        _hiddenPageIds
          ..clear()
          ..addAll(list);
      }
    } catch (_) {}
  }

  // ─── ページお気に入り管理 ───────────────────────────────────────────
  final Set<String> _favoritePageIds = <String>{};
  Set<String> get favoritePageIds => _favoritePageIds;
  bool isPageFavorite(String id) => _favoritePageIds.contains(id);

  /// お気に入りトグル。
  void toggleFavoritePage(String pageId) {
    if (_favoritePageIds.contains(pageId)) {
      _favoritePageIds.remove(pageId);
    } else {
      _favoritePageIds.add(pageId);
    }
    _persistFavoritePages();
    notifyListeners();
  }

  Future<void> _persistFavoritePages() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setStringList('favorite_page_ids', _favoritePageIds.toList());
    } catch (_) {}
  }

  Future<void> _loadFavoritePages() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final list = prefs.getStringList('favorite_page_ids');
      if (list != null) {
        _favoritePageIds
          ..clear()
          ..addAll(list);
      }
    } catch (_) {}
  }

  // ─── ページ順 シャッフル/復元 ──────────────────────────────────────
  /// シャッフル前のページ順序 (= 元に戻す用)。 null なら未シャッフル状態。
  List<String>? _originalPageOrder;
  bool get isPagesShuffled => _originalPageOrder != null;

  // ─── Qiita ブロック投稿者管理 ───────────────────────────────────────
  /// ブロック対象の Qiita 投稿者 ID (= ユーザー名)。 Qiita 検索結果ページで
  /// この ID の投稿者の記事を JavaScript で非表示にする。
  final Set<String> _qiitaBlockedAuthors = <String>{};
  Set<String> get qiitaBlockedAuthors => _qiitaBlockedAuthors;

  /// 投稿者 ID をブロックリストに追加。
  void addQiitaBlockedAuthor(String authorId) {
    final id = authorId.trim().replaceAll('@', '');
    if (id.isEmpty) return;
    if (_qiitaBlockedAuthors.add(id)) {
      _persistQiitaBlocked();
      notifyListeners();
    }
  }

  /// 投稿者 ID をブロックリストから外す。
  void removeQiitaBlockedAuthor(String authorId) {
    if (_qiitaBlockedAuthors.remove(authorId)) {
      _persistQiitaBlocked();
      notifyListeners();
    }
  }

  Future<void> _persistQiitaBlocked() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setStringList(
          'qiita_blocked_authors', _qiitaBlockedAuthors.toList());
    } catch (_) {}
  }

  Future<void> _loadQiitaBlocked() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final list = prefs.getStringList('qiita_blocked_authors');
      if (list != null) {
        _qiitaBlockedAuthors
          ..clear()
          ..addAll(list);
      }
    } catch (_) {}
  }

  /// マップ一覧のページ順序をランダムシャッフルする。
  /// シャッフル前の順序を保存しておき、 restorePageOrder で復元可能。
  void shufflePages() {
    if (pages.length < 2) return;
    // 元の順序を保存 (既にシャッフル済みなら上書きしない)
    _originalPageOrder ??= pages.map((p) => p.id).toList();
    pages.shuffle();
    _saveToStorage();
    notifyListeners();
  }

  /// シャッフル前の順序にページ並びを復元する。
  void restorePageOrder() {
    if (_originalPageOrder == null) return;
    final byId = {for (final p in pages) p.id: p};
    final restored = <MindMapPage>[];
    for (final id in _originalPageOrder!) {
      final p = byId[id];
      if (p != null) restored.add(p);
    }
    // _originalPageOrder に無い (= 後で追加された) ページは末尾へ
    for (final p in pages) {
      if (!_originalPageOrder!.contains(p.id)) restored.add(p);
    }
    pages
      ..clear()
      ..addAll(restored);
    _originalPageOrder = null;
    _saveToStorage();
    notifyListeners();
  }

  void updateNodeMemo(String id, String memo) {
    final node = currentPage.nodes[id];
    if (node == null) return;
    _pushUndo();
    // メモ更新時もテキストが収まるように width / height を自動で伸ばす
    final sizes = _computeAutoSizeForText(
      title: node.title,
      memo: memo,
      currentWidth: node.width,
      currentHeight: node.height,
      titleFontSize: node.titleFontSize ?? defaultTitleFontSize,
      memoFontSize: node.memoFontSize ?? defaultMemoFontSize,
    );
    currentPage.nodes[id] = node.copyWith(
      memoText: memo,
      contentType:
          memo.isNotEmpty ? NodeContentType.memo : NodeContentType.none,
      width: sizes.$1,
      height: sizes.$2,
    );
    _saveToStorage();
    notifyListeners();
  }

  /// ノードのリッチテキスト本文を更新する (= ユーザー要望: タイトルとメモを
  /// 分けず、 編集ボタンでまとめてリッチテキストで書ける)。
  /// [richText] は Quill Delta の JSON 文字列。 [title]/[memo] はその平文から
  /// 派生したもので、 検索・サイズ計算(visualHeight)・後方互換のため保持する。
  /// 本文が空なら richText=null に戻して従来ノード扱いにする。
  void updateNodeRichText(String id,
      {required String richText, required String title, required String memo}) {
    final node = currentPage.nodes[id];
    if (node == null) return;
    _pushUndo();
    final sizes = _computeAutoSizeForText(
      title: title,
      memo: memo,
      currentWidth: node.width,
      currentHeight: node.height,
      titleFontSize: node.titleFontSize ?? defaultTitleFontSize,
      memoFontSize: node.memoFontSize ?? defaultMemoFontSize,
    );
    final bool hasRich = richText.trim().isNotEmpty &&
        MindMapNode.richDeltaToPlainText(richText).trim().isNotEmpty;
    currentPage.nodes[id] = node.copyWith(
      richText: hasRich ? richText : null,
      title: title,
      memoText: memo,
      // メモがあれば memo タイプに昇格。 空でも既存タイプは維持し、
      //   youtube/attachment 等を不用意に none へ落とさない。
      contentType: memo.isNotEmpty ? NodeContentType.memo : node.contentType,
      width: sizes.$1,
      height: sizes.$2,
    );
    _saveToStorage();
    notifyListeners();
  }

  /// テキスト量に応じたノードの推奨サイズを計算する。
  /// - 縮小はせず、必要に応じて現在サイズより大きい値を返す
  /// - 幅は最大 360 まで自動で広がる (それ以上はユーザーが手動リサイズ)
  /// - 改行を含むメモでも各行がはみ出さないように最長行基準で幅を決める
  ///
  /// 戻り値: (width, height)
  (double, double) _computeAutoSizeForText({
    required String title,
    required String memo,
    required double currentWidth,
    required double currentHeight,
    required double titleFontSize,
    required double memoFontSize,
  }) {
    const double minWidth = 120.0;
    // 自動拡張（タイトル/メモ入力に応じて自動で広がる）の上限。
    // ユーザーが意図せず巨大化しないよう 300px までに制限。
    // それ以上はユーザーが手動スライダーで明示的に広げる必要がある。
    const double maxAutoWidth = 300.0;
    const double minHeight = 40.0;

    // ── 1) 「最長行」基準でまず必要な最小幅を算出 ─────────────────────
    // タイトル側: 改行のある場合は各行、改行無しでも全体を一行として評価。
    // その後「その幅で収まった場合の visualHeight」を計算し、height も決める。
    final bool hasJaTitle =
        RegExp(r'[\u3000-\u9FFF\uF900-\uFAFF]').hasMatch(title);
    final double titleCharW =
        (titleFontSize.clamp(8.0, 28.0)) * (hasJaTitle ? 0.95 : 0.55);

    // タイトルは基本 1 行で表示したい (改行された入力はそのまま行扱い)
    final titleSegments = title.split('\n');
    double neededWForTitle = minWidth;
    for (final seg in titleSegments) {
      if (seg.isEmpty) continue;
      // テキスト幅 + 左右 padding(10+10) + 予備(5) = 25
      final w = seg.length * titleCharW + 25.0;
      if (w > neededWForTitle) neededWForTitle = w;
    }

    // メモの最長行にも合わせる (改行で区切った各行ごとに必要幅を見る)
    if (memo.isNotEmpty) {
      final bool hasJaMemo =
          RegExp(r'[\u3000-\u9FFF\uF900-\uFAFF]').hasMatch(memo);
      final double memoCharW =
          memoFontSize.clamp(6.0, 22.0) * (hasJaMemo ? 1.0 : 0.58);
      for (final seg in memo.split('\n')) {
        if (seg.isEmpty) continue;
        final w = seg.length * memoCharW + 25.0;
        if (w > neededWForTitle) neededWForTitle = w;
      }
    }

    // 現状 width が十分ならそのまま、そうでなければ拡張 (ただし maxAutoWidth まで)
    double finalW = currentWidth;
    if (neededWForTitle > finalW) {
      finalW = neededWForTitle.clamp(minWidth, maxAutoWidth);
    }

    // ── 2) その幅で visualHeight を計算し、height を必要なら拡張 ─────
    // visualHeight は title のラップ + memo の行数 + サムネイル等を含む。
    // ここでは「基本ブロック (タイトル領域)」の最小高さを決める:
    //   1 行で収まるならデフォルト高さ 42 でOK
    //   2 行以上ラップが必要なら (lines * fs * 1.2 + 16) を height に
    final double usableTextWidth = finalW - 25.0;
    int titleLinesNeeded = 1;
    if (title.isNotEmpty && usableTextWidth > 0) {
      final charsPerLine =
          (usableTextWidth / titleCharW).floor().clamp(1, 1000);
      // 明示的な改行も考慮
      int lines = 0;
      for (final seg in title.split('\n')) {
        final segLen = seg.isEmpty ? 0 : seg.length;
        lines += segLen == 0 ? 1 : (segLen / charsPerLine).ceil();
      }
      titleLinesNeeded = lines.clamp(1, 50);
    }
    final double requiredHeightForTitle = titleLinesNeeded > 1
        ? titleLinesNeeded * (titleFontSize.clamp(8.0, 28.0) * 1.2) + 16
        : minHeight;

    double finalH = currentHeight;
    if (requiredHeightForTitle > finalH) {
      finalH = requiredHeightForTitle;
    }
    return (finalW, finalH);
  }

  /// 全ページから nodeId を検索して (Page, Node) を返す。
  /// 見つからなければ null。
  /// バルク DL のように非同期で完了する処理は、ユーザーが途中で別ページに
  /// 移動するケースをカバーするため currentPage 限定検索だと取りこぼす。
  (MindMapPage, MindMapNode)? _findPageAndNodeById(String id) {
    for (final page in _pages) {
      final node = page.nodes[id];
      if (node != null) return (page, node);
    }
    return null;
  }

  void updateNodeYoutube(String id, String url) {
    // 全ページ走査: バルクダウンロード中にユーザーが別ページに移動しても
    // 元のノードに DL 済み URL を反映するため、currentPage 限定にしない。
    final found = _findPageAndNodeById(id);
    if (found == null) return;
    final page = found.$1;
    final node = found.$2;
    // 別ページのノードを更新する場合は Undo を積まない
    // (currentPage の Undo スタックに入れても文脈が合わないため)
    if (page == currentPage) _pushUndo();
    if (url.isNotEmpty) {
      page.nodes[id] = node.copyWith(
        youtubeUrl: url,
        contentType: NodeContentType.youtube,
      );
    } else {
      // youtubeを消す。linkUrlが残っていればcontentTypeはそのまま
      final updated = node.copyWith(youtubeUrl: '');
      page.nodes[id] = (updated.linkUrl ?? '').isNotEmpty
          ? updated
          : updated.copyWith(contentType: NodeContentType.none);
    }
    // ギャラリーページなら動画化に合わせて再タイル整列。
    _autoArrangeIfBookshelf(page.id);
    _saveToStorage();
    notifyListeners();
  }

  /// ダウンロード一覧から動画ファイルが削除された時に、ローカルパスを
  /// 持っているノードを元の YouTube URL に戻す。
  ///
  /// [restorations] は `{localPath: sourceUrl}` の Map。ローカルパスが
  /// `youtubeUrl` に一致するノードを全ページから探し、その URL を
  /// sourceUrl に書き戻して、サムネ・videoStorageUrl もクリアする。
  /// これにより「オフライン」表示が消え、元の YouTube サムネが復活する。
  ///
  /// Undo は積まない (DL 一覧側のクリーンアップ操作なので、Undo で復元
  /// しても動画ファイルは戻らないため意味がない)。
  void restoreNodesFromLocalVideos(Map<String, String> restorations) {
    if (restorations.isEmpty) return;
    bool changed = false;
    for (final page in _pages) {
      for (final entry in page.nodes.entries) {
        final node = entry.value;
        final localUrl = (node.youtubeUrl ?? '').trim();
        if (localUrl.isEmpty) continue;
        // ローカルパス完全一致のみリストア (URL 直リンクは触らない)
        final sourceUrl = restorations[localUrl];
        if (sourceUrl == null || sourceUrl.isEmpty) continue;
        page.nodes[entry.key] = node.copyWith(
          youtubeUrl: sourceUrl,
          // ローカルファイル由来のサムネはもう存在しないのでクリア。
          // 通常 YouTube ノードに戻れば CDN サムネが自動表示される。
          videoThumbnailPath: '',
          // 動画 Storage URL もクリア (もう紐づくローカルファイルが
          // 無いので、別端末でクラウドから再 DL したい場合は再アップロード)
          videoStorageUrl: '',
        );
        changed = true;
      }
    }
    if (changed) {
      _saveToStorage();
      notifyListeners();
    }
  }

  void updateNodeLink(String id, String url) {
    final node = currentPage.nodes[id];
    if (node == null) return;
    _pushUndo();
    if (url.isNotEmpty) {
      currentPage.nodes[id] = node.copyWith(
        linkUrl: url,
        contentType: NodeContentType.link,
      );
      // OGP画像の自動取得（非同期、失敗しても何もしない）
      // YouTube URL はすでに別途サムネイル処理があるため除外
      // 既存の添付がある場合は上書きしない
      final isYoutube =
          url.contains('youtu.be/') || url.contains('youtube.com/');
      if (!isYoutube && (node.attachmentPath ?? '').isEmpty) {
        // ignore: discarded_futures
        _fetchAndAttachOgImage(id, url);
      }
    } else {
      // linkを消す。youtubeUrlが残っていればcontentTypeはそのまま
      final updated = node.copyWith(linkUrl: '');
      currentPage.nodes[id] = (updated.youtubeUrl ?? '').isNotEmpty
          ? updated
          : updated.copyWith(contentType: NodeContentType.none);
    }
    _autoArrangeIfBookshelf();
    _saveToStorage();
    notifyListeners();
  }

  /// OGP/Twitter Card の画像を取得してノードに添付
  /// ネットワーク失敗時・画像がない場合は何もしない
  Future<void> _fetchAndAttachOgImage(String nodeId, String pageUrl) async {
    try {
      final res = await http.get(
        Uri.parse(pageUrl),
        headers: {
          'User-Agent':
              'Mozilla/5.0 (compatible; MindMapApp/1.0; +https://example.com)',
        },
      ).timeout(const Duration(seconds: 8));
      if (res.statusCode != 200) return;
      final body = res.body;

      // og:image / twitter:image を抽出
      String? imageUrl;
      final ogMatch = RegExp(
              r'''<meta[^>]*property\s*=\s*["']og:image["'][^>]*content\s*=\s*["']([^"']+)["']''',
              caseSensitive: false)
          .firstMatch(body);
      if (ogMatch != null) {
        imageUrl = ogMatch.group(1);
      } else {
        final ogMatch2 = RegExp(
                r'''<meta[^>]*content\s*=\s*["']([^"']+)["'][^>]*property\s*=\s*["']og:image["']''',
                caseSensitive: false)
            .firstMatch(body);
        if (ogMatch2 != null) imageUrl = ogMatch2.group(1);
      }
      if (imageUrl == null || imageUrl.isEmpty) {
        final twMatch = RegExp(
                r'''<meta[^>]*name\s*=\s*["']twitter:image["'][^>]*content\s*=\s*["']([^"']+)["']''',
                caseSensitive: false)
            .firstMatch(body);
        if (twMatch != null) imageUrl = twMatch.group(1);
      }
      if (imageUrl == null || imageUrl.isEmpty) return;

      // 相対URL解決
      if (imageUrl.startsWith('//')) {
        imageUrl = 'https:$imageUrl';
      } else if (imageUrl.startsWith('/')) {
        final base = Uri.parse(pageUrl);
        imageUrl = '${base.scheme}://${base.host}$imageUrl';
      }

      // 画像ダウンロード
      final imgRes = await http
          .get(Uri.parse(imageUrl))
          .timeout(const Duration(seconds: 10));
      if (imgRes.statusCode != 200) return;
      final bytes = imgRes.bodyBytes;
      if (bytes.isEmpty) return;

      // 拡張子判定（URLの末尾 or Content-Type）
      String ext = 'jpg';
      final lower = imageUrl.toLowerCase();
      if (lower.endsWith('.png')) {
        ext = 'png';
      } else if (lower.endsWith('.jpg') || lower.endsWith('.jpeg')) {
        ext = 'jpg';
      } else {
        final ct = imgRes.headers['content-type'] ?? '';
        if (ct.contains('png')) ext = 'png';
      }

      // attachments フォルダに保存
      final dir = await getApplicationDocumentsDirectory();
      final attachDir = Directory('${dir.path}/attachments');
      if (!await attachDir.exists()) {
        await attachDir.create(recursive: true);
      }
      final ts = DateTime.now().millisecondsSinceEpoch;
      final filePath = '${attachDir.path}/og_${ts}_$nodeId.$ext';
      await File(filePath).writeAsBytes(bytes);

      // ノードに添付（再検証: ノードが存在し、まだ添付が空の場合のみ）
      final current = currentPage.nodes[nodeId];
      if (current == null) {
        // ノードが削除済み → ファイルを消す
        try {
          await File(filePath).delete();
        } catch (_) {}
        return;
      }
      if ((current.attachmentPath ?? '').isNotEmpty) {
        // ユーザーが手動で別の添付を付けた → ファイルを消す
        try {
          await File(filePath).delete();
        } catch (_) {}
        return;
      }
      // contentType は link のまま保持（画像プレビューは attachmentPath で表示）
      currentPage.nodes[nodeId] = current.copyWith(
        attachmentPath: filePath,
        attachmentName: 'サムネイル.$ext',
      );
      _saveToStorage();
      notifyListeners();
    } catch (_) {
      // ネットワーク失敗・パース失敗は無視
    }
  }

  void updateNodeColor(String id, Color color) {
    final node = currentPage.nodes[id];
    if (node == null) return;
    _pushUndo();
    currentPage.nodes[id] = node.copyWith(color: color);
    _saveToStorage();
    notifyListeners();
  }

  /// 指定位置に「表ノード」 を新規作成する。
  ///
  /// [rows] / [cols] は 1 以上に正規化。 タイトル空、 `tableData` に
  /// 空セルで初期化されたテーブルを持たせる。 ノード幅は表の全幅にぴったり。
  ///
  /// セル幅/高さのデフォルトは控えめに 70×28 (旧 100×36)。 3×3 で
  /// 約 216×90 のコンパクトサイズ。 ユーザーは右クリックメニューから
  /// 一律で大きく/小さく変更できる。
  MindMapNode addTableNode({
    required int rows,
    required int cols,
    required Offset position,
    double colWidth = 70.0,
    double rowHeight = 28.0,
  }) {
    final table =
        TableData.empty(rows, cols, colWidth: colWidth, rowHeight: rowHeight);
    // ノード幅は「表全幅 + 左右パディング (各 14px = 計 28px)」。
    // 表ノードはタイトル/メモを持たないため、 表の左右にぴったり詰めると
    // 圧迫感が出る。 14px ずつ呼吸を入れる (ユーザー要望「左右にも余白
    // を付けて」)。
    // 下限 80px、 上限 2000px (それ以上は内部の横スクロールに任せる)。
    final nodeWidth = (table.totalWidth + 28.0).clamp(80.0, 2000.0).toDouble();
    final newNode = MindMapNode(
      id: _uuid.v4(),
      title: '',
      position: position,
      contentType: NodeContentType.table,
      tableData: table,
      width: nodeWidth,
      height: 14.0, // ドラッグハンドル帯の高さ (visualHeight で表分は別途加算)
      color: _childColor(),
    );
    _pushUndo();
    currentPage.nodes[newNode.id] = newNode;
    _selectedNodeId = newNode.id;
    _saveToStorage();
    notifyListeners();
    return newNode;
  }

  /// テーブル全体を差し替え (_NodeTableInlineWidget の onChanged から呼ばれる)。
  /// セル文字列の編集は連続発生するため undo には積まない (= 保存のみ)。
  void updateNodeTable(String nodeId, TableData newTable) {
    final node = currentPage.nodes[nodeId];
    if (node == null) return;
    node.tableData = newTable;
    _saveToStorage();
    notifyListeners();
  }

  /// 指定ノードのテーブルに行を挿入する。
  void insertTableRow(String nodeId, int rowIndex) {
    final node = currentPage.nodes[nodeId];
    final t = node?.tableData;
    if (node == null || t == null) return;
    _pushUndo();
    t.insertRow(rowIndex);
    _saveToStorage();
    notifyListeners();
  }

  /// 指定ノードのテーブルから行を削除する (1 行のときは保持)。
  void removeTableRow(String nodeId, int rowIndex) {
    final node = currentPage.nodes[nodeId];
    final t = node?.tableData;
    if (node == null || t == null) return;
    _pushUndo();
    final ok = t.removeRow(rowIndex);
    if (ok) {
      _saveToStorage();
      notifyListeners();
    }
  }

  /// 指定ノードのテーブルに列を挿入する。
  ///
  /// 列追加後、 ノード幅を新しい表全幅 (= 列数 × defaultColWidth + 罫線)
  /// にぴったり追従させる。 これでセルが「等分割」 の状態を保てる
  /// (= 列が増えても各セル幅は同じ defaultColWidth を維持。 ノードが
  /// 横に伸びる)。
  void insertTableColumn(String nodeId, int colIndex) {
    final node = currentPage.nodes[nodeId];
    final t = node?.tableData;
    if (node == null || t == null) return;
    _pushUndo();
    t.insertColumn(colIndex);
    node.width = (t.totalWidth + 28.0).clamp(80.0, 2000.0).toDouble();
    _saveToStorage();
    notifyListeners();
  }

  /// 指定ノードのテーブルから列を削除する (1 列のときは保持)。
  ///
  /// 列削除後、 ノード幅を新しい表全幅にぴったり追従させる。 セル幅は
  /// defaultColWidth のままで、 ノードが横に縮む。
  void removeTableColumn(String nodeId, int colIndex) {
    final node = currentPage.nodes[nodeId];
    final t = node?.tableData;
    if (node == null || t == null) return;
    _pushUndo();
    final ok = t.removeColumn(colIndex);
    if (ok) {
      node.width = (t.totalWidth + 28.0).clamp(80.0, 2000.0).toDouble();
      _saveToStorage();
      notifyListeners();
    }
  }

  /// テーブルのヘッダー行/列フラグをトグル。
  void toggleTableHeader(String nodeId,
      {required bool row, required bool col}) {
    final node = currentPage.nodes[nodeId];
    final t = node?.tableData;
    if (node == null || t == null) return;
    _pushUndo();
    if (row) t.headerRow = !t.headerRow;
    if (col) t.headerCol = !t.headerCol;
    _saveToStorage();
    notifyListeners();
  }

  /// 指定列の幅をセット (null でデフォルト復帰)。 範囲外/不正値は無視。
  ///
  /// ★ 設計変更: 表のセルは「常に等幅」 を保証する設計に変更したため、
  /// この API は実装上 `colIndex` を無視して、 表全体のデフォルト列幅
  /// (defaultColWidth) を更新する。 個別列だけの幅オーバーライドは
  /// もう描画側で見ない (= colWidths[] は無視される) ので、 ここで
  /// 個別配列を書き換える意味もない。
  /// ノード幅は新しい defaultColWidth × colCount + 罫線分にぴったり追従。
  void setTableColumnWidth(String nodeId, int colIndex, double? width) {
    final node = currentPage.nodes[nodeId];
    final t = node?.tableData;
    if (node == null || t == null) return;
    if (width == null || width <= 0) return;
    _pushUndo();
    t.defaultColWidth = width;
    // 旧 colWidths[] オーバーライドが残っていれば全部クリア (= 等幅化)
    for (int i = 0; i < t.colWidths.length; i++) {
      t.colWidths[i] = null;
    }
    // ノード幅を「表全幅」 にぴったり合わせる (= 全セルが等幅になる)
    node.width = (t.totalWidth + 28.0).clamp(80.0, 2000.0).toDouble();
    _saveToStorage();
    notifyListeners();
  }

  /// 指定行の高さをセット (null でデフォルト復帰)。
  ///
  /// ★ 設計変更: 表の行高さも「常に均等」 を保証するため、 `rowIndex` は
  /// 無視して `defaultRowHeight` を更新する。 個別行の高さオーバーライド
  /// は描画側で参照されない (= rowHeights[] は無視) ので個別配列は
  /// クリアするだけ。
  void setTableRowHeight(String nodeId, int rowIndex, double? height) {
    final node = currentPage.nodes[nodeId];
    final t = node?.tableData;
    if (node == null || t == null) return;
    if (height == null || height <= 0) return;
    _pushUndo();
    t.defaultRowHeight = height;
    for (int i = 0; i < t.rowHeights.length; i++) {
      t.rowHeights[i] = null;
    }
    _saveToStorage();
    notifyListeners();
  }

  /// すべての列幅をデフォルトに戻す (= colWidths を全て null にして
  /// defaultColWidth に一括変更)。 同時にデフォルト幅自体も指定可。
  ///
  /// (新設計では setTableColumnWidth が同じ役割を果たすが、 後方互換と
  /// 「リセット」 という意図の明示性のために残してある)
  void resetTableColumnWidths(String nodeId, {double? newDefault}) {
    final node = currentPage.nodes[nodeId];
    final t = node?.tableData;
    if (node == null || t == null) return;
    _pushUndo();
    if (newDefault != null && newDefault > 0) {
      t.defaultColWidth = newDefault;
    }
    for (int i = 0; i < t.colWidths.length; i++) {
      t.colWidths[i] = null;
    }
    node.width = (t.totalWidth + 28.0).clamp(80.0, 2000.0).toDouble();
    _saveToStorage();
    notifyListeners();
  }

  /// すべての行高さをデフォルトに戻す。
  void resetTableRowHeights(String nodeId, {double? newDefault}) {
    final node = currentPage.nodes[nodeId];
    final t = node?.tableData;
    if (node == null || t == null) return;
    _pushUndo();
    if (newDefault != null && newDefault > 0) {
      t.defaultRowHeight = newDefault;
    }
    for (int i = 0; i < t.rowHeights.length; i++) {
      t.rowHeights[i] = null;
    }
    _saveToStorage();
    notifyListeners();
  }

  // ─── AI 一問一答クイズ生成 ─────────────────────────────────────────────
  //
  // PDF を Gemini API に渡して、 ユーザーが指定した問題数の一問一答
  // クイズを JSON 形式で生成させる。 結果は List<Map<String, String>>
  // で返し、 各要素は {'q': '質問', 'a': '答え'} の形を取る。
  //
  // モバイル/デスクトップ両方で動作。 失敗時は例外を throw するので
  // 呼び出し側で catch して SnackBar 等に出すこと。
  //
  // ── 重複回避機能 ──
  // [quizAvoidDuplicates] が true のときは、 過去に生成した質問
  // ([_pastQuizQuestions]) を Gemini に「これらと内容がかぶる問題は
  // 出さないでください」 と指示するヒントとして渡す。 生成された問題は
  // 履歴に蓄積され、 次回以降の生成にも影響する。 履歴は
  // SharedPreferences に永続化されてアプリ再起動を跨いでも保持される。
  //
  // [clearPastQuizQuestions()] で履歴を全消去できる。 「新しいテーマで
  // やり直したい」 ときに使う想定。

  /// 「同じ問題を二度と出さない」 設定。 デフォルト true (重複回避が
  /// 効くようにユーザー要望でデフォルト ON)。
  bool _quizAvoidDuplicates = true;
  bool get quizAvoidDuplicates => _quizAvoidDuplicates;

  /// 過去に生成したクイズの質問テキスト一覧。 最大 500 件まで保持
  /// (古いものから順に削除)。 SharedPreferences に永続化。
  final List<String> _pastQuizQuestions = [];
  List<String> get pastQuizQuestions => List.unmodifiable(_pastQuizQuestions);
  int get pastQuizQuestionCount => _pastQuizQuestions.length;

  /// 起動時に SharedPreferences から復元する。 既存の `_loadXxx` 系と
  /// 同じパターンで initState から非同期に呼ばれる想定。
  Future<void> _loadQuizSettings() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      _quizAvoidDuplicates = prefs.getBool('quizAvoidDuplicates') ?? true;
      final past = prefs.getStringList('pastQuizQuestions');
      if (past != null) {
        _pastQuizQuestions
          ..clear()
          ..addAll(past);
      }
      notifyListeners();
    } catch (_) {/* ignore */}
  }

  /// 設定 ON/OFF。
  Future<void> setQuizAvoidDuplicates(bool v) async {
    _quizAvoidDuplicates = v;
    notifyListeners();
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setBool('quizAvoidDuplicates', v);
    } catch (_) {}
  }

  /// クイズ履歴を全消去。
  Future<void> clearPastQuizQuestions() async {
    _pastQuizQuestions.clear();
    notifyListeners();
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.remove('pastQuizQuestions');
    } catch (_) {}
  }

  // ─── フラッシュカード (= ユーザー要望: 表裏カード + AI 生成/採点 + フォルダー) ───
  final List<Flashcard> _flashcards = [];
  final List<FlashcardFolder> _flashcardFolders = [];
  List<Flashcard> get flashcards => List.unmodifiable(_flashcards);
  List<FlashcardFolder> get flashcardFolders =>
      List.unmodifiable(_flashcardFolders);
  List<Flashcard> flashcardsInFolder(String? folderId) =>
      _flashcards.where((c) => c.folderId == folderId).toList();

  Flashcard addFlashcard(
      {String front = '', String back = '', String? folderId}) {
    final c =
        Flashcard(id: _uuid.v4(), front: front, back: back, folderId: folderId);
    _flashcards.add(c);
    _saveFlashcards();
    notifyListeners();
    return c;
  }

  void updateFlashcard(String id, {String? front, String? back}) {
    final i = _flashcards.indexWhere((x) => x.id == id);
    if (i < 0) return;
    if (front != null) _flashcards[i].front = front;
    if (back != null) _flashcards[i].back = back;
    _saveFlashcards();
    notifyListeners();
  }

  void deleteFlashcard(String id) {
    _flashcards.removeWhere((c) => c.id == id);
    _saveFlashcards();
    notifyListeners();
  }

  void moveFlashcardToFolder(String cardId, String? folderId) {
    final i = _flashcards.indexWhere((x) => x.id == cardId);
    if (i < 0) return;
    _flashcards[i].folderId = folderId;
    _saveFlashcards();
    notifyListeners();
  }

  FlashcardFolder addFlashcardFolder(String name) {
    final f = FlashcardFolder(id: _uuid.v4(), name: name);
    _flashcardFolders.add(f);
    _saveFlashcards();
    notifyListeners();
    return f;
  }

  void renameFlashcardFolder(String id, String name) {
    final i = _flashcardFolders.indexWhere((x) => x.id == id);
    if (i < 0) return;
    _flashcardFolders[i].name = name;
    _saveFlashcards();
    notifyListeners();
  }

  void deleteFlashcardFolder(String id) {
    _flashcardFolders.removeWhere((f) => f.id == id);
    // フォルダー内のカードは「未分類」 に戻す (= カード自体は消さない)。
    for (final c in _flashcards) {
      if (c.folderId == id) c.folderId = null;
    }
    _saveFlashcards();
    notifyListeners();
  }

  Future<void> _saveFlashcards() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString('flashcards_v1',
        jsonEncode(_flashcards.map((c) => c.toJson()).toList()));
    await prefs.setString('flashcardFolders_v1',
        jsonEncode(_flashcardFolders.map((f) => f.toJson()).toList()));
  }

  Future<void> _loadFlashcards() async {
    final prefs = await SharedPreferences.getInstance();
    try {
      final cs = prefs.getString('flashcards_v1');
      if (cs != null && cs.isNotEmpty) {
        _flashcards
          ..clear()
          ..addAll((jsonDecode(cs) as List)
              .map((e) => Flashcard.fromJson(e as Map<String, dynamic>)));
      }
      final fs = prefs.getString('flashcardFolders_v1');
      if (fs != null && fs.isNotEmpty) {
        _flashcardFolders
          ..clear()
          ..addAll((jsonDecode(fs) as List)
              .map((e) => FlashcardFolder.fromJson(e as Map<String, dynamic>)));
      }
    } catch (_) {}
    notifyListeners();
  }

  /// AI でカードの裏面 (答え) を生成する (= ユーザー要望)。
  Future<String> generateFlashcardBack(String front) async {
    final q = front.trim();
    if (q.isEmpty) return '';
    final prompt = '次の用語または質問の「答え・要点」 を、 学習用フラッシュカードの'
        '裏面として簡潔に書いてください。 余計な前置きや繰り返しは不要で、 答え'
        'だけを返してください。\n\n$q';
    try {
      return (await askAi(prompt)).trim();
    } catch (_) {
      return '';
    }
  }

  /// ユーザーの回答を AI で採点する (正誤判定 + 解説) (= ユーザー要望)。
  Future<({bool correct, String explanation})> judgeFlashcardAnswer(
      String front, String back, String userAnswer) async {
    final prompt = '次のフラッシュカードについて、 ユーザーの回答が正しいか判定して'
        'ください。\n問題(表): $front\n模範解答(裏): $back\nユーザーの回答: '
        '$userAnswer\n\n1 行目に「正解」 か「不正解」 のどちらかだけを書き、 '
        '2 行目以降に簡潔な解説を書いてください。';
    try {
      final res = (await askAi(prompt)).trim();
      final firstLine = res.split('\n').first.trim();
      final correct = firstLine.contains('正解') && !firstLine.contains('不正解');
      final explanation = res.contains('\n')
          ? res.substring(res.indexOf('\n') + 1).trim()
          : res;
      return (correct: correct, explanation: explanation);
    } catch (e) {
      return (correct: false, explanation: 'AI 判定に失敗しました: $e');
    }
  }

  /// 生成した質問を履歴に追加。 [generateQuizFromPdf] の内部で呼ばれる。
  Future<void> _appendPastQuizQuestions(List<String> qs) async {
    if (qs.isEmpty) return;
    _pastQuizQuestions
        .addAll(qs.map((s) => s.trim()).where((s) => s.isNotEmpty));
    // 上限 500 件 (古いものから捨てる)
    const maxKeep = 500;
    if (_pastQuizQuestions.length > maxKeep) {
      _pastQuizQuestions.removeRange(0, _pastQuizQuestions.length - maxKeep);
    }
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setStringList('pastQuizQuestions', _pastQuizQuestions);
    } catch (_) {}
  }

  /// 指定された PDF ファイル/URL から、 一問一答クイズを [count] 問生成する。
  ///
  /// [startPage] / [endPage] が指定された場合は、 PDF のそのページ範囲に
  /// 限定した問題を作る (= AI への指示で「○ページ〜△ページの内容から」
  /// と明示する。 PDF 自体は丸ごと送るので、 範囲外のページが参照される
  /// 可能性はゼロではないが、 Gemini はこの指示にだいたい従う)。
  /// null の場合は PDF 全体から作る。
  ///
  /// [quizType] で問題タイプを指定:
  ///   - 'qa'    : 一問一答 (デフォルト) — 答えは自由記述
  ///   - 'ox'    : ○×二択 — 答えは "○" または "×"、 質問は事実の正誤を問う
  ///   - 'mixed' : 一問一答と○×を混合
  ///
  /// 戻り値の各要素は `{'q': 質問, 'a': 答え, 'type': 'qa'|'ox'}` のマップ。
  /// 解析に失敗した場合は空リストを返す。
  Future<List<Map<String, String>>> generateQuizFromPdf(
      String pdfPathOrUrl, int count,
      {int? startPage, int? endPage, String quizType = 'qa'}) async {
    if ((_geminiApiKey ?? '').isEmpty) {
      throw Exception('Gemini APIキーが設定されていません');
    }
    final n = count.clamp(1, 50);

    // PDF データを base64 化。
    // - ローカルパス (file:// または絶対パス) → File.readAsBytes
    // - URL (http/https) → http.get で取得
    List<int> bytes;
    if (pdfPathOrUrl.startsWith('http://') ||
        pdfPathOrUrl.startsWith('https://')) {
      final res = await http
          .get(Uri.parse(pdfPathOrUrl))
          .timeout(const Duration(seconds: 60));
      if (res.statusCode != 200) {
        throw Exception('PDF 取得失敗: HTTP ${res.statusCode}');
      }
      bytes = res.bodyBytes;
    } else {
      final path = pdfPathOrUrl.replaceFirst('file://', '');
      final file = File(path);
      if (!await file.exists()) {
        throw Exception('PDF ファイルが見つかりません: $path');
      }
      bytes = await file.readAsBytes();
    }
    final b64 = base64Encode(bytes);

    final model = _geminiModels.first;
    final url =
        'https://generativelanguage.googleapis.com/v1beta/models/$model:generateContent?key=$_geminiApiKey';

    // ── ページ範囲指定 ──
    // startPage / endPage が指定された場合、 「○ページから△ページまで」
    // の範囲に問題のソースを限定するよう指示する。
    final pageScopeLine = (startPage != null && endPage != null)
        ? '- 出題範囲: PDF の **$startPage ページから $endPage ページまで** に限定し、 範囲外からは出題しない'
        : '- バランスよく PDF 全体から問題を作る (= 冒頭だけに偏らない)';

    // ── 重複回避: 過去に出した質問を除外する指示 ──
    // 履歴が空の場合は何も挿入しない。 履歴が多すぎるとプロンプトが
    // 肥大化するので、 最新の 80 件だけ参照させる。
    String avoidanceBlock = '';
    if (_quizAvoidDuplicates && _pastQuizQuestions.isNotEmpty) {
      final recent = _pastQuizQuestions
          .skip(_pastQuizQuestions.length > 80
              ? _pastQuizQuestions.length - 80
              : 0)
          .map((q) => '- $q')
          .join('\n');
      avoidanceBlock = '''

**重要: 以下の質問は過去に既に出題済みです。 これらと同じ・または内容が
ほぼ重複する問題は絶対に出さないでください。 別の論点・角度から作成してください:**
$recent
''';
    }

    // ── 問題タイプ別の指示 ──
    // 'qa'    : 一問一答 — 答えは自由記述 1〜3 文
    // 'ox'    : ○×二択   — 質問は事実を述べる文、 答えは "○" または "×"
    // 'mixed' : 混合     — 50% 程度ずつ
    final String typeInstruction;
    final String jsonExample;
    if (quizType == 'ox') {
      typeInstruction = '''
**問題タイプ: ○×二択 (まるばつ)**
- 各問題は事実を述べる**断定文**として作成する (例: 「光速は秒速30万kmである」)
- その断定文が PDF の内容に対して**正しいか間違っているか**を答えさせる
- 答えは "○" または "×" のみ (= 記号 1 文字だけ、 補足や説明は付けない)
- 正しい問題と間違った問題を**バランスよく混ぜる** (= 全部 ○ や全部 × にしない)
- 間違った問題は、 PDF の内容を意図的に変えた（数値・人名・年号など）形にする
- **各問題に解説 (e フィールド) を 1〜3 文で付ける**: なぜ ○ / × なのか、 PDF の根拠となる情報を簡潔に説明する
- **各問題に元ネタのページ番号 (page フィールド) を付ける**: 問題の根拠となる記述がある PDF のページ番号 (1-indexed の整数)
- **各問題に検索キーワード (s フィールド) を付ける**: その問題のトピックを Web で調べたいときに使う 1〜3 個のキーワード (半角スペース区切り)。 文章ではなく単語/専門用語のみ''';
      jsonExample = '''
[
  {"q": "光速は秒速30万kmである", "a": "○", "e": "PDF によれば光速は約 299,792 km/s で、 およそ秒速 30 万 km。", "page": 12, "s": "光速 真空", "type": "ox"},
  {"q": "地球は太陽の周りを28日で1周する", "a": "×", "e": "公転周期は約 365 日。 28 日は月の公転周期。", "page": 5, "s": "地球 公転周期", "type": "ox"}
]''';
    } else if (quizType == 'fill') {
      typeInstruction = '''
**問題タイプ: 穴埋め (fill-in-the-blank)**
- 文中の重要な**語句を 1 つだけ** `___` (アンダースコア 3 つ) で隠した問題を作る
- 質問 (q フィールド) の中に `___` を必ず含める (例: 「光合成で植物が吸収する気体は ___ である」)
- 答え (a フィールド) は `___` に当てはまる語句のみ (短く明確に。 1〜数語)
- `___` は 1 問につき **1 ヶ所だけ** (複数空欄は混乱の元)
- 表形式の穴埋めも OK (例: 「以下の表で空欄 ___ に入る値は？ 計算式: f(x) = ___」)
- **各問題に解説 (e フィールド) を 1〜3 文で付ける**: 答えの根拠と関連知識を簡潔に説明する
- **各問題に元ネタのページ番号 (page フィールド) を付ける**: 1-indexed の整数
- **各問題に検索キーワード (s フィールド) を付ける**: 1〜3 個の単語/専門用語 (半角スペース区切り)''';
      jsonExample = '''
[
  {"q": "光合成で植物が吸収する気体は ___ である", "a": "二酸化炭素", "e": "葉の気孔から CO2 を取り込み、 光エネルギーで糖を合成する。", "page": 8, "s": "光合成 二酸化炭素", "type": "fill"},
  {"q": "細胞のエネルギー通貨と呼ばれる分子は ___ である", "a": "ATP", "e": "ATP は加水分解されてエネルギーを供給する。", "page": 14, "s": "ATP エネルギー", "type": "fill"}
]''';
    } else if (quizType == 'mixed') {
      typeInstruction = '''
**問題タイプ: 一問一答 / ○×二択 / 穴埋め の混合**
- 全 $n 問のうち、 **一問一答 (qa)**、 **○×二択 (ox)**、 **穴埋め (fill)** をバランスよく混ぜる (= 各タイプ 1/3 程度ずつ)
- 一問一答: 質問文 + 自由記述 (1〜3 文) の答え
- ○×二択: 断定文 + "○" または "×" の答え (= 記号 1 文字だけ、 補足を付けない)
- 穴埋め: 質問文中に `___` を 1 ヶ所含めて、 答えはその空欄に入る語句のみ
- 各要素の "type" フィールドで "qa" / "ox" / "fill" を明示すること
- **各問題に解説 (e フィールド) を 1〜3 文で付ける**: 答えの根拠を PDF の内容に基づき簡潔に説明する
- **各問題に元ネタのページ番号 (page フィールド) を付ける**: 1-indexed の整数
- **各問題に検索キーワード (s フィールド) を付ける**: 1〜3 個の単語/専門用語 (半角スペース区切り)''';
      jsonExample = '''
[
  {"q": "光合成で植物が吸収する気体は何か", "a": "二酸化炭素", "e": "葉の気孔から CO2 を取り込み、 光エネルギーで糖を合成する。", "page": 8, "s": "光合成 二酸化炭素", "type": "qa"},
  {"q": "水は100℃で凍る", "a": "×", "e": "水の凝固点は 0℃ (1 気圧)。 100℃ は沸点。", "page": 3, "s": "水 凝固点 沸点", "type": "ox"},
  {"q": "細胞のエネルギー通貨と呼ばれる分子は ___ である", "a": "ATP", "e": "ATP は加水分解されてエネルギーを供給する。", "page": 14, "s": "ATP エネルギー", "type": "fill"}
]''';
    } else {
      // default: 'qa' = 一問一答
      typeInstruction = '''
**問題タイプ: 一問一答**
- 各問題は PDF の内容に基づく、 重要度の高い知識を問う問題にする
- 質問は明確で簡潔に
- 答えも簡潔に (1〜3 文程度)
- **各問題に解説 (e フィールド) を 1〜3 文で付ける**: 答えの根拠や補足情報を PDF の内容から簡潔に説明する
- **各問題に元ネタのページ番号 (page フィールド) を付ける**: 問題の根拠となる記述がある PDF のページ番号 (1-indexed の整数)
- **各問題に検索キーワード (s フィールド) を付ける**: その問題のトピックを Web で調べたいときに使う 1〜3 個のキーワード (半角スペース区切り)。 文章ではなく単語/専門用語のみ''';
      jsonExample = '''
[
  {"q": "光合成で植物が吸収する気体は何か", "a": "二酸化炭素", "e": "葉の気孔から CO2 を取り込み、 光エネルギーで糖を合成する。", "page": 8, "s": "光合成 二酸化炭素", "type": "qa"},
  {"q": "細胞の発電所と呼ばれる細胞小器官は何か", "a": "ミトコンドリア", "e": "ATP を生成し、 細胞の主要なエネルギー供給源となる。", "page": 14, "s": "ミトコンドリア ATP", "type": "qa"}
]''';
    }

    final prompt = '''
このPDFの内容をもとに、 クイズを **$n問** 作成してください。

$typeInstruction

要件:
$pageScopeLine
$avoidanceBlock
**必ず以下の JSON 配列形式のみで返答してください。 マークダウンの ```json``` ブロックや説明文は不要です。**

$jsonExample
''';

    final res = await http
        .post(
          Uri.parse(url),
          headers: {'Content-Type': 'application/json'},
          body: jsonEncode({
            'contents': [
              {
                'parts': [
                  {
                    'inline_data': {
                      'mime_type': 'application/pdf',
                      'data': b64,
                    },
                  },
                  {'text': prompt},
                ],
              },
            ],
            'generationConfig': {
              'temperature': 0.6,
              'maxOutputTokens': 8192,
              'responseMimeType': 'application/json',
            },
          }),
        )
        .timeout(const Duration(seconds: 240));

    if (res.statusCode != 200) {
      throw Exception('Gemini API エラー: ${res.statusCode} ${res.body}');
    }
    final data = jsonDecode(utf8.decode(res.bodyBytes)) as Map<String, dynamic>;
    final candidates = data['candidates'] as List?;
    if (candidates == null || candidates.isEmpty) {
      throw Exception('Gemini API: レスポンスが空でした');
    }
    final parts =
        ((candidates.first as Map)['content'] as Map?)?['parts'] as List?;
    final buf = StringBuffer();
    for (final part in parts ?? const []) {
      final t = (part as Map)['text'];
      if (t is String) buf.write(t);
    }
    var text = buf.toString().trim();
    if (text.isEmpty) return [];

    // モデルが ```json ... ``` のように囲んできた場合に剥がす
    final fenceMatch =
        RegExp(r'```(?:json)?\s*([\s\S]*?)\s*```').firstMatch(text);
    if (fenceMatch != null) {
      text = fenceMatch.group(1)!.trim();
    }
    // JSON 配列以外の文字 (説明文の頭/末尾) が混ざることがあるので
    // 最初の [ と最後の ] を切り出す。
    final firstBracket = text.indexOf('[');
    final lastBracket = text.lastIndexOf(']');
    if (firstBracket != -1 && lastBracket > firstBracket) {
      text = text.substring(firstBracket, lastBracket + 1);
    }

    try {
      final decoded = jsonDecode(text);
      if (decoded is! List) return [];
      final result = decoded
          .whereType<Map>()
          .map((m) {
            final qStr = (m['q'] ?? m['question'] ?? '').toString().trim();
            var aStr = (m['a'] ?? m['answer'] ?? '').toString().trim();
            final eStr = (m['e'] ?? m['explanation'] ?? '').toString().trim();
            final tStr = (m['type'] ?? quizType).toString().trim();
            final pStr = (m['page'] ?? '').toString().trim();
            final sStr = (m['s'] ?? m['search'] ?? m['searchKey'] ?? '')
                .toString()
                .trim();
            // ── ○× 答えの正規化 ──
            // Gemini が「○ 正しい」 のように補足を付けてくることがあるので、
            // 'ox' タイプの答えは strict に "○" or "×" の 1 文字に切り詰める
            // (= 表示時の「○ ○」 のような二重を防ぐ)。
            if (tStr == 'ox') {
              if (aStr.contains('○') ||
                  aStr.toLowerCase().startsWith('o') ||
                  aStr.contains('正') ||
                  aStr.contains('まる') ||
                  aStr.contains('マル')) {
                aStr = '○';
              } else if (aStr.contains('×') ||
                  aStr.toLowerCase().startsWith('x') ||
                  aStr.contains('誤') ||
                  aStr.contains('違') ||
                  aStr.contains('ばつ') ||
                  aStr.contains('バツ')) {
                aStr = '×';
              }
            }
            return <String, String>{
              'q': qStr,
              'a': aStr,
              'e': eStr,
              'type': tStr,
              if (pStr.isNotEmpty) 'page': pStr,
              if (sStr.isNotEmpty) 's': sStr,
            };
          })
          .where((e) => e['q']!.isNotEmpty)
          .toList();
      // 生成された質問を履歴に追加 (= 次回の重複回避に使う)。
      // 設定が OFF でも履歴自体は記録しておく (後から ON にしたときに
      // すぐ機能するように)。
      await _appendPastQuizQuestions(result.map((e) => e['q']!).toList());
      return result;
    } catch (_) {
      return [];
    }
  }

  /// PDF の内容から「重要語句 → 説明」 のフラッシュカードを生成する
  /// (= ユーザー要望: ノードからではなく PDF の内容から重要語句を抜き出す)。
  /// 返り値は (表=語句, 裏=説明) のリスト。
  Future<List<(String, String)>> generateFlashcardsFromPdf(
      String pdfPathOrUrl, int count,
      {int? startPage,
      int? endPage,
      String format = 'term',
      bool includeRelated = false}) async {
    if ((_geminiApiKey ?? '').isEmpty) {
      throw Exception('Gemini APIキーが設定されていません');
    }
    final n = count.clamp(1, 60);
    List<int> bytes;
    if (pdfPathOrUrl.startsWith('http://') ||
        pdfPathOrUrl.startsWith('https://')) {
      final res = await http
          .get(Uri.parse(pdfPathOrUrl))
          .timeout(const Duration(seconds: 60));
      if (res.statusCode != 200) {
        throw Exception('PDF 取得失敗: HTTP ${res.statusCode}');
      }
      bytes = res.bodyBytes;
    } else {
      final path = pdfPathOrUrl.replaceFirst('file://', '');
      final file = File(path);
      if (!await file.exists()) {
        throw Exception('PDF ファイルが見つかりません: $path');
      }
      bytes = await file.readAsBytes();
    }
    final b64 = base64Encode(bytes);
    final model = _geminiModels.first;
    final url =
        'https://generativelanguage.googleapis.com/v1beta/models/$model:generateContent?key=$_geminiApiKey';
    final pageScopeLine = (startPage != null && endPage != null)
        ? '- 対象範囲: PDF の **$startPage ページから $endPage ページまで** に限定する'
        : null;
    final prompt = _buildFlashcardPrompt(n,
        format: format,
        includeRelated: includeRelated,
        scopeLine: pageScopeLine);
    final res = await http
        .post(
          Uri.parse(url),
          headers: {'Content-Type': 'application/json'},
          body: jsonEncode({
            'contents': [
              {
                'parts': [
                  {
                    'inline_data': {
                      'mime_type': 'application/pdf',
                      'data': b64,
                    },
                  },
                  {'text': prompt},
                ],
              },
            ],
            'generationConfig': {
              'temperature': 0.5,
              'maxOutputTokens': 8192,
              'responseMimeType': 'application/json',
            },
          }),
        )
        .timeout(const Duration(seconds: 240));
    if (res.statusCode != 200) {
      throw Exception('Gemini API エラー: ${res.statusCode} ${res.body}');
    }
    final data = jsonDecode(utf8.decode(res.bodyBytes)) as Map<String, dynamic>;
    final candidates = data['candidates'] as List?;
    if (candidates == null || candidates.isEmpty) {
      throw Exception('Gemini API: レスポンスが空でした');
    }
    final parts =
        ((candidates.first as Map)['content'] as Map?)?['parts'] as List?;
    final buf = StringBuffer();
    for (final part in parts ?? const []) {
      final t = (part as Map)['text'];
      if (t is String) buf.write(t);
    }
    return _parseFlashcardJson(buf.toString());
  }

  /// AI 応答テキストからフラッシュカード JSON 配列を抽出し (表, 裏) のリストに
  /// 変換する。 マークダウンのコードフェンスや前後の説明文を取り除く。
  List<(String, String)> _parseFlashcardJson(String raw) {
    var text = raw.trim();
    if (text.isEmpty) return [];
    final fenceMatch =
        RegExp(r'```(?:json)?\s*([\s\S]*?)\s*```').firstMatch(text);
    if (fenceMatch != null) text = fenceMatch.group(1)!.trim();
    final firstBracket = text.indexOf('[');
    final lastBracket = text.lastIndexOf(']');
    if (firstBracket != -1 && lastBracket > firstBracket) {
      text = text.substring(firstBracket, lastBracket + 1);
    }
    // ① そのまま厳密パース → ② 文字列内の生制御文字をエスケープして再パース。
    //   (= ユーザー報告: 図表/計算問題を含めると「生成できませんでした」 になる。
    //    原因は AI が JSON 文字列値の中に生の改行/タブ (Markdown 表や数式の
    //    改行) を入れてしまい、 厳密な jsonDecode が落ちるため。 一問一答/穴埋め
    //    など 1 行で収まる形式では起きない。)
    final fromStrict = _decodeFlashcardList(text);
    if (fromStrict != null) return fromStrict;
    final fromSanitized = _decodeFlashcardList(_sanitizeJsonControlChars(text));
    if (fromSanitized != null) return fromSanitized;
    // ③ それでも壊れている時の最終フォールバック: 正規表現で f/b ペアを直接拾う
    //   (= 図表/計算/コード等で AI が引用符のエスケープ漏れ等をしても救済)。
    final loose = _extractFlashcardPairsLoose(text);
    if (loose.isNotEmpty) return loose;
    return const [];
  }

  /// 壊れた JSON からでも "f"/"b" ペアを緩く抽出する最終フォールバック。
  /// 値は生の改行を含んでいても良い (`[^"\\]` が改行も許容する)。
  List<(String, String)> _extractFlashcardPairsLoose(String text) {
    final out = <(String, String)>[];
    final re = RegExp(
        r'"(?:f|front|term|q)"\s*:\s*"((?:\\.|[^"\\])*)"\s*,\s*'
        r'"(?:b|back|definition|a)"\s*:\s*"((?:\\.|[^"\\])*)"',
        dotAll: true);
    for (final m in re.allMatches(text)) {
      final f = _unescapeJsonStr(m.group(1) ?? '').trim();
      final b = _unescapeJsonStr(m.group(2) ?? '').trim();
      if (f.isNotEmpty || b.isNotEmpty) out.add((f, b));
    }
    return out;
  }

  /// JSON 文字列エスケープ (\n \t \" \\ 等) を実文字に戻す。
  String _unescapeJsonStr(String s) {
    final sb = StringBuffer();
    for (int i = 0; i < s.length; i++) {
      final c = s[i];
      if (c == r'\' && i + 1 < s.length) {
        final nx = s[i + 1];
        switch (nx) {
          case 'n':
            sb.write('\n');
            break;
          case 't':
            sb.write('\t');
            break;
          case 'r':
            sb.write('\r');
            break;
          case '"':
            sb.write('"');
            break;
          case r'\':
            sb.write(r'\');
            break;
          case '/':
            sb.write('/');
            break;
          default:
            sb.write(nx);
        }
        i++;
      } else {
        sb.write(c);
      }
    }
    return sb.toString();
  }

  /// JSON 配列をフラッシュカードのリストにデコードする。 失敗時は null。
  List<(String, String)>? _decodeFlashcardList(String text) {
    try {
      final decoded = jsonDecode(text);
      if (decoded is! List) return null;
      return decoded
          .whereType<Map>()
          .map((m) => (
                (m['f'] ?? m['front'] ?? m['term'] ?? m['q'] ?? '')
                    .toString()
                    .trim(),
                (m['b'] ?? m['back'] ?? m['definition'] ?? m['a'] ?? '')
                    .toString()
                    .trim(),
              ))
          .where((c) => c.$1.isNotEmpty || c.$2.isNotEmpty)
          .toList();
    } catch (_) {
      return null;
    }
  }

  /// JSON 文字列リテラル内の「生の制御文字」 (エスケープされていない改行/復帰/
  /// タブ等) を正しい JSON エスケープに置換する。 文字列の外側 (構造) は触らない。
  String _sanitizeJsonControlChars(String s) {
    final sb = StringBuffer();
    bool inStr = false;
    bool esc = false;
    for (int i = 0; i < s.length; i++) {
      final ch = s[i];
      final code = s.codeUnitAt(i);
      if (inStr) {
        if (esc) {
          sb.write(ch);
          esc = false;
          continue;
        }
        if (ch == '\\') {
          sb.write(ch);
          esc = true;
          continue;
        }
        if (ch == '"') {
          sb.write(ch);
          inStr = false;
          continue;
        }
        if (code == 0x0A) {
          sb.write('\\n');
          continue;
        }
        if (code == 0x0D) {
          sb.write('\\r');
          continue;
        }
        if (code == 0x09) {
          sb.write('\\t');
          continue;
        }
        if (code < 0x20) {
          continue; // その他の制御文字は除去
        }
        sb.write(ch);
      } else {
        if (ch == '"') inStr = true;
        sb.write(ch);
      }
    }
    return sb.toString();
  }

  /// 暗記カード生成プロンプト (PDF 以外の資料/テキスト共通)。
  /// フラッシュカード生成プロンプト (= ユーザー要望: 問題形式・関連問題の有無・
  /// 読む範囲を設定できるように)。
  /// [format]: 'term'=語句→意味 / 'qa'=一問一答 / 'cloze'=穴埋め / 'choice'=4択。
  /// [includeRelated]: true なら資料外の関連発展問題も一部含める。
  /// [scopeLine]: PDF ページ範囲・txt 行範囲などの追加注記 (null で全体)。
  /// 問題形式ごとの (形式説明行, JSON 例) を返す。
  /// [format] が "qa,calc,diagram" のようにカンマ区切りなら、 指定された複数の
  /// 形式を「バランスよく混ぜて」 出題する指示にまとめる (= ユーザー要望:
  /// 計算問題・穴埋め・図表など複数タイプを設定で選んで出力)。 単一なら従来通り。
  (String, String) _flashcardFormatParts(String format) {
    final types = format
        .split(',')
        .map((s) => s.trim())
        .where((s) => s.isNotEmpty)
        .toList();
    if (types.length <= 1) {
      return _flashcardFormatPartsSingle(types.isEmpty ? 'term' : types.first);
    }
    // 複数タイプ → 各形式の説明を箇条書きで束ね、 混合出題を指示する。
    final lines = <String>[];
    String example = '';
    for (final t in types) {
      final (l, ex) = _flashcardFormatPartsSingle(t);
      // 先頭の "- 形式: " を外して見やすく束ねる
      lines.add(l.replaceFirst(RegExp(r'^-\s*'), '  ・ '));
      if (example.isEmpty) example = ex;
    }
    final combined = '- 以下の形式を**バランスよく混ぜて**出題する '
        '(各形式がほぼ均等の枚数になるように):\n${lines.join('\n')}';
    return (combined, example);
  }

  /// 単一形式の (形式説明行, JSON 例)。
  /// 'term'=語句→意味 / 'qa'=一問一答 / 'cloze'=穴埋め / 'choice'=4択 /
  /// 'calc'=計算問題 / 'diagram'=図表を伴う問題。
  (String, String) _flashcardFormatPartsSingle(String format) {
    switch (format) {
      case 'qa':
        return (
          '- 形式: 一問一答。 表 (f)=問題文 (例:「光合成とは何か?」)、 裏 (b)=その答え',
          '[\n  {"f": "光合成とは何か?", '
              '"b": "植物が光エネルギーで二酸化炭素と水から糖と酸素を作る反応。"}\n]'
        );
      case 'cloze':
        return (
          '- 形式: 穴埋め。 表 (f)=重要語を ___ で隠した文、 裏 (b)=隠した語',
          '[\n  {"f": "植物は ___ で糖と酸素を作る。", "b": "光合成"}\n]'
        );
      case 'choice':
        return (
          '- 形式: 4択問題。 表 (f)=問題文と選択肢 A〜D、 裏 (b)=正解の記号と簡単な理由',
          '[\n  {"f": "細胞のエネルギー通貨は? '
              'A:DNA B:ATP C:RNA D:脂質", "b": "B (ATP)。 加水分解でエネルギーを放出。"}\n]'
        );
      case 'calc':
        return (
          '- 形式: 計算問題。 表 (f)=計算を要する問題文 (数値・数式・単位を含める)、'
              ' 裏 (b)=最終的な答え＋途中の計算式・考え方を簡潔に',
          '[\n  {"f": "時速 60km で 2.5 時間走ると何 km 進むか?", '
              '"b": "150 km (60 × 2.5 = 150)"},\n'
              '  {"f": "底辺 8cm・高さ 5cm の三角形の面積は?", '
              '"b": "20 cm² (8 × 5 ÷ 2 = 20)"}\n]'
        );
      case 'diagram':
        return (
          '- 形式: 図表を伴う問題。 表 (f)=Markdown の表や簡単な図 '
              '(箇条書き・ASCII) を含む問題文 (改行は \\n)、 裏 (b)=答え',
          '[\n  {"f": "次の表の空欄に入る元素記号を答えよ:\\n'
              '| 元素 | 記号 |\\n|---|---|\\n| 水素 | ___ |\\n| 酸素 | ___ |", '
              '"b": "水素 = H、 酸素 = O"}\n]'
        );
      case 'coding':
        return (
          '- 形式: コーディング問題。 表 (f)=実装課題 (「〜する関数/コードを書け」 等。'
              ' 言語を明記する)、 裏 (b)=模範解答のソースコード (``` で囲む) + 簡単な解説。'
              ' コード内の改行は必ず \\n でエスケープする',
          '[\n  {"f": "Python で 1〜n の整数の総和を返す関数 sum_to(n) を書け。", '
              '"b": "```python\\ndef sum_to(n):\\n    return n * (n + 1) // 2\\n```\\n'
              '等差数列の和の公式 n(n+1)/2 を使うと O(1)。"}\n]'
        );
      default: // term
        return (
          '- 形式: 表 (f)=重要語句・用語・概念名 (短く。 1〜数語)、 裏 (b)=その意味・定義 (1〜3 文)',
          '[\n  {"f": "光合成", "b": "植物が光エネルギーを使って'
              '二酸化炭素と水から糖と酸素を作る反応。"},\n'
              '  {"f": "ATP", "b": "細胞のエネルギー通貨。 加水分解でエネルギーを放出。"}\n]'
        );
    }
  }

  String _buildFlashcardPrompt(int n,
      {String format = 'term',
      bool includeRelated = false,
      String? scopeLine}) {
    final (formatLine, example) = _flashcardFormatParts(format);
    final relatedLine = includeRelated
        ? '- 資料に直接載っていない**関連する発展知識・周辺問題**も全体の3割程度まで含めてよい'
        : '- **資料に書かれている内容のみ**から作成する (推測や外部知識は加えない)';
    final scope = scopeLine ?? '- 資料全体からバランスよく抽出する (= 冒頭だけに偏らない)';
    return '''
この資料の内容から、 暗記用フラッシュカードを **$n枚** 作成してください。

要件:
$scope
$formatLine
$relatedLine
- 重要度の高いものから優先し、 重複や些末な語は避ける
**必ず以下の JSON 配列形式のみで返答してください。 マークダウンや説明文は不要です。**

$example
''';
  }

  /// キーワード/文章を主題として、 AI の知識からフラッシュカードを生成する
  /// (= ユーザー要望: 資料からだけでなく指定したキーワードや文章に対しても)。
  Future<List<(String, String)>> generateFlashcardsAboutTopic(
      String topic, int count,
      {String format = 'term', List<String>? avoidFronts}) async {
    final n = count.clamp(1, 60);
    var t = topic.trim();
    // ── プログラミング系の主題ならコーディング問題も混ぜる (= ユーザー要望) ──
    //   設定で明示的に coding を選んでいなくても、 主題がプログラミング関連なら
    //   実装課題を出題できるようにする。
    var fmt = format;
    if (_looksLikeProgramming(t) && !fmt.split(',').contains('coding')) {
      fmt = fmt.isEmpty ? 'coding' : '$fmt,coding';
    }
    final (formatLine, example) = _flashcardFormatParts(fmt);
    const int kMaxChars = 8000;
    if (t.length > kMaxChars) t = t.substring(0, kMaxChars);
    // ── 既存カードと重複しない指示 (= ユーザー要望: 現在のカードと被る内容は
    //   生成しない設定) ──
    String avoidLine = '';
    if (avoidFronts != null && avoidFronts.isNotEmpty) {
      final list = avoidFronts
          .map((s) => s.replaceAll('\n', ' ').trim())
          .where((s) => s.isNotEmpty)
          .take(120)
          .toList();
      if (list.isNotEmpty) {
        avoidLine = '\n- 次の内容 (既存カード) と**重複・言い換え・同義のカードは作らない**。'
            ' 別の観点・項目を出すこと:\n  ${list.join(' / ')}';
      }
    }
    final prompt = '''
次の主題について、 暗記用フラッシュカードを **$n枚** 作成してください。
主題に関する重要な語句・概念・事実・要点を、 あなたの知識から網羅的に挙げてください。

主題: 「$t」

要件:
- 主題に対して重要度の高い・基礎的なものから優先する
$formatLine
- 重複や些末なものは避け、 学習に役立つ内容にする$avoidLine
**必ず以下の JSON 配列形式のみで返答してください。 マークダウンや説明文は不要です。**

$example
''';
    final responseText = await askAi(prompt);
    return _parseFlashcardJson(responseText);
  }

  /// 主題がプログラミング関連か簡易判定する (= コーディング問題の自動付与に使う)。
  bool _looksLikeProgramming(String topic) {
    final s = topic.toLowerCase();
    const kw = [
      'プログラ', 'コーディング', 'コード', 'アルゴリズム', '関数', 'クラス', '変数',
      '配列', 'ループ', '再帰', 'データ構造', 'オブジェクト指向', '競技プログラ', 'atcoder',
      'leetcode', 'paiza', '実装',
      'python', 'java', 'javascript', 'typescript', 'kotlin', 'swift', 'dart',
      'flutter', 'react', 'node', 'c++', 'c#', 'golang', ' go ', 'rust', 'ruby',
      'php', 'sql', 'html', 'css', 'shell', 'bash', 'api', 'oop', 'recursion',
      'algorithm', 'function', 'programming', 'leet', 'コンパイル', '計算量',
    ];
    return kw.any((k) => s.contains(k));
  }

  /// ファイル (PDF / docx / pptx / txt 等) の内容から暗記カードを AI 生成する
  /// (= ユーザー要望: フラッシュカードを PDF 以外の docx/pptx/txt からも作れる
  /// ように)。 PDF はページ範囲対応の [generateFlashcardsFromPdf] を流用。
  /// docx/pptx は Gemini にバイナリ送信、 テキスト系は本文を読んで送る。
  Future<List<(String, String)>> generateFlashcardsFromFile(
      String filePath, String fileName, int count,
      {int? startPage,
      int? endPage,
      String format = 'term',
      bool includeRelated = false}) async {
    final dot = fileName.lastIndexOf('.');
    final ext = dot >= 0 ? fileName.substring(dot + 1).toLowerCase() : '';
    if (ext == 'pdf') {
      return generateFlashcardsFromPdf(filePath, count,
          startPage: startPage,
          endPage: endPage,
          format: format,
          includeRelated: includeRelated);
    }
    final n = count.clamp(1, 60);
    final prompt = _buildFlashcardPrompt(n,
        format: format, includeRelated: includeRelated);
    const textExts = {
      'txt',
      'md',
      'markdown',
      'csv',
      'tsv',
      'json',
      'log',
      'dart',
      'py',
      'js',
      'ts',
      'java',
      'kt',
      'cpp',
      'c',
      'h',
      'hpp',
      'cs',
      'go',
      'rb',
      'rs',
      'swift',
      'sh',
      'yml',
      'yaml',
      'xml',
      'html',
      'htm',
      'css',
    };
    String responseText;
    if (textExts.contains(ext)) {
      final f = File(filePath);
      String content;
      try {
        content = await f.readAsString();
      } catch (_) {
        content = String.fromCharCodes(await f.readAsBytes());
      }
      const int kMaxChars = 60000;
      if (content.length > kMaxChars) {
        content = '${content.substring(0, kMaxChars)}\n... [truncated]';
      }
      responseText = await askAi('$prompt\n\n--- 資料の内容 ---\n$content');
    } else {
      // docx / pptx / 画像など → バイナリのまま AI (Gemini) に送る
      responseText = await _askAiWithBinaryDoc(
          filePath: filePath, fileName: fileName, ext: ext, prompt: prompt);
    }
    return _parseFlashcardJson(responseText);
  }

  /// 抽出済みテキストからフラッシュカードを生成する (= ユーザー要望: 設定した
  /// モデル (Gemini 以外も) で生成。 PDF 等のバイナリ非対応プロバイダ向けに、
  /// 呼び出し側でテキストを抽出してここへ渡す)。 `askAi` で選択中プロバイダを使う。
  Future<List<(String, String)>> generateFlashcardsFromText(
      String text, int count,
      {String format = 'term',
      bool includeRelated = false,
      String? scopeLine}) async {
    final n = count.clamp(1, 60);
    var content = text;
    const int kMaxChars = 60000;
    if (content.length > kMaxChars) {
      content = '${content.substring(0, kMaxChars)}\n... [truncated]';
    }
    final prompt = _buildFlashcardPrompt(n,
        format: format, includeRelated: includeRelated, scopeLine: scopeLine);
    final responseText = await askAi('$prompt\n\n--- 資料の内容 ---\n$content');
    return _parseFlashcardJson(responseText);
  }

  void updateNodeSize(String id, double width, double height) {
    final node = currentPage.nodes[id];
    if (node == null) return;
    _pushUndo();
    // ── 表ノード分岐: スライダーで受けた (width, height) を「表全体の
    // 見かけサイズ」 とみなし、 defaultColWidth / defaultRowHeight を逆算 ──
    //
    // node.height は 14 (ドラッグハンドル帯) 固定。 visualHeight は
    // tableData.estimateTotalHeight() 経由で実描画と一致する。
    if (node.tableData != null) {
      final t = node.tableData!;
      // 表ノードの上限は通常ノードより少し広めに (200 だと 10行 でも
      // 行高さが 17px しか取れない)。 800 まで許容。
      final clampedW = width.clamp(80.0, 2000.0).toDouble();
      final clampedH = height.clamp(36.0, 800.0).toDouble();

      // ── defaultRowHeight 逆算 ──
      if (t.rowCount > 0) {
        final innerH = (clampedH - 28.0).clamp(20.0, double.infinity);
        final rowH = ((innerH - (t.rowCount + 1) * t.borderWidth) / t.rowCount)
            .clamp(10.0, 300.0);
        t.defaultRowHeight = rowH.toDouble();
        for (int i = 0; i < t.rowHeights.length; i++) {
          t.rowHeights[i] = null;
        }
      }

      // ── defaultColWidth 逆算 ──
      if (t.colCount > 0) {
        final innerW = (clampedW - 28.0).clamp(40.0, double.infinity);
        final colW = ((innerW - (t.colCount + 1) * t.borderWidth) / t.colCount)
            .clamp(20.0, 1000.0);
        t.defaultColWidth = colW.toDouble();
        for (int i = 0; i < t.colWidths.length; i++) {
          t.colWidths[i] = null;
        }
      }

      t.invalidateHeightCache();

      currentPage.nodes[id] = node.copyWith(
        width: clampedW,
        height: 14.0,
      );
      _saveToStorage();
      notifyListeners();
      return;
    }
    // 画像オリジナルサイズで貼り付けたノード (= attachmentAspectRatio が
    // セットされている) は手動リサイズの許容範囲を広く取る:
    // 80〜1800 × 36〜1200 px。 通常ノードと同じ 80〜400 × 36〜200 だと、
    // 画像ノードを少しドラッグしただけで一気にサイズが縮んでしまう。
    final isImageNode = node.attachmentAspectRatio != null;
    final maxW = isImageNode ? 1800.0 : 400.0;
    final maxH = isImageNode ? 1200.0 : 200.0;
    currentPage.nodes[id] = node.copyWith(
      width: width.clamp(80.0, maxW),
      height: height.clamp(36.0, maxH),
    );
    // ── ギャラリーページ: サイズ変更したら隣接タイルが重ならないよう即再整列 ──
    //   (= ユーザー要望 #4: 要素の横幅を大きくしても、 どの大きさでも一定間隔を
    //    保つ)。 リサイズ中のノードは自分の左端 (= 左側の列幅で決まる) が動かず
    //    右方向にだけ伸びるので、 ハンドルの基準がずれずスムーズ。
    if (currentPage.pageType == 'bookshelf') {
      _arrangeAsBookshelfBody(currentPage);
    }
    _saveToStorage();
    notifyListeners();
  }

  /// `updateNodeSize` の上限緩和版。 ペースト画像など、 大きなオリジナル
  /// サイズで貼り付ける場合用。 通常 [updateNodeSize] (80〜400 × 36〜200) は
  /// マウスドラッグでのリサイズ用なので狭めだが、 こちらは 80〜2000 × 36〜2000
  /// まで許容する。
  void updateNodeSizeUnclamped(String id, double width, double height) {
    final node = currentPage.nodes[id];
    if (node == null) return;
    _pushUndo();
    currentPage.nodes[id] = node.copyWith(
      width: width.clamp(80.0, 2000.0),
      height: height.clamp(36.0, 2000.0),
    );
    _saveToStorage();
    notifyListeners();
  }

  /// 添付画像のアスペクト比 (= width / height) をノードに記録する。
  /// 「画像オリジナルサイズで貼り付け」 設定 ON で貼った時にだけ使う想定で、
  /// 描画時に `node_widget` の attachH 計算で参照される。
  /// null を渡すと未設定 (= 旧来の `nw * 0.6` 計算) に戻る。
  void updateNodeAttachmentAspectRatio(String id, double? ratio) {
    final node = currentPage.nodes[id];
    if (node == null) return;
    _pushUndo();
    currentPage.nodes[id] = node.copyWith(
      attachmentAspectRatio: ratio,
    );
    _saveToStorage();
    notifyListeners();
  }

  /// ノード個別のタイトルフォントサイズを設定（nullで全体デフォルトに戻す）
  void updateNodeTitleFontSize(String id, double? size) {
    final node = currentPage.nodes[id];
    if (node == null) return;
    _pushUndo();
    currentPage.nodes[id] = node.copyWith(
      titleFontSize: size,
    );
    _saveToStorage();
    notifyListeners();
  }

  /// ノード個別のメモフォントサイズを設定（nullで全体デフォルトに戻す）
  void updateNodeMemoFontSize(String id, double? size) {
    final node = currentPage.nodes[id];
    if (node == null) return;
    _pushUndo();
    currentPage.nodes[id] = node.copyWith(
      memoFontSize: size,
    );
    _saveToStorage();
    notifyListeners();
  }

  void setDefaultTitleFontSize(double size) {
    defaultTitleFontSize = size.clamp(8.0, 28.0);
    _saveToStorage();
    notifyListeners();
  }

  void setDefaultMemoFontSize(double size) {
    defaultMemoFontSize = size.clamp(6.0, 22.0);
    _saveToStorage();
    notifyListeners();
  }

  /// ノードのアンカーモードを切替（2→4→8→2...）
  void cycleAnchorMode(String id) {
    final node = currentPage.nodes[id];
    if (node == null) return;
    _pushUndo();
    final next = NodeAnchorMode
        .values[(node.anchorMode.index + 1) % NodeAnchorMode.values.length];
    currentPage.nodes[id] = node.copyWith(anchorMode: next);
    _saveToStorage();
    notifyListeners();
  }

  /// YouTube検索結果からノードを自動生成（生成済みは除外）
  /// [startIndex] から最大 [batchSize] 件を生成。戻り値は (parentId, 残り件数)。
  (String, int) addYoutubeNodes(String keyword, List<String> videoIds,
      List<String> titles, Offset basePos,
      {int startIndex = 0, int batchSize = 10, String? existingParentId}) {
    const gap = 16.0;
    final nodeMap = currentPage.nodes;

    // 生成済み動画を除外
    final newIds = <String>[];
    final newTitles = <String>[];
    for (int i = 0; i < videoIds.length; i++) {
      if (!_generatedVideoIds.contains(videoIds[i])) {
        newIds.add(videoIds[i]);
        newTitles.add(titles[i]);
      }
    }

    // 親ノード（キーワード）— 既存の親があればそれを使う
    String parentId;
    if (existingParentId != null && nodeMap.containsKey(existingParentId)) {
      parentId = existingParentId;
    } else {
      parentId = _uuid.v4();
      final parent = MindMapNode(
        id: parentId,
        title: keyword,
        position: basePos,
        color: const Color(0xFFE53935),
      );
      nodeMap[parentId] = parent;
    }

    // 新しい動画が0件なら親ノードだけ返す
    if (newIds.isEmpty) {
      _saveToStorage();
      notifyListeners();
      return (parentId, 0);
    }

    // 既存の子ノードの最下部Y座標を求める
    double? existingBottom;
    for (final c in currentPage.connections) {
      if (c.fromId == parentId) {
        final child = nodeMap[c.toId];
        if (child != null) {
          final bottom = child.position.dy + child.visualHeight + gap;
          if (existingBottom == null || bottom > existingBottom) {
            existingBottom = bottom;
          }
        }
      }
    }

    // startIndex から batchSize 件分を生成
    final endIndex = (startIndex + batchSize).clamp(0, newIds.length);
    final count = endIndex - startIndex;

    double currentY;
    if (existingBottom != null) {
      // 追加生成: 既存の子の下に配置
      currentY = existingBottom;
    } else {
      // 初回生成: 仮ノードで合計高さを計算し、親の中央に揃える
      double totalH = 0;
      for (int i = startIndex; i < endIndex; i++) {
        final temp = MindMapNode(
          id: _uuid.v4(),
          title: newTitles[i],
          position: Offset.zero,
          youtubeUrl: 'https://www.youtube.com/watch?v=${newIds[i]}',
          contentType: NodeContentType.youtube,
          color: _childColor(),
        );
        totalH += temp.visualHeight;
      }
      totalH += gap * (count - 1);
      final parentNode = nodeMap[parentId];
      final parentCenterY = parentNode != null
          ? parentNode.position.dy + parentNode.visualHeight / 2
          : basePos.dy;
      currentY = (parentCenterY - totalH / 2).clamp(0.0, 20000.0);
    }

    for (int i = startIndex; i < endIndex; i++) {
      final childId = _uuid.v4();
      final childPos = Offset(basePos.dx + 200, currentY);
      final child = MindMapNode(
        id: childId,
        title: newTitles[i],
        position: childPos,
        youtubeUrl: 'https://www.youtube.com/watch?v=${newIds[i]}',
        contentType: NodeContentType.youtube,
        color: _childColor(),
      );
      nodeMap[childId] = child;

      currentPage.connections.add(NodeConnection(
        fromId: parentId,
        fromAnchor: AnchorDirection.east,
        toId: childId,
        toAnchor: AnchorDirection.west,
      ));

      _generatedVideoIds.add(newIds[i]);
      currentY += child.visualHeight + gap;
    }

    _saveToStorage();
    _saveGeneratedIds();
    notifyListeners();

    final remaining = newIds.length - endIndex;
    return (parentId, remaining);
  }

  /// プレイリストからノードを生成（動画タイトルをそのまま使用、5件ずつ）
  /// プレイリストからノードを生成（5件ずつ、親ノード中央展開）
  /// 戻り値: (parentId, remaining, loadMoreNodeId?)
  /// 戻り値: (parentId, remainingUnseen, loadMoreNodeId, nextStartIndex)
  (String, int, String?, int) addPlaylistNodes(String playlistId,
      List<String> videoIds, List<String> titles, Offset basePos,
      {required String parentNodeId, int startIndex = 0, int batchSize = 5}) {
    const gap = 16.0;
    final nodeMap = currentPage.nodes;

    if (videoIds.isEmpty) return ('', 0, null, 0);

    final parentId = parentNodeId;
    final parentNode = nodeMap[parentId];

    // startIndex以降で未生成の動画だけを収集（最大batchSize件）
    // ただし `_allowDuplicateVideoNodes` が立っていれば既に生成済みでも
    // 再度ノード化する (ユーザー要望: 過去に生成した動画も再度生成したい)。
    final pickedIndices = <int>[];
    for (int i = startIndex;
        i < videoIds.length && pickedIndices.length < batchSize;
        i++) {
      if (_allowDuplicateVideoNodes ||
          !_generatedVideoIds.contains(videoIds[i])) {
        pickedIndices.add(i);
      }
    }

    if (pickedIndices.isEmpty) {
      // 未生成の動画が残っているか確認 (フラグ ON 時は全て残ってる扱い)
      int remainingUnseen = 0;
      for (int i = startIndex; i < videoIds.length; i++) {
        if (_allowDuplicateVideoNodes ||
            !_generatedVideoIds.contains(videoIds[i])) {
          remainingUnseen++;
        }
      }
      return (parentId, remainingUnseen, null, startIndex);
    }

    // 実際にここまで使ったインデックス（次回のstartIndex用）
    final lastPickedIndex = pickedIndices.last;

    // 仮ノードで合計高さを計算
    final tempNodes = <MindMapNode>[];
    for (final i in pickedIndices) {
      tempNodes.add(MindMapNode(
        id: _uuid.v4(),
        title: titles[i].isNotEmpty ? titles[i] : 'Video ${i + 1}',
        position: Offset.zero,
        youtubeUrl: 'https://www.youtube.com/watch?v=${videoIds[i]}',
        contentType: NodeContentType.youtube,
        color: _childColor(),
      ));
    }
    double totalH = 0;
    for (final n in tempNodes) {
      totalH += n.visualHeight;
    }
    totalH += gap * (tempNodes.length - 1);

    // 既存の子ノードがあるか確認
    double? existingBottom;
    for (final c in currentPage.connections) {
      if (c.fromId == parentId) {
        final child = nodeMap[c.toId];
        if (child != null) {
          final bottom = child.position.dy + child.visualHeight + gap;
          if (existingBottom == null || bottom > existingBottom) {
            existingBottom = bottom;
          }
        }
      }
    }

    double startY;
    if (existingBottom != null) {
      // 既存の子がある → その下に配置
      startY = existingBottom;
    } else if (parentNode != null) {
      // 初回 → 親ノード中央に揃える
      final parentCenterY =
          parentNode.position.dy + parentNode.visualHeight / 2;
      startY = (parentCenterY - totalH / 2).clamp(0.0, 20000.0);
    } else {
      startY = basePos.dy;
    }

    // ノードを配置
    double currentY = startY;
    for (final temp in tempNodes) {
      final childPos = Offset(basePos.dx, currentY);
      final child = temp.copyWith(position: childPos);
      nodeMap[child.id] = child;

      currentPage.connections.add(NodeConnection(
        fromId: parentId,
        fromAnchor: AnchorDirection.east,
        toId: child.id,
        toAnchor: AnchorDirection.west,
      ));

      _generatedVideoIds.add(RegExp(r'v=([a-zA-Z0-9_-]{11})')
              .firstMatch(child.youtubeUrl!)
              ?.group(1) ??
          '');
      currentY += child.visualHeight + gap;
    }

    // 残りの未生成動画数をカウント (フラグ ON なら「全て未生成扱い」)
    int remainingUnseen = 0;
    for (int i = lastPickedIndex + 1; i < videoIds.length; i++) {
      if (_allowDuplicateVideoNodes ||
          !_generatedVideoIds.contains(videoIds[i])) {
        remainingUnseen++;
      }
    }

    // 次回のstartIndexは最後にピックしたインデックスの次
    final nextStart = lastPickedIndex + 1;
    final displayed = videoIds.length - remainingUnseen;
    final total = videoIds.length;
    String? loadMoreNodeId;

    // 残りがある場合「次のN件を表示」ノードを配置
    if (remainingUnseen > 0) {
      final nextBatch = remainingUnseen.clamp(1, batchSize);
      final loadMoreId = _uuid.v4();
      // タイトルは多言語対応 (現在のアプリ言語で書き込まれる)。
      // 後でユーザーが言語を切り替えてもこの 1 ノードは旧言語のままだが、
      // プレイリスト再生成で新しい言語に追従する。
      final loadMoreTitle = t('loadMore.label')
          .replaceAll('{n}', nextBatch.toString())
          .replaceAll('{displayed}', displayed.toString())
          .replaceAll('{total}', total.toString());
      final loadMoreNode = MindMapNode(
        id: loadMoreId,
        title: loadMoreTitle,
        position: Offset(basePos.dx, currentY),
        color: const Color(0xFFE53935),
        width: 180,
        height: 36,
      );
      nodeMap[loadMoreId] = loadMoreNode;
      currentPage.connections.add(NodeConnection(
        fromId: parentId,
        fromAnchor: AnchorDirection.east,
        toId: loadMoreId,
        toAnchor: AnchorDirection.west,
      ));
      loadMoreNodeId = loadMoreId;
    }

    _saveToStorage();
    _saveGeneratedIds();
    notifyListeners();

    return (parentId, remainingUnseen, loadMoreNodeId, nextStart);
  }

  Future<void> _saveGeneratedIds() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setStringList('generatedVideoIds', _generatedVideoIds.toList());
  }

  Future<void> _loadGeneratedIds() async {
    final prefs = await SharedPreferences.getInstance();
    final ids = prefs.getStringList('generatedVideoIds');
    if (ids != null) _generatedVideoIds.addAll(ids);
  }

  bool isVideoGenerated(String videoId) => _generatedVideoIds.contains(videoId);

  int get generatedVideoCount => _generatedVideoIds.length;

  void clearGeneratedVideoIds() {
    _generatedVideoIds.clear();
    _saveGeneratedIds();
    notifyListeners();
  }

  // ─── 動画再生位置 ──────────────────────────────────────────────────────────

  void saveVideoPosition(String videoId, double seconds) {
    _videoPositions[videoId] = seconds;
    _lastWatchedVideoId = videoId;
    _saveVideoPositions();
  }

  double getVideoPosition(String videoId) => _videoPositions[videoId] ?? 0;

  String? get lastWatchedVideoId => _lastWatchedVideoId;

  Future<void> _saveVideoPositions() async {
    final prefs = await SharedPreferences.getInstance();
    final map = _videoPositions.map((k, v) => MapEntry(k, v.toString()));
    await prefs.setString('videoPositions', jsonEncode(map));
    if (_lastWatchedVideoId != null) {
      await prefs.setString('lastWatchedVideoId', _lastWatchedVideoId!);
    }
  }

  Future<void> _loadVideoPositions() async {
    final prefs = await SharedPreferences.getInstance();
    final str = prefs.getString('videoPositions');
    if (str != null) {
      try {
        final map = jsonDecode(str) as Map<String, dynamic>;
        for (final e in map.entries) {
          _videoPositions[e.key] = double.tryParse(e.value.toString()) ?? 0;
        }
      } catch (_) {}
    }
    _lastWatchedVideoId = prefs.getString('lastWatchedVideoId');
    _lastYoutubeBrowseUrl = prefs.getString('lastYoutubeBrowseUrl');
  }

  /// 「YouTubeを開く」ブラウザを閉じた直後などに、その時表示していた URL を
  /// 保存する。次回起動時に同じ画面から再開するために使う。
  /// 動画再生 (/watch, /shorts) や about:blank はスキップ
  /// (検索結果ページやチャンネルページなどブラウズ中の状態だけ保存する)。
  void saveYoutubeBrowseUrl(String url) {
    if (url.isEmpty || url == 'about:blank') return;
    // 動画再生ページや埋め込みページは保存しない (動画から戻ったときに
    // 同じ動画が再生され続けるのは望ましくない)。検索結果やチャンネル
    // ページからの再開だけサポート。
    if (url.contains('/watch') ||
        url.contains('/shorts/') ||
        url.contains('/embed/') ||
        url.contains('youtu.be/')) {
      return;
    }
    _lastYoutubeBrowseUrl = url;
    _saveLastYoutubeBrowseUrl();
  }

  Future<void> _saveLastYoutubeBrowseUrl() async {
    final prefs = await SharedPreferences.getInstance();
    if (_lastYoutubeBrowseUrl != null) {
      await prefs.setString('lastYoutubeBrowseUrl', _lastYoutubeBrowseUrl!);
    }
  }

  /// 保存された URL をクリアする (検索ワード入力に戻したい場合に使う)。
  void clearLastYoutubeBrowseUrl() {
    _lastYoutubeBrowseUrl = null;
    SharedPreferences.getInstance()
        .then((p) => p.remove('lastYoutubeBrowseUrl'));
  }

  // 折りたたみ時の親ノード位置を記録
  final Map<String, Offset> _collapsedPositions = {};

  void toggleNodeCollapsed(String id) {
    final node = currentPage.nodes[id];
    if (node == null) return;
    _pushUndo();

    if (node.collapsed) {
      // 展開: 親が移動していたら子孫も同じだけ移動
      final savedPos = _collapsedPositions[id];
      if (savedPos != null) {
        final delta = Offset(
          node.position.dx - savedPos.dx,
          node.position.dy - savedPos.dy,
        );
        if (delta.dx.abs() > 0.1 || delta.dy.abs() > 0.1) {
          final descendants = getDescendants(id);
          for (final descId in descendants) {
            final desc = currentPage.nodes[descId];
            if (desc != null) {
              currentPage.nodes[descId] = desc.copyWith(
                position: Offset(
                  (desc.position.dx + delta.dx)
                      .clamp(0.0, 20000.0 - desc.width),
                  (desc.position.dy + delta.dy)
                      .clamp(0.0, 20000.0 - desc.height),
                ),
              );
            }
          }
        }
        _collapsedPositions.remove(id);
      }
    } else {
      // 折りたたみ: 現在位置を記録
      _collapsedPositions[id] = node.position;
    }

    currentPage.nodes[id] = node.copyWith(collapsed: !node.collapsed);
    _saveToStorage();
    notifyListeners();
  }

  /// 折りたたみ中の親 [parentId] に新しい子を接続したとき、 子が hiddenNodeIds
  /// に入って画面から消えるのを防ぐため親を展開する (= 「配置候補に置くと
  /// ノードが消えてしまう」 バグの修正)。
  /// 呼び出し側 (connectNodes / moveAndConnectToTarget 等) が既に _pushUndo
  /// 済みである前提で、 undo は二重に積まない。
  void _expandIfCollapsed(String parentId) {
    final nodeMap = currentPage.nodes;
    final parent = nodeMap[parentId];
    if (parent == null || !parent.collapsed) return;
    // toggleNodeCollapsed の展開分岐と同等 (折りたたみ中に親が動いていたら
    // 子孫も同じだけ移動して相対位置を保つ)。
    final savedPos = _collapsedPositions[parentId];
    if (savedPos != null) {
      final delta = Offset(
        parent.position.dx - savedPos.dx,
        parent.position.dy - savedPos.dy,
      );
      if (delta.dx.abs() > 0.1 || delta.dy.abs() > 0.1) {
        for (final descId in getDescendants(parentId)) {
          final desc = nodeMap[descId];
          if (desc != null) {
            nodeMap[descId] = desc.copyWith(
              position: Offset(
                (desc.position.dx + delta.dx).clamp(0.0, 20000.0 - desc.width),
                (desc.position.dy + delta.dy).clamp(0.0, 20000.0 - desc.height),
              ),
            );
          }
        }
      }
      _collapsedPositions.remove(parentId);
    }
    nodeMap[parentId] = parent.copyWith(collapsed: false);
  }

  /// あるノードの子孫IDを再帰的に取得（接続の from→to 方向を子とみなす）
  Set<String> getDescendants(String nodeId) {
    final result = <String>{};
    final conns = currentPage.connections;
    void collect(String id) {
      for (final c in conns) {
        if (c.fromId == id && !result.contains(c.toId)) {
          result.add(c.toId);
          collect(c.toId);
        }
      }
    }

    collect(nodeId);
    return result;
  }

  /// 折りたたみ状態で非表示にすべきノードIDの集合
  Set<String> get hiddenNodeIds {
    final hidden = <String>{};
    for (final node in currentPage.nodes.values) {
      if (node.collapsed) {
        hidden.addAll(getDescendants(node.id));
      }
    }
    return hidden;
  }

  void deleteNode(String id) {
    final nodeMap = currentPage.nodes;
    if (!nodeMap.containsKey(id)) return;
    _pushUndo();
    nodeMap.remove(id);
    // このノードに関連するすべての接続を削除
    currentPage.connections.removeWhere((c) => c.fromId == id || c.toId == id);
    if (_selectedNodeId == id) _selectedNodeId = null;
    // = ユーザー要望: ギャラリーは削除後に左詰めして gap を除去。
    // ★ compactShelfCells は論理セル (_shelfCells) を詰めるだけで、 タイルは
    //   node.position で描画されるため見た目が動かなかった (= ユーザー報告:
    //   削除しても詰まらない)。 _arrangeAsBookshelfBody で実際の位置を再配置する。
    if (currentPage.pageType == 'bookshelf') {
      compactShelfCells();
      _arrangeAsBookshelfBody(currentPage);
    }
    _saveToStorage();
    notifyListeners();
  }

  void clearCurrentPage() {
    _pushUndo();
    currentPage.nodes.clear();
    currentPage.connections.clear();
    _selectedNodeId = null;
    // 仕様変更（2026-04）:
    // リセット時もメインテーマ(ルート)ノードは作成しない。完全に空に戻す。
    _saveToStorage();
    notifyListeners();
  }

  /// 複数ノードを一括削除
  void deleteNodes(Set<String> ids) {
    final nodeMap = currentPage.nodes;
    _pushUndo();
    for (final id in ids) {
      nodeMap.remove(id);
      currentPage.connections
          .removeWhere((c) => c.fromId == id || c.toId == id);
    }
    if (ids.contains(_selectedNodeId)) _selectedNodeId = null;
    // = ユーザー要望: ギャラリーは削除後に左詰めして gap を除去。
    // ★ compactShelfCells は論理セル (_shelfCells) を詰めるだけで、 タイルは
    //   node.position で描画されるため見た目が動かなかった (= ユーザー報告:
    //   削除しても詰まらない)。 _arrangeAsBookshelfBody で実際の位置を再配置する。
    if (currentPage.pageType == 'bookshelf') {
      compactShelfCells();
      _arrangeAsBookshelfBody(currentPage);
    }
    _saveToStorage();
    notifyListeners();
  }

  /// 複数ノードを一括移動（オフセット加算）
  void moveNodes(Set<String> ids, Offset delta) {
    final nodeMap = currentPage.nodes;
    _pushUndo();
    for (final id in ids) {
      final node = nodeMap[id];
      if (node == null) continue;
      nodeMap[id] = node.copyWith(
        position: Offset(
          (node.position.dx + delta.dx).clamp(0.0, 20000.0 - node.width),
          (node.position.dy + delta.dy).clamp(0.0, 20000.0 - node.height),
        ),
      );
    }
    _saveToStorage();
    notifyListeners();
  }

  /// 範囲選択した図形 (装飾) を delta だけまとめて平行移動する
  /// (ユーザー要望: 複数図形の一括ドラッグ移動)。 undo に 1 回積む。
  void moveDecorations(Set<String> ids, Offset delta) {
    if (ids.isEmpty || delta == Offset.zero) return;
    _pushUndo();
    final list = currentPage.decorations;
    for (var i = 0; i < list.length; i++) {
      final d = list[i];
      if (!ids.contains(d.id)) continue;
      list[i] = d.copyWith(
        start: d.start + delta,
        end: d.end + delta,
      );
    }
    currentPage.lastModifiedAt = DateTime.now();
    _saveToStorage();
    notifyListeners();
  }

  /// 選択ノードを指定ページにコピー
  /// [sourcePageId] の全要素 (ノード/接続/装飾/グループ) を [targetPageId] へ
  /// そのまま移動する (= ユーザー要望: 別マップへ全移動して元を削除)。
  /// copyNodesToPage と違い、 ノードオブジェクトを丸ごと移すので richText・表・
  /// PDF メモ等の全フィールドが保持される。 ID は uuid で一意なのでそのまま使い、
  /// 接続も保たれる。 移動先の既存要素と重ならないよう右側にオフセットする。
  /// 戻り値 = 移動したノード数。 移動元ページは空になる (削除は呼び出し側)。
  int moveAllNodesToPage(String sourcePageId, String targetPageId) {
    final si = _pages.indexWhere((p) => p.id == sourcePageId);
    final ti = _pages.indexWhere((p) => p.id == targetPageId);
    if (si < 0 || ti < 0 || si == ti) return 0;
    final src = _pages[si];
    final tgt = _pages[ti];
    if (src.nodes.isEmpty && src.decorations.isEmpty) return 0;

    // 移動先の既存ノードの右端の右に寄せるためのオフセットを計算。
    double offsetX = 0;
    if (tgt.nodes.isNotEmpty) {
      double maxRight = double.negativeInfinity;
      for (final n in tgt.nodes.values) {
        final r = n.position.dx + n.width;
        if (r > maxRight) maxRight = r;
      }
      double minX = double.infinity;
      for (final n in src.nodes.values) {
        if (n.position.dx < minX) minX = n.position.dx;
      }
      for (final d in src.decorations) {
        if (d.start.dx < minX) minX = d.start.dx;
        if (d.end.dx < minX) minX = d.end.dx;
      }
      if (minX.isFinite && maxRight.isFinite) {
        offsetX = (maxRight + 200) - minX;
        if (offsetX < 0) offsetX = 0;
      }
    }
    final off = Offset(offsetX, 0);

    _pushUndo();
    int count = 0;
    for (final n in src.nodes.values) {
      tgt.nodes[n.id] = n.copyWith(position: n.position + off);
      count++;
    }
    tgt.connections.addAll(src.connections);
    for (final d in src.decorations) {
      d.start = d.start + off;
      d.end = d.end + off;
      tgt.decorations.add(d);
    }
    // 名前付きグループ (付箋) も引き継ぐ。
    final srcGroups = _namedGroups[src.id];
    if (srcGroups != null && srcGroups.isNotEmpty) {
      final tgtGroups = _namedGroups.putIfAbsent(tgt.id, () => {});
      srcGroups.forEach((name, ids) {
        tgtGroups.putIfAbsent(name, () => <String>{}).addAll(ids);
      });
    }
    // 移動元を空にする。
    src.nodes.clear();
    src.connections.clear();
    src.decorations.clear();
    _namedGroups.remove(src.id);

    _saveToStorage();
    notifyListeners();
    return count;
  }

  void copyNodesToPage(Set<String> ids, int targetPageIndex) {
    if (targetPageIndex < 0 || targetPageIndex >= _pages.length) return;
    final targetPage = _pages[targetPageIndex];
    final sourceNodes = currentPage.nodes;
    final sourceConns = currentPage.connections;

    // IDの対応マップ（旧ID → 新ID）
    final idMap = <String, String>{};
    for (final id in ids) {
      idMap[id] = _uuid.v4();
    }

    // ノードをコピー
    for (final id in ids) {
      final node = sourceNodes[id];
      if (node == null) continue;
      final newId = idMap[id]!;
      final newNode = MindMapNode(
        id: newId,
        title: node.title,
        position: node.position,
        contentType: node.contentType,
        memoText: node.memoText,
        youtubeUrl: node.youtubeUrl,
        linkUrl: node.linkUrl,
        color: node.color,
        width: node.width,
        height: node.height,
        attachmentPath: node.attachmentPath,
        attachmentName: node.attachmentName,
      );
      targetPage.nodes[newId] = newNode;
    }

    // 両端が選択範囲内の接続をコピー
    for (final conn in sourceConns) {
      if (ids.contains(conn.fromId) && ids.contains(conn.toId)) {
        targetPage.connections.add(NodeConnection(
          fromId: idMap[conn.fromId]!,
          fromAnchor: conn.fromAnchor,
          toId: idMap[conn.toId]!,
          toAnchor: conn.toAnchor,
        ));
      }
    }

    // グループ付箋のコピー（全メンバーが選択範囲に含まれる場合のみ）
    final sourceGroups = _namedGroups[currentPage.id] ?? {};
    final targetGroups = _namedGroups.putIfAbsent(targetPage.id, () => {});
    for (final entry in sourceGroups.entries) {
      final groupName = entry.key;
      final groupIds = entry.value;
      if (groupIds.isEmpty) continue;
      // 全メンバーが選択範囲に含まれるか判定
      if (!groupIds.every((id) => ids.contains(id))) continue;
      // コピー先に既に同名グループがあれば新名を作る
      var name = groupName;
      int n = 2;
      while (targetGroups.containsKey(name)) {
        name = '$groupName ($n)';
        n++;
      }
      targetGroups[name] = groupIds.map((id) => idMap[id]!).toSet();
      // 色・フォント・行数を引き継ぎ
      final colorIdx = _groupColors[currentPage.id]?[groupName];
      if (colorIdx != null) {
        _groupColors.putIfAbsent(targetPage.id, () => {})[name] = colorIdx;
      }
      final fs = _groupFontSizes[currentPage.id]?[groupName];
      if (fs != null) {
        _groupFontSizes.putIfAbsent(targetPage.id, () => {})[name] = fs;
      }
      final ff = _groupFontFamilies[currentPage.id]?[groupName];
      if (ff != null) {
        _groupFontFamilies.putIfAbsent(targetPage.id, () => {})[name] = ff;
      }
      final rows = _groupLayoutRows[currentPage.id]?[groupName];
      if (rows != null) {
        _groupLayoutRows.putIfAbsent(targetPage.id, () => {})[name] = rows;
      }
      final mode = _groupLayoutModes[currentPage.id]?[groupName];
      if (mode != null) {
        _groupLayoutModes.putIfAbsent(targetPage.id, () => {})[name] = mode;
      }
      final pad = _groupPadding[currentPage.id]?[groupName];
      if (pad != null) {
        _groupPadding.putIfAbsent(targetPage.id, () => {})[name] =
            List<double>.of(pad);
      }
    }
    _saveNamedGroups();

    _saveToStorage();
    notifyListeners();
  }

  /// 選択ノードを別ページへ「転送 (移動)」する (= ユーザー要望: 範囲選択の
  /// 「他ページに転送」 と、 単一ノード右クリックの 「別ページに送る」)。
  ///
  /// ★ データ欠落を防ぐため、 copyNodesToPage (一部フィールドしかコピーしない
  ///   ハンドメイド構築) + deleteNodes ではなく、 ノード本体 (同一インスタンス・
  ///   同一 id・全フィールド) をそのまま元ページから外して対象ページへ移す。
  ///   これで表・リッチテキスト・PDF メモ・サブマップリンク・格納ノード等の
  ///   情報が転送で失われない。
  /// undo は元ページのスナップショットを 1 回積む (= 元ページ上の削除は元に
  ///   戻せる)。 対象ページ側は既存のコピー機能と同様にページ別 undo の
  ///   対象外 (アーキ上クロスページ undo 非対応)。
  /// 同一ページ・空集合・範囲外 index は何もしない。
  void moveNodesToPage(Set<String> ids, int targetPageIndex) {
    if (ids.isEmpty) return;
    if (targetPageIndex < 0 || targetPageIndex >= _pages.length) return;
    if (targetPageIndex == currentPageIndex) return; // 同一ページへの転送は無意味
    final source = currentPage;
    final target = _pages[targetPageIndex];
    _pushUndo();

    // ── 格納ノード (コンテナ) は中の子ノードも一緒に移動する ──
    // コンテナだけ移すと containedNodeIds が対象ページに存在しないノードを
    //   指してコンテナが壊れ、 元ページには hiddenInContainer の迷子ノードが
    //   残る。 これを防ぐため移動対象にコンテナの子 id を加える。
    final toMove = <String>{...ids};
    for (final id in ids) {
      final n = source.nodes[id];
      if (n != null && n.isContainer && n.containedNodeIds != null) {
        toMove.addAll(n.containedNodeIds!);
      }
    }

    // ── ノード本体をそのまま移動 (全フィールド保持) ──
    final moved = <String>{};
    for (final id in toMove) {
      final node = source.nodes.remove(id);
      if (node == null) continue;
      // 念のため: 対象ページに同一 id があれば上書きを避けて新 id を振る…の
      //   前に、 id は UUID なので衝突はまず無い。 単純に同一 id で移す。
      target.nodes[id] = node;
      moved.add(id);
    }
    if (moved.isEmpty) {
      notifyListeners();
      return;
    }

    // ── 接続: 両端が移動対象なら対象ページへ持って行く。 片端だけの接続は
    //    相手がページをまたげないので破棄する。 ──
    final carried = <NodeConnection>[];
    source.connections.removeWhere((c) {
      final fromMoved = moved.contains(c.fromId);
      final toMoved = moved.contains(c.toId);
      if (fromMoved && toMoved) {
        carried.add(c);
        return true;
      }
      return fromMoved || toMoved; // 片端のみ → 破棄
    });
    target.connections.addAll(carried);

    // ── 名前付きグループ (付箋): 全メンバーが移動するならグループごと対象
    //    ページへ移し、 一部のみなら移動 id を元グループから外す (ダングリング
    //    参照を残さない)。 空になったグループは元ページから除去する。 ──
    final srcGroups = _namedGroups[source.id];
    if (srcGroups != null && srcGroups.isNotEmpty) {
      final tgtGroups = _namedGroups.putIfAbsent(target.id, () => {});
      final dropFromSrc = <String>[];
      for (final entry in srcGroups.entries.toList()) {
        final gName = entry.key;
        final gIds = entry.value;
        if (gIds.isEmpty) {
          dropFromSrc.add(gName);
          continue;
        }
        if (gIds.every((id) => moved.contains(id))) {
          // グループ全体が移動 → 対象ページに同名衝突を避けて作り直す
          var name = gName;
          int n = 2;
          while (tgtGroups.containsKey(name)) {
            name = '$gName ($n)';
            n++;
          }
          tgtGroups[name] = gIds.toSet();
          // スタイル (色/フォント/行数/レイアウト/余白) を引き継ぐ
          final colorIdx = _groupColors[source.id]?[gName];
          if (colorIdx != null) {
            _groupColors.putIfAbsent(target.id, () => {})[name] = colorIdx;
          }
          final fs = _groupFontSizes[source.id]?[gName];
          if (fs != null) {
            _groupFontSizes.putIfAbsent(target.id, () => {})[name] = fs;
          }
          final ff = _groupFontFamilies[source.id]?[gName];
          if (ff != null) {
            _groupFontFamilies.putIfAbsent(target.id, () => {})[name] = ff;
          }
          final rows = _groupLayoutRows[source.id]?[gName];
          if (rows != null) {
            _groupLayoutRows.putIfAbsent(target.id, () => {})[name] = rows;
          }
          final mode = _groupLayoutModes[source.id]?[gName];
          if (mode != null) {
            _groupLayoutModes.putIfAbsent(target.id, () => {})[name] = mode;
          }
          final pad = _groupPadding[source.id]?[gName];
          if (pad != null) {
            _groupPadding.putIfAbsent(target.id, () => {})[name] =
                List<double>.of(pad);
          }
          dropFromSrc.add(gName);
        } else {
          // 一部のみ移動 → 元グループから移動 id を外す
          gIds.removeWhere((id) => moved.contains(id));
          if (gIds.isEmpty) dropFromSrc.add(gName);
        }
      }
      // 元ページから空/移動済みグループとそのスタイルを除去
      for (final g in dropFromSrc) {
        srcGroups.remove(g);
        _groupColors[source.id]?.remove(g);
        _groupFontSizes[source.id]?.remove(g);
        _groupFontFamilies[source.id]?.remove(g);
        _groupLayoutRows[source.id]?.remove(g);
        _groupLayoutModes[source.id]?.remove(g);
        _groupPadding[source.id]?.remove(g);
      }
      _saveNamedGroups();
    }

    // 選択中ノードが移動したら選択解除。
    if (moved.contains(_selectedNodeId)) _selectedNodeId = null;

    // ギャラリー (bookshelf) の元ページは削除後に左詰めして gap を除去。
    if (source.pageType == 'bookshelf') {
      compactShelfCells();
      _arrangeAsBookshelfBody(source);
    }

    _saveToStorage();
    notifyListeners();
  }

  /// 複数ページの中身 (ノード/接続/装飾/名前付きグループ) を 1 つの新規ページに
  /// 統合する (= ユーザー要望: 複数のマインドマップやギャラリーを中の要素まで
  /// まとめて 1 つに統合)。 各ページのノードは新 ID を振り直し、 重ならないよう
  /// 縦に並べて配置する。 元のページは残す。 戻り値は統合ページの index (失敗 -1)。
  int mergePages(List<String> pageIds, {String? name}) {
    final srcs = <MindMapPage>[];
    for (final pid in pageIds) {
      for (final p in _pages) {
        if (p.id == pid) {
          srcs.add(p);
          break;
        }
      }
    }
    if (srcs.length < 2) return -1;

    // ページ種別: 全て同じならそれを、 異なれば 'normal'。
    final firstType = srcs.first.pageType;
    final sameType = srcs.every((p) => p.pageType == firstType);
    final mergedType = sameType ? firstType : 'normal';

    final merged = MindMapPage(
      id: _uuid.v4(),
      name: name ?? '統合 (${srcs.length}件)',
      folderId: srcs.first.folderId,
      pageType: mergedType,
      shelfPerRow: srcs.first.shelfPerRow,
      shelfRows: srcs.first.shelfRows,
    );

    final idMap = <String, String>{};
    double cursorY = 0;
    const gap = 400.0;

    for (final page in srcs) {
      // このページのノード外接矩形を求める。
      double minX = double.infinity, minY = double.infinity;
      double maxX = -double.infinity, maxY = -double.infinity;
      for (final n in page.nodes.values) {
        final p = n.position;
        if (p.dx < minX) minX = p.dx;
        if (p.dy < minY) minY = p.dy;
        if (p.dx + n.width > maxX) maxX = p.dx + n.width;
        if (p.dy + n.visualHeight > maxY) maxY = p.dy + n.visualHeight;
      }
      final hasNodes = page.nodes.isNotEmpty;
      final off = hasNodes
          ? Offset(-minX + 200, cursorY - minY + 200)
          : Offset(200, cursorY + 200);

      // ノードを忠実にクローン (新 ID + オフセット)。
      final localOldIds = <String>[];
      for (final entry in page.nodes.entries) {
        final newId = _uuid.v4();
        idMap[entry.key] = newId;
        localOldIds.add(entry.key);
        final j = Map<String, dynamic>.from(entry.value.toJson());
        j['id'] = newId;
        var clone = MindMapNode.fromJson(j);
        clone =
            clone.copyWith(position: clone.position.translate(off.dx, off.dy));
        merged.nodes[newId] = clone;
      }
      // コンテナ参照 (containedNodeIds / hiddenInContainer) を新 ID へ remap。
      for (final oldId in localOldIds) {
        final newId = idMap[oldId]!;
        var n = merged.nodes[newId]!;
        final cids = n.containedNodeIds;
        if (cids != null && cids.isNotEmpty) {
          n = n.copyWith(
              containedNodeIds: cids.map((c) => idMap[c] ?? c).toList());
          merged.nodes[newId] = n;
        }
        final hic = n.hiddenInContainer;
        if (hic != null && idMap.containsKey(hic)) {
          merged.nodes[newId] = n.copyWith(hiddenInContainer: idMap[hic]);
        }
      }
      // 接続をクローン (両端を remap)。
      for (final c in page.connections) {
        final f = idMap[c.fromId];
        final t = idMap[c.toId];
        if (f == null || t == null) continue;
        final cj = Map<String, dynamic>.from(c.toJson());
        cj['fromId'] = f;
        cj['toId'] = t;
        merged.connections.add(NodeConnection.fromJson(cj));
      }
      // 装飾図形をクローン (オフセット + 新 ID)。
      for (final d in page.decorations) {
        merged.decorations.add(MapDecoration(
          id: _uuid.v4(),
          kind: d.kind,
          start: d.start.translate(off.dx, off.dy),
          end: d.end.translate(off.dx, off.dy),
          colorRgb: d.colorRgb,
          strokeWidth: d.strokeWidth,
          text: d.text,
          textAnchorX: d.textAnchorX,
          textAnchorY: d.textAnchorY,
        ));
      }
      // 名前付きグループをクローン (名前衝突回避 + ID remap + 色引き継ぎ)。
      final srcGroups = _namedGroups[page.id];
      if (srcGroups != null && srcGroups.isNotEmpty) {
        final tgt = _namedGroups.putIfAbsent(merged.id, () => {});
        srcGroups.forEach((gname, gids) {
          var nm = gname;
          int k = 2;
          while (tgt.containsKey(nm)) {
            nm = '$gname ($k)';
            k++;
          }
          tgt[nm] = gids.map((id) => idMap[id]).whereType<String>().toSet();
          final ci = _groupColors[page.id]?[gname];
          if (ci != null) {
            _groupColors.putIfAbsent(merged.id, () => {})[nm] = ci;
          }
        });
      }

      cursorY += (hasNodes ? (maxY - minY) : 0) + gap;
    }

    _pages.add(merged);
    _currentPageIndex = _pages.length - 1;
    _selectedNodeId = null;
    _saveNamedGroups();
    _saveToStorage();
    notifyListeners();
    return _pages.length - 1;
  }

  /// マークダウン (= インデント階層) から現在ページのノード/接続を作り直す
  /// (= ユーザー要望: マインドマップを Markdown で書けるように)。
  /// [nodes] は (テキスト, 親 index, x, y) のリスト。 親 index < 0 はルート。
  void importMarkdownNodes(
      List<({String text, int parentIndex, double x, double y})> nodes) {
    final page = currentPage;
    // ── 既存ノードの中身を引き継ぐ (= ユーザー要望: マークダウンで編集して
    //   「マップに反映」 すると、 保存していた動画/PDF/メモ/添付が全部消える
    //   バグの修正) ──
    // マークダウンに載るのは「構造 (親子) とタイトル」 だけ。 全ノードを作り
    // 直すと添付情報 (動画 URL・PDF パス・メモ・リンク先ページ等) が失われる。
    // そこで、 タイトルが一致する既存ノードを再利用して中身を維持する。
    // タイトルを書き換えた行・新規行のみ新しいプレーンノードを作る。
    _pushUndo(); // 反映で意図せず消えても Ctrl+Z で戻せるように
    final byTitle = <String, List<MindMapNode>>{};
    for (final n in page.nodes.values) {
      byTitle.putIfAbsent(n.title.trim(), () => []).add(n);
    }
    page.nodes.clear();
    page.connections.clear();
    // 装飾 (図形描画) はマークダウンに載らないので消さずに残す。
    final ids = <String>[];
    for (final nd in nodes) {
      final key = nd.text.trim();
      final pool = byTitle[key];
      MindMapNode node;
      if (pool != null && pool.isNotEmpty) {
        // タイトル一致 → 既存ノードを再利用 (中身は維持、 位置だけ更新)。
        node = pool.removeAt(0).copyWith(position: Offset(nd.x, nd.y));
      } else {
        node = MindMapNode(
            id: _uuid.v4(), title: nd.text, position: Offset(nd.x, nd.y));
      }
      ids.add(node.id);
      page.nodes[node.id] = node;
    }
    for (int i = 0; i < nodes.length; i++) {
      final p = nodes[i].parentIndex;
      if (p >= 0 && p < ids.length) {
        page.connections.add(NodeConnection(
            fromId: ids[p],
            fromAnchor: AnchorDirection.east,
            toId: ids[i],
            toAnchor: AnchorDirection.west));
      }
    }
    page.lastModifiedAt = DateTime.now();
    _selectedNodeId = null;
    _saveToStorage();
    notifyListeners();
  }

  /// 選択ノードを同じページにペースト（オフセット付きコピー）
  /// [ids] コピー対象ノードID, [connections] コピー対象接続リスト
  /// 戻り値: 新しく追加されたノードIDのセット
  Set<String> pasteNodes(Set<String> ids, List<NodeConnection> sourceConns) {
    if (ids.isEmpty) return {};
    const pasteOffset = Offset(40, 40);
    final nodeMap = currentPage.nodes;
    final idMap = <String, String>{};
    _pushUndo();
    for (final id in ids) {
      idMap[id] = _uuid.v4();
    }
    final newIds = <String>{};
    for (final id in ids) {
      final node = nodeMap[id];
      if (node == null) continue;
      final newId = idMap[id]!;
      nodeMap[newId] = MindMapNode(
        id: newId,
        title: node.title,
        position: Offset(
          (node.position.dx + pasteOffset.dx).clamp(0.0, 19000.0),
          (node.position.dy + pasteOffset.dy).clamp(0.0, 19000.0),
        ),
        contentType: node.contentType,
        memoText: node.memoText,
        youtubeUrl: node.youtubeUrl,
        linkUrl: node.linkUrl,
        color: node.color,
        width: node.width,
        height: node.height,
        anchorMode: node.anchorMode,
        attachmentPath: node.attachmentPath,
        attachmentName: node.attachmentName,
      );
      newIds.add(newId);
    }
    for (final conn in sourceConns) {
      if (ids.contains(conn.fromId) && ids.contains(conn.toId)) {
        currentPage.connections.add(NodeConnection(
          fromId: idMap[conn.fromId]!,
          fromAnchor: conn.fromAnchor,
          toId: idMap[conn.toId]!,
          toAnchor: conn.toAnchor,
        ));
      }
    }
    _autoArrangeIfBookshelf();
    _saveToStorage();
    notifyListeners();
    return newIds;
  }

  /// ノードに添付ファイルを設定
  void updateNodeAttachment(String id, String path, String name) {
    final node = currentPage.nodes[id];
    if (node == null) return;
    _pushUndo();
    currentPage.nodes[id] = node.copyWith(
      attachmentPath: path,
      attachmentName: name,
      contentType: NodeContentType.attachment,
    );
    _autoArrangeIfBookshelf();
    _saveToStorage();
    notifyListeners();
  }

  /// 添付ファイル (PDF / pptx 等) のサムネイル画像とアスペクト比を設定する
  /// (= ユーザー要望: ドロップした PDF / pptx の 1 枚目をサムネイル表示)。
  void setAttachmentThumb(String id, String thumbPath, double aspectRatio) {
    final node = currentPage.nodes[id];
    if (node == null) return;
    currentPage.nodes[id] = node.copyWith(
      attachmentThumbPath: thumbPath,
      attachmentAspectRatio: aspectRatio > 0 ? aspectRatio : null,
    );
    // ギャラリーページではサムネ確定で本来比が入るので、 統一比を再計算して再タイル。
    _autoArrangeIfBookshelf();
    _saveToStorage();
    notifyListeners();
  }

  /// ノードの添付ファイルを削除
  void removeNodeAttachment(String id) {
    final node = currentPage.nodes[id];
    if (node == null) return;
    _pushUndo();
    currentPage.nodes[id] = node.copyWith(
      attachmentPath: '',
      attachmentName: '',
      contentType: (node.youtubeUrl ?? '').isNotEmpty
          ? NodeContentType.youtube
          : (node.linkUrl ?? '').isNotEmpty
              ? NodeContentType.link
              : (node.memoText ?? '').isNotEmpty
                  ? NodeContentType.memo
                  : NodeContentType.none,
    );
    _saveToStorage();
    notifyListeners();
  }

  /// テキストメモ付きノードを新規生成
  void addMemoNode(Offset position, String memoText) {
    const nodeW = 180.0;
    const nodeH = 42.0;
    const gap = 24.0;
    const canvasW = 20000.0;
    const canvasH = 20000.0;
    final nodeMap = currentPage.nodes;

    Offset candidate = Offset(
      position.dx.clamp(gap, canvasW - nodeW - gap),
      position.dy.clamp(gap, canvasH - nodeH - gap),
    );
    for (int i = 0; i < 30; i++) {
      bool overlap = false;
      for (final n in nodeMap.values) {
        if (_nodesOverlap(candidate, nodeW, nodeH, n, gap)) {
          overlap = true;
          candidate = Offset(
              candidate.dx,
              (n.position.dy + n.visualHeight + gap)
                  .clamp(gap, canvasH - nodeH - gap));
          break;
        }
      }
      if (!overlap) break;
    }
    final newNode = MindMapNode(
      id: _uuid.v4(),
      title: 'メモ',
      position: candidate,
      memoText: memoText,
      contentType: NodeContentType.memo,
      color: const Color(0xFF43B97F),
      width: nodeW,
    );
    _pushUndo();
    nodeMap[newNode.id] = newNode;
    _selectedNodeId = newNode.id;
    _saveToStorage();
    notifyListeners();
  }

  // ─── 動画サムネイル生成 ───────────────────────────────────────────────────

  /// 起動時に全ページ・全ノードのサムネイルを一括生成
  Future<void> _generateAllMissingThumbnails() async {
    for (final page in _pages) {
      for (final node in page.nodes.values.toList()) {
        final videoPath = node.youtubeUrl;
        if (videoPath == null || videoPath.isEmpty) continue;
        // YouTube URLはネットワークサムネイルを使うのでスキップ
        if (_isYoutubeUrl(videoPath)) continue;
        // 既にサムネイルがあればスキップ
        if ((node.videoThumbnailPath ?? '').isNotEmpty) {
          try {
            if (File(node.videoThumbnailPath!).existsSync()) continue;
          } catch (_) {}
        }
        // ローカルファイル or Firebase Storage URL のサムネイル生成
        await _generateThumbnailForNode(page, node);
      }
    }
  }

  static bool _isYoutubeUrl(String url) {
    return url.contains('youtube.com') || url.contains('youtu.be');
  }

  /// 1ノードの動画サムネイルを生成（ローカルファイル・Firebase Storage URL両対応）
  Future<void> _generateThumbnailForNode(
      MindMapPage page, MindMapNode node) async {
    if (kIsWeb) return;
    // Windows/Mac/Linuxではスキップ
    try {
      if (Platform.isWindows || Platform.isMacOS || Platform.isLinux) return;
    } catch (_) {
      return;
    }

    final videoPath = node.youtubeUrl!;
    try {
      final appDir = await getApplicationDocumentsDirectory();
      final thumbDir = Directory('${appDir.path}/video_thumbs');
      if (!await thumbDir.exists()) await thumbDir.create(recursive: true);

      String videoSource = videoPath;
      // Firebase Storage URLの場合でもvideo_thumbnailは直接URLを扱える
      final thumbPath = await vt.VideoThumbnail.thumbnailFile(
        video: videoSource,
        thumbnailPath: thumbDir.path,
        imageFormat: vt.ImageFormat.JPEG,
        maxWidth: 320,
        quality: 50,
      );
      if (thumbPath != null && thumbPath.isNotEmpty) {
        page.nodes[node.id] = node.copyWith(videoThumbnailPath: thumbPath);
        _saveToStorage();
        notifyListeners();
      }
    } catch (e) {
      debugPrint('Auto thumbnail generation failed (${node.title}): $e');
    }
  }

  /// ローカル動画ファイルからサムネイルを生成してノードに設定
  /// ノードの `videoThumbnailPath` を直接セットする (公開 API)。
  /// 主に YouTube ダウンロード時にネット側の hqdefault.jpg を保存して
  /// 即座にノードのサムネとして反映するために使う。`generateVideoThumbnail`
  /// と違って動画ファイルからフレームを抽出するわけではなく、既に
  /// 用意したサムネ画像のパスを記録するだけ。
  ///
  /// `path` が空文字列ならクリア (元のプレースホルダ表示に戻る)。
  ///
  /// 全ページ走査: バルク DL 中にユーザーが別ページに移動していても
  /// 元のノードにサムネを反映するため currentPage 限定にしない。
  Future<void> setVideoThumbnailPath(String nodeId, String path) async {
    final found = _findPageAndNodeById(nodeId);
    if (found == null) return;
    final page = found.$1;
    final node = found.$2;
    page.nodes[nodeId] =
        node.copyWith(videoThumbnailPath: path.isEmpty ? null : path);
    _saveToStorage();
    notifyListeners();
  }

  Future<void> generateVideoThumbnail(String nodeId) async {
    // 全ページ走査 (DL 中の page 切替対応)
    final found = _findPageAndNodeById(nodeId);
    if (found == null) return;
    final page = found.$1;
    final node = found.$2;
    final videoPath = node.youtubeUrl;
    if (videoPath == null || videoPath.isEmpty) return;
    // YouTube URLの場合はスキップ（YouTubeはネットワークサムネイルを使う）
    if (_isYoutubeUrl(videoPath)) return;
    // 既にサムネイルがあり、かつファイルが存在する場合はスキップ
    // （URLが変わった場合は再生成するため、ファイル存在チェックのみ）
    if ((node.videoThumbnailPath ?? '').isNotEmpty) {
      try {
        final existing = File(node.videoThumbnailPath!);
        // サムネイルのファイル名にURLのハッシュが含まれているか確認
        // → video_thumbnailは毎回異なるファイル名を生成するため、
        //   ここではファイルが存在すればスキップ（同一セッション内の重複生成を防ぐ）
        if (existing.existsSync()) return;
      } catch (_) {}
    }
    // Windows/Webではスキップ（video_thumbnailはAndroid/iOSのみ）
    if (kIsWeb || Platform.isWindows || Platform.isMacOS || Platform.isLinux)
      return;
    try {
      final appDir = await getApplicationDocumentsDirectory();
      final thumbDir = Directory('${appDir.path}/video_thumbs');
      if (!await thumbDir.exists()) await thumbDir.create(recursive: true);
      final thumbPath = await vt.VideoThumbnail.thumbnailFile(
        video: videoPath,
        thumbnailPath: thumbDir.path,
        imageFormat: vt.ImageFormat.JPEG,
        maxWidth: 320,
        quality: 50,
        timeMs: 0,
      );
      if (thumbPath != null && thumbPath.isNotEmpty) {
        // 走査時に取った node ではなく、再取得して最新状態にマージ
        // (生成中に他の更新が入った可能性に備える)
        final latest = page.nodes[nodeId] ?? node;
        page.nodes[nodeId] = latest.copyWith(videoThumbnailPath: thumbPath);
        _saveToStorage();
        notifyListeners();
      }
    } catch (e) {
      debugPrint('Thumbnail generation failed: $e');
    }
  }

  // ══════════════════════════════════════════════════════════════════
  // Google検索ダイアログ関連 (ドラフトメモ + 保存済みメモリスト + Undo)
  // ══════════════════════════════════════════════════════════════════
  //
  // 機能概要:
  // 1. ドラフトメモ (`googleSearchMemoDraft`):
  //    - Google検索ダイアログのメモ入力欄に書き途中のテキスト 1 つ。
  //    - SharedPreferences で永続化、 アプリ再起動でも保持。
  //    - 「保存」 や「マップ追加」 で確定すると空になる。
  // 2. 保存済みメモリスト (`googleSearchMemos`):
  //    - 複数の `GoogleSearchMemo` を蓄積。 PDF メモと同じ思想。
  //    - JSON 配列として SharedPreferences に永続化。
  // 3. 一括復元 (`restoreGoogleSearchMemos`):
  //    - 削除取り消し (Ctrl+Z) のために、 元の id / updatedAtMs を維持して
  //      復元する API。

  String _googleSearchMemoDraft = '';
  String get googleSearchMemoDraft => _googleSearchMemoDraft;
  Future<void> setGoogleSearchMemoDraft(String v) async {
    _googleSearchMemoDraft = v;
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString('googleSearchMemoDraft', v);
    // notifyListeners() は意図的に呼ばない (再描画ループ防止 + パフォーマンス)
  }

  final List<GoogleSearchMemo> _googleSearchMemos = [];
  List<GoogleSearchMemo> get googleSearchMemos {
    // 新しいもの順で返す (= リスト上部に最新が来る)
    final sorted = List<GoogleSearchMemo>.from(_googleSearchMemos)
      ..sort((a, b) => b.updatedAtMs.compareTo(a.updatedAtMs));
    return List.unmodifiable(sorted);
  }

  /// 新規メモを追加。
  Future<void> addGoogleSearchMemo(GoogleSearchMemo memo) async {
    _googleSearchMemos.add(memo);
    await _saveGoogleSearchMemos();
    notifyListeners();
  }

  /// 削除した複数メモを一括で復元する (Ctrl+Z Undo 用)。
  /// 元の id と updatedAtMs を保ったまま追加されるので、 ソート順も復元される。
  Future<void> restoreGoogleSearchMemos(List<GoogleSearchMemo> memos) async {
    if (memos.isEmpty) return;
    final existingIds = _googleSearchMemos.map((m) => m.id).toSet();
    var added = 0;
    for (final m in memos) {
      if (existingIds.contains(m.id)) continue;
      _googleSearchMemos.add(m);
      added++;
    }
    if (added == 0) return;
    await _saveGoogleSearchMemos();
    notifyListeners();
  }

  /// 既存メモを更新。 `updatedAtMs` も自動更新される。
  Future<void> updateGoogleSearchMemo(
    String id, {
    String? text,
    Object? snapshotUrl = _gsmSentinel,
  }) async {
    final idx = _googleSearchMemos.indexWhere((m) => m.id == id);
    if (idx < 0) return;
    final m = _googleSearchMemos[idx];
    if (text != null) m.text = text;
    if (snapshotUrl != _gsmSentinel) {
      m.snapshotUrl = snapshotUrl as String?;
    }
    m.updatedAtMs = DateTime.now().millisecondsSinceEpoch;
    await _saveGoogleSearchMemos();
    notifyListeners();
  }

  Future<void> removeGoogleSearchMemo(String id) async {
    _googleSearchMemos.removeWhere((m) => m.id == id);
    await _saveGoogleSearchMemos();
    notifyListeners();
  }

  Future<void> clearAllGoogleSearchMemos() async {
    if (_googleSearchMemos.isEmpty) return;
    _googleSearchMemos.clear();
    await _saveGoogleSearchMemos();
    notifyListeners();
  }

  Future<void> _saveGoogleSearchMemos() async {
    final prefs = await SharedPreferences.getInstance();
    final raw = jsonEncode(_googleSearchMemos.map((m) => m.toJson()).toList());
    await prefs.setString('googleSearchMemos', raw);
  }

  /// updateGoogleSearchMemo で「null 明示」 と「省略」 を区別するセンチネル。
  static const Object _gsmSentinel = Object();

  /// 永続化された Google検索メモ関連の状態を SharedPreferences から復元。
  /// MindMapProvider の初期化フローのどこかで 1 度だけ呼ぶ前提。
  Future<void> loadGoogleSearchMemoState() async {
    final prefs = await SharedPreferences.getInstance();
    _googleSearchMemoDraft = prefs.getString('googleSearchMemoDraft') ?? '';
    final memosRaw = prefs.getString('googleSearchMemos');
    if (memosRaw != null && memosRaw.isNotEmpty) {
      try {
        final List<dynamic> arr = jsonDecode(memosRaw) as List<dynamic>;
        _googleSearchMemos
          ..clear()
          ..addAll(arr.map(
              (j) => GoogleSearchMemo.fromJson(j as Map<String, dynamic>)));
      } catch (e) {
        debugPrint('googleSearchMemos JSON parse failed: $e');
      }
    }
    // notifyListeners() は呼ばない (init 段階)。 必要なら呼び出し側で。
  }
}
